INSERT INTO `b_search_content` VALUES (1,'2026-04-05 15:46:41','main','s1|/about/history.php',0,NULL,NULL,NULL,'/about/history.php','История компании','ЗАО «Банк» основан 18 января 1993 года.\rДо 1996 года Банк развивался как небольшой коммерческий банк.\r1996 год. Открывается первый дополнительный офис по работе с населением. Банк приступает к активному развитию филиальной сети. \r1997 год. Банк начинает выпуск и обслуживание пластиковых карт, использование которых позволяет вынести финансовый сервис за пределы привычных операционных залов банка и филиалов на места фактического востребования услуг.\rЯнварь 1998 года. Банк получает лицензию профессионального участника рынка ценных бумаг. По результатам анализа бухгалтерской и финансовой отчётности Банк относится по критериям ЦБ РФ к первой категории – финансово стабильные банки.\r1999 год. Банк, успешно преодолев кризис, продолжает активное развитие филиальной сети. В этом же году Банк приступает к реализации программы ипотечного кредитования муниципальных служащих.\r2004год. Банк приступает к выпуску карт платёжной системы Visa International. В течение 2004 года банк представил клиентам ряд высокотехнологичных продуктов. В области кредитования физических лиц – систему Интернет-кредитования на приобретение автомобилей, обучение в вузе, отдых и туризм. \r2006 год. Десять лет с начала работы Банка в области предоставления финансовых услуг населению. За это время в банке взяли кредит более 50 000 человек, более 200 000 человек доверили свои деньги, сделав вклады, более 50 000 человек стали держателями пластиковых карт Банка.\r2007 год. Банк получает Главную Всероссийскую Премию «Российский Национальный Олимп» в числе лучших предприятий малого и среднего бизнеса России.\r2008 год. По результатам Международного конкурса \"Золотая медаль \"Европейское качество\", проведенного Международной академией Качества и Маркетинга\" и Ассоциацией качественной продукции Банк становится Лауреатом международной награды \"Золотая Медаль \"Европейское качество\".\r2009 год. Переход на новую автоматизированную банковскую систему iBank System Российской компании «МКТ».\r2010 год. По данным финансовой отчётности на 1 января 2010 года Банк завершает 2009 год с положительными результатами. Размер прибыли за 2009 год составляет 95 149 тыс. рублей. Положительную динамику роста показывают почти все финансовые показатели.Уставный капитал банка увеличивается на 20 % и на данный момент составляет 415 240 тысяч рублей.Размер собственного капитала банка составляет 1 535 522 тысячи рублей, что на 31 % больше чем в прошлом году. \rЧасть дохода за 2009 год Банк направляет на формирование резерва на возможные потери по ссудам, ссудной и приравненной к ней задолженности. Объём такого резерва по состоянию на 1 февраля 2010 года составляет порядка 650 млн. рублей.\rСвое дальнейшее развитие Банк связывает с повышением качества и наращиванием объемов услуг, собственного капитала, внедрением новейших технологий, совершенствованием форм обслуживания клиентов и развитием новых перспективных направлений в работе.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(2,'2026-04-05 15:46:41','main','s1|/about/index.php',0,NULL,NULL,NULL,'/about/index.php','Информация о компании','&laquo;Банк&raquo;\r&mdash; один из крупнейших участников российского рынка банковских услуг. Банк работает в России с 1997 года и на сегодняшний день осуществляет все основные виды банковских операций, представленных на рынке финансовых услуг. Сеть банка формируют 490 филиалов и дополнительных офисов в 70 регионах страны. Мы предлагаем клиентам основные банковские продукты, принятые в международной финансовой практике.\nЗАО &laquo;Банк&raquo; занимает 7-е место по размеру активов по результатам 2009 года. Банк находится на 5-м месте в России по объему частных депозитов и на 4-м месте по объему кредитов для частных лиц по результатам 2009 года. 									\r&laquo;Банк&raquo;\rявляется универсальным банком и оказывает полный спектр услуг, включая обслуживание частных и корпоративных клиентов, инвестиционный банковский бизнес, торговое финансирование и управление активами.\rВ числе предоставляемых услуг: 									\nвыпуск банковских карт;\rипотечное и потребительское кредитование;\rавтокредитование;\rуслуги дистанционного управления счетами;\rкредитные карты с льготным периодом;\rсрочные вклады, аренда сейфовых ячеек;\rденежные переводы.\rЧасть услуг доступна нашим клиентам в круглосуточном режиме, для чего используются современные телекоммуникационные технологии.\r&laquo;Банк&raquo;\rявляется одним из самых надежных банков нашей страны. Основными ценностями, которыми мы руководствуемся в своей деятельности являются \rсправедливость\r,\rпрозрачность\r, \rуважение\r, \rсотрудничество\r,\rсвобода\rи\rдоверие\r. Одной из главных задач \r&laquo;Банк&raquo;\rвидит поддержание и совершенствование развитой финансовой системы России.\rВ качестве одного из приоритетных направлений культурно-просветительской деятельности \r&laquo;Банк&raquo;\rосуществляет поддержку национального. При нашем содействии Россию посетили многие всемирно известные зарубежные музыканты, в регионах России ежегодно проходят театральные фестивали, концерты и многочисленные выставки.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(3,'2026-04-05 15:46:41','main','s1|/about/management/index.php',0,NULL,NULL,NULL,'/about/management/index.php','Руководство','Коллегиальный исполнительный орган правления Банка\rДолжность\rОбразование\rПлешков Юрий Григорьевич \rНачальник экономического управления \rВ 1996 году окончил Иркутскую государственную экономическую академию по специальности &laquo;Финансы и кредит&raquo; \rСмирнов Вячеслав Евгеньевич \rЗаместитель Председателя Правления \rВ 1991 году окончил Университет Дружбы народов (Москва). В 2000 году получил степень MBA в бизнес-школе INSEAD. \rКорнева Ирина Станиславовна \rЗаместитель Председателя Правления \rВ 1997 году окончила Московскую государственную юридическую академию по специальности «Банковское дело» \rИгнатьев Вадим Михайлович \rПервый заместитель Председателя Правления \rВ 1988 году окончил Иркутскую государственную экономическую академию по специальности «Экономика и управление производством» \rВолошин Станислав Семенович \rПредседатель Правления \rВ 1986 году окончил Свердловский юридический институт по специальности «Правоведение» и Московский индустриальный институт по специальности «Экономика и управление на предприятии» \rСписок членов Совета директоров банка\rДолжность\rОбразование\rМихайлова Татьяна Васильевна \rДиректор по финансам \rВ 1996 году окончила Российскую экономическую академию им. Г.В. Плеханова по специальности «банковское дело». \rЛях Евгений Викторович \rДиректор по обеспечению банковской деятельности \rВ 1993 году окончил Российскую экономическую академию им. Плеханова, по специальности МВА «стратегический менеджмент». \rКондрусев Роман Александрович \rДиректор казначейства \rВ 1993 году окончил Кемеровский государственный университет по специальности «Правоведение» \rХрамов Анатолий Фёдорович \rДиректор по работе с персоналом \rВ 1996 году окончил Государственный университет управления по специализации «Управление персоналом». В 2002 прошел программу повышения квалификации «Современные технологии управления человеческими ресурсами» \rЖуравлева Ольга Николаевна \rГлавный бухгалтер \rВ 1985 году окончила Санкт-петербургский институт народного хозяйства по специальности «Бухгалтерский учет» \rКалинин Андрей Геннадьевич \rДиректор департамента корпоративного бизнеса \rВ 1998 году закончил Московский государственный институт международных отношений, в 2002 &ndash; Школу Менеджмента Университета Антверпена (UAMS) по специальности MBA.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(4,'2026-04-05 15:46:41','main','s1|/about/mission.php',0,NULL,NULL,NULL,'/about/mission.php','Миссия','Миссия Банка - предоставлять каждому клиенту максимально возможный набор банковских услуг высокого качества и надежности,следуя\rмировым стандартам и принципам корпоративной этики. Наш Банк - это современный высокотехнологичный банк,сочетающий\rв себе новейшие технологии оказания услуг и лучшие традиции банковского сообщества и российского предпринимательства.\rИндивидуальный подход\rНаша цель — предоставление каждому клиенту полного комплекса современных банковских продуктов и услуг с использованием последних достижений и инноваций в сфере финансовых технологий. Индивидуальный подход к ситуации и проблематике каждого клиента и философия партнерства - основы взаимодействия с нашими клиентами.\rУниверсальность\rБанк обеспечивает своим клиентам — частным лицам, крупнейшим отраслевым компаниям, предприятиям среднего и малого бизнеса, государственным структурам — широкий спектр услуг. Чтобы максимально полно обеспечить потребности клиентов, мы активно развиваем филиальную сеть в России и за ее пределами. Это позволяет нашим клиентам всегда и везде получать современные банковские услуги на уровне мировых стандартов.\rБанк — надежный партнер при реализации крупных социально-экономических проектов России и является одним из лидеров на рынке инвестиционного обеспечения региональных программ.\rПартнерство и помощь в развитии бизнеса\rВ своей деятельности мы опираемся на высочайшие стандарты предоставления финансовых услуг и тщательный анализ рынка.\rПредлагая адресные решения и соблюдая конфиденциальность взаимоотношений с партнерами, Банк проявляет гибкий подход к запросам клиентов, как розничных, так и корпоративных. Внедряя передовые технологии и инновационные решения, Банк гарантирует клиентам высокое качество обслуживания и стабильный доход.\rМы честны и открыты по отношению ко всем нашим партнерам и стремимся быть примером надежности и эффективности для всех, кто с нами сотрудничает.\rСоциальная ответственность\rБанк ориентирован на поддержку социально-экономического развития клиентов. Мы вносим вклад в повышение благосостояния общества, предоставляя нашим клиентам первоклассные экономические возможности, а также реализуя экологические программы, образовательные и культурные проекты. Банк оказывает благотворительную помощь социально незащищенным слоям общества, учреждениям медицины, образования и культуры, спортивным и религиозным организациям в регионах России. \rНаш Банк — это банк, работающий на благо общества, cтраны и каждого ее жителя.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(5,'2026-04-05 15:46:41','main','s1|/about/vacancies.php',0,NULL,NULL,NULL,'/about/vacancies.php','Вакансии','','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(6,'2022-06-15 18:07:40','main','s1|/applications.html',0,NULL,NULL,NULL,'/applications.html','Bitnami: Open Source. Simplified','Apache Friends\rMenu\rApplications\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rApache Friends and Bitnami are cooperating to make dozens of open source applications available on XAMPP, for free. Bitnami-packaged applications include Wordpress, Drupal, Joomla! and dozens of others and can be deployed with one-click installers. Visit the \rBitnami XAMPP page\rfor details on the currently available apps.\rCheck out our \rBitnami for XAMPP Start Guide\rfor more information about the applications installed.\rFollow us on Twitter\rLike us on Facebook\rAdd us to your G+ Circles\rBlog\rPrivacy Policy\rCDN provided by\nCopyright (c) 2015, Apache Friends','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(7,'2026-04-05 15:46:41','main','s1|/auth.php',0,NULL,NULL,NULL,'/auth.php','Авторизация','Вы зарегистрированы и успешно авторизовались.\rИспользуйте административную панель в верхней части экрана для быстрого доступа к функциям управления структурой и информационным наполнением сайта. Набор кнопок верхней панели отличается для различных разделов сайта. Так отдельные наборы действий предусмотрены для управления статическим содержимым страниц, динамическими публикациями (новостями, каталогом, фотогалереей) и т.п.\rВернуться на главную страницу','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(8,'2026-04-05 15:46:41','main','s1|/contacts/feedback.php',0,NULL,NULL,NULL,'/contacts/feedback.php','Задать вопрос','','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(9,'2026-04-05 15:46:41','main','s1|/contacts/index.php',0,NULL,NULL,NULL,'/contacts/index.php','Контактная информация','Обратитесь к нашим специалистам и получите профессиональную консультацию по услугам нашего банка.\rВы можете обратиться к нам по телефону, по электронной почте или договориться о встрече в нашем офисе. Будем рады помочь вам и ответить на все ваши вопросы. \rТелефоны\rТелефон/факс: \n(495) 212-85-06\rТелефоны: \n(495) 212-85-07\r(495) 212-85-08\rНаш офис в Москве','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(10,'2026-04-05 15:46:41','main','s1|/contacts/requisites.php',0,NULL,NULL,NULL,'/contacts/requisites.php','Наши реквизиты','Наименование Банка\rЗакрытое акционерное общество \"Название банка\"\rСокращенное название\rЗАО \"Название банка\"\rПолное наименование на английском языке\r\"The Name of Bank\"\rОсновной государственный регистрационный номер\r152073950937987\rTelex\r911156 IRS RU\rS.W.I.F.T.\rIISARUMM\rSPRINT\rRU.BANK/BITEX\rЮридический адрес: \r175089, Россия, г. Москва, ул. Большая Дмитровка, д. 15, стр. 1\rКор/счет: \r30102810000000000569\rИНН:\r7860249880\rБИК:\r044591488\rОКПО:\r11806935\rОКОНХ:\r98122\rКПП:\r775021017\rПрочая информация\rБанковский идентификационный код: 0575249000\rПочтовый адрес: 115035, Россия, г. Москва, ул. Балчуг, д. 2\rТелефон: (495) 960-10-12\rФакс: (495) 240-38-12\rE-mail: \rRusBk@mail.rusbank.ru','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(11,'2022-11-22 16:37:09','main','s1|/dashboard/404.html',0,NULL,NULL,NULL,'/dashboard/404.html','404 Not Found','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\r404 \rNot Found\rThe page you were looking for doesn\'t exist.\rThink this is an error? Please \rlet us know\r.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(12,'2022-11-22 16:37:11','main','s1|/dashboard/de/faq.html',0,NULL,NULL,NULL,'/dashboard/de/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rHäufig gestellte Fragen\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHäufig gestellte Fragen\rWie installiere ich XAMPP?\rXAMPP für Windows gibt es in drei verschiedenen Versionen:\rInstallationsprogramm:\rWahrscheinlich der einfachste Weg, um XAMPP zu installieren.\rZIP:\rFür Puristen: XAMPP als ZIP-Archiv.\r7zip:\rFür Puristen mit geringer Bandbreite: XAMPP als 7zip-Archiv.\rHinweis: Wenn Sie die Dateien entpacken, kann es zu falschen Warnungen Ihres Anti-Viren-Programms kommen.\rMit dem Installer:\rDas XAMPP-Control-Panel zum Starten und Beenden von Apache, MySQL, FileZilla & Mercury oder zum Installieren dieser Server als Dienste.\rInstallation mit einer Zip-Datei\rPacken Sie das Zip-Archiv in den Ordner Ihrer Wahl aus. XAMPP extrahiert sich in das Unterverzeichnis \"\\\\xampp\" unterhalb des gewählten Zielverzeichnisses. Starten Sie dann die Datei \"setup_xampp.bat\", um die XAMPP-Einstellungen an Ihr System anzupassen.\rWenn Sie ein Wurzel-Verzeichnis \"C:\\\\\" als Ziel wählen, müssen Sie die \"setup_xampp.bat\" nicht starten.\rWie mit dem Installationsprogramm können Sie nun das \"XAMPP-Control-Panel\" für weitere Aufgaben benutzen.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rWie kann ich XAMPP ohne Setup starten?\rWenn Sie XAMPP in einen Top-Level-Ordner wie \"C:\\\\\" oder \"D:\\\\\" entpacken, können Sie die meisten Server wie Apache oder MySQL direkt starten, ohne die Datei \"setup_xampp.bat\" auszuführen.\rWenn Sie XAMPP auf ein USB-Laufwerk installieren, wird empfohlen, das Setup-Skript nicht zu benutzen oder darin relative Pfade auszuwählen, da ein solches Laufwerk auf jedem PC einen anderen Laufwerksbuchstaben haben kann. Sie können mit dem Setup-Script jederzeit von absoluten auf relative Pfade wechseln.\rDer einfachste Weg ist, die Installer-Version von der Download-Seite zu nutzen, um XAMPP zu Installieren. Nach dem Fertigstellen der Installation finden Sie XAMPP unter Start &rarr; Programme &rarr; XAMPP. Man kann das XAMPP-Controll-Panel benutzen, um die Server manuell zu starten oder zu beenden, als auch diese Programme als Windows-Dienste zu installieren oder zu deinstallieren.\rDas XAMPP-Control-Panel zum Starten und Beenden von Apache, MySQL, FileZilla & Mercury oder zum Installieren dieser Server als Dienste.\rWie starte / stoppe ich XAMPP?\rDas universelle Kontrollzentrum ist das \"XAMPP Control Panel\" (Dank an www.nat32.com). Es wird mit folgendem Befehl gestartet:\r\\xampp\\xampp-control.exe\rSie können auch einige Batchdateien benutzen, um die Serverdienste zu starten/stoppen:\rApache- & MySQL-Start:\n\\xampp\\xampp_start.exe\rApache- & MySQL-Stopp:\n\\xampp\\xampp_stop.exe\rApache-Start:\n\\xampp\\apache_start.bat\rApache-Stopp:\n\\xampp\\apache_stop.bat\rMySQL-Start:\n\\xampp\\mysql_start.bat\rMySQL-Stopp:\n\\xampp\\mysql_stop.bat\rMercury-Mailserver-Start:\n\\xampp\\mercury_start.bat\rMercury-Mailserver-Stopp:\n\\xampp\\mercury_stop.bat\rFileZilla-Server-Start:\n\\xampp\\filezilla_start.bat\rFileZilla-Server-Stopp:\n\\xampp\\filezilla_stop.bat\rWie kann ich testen, ob alles funktioniert?\rGeben Sie folgende URL in Ihrem Lieblings-Web-Browser ein:\rhttp://localhost/\roder \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rWie kann ich ein Serverprogramm als Windowsdienst installieren?\rJedes Serverprogramm in XAMPP kann als Windowsdienst installiert werden. Diese Installation kann über das XAMPP-Control-Panel durchgeführt werden. Es ist nötig Administrationsrechte zu haben, um das XAMPP-Controll-Panel und dessen Skripten zu nutzen.\rManuelle Installation des Apache als Windowsdienst: \\\\xampp\\\\apache\\\\apache_installservice.bat\rManuelle Deinstallation des Apache als Windowsdienst: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rManuelle Installation des MySQL-Servers als Windowsdienst: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rManuelle Deinstallation des MySQL-Servers als Windowsdienst: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \rFileZilla (FTP Server) als Windowsdienst installieren und deinstallieren: \\\\xampp\\\\filezilla_setup.bat \rMercury-Mail-Server: eine Windowsdienst-Installation gibt es nicht\rIst XAMPP zum Produktiveinsatz geeignet?\rXAMPP ist nicht für den Einsatz in Produktivumgebungen, sondern ausschließlich für den Einsatz als Entwicklungsumgebung gedacht. XAMPP ist so offen wie möglich konfiguriert, um dem Entwickler alles, was er/sie möchte, zu erlauben. Dies ist für Entwicklungsumgebungen großartig, kann aber im Produktiveinsatz fatale Auswirkungen haben.\rHier ist eine Liste fehlender Sicherheitseinstellungen in XAMPP:\rDer MySQL-Administrator (root) hat kein Passwort.\rDer MySQL-Daemon ist übers Netzwerk erreichbar.\rProFTPD nutzt das Passwort \"lampp\" für den Benutzer \"daemon\".\rDie Standard-Benutzer von Mercury und FileZilla sind bekannt.\rAlle Einstellungen beinhalten einen hohen Sicherheitsrisiko, besonders wenn XAMPP über das Netz und von anderen Personen außerhalb Ihres lokalen Netzes erreichbar ist. Es kann auch helfen, eine Firewall oder einen (NAT-) Router zu nutzen. Im Falle, dass Sie eine Firewall oder einen Router nutzen, ist Ihr PC, auf dem XAMPP läuft, normalerweise nicht mehr aus dem Internet erreichbar. Es liegt an Ihnen, diese Probleme zu lösen. Eine kleine Hilfe dazu ist unter der \"XAMPP-Sicherheits-Konsole\" zu finden.\rBitte sichern Sie XAMPP ab, bevor Sie etwas für alle Online zur Verfügung stellen. Eine Firewall und ein externer Router sind nur für eine unterste Ebene an Sicherheit ausreichend. Für etwas mehr Sicherheit sollten Sie die \"XAMPP-Sicherheits-Konsole\" aufrufen und Passwörter vergeben.\rWenn Sie möchten, dass Ihr XAMPP auch aus dem Internet erreichbar ist, so besuchen Sie bitte folgenden URI, der einige Probleme lösen kann:\rhttp://localhost/security/\rMit der Sicherheitskonsole können Sie ein Passwort für den MySQL-Benutzer \"root\" und für phpMyAdmin setzen. Sie können auch eine Authentifikation für die Demoseiten von XAMPP aktivieren.\rDieses web-basierte Werkzeug löst keine weitergehenden Sicherheitslücken. Insbesondere den FileZilla-FTP-Server und den Mercury-Mail-Server müssen Sie selbst absichern.\rWie deinstalliere ich XAMPP?\rWenn Sie XAMPP mit Hilfe der Installer-Version installiert haben, verwenden Sie unbedingt den \"Uninstaller\" (De-Installationsassistent), also nicht nur löschen. Durch den \"Uninstaller\" werden alle Einstellungen in der Windowsregistrierung zurückgenommen, gleichzeitig werden alle Anwendungen deinstalliert, die zu XAMPP gehören. Wir empfehlen dringend, das \"Uninstall\"-Programm aus der Version des Installers zu benutzen, mit dem Sie XAMPP installiert haben. Bitte sichern Sie alle wichtigen Daten, die Sie behalten möchten, bevor Sie XAMPP deinstallieren.\rWenn Sie XAMPP mit Hilfe der ZIP- oder 7zip-Version installiert haben, fahren Sie alle XAMPP-Server herunter und verlassen Sie alle Fenster. Wenn Sie irgendwelche Dienste eingerichtet haben, machen Sie auch das rückgängig. Dann löschen Sie einfach den gesamten Ordner, in dem XAMPP installiert war. Es gibt keine Registry-Einträge und keine Environment-Variablen, die gelöscht werden müssten.\rWas ist die \"lite\"-Version von XAMPP?\rXAMPP Lite (das bedeutet \"light\" (leicht) wie in \"Leichtgewicht\") ist ein kleineres Bündel aus XAMPP-Komponenten, das empfohlen wird für rasche Arbeiten, die nur PHP und MySQL brauchen. Einige Dienste wie Mercury-Mail und FileZilla-FTP fehlen in der Lite-Version.\rWohin gehört mein Web-Inhalt?\rDas Stammverzeichnis für alle WWW-Dokumente ist \\\\xampp\\\\htdocs. Wenn Sie eine Datei \"test.html\" in dieses Verzeichnis legen, können Sie darauf mit der URI \"http://localhost/test.html\" zugreifen.\rUnd \"test.php\"? Einfach folgende Adresse aufrufen \"http://localhost/test.php\". Ein einfaches Testskript kann so aussehen:\r<?php\recho \'Hello world\'; \r?>\rEine neues Unterverzeichnis für ihr eigenes Web? Einfach ein neues Verzeichnis (z. B. \"neu\") innerhalb des Verzeichnisses \"\\\\xampp\\\\htdocs\" anlegen (am besten ohne Leerzeichen und nur ASCII-Zeichen), erstellen Sie dann einfach eine Testdatei in diesem neuen Verzeichnis und rufen Sie sie mit \"http://localhost/neu/test.php\" auf.\rZusätzliche Einzelheiten\rHTML:\rAusführbar: \\xampp\\htdocs\rErlaubte Endungen: .html .htm\r=> Basispaket\rSSI:\rAusführbar: \\xampp\\htdocs\rErlaubte Endungen: .shtml\r=> Basispaket\rCGI:\rAusführbar: \\xampp\\htdocs and \\xampp\\cgi-bin\rErlaubte Endungen: .cgi\r=> Basispaket\rPHP:\rAusführbar: \\xampp\\htdocs and \\xampp\\cgi-bin\rErlaubte Endungen: .php\r=> Basispaket\rPerl:\rAusführbar: \\xampp\\htdocs and \\xampp\\cgi-bin\rErlaubte Endungen: .pl\r=> Basispaket\rApache::ASP Perl:\rAusführbar: \\xampp\\htdocs\rErlaubte Endungen: .asp\r=> Basispaket\rJSP Java:\rAusführbar: \\xampp\\tomcat\\webapps\\java (e.g.)\rErlaubte Endungen: .jsp\r=> Tomcat add-on\rServlets Java:\rAusführbar: \\xampp\\tomcat\\webapps\\java (e.g.)\rErlaubte Endungen: .html (u.a)\r=> Tomcat add-on\rKann ich die XAMPP-Installation woanders hin legen?\rJa. Nachdem Sie das XAMPP-Verzeichnis woanders hin gelegt haben, müssen Sie die \"setup_xampp.bat\"-Datei ausführen. Die Verzeichnispfade in den Konfigurationsdateien werden durch diesen Schritt angepasst.\rWurden Server als Windowsdienst installiert, so ist es wichtig, diese vorher zu deinstallieren, nach dem Verlegen der XAMPP-Installation kann man dann die Windowsdienste wieder installieren.\rAchtung: Die Konfigurationsdateien Ihrer eigenen Skripten - wie PHP-Anwendungen - werden nicht geändert. Aber es ist möglich, ein \"Plug-in\" für den Installer zu schreiben. Mit einem solchen Plug-in kann der Installer auch solche Dateien anpassen.\rWas sind \"automatische Startseiten\" für die WWW-Verzeichnisse?\rDer Standard-Dateiname für die Appachefunktion \"DirectoryIndex\" ist \"index.html\" oder \"index.php\". Jedes Mal, wenn Sie lediglich ein Verzeichnis im Browser aufrufen (z. B. \"http://localhost/xampp/\") und Apache findet darin eine solche Datei, wird diese Datei anstelle eines Inhaltsverzeichnisses angezeigt.\rWo kann ich die Konfigurationen ändern?\rFast alle Einstellungen in XAMPP können Sie mit Konfigurationsdateien ändern. Öffnen Sie einfach die Datei in einem Text-Editor und ändern Sie die gewünschte Einstellung. Nur FileZilla und Mercury sollten Sie mit dem Konfigurationswerkzeug konfigurieren.\rWarum läuft XAMPP nicht auf Windows XP SP2?\rMicrosoft liefert mit Service Pack 2 (SP2) eine bessere Firewall, die automatisch startet. Diese Firewall blockiert jedoch die erforderlichen Ports 80 (http) und 443 (https), sodass Apache nicht starten kann.\rDie schnelle Lösung:\rDeaktivieren Sie die Microsoft-Firewall mit der Systemsteuerung &rarr; Windows-Firewall und versuchen Sie, XAMPP erneut zu starten. Besser wäre es, eine Ausnahme im Sicherheitscenter einzurichten.\rDie folgenden Ports sind in Benutzung für Basis-Funktionalitäten:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rWarum funktioniert XAMPP nicht bei Windows VISTA?\rBenutzerkontensteuerung (UAC)\rIm Verzeichnis \"C:\\\\Programme\" haben Sie nicht alle Zugriffsrechte, nicht einmal als Administrator. Oder Sie haben eingeschränkte Zugriffsrechte (z. B. für \"\\\\xampp\\\\htdocs\"). In diesem Fall können Sie die Datei nicht verändern.\rLösung:\rErhöhen Sie ihre Zugriffsrechte über den Dateimanager (rechte Maustaste / Sicherheit) oder schalten Sie die Benutzerkontensteuerung (UAC) ab.\rSie haben Apache/MySQL in \"C:\\\\xampp\" als Windowsdienste installiert. Aber Sie können diese Windowsdienste nicht mehr über das \"XAMPP-Controll-Panel\" starten/anhalten oder sie können sie nicht deinstallieren.\rLösung:\rBenutzen Sie die Systemsteuerung &rarr; Verwaltung &rarr; Dienste-Konsole von Windows oder deaktivieren Sie die Benutzerkontensteuerung UAC.\rDeaktivieren der Benutzerkontensteuerung (UAC)\rVerwenden Sie das Programm \"msconfig\", um die Benutzerkontensteuerung zu deaktivieren. In \"msconfig\" gehen Sie auf \"Tools\", wählen \"UAC-Einstellungen ändern\", klicken auf \"Starten\" und überprüfen Ihre Auswahl. Danach müssen Sie Windows neu starten. Zur gleichen Zeit können Sie die Benutzerkontensteuerung wieder aktivieren.\rWie überprüfe ich die md5-Prüfsumme (md5_checksum)?\rUm Dateien zu vergleichen, werden oft Prüfsummen (checksums) benutzt. Üblicherweise erzeugt man eine md5-Prüfsumme (Message Digest Algorithm 5).\rMit dieser md5-Prüfsumme können Sie testen, ob Ihr Download des XAMPP-Pakets korrekt ist oder nicht. Natürlich benötigen Sie ein Programm, das diese Prüfsummen erstellen kann. Für Windows können Sie ein Kommandozeilenwerkzeug von Microsoft verwenden:\rVerfügbarkeit und Beschreibung des Prüfsummen-Dienstprogramms \"File Checksum Integrity Verifier utility\" - fciv\rEs ist auch möglich, ein anderes Programm zu benutzen, das eine md5-Prüfsumme erzeugen kann, z. B. \"GNU md5sum\" oder \"winMd5Sum.exe\".\rWenn Sie ein solches Programm installiert haben (z.B. fciv.exe), können Sie die folgenden Schritte ausführen:\rLaden Sie XAMPP (z. B. xampp-win32-1.8.2-0.exe) herunter\rErstellen Sie eine Prüfsumme mit:\rfciv.exe xampp-win32-1.8.2-0.exe\rUnd nun können Sie Ihre Prüfsumme mit der angezeigten Prüfsumme auf der XAMPP_für_Windows-Homepage vergleichen.\rWenn beide Prüfsummen gleich sind, dann ist alles in Ordnung. Wenn nicht, so kann der Download abgebrochen sein oder die Datei wurde verändert.\rWarum haben Änderungen in der php.ini keine Auswirkungen?\rWenn Änderungen in der php.ini keine Wirkung zeigen, so ist es möglich, dass eine andere php.ini benutzt wird. Eine Prüfung kann mit phpinfo() vollzogen werden. Gehen Sie auf die URI http://localhost/xampp/phpinfo.php und suchen Sie nach \"Loaded Configuration File\". In diesem Eintrag ist der Dateipfad der php.ini abzulesen, der wirklich benutzt wird.\rHinweis:\rNach Änderungen in der php.ini ist es wichtig, den Apache neu zu starten, damit der Apache den PHP-Parser veranlasst, die neuen Einstellungen einzulesen.\rHilfe! Hier ist ein Virus im XAMPP!\rEinige Antivirus Programme halten XAMPP für einen Virus, typischerweise mit dem Hinweis auf den XAMPP-Manager.exe. Das ist eine falsche Positiv-Meldung des Antivirus-Programms, das bedeutet, dass das Antivirus-Programm XAMPP irrtümlich als Virus identifiziert hat, obwohl XAMPP keines ist. Bevor wir eine neue Version von XAMPP herausgeben, testen wir sie mit unterschiedlichen Virenscannern, die zu diesem Zeitpunkt aktuell vorhanden sind. Im Augenblick benutzen wir \rKapersky Online Virus Scanner\r. Sie können auch das Onlinewerkzeug benutzen, \rVirus Total\rum XAMPP zu untersuchen oder Sie senden uns eine E-Mail an security (at) apachefriends (dot) org, wenn Sie ein Problem gefunden haben.\rWie konfiguriere ich mein Antivirusprogramm?\rWir haben alle zum Ausführen der gebündelten Webanwendung benötigten Server und die damit verbundenen Dateien eingefügt, sie werden also bemerken, dass XAMPP eine große Anzahl an Dateien installiert. Wenn sie eine XAMPP-Anwendung auf einem Windowsrechner mit einem aktiven Antivirusprogramm installieren, dann kann das die Installation merklich verlangsamen und es kann sein, dass einer der Server (Web-Server, Datenbankserver) von der Antivirussoftware blockiert wird. Wenn Sie ein Antivirusprogramm aktiviert haben, prüfen Sie die folgenden Einstellungen, damit XAMPP ohne Leistungseinbußen ausgeführt wird:\rFügen Sie Ausnahmen in der Firewall hinzu: für Apache, MySQL oder jeden weiteren Server.\rDateien untersuchen beim Aufruf: Wenn Sie die Virusuntersuchung für alle Dateien aktiviert haben, können die ausführbaren Dateien für den Server langsamer werden.\rUntersuchen Sie den Verkehr für unterschiedliche URLs: wenn Sie mit XAMPP auf Ihrem eigenen Rechner entwickeln, können Sie den \"localhost\"-Verkehr in den Antiviruseinstellungen ausschließen.\rWarum startet der Apache Server auf meinem System nicht?\rDies Problem kann einen von mehrere Gründen habe:\rSie haben mehr als einen HTTP-Server (IIS, Sambar, ZEUS usw.) gestartet. Nur ein Server kann Port 80 verwenden. Diese Fehlermeldung weist auf das Problem hin:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rSie haben eine andere Software wie das Internettelefon \"Skype\", die auch den Port 80 besetzt. Wenn \"Skype\" das Problem ist, gehen Sie in Skype auf Aktionen &rarr; Verbindungsoptionen &rarr; Verbindung &rarr; entfernen Sie das Häkchen bei \"Ports 80 und 443 für zusätzliche eingehende Verbindungen verwenden\" und starten Sie Skype erneut. Jetzt sollte es funktionieren.\rSie haben eine Firewall, die den Port von Apache blockiert. Nicht alle Firewalls sind kompatibel mit Apache, und es kommt manchmal vor, dass man die Firewall abschalten muss und wenn das nicht reicht, sogar eine Deinstallation durchführen muss. Diese Meldung zeigt eine Firewallblockade an:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rAuch wenn der Apache gestartet werden kann, aber Ihr Browser kann nicht darauf zugreifen (http://localhost/), so könnte es einen der folgenden Gründe haben:\rEinige Virusscanner können das in der gleicher Weise verursachen, wie eine Firewall stören kann.\rSie benutzen Windows XP Professional ohne Servicepack 1. Sie müssen wenigstens das Servicepack 1 haben, damit XAMPP funktioniert.\rTipp:\rWenn Sie Probleme mit belegten Ports haben, können Sie das Tool \"xampp-portcheck.exe\" ausprobieren. Manchmal hilft es.\rWarum ist meine CPU-Auslastung mit Apache bei 99%?\rEines von zwei Szenarien spiel hier ein Rolle. Entweder ihre CPU ist am Limit oder Sie rufen eine Seite auf, sehen aber nichts (das System versucht vergeblich die Seite zu laden). In beiden Fällen können Sie die folgende Nachricht in Ihrer Apache-Logdatei finden:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rDer MPM fällt zurück in eine sicherere Implementierung, aber einige Clients werden nicht korrekt behandelt. Um diesen Fehler zu vermeiden, setzen Sie \"AcceptFilter\" mit accept filter \"none\" in der \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\"-Datei.\rWarum werden Bilder und Stylesheets-Formate nicht angezeigt?\rGelegentlich gibt es Probleme mit der Anzeige von Bildern und Stylesheets, insbesondere wenn diese Dateien auf einem Netzwerklaufwerk liegen. In diesem Fall können Sie eine der folgenden Zeilen in der Datei \"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\" aktivieren (oder hinzufügen):\rEnableSendfile off\rEnableMMAP off\rDas Problem kann auch von Programmen verursacht werden, die die Bandbreite der Übertragung regulieren (z. B. NetLimiter).\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rWie kann ich ein root-Passwort für die MySQL-Datenbank setzen?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rKann ich meinen eigenen MySQL-Server nutzen?\rJa. Starten Sie einfach nicht den MySQL vom XAMPP-Paket. Bitte beachten Sie, dass nicht zwei Server am gleichen Port lauschen können. Wenn Sie ein Passwort für \"root\" gesetzt haben, vergessen Sie bitte nicht, die Datei \"\\\\xampp\\\\phpMyAdmin\\\\config.inc.php\" anzupassen.\rWie schränke ich den Zugriff auf phpMyAdmin von außen ein?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rBevor Sie auf den MySQL-Server zugreifen können, wird phpMyAdmin nach einem Benutzernamen und einem Passwort fragen. Vergessen Sie nicht, zuerst ein Passwort für den Benutzer \"root\" zu setzen.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rWo ist der IMAP-Support bei PHP?\rIn der Standardeinstellung ist die IMAP-Unterstützung aufgrund einiger mysteriöser Initialisierungsfehler mit einigen Homeversionen wie Windows_98 deaktiviert. Wenn Sie mit NT-Systemen arbeiten, können Sie die Datei \"\\\\xampp\\\\php\\\\php.ini\" öffnen, damit Sie die PHP-Erweiterung durch Entfernen des Semikolons am Beginn der Zeile \";extension=php_imap.dll\" aktivieren können. Es sollte sein:\rextension=php_imap.dll\rJetzt starten Sie den Apache neu und IMAP sollte funktionieren. Sie können die gleichen Schritte für alle Erweiterungen anwenden, die in der Standardeinstellung nicht aktiviert sind.\rWarum funktionieren einige PHP-open-source-Anwendungen nicht mit XAMPP für Windows?\rViele PHP-Anwendungen oder Erweiterungen, die für Linux geschrieben worden sind, wurden nicht auf Windows übertragen. \rKann ich das Verzeichnis \"install\" nach der Installation löschen?\rBesser nicht. Die Skripten darin werden noch für alle Zusatzpakete (add-ons) und Upgrades von XAMPP gebraucht.\rWie aktiviere ich den eAccelerator?\rWie andere (Zend-) Erweiterungen können Sie sie in in der \"php.ini\"-Datei aktivieren. Aktivieren Sie in dieser Datei die Zeile \";zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\". Es sollte sein:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rWie behebe ich Verbindungsfehler zum MS_SQL-Server?\rWenn die mssql-Erweiterung in der php.ini geladen wird, erscheinen gelegentlich Probleme, wenn nur TCP/IP benutzt wird. Sie können das Problem mit einer neueren Version der \"ntwdblib.dll\" von Microsoft lösen. Bitte ersetzen Sie die ältere Datei in \"\\\\xampp\\\\apache\\\\bin\" und \"\\\\xampp\\\\php\" mit der neueren. Wegen der Lizenz können wir nicht selbst eine neuere Version mit XAMPP ausliefern.\rWie arbeite ich mit der PHP-mcrypt-Erweiterung?\rDafür haben wir einen Betreff im Forum mit Beispielen und möglichen Lösungen geöffnet: \rMCrypt-Eintrag\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rNein. Und Apache::ASP mit dem Perl_ Add-On ist nicht das Gleiche. Apache::ASP kennt nur Perl-Skripten, wohingegen ASP des Internet-Information-Servers (IIS) auch normales VBScript beherrscht. Allerdings ist ein Apache-Modul für APS .NET von einem Drittanbieter verfügbar.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rDatenschutzbestimmungen\rCDN bereitgestellt durch','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(13,'2022-11-22 16:37:12','main','s1|/dashboard/de/howto.html',0,NULL,NULL,NULL,'/dashboard/de/howto.html','XAMPP howto guides','Apache Friends\rMenu\rHäufig gestellte Fragen\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rDatenschutzbestimmungen\rCDN bereitgestellt durch','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(14,'2022-11-22 16:37:13','main','s1|/dashboard/de/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/de/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rHäufig gestellte Fragen\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rDatenschutzbestimmungen\rCDN bereitgestellt durch','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(15,'2022-11-22 16:37:12','main','s1|/dashboard/de/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/de/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rHäufig gestellte Fragen\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rDatenschutzbestimmungen\rCDN bereitgestellt durch','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(16,'2023-11-19 12:10:26','main','s1|/dashboard/de/index.html',0,NULL,NULL,NULL,'/dashboard/de/index.html','Welcome to XAMPP','Apache Friends\rMenu\rHäufig gestellte Fragen\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rHäufig gestellte Fragen\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nGemeinschaft\rXAMPP gibt es seit mehr als 10 Jahren &ndash; eine riesige Gemeinschaft steht dahinter. Auch du kannst ein Teil davon werden, durch Teilnahme an unseren \rForen\r, uns auf \rFacebook\rlikest, oder unseren Tätigkeiten auf \rTwitter\rfolgst.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rDatenschutzbestimmungen\rCDN bereitgestellt durch','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(17,'2022-11-22 16:37:10','main','s1|/dashboard/docs/access-phpmyadmin-remotely.html',0,NULL,NULL,NULL,'/dashboard/docs/access-phpmyadmin-remotely.html','Enable Remote Access to phpMyAdmin','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\naccess-phpmyadmin-remotely.pdf\rEnable Remote Access to phpMyAdmin\rXAMPP includes \rphpMyAdmin\r, an open-source, browser-based tool for managing MySQL/MariaDB database servers. By default, for security reasons, phpMyAdmin is configured to only accept connections from the host on which XAMPP is installed. Attempting to access phpMyAdmin from any other host will produce the error below:\rTo enable remote access to phpMyAdmin from other hosts, follow these steps:\rEdit the \rapache/conf/extra/httpd-xampp.conf\rfile in your XAMPP installation directory (usually, \rC:\\xampp\r).\rWithin this file, find the block below:\r<Directory \"/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\n...\rUpdate this block and replace \rRequire local\rwith \rRequire all granted\r, so that it looks like this:\r<Directory \"/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\n...\rSave the file and restart the Apache server using the XAMPP control panel.\rYou should now be able to access phpMyAdmin from other hosts.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(18,'2022-11-22 16:37:10','main','s1|/dashboard/docs/activate-use-xdebug.html',0,NULL,NULL,NULL,'/dashboard/docs/activate-use-xdebug.html','Activate and Use Xdebug','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nactivate-use-xdebug.pdf\rActivate and Use Xdebug\rXdebug\ris a powerful open source debugger and profiler for PHP. It is included with XAMPP and can be used to display stack traces, analyze code coverage and profile your PHP code.\rTo activate Xdebug, follow these steps:\rEdit the \rphp.ini\rfile in the \rphp\\\rsubdirectory of your XAMPP installation directory (usually, \rC:\\xampp\r). Within this file, find the [XDebug] section and within it, add the following configuration directive (or modify the existing one):\rzend_extension = \"C:/xampp/php/ext/php_xdebug.dll\"\rRestart the Apache server using the XAMPP control panel.\rXdebug should now be active. To verify this, browse to the URL \rhttp://localhost/xampp/phpinfo.php\r, which displays the output of the \rphpinfo(\r) command. Look through the script and verify that the Xdebug extension is now active.\rXdebug overloads the default \rvar_dump(\r) function with its own version that includes (among other things) color coding for different PHP types, so you can see it in action immediately by using the \rvar_dump()\rfunction in a PHP script. For example, create a simple PHP script in the \rhtdocs\\\rsubdirectory of your XAMPP installation directory with the following content:\r<?php\nvar_dump($_SERVER);\rWhen you view your script through a browser, here&#8217;s an example of what you might see:\rOne of Xdebug&#8217;s most powerful features is its ability to profile a PHP script and produce detailed statistics on how long each function call or line of code takes to execute. This can be very useful for performance analysis of complex scripts. To turn on script profiling, follow these steps:\rEdit the \rphp.ini\rfile in the \rphp\\\rsubdirectory of your XAMPP installation directory. Within this file, find the [XDebug] section and within it, uncomment and modify the lines below so that they look like this:\rxdebug.profiler_append = 0\nxdebug.profiler_enable = 1\nxdebug.profiler_enable_trigger = 0\nxdebug.profiler_output_dir = \"C:/xampp/tmp\"\nxdebug.profiler_output_name = \"cachegrind.out.%t-%s\"\rRestart the Apache server using the XAMPP control panel.\rAt this point, Xdebug profiling is active. Every PHP script that you run will be profiled and the results will be placed in the \rC:\\xampp\\tmp\ras a so-called cachegrind file. You can view this cachegrind file with a tool like \rWinCacheGrind\r, which you must download and install separately.\rTo illustrate how this works, consider the screenshot below, which shows the profiled output of a script using WinCacheGrind. As the screenshot illustrates, it&#8217;s easy to see the entire life cycle of a PHP script, including the call sequence and the amount of time taken by each function, and thereby find targets for further optimization.\rTo find out more about Xdebug’s powerful features, \rread the Xdebug documentation\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(19,'2022-11-22 16:37:09','main','s1|/dashboard/docs/auto-start-xampp.html',0,NULL,NULL,NULL,'/dashboard/docs/auto-start-xampp.html','Auto-Start XAMPP','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nauto-start-xampp.pdf\rAuto-Start XAMPP\rBy default, you have to start XAMPP or its components manually every time you reboot your system. However, you can also configure XAMPP components to start automatically on system boot. Follow the steps below.\rLaunch the XAMPP control panel.\rStop all the running XAMPP components by clicking the \"Stop\" button next to each component.\rClick the \"Service\" button next to each component to install it as a service. Click \"Yes\" when prompted to confirm. This will install the corresponding service and set it to start automatically on boot.\rReboot your system and the selected components should start automatically.\rTo revert the changes, simply uncheck the selected services in the XAMPP control panel.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(20,'2022-11-22 16:37:09','main','s1|/dashboard/docs/backup-restore-mysql.html',0,NULL,NULL,NULL,'/dashboard/docs/backup-restore-mysql.html','Backup and Restore MySQL/MariaDB Databases','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nbackup-restore-mysql.pdf\rContents\rUsing phpMyAdmin\rUsing Command-Line Tools\rBackup and Restore MySQL/MariaDB Databases\rAs you use XAMPP, you might find that you need to backup or restore a MySQL or MariaDB database. There are two easy ways to do this with XAMPP: using the browser-based phpMyAdmin tool or using MySQL/MariaDB&#8217;s command-line tools. This guide describes both options.\rThis guide assumes that you already have a PHP application that uses a MySQL/MariaDB database deployed on XAMPP. The example application used in this guide is WordPress, although the steps outlined below will work for any application.\rRemember that you can install WordPress quickly using the \rBitnami WordPress module for XAMPP\r.\nUsing phpMyAdmin\rXAMPP includes \rphpMyAdmin\r, an open-source, browser-based tool for managing MySQL/MariaDB database servers. To backup a MySQL/MariaDB database using phpMyAdmin, follow these steps:\rBrowse to \rhttp://localhost/phpMyAdmin\ror \rhttp://127.0.0.1/phpMyAdmin\r. If required, log in using your database access credentials. On a fresh XAMPP installation without any changes, you can log in as \rroot\rwith a blank password.\rSelect the database to be backed up from the list in the left navigation pane. In this case, we&#8217;re backing up the WordPress database, which is named \rbitnami_wordpress\r.\rSelect the \"Export\" command in the top navigation bar.\rOn the resulting page, select \"Quick\" as the export method and \"SQL\" as the output format. Click \"Go\" to proceed.\rphpMyAdmin will export the database to a text file as a series of SQL statements. Once done, the browser will prompt you to download it to the desktop. This text file is your backup, so store it safely!\rAt a later point, you may wish to restore the database. To restore the data to a fresh MySQL/MariaDB database using phpMyAdmin, follow these steps:\rBrowse to \rhttp://localhost/phpMyAdmin\ror \rhttp://127.0.0.1/phpMyAdmin\r. If required, log in using your database access credentials.\rSelect the \"New\" command in the left navigation pane.\rOn the resulting page, enter a name for the new database (in this case, \rmyblog\r). Select the collation \"utf8_general_ci\". Click \"Create\" to create the database.\rOnce the database has been created, it will appear in the left navigation pane.\rSelect the new database from the left navigation pane. In the resulting page, select the \"Import\" command in the top navigation bar.\rClick the \"Browse&#8230;&#8203;\" button and select the backup file created earlier. Click \"Go\" to proceed.\rphpMyAdmin will import the data from the backup file. Once complete, you will see a screen indicating the status of the import.\rIf you browse the contents of the database, you should now see your original data.\rYou should now update your application&#8217;s configuration and point it to your newly-created database. For example, with the Bitnami WordPress module, you will need to edit the \rwp-config.php\rfile in the \rapps\\wordpress\\htdocs\\\rsubdirectory of your XAMPP installation directory. Within this file, you will need to update the \rDB_NAME\rconstant to use the new database name.\rBy default, PHP (and therefore phpMyAdmin) is configured to only accept uploads up to 2 MB in size. If your database is larger than this, you need to modify the PHP configuration file to accept a larger upload size. To do this, edit the \rphp.ini\rfile in the \rphp\\\rsubdirectory of your XAMPP installation directory and increase the values of the \rpost_max_size\rand \rupload_max_filesize\rvariables. Save your changes and restart Apache for the changes to take effect.\nUsing Command-Line Tools\rMySQL and MariaDB include two command-line tools that you can use to quickly backup and restore databases. The \rmysqldump\rtool is used to export the contents of a database to a text file, while the \rmysql\rclient can be used to import data from a text file into a MySQL/MariaDB database.\rTo backup a MySQL/MariaDB database from the command line, follow these steps:\rLaunch a new Windows command shell using the \"Shell\" button in the XAMPP control panel.\rUse the command below to export the contents of the selected database. In this example, we&#8217;re backing up the WordPress database, which is named \rbitnami_wordpress\r, to a file named \rbitnami_wordpress.sql\r. This text file is your backup, so store it safely!\rmysqldump --user=root --password=\"\" bitnami_wordpress > bitnami_wordpress.sql\rAt a later point, you may wish to restore the database. To restore the data to a fresh MySQL/MariaDB database from the command line, follow these steps:\rLaunch a new Windows command shell using the \"Shell\" button in the XAMPP control panel.\rUse the \rmysql\rclient to create a new, empty database to hold your data. In this example, the new database is named \rmyblog\r.\rmysql --user=root --password=\"\" -e \"CREATE DATABASE myblog\"\rRemember to use the correct database access credentials in the command. On a fresh XAMPP installation without any changes, you can usually log in as root with a blank password.\rUse the \rmysql\rclient to import the contents of the backup file into the new database.\rmysql --user=root --password=\"\" --database=myblog < bitnami_wordpress.sql\rThe command-line client will now import the data from the backup file.\rIf you browse the contents of the database, you should now see your original data.\rYou should now update your application&#8217;s configuration and point it to your newly-created database. For example, with the Bitnami WordPress module, you will need to edit the \rwp-config.php\rfile in the \rapps\\wordpress\\htdocs\\\rsubdirectory of your XAMPP installation directory. Within this file, you will need to update the \rDB_NAME\rconstant to use the new database name.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(21,'2022-11-22 16:37:10','main','s1|/dashboard/docs/change-mysql-temp-dir.html',0,NULL,NULL,NULL,'/dashboard/docs/change-mysql-temp-dir.html','Change the MySQL Temporary Files Directory','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nchange-mysql-temp-dir.pdf\rChange the MySQL Temporary Files Directory\rBy default, MySQL&#8217;s temporary files are stored in the \rtmp\\\rsubdirectory of your XAMPP installation directory (usually, \rC:\\xampp\r). In case you wish to change the location of this directory, follow these steps:\rEdit the \rmy.ini\rfile in the \rmysql\\bin\\\rsubdirectory of your XAMPP installation directory. Within this file, find the \rtmpdir\rvariable in the [mysqld] section and change it to reflect your new desired location. For example:\rtmpdir = \"D:/temp\"\rSave your changes to the file.\rRestart the MySQL server using the XAMPP control panel.\rMySQL&#8217;s temporary files should now get created in the new location.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(22,'2022-11-22 16:37:09','main','s1|/dashboard/docs/configure-use-tomcat.html',0,NULL,NULL,NULL,'/dashboard/docs/configure-use-tomcat.html','Configure and Use Apache Tomcat','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nconfigure-use-tomcat.pdf\rConfigure and Use Apache Tomcat\rXAMPP for Windows comes with Apache Tomcat built in, making it easy to get started with Java-based Web applications. This guide will walk you through the process of using Apache Tomcat with XAMPP.\rXAMPP for Windows does not include Java, which is a pre-requisite for using Apache Tomcat. If you do not already have Java installed, you will see an error similar to the below when you attempt to start Apache Tomcat through the XAMPP control panel.\rTo correct this, install Java and then attempt to use Apache Tomcat, as below:\rBrowse to \rhttps://www.java.com/en/download/\rand follow the instructions to download the latest version of the Java Runtime Environment.\rFollow the on-screen instructions to install Java.\rOnce installed, you will see a message like the one below:\rOn some versions of Windows, you will not be able to install Java without administrator privileges. You may either need to log in as a user with administrative rights or, if you are using the offline Java installer, you may need to right-click the installer file and select the \"Run as administrator\" menu option, then enter administrator credentials (if required) to proceed.\nStart the Apache Tomcat server using the XAMPP control panel.\rYou should now be able to access Apache Tomcat by browsing to \rhttp://localhost:8080/\rin your browser&#8217;s address bar. Here&#8217;s an example of what you should see:\rApache Tomcat includes two applications, the \"manager\" application and the \"host-manager\" application, that simplify management and deployment of Web applications and provide detailed information on server status. These applications can be accessed from the Apache Tomcat welcome page, as highlighted in the image above.\rAccess to the above applications is blocked by default. To access them, you must configure one or more sets of administrator accounts and then assign the roles \"manager-gui\" and/or \"admin-gui\" to these accounts. Accounts with the \"manager-gui\" role would have access to the \"manager\" application, and those with the \"admin-gui\" role would have access to the \"host-manager\" application.\rTo configure these accounts, follow the steps below:\rEdit the \rtomcat-users.xml\rfile in the \rtomcat/conf\rsubdirectory of your XAMPP installation directory (typically \rC:\\xampp\r) and add the line below, before the closing \r</tomcat-users>\relement:\r<user username=\"admin\" password=\"admin\" roles=\"manager-gui,admin-gui\" />\rThis configures an account with username \"admin\" and password \"admin\", with access to both the Apache Tomcat Web applications. Remember to replace the username and password with values specific to your installation.\rIf you prefer to have a separate account for each application, replace the previous configuration with this example:\r<user username=\"manager\" password=\"manager\" roles=\"manager-gui\" />\n<user username=\"admin\" password=\"admin\" roles=\"admin-gui\" />\rSave the changes.\rRestart the Apache Tomcat server using the XAMPP control panel.\rYou should now be able to access the Apache Tomcat Web applications using the configured credentials. Here&#8217;s an example of the management Web application, which includes controls to deploy new WAR applications.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(23,'2022-11-22 16:37:09','main','s1|/dashboard/docs/configure-vhosts.html',0,NULL,NULL,NULL,'/dashboard/docs/configure-vhosts.html','Configure Virtual Hosts','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nconfigure-vhosts.pdf\rConfigure Virtual Hosts\rApache makes it easy to have multiple websites or web applications running on the same physical server, and access each using a custom domain name. This is known as \rvirtual hosting\r, and each virtual host can be mapped to a different subdirectory of the server.\rThis feature is especially useful in development scenarios, as it allows developers to isolate and access different applications using unique domain names. For example, the domains \rhttp://app01.localhost\rand \rhttp://app02.localhost\rcould point to two separate applications on the same server. Or, you could create separate domains, such as \rhttp://client1/\r, \rhttp://client2/\rand so on, for multiple client websites hosted on the same server.\rVirtual hosts created in this manner will not be accessible from other systems, unless those systems are separately configured to associate the custom domain used by the virtual host with the IP address of the XAMPP server.\nThis guide walks you through the process of setting up a new virtual host with XAMPP, by creating and configuring an example host named \rwordpress.localhost\rfor a WordPress installation. It assumes that you have an existing WordPress installation at \rC:\\xampp\\apps\\wordpress\\htdocs\\\rand accessible via the URL \rhttp://localhost/wordpress\r.\nYou can install WordPress with just a few clicks using the \rBitnami WordPress Module for XAMPP\r.\nFollow the steps below to create a virtual host:\rChange to your XAMPP installation directory (typically, \rC:\\xampp\r) and open the \rhttpd-vhosts.conf\rfile in the \rapache\\conf\\extra\\\rsubdirectory using your favourite text editor.\rReplace the contents of this file with the following directives:\r<VirtualHost *:80>\nDocumentRoot \"C:/xampp/htdocs/\"\nServerName localhost\n</VirtualHost>\n<VirtualHost *:80>\nDocumentRoot \"C:/xampp/apps/wordpress/htdocs\"\nServerName wordpress.localhost\n</VirtualHost>\rThis contains two virtual host configuration blocks:\rThe first block is the default or fallback virtual host, which is used for all requests that are not matched by subsequent blocks.\rThe second block sets up a virtual host named \rwordpress.localhost\r. The DocumentRoot directive specifies the directory to be used when serving requests for this virtual host (in this case, the WordPress installation directory), while the ServerName directive specifies the custom domain name for the virtual host.\rTo add more virtual hosts, simply duplicate the second virtual host block and modify the port number, DocumentRoot and ServerName directives as per your requirements. For example, if you want to use SSL with your custom domain name, you can add a new virtual host block for port 443.\rIf you plan to have a large number of virtual hosts with very similar configuration, consider using wildcard-based subdomains with your virtual hosts.\nRestart Apache using the XAMPP control panel for your changes to take effect.\rAt this point, your virtual host is configured. However, if you try browsing to the \rwordpress.localhost\rdomain, your browser will show a failure notice, since this domain does not exist in reality. To resolve this, it is necessary to map the custom domain to the local IP address. To do this, open the file \rC:\\windows\\system32\\drivers\\etc\\hosts\rand add the following line to it:\r127.0.0.1 wordpress.localhost\rThis takes care of mapping the \rwordpress.localhost\rdomain name to the local machine, which always has the IP address 127.0.0.1.\rOn some versions of Windows, you will not be able to edit the \rC:\\windows\\system32\\drivers\\etc\\hosts\rfile without administrator privileges. You can edit the file by right-clicking the Notepad icon and selected the \"Run as administrator\" menu option, then entering administrator credentials (if required) and clicking \"OK\" or \"Yes\" to proceed.\nAt this point, you should be able to enter the URL \rhttp://wordpress.localhost\rin your browser&#8217;s address bar and see your WordPress installation. Here&#8217;s an example of what you should see:\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(24,'2022-11-22 16:37:10','main','s1|/dashboard/docs/configure-wildcard-subdomains.html',0,NULL,NULL,NULL,'/dashboard/docs/configure-wildcard-subdomains.html','Configure Wildcard-Based Subdomains','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nconfigure-wildcard-subdomains.pdf\rConfigure Wildcard-Based Subdomains\rApache&#8217;s virtual hosting feature makes it easy to host multiple websites or web applications on the same server, each accessible with a different domain name. However, when you have a large number of virtual hosts sharing almost-identical configuration, wildcard-based subdomains simplify maintenance and reduce the effort involved in adding a new virtual host.\rWith wildcard subdomains, it&#8217;s no longer necessary to edit the Apache configuration file or restart the server to initialize a new virtual host. Instead, you simply need to create a subdirectory matching the subdomain name on the server with your content, and Apache will automatically use that directory to serve requests for the corresponding subdomain.\rVirtual hosts created in this manner will not be accessible from other systems, unless those systems are separately configured to associate the custom domains used by virtual hosts with the IP address of the XAMPP server.\nThis guide walks you through the process of setting up wildcard virtual hosts with XAMPP, such that requests for \rsubdomain.localhost\rare automatically served by the \rsubdomain/\rdirectory of the main server document root. Follow the steps below:\n. Change to your XAMPP installation directory (typically, \rC:\\xampp\r) and open the \rhttpd.conf\rfile in the \rapache\\conf\\\rsubdirectory using your favourite text editor. Within the file, find the following line and uncomment it by removing the hash symbol (#) at the beginning of the line.\rLoadModule vhost_alias_module modules/mod_vhost_alias.so\rNext, edit the \rhttpd-vhosts.conf\rfile in the \rapache\\conf\\extra\\\rsubdirectory of your XAMPP installation directory.\rReplace the contents of this file with the following directives:\rUseCanonicalName Off\n<VirtualHost *:80>\nDocumentRoot \"C:/xampp/htdocs/\"\nServerName localhost\n</VirtualHost>\n<VirtualHost *:80>\nServerAlias *.localhost\nVirtualDocumentRoot \"C:/xampp/htdocs/%1/\"\n</VirtualHost>\rIn this configuration, the first virtual host block configures how requests are handled by default. The second block configures wildcard virtual hosting for subdomains, such that requests for \rsubdomain.localhost\rare automatically served by the \rsubdomain\\\rdirectory of the \rC:\\xampp\\htdocs\\\rdirectory. In particular, notice the %1 placeholder, which matches the subdomain name from the request URL.\rRestart Apache using the XAMPP control panel for your changes to take effect.\rAt this point, your wildcard subdomains are configured. You can easily test this by using the Windows Explorer to create two new subdirectories at \rC:\\xampp\\htdocs\\app01\\\rand \rC:\\xampp\\htdocs\\app02\\\r. Within each subdirectory, create a file named \rindex.html\rand fill it with some sample HTML content. Use different content for each file, so that you can easily distinguish that they&#8217;re being served from different directories - for example:\r<!-- index.html in app01 directory -->\n<html>\n<head></head>\n<body>\n<h1>Welcome to app01.localhost!</h1>\n</body>\n</html>\r<!-- index.html in app02 directory -->\n<html>\n<head></head>\n<body>\n<h1>Hello from app02.localhost!</h1>\n</body>\n</html>\rSince these domains do not actually exist in reality, you also need to map them to the local IP address. Open the file \rC:\\windows\\system32\\drivers\\etc\\hosts\rin a text editor and add the following line to it:\r127.0.0.1 app01.localhost app02.localhost\rYou will need to do this every time you want to configure a new wildcard virtual host, because the Windows \rhosts\rfile does not support wildcard entries. To avoid this step, you can use a DNS server or local DNS proxy that supports wildcards and therefore takes care of automatically resolving requests for \r*.localhost\rto the local IP address.\nOn some versions of Windows, you will not be able to edit the \rC:\\windows\\system32\\drivers\\etc\\hosts\rfile without administrator privileges. You can edit the file by right-clicking the Notepad icon and selected the \"Run as administrator\" menu option, then entering administrator credentials (if required) and clicking \"OK\" or \"Yes\" to proceed.\nAt this point, you should be able to enter the URLs \rhttp://app01.localhost\ror \rhttp://app02.localhost\rin your browser&#8217;s address bar, and you should then see the corresponding HTML page.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(25,'2022-11-22 16:37:09','main','s1|/dashboard/docs/create-framework-project-zf1.html',0,NULL,NULL,NULL,'/dashboard/docs/create-framework-project-zf1.html','Start a New Zend Framework 1 Project','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\ncreate-framework-project-zf1.pdf\rStart a New Zend Framework 1 Project\rXAMPP makes it easy to start developing with PHP, and \rZend Framework\ris one of the most popular PHP development frameworks. This guide walks you through the process of initializing a new Zend Framework 1 project with XAMPP.\rThis guide assumes that the new Zend Framework application will be accessible at the URL \rhttp://localhost/myapp/\r.\nDownload the latest version of the Zend Framework 1 minimal package\ras a ZIP archive.\rWithin your XAMPP installation directory (usually \rC:\\xampp\r), create a new directory named \rapps\\\r(if it doesn&#8217;t already exist). Then, within this new \rapps\\\rdirectory, create a directory to hold your Zend Framework application and its related XAMPP configuration files. In this example, call the directory \rmyapp\\\r.\rExtract the contents of the ZIP archive to the \rmyapp\\ directory. This will produce a _ZendFramework-[x.y]-minimal.zip\\\rsubdirectory in the \rmyapp\r\\ directory. Rename this newly-created subdirectory to \rhtdocs\r.\rThis new \rhtdocs\rdirectory will be the main working directory for your Zend Framework project.\nWithin the \rmyapp\\\rdirectory, create a new \rconf\\\rsubdirectory.\rWithin the new \rconf\r\\ subdirectory, use your text editor to create and populate a file named \rttpd-prefix.conf\rwith the following content:\rAlias /myapp/ \"C:/xampp/apps/myapp/htdocs/public/\"\nAlias /myapp \"C:/xampp/apps/myapp/htdocs/public\"\nInclude \"C:/xampp/apps/myapp/conf/httpd-app.conf\"\rWithin the \rconf\r\\ subdirectory, also create and populate a file named \rhttpd-app.conf\rwith the following content:\r<Directory C:/xampp/apps/myapp/htdocs/public>\nOptions +FollowSymLinks\nAllowOverride All\nRequire all granted\n</Directory>\rEdit the \rhttpd-xampp.conf\rfile in the \rapache\\conf\\extra\\\rsubdirectory of your XAMPP installation directory and add the following line at the end to include the \rhttpd-prefix.conf\rfile created earlier.\rInclude \"C:/xampp/apps/myapp/conf/httpd-prefix.conf\"\rRemember to update the above file and directory paths so that they&#8217;re valid for your system.\nLaunch a new Windows command shell using the \"Shell\" button in the XAMPP control panel.\rWithin the command shell, change to the \rmyapp\\htdocs\\\rdirectory and run the following commands to create a new stub project.\rbin\\zf.bat create project .\rCheck that you have a directory structure like this:\rRestart the Apache server using the XAMPP control panel.\rYou should be able to access the Zend Framework skeleton application by browsing to \rhttp://localhost/myapp\r. Here&#8217;s what the default welcome page looks like:\rYou can now begin developing your Zend Framework application by modifying the skeleton application code. For more information, \rrefer to the Zend Framework documentation\r.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(26,'2022-11-22 16:37:10','main','s1|/dashboard/docs/create-framework-project-zf2.html',0,NULL,NULL,NULL,'/dashboard/docs/create-framework-project-zf2.html','Start a New Zend Framework 2 Project','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\ncreate-framework-project-zf2.pdf\rStart a New Zend Framework 2 Project\rXAMPP makes it easy to start developing with PHP, and \rZend Framework 2\ris one of the most popular PHP development frameworks. This guide walks you through the process of initializing a new Zend Framework 2 project with XAMPP.\rThis guide assumes that you have already downloaded and installed Git for Windows, and that the git binary is in your Windows PATH. If you don&#8217;t have Git for Windows, you can \rdownload and install it from here\r. It also assumes that the new Zend Framework 2 application will be accessible at the URL \rhttp://localhost/myapp/\r.\nFollow these steps:\rDownload the Zend Framework 2 skeleton application\ras a ZIP archive from Github.\rWithin your XAMPP installation directory (usually \rC:\\xampp\r), create a new directory named \rapps\\\r(if it doesn&#8217;t already exist). Then, within this new \rapps\\\rdirectory, create a directory to hold your Zend Framework 2 application and its related XAMPP configuration files. In this example, call the directory \rmyapp\\\r.\rExtract the contents of the ZIP archive to the \rmyapp\\\rdirectory. This will produce a \rzendframework-ZendSkeletonApplication-[xx]\\\rsubdirectory in the \rmyapp\\\rdirectory. Rename this newly-created subdirectory to \rhtdocs\r.\rThis new \rhtdocs\rdirectory will be the main working directory for your Zend Framework 2 project.\nWithin the \rmyapp\\\rdirectory, create a new \rconf\\\rsubdirectory.\rWithin the new \rconf\\\rsubdirectory, use your text editor to create and populate a file named \rhttpd-prefix.conf\rwith the following content:\rAlias /myapp/ \"C:/xampp/apps/myapp/htdocs/public/\"\nAlias /myapp \"C:/xampp/apps/myapp/htdocs/public\"\nInclude \"C:/xampp/apps/myapp/conf/httpd-app.conf\"\rWithin the \rconf\\\rsubdirectory, also create and populate a file named \rhttpd-app.conf\rwith the following content:\r<Directory C:/xampp/apps/myapp/htdocs/public>\nOptions +FollowSymLinks\nAllowOverride All\nRequire all granted\n</Directory>\rEdit the \rhttpd-xampp.conf\rfile in the \rapache\\conf\\extra\\\rsubdirectory of your XAMPP installation directory and add the following line at the end to include the \rhttpd-prefix.conf\rfile created earlier.\rInclude \"C:/xampp/apps/myapp/conf/httpd-prefix.conf\"\rRemember to update the above file and directory paths so that they&#8217;re valid for your system.\nCheck that you have a directory structure like this:\rRestart the Apache server using the XAMPP control panel.\rLaunch a new Windows command shell using the \"Shell\" button in the XAMPP control panel.\rWithin the command shell, change to the \rmyapp\\htdocs\\\rdirectory and run the following commands to update \rComposer\r(the PHP dependency manager) and install the Zend Framework 2 components.\rphp composer.phar self-update\nphp composer.phar install\rHere&#8217;s an example of what you might see as Composer downloads and installs dependencies.\rOnce Composer is done, you should be able to access the Zend Framework 2 skeleton application by browsing to \rhttp://localhost/myapp\r. Here is an example of the default welcome page you should see:\rYou can now begin developing your Zend Framework 2 application by modifying the skeleton application code. For more information, \rrefer to the Zend Framework 2 User Guide\r.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(27,'2022-11-22 16:37:09','main','s1|/dashboard/docs/deploy-git-app.html',0,NULL,NULL,NULL,'/dashboard/docs/deploy-git-app.html','Deploy an Application Using Git','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\ndeploy-git-app.pdf\rDeploy an Application Using Git\rGit\ris a popular distributed version control system. As you work with XAMPP, you might often find yourself needing to download and install applications or code libraries from a developer&#8217;s public git repository.\rThis guide walks you through the process, showing you how to use a git client to transfer code from a public online git repository to your XAMPP server. As an example, this guide assumes that you wish to download the latest version of \rSlim\r, a popular PHP micro-framework for Web application development that also has its own Github repository.\nNOTE: This guide uses \rGit Extensions\r, an open source git client that&#8217;s available for Windows, Linux and Mac OS, and assumes that you have already downloaded and installed this software. If you don&#8217;t already have this, you can \rdownload it from the official Git Extensions website\r, and \rinstall it using these instructions\r.\rTo download Slim (or any other application) from its git repository, follow these steps:\rEnsure that your Apache server is running.\rObtain the repository&#8217;s clone URL. On Github, this can be easily obtained by visiting the project&#8217;s Github page and copying the clone URL from the right side of the page. For third-party or private git repositories, you can obtain the clone URL by asking the project team directly. Make a note of the clone URL, as you&#8217;ll need it in subsequent steps.\rLaunch Git Extensions by double-clicking the icon in the Windows Start menu or Start screen.\rClick the \"Clone repository\" link or use the \"Start &#8594; Clone repository&#8230;&#8203;\" menu item.\rIn the resulting \"Clone\" dialog box, enter the clone URL obtained in the first step. Set the destination directory to the \rhtdocs\\\rsubdirectory of your XAMPP installation directory (typically, \rC:\\xampp\r). Optionally, change the name of the subdirectory that will hold the downloaded code.\rClick the \"Clone\" button to start cloning the repository. Git Extensions will display a progress dialog as it downloads the code from the source repository.\rOnce the repository has been cloned, Git Extensions will prompt you to open the new repository. Click \"Yes\".\rYou should now see the entire commit history of the repository in a graphical tree structure, together with details on the changes made in each commit.\rAt this point, the code has been downloaded from the remote git repository and you can begin using it. In this particular case, since the Slim framework includes a starter application, you can simply browse to the URL \rhttp://localhost/Slim\rand you should see the example application&#8217;s welcome page, as shown below.\rYou can use Git Extensions to create a new branch of the codebase should you wish to make any changes to it. Any changes you make will be automatically reflected in the Git Extensions interface, and if you have appropriate privileges, you can also commit your changes back to the remote repository. \rLearn more about git\r, or \rread the Git Extensions documentation\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(28,'2022-11-22 16:37:09','main','s1|/dashboard/docs/increase-php-file-upload-limit.html',0,NULL,NULL,NULL,'/dashboard/docs/increase-php-file-upload-limit.html','Increase the PHP File Upload Limit','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nincrease-php-file-upload-limit.pdf\rIncrease the PHP File Upload Limit\rTo increase the allowed file size for uploads through PHP, follow these steps:\rEdit the \rphp.ini\rfile in the \rphp/\rsubdirectory of your XAMPP installation directory (usually, \rC:\\xampp\r). Within this file, find the \rpost_max_size\rand \rupload_max_filesize\rvariables and change them to reflect the new file upload limit. For example, to restrict uploads to not more than 16M, change these variables as shown below:\r; Maximum size of POST data that PHP will accept.\n; http://php.net/post-max-size\npost_max_size=16M\n...\n; Maximum allowed size for uploaded files.\n; http://php.net/upload-max-filesize\nupload_max_filesize=16M\rSave your changes to the file.\rRestart the Apache server.\rThe new file upload limit will now come into effect.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(29,'2022-11-22 16:37:10','main','s1|/dashboard/docs/reset-mysql-password.html',0,NULL,NULL,NULL,'/dashboard/docs/reset-mysql-password.html','Reset the MySQL/MariaDB Root Password','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nreset-mysql-password.pdf\rReset the MySQL/MariaDB Root Password\rBy default, the MySQL/MariaDB installation that ships with XAMPP has an empty root password. This is a serious security risk, especially if you plan to use XAMPP in production scenarios.\rTo change the MySQL/MariaDB root password, follow these steps:\rEnsure that the MySQL/MariaDB server is running.\rOpen your Windows command prompt by clicking the \"Shell\" button in the XAMPP control panel.\rUse the \rmysqladmin\rcommand-line utility to alter the MySQL/MariaDB password, using the following syntax:\rmysqladmin --user=root password \"newpassword\"\rFor example, to change the MySQL/MariaDB root password from its default empty value to the password \rgue55me\r, you would execute:\rmysqladmin --user=root password \"gue55me\"\rOr, if a password has already been previously set and you&#8217;d like to change it to a new one, you can use the following syntax:\rmysqladmin --user=root --password=oldpassword password \"newpassword\"\rFor example, to change the root password from \r12345\rto \rgue55me\r, you would execute:\rmysqladmin --user=root --password=12345 password \"gue55me\"\rTest that your password change has been accepted, by attempting to connect to the MySQL/MariaDB server using the \rmysql\rcommand-line client in the same directory. For example, you could use the command below to connect to the server and return the results of a calculation:\rmysql --user=root --password=gue55me -e \"SELECT 1+1\"\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(30,'2022-11-22 16:37:09','main','s1|/dashboard/docs/send-mail.html',0,NULL,NULL,NULL,'/dashboard/docs/send-mail.html','Send Mail with PHP','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nsend-mail.pdf\rSend Mail with PHP\rIf you&#8217;re a PHP application developer, you might need to send email notifications through your custom PHP applications. With XAMPP, there are two ways to do this: you can use the included \rsendmail.exe\rbinary, or you can use the third-party \rPHPMailer\rclass. This guide walks you through both options.\rThis guide assumes that you have an existing Gmail account, and that you will use Gmail&#8217;s SMTP server to transmit email. You can also use your organization or ISP&#8217;s mail server, although you&#8217;ll need to replace key details, such as the SMTP server name and port, with appropriate values for your environment. Your network administrator or ISP support desk will typically be able to provide this information. The example code provided in this tutorial is illustrative only and should not be used in production environments.\nTo configure XAMPP to use \rsendmail.exe\rfor email notifications, follow these steps:\rEdit the \rphp.ini\rfile in the \rphp\\\rsubdirectory of your XAMPP installation directory (usually, \rC:\\xampp\r). Within this file, find the [mail function] section and replace it with the following directives:\rsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\rEdit the \rsendmail.ini\rfile in the \rsendmail\\\rsubdirectory of your XAMPP installation directory. Within this file, find the [sendmail] section and replace it with the following directives:\rsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\rRemember to replace the dummy values shown with your actual Gmail address and account password.\rRestart the Apache server using the XAMPP control panel.\rYou can now use PHP&#8217;s \rmail()\rfunction to send email from your application. To illustrate how it can be used with your Gmail account, use your text editor to create an example script named \rsendmail.php\rin the \rhtdocs\\\rsubdirectory and fill it with the following code. Once done, save your changes.\r<?php\n$to = \'recipients@email-address.com\';\n$subject = \'Hello from XAMPP!\';\n$message = \'This is a test\';\n$headers = \"From: your@email-address.com\\r\\n\";\nif (mail($to, $subject, $message, $headers)) {\necho \"SUCCESS\";\n} else {\necho \"ERROR\";\n}\rRemember to replace the dummy values shown with valid email addresses. For this simple test, use your own email address as the recipient address.\rNow, browse to the URL \rhttp://localhost/sendmail.php\rto execute the script and send the email message. If all goes well, you should see a success notification in your browser. If you used your own email address for the recipient address, you should also receive the email message.\rTo configure XAMPP to use PHPMailer for email notifications, follow these steps:\rDownload PHPMailer from its Github repository using the \"Download Zip\" button.\rCreate a directory for your new application within the \rhtdocs\\\rsubdirectory of your XAMPP installation directory. In this tutorial, the application directory is named \rexample\\\r.\rExtract the contents of the PHPMailer ZIP archive to the application directory.\rYou can now use PHPMailer to send email from your application. To illustrate how it can be used with your Gmail account, use your text editor to create an example script named \rphpmailer.php\rin the application directory, and fill it with the following code. Once done, save your changes.\r<?php\nrequire \'PHPMailer-master/PHPMailerAutoload.php\';\n$mail = new PHPMailer;\n$mail->isSMTP();\n$mail->SMTPSecure = \'ssl\';\n$mail->SMTPAuth = true;\n$mail->Host = \'smtp.gmail.com\';\n$mail->Port = 465;\n$mail->Username = \'your-gmail-username@gmail.com\';\n$mail->Password = \'your-gmail-password\';\n$mail->setFrom(\'your@email-address.com\');\n$mail->addAddress(\'recipients@email-address.com\');\n$mail->Subject = \'Hello from PHPMailer!\';\n$mail->Body = \'This is a test.\';\n//send the message, check for errors\nif (!$mail->send()) {\necho \"ERROR: \" . $mail->ErrorInfo;\n} else {\necho \"SUCCESS\";\n}\rRemember to replace the dummy values shown with your actual Gmail address and account password. You should also use a valid sender and recipient address. For this simple test, use your own email address as the recipient address.\rNow, browse to the URL \rhttp://localhost/example/phpmailer.php\r. This should execute the script and send the email message. If all goes well, you should see a success notification in your browser. If you used your own email address for the recipient address, you should also receive the email message.\rAs a security precaution, Gmail will automatically rewrite the From: and Reply-to: headers in your email message to reflect your Gmail address. If you want to avoid this, you must add and validate your custom email address in your Gmail account as a sender. Refer to \rGmail&#8217;s documentation for more information and important restrictions\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(31,'2022-11-22 16:37:10','main','s1|/dashboard/docs/transfer-files-ftp.html',0,NULL,NULL,NULL,'/dashboard/docs/transfer-files-ftp.html','Configure FTP Access','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\ntransfer-files-ftp.pdf\rConfigure FTP Access\rXAMPP includes the server version of \rFileZilla\r, an open-source FTP solution. This makes it easy to transfer files to and from a XAMPP environment using FTP.\rTo illustrate, assume that you have a simple PHP script named \rexample.php\ron your Windows desktop containing the following code, that you wish to transfer to the XAMPP server.\r<!-- example.php -->\n<html>\n<head></head>\n<body>\n<h2><?php echo \"Hello. Today is \" . date(\'l\'); ?>.</h2>\n</body>\n</html>\rTo transfer files using FTP, you must first configure the FileZilla FTP server. Follow the steps below.\rEnsure that FileZilla is running.\rStart the FileZilla administration interface by clicking the \"Admin\" button in the XAMPP control panel.\rIn the resulting \"Connect to Server\" dialog box, leave all values at their default values and click \"OK\".\rYou should now arrive at the FileZilla server console.\rYou now need to set up at least one FTP user. To do this, click the \"Edit &#8594; Users\" menu item. This will bring you to the user management interface.\rClick the \"Add\" button to add a new user account. Enter a name for the new user account.\rSelect and check the \"Password\" field and enter a password for the new user.\rNext, you need to define which folders the user has access to. To do this, click the \"Shared folder\" sub-item in the left navigation menu.\rClick the \"Add\" button and select the \rhtdocs\\\rsubdirectory of the XAMPP installation directory as the user&#8217;s home directory.\rGrant the user all available rights to this directory.\rClick \"OK\" to save your changes.\rUse the \"File &#8594; Quit\" menu item to disconnect from the FileZilla administration interface.\rYou can now transfer files to the XAMPP server by following the steps below:\rLaunch your FTP client and enter connection details as below.\rIf you’re connecting to the server from the same system, use \"127.0.0.1\" as the host address. If you’re connecting from a different system, use the network hostname or IP address of the XAMPP server.\rUse \"21\" as the port.\rSpecify the username and password configured previously as your FTP credentials.\rYour FTP client should now connect to the server and enter the \rC:\\xampp\\htdocs\rdirectory, which is the default Web server document root.\rTransfer the file from your home directory to the server using normal FTP transfer conventions. If you’re using a graphical FTP client, you can usually drag and drop the file from one directory to the other. If you’re using a command-line FTP client, you can use the FTP PUT command.\rOnce the file is successfully transferred, you should be able to see it in action by browsing to \rhttp://localhost/example.php\r, as shown below:\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(32,'2022-11-22 16:37:10','main','s1|/dashboard/docs/troubleshoot-apache.html',0,NULL,NULL,NULL,'/dashboard/docs/troubleshoot-apache.html','Troubleshoot Apache Startup Problems','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\ntroubleshoot-apache.pdf\rContents\rPort 80 in use by PID 4\rPorts 80 and 443 in use by Skype\rPort 443 in use by VMWare\rServerRoot Must Be a Valid Directory\rXAMPP cannot start on port 80 (Windows 10)\rThe Microsoft Edge browser cannot be used to access local addresses using the machine host name.\rTroubleshoot Apache Startup Problems\rAre you having difficulty getting your Apache server started? Here is a list of common problems and their solutions.\rThe information in this document is based on \rthis ApacheFriends community forum thread\r.\nPort 80 in use by PID 4\rYour XAMPP control panel displays this message:\rXX:XX:XX [Apache] Port 80 in use by \"Unable to open process\" with PID 4!\rTo solve this problem, follow these steps:\rRight-click the XAMPP control panel icon and select \"Run as administrator\". Enter administrator credentials (if required) and click \"OK\" or \"Yes\" to proceed.\rOpen your Windows command prompt by clicking the \"Shell\" button in the XAMPP control panel.\rAt the command prompt, enter this command:\rnetsh http add iplisten ipaddress=::\rOpen the file \rC:\\Windows\\system32\\drivers\\etc\\hosts\rand add the following line to it. Then, save the file.\r127.0.0.1 localhost\rThis takes care of mapping the \rlocalhost\rdomain name to the local machine, which always has the IP address 127.0.0.1.\rOn some versions of Windows, you will not be able to edit the \rC:\\Windows\\system32\\drivers\\etc\\hosts\rfile without administrator privileges. You can edit the file by right-clicking the Notepad icon and selected the \"Run as administrator\" menu option, then entering administrator credentials (if required) and clicking \"OK\" or \"Yes\" to proceed.\nIf the problem persists even after performing these steps, it could be due to a problem with Microsoft Internet Information Services (IIS), with Windows Work Folders or with third-party services. \rRefer to this page for alternative solutions\r.\nPorts 80 and 443 in use by Skype\rYour XAMPP control panel displays these messages:\rXX:XX:XX [Apache] Port 80 in use by \"C:\\Program Files (x86)\\Skype\\Phone\\Skype.exe\" with PID XXXX!\nXX:XX:XX [Apache] Port 443 in use by \"C:\\Program Files (x86)\\Skype\\Phone\\Skype.exe\" with PID XXXX!\rTo solve this problem, follow these steps:\rLaunch Skype.\rSelect the \"Tools &#8594; Options &#8594; Advanced &#8594; Connection\" menu item and in the resulting screen, disable the use of ports 80 and 443 for incoming Skype connections.\rClick \"Save\". Restart Skype for your change to take effect.\rPort 443 in use by VMWare\rYour XAMPP control panel displays these messages:\rXX:XX:XX [Apache] Port 443 in use by \"\"C:\\Program Files (x86)\\VMware\\VMware Workstation\\vmware-hostd.exe\" -u \"C:\\ProgramData\\VMware\\hostd\\config.xml\"\" with PID XXXX!\rTo solve this problem, follow these steps:\rLaunch VMWare Workstation.\rUse the \"Edit &#8594; Preferences &#8594; Shared VMs\" menu and in the resulting dialog, enter a new port number for the VMWare Workstation Server.\rClick \"OK\" to save your changes. Restart VMWare Workstation for your change to take effect.\rServerRoot Must Be a Valid Directory\rApache startup includes an error message like the one below:\rhttpd.exe: Syntax error on line XX of X:/xampp/apache/conf/httpd.conf: ServerRoot must be a valid directory\rThis is a common issue for XAMPP installations on portable devices. It occurs if the Apache configuration file points to a directory that no longer exists (for example, due to a drive letter change when a portable device is removed and reinserted). To solve this problem, follow these steps:\rIf the Apache service is registered (indicated by a green check mark next to its name in the XAMPP control panel), unregister it by clicking the check mark and answering \"Yes\" in the resulting dialog box.\rEdit the \rsetup_xampp.bat\rfile in your XAMPP installation directory (usually, \rC:\\xampp\r). Within the file, find this line:\r%PHP_BIN% -n -d output_buffering=0 %CONFIG_PHP%\rEdit the line to include the special directive \"usb\" at the end, so that it looks like this.\r%PHP_BIN% -n -d output_buffering=0 %CONFIG_PHP% usb\rSave your changes. The, execute the file by double-clicking it in the Windows Explorer or executing it at the command prompt. This will fix any and all wrong base paths.\rXAMPP cannot start on port 80 (Windows 10)\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo check whether port 80 is in use, open a command prompt and run these commands:\rnetstat -o -n -a | findstr 0.0.0.0:80\nnetstat -o -n -a | findstr 127.0.0.1:80\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \"World Wide Web Publishing Service\" and select it.\rClick the link to \"Stop the service\".\rDouble-click the service name.\rIn the \"Startup type\" field, change the startup type to \"Disabled\".\rClick \"OK\" to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rThe Microsoft Edge browser cannot be used to access local addresses using the machine host name.\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as \rhttp://myhost\rin Microsoft Edge. To resolve this, you should instead use the addresses \rhttp://127.0.0.1\ror \rhttp://localhost\r.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(33,'2022-11-22 16:37:10','main','s1|/dashboard/docs/use-different-php-version.html',0,NULL,NULL,NULL,'/dashboard/docs/use-different-php-version.html','Use a Different PHP Version','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nuse-different-php-version.pdf\rUse a Different PHP Version\rIn many cases, you might want to use XAMPP with a different PHP version than the one that comes pre-installed. You might do this to get the benefits of a newer version of PHP, or to reproduce bugs using an earlier version of PHP.\rTo use a different version of PHP with XAMPP, follow these steps:\rDownload a binary build of the PHP version that you wish to use from the PHP website, and extract the contents of the compressed archive file to your XAMPP installation directory (usually, \rC:\\xampp\r). Ensure that you give it a different directory name to avoid overwriting the existing PHP version. For example, in this tutorial, we&#8217;ll call the new directory \rC:\\xampp\\php5-6-0\r.\rEnsure that the PHP build you download matches the Apache build (VC9 or VC11) in your XAMPP platform.\nWithin the new directory, rename the \rphp.ini-development\rfile to \rphp.ini\r. If you prefer to use production settings, you could instead rename the \rphp.ini-production\rfile to \rphp.ini\r.\rEdit the \rhttpd-xampp.conf\rfile in the \rapache\\conf\\extra\\\rsubdirectory of your XAMPP installation directory. Within this file, search for all instances of the old PHP directory path and replace them with the path to the new PHP directory created in Step 1.\rIn particular, be sure to change the lines\rLoadFile \"/xampp/php/php5ts.dll\"\nLoadFile \"/xampp/php/libpq.dll\"\nLoadModule php5_module \"/xampp/php/php5apache2_4.dll\"\rto\rLoadFile \"/xampp/php5-6-0/php5ts.dll\"\nLoadFile \"/xampp/php5-6-0/libpq.dll\"\nLoadModule php5_module \"/xampp/php5-6-0/php5apache2_4.dll\"\rRemember to adjust the file and directory paths above to reflect valid paths on your system.\nRestart your Apache server through the XAMPP control panel for your changes to take effect.\rThe new version of PHP should now be active. To verify this, browse to the URL \rhttp://localhost/xampp/phpinfo.php\r, which displays the output of the \rphpinfo()\rcommand, and check the version number at the top of the page.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(34,'2022-11-22 16:37:10','main','s1|/dashboard/docs/use-php-fcgi.html',0,NULL,NULL,NULL,'/dashboard/docs/use-php-fcgi.html','Run PHP under FastCGI','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nuse-php-fcgi.pdf\rRun PHP under FastCGI\rBy default, XAMPP runs PHP as an Apache handler. An alternative approach is to run PHP under FastCGI, which can produce better performance in certain scenarios. To do this, follow these steps:\rDownload a binary version of the \rmod_fcgid\rApache module from \rthe ApacheLounge website\r. This module is included in the \rmodules-2.4.x-win32-VC11.zip\rarchive.\rXAMPP for Windows only uses 32-bit Apache builds.\nExtract the \rmod_fcgid.so\rfile from the downloaded archive file and copy it to the \rapache\\modules\r\\ subdirectory of your XAMPP installation directory (usually, \rC:\\xampp\r).\rEdit the \rhttpd-xampp.conf\rfile in the \rapache\\conf\\extra\\\rsubdirectory of your XAMPP installation directory. Within this file, make the following changes:\rSearch for the line\rLoadModule php5_module \"/xampp/php/php5apache2_4.dll\"\rand modify it to read\rLoadModule fcgid_module modules/mod_fcgid.so\rFind and delete the following lines:\r<FilesMatch \"\\.php$\">\nSetHandler application/x-httpd-php\n</FilesMatch>\n<FilesMatch \"\\.phps$\">\nSetHandler application/x-httpd-php-source\n</FilesMatch>\rAdd the following lines:\rFcgidInitialEnv PHPRC \"c:/xampp/php\"\nAddHandler fcgid-script .php\nFcgidWrapper \"c:/xampp/php/php-cgi.exe\" .php\rRemember to adjust the file and directory paths above to reflect valid paths on your system.\nRestart your Apache server through the XAMPP control panel for your changes to take effect.\rPHP should now be active using FastCGI. To verify this, browse to the URL \rhttp://localhost/xampp/phpinfo.php\r, which displays the output of the \rphpinfo()\rcommand, and check the \"Server API\" value near the top of the page.\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(35,'2022-11-22 16:37:10','main','s1|/dashboard/docs/use-sqlite.html',0,NULL,NULL,NULL,'/dashboard/docs/use-sqlite.html','Use SQLite and PHP','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rDocumentation\rDownload PDF\nuse-sqlite.pdf\rUse SQLite and PHP\rXAMPP comes with built-in support for SQLite, making it easy to get started building database-powered applications with PHP. This guide will walk you through the process of creating and populating a new SQLite database using XAMPP, then accessing the data within it using PHP.\rBegin by creating and populating a new database using the SQLite command-line client, as below:\rOpen your Windows command prompt by clicking the “Shell” button in the XAMPP control panel.\rChange to the \rhtdocs\\\rsubdirectory of your XAMPP installation directory (typically \rC:\\xampp\r) and create a new SQLite database file named \rmydb.sq3\rwith the SQLite command-line client:\rcd C:\\xampp\\htdocs\nsqlite3 mydb.sq3\rYou should now see an SQLite prompt, as below:\rAt the \rsqlite>\rprompt, create a new table to hold your data. In this example, the table is named items and it contains 3 columns, for item ID, item name and item cost. You can use standard CREATE TABLE syntax to create the table, and you can \rlearn more about SQLite&#8217;s built-in datatypes here\r.\rCREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT, price REAL);\rAdd some data to the new inventory table using INSERT commands, as shown below:\rINSERT INTO items VALUES (\'1001\', \'Salt\', 3.15);\nINSERT INTO items VALUES (\'1002\', \'Pepper\', 2.75);\nINSERT INTO items VALUES (\'1003\', \'Eggs\', 2.00);\nINSERT INTO items VALUES (\'1004\', \'Bacon\', 7.25);\nINSERT INTO items VALUES (\'1005\', \'Milk\', 1.15);\nINSERT INTO items VALUES (\'1006\', \'Strawberries\', 8.73);\nINSERT INTO items VALUES (\'1007\', \'Cereal\', 2.65);\rYou can now also run a SELECT query on the data. For example, the query below returns all items that cost less than $3:\rSELECT * FROM items WHERE price < 3.00;\rOnce you&#8217;re done using the database, exit it by typing \r.quit\rat the \rsqlite>\rprompt.\rThe database file (in this example, \rmydb.sq3\r) contains all your tables and data, so you should remember to back it up regularly.\nThe previous steps discussed how to create and use an SQLite database using the command-line client. However, more often than not, you&#8217;ll be using an SQLite database in combination with a PHP-powered Web application. XAMPP includes the PHP SQLite extension, so doing this is not very difficult at all.\rTo connect to your SQLite database and execute queries on it with PHP, use your text editor to create an example script named \rsqlite.php\rin the \rhtdocs\rsubdirectory of your XAMPP installation directory and fill it with the following code:\r<?php\n$db = new SQLite3(\'mydb.sq3\');\n$sql = \"SELECT * FROM items WHERE price < 3.00\";\n$result = $db->query($sql);\nwhile ($row = $result->fetchArray(SQLITE3_ASSOC)){\necho $row[\'name\'] . \': $\' . $row[\'price\'] . \'<br/>\';\n}\nunset($db);\rThe first line of code creates a new SQLite3 object, using the \rmydb.sq3\rdatabase file you created earlier. Then, the object&#8217;s \rquery()\rmethod is used to execute a SELECT query on the database, and the result object&#8217;s \rfetchArray()\rmethod is used to iterate over the result set. Adding the SQLITE3_ASSOC parameter to the \rfetchArray()\rmethod tells PHP to return the results as an associative array, making it easy to access individual fields of the result set and display them on a Web page.\rOnce done, save your changes and ensure that your Apache server is running. Then, browse to \rhttp://localhost/sqlite.php\rto execute the script. You should see something like this:\rTo find out more about SQLite’s powerful features, \rread the SQLite documentation\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(36,'2022-11-22 16:37:11','main','s1|/dashboard/es/faq.html',0,NULL,NULL,NULL,'/dashboard/es/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rPreguntas frecuentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rPreguntas frecuentes\r¿Cómo instalo XAMPP?\rExisten tres tipos diferentes de XAMPP para Windows:\rInstalador:\rProbablemente la forma más fácil de instalar XAMPP.\rZIP:\rPara puristas: XAMPP como archivo ZIP.\r7zip:\rPara puristas con ancho de banda bajo: XAMPP como archivo 7zip.\rNota: Si extraes los ficheros, puede haber falsos avisos de virus.\rUsando el instalador:\rEl panel de control de XAMPP para iniciar/detener Apache, MySQL, FileZilla y Mercury o instalar esos servidores como servicios.\rInstalando desde ZIP\rDescomprime los archivos zip en la carpeta que elijas. XAMPP es extraido en el subdirectorio \"C:\\\\xampp\" en el directorio de destino seleccionado. Ahora ejecuta el fichero \"setup_xampp.bat\" para ajustar la configuración de XAMPP en tu sistema.\rSi elijes un directorio raíz, como \"C:\\\\\", no debes ejecutar \"setup_xampp.bat\".\rAl igual que con el instalador, puedes usar ahora el \"XAMPP Control Panel\" para tareas adicionales.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\r¿Cómo inicio XAMPP sin instalar?\rSi extraes XAMPP en un directorio principal como \"C:\\\\\" o \"D:\\\\\", puedes iniciar la mayoría de los servidores como Apache o MySQL directamente sin ejecutar el archivo \"setup_xampp.bat\".\rNo usar el script de instalación, o seleccionar paths relativos en el script de instalación, es preferible si estás instalando XAMPP en un disco duro USB, debido a que en cada ordenador ese dispositivo puede estar en una unidad distinta. Puedes cambiar de paths absolutos a relativos cuando quieras con el script de instalación.\rUsar el instalador de nuestra página de Descargas es la forma más fácil de instalar XAMPP. Cuando la instalación se complete, encontrarás XAMPP en Inicio | Programas | XAMPP. Puedes usar el Panel de Control de XAMPP para iniciar/parar todos los servidores y también para instalar/desinstalar servicios.\rEl panel de control de XAMPP para iniciar/detener Apache, MySQL, FileZilla y Mercury o instalar esos servidores como servicios.\r¿Cómo inicio y paro XAMPP?\rEl Centro de Control principal es el \"XAMPP Control Panel\" (gracias www.nat32.com). Se inicia con:\r\\xampp\\xampp-control.exe\rPuedes también usar algunos ficheros batch para iniciar/parar servidores:\rIniciar Apache y MySQL:\n\\xampp\\xampp_start.exe\rParar Apache y MySQL:\n\\xampp\\xampp_stop.exe\rIniciar Apache:\n\\xampp\\apache_start.bat\rDetener Apache:\n\\xampp\\apache_stop.bat\rIniciar MySQL:\n\\xampp\\mysql_start.bat\rPara MySQL:\n\\xampp\\mysql_stop.bat\rIniciar Mercury Mailserver:\n\\xampp\\mercury_start.bat\rParar Mercury Mailserver:\n\\xampp\\mercury_stop.bat\rIniciar Servidor FileZilla:\n\\xampp\\filezilla_start.bat\rParar Servidor FileZilla:\n\\xampp\\filezilla_stop.bat\r¿Cómo compruebo que todo ha ido bien?\rEscribe la siguiente URL en tu navegador favorito:\rhttp://localhost/\ro \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\r¿Cómo puedo instalar un servidor como servicio?\rPuedes instalar cada servidor en XAMPP como servicio de Windows. También puedes instalarlo desde el Panel de Control de XAMPP. En este caso, es necesario ejecutar los scripts o el Panel de Control con privilegios de Administrador.\rInstalar el servicio Apache: \\\\xampp\\\\apache\\\\apache_installservice.bat\rDesinstalar el servicio Apache: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rInstalar el servicio MySQL: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rDesinstalar el servicio MySQL: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \r(Des)instalación del servicio FileZilla: \\\\xampp\\\\filezilla_setup.bat \rMercury: No disponible la instalación de servicio\r¿Está XAMPP listo para producción?\rXAMPP no está pensado para uso en producción, sino para entornos de desarrollo. XAMPP está configurado de forma que sea tan abierto como sea posible, permitiendo al desarrollador hacer lo que quiera. En entornos de desarrollo esto es magnífico pero en un entorno de producción puede ser fatal.\rA continuación se muestra una lista de posibles fallos de seguridad en XAMPP:\rEl administrador de MySQL (root) no tiene password.\rEl proceso MySQL está accesible a través de la red.\rProFTPD usa la contraseña \"lampp\" para el usuario \"daemon\".\rLos usuarios por defecto de Mercury y FileZilla son conocidos.\rTodo esto puede ser un enorme riesgo de seguridad. Especialmente si XAMPP está accesible a través de la red y gente fuera de tu LAN. Para mejorar la seguridad, puede ayudar el uso de un firewall o un router (NAT). En el caso de un router o firewall, tu PC no estará normalmente accesible a través de la red. Depende de ti arreglar estos problemas. Una pequeña ayuda es la \"Consola de Seguridad de XAMPP\".\rPor favor, establece seguridad en XAMPP antes de publicar nada online. Un firewall o un router sólo son correctos para bajos niveles de seguridad. Para algo más de seguridad, puedes ejecutar la \"Consola de Seguridad de XAMPP\" y asignar contraseñas.\rSi quieres tener tu XAMPP accesible desde internet, ve a la siguiente URI que puede arreglar algunos problemas:\rhttp://localhost/security/\rCon la consola de seguridad puedes establecer una contraseña para el usuario \"root\" de MySQL y phpMyAdmin. Puedes también habilitar autenticación para las páginas de ejemplo de XAMPP.\r¡Esta herramienta web no corrige ningún problema adicional de seguridad! Especialmente, debes establecer tu propia seguridad en los servidores FileZilla FTP y Mercury.\r¿Cómo desinstalo XAMPP?\rSi instalaste XAMPP usando la versión de instalador, por favor, usa el desinstalador. El desinstalador eliminará todas las entradas de XAMPP de tu registro y desinstalará algunos servicios incluidos con XAMPP. Recomendamos fervientemente que uses el programa de desinstalación para eliminar las instalaciones de XAMPP realizadas con el instalador. Por favor, haz copia de seguridad de todos los datos que quieras mantener antes de desinstalar XAMPP.\rSi instalaste XAMPP usando las versiones ZIP o 7zip, apaga todos los servidores de XAMPP y sal de todos los paneles. Si instalaste algún servicio, apágalo y desinstálalo también. Ahora simplemente borra el directorio completo donde XAMPP está instalado. No hay entradas ni variables de entorno que debas borrar.\r¿Qué es la versión \"lite\" de XAMPP?\rXAMPP Lite (significa \"ligero\" como en \"peso ligero\") es un conjunto más pequeño de los componentes de XAMPP, el cual es recomendado para trabajo rápido usando sólo PHP y MySQL. Algunos servidores o herramientas como Mercury Mail y FileZilla FTP no están incluidos en la versión Lite.\r¿Dónde debo colocar mi contenido web?\rEl directorio principal para los documentos WWW es \\\\xampp\\\\htdocs. Si pones un fichero \"test.html\" en este directorio, puedes acceder a él con la URI \"http://localhost/test.html\".\r¿Y \"test.php\"? Simplemente usa \"http://localhost/test.php\". Un fichero de test simple puede ser:\r<?php\recho \'Hello world\'; \r?>\r¿Un nuevo subdirectorio para tu web? Simplemente crea un nuevo directorio (p.ej. \"new\") dentro del directorio \"\\\\xampp\\\\htdocs\" (mejor sin espacios y sólo caracteres ASCII), crea un fichero de ejemplo en este directorio y accede a el con \"http://localhost/new/test.php\".\rEspecíficamente\rHTML:\rEjecutable: \\xampp\\htdocs\rFinales permitidos: .html .htm\r=> paquete basico\rSSI:\rEjecutable: \\xampp\\htdocs\rFinales permitidos: .shtml\r=> paquete basico\rCGI:\rEjecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rFinales permitidos: .cgi\r=> paquete basico\rPHP:\rEjecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rFinales permitidos: .php\r=> paquete basico\rPerl:\rEjecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rFinales permitidos: .pl\r=> paquete basico\rApache::ASP Perl:\rEjecutable: \\xampp\\htdocs\rFinales permitidos: .asp\r=> paquete basico\rJSP Java:\rEjecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rFinales permitidos: .jsp\r=> Tomcat add-on\rServlets Java:\rEjecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rFinales permitidos: .html (u.a)\r=> Tomcat add-on\r¿Puedo mover la instalación de XAMPP?\rSí. Tras mover el directorio de XAMPP, debes ejecutar \"setup_xampp.bat\". Los paths de los directorios de configuración se ajustarán con este paso.\rSi has instalado algún servidor como servicio de Windows, debes primero eliminar el servicio de Windows y después de mover, podrás instalar el servicio de nuevo.\rAviso: Los ficheros de configuración de tus propios scripts, como aplicaciones PHP, no serán ajustados. Pero es posible escribir un \"plug-in\" para el instalador. Con ese plug-in, el instalador puede ajustar esos ficheros también.\r¿Qué son las \"páginas de inicio automático\" de los directorios WWW?\rEl nombre del fichero por defecto para la función de Apache \"DirectoryIndex\" es \"index.html\" o \"index.php\". Cada vez que navegas a una carpeta (e.j. \"http://localhost/xampp/\"), y Apache puede encontrar ese fichero, Apache lo muestra en en lugar de un listado de directorio.\r¿Dónde puedo cambiar la configuración?\rCasi todas las opciones de XAMPP pueden cambiarse con ficheros de configuración. Simplemente abre el fichero en un editor de texto y cambia las opciones que quieras. Sólo FileZilla y Mercury deberían ser configuradas con la herramienta de configuración de aplicaciones.\r¿Por qué no funciona XAMPP en Windows XP SP2?\rMicrosoft incluye un mejor firewall con service pack 2 (SP2), que se inicia automáticamente. Este firewall bloquea los puertos 80 (http) y 443 (https), necesarios para Apache, que no puede iniciarse.\rLa solución rápida:\rDeshabilita el firewall de Microsoft con el barra de herramientas e intenta iniciar XAMPP otra vez. La mejor solución es definir una excepción en el centro de seguridad.\rLos siguientes puertos son usados para funcionalidades básicas:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\r¿Por qué no funciona XAMPP en Vista?\rControl de Cuentas de Usuario (UAC)\rNo tienes totales privilegios de escritura en el directorio \"C:\\\\Archivos de Programas\", ni siquiera como Administrador. O tienes sólo privilegios limitados (p.ej. en \".\\\\xampp\\\\htdocs\"). Es este caso, no puedes editar un fichero.\rSolución:\rAumenta tus privilegios en el explorador (botón derecho / seguridad) o deshabilita el control de cuentas de usuario (UAC).\rHas instalado Apache/MySQL en \"C:\\\\xampp\" como servicio de Windows. Pero no puedes iniciar/parar los servicios con el \"XAMPP Control Panel\" o no puedes desinstalarlos.\rSolución:\rUsa la consola de administración de Windows o deshabilita UAC.\rDeshabilitando el Control de Cuenta de Usuario (UAC)\rPara deshabilitar el UAC, usa el programa \"msconfig\". En \"msconfig\" ve a \"Herramientas\", selecciona \"deshabilitar el control de cuentas de usuario\" y verifica tu selección. Ahora debes reiniciar Windows. Si quieres volver a habilita la UAC, puedes hacerlo del mismo modo.\r¿Cómo compruebo el checksum md5?\rPara comparar ficheros, normalmente se usan checksums. Un estándar para crear este checksum es md5 (Message Digest Algorithm 5).\rCon este checksum md5 puedes comprobar si tu descarga del paquete XAMPP es correcto o no. Por supuesto, necesitas un programa que puede crear estos checksums. Para Windows puedes usar una herramienta de Microsoft:\rDisponibilidad y descripción de la utilidad File Checksum Integrity Verifier\rTambién es posible usar cualquier otro programa que cree checksums md5, como GNU md5sum.\rPara instalar un programa así (p.ej. fciv.exe), puedes seguir los siguientes pasos:\rDescarga XAMPP (p.ej. xampp-win32-1.8.2-0.exe)\rCrea el checksum con:\rfciv.exe xampp-win32-1.8.2-0.exe\rY ahora puedes comparar este checksum con el que puedes encontrar en la página de XAMPP para Windows.\rSi ambos checksums son iguales, todo está bien. Si no, la descarga está dañada o el fichero ha sido modificado.\r¿Por qué lo cambios realizados en mi php.ini no tienen efecto?\rSi un cambio en el \"php.ini\" no tiene efecto, es posible que PHP esté usando uno diferente. Puedes verificarlo con phpinfo(). Ve a la URI http://localhost/xampp/phpinfo.php y busca \"Loaded Configuration File\". Este valor muestra el \"php.ini\" que PHP está usando realmente.\rNota:\rTras cambiar el \"php.ini\" debes reiniciar Apache para que Apache/PHP puedan leer la nueva configuración.\r¡Ayuda! ¡Hay un virus en XAMPP!\rAlgunos programas de antivirus confunden XAMPP con un virus, normalmente apuntando al fichero xampp-manager.exe. Esto es un falso positivo, lo que significa que el antivirus lo identifica erróneamente como un virus, cuando no es así. Antes de lanzar cada versión de XAMPP la ejecutamos con un programa de escaneo de virus. En estos momentos usamos \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\r¿Cómo configuro mi aplicación de antivirus?\rHemos incluido todas las dependencias y servidores requeridos para ejecutar la aplicación web incluida, por lo que comprobarás que XAMPP instala un gran número de ficheros. Si estás instalando una aplicación XAMPP en una máquina de Windows con un antivirus activado, puede ralentizar la instalación significativamente, y hay también posibilidades de que uno de los servidores (servidor web, servidor de base de datos) sea bloqueado por el antivirus. Si tienes una herramienta de antivirus habilitada, comprueba las siguientes opciones para ejecutar XAMPP sin problemas de rendimiento:\rAñade excepciones en el firewall: para Apache, MySQL o cualquier otro servidor.\rEscanear los ficheros mientras se ejecutan: si tienes habilitado que el antivirus escanee todos los ficheros, los ficheros ejecutables de los servidores pueden ralentizarse.\rEscanear el tráfico de las distintas URLs: Si estás desarrollando con XAMPP en tu propia máquina, puedes excluir el tráfico de \"localhost\" en las opciones de tu antivirus.\r¿Por qué no se inicia el servidor de Apache en mi sistema?\rEste problema puede deberse a varias razones:\rHas iniciado más de un servidor HTTP (IIS, Sambar, ZEUS and so on). Sólo puede haber un servidor usando el puerto 80. Este mensaje de error indica el problema:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rTienes otro software, como \"Skype\" que también bloquea el puerto 80. Si el problema es \"Skype\", puedes ir en Skype a Acciones->Opciones->Conexión->eliminar la marca de verificación en \"usar puerto 80 en lugar de otro puerto\" y reiniciar Skype. Ahora debería funcionar.\rTienes un firewall que bloquea el puerto Apache. No todos los firewalls son compatibles con Apache, y a veces desactivar el firewall no es suficiente y debes desinstalarlo. Este mensaje de error indica que hay un firewall:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rSi Apache puede iniciarse, pero tu navegador no puede conectarse a él, también puede deberse a uno de los siguientes motivos:\rAlgunos antivirus y firewalls pueden causar este problema.\rTienes XP Professional sin el service pack 1. Debes tener al menos SP1 para usar XAMPP.\rConsejo:\rSi tienes problemas con los puertos usados, puedes usar la herramienta \"xampp-portcheck.exe\". Tal vez te ayude.\r¿Por qué mi carga de CPU en Apache está casi al 99%?\rHay dos opciones aquí. O la CPU ha alcanzado su máximo, o puedes conectarte al servidor, pero no ves nada (el sistema está intentando sin éxito cargar la página). En cualquier caso, puedes encontrar el siguiente mensaje en el fichero log de Apache:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rMPM recurre a una implementación más segura, pero algunas peticiones de clientes no fueron procesadas correctamente. Para evitar este error, usa \"AcceptFilter\" con el filtro \"none\" in el fichero \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\".\r¿Por qué las imágenes y las hojas de estilo no se muestran?\rA veces hay problemas mostrando imágenes y hojas de estilo. Especialmente si estos ficheros están almacenados en un dispositivo en red. En este caso, puedes activar (o añadir) una de las siguientes líneas en el fichero \"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\":\rEnableSendfile off\rEnableMMAP off\rEste problema también puede estar causado por programas de regulación de ancho de banda, como NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rReinicia el servidor de XAMPP usando el panel de control.\nYou can now use PHP\'s mail() function to send email from your application.\r¿Cómo puedo establecer la contraseña de root de MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\r¿Puedo usar mi propio servidor de MySQL?\rSí. Simplemente no inicies MySQL desde el paquete XAMPP. Por favor, ten en cuenta que dos servidores no pueden iniciarse en el mismo puerto. Si has seleccionado una contraseña para \"root\", no olvides editar el fichero \"\\\\xampp\\\\phpMyAdmin\\\\config.inc.php\".\r¿Cómo restrinjo el acceso a phpMyAdmin desde el exterior?\rEn la configuración básica de XAMPP, phpMyAdmin es accessible sólo desde la máquina donde está instalada en http://127.0.0.1 o http://localhost.\rPara acceder al servidor MySQL, phpMyAdmin te preguntará por un nombre de usuario y contraseña. No olvides fijar la contraseña del usuario \"root\" antes.\r¿Cómo habilitar el accesso a phpMyAdmin desde fuera?\rEn la configuración básica de XAMPP, phpMyAdmin es accessible sólo desde la máquina donde está instalada en http://127.0.0.1 o http://localhost.\rIMPORTANTE: Habilitar el accesso de phpMyAdmin para usuarios externos no está recomendado para entornos de producción. Un atacante podría usar cualquier vulnerabilidad de la aplicación para ejecutar código o modificar datos.\rPara habilitar el acceso remote a phpMyAdmin, sigue estos pasos:\rEdita el fichero apache\\conf\\extra\\httpd-xampp.conf en tu directorio de instalación.\rEn este fichero encuentra las siguientes líneas. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nReemplaza \'Require local\' por \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nReinicia el servidor de XAMPP usando el panel de control.\r¿Dónde se encuentra el soporte a IMAP para PHP?\rPor defecto, el soporte a IMAP para PHP está desactivado en XAMPP debido a algunos extraños errores de inicialización con algunas versiones home, como Windows 98. Si trabajas con sistemas NT, puedes abrir el fichero \"\\\\xampp\\\\php\\\\php.ini\" para activar la extensión php eliminando el punto y coma inicial en la línea \";extension=php_imap.dll\". Debería ser:\rextension=php_imap.dll\rAhora reinicia Apache e IMAP debería funcionar. Puedes usar los mismos pasos para cualquier extensión que no esté habilitada en la configuración por defecto.\r¿Por qué algunas aplicaciones open source de PHP no funcionan con XAMPP en Windows?\rMuchas de las aplicaciones de PHP o extensiones que han sido escritas para Linux no han sido portadas a Windows. \r¿Puedo borrar el directorio \"install\" después de la instalación?\rEs mejor que no. Los scripts que se encuentran aquí aún son necesarios para todos los paquetes adicionales (add-ons) y actializaciones de XAMPP.\r¿Cómo activo el eaccelerator?\rComo otras extensiones (Zend) , puedes activarla en \"php.ini\". En este fichero, descomenta la línea \";zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"\". Debe ser:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\r¿Cómo arreglo el error de conexión a mi servidor MS SQL?\rSi la extensión mssql no se cargó en el php.ini, a veces aparecerán problemas cuando sólo se use TCP/IP. Puedes arreglar este problema con un \"ntwdblib.dll\" de Microsoft más nuevo. Por favor, sustituye el fichero anterior en \"\\\\xampp\\\\apache\\\\bin\" y \"\\\\xampp\\\\php\" por el nuevo. Debido a la licencia, no podemos empaquetar nuevas versiones de este fichero en XAMPP.\r¿Cómo uso la extensión mcrypt de PHP?\rPara ello, hemos abierto un topic en el foro con ejemplos y posibles soluciones: \rTopic de MCrypt\r¿Funciona Microsoft Active Server Pages (ASP) con XAMPP?\rNo. Y Apache::ASP con el Add-On de Perl tampoco. Apache::ASP sólo usa Perl-Script pero el ASP de Internet Information Server (IIS) también usa VBScript. Pero para ASP .NET hay un módulo de Apache de terceros disponible.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de privacidad\rCDN proporcionado por','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(37,'2022-11-22 16:37:12','main','s1|/dashboard/es/howto.html',0,NULL,NULL,NULL,'/dashboard/es/howto.html','XAMPP howto guides','Apache Friends\rMenu\rPreguntas frecuentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de privacidad\rCDN proporcionado por','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(38,'2022-11-22 16:37:14','main','s1|/dashboard/es/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/es/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rPreguntas frecuentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de privacidad\rCDN proporcionado por','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(39,'2022-11-22 16:37:12','main','s1|/dashboard/es/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/es/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rPreguntas frecuentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de privacidad\rCDN proporcionado por','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(40,'2023-11-19 12:10:26','main','s1|/dashboard/es/index.html',0,NULL,NULL,NULL,'/dashboard/es/index.html','Welcome to XAMPP','Apache Friends\rMenu\rPreguntas frecuentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rPreguntas frecuentes\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nComunidad\rXAMPP tiene más de 10 años &ndash; hay una gran comunidad detrás del proyecto. Puedes participar uniéndote a nuestros \rForos\r, uniéndote a nuestro \rFacebook\r, o siguiendo nuestras hazañas en \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de privacidad\rCDN proporcionado por','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(41,'2022-11-22 16:37:11','main','s1|/dashboard/faq.html',0,NULL,NULL,NULL,'/dashboard/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rFrequently Asked Questions\rHow do I install XAMPP?\rXAMPP for Windows exists in three different flavors:\rInstaller:\rProbably the easiest way to install XAMPP.\rZIP:\rFor purists: XAMPP as ordinary ZIP archive.\r7zip:\rFor purists with low bandwidth: XAMPP as 7zip archive.\rNote: If you extract the files, there can be false-positives virus warnings.\rUsing the installer:\rThe XAMPP control panel for start/stop Apache, MySQL, FileZilla & Mercury or install these server as services.\rInstalling from ZIP\rUnzip the zip archives into the folder of your choice. XAMPP is extracting to the subdirectory \"C:\\xampp\" below the selected target directory. Now start the file \"setup_xampp.bat\", to adjust the XAMPP configuration to your system.\rIf you choose a root directory \"C:\\\" as target, you must not start \"setup_xampp.bat\".\rLike with the installer version, you can now use the \"XAMPP Control Panel\" for additional tasks.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rHow can I start XAMPP without setup?\rIf you extract XAMPP in a top level folder like \"C:\\\" or \"D:\\\", you can start most servers like Apache or MySQL directly without execution of the file \"setup_xampp.bat\".\rNot using the setup script, or selecting relative paths in the setup script, is preferred if you are installing XAMPP on a usb drive. Because on each pc such a drive can have an other drive letter. You can switch from absolute to relative paths at any time with the setup script.\rUsing the installer from our Downloads page is the easiest way to install XAMPP. After the installation is complete, you will find XAMPP under Start | Programs | XAMPP. You can use the XAMPP Control Panel to start/stop all server and also install/uninstall services.\rThe XAMPP control panel for start/stop Apache, MySQL, FileZilla & Mercury or install these server as services.\rHow do I start and stop XAMPP?\rThe universal control center is the \"XAMPP Control Panel\" (thanks www.nat32.com). It is started with:\r\\xampp\\xampp-control.exe\rYou can also use some batchfiles to start/stop the servers:\rApache & MySQL start:\n\\xampp\\xampp_start.exe\rApache & MySQL stop:\n\\xampp\\xampp_stop.exe\rApache start:\n\\xampp\\apache_start.bat\rApache stop:\n\\xampp\\apache_stop.bat\rMySQL start:\n\\xampp\\mysql_start.bat\rMySQL stop:\n\\xampp\\mysql_stop.bat\rMercury Mailserver start:\n\\xampp\\mercury_start.bat\rMercury Mailserver stop:\n\\xampp\\mercury_stop.bat\rFileZilla Server start:\n\\xampp\\filezilla_start.bat\rFileZilla Server stop:\n\\xampp\\filezilla_stop.bat\rHow can I test that everything worked?\rType in the following URL at your favourite web browser:\rhttp://localhost/\ror \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rHow can I install a server as a service?\rEach server in XAMPP you can install also as Windows service. You can also install it from the XAMPP Control Panel. In this case it is necessary to run the scripts or the Control Panel with Administrator privileges.\rApache service install: \\xampp\\apache\\apache_installservice.bat\rApache service uninstall: \\xampp\\apache\\apache_uninstallservice.bat \rMySQL service install: \\xampp\\mysql\\mysql_installservice.bat \rMySQL service uninstall: \\xampp\\mysql\\mysql_uninstallservice.bat \rFileZilla service (un)install: \\xampp\\filezilla_setup.bat \rMercury: No service installation available\rIs XAMPP production ready?\rXAMPP is not meant for production use but only for development environments. XAMPP is configured to be open as possible to allow the developer anything he/she wants. For development environments, this is great but in a production environment, it could be fatal.\rHere a list of missing security in XAMPP:\rThe MySQL administrator (root) has no password.\rThe MySQL daemon is accessible via network.\rProFTPD uses the password \"lampp\" for user \"daemon\".\rThe default users of Mercury and FileZilla are known.\rAll points can be a huge security risk. Especially if XAMPP is accessible via network and people outside your LAN. It can also help to use a firewall or a (NAT) router. In case of a router or firewall, your PC is normally not accessible via network. It is up to you to fix these problems. As a small help there is the \"XAMPP Security console\".\rPlease secure XAMPP before publishing anything online. A firewall or an external router are only sufficient for low levels of security. For slightly more security, you can run the \"XAMPP Security console\" and assign passwords.\rIf you want have your XAMPP accessible from the internet, you should go to the following URI which can fix some problems:\rhttp://localhost/security/\rWith the security console you can set a password for the MySQL user \"root\" and phpMyAdmin. You can also enable a authentication for the XAMPP demopages.\rThis web based tool does not fix any additional security issues! Especially the FileZilla FTP server and the Mercury mail server you must secure yourself.\rHow do I uninstall XAMPP?\rIf you installed XAMPP using the installer version, please use the Uninstaller. The Uninstaller will delete all XAMPP entries from your registry and it will uninstall some installed services included with XAMPP. We highly recommend that you use the Uninstall program for removing XAMPP installations from the Installer version.Please backup all the data you want to keep before uninstalling XAMPP.\rIf you installed XAMPP using the ZIP and 7zip versions, shut down all XAMPP servers and exit all panels. If you installed any services, uninstall and shut them down too. Now simply delete the entire folder where XAMPP is installed. There are no registry entries and no environment variables to clean up.\rWhat is the \"lite\" version of XAMPP?\rXAMPP Lite (means \"light\" as in \"light-weight\") is a smaller bundle of XAMPP components, which is recommended for quick work using only PHP and MySQL. Some servers or tools such as Mercury Mail and FileZilla FTP are missing in the Lite version.\rWhere should I place my web content?\rThe main directory for all WWW documents is \\xampp\\htdocs. If you put a file \"test.html\" in this directory, you can access it with the URI \"http://localhost/test.html\".\rAnd \"test.php\"? Just use \"http://localhost/test.php\". A simple testscript can be:\r<?php\recho \'Hello world\'; \r?>\rA new subdirectory for your web? Just make a new directory (e.g. \"new\") inside the directory \"\\xampp\\htdocs\" (best without whitespaces and only ASCII), create a test file in this directory and access it with \"http://localhost/new/test.php\".\rFurther specifics\rHTML:\rExecutable: \\xampp\\htdocs\rAllowed endings: .html .htm\r=> basic package\rSSI:\rExecutable: \\xampp\\htdocs\rAllowed endings: .shtml\r=> basic package\rCGI:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .cgi\r=> basic package\rPHP:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .php\r=> basic package\rPerl:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .pl\r=> basic package\rApache::ASP Perl:\rExecutable: \\xampp\\htdocs\rAllowed endings: .asp\r=> basic package\rJSP Java:\rExecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rAllowed endings: .jsp\r=> Tomcat add-on\rServlets Java:\rExecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rAllowed endings: .html (u.a)\r=> Tomcat add-on\rCan I move the XAMPP installation?\rYes. After moving of the XAMPP directory, you must execute \"setup_xampp.bat\". The paths in the configuration files will be adjusted with this step.\rIf you have installed any server as Windows service, you must first remove the Windows service, and after the moving you can install the service again.\rWARNING: The configuration files from your own scripts, like PHP applications, are not adjusted. But it\'s possible to write a \"plug-in\" for the installer. With such a plug-in, the installer can adjust such files too.\rWhat are \"Automatic start pages\" for the WWW directories?\rThe standard filename for the Apache function \"DirectoryIndex\" is \"index.html\" or \"index.php\". Every time you are just browsing to a folder (e.g. \"http://localhost/xampp/\"), and Apache can find such a file, Apache is displaying this file instead of a directory listing.\rWhere can I change the configuration?\rAlmost all settings in XAMPP you can change with configuration files. Just open the file in a textedit and change the setting you want. Only FileZilla and Mercury should be configured with the application config tool.\rWhy can\'t XAMPP work on Windows XP SP2?\rMicrosoft delivers a better firewall with service pack 2 (SP2), which starts automatically. This firewall now blocks the necessary ports 80 (http) and 443 (https) and Apache can\'t start.\rThe fast solution:\rDisable the Microsoft firewall with the toolbar and try to start XAMPP onces more. The better solution is to define an exception within the security center.\rThe following ports are used for basic functionality:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rWhy doesn\'t XAMPP work on Vista?\rUser Account Control (UAC)\rIn the directory \"C:\\program files\" you don\'t have full write privileges, even as Admin. Or you have only limited privileges (e.g. for \".\\xampp\\htdocs\"). In this case you can\'t edit a file.\rSolution:\rRaise your privileges within explorer (right click / security) or deactivate the user account control (UAC).\rYou have installed Apache/MySQL in \"C:\\xampp\" as Windows service. But you can\'t start/stop the services with the \"XAMPP Control Panel\" or can\'t uninstall them.\rSolution:\rUse the service management console from Windows or deactivate UAC.\rDisabling the User Account Control (UAC)\rTo deactivate the UAC, use the program \"msconfig\". In \"msconfig\" go to \"Tools\", select \"disable user account control\" and verify your selection. Now you must restart Windows. At the same time, you can enable the UAC again.\rHow do I check the md5 checksum?\rTo compare files, often checksums are used. A standard to create this checksum md5 (Message Digest Algorithm 5).\rWith this md5 checksum you can test, if your download of the XAMPP package is correct or not. Of course you need a program which can create these checksums. For Windows you can use a tool from Microsoft:\rAvailability and description of the File Checksum Integrity Verifier utility\rIt\'s also possible to use any other program which can create md5 checksums, like the GNU md5sum.\rAs you have installed such a program (e.g. fciv.exe), you can do following steps:\rDownload XAMPP (f.e. xampp-win32-1.8.2-0.exe)\rCreate the checksum with:\rfciv.exe xampp-win32-1.8.2-0.exe\rAnd now you can compare this checksum with that one you can find on the XAMPP for Windows homepage.\rIf both checksums equal, all is ok. If not, the download is broken or the file has been changed.\rWhy have changes in my php.ini not taken effect?\rIf a change in the \"php.ini\" has no effect, it\'s possible PHP is using a different one. You can verify this with phpinfo(). Go to the URI http://localhost/xampp/phpinfo.php and search for \"Loaded Configuration File\". This value shows you the \"php.ini\" PHP is really using.\rNote:\rAfter changing the \"php.ini\" you have to restart Apache so that Apache/PHP can read the new settings.\rHelp! There is a virus in XAMPP!\rSome antivirus programs mistake XAMPP for a virus, typically flagging the file xampp-manager.exe This is a false positive meaning that the antivirus erroneously identified it as a virus, when it is not. Before we release each new version of XAMPP we run it through virus scanning software. At the moment we are using \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rHow do I configure my antivirus application?\rWe have included all dependences and servers required for running the bundled web application, so you will find that XAMPP installs large numbers of files. If you are installing a XAMPP application on a Windows machine with an antivirus app enabled, this may slow down the installation significantly, and there is also a chance that one of the servers (web server, database server) may be blocked by the antivirus software. If you have an antivirus tool enabled, check the following settings for running XAMPP without performance issues:\rAdd exceptions in the firewall: for Apache, MySQL or any other server.\rScan files when executing: If you have enabled the antivirus scan for all files, the executable files for the servers may slow down.\rScan the traffic for different URLs: If you are developing with XAMPP on your own machine, you can exclude \"localhost\" traffic in the Antivirus settings.\rWhy doesn\'t the Apache server start on my system?\rThis problem can be one of several reasons:\rYou have started more then one HTTP Server (IIS, Sambar, ZEUS and so on). Only one Server can use port 80. This error message indicate the problem:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rYou have other software, such as the Internet Telephone \"Skype\" which also blocks the port 80. If the problem is \"Skype\", you can go in Skype to Actions --> Options --> Connection --> remove the check mark at \"use port 80 for an alternate port\" and restart Skype. Now it should work.\rYou have a firewall which blocks the Apache port. Not all firewalls are compatible with Apache, and sometimes deactivating the firewall is not enough and you must deinstall it. This error message indicates a firewall:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rAlso if Apache can start, but your browser can\'t connect to it it could be due to one of the following:\rSome virus scanners can cause this in the same way that firewalls can interfere.\rYou have XP Professional without service pack 1. You must have at least SP1 for XAMPP.\rTip:\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\rWhy is my CPU load for Apache almost 99%?\rThere is one of two scenarios at play here. Either your CPU is maxing out, or you can browser connect to the server, but not see anything (the system is trying unsucessfully to load the page). In either case you can find the following message in the Apache log file:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rThe MPM falls back to a safer implementation, but some client requests were not processed correctly. In order to avoid this error, use \"AcceptFilter\" with accept filter \"none\" in the \"\\xampp\\apache\\conf\\extra\\httpd-mpm.conf\" file.\rWhy are pictures and style-sheets not displayed?\rSometimes there are problems with displaying pictures and style-sheets. Especially if these files are located on a network drive. In this case you can enable (or add) one if the following lines in the file \"\\xampp\\apache\\conf\\httpd.conf\":\rEnableSendfile off\rEnableMMAP off\rThis problem can also be caused by programs for regulating bandwidth, like NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rHow can I set a root password in MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rCan I use my own MySQL server?\rYes. Simply don\'t start the MySQL from the XAMPP package. Please note that two servers cannot be started on the same port. If you have set a password for \"root\", please do not forget to edit the file \"\\xampp\\phpMyAdmin\\config.inc.php\".\rHow do I restrict access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rBefore you can access the MySQL server, phpMyAdmin will prompt you for a user name and password. Don\'t forget to set a password for the user \"root\" first.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rWhere is the IMAP support for PHP?\rAs default, the IMAP support for PHP is deactivated in XAMPP due to some mysterious initialization errors with some home versions like Windows 98. If you work with NT systems, you can open the file \"\\xampp\\php\\php.ini\" to activate the php exstension by removing the beginning semicolon at the line \";extension=php_imap.dll\". It should be:\rextension=php_imap.dll\rNow restart Apache and IMAP should work. You can use the same steps for every extension, which is not enabled in the default configuration.\rWhy don\'t some PHP open source apps work with XAMPP on Windows?\rA lot of PHP applications or extensions that have been written for Linux haven’t been ported to Windows. \rCan I delete the \"install\" directory after installation?\rIt\'s better not to. The scripts here are still needed for all additional packages (add-ons) and upgrades of XAMPP.\rHow do I activate the eaccelerator?\rLike other (Zend) extensions, you can activate it in \"php.ini\". In this file, enable the line \";zend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\". It should be:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rHow do I fix a connection error to my MS SQL server?\rIf the mssql extension was loaded in the php.ini, sometimes problems appear when only TCP/IP is used. You can fix that problem with a newer \"ntwdblib.dll\" from Microsoft. Please replace the older file in \"\\xampp\\apache\\bin\" and \"\\xampp\\php\" with the new one. Because of the license, we can\'t package a newer version of this file with XAMPP.\rHow do I work with the PHP mcrypt extension?\rFor this, we have opened a topic in the forum with examples and possible solutions: \rMCrypt topic\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rNo. And Apache::ASP with the Perl Add-On is not the same. Apache::ASP only knows Perl-Script, but ASP from the Internet Information Server (IIS) also knows the normal VBScript. But for ASP .NET, there is a 3rd party Apache module available.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(42,'2022-11-22 16:37:11','main','s1|/dashboard/fr/faq.html',0,NULL,NULL,NULL,'/dashboard/fr/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rQuestions fréquentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rQuestions Fréquentes\rComment installé-je XAMPP ?\rXAMPP pour Windows existe en trois déclinaisons:\rInstallateur :\rProbablement le plus facile pour installer XAMPP.\rZIP:\rPour les puristes: XAMPP dans une archive ZIP.\r7zip:\rPour les puristes en bas débit: XAMPP en archive 7zip.\rNote: Si vous extrayez les fichiers, de fausses alertes virus peuvent survenir.\rUtilisation de l\'installateur :\rLe panneau de contrôle XAMPP pour démarrer/stopper Apache, MySQL, FileZilla et Mercury ou installer ces serveurs comme services.\rInstallation à partir de ZIP\rDézippez l\'archive zip dans le dossier de votre choix. XAMPP s\'extrait dans le sous-répertoire \"C:\\\\xampp\" du répertoire cible sélectionné. Lancez le fichier \"setup_xampp.bat\" pour adapter la configuration de XAMPP à votre système.\rSi vous choisissez comme cible un répertoire racine \"C:\\\\\", vous ne devez pas lancer \"setup_xampp.bat\".\rComme avec l\'installateur, le \"panneau de contrôle XAMPP\" permet des tâches additionelles.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rComment utiliser XAMPP sans l\'installer?\rSi vous extrayez XAMPP sous la racine comme \"C:\\\\\" ou \"D:\\\\\", vous lancerez la plupart des serveurs comme Apache ou MySQL sans exécution de \"setup_xampp.bat\".\rPour une installation sur une clé USB, ne pas utiliser le script d\'installation ou utiliser des chemins relatifs est préférable. Parce que sur chaque PC ce type de drive peut avoir une lettre différente. A tout moment, vous pourrez passez au chemins relatifs avec le script d\'installation.\rLe plus facile est d\'installer XAMPP avec l\'installateur de la page de téléchargement. Ensuite, vous trouverez Démarrer | Programmes | XAMPP. Le panneau de contrôle XAMPP permet de démarrer/stopper tous les serveurs et installer/désinstaller les services.\rLe panneau de contrôle XAMPP pour démarrer/stopper Apache, MySQL, FileZilla et Mercury ou installer ces serveurs comme services.\rComment lancer/arrêter XAMPP ?\rLe centre de contrôle universel est le \"Panneau de Contrôle XAMPP\" (grâce à www.nat32.com). Il est lancé avec :\r\\xampp\\xampp-control.exe\rDes fichiers batch permettent aussi de démarrer/stopper les serveurs:\rDémarrer Apache & MySQL:\n\\xampp\\xampp_start.exe\rArrêter Apache & MySQL:\n\\xampp\\xampp_stop.exe\rDémarrer Apache:\n\\xampp\\apache_start.bat\rArrêt de Apache:\n\\xampp\\apache_stop.bat\rDémarrer MySQL:\n\\xampp\\mysql_start.bat\rArrêter MySQL:\n\\xampp\\mysql_stop.bat\rDémarrer Mercury Mailserver:\n\\xampp\\mercury_start.bat\rArrêter Mercury Mailsever:\n\\xampp\\mercury_stop.bat\rDémarrer FileZillo Server:\n\\xampp\\filezilla_start.bat\rArrêter FileZilla Server:\n\\xampp\\filezilla_stop.bat\rComment tester si tout a fonctionné ?\rConsultez avec votre navigateur cette URL:\rhttp://localhost/\rou \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rComment installer un serveur comme service?\rChaque serveur dans XAMPP peut devenir un service Windows. C\'est possible depuis le panneau de contrôle XAMPP. Il est alors nécessaire de démarrer le Panneau de Contrôle en tant qu\'administrateur.\rInstallation du service Apache : \\\\xampp\\\\apache\\\\apache_installservice.bat\rDésinstallation du service Apache : \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rInstallation du service MySQL : \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rDésinstallation du service MySQL : \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \r(Dés)Installation du service FileZilla: \\\\xampp\\\\filezilla_setup.bat \rMercury: Service d\'installation NON disponible\rXAMPP destiné à la production?\rXAMPP est destiné exclusivement aux développeurs. La manière dont XAMPP est configuré donne un maximum de libertés en cours de développement. Ceci permet de gagner du temps en phase de développement, mais peut être fatal en environnement de production.\rListe des trous de sécurité dans XAMPP:\rL\'administrateur MySQL (root) sans mot de passe.\rLe démon MySQL est accessible via le réseau.\rProFTPD utilise le mot de passe \"lampp\" pour l\'utilisateur \"daemon\".\rLes utilisateurs par défaut de Mercury et FileZilla sont connus.\rTout peut être une faille de sécurité. Spécialement si XAMPP est accessible en réseau local ou au delà. La présence d\'un pare-feu ou d\'un routeur (NAT) peut aider, car dans ce cas votre PC est normalement inaccessible via le réseau. C\'est à vous de résoudre ces questions. La \"Console de Sécurité XAMPP\" apportera une petite aide.\rSécurisez XAMPP avant toute publication en ligne. Un pare-feu ou un routeur suffisent pour de faibles niveaux de sécurité. Pour plus de sécurité, utilisez la \"Console de Sécurité XAMPP\" et choisissez des mots de passes.\rSi vous désirez que votre XAMPP soit accessible depuis internet, visitez l\'URI suivante pour résoudre certains problèmes :\rhttp://localhost/security/\rDans la console de sécurité vous pourrez choisir un mot de passe pour l\'utilisateur \"root\" de MySQL et phpMyAdmin. Ou activer une identification pour les pages de démo XAMPP.\rCet outil en ligne ne résout aucune question de sécurité supplémentaire ! Veillez spécialement à sécuriser vous-même le serveur FTP FileZilla et le serveur mail Mercury.\rComment désinstaller XAMPP ?\rNous recommandons fortement d\'utiliser l\'outil de désinstallation pour supprimer une installation XAMPP faite avec l\'installateur. Cet outil de désinstallation supprimera les entrées de la base de registre ainsi que certains services installés avec XAMPP. Avant d\'utiliser cet outil de désinstallation, ayez soin de sauvegarder les données que vous désirez conserver.\rSi vous aviez installé XAMPP en utilisant les versions ZIP et 7zip, arrêtez tous les serveurs XAMPP et fermez tous les panneaux. Si vous aviez installé des services, arrêtez les et désinstallez les aussi. Ensuite, supprimez le répertoire XAMPP. Il n\'y a pas d\'entrées de registre ni de variables d\'environnement à nettoyer.\rQu\'est ce que la version \"lite\" de XAMPP?\rXAMPP Lite (signifie \"léger\" comme \"poids léger\") est un sous-ensemble de composants XAMPP, recommandé pour du travail rapide avec seulement PHP et MySQL. Certains serveurs ou outils comme Mercury Mail et FileZilla FTP sont absents de la version Lite.\rOù devrais-je placer mon contenu web?\rLe répertoire principal pour les documents WWW est \\\\xampp\\\\htdocs. Placez-y un fichier \"test.html\" dans ce répertoire, et accédez-y avec l\'URI \"http://localhost/test.html\".\rEt \"test.php\" ? Utilisez \"http://localhost/test.php\". Un script de test peut être:\r<?php\recho \'Hello world\'; \r?>\rUn nouveau sous-répertoire pour votre web? Créez un répertoire (par ex. \"nouveau\") dans \"\\\\xampp\\\\htdocs\" (de préférence sans espaces et seulement en ASCII), créez-y un fichier de test accessible avec \"http://localhost/nouveau/test.php\".\rAutres spécificités\rHTML:\rExécutable: \\xampp\\htdocs\rSuffixes autorisés: .html .htm\r=> paquetage de base\rSSI:\rExécutable: \\xampp\\htdocs\rSuffixes autorisés: .shtml\r=> paquetage de base\rCGI:\rExécutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rSuffixes autorisés: .cgi\r=> paquetage de base\rPHP:\rExécutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rSuffixes autorisés: .php\r=> paquetage de base\rPerl:\rExécutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rSuffixes autorisés: .pl\r=> paquetage de base\rApache::ASP Perl:\rExécutable: \\xampp\\htdocs\rSuffixes autorisés: .asp\r=> paquetage de base\rJSP Java:\rExécutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rSuffixes autorisés: .jsp\r=> Tomcat add-on\rServlets Java:\rExécutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rSuffixes autorisés: .html (u.a)\r=> Tomcat add-on\rPuis je déplacer l\'installation XAMPP?\rOui. D\'abord, déplacez le répertoire XAMPP, ensuite exécutez \"setup_xampp.bat\". Les chemins dans les fichiers de configuration seront actualisés.\rSi vous avez installé un serveur comme service Windows, vous devez d\'abord supprimer le service et après déplacement, vous pouvez réinstaller le service.\rAttention : Vos fichiers de configuration, comme ceux de vos applications PHP, ne sont pas actualisés. Mais il est possible d\'écrire un \"plug-in\" pour l\'installateur, avec lequel l\'installateur peut ajuster ces fichiers.\rQue sont les \"pages de démarrage automatique\" des répertoires WWW ?\rLe nom de fichier standard de la fonction Apache \"DirectoryIndex\" est \"index.html\" ou \"index.php\". Chaque fois que vous naviguez vers un dossier (par ex. \"http://localhost/xampp/\") où Apache peut trouver un tel fichier, Apache l\'affichera au lieu de la liste des fichiers du répertoire.\rOù puis-je changer la configuration ?\rPratiquement tous les paramètres de XAMPP peuvent être modifiés avec les fichiers de configuration. Ouvrez simplement le fichier dans un éditeur de texte et changez le paramètre désiré. Seuls FileZilla et Mercury doivent être configurés avec l\'outil de configuration de l\'application.\rPourquoi XAMPP ne peut il fonctionner sur Windows XP SP2 ?\rAvec le Service Pack 2 (SP2), Microsoft fournit un meilleur firewall qui démarre automatiquement. Ce firewall bloque les indispensables ports 80 (http) et 443 (https) et Apache ne peut pas démarrer.\rSolution rapide :\rDésactivez le pare-feu de Microsoft à l\'aide de la barre d\'outils et essayez de relancer XAMPP. La meilleure solution est de définir une exception dans le centre de sécurité.\rLes ports suivants sont utilisés pour un fonctionnement de base :\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rPourquoi XAMPP ne fonctionne-t-il pas sur Vista ?\rContrôle des comptes d\'utilisateurs (UAC)\rDans le répertoire \"C:\\\\program files\", vous n\'avez pas les droits d\'écriture complets, même en tant qu\'Administrateur. Ou bien vous n\'avez que des droits limités (par ex. pour \".\\\\xampp\\\\htdocs\"). Dans ce cas, vous ne pouvez pas éditer un fichier.\rSolution :\rAugmentez vos droits dans l\'explorateur (clic droit / sécurité) ou désactivez le contrôle des comptes d\'utilisateurs (UAC).\rVous avez installé Apache/MySQL dans \"C:\\\\xampp\" comme un service Windows Mais vous ne pouvez démarrer/arrêter les services avec le \"panneau de contrôle XAMPP\" ou vous ne pouvez pas les désinstaller.\rSolution :\rUtilisez la console de gestion des services de Windows ou désactivez l\'UAC.\rDésactivation du Contrôle de Compte d\'Utilisateur (UAC)\rPour désactiver l\'UAC, utilisez le programme \"msconfig\". Dans \"msconfig\", allez dans \"Outils\", sélectionnez \"désactiver le contrôle de compte d\'utilisateur\" et vérifiez votre sélection. Vous devez redémarrer Windows. Dans le même temps, vous pouvez réactiver l\'UAC.\rComment vérifié-je l\'empreinte md5 ?\rPour comparer les fichiers, des empreintes sont souvent utilisées. Une norme pour créer cette empreinte md5 (Message Digest Algorithm 5).\rAvec cette empreinte md5 vous pouvez vérifier si votre paquetage XAMPP téléchargé est correct. Bien sûr vous devez disposer d\'un programme de création de telles empreintes. Pour Windows, vous pouvez utiliser un outil de Microsoft :\rDisponibilité et description de l\'utilitaire de vérification de l\'intégrité de l\'empreinte\rIl est aussi possible d\'utiliser n\'importe quel autre programme qui peut générer une empreinte md5, comme le GNU md5sum.\rComme vous avez installé un tel programme (par ex. fciv.exe), vous pouvez suivre les étapes suivantes :\rTéléchargez XAMPP (par ex. xampp-win32-1.8.2-0.exe)\rGénérez l\'empreinte avec :\rfciv.exe xampp-win32-1.8.2-0.exe\rEt maintenant vous pouvez comparer l\'empreinte avec celle qui se trouve sur la page d\'accueil de XAMPP pour Windows.\rSi les deux empreintes sont identiques, tout va bien. Sinon, le téléchargement est corrompu ou le fichier a été modifié.\rPourquoi les changements de mon php.ini n\'ont ils pas été pris en compte ?\rSi un changement du \"php.ini\" demeure sans effet, il est possible que PHP en utilise un autre. Vous pouvez le vérifier par phpinfo(). Rendez vous à l\'URI http://localhost/xampp/phpinfo.php et recherchez \"Fichier de configuration chargé\". La valeur vous indique le \"php.ini\" réellement utilisé.\rNota :\rAprès modification de \"php.ini\" vous devez redémarrer Apache pour que les nouveaux paramètres soient lus.\rAu secours ! Il y a un virus dans XAMPP !\rQuelques programmes antivirus prennent à tort XAMPP pour un virus, en pointant généralement le fichier xampp-manager.exe. Ceci est un faux positif, car ce fichier n\'est pas un virus. Avant de diffuser toute nouvelle version de XAMPP, nous la scannons avec un logiciel de détection de virus. Actuellement, nous utilisons \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rComment configurer mon antivirus ?\rNous avons inclus toutes les dépendances et serveurs requis pour exécuter l\'application web empaquetée, vous trouverez donc que XAMPP installe un grand nombre de fichiers. Si vous installez une application XAMPP sur une machine Windows avec un antivirus actif, l\'installation peut être significativement ralentie et il est possible qu\'un des serveurs (serveur web, serveur de base de données) soit bloqué par l\'antivirus. Si votre antivirus est activé, vérifiez les paramètres suivants pour exécuter XAMPP sans problème de performance :\rAjoutez des exceptions dans le firewall : pour Apache, MySQL ou tout autre serveur.\rAnalysez les fichiers lors de l\'exécution : si vous avez activé l\'analyse antivirus pour tous les fichiers, les fichiers exécutables pour les serveurs peuvent ralentir.\rAnalysez le trafic pour différentes URL : Si vous développez avec XAMPP sur votre propre machine, vous pouvez exclure le trafic \"localhost\" des paramètres de l\'antivirus.\rPourquoi le serveur Apache ne démarre-t-il pas sur mon système ?\rCe problème peut avoir plusieurs causes :\rVous avez lancé plus d\'un serveur HTTP (IIS, Sambar, ZEUS et autres). Un seul serveur peut utiliser le port 80. Le message d\'erreur indique le problème :\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rVous avez un autre logiciel, comme le téléphone par internet \"Skype\" qui bloque également le port 80. Si le problème est \"Skype\", vous pouvez aller dans Skype jusqu\'à Actions --> Options --> Correction --> décocher la case \"utiliser le port 80 comme port alternatif\" avant de redémarrer Skype. Maintenant ça devrait fonctionner.\rVotre firewall bloque le port Apache. Tous les firewalls ne sont pas compatibles avec Apache, et parfois la désactivation du firewall ne suffit pas et vous devez le désinstaller. Ce message d\'erreur signale un firewall :\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rSi Apache démarre, mais que votre navigateur ne peut pas s\'y connecter, cela peut avoir l\'une des causes suivantes :\rCertains scanners de virus peuvent le provoquer de la même manière que les firewalls peuvent interférer.\rVous avez XP Professionnel sans le Service Pack 1. Vous devez au moins disposer de SP1 pour XAMPP.\rAstuce :\rSi vous avez des problèmes avec les ports utilisés, vous pouvez utiliser l\'outil \"xampp-portcheck.exe\". Cela vous aidera peut être.\rPourquoi ma charge CPU pour Apache atteint elle presque 99% ?\rL\'un des deux scenarios est en jeu ici. Soit votre CPU plafonne, soit votre navigateur se connecte au serveur, mais ne voit rien (le système essaie sans succès de charger la page). Dans les deux cas, vous pouvez trouver le message suivant dans le fichier journal d\'Apache :\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rLe MPM a recours à une implémentation plus sûre, mais certaines requêtes de clients n\'ont pas été traitées correctement. Pour éviter cette erreur, utilisez \"AcceptFilter\" avec l\'option \"aucun\" dans le fichier \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\".\rPourquoi les images et les feuilles de style ne s\'affichent elles pas ?\rQuelquefois il y a des problèmes avec l\'affichage des images et des feuilles de style. Surtout si ces fichiers sont situés sur un périphérique réseau. Dans ce cas, vous pouvez activer (ou ajouter) l\'une des lignes suivantes dans le fichier \"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\" :\rEnableSendfile off\rEnableMMAP off\rCe problème peut aussi être causé par des programmes de régulation de la bande passante, tels que NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rComment puis je attribuer un mot de passe à root dans MySQL ?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rPuis-je utiliser mon propre serveur MySQL ?\rOui. Il suffit de ne pas lancer MySQL à partir du paquetage XAMPP. Notez que deux serveurs ne peuvent pas être démarrés sur le même port. Si vous avez attribué un mot de passe à \"root\", n\'oubliez pas de modifier le fichier \"\\\\xampp\\\\phpMyAdmin\\\\config.inc.php\".\rComment restreindre l\'accès à phpMyAdmin depuis l\'extérieur ?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rAvant de vous laisser accéder au serveur MySQL, phpMyAdmin vous demandera un nom d\'utilisateur et un mot de passe. N\'oubliez pas en premier d\'attribuer un mot de passe à l\'utilisateur \"root\".\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rOù est le support IMAP de PHP ?\rA défaut, le support IMAP de PHP est désactivé dans XAMPP en raison d\"erreurs mystérieuses d\'initialisation avec certaines versions familiales comme Windows 98. Si vous travaillez avec les systèmes NT, vous pouvez ouvrir le fichier \"\\\\xampp\\\\php\\\\php.ini\" pour activer l\'extension php en supprimant le point-virgule au début de la ligne \";extension=php_imap.dll\". Ca devrait être :\rextension=php_imap.dll\rRedémarrez Apache et IMAP devrait fonctionner. Vous pouvez suivre les mêmes étapes pour chaque extension qui n\'est pas activée dans la configuration par défaut.\rPourquoi certaines applications php libres ne fonctionnent elles pas avec XAMPP sous Windows ?\rUn grand nombre d\'applications ou d\'extensions PHP écrites pour Linux n\'ont pas été portées sous Windows. \rPuis-je supprimer le répertoire \"install\' après l\'installation ?\rIl ne vaut mieux pas. Les scripts qu\'il contient restent nécessaires aux paquetages additionnels (add-ons) et aux mises à jour de XAMPP.\rComment activé-je l\'eaccelerator ?\rComme d\'autres extensions (Zend), vous pouvez l\'activer dans \"php.ini\". Dans ce fichier, activez la ligne \";zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"\". Ce devrait être :\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rComment puis-je corriger une erreur de connexion à mon serveur MS SQL ?\rSi l\'extension mssql a été chargée dans le php.ini, des problèmes peuvent apparaître quand seul TCP/IP est utilisé. Vous pouvez corriger ce problème avec un nouveau \"ntwdblib.dll\" de Microsoft. Remplacez l\'ancien fichier dans \"\\\\xampp\\\\apache\\\\bin\" et dans \"\\\\xampp\\\\php\" par le nouveau. En raison de la licence, nous ne pouvons pas empaqueter une nouvelle version de ce fichier dans XAMPP.\rComment fais-je pour travailler avec l\'extension mcrypt de PHP ?\rPour cela, nous avons ouvert un sujet dans le forum avec des exemples et des solutions possibles : \rSujet MCrypt\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rNon. Et Apache::ASP avec le complément Perl n\'est pas pareil. Apache::ASP ne connaît que le Perl-Script, mais ASP de Internet Information Server (IIS) connaît aussi le VBScript normal. Mais pour ASP .NET, un module Apache tiers est disponible.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitique de confidentialité\rCDN fourni par','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(43,'2022-11-22 16:37:13','main','s1|/dashboard/fr/howto.html',0,NULL,NULL,NULL,'/dashboard/fr/howto.html','XAMPP howto guides','Apache Friends\rMenu\rQuestions fréquentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitique de confidentialité\rCDN fourni par','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(44,'2022-11-22 16:37:14','main','s1|/dashboard/fr/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/fr/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rQuestions fréquentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitique de confidentialité\rCDN fourni par','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(45,'2022-11-22 16:37:12','main','s1|/dashboard/fr/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/fr/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rQuestions fréquentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitique de confidentialité\rCDN fourni par','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(46,'2023-11-19 12:10:26','main','s1|/dashboard/fr/index.html',0,NULL,NULL,NULL,'/dashboard/fr/index.html','Welcome to XAMPP','Apache Friends\rMenu\rQuestions fréquentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rQuestions fréquentes\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nCommunauté\rXAMPP existe depuis plus de 10 ans &ndash; une énorme communauté l\'appuie. Vous pouvez en faire partie en rejoignant nos \rForums\r, en nous appréciant sur \rFacebook\r, ou en suivant nos exploits sur \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitique de confidentialité\rCDN fourni par','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(47,'2022-11-22 16:37:12','main','s1|/dashboard/howto.html',0,NULL,NULL,NULL,'/dashboard/howto.html','XAMPP howto guides','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(48,'2022-11-22 16:37:14','main','s1|/dashboard/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(49,'2022-11-22 16:37:12','main','s1|/dashboard/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(50,'2022-11-22 16:37:11','main','s1|/dashboard/hu/faq.html',0,NULL,NULL,NULL,'/dashboard/hu/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rGyakori kérdések\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rGyakran ismételt kérdések\rHogyan telepítsem a XAMPP-ot?\rA XAMPP Windows változata három különböző formában létezik:\rTelepítő:\rValószínűleg a legegyszerűbb módja a XAMPP telepítésének.\rZIP:\rPuristáknak: a XAMPP szokásos ZIP archívumként.\r7zip:\rPuristáknak kis sávszélességgel: a XAMPP 7zip archívumként.\rMegjegyzés: A fájlok kibontásakor előfordulhatnak hamis pozitív vírusriasztások.\rA telepítő használata:\rHasználja a Xampp vezérlőpultot az Apache, MySQL, FileZillaés a Mercury szolgáltatások elindításához és leállításához vagy a server szolgáltatások telepítéséhez.\rTelepítés ZIP-ből\rBontsa ki a zip archívumokat a választott mappába. A XAMPP a „C:\\\\xampp” alkönyvtárba kerül kibontásra a választott célkönyvtár alá. Most indítsa el a „setup_xampp.bat” fájlt, hogy elvégezze a XAMPP beállítását a rendszeréhez.\rHa a „C:\\\\” gyökérkönyvtárat válassza célnak, akkor nem szabad a „setup_xampp.bat” fájlt futtatnia.\rMint a telepítő verzióban, most már használhatja a „XAMPP vezérlőpultot” a további feladatokhoz.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rHogyan indíthatom a XAMPP programot beállítás nélkül?\rHa a XAMPP programot egy felsőszintű mappába bontotta ki, mint például „C:\\\\” vagy „D:\\\\”, akkor a legtöbb szolgáltatást - úgymint Apache vagy MySQL - közvetlenül is el tudja indítani a „setup_xampp.bat” fájl futtatása nélkül.\rNem javasolt a beállító parancsfájl használata, vagy relatív elérési utak kiválasztása a beállító parancsfájlban, ha a XAMPP programot USB-meghajtóra telepítette. Ennek oka, hogy minden PC más meghajtóbetűt rendelhet a meghajtónak. Bármikor átválthat abszolút útvonalakról relatívakra a beállító parancsfájllal.\rA Letöltések oldalról elérhető telepítő használata a legegyszerűbb módja a XAMPP telepítésének. A telepítés befejezése után a Start | Programok | XAMPP helyen fogja megtalálni a XAMPP programot. A XAMPP vezérlőpultot használhatja az összes kiszolgáló indításához és leállításához, valamint szolgáltatások telepítéséhez és eltávolításához.\rHasználja a Xampp vezérlőpultot az Apache, MySQL, FileZillaés a Mercury szolgáltatások elindításához és leállításához vagy a server szolgáltatások telepítéséhez.\rHogyan indíthatom el és állíthatom le a XAMPP-ot?\rAz egyetemes vezérlőpult a „XAMPP vezérlőpult” (köszönet: www.nat32.com). Az alábbi módon indítható:\r\\xampp\\xampp-control.exe\rHasználhat néhány kötegfájlt is a kiszolgálók indításához és leállításához:\rApache és MySQL indítás:\n\\xampp\\xampp_start.exe\rApache és MySQL leállítás:\n\\xampp\\xampp_stop.exe\rApache indítás:\n\\xampp\\apache_start.bat\rApache leállítás:\n\\xampp\\apache_stop.bat\rMySQL indítás:\n\\xampp\\mysql_start.bat\rMySQL leállítás:\n\\xampp\\mysql_stop.bat\rMercury levelezőkiszolgáló indítás:\n\\xampp\\mercury_start.bat\rMercury levelezőkiszolgáló leállítás:\n\\xampp\\mercury_stop.bat\rFileZilla kiszolgáló indítás:\n\\xampp\\filezilla_start.bat\rFileZilla kiszolgáló leállítás:\n\\xampp\\filezilla_stop.bat\rHogyan ellenőrizhetem, hogy minden működik-e?\rGépelje be a következő URL-t a kedvenc webböngészőjébe:\rhttp://localhost/\rvagy \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rHogyan tudok egy kiszolgálót szolgáltatásként telepíteni?\rA XAMPP minden kiszolgálója Windows szolgáltatásként is telepíthető. Ezt is a XAMPP vezérlőpultból tudja telepíteni. Ebben az esetben a parancsfájlok vagy a vezérlőpult futtatása rendszergazdai jogosultságokkal szükséges.\rApache szolgáltatás telepítés: \\\\xampp\\\\apache\\\\apache_installservice.bat\rApache szolgáltatás eltávolítás: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rMySQL szolgáltatás telepítés: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rMySQL szolgáltatás eltávolítás: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \rFileZilla szolgáltatás telepítés és eltávolítás: \\\\xampp\\\\filezilla_setup.bat \rMercury: nem érhető el szolgáltatás telepítés\rA XAMPP készen áll a munkához?\rA XAMPP nem a produktív használatot jelenti, ez csak egy fejlesztői környezet. A XAMPP oly módon lett beállítva, hogy annyira nyitott legyen, amennyire csak lehetséges, hogy lehetővé tegyen a fejlesztőknek bármit, amit szeretnének. Ez nagyszerű egy fejlesztői környezethez, de produktív környezetben végzetes lehet.\rItt egy lista a XAMPP hiányzó biztonsági dolgairól:\rA MySQL adminisztrátornak (root) nincs jelszava.\rA MySQL démon elérhető a hálózaton keresztül.\rA ProFTPD a „lampp” jelszót használja a „daemon” felhasználóhoz.\rA Mercury és FileZilla alapértelmezett felhasználói ismertek.\rMinden pont hatalmas biztonsági kockázat lehet. Különösen akkor, ha a XAMPP elérhető a hálózaton keresztül és a LAN-on kívüli emberek számára. Segíthet azonban egy tűzfal vagy egy router (NAT) használata. Egy router vagy egy tűzfal esetén a PC normális esetben nem érhető el a hálózaton keresztül. Öntől függ, hogy kijavítja-e ezeket a hibákat. Egy kis segítségként létezik egy „XAMPP biztonsági konzol”.\rKérjük tegye biztonságossá a XAMPP programot, mielőtt bármit közzétenne online. Egy tűzfal vagy egy külső router csak alacsony szintű biztonsághoz elegendő. A valamivel nagyobb biztonság érdekében futtassa a „XAMPP biztonsági konzolt” és rendeljen hozzá jelszavakat.\rHa elérhetővé szeretné tenni a XAMPP programot az interneten, akkor látogassa meg a következő URI-t, amely kijavíthat néhány problémát:\rhttp://localhost/security/\rA biztonsági konzollal beállíthatja a MySQL „root” felhasználó és a phpMyAdmin jelszavát. Továbbá bekapcsolhatja a hitelesítést a XAMPP bemutató oldalakhoz.\rEz a webalapú eszköz nem javít ki semmilyen egyéb biztonsági problémát! Különösen a FileZilla FTP-kiszolgáló és a Mercury levelezőkiszolgáló biztonságáról kell önnek gondoskodnia.\rHogyan távolíthatom el a XAMPP-ot?\rAmennyiben a telepítős verzióval telepítette a XAMPP programot, használja az eltávolítót. Az eltávolító el fog távolítani minden XAMPP bejegyzést a rendszerleíró adatbázisból, illetve el fogja távolítani a XAMPP részeként telepített szolgáltatásokat. Erősen ajánljuk, hogy az eltávolító használatával távolítsa el a telepítős verziójú XAMPP telepítést. Készítsen biztonsági mentést a XAMPP eltávolítása előtt minden olyan adatról, amelyet meg szeretne tartani.\rAmennyiben a ZIP és a 7zip verziókkal telepítette a XAMPP programot, állítson le minden XAMPP kiszolgálót és lépjen ki minden panelből. Ha telepített valamilyen szolgáltatást, távolítsa el és állítsa le azokat is. Most egyszerűen törölje az egész mappát, ahova a XAMPP programot telepítette. Nincsenek törlendő rendszerleíró adatbázis bejegyzések és nincsenek törlendő környezeti változók.\rMi a XAMPP „lite” verziója?\rA XAMPP Lite (amely „könnyűt” jelent, úgymint „könnyűsúlyú”) a XAMPP komponensek kisebb csomagja, amely kizárólag PHP és MySQL használatával történő gyors munkavégzéshez ajánlott. Néhány kiszolgáló vagy eszköz, mint például a Mercury levelező és a FileZilla FTP hiányoznak a Lite verzióból.\rHová tegyem a webes tartalmakat?\rMinden WWW dokumentum fő könyvtára a \\\\xampp\\\\htdocs. Ha ebbe a könyvtárba teszi a „teszt.html” fájlt, akkor a „http://localhost/teszt.html” URI segítségével férhet hozzá.\rÉs a „teszt.php”? Csak használja a „http://localhost/teszt.php” hivatkozást. Egy egyszerű teszt-parancsfájl lehet:\r<?php\recho \'Hello world\'; \r?>\rEgy új alkönyvtár a webhez? Csak hozzon létre egy új könyvtárat (például „valami”) a „\\\\xampp\\\\htdocs” könyvtáron belül (a legjobb szóközök nélkül és csak ASCII karakterekkel), hozzon létre egy tesztfájlt ebben a könyvtárban és elérheti a „http://localhost/valami/teszt.php” címen.\rTovábbi specifikációk\rHTML:\rProgramfájl: \\xampp\\htdocs\rEngedélyezett végződések: .html .htm\r=> alap csomag\rSSI:\rProgramfájl: \\xampp\\htdocs\rEngedélyezett végződések: .shtml\r=> alap csomag\rCGI:\rProgramfájl: \\xampp\\htdocs and \\xampp\\cgi-bin\rEngedélyezett végződések: .cgi\r=> alap csomag\rPHP:\rProgramfájl: \\xampp\\htdocs and \\xampp\\cgi-bin\rEngedélyezett végződések: .php\r=> alap csomag\rPerl:\rProgramfájl: \\xampp\\htdocs and \\xampp\\cgi-bin\rEngedélyezett végződések: .pl\r=> alap csomag\rApache::ASP Perl:\rProgramfájl: \\xampp\\htdocs\rEngedélyezett végződések: .asp\r=> alap csomag\rJSP Java:\rProgramfájl: \\xampp\\tomcat\\webapps\\java (e.g.)\rEngedélyezett végződések: .jsp\r=> Tomcat add-on\rServlets Java:\rProgramfájl: \\xampp\\tomcat\\webapps\\java (e.g.)\rEngedélyezett végződések: .html (u.a)\r=> Tomcat add-on\rÁthelyezhetem a XAMPP telepítését?\rIgen. A XAMPP könyvtár áthelyezése után le kell futtatnia a „setup_xampp.bat” parancsfájlt. A beállítófájlban lévő elérési út ehhez a lépéshez lesz igazítva.\rAmennyiben valamilyen kiszolgálót Windows szolgáltatásként telepített, akkor először el kell távolítania a Windows szolgáltatást, majd az áthelyezés után ismét telepítheti azt.\rFigyelem: a saját parancsfájljaiban lévő beállítófájlok, mint például PHP alkalmazások, nem lesznek hozzáigazítva. De lehetséges egy „bővítmény” írása a telepítőhöz. Egy ilyen bővítménnyel a telepítő ezeket a fájlokat is hozzá tudja igazítani.\rMik az „Automatikus nyitóoldalak” a WWW könyvtárakhoz?\rA szabványos fájlnév a „DirectoryIndex” Apache függvényhez „index.html” vagy „index.php”. Minden esetben, amikor rátallóz egy mappára (például „http://localhost/xampp/”), és az Apache talál egy ilyen fájlt, akkor az Apache ezt a fájlt jeleníti meg a könyvtár listázása helyett.\rHol tudom megváltoztatni a beállításokat?\rA XAMPP majdnem minden beállítása megváltoztatható beállítófájlokkal. Csak nyissa meg a fájlt egy szövegszerkesztővel és változtassa meg azt a beállítást, amelyet szeretne. Csak a FileZilla és a Mercury beállítását kell az alkalmazásbeállító eszközzel elvégezni.\rMiért nem működik a XAMPP Windows XP SP2 alatt?\rA Microsoft egy jobb tűzfalat szállított a 2. javítócsomaggal (SP2), amely automatikusan elindul. Ez a tűzfal már blokkolja a szükséges 80-as (http) és 443-as (https) portokat, és az Apache nem tud elindulni.\rA gyors megoldás:\rTiltsa le a Microsoft tűzfalat az eszköztárral, és próbálja meg még egyszer elindítani a XAMPP programot. A jobb megoldás egy kivétel meghatározása a biztonsági központon belül.\rA következő portok vannak használatban az alap működéshez:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rMiért nem működik a XAMPP Vistán?\rFelhasználói fiókok felügyelete (UAC)\rA „C:\\\\Program files” könyvtárra nincs teljes írási jogosultsága, kivéve rendszergazdaként. Vagy csak korlátozott jogosultságai vannak (például a „.\\\\xampp\\\\htdocs” mappára). Ebben az esetben nem tudja szerkeszteni a fájlt.\rMegoldás:\rEmelje meg a jogosultságait az exploreren belül (jobb kattintás / biztonság), vagy tiltsa le a felhasználói fiókok felügyeletét (UAC).\rAz Apache/MySQL kiszolgálókat a „C:\\\\xampp” helyre telepítette Windows szolgáltatásként. De nem tudja elindítani vagy leállítani a szolgáltatásokat a „XAMPP vezérlőpulttal”, vagy nem tudja eltávolítani azokat.\rMegoldás:\rHasználja a Windows szolgáltatáskezelő konzolját vagy tiltsa le az UAC-ot.\rA felhasználói fiókok felügyeletének (UAC) letiltása\rAz UAC letiltásához használja az „msconfig” programot. Az „msconfig” programban menjen az „Eszközökre”, válassza a „felhasználói fiókok felügyeletének letiltása” lehetőséget, és erősítse meg a választását. Ezután újra kell indítania a Windowst. Ezzel egy időben ismét engedélyezheti az UAC-ot.\rHogyan ellenőrizhetem az MD5 ellenőrzőösszeget?\rFájlok összehasonlításához gyakran ellenőrzőösszegeket használnak. A szabvány az MD5 (Message Digest Algorithm 5) ellenőrzőösszeg létrehozása.\rEzzel az MD5 ellenőrzőösszeggel tesztelheti, hogy a XAMPP csomag letöltése helyes volt-e vagy sem. Természetesen szüksége van egy olyan programra, amely elő tudja állítani ezeket az ellenőrzőösszegeket. A Windowsnál használhatja a Microsoft eszközét:\rElérhetőség és fájl ellenőrzőösszeg integritás leírása ellenőrző segédprogram\rLehetséges bármely más olyan program használata is, amely létre tud hozni MD5 ellenőrzőösszegeket, úgymint a GNU md5sum.\rHa telepített egy ilyen programot (például fciv.exe), végezze el a következő lépéseket:\rTöltse le a XAMPP csomagot (például xampp-win32-1.8.2-0.exe)\rHozza létre az ellenőrzőösszeget ezzel:\rfciv.exe xampp-win32-1.8.2-0.exe\rÉs most már össze tudja hasonlítani ezt az ellenőrzőösszeget azzal, amelyet a Windows rendszerre készített XAMPP honlapján talál.\rHa mindkét ellenőrzőösszeg azonos, akkor minden rendben van. Ha nem, akkor a letöltött fájl sérült vagy a fájl módosult.\rMiért nem érvényesülnek a php.ini fájlban elvégzett módosítások?\rHa a „php.ini” fájlban elvégzett módosításnak nincs hatása, lehetséges, hogy a PHP egy másikat használ. Ezt a phpinfo() függvénnyel ellenőrizheti. Látogassa meg a http://localhost/xampp/phpinfo.php oldalt, és keressen rá a „Loaded Configuration File” kifejezésre. Ez az érték jeleníti meg azt a „php.ini” fájlt, amelyet a PHP igazából használ.\rMegjegyzés:\rA „php.ini” módosítása után újra kell indítania az Apache webkiszolgálót, hogy az Apache/PHP be tudja olvasni az új beállításokat.\rSegítség! Vírusos a XAMPP!\rNéhány vírusirtó program hibásan vírusnak érzékeli a XAMPP-ot, tipikusan a xampp-manager.exe fájlt megjelölve. Ez egy vakriasztás, amely azt jelenti, hogy a vírusirtó tévesen vírusként azonosítja, miközben nem az. A XAMPP minden egyes új verziójának kiadása előtt lefuttatunk egy víruskereső programot. Jelenleg ezt használjuk: \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rHogyan állítsam be a vírusirtó alkalmazásomat?\rMinden függőséget és kiszolgálót mellékelünk, amely a csomagolt webalkalmazás futtatásához szükséges, így a XAMPP telepítésben nagy számú fájlt fog találni. Amennyiben a XAMPP alkalmazást egy olyan Windowst futtató számítógépre telepíti, amelyen bekapcsolt vírusirtó alkalmazás van, akkor ez jelentősen lelassíthatja a telepítést, és megvan az esély arra, hogy a kiszolgálók egyikét (webkiszolgáló, adatbázis-kiszolgáló) blokkolja a vírusirtó program. Ha engedélyezve van egy vírusirtó eszköz, ellenőrizze a következő beállításokat a XAMPP teljesítményproblémák nélküli futtatásához:\rKivételek hozzáadása a tűzfalhoz: az Apache, a MySQL vagy bármely más kiszolgálóhoz.\rFájlok vizsgálata végrehajtáskor: ha engedélyezve van a vírusirtó vizsgálata minden fájlra, a kiszolgálók végrehajtható fájljait lelassíthatja.\rA forgalom vizsgálata különböző URL-eknél: ha a saját gépén fejleszt a XAMPP programmal, zárja ki a „localhost” forgalmát a vírusirtó beállításaiban.\rMiért nem indul az Apache kiszolgáló a rendszeremen?\rEnnek a problémának számos oka lehet:\rEgynél több HTTP kiszolgálót indított el (IIS, Sambar, ZEUS, stb.). Csak egyetlen kiszolgáló használhatja a 80-as portot. Ez a hibaüzenet jelzi a problémát:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rMás szoftverei is vannak, mint például a „Skype” internettelefon, amely szintén blokkolja a 80-as portot. Ha a „Skype” a probléma, menjen a Skype programban a Műveletek --> Beállítások --> Kapcsolat menüpontra, és távolítsa el a pipát a „80-as port használata tartalék portként” lehetőségből, majd indítsa újra a Skype programot. Ezután működnie kellene.\rTűzfala van, amely blokkolja az Apache portját. Nem minden tűzfal kompatibilis az Apache kiszolgálóval, és néha a tűzfal kikapcsolása nem elegendő, el kell távolítania azt. Ez a hibaüzenet jelzi a tűzfalat:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rHa az Apache el tud ugyan indulni, de a böngésző nem tud csatlakozni hozzá, akkor ez a következők egyike miatt lehet:\rNéhány vírusirtó okozhatja ezt ugyanolyan módon, ahogy a tűzfalak zavarhatják.\rXP Professional rendszere van 1. javítócsomag nélkül. Legalább SP1 szükséges a XAMPP programhoz.\rTipp:\rHa problémái vannak a portok használatával, megpróbálhatja a „xampp-portcheck.exe” eszközt. Talán segíthet.\rMiért van majdnem 99%-os CPU terhelés az Apache használatakor?\rKét forgatókönyv játszhat itt szerepet. Vagy a CPU van maximálisan kihasználva, vagy a böngésző képes ugyan csatlakozni a kiszolgálóhoz, de nem lát semmit (a rendszer sikertelenül próbálja betölteni az oldalt). Mindkét esetben a következő üzenetet láthatja az Apache naplófájljában:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rAz MPM visszaáll egy biztonságosabb megvalósításra, de néhány klienskérés nem lett helyesen feldolgozva. Ezen hiba elkerülésének érdekében használja az „AcceptFilter” beállítást a „none” elfogadásszűrővel a „\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf” fájlban.\rMiért nem jelennek meg a képek és a stíluslapok?\rNéha problémák vannak a képek és a stíluslapok megjelenítésével. Különösen akkor, ha ezek a fájlok egy hálózati eszközön találhatók. Ebben az esetben engedélyezhet (vagy hozzáadhat) egyet, ha a következő sorok a „\\\\xampp\\\\apache\\\\conf\\\\httpd.conf” fájlban vannak:\rEnableSendfile off\rEnableMMAP off\rEzt a hibát okozhatják sávszélesség-szabályzó programok is, mint például a NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rHogyan állíthatok be rendszergazda jelszót a MySQL-ben?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rHasználhatom a saját MySQL kiszolgálómat?\rIgen. Egyszerűen ne indítsa el a MySQL kiszolgálót a XAMPP csomagból. Vegye figyelembe, hogy nem lehet két kiszolgálót elindítani ugyanazon a porton. Ha a „root” felhasználónak állított be jelszót, ne felejtse el szerkeszteni a „\\\\xampp\\\\phpMyAdmin\\\\config.inc.php” fájlt.\rHogyan tudom korlátozni a phpMyAdmin kívülről való hozzáférését?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rMielőtt hozzáférne a MySQL kiszolgálóhoz, a phpMyAdmin kérni fog Öntől egy felhasználónevet és egy jelszót. Ne felejtsen el először beállítani jelszót a „root” felhasználónak.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rHol van az IMAP támogatás a PHP-hoz?\rAlapértelmezetten az IMAP támogatás nincs aktiválva a PHP-hoz az XAMPP programban néhány megmagyarázhatatlan előkészítési hiba miatt egy-két otthoni verzióban, mint például a Windows 98-ban. Ha NT rendszerekkel dolgozik, megnyithatja a „\\\\xampp\\\\php\\\\php.ini” fájlt a PHP-kiterjesztés aktiválásához a kezdő pontosvessző eltávolításával a „;extension=php_imap.dll” sor elejéről. Ilyennek kell lennie:\rextension=php_imap.dll\rMost indítsa újra az Apache kiszolgálót és az IMAP működni fog. Ugyanezeket a lépéseket használhatja minden olyan kiterjesztésnél, amely nincs engedélyezve az alapértelmezett beállításban.\rMiért nem működik néhány nyílt forrású PHP alkalmazás a XAMPP programmal Windowson?\rSzámos Linuxhoz írt PHP alkalmazást vagy kiterjesztést még nem írtak át Windowsra. \rTörölhetem az „install” könyvtárat a telepítés után?\rJobban tenné, ha nem. Az itt lévő parancsfájlok még szükségesek a XAMPP minden további csomagjához (kiegészítőkhöz) és frissítéséhez.\rHogyan aktiválhatom az eAccelerator kiterjesztést?\rMint a többi (Zend) kiterjesztést, a „php.ini” fájlban aktiválhatja. Ebben a fájlban engedélyezze a „;zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"” sort. Ilyennek kell lennie:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rHogyan tudom javítani a csatlakozási hibát az MS SQL kiszolgálómhoz?\rHa az mssql kiterjesztés be lett töltve a php.ini fájlban, néha probléma jelentkezik, amikor kizárólag TCP/IP van használva. Kijavíthatja ezt a hibát a Microsoft által közzétett újabb „ntwdblib.dll” fájllal. Cserélje le a régebbi fájlt a „\\\\xampp\\\\apache\\\\bin” és a „\\\\xampp\\\\php” könyvtárban az újra. A licenc miatt nem csomagolhatjuk a XAMPP-hoz ennek a fájlnak az újabb verzióját.\rHogyan dolgozhatok a PHP mcrypt kiterjesztéssel?\rEhhez nyitottunk egy témát a fórumban példákkal és lehetséges megoldásokkal: \rMCrypt téma\rMűködik a Microsoft Active Server Pages (ASP) XAMPP-on?\rNem. És az Apache::ASP a Perl kiegészítővel nem ugyanaz. Az Apache::ASP csak ismeri a Perl-parancsfájlokat, de az Internet Information Server (IIS) által tartalmazott ASP szintén ismeri a normál VBScriptet. Azonban az ASP .NET-hez elérhető harmadik fél által készített Apache-modul.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright © Apache Friends, 2022.\rBlog\rAdatvédelmi irányelv\rCDN által nyújtott','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(51,'2022-11-22 16:37:13','main','s1|/dashboard/hu/howto.html',0,NULL,NULL,NULL,'/dashboard/hu/howto.html','XAMPP howto guides','Apache Friends\rMenu\rGyakori kérdések\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright © Apache Friends, 2022.\rBlog\rAdatvédelmi irányelv\rCDN által nyújtott','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(52,'2022-11-22 16:37:14','main','s1|/dashboard/hu/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/hu/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rGyakori kérdések\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright © Apache Friends, 2022.\rBlog\rAdatvédelmi irányelv\rCDN által nyújtott','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(53,'2022-11-22 16:37:12','main','s1|/dashboard/hu/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/hu/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rGyakori kérdések\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright © Apache Friends, 2022.\rBlog\rAdatvédelmi irányelv\rCDN által nyújtott','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(54,'2023-11-19 12:10:26','main','s1|/dashboard/hu/index.html',0,NULL,NULL,NULL,'/dashboard/hu/index.html','Welcome to XAMPP','Apache Friends\rMenu\rGyakori kérdések\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rGyakori kérdések\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nKözösség\rA XAMPP már több mint 10 éves &ndash; egy hatalmas közösség áll mögötte. Részt vehet benne, ha csatlakozik és igénybe veszi a \rFórumok\rszolgáltatását, lájkol minket a \rFacebook\rközösségi oldalán vagy követi a közzétételeinket a \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright © Apache Friends, 2022.\rBlog\rAdatvédelmi irányelv\rCDN által nyújtott','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(55,'2023-11-19 12:10:26','main','s1|/dashboard/index.html',0,NULL,NULL,NULL,'/dashboard/index.html','Welcome to XAMPP','Apache Friends\rMenu\rFAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rFAQs\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nCommunity\rXAMPP has been around for more than 10 years &ndash; there is a huge community behind it. You can get involved by joining our \rForums\r, liking us on \rFacebook\r, or following our exploits on \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPrivacy Policy\rCDN provided by','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(56,'2022-11-22 16:37:11','main','s1|/dashboard/it/faq.html',0,NULL,NULL,NULL,'/dashboard/it/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rDomande frequenti\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rDomande frequenti\rCome faccio ad installare XAMPP?\rXAMPP per Windows esiste in tre diversi modelli:\rInstallatore\rProbabilmente il modo più semplice per installare XAMPP.\rZIP:\rIl pannello di controllo XAMPP per avviare ed interrompere Apache, MySQL, FileZilla & Mercury o per installare questi server come servizi.\r7zip:\rPer i puristi con bassa larghezza di banda XAMPP e disponibile come archivio 7zip.\rNota: se avete estratto i file, possono essere presenti degli avvisi di virus falsi-positivi.\rUtilizzare il programma di installazione:\rIl pannello di controllo di XAMPP per avviare ed interrompere Apache, MySQL, FileZilla & Mercury od installare questi server come servizi.\rInstallazione da file ZIP\rDecomprimere gli archivi zip nella cartella di vostra scelta. XAMPP verrà estratto nella sottodirectory \"C:\\\\xampp\" sotto la directory di destinazione selezionata. Ora avviare il file \"setup_xampp.bat\", per regolare la configurazione XAMPP al vostro sistema.\rSe si sceglie una radice directory \'C \\\\ \' come obbietivo, non devi avviare \'setup_xampp.bat\'.\rCome con la versione installer, è ora possibile utilizzare il \'Pannello di controllo di XAMPP\' per ulteriori compiti.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rCome posso avviare XAMPP senza installazione?\rSe si estrae XAMPP in una cartella di livello superiore come \'C \\\\ \' o \'D \\\\ \', è possibile avviare la maggior parte dei server come Apache o MySQL direttamente senza l\'esecuzione del file \'setup_xampp.bat\'.\rNon usando lo script di installazione, oppure selezionando i percorsi relativi nello script di setup, è preferibile se si sta installando XAMPP su un drive usb. Perché su ogni pc una tale unità possa avere un\'altra lettera di unità. È possibile passare da assoluto a percorsi relativi in ​​ogni momento con lo script di installazione.\rUtilizzando il programma di installazione dalla nostra pagina di download è il modo più semplice per installare XAMPP.Dopo aver completato l\'installazione, troverete XAMPP sotto Start | Programmi | XAMPP. È possibile utilizzare il Pannello di controllo di XAMPP per avviare / arrestare tutti i server e anche installare / disinstallare servizi.\rIl pannello di controllo di XAMPP per avviare ed interrompere Apache, MySQL, FileZilla & Mercury od installare questi server come servizi.\rCome faccio ad avviare o stoppare XAMPP?\rIl centro di controllo universale è il \'Pannello di XAMPP Control\' (grazie www.nat32.com). Si è iniziato con:\r\\xampp\\xampp-control.exe\rÈ inoltre possibile utilizzare alcuni batchfiles per avviare/arrestare i server:\rAvvio Apache & MySQL:\n\\xampp\\xampp_start.exe\rApache & MySQL stop:\n\\xampp\\xampp_stop.exe\rAvvia Apache:\n\\xampp\\apache_start.bat\rFerma Apache:\n\\xampp\\apache_stop.bat\rAvvia Mysql:\n\\xampp\\mysql_start.bat\rFerma MySQL:\n\\xampp\\mysql_stop.bat\rAvvia Mercury Mailserve:\n\\xampp\\mercury_start.bat\rFerma Mercury Mailserver:\n\\xampp\\mercury_stop.bat\rAvvia FileZilla Server:\n\\xampp\\filezilla_start.bat\rFerma FileZilla Server:\n\\xampp\\filezilla_stop.bat\rCome posso verificare che tutto funzioni?\rDigitare il seguente URL sul vostro browser web preferito:\rhttp://localhost/\roppure \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rCome posso installare un server come servizio?\rPer ogni server XAMPP è possibile installare come servizio di Windows. È inoltre possibile installare dal pannello di controllo di XAMPP. In questo caso è necessario eseguire gli script o il pannello di controllo con privilegi di amministratore.\rInstallare il servizio Apache:\\\\xampp\\\\apache\\\\apache_installservice.bat\rDisinstallazione del servizio Apache:\\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rInstallazione del servizio MySQL: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rDisinstallazione sel servizio MySQL: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \rFileZilla (Server FTP) installazione/disinstallazione del servizio: \\\\xampp\\\\filezilla_setup.bat \rMercury Nessuna installazione disponibile per il servizio\rIl prodotto XAMPP e\' pronto?\rXAMPP non è inteso per la produzione ma solo per ambienti di sviluppo. Il modo in cui XAMPP è configurato è quello di essere più aperto possibile per permettere allo sviluppatore lui/lei di personalizzarlo. Per ambienti di sviluppo questo è ottimo ma in un ambiente di produzione potrebbe essere pericoloso.\rEcco una lista delle impostazioni di sicurezza mancanti in XAMPP:\rL\'amministratore di MySQL (root) non ha password.\rIl demone MySQL è accessibile via rete.\rProFTPD usa come password \"lampp\" e come user \"daemon\".\rL\'impostazione predefinita, gli utenti di Mercury e FileZilla sono noti.\rTutti i punti possono essere un enorme rischio per la sicurezza. Soprattutto se XAMPP è accessibile tramite la rete e le persone al di fuori della LAN. Può inoltre essere utile per utilizzare un firewall o un router NAT (Network Address Translation). In caso di un router o un firewall, il PC è normalmente non accessibili tramite la rete. A voi il compito di risolvere questi problemi. Come un piccolo aiuto c\'è il \"XAMPP Security console\".\rMettere in sicurezza XAMPP prima di pubblicare qualcosa online. UN firewall o un router esterno sono sufficienti solo per bassi livelli di sicurezza. Per più sicurezza, è possibile eseguire il \"XAMPP Security console\' e assegnare le password.\rSe volete avere il vostro XAMPP accessibili da Internet, si dovrebbe andare al seguente URI che può risolvere alcuni problemi\rhttp://localhost/security/\rCon la console di sicurezza è possibile impostare una password per l\'utente \'root\' MySQL e phpMyAdmin. È inoltre possibile attivare l\'autenticazione per i demopages XAMPP.\rQuesto strumento web-based non risolve tutti i problemi di sicurezza aggiuntivi! Soprattutto il server FileZilla FTP e il server di posta Mercury è necessario proteggerti.\rCome faccio a disinstallare XAMPP?\rSe avete installato XAMPP utilizzando la versione installer, si prega di utilizzare il programma di disinstallazione. Il programma di disinstallazione cancella tutte le voci di XAMPP dal registro di sistema e disinstallera\' alcuni servizi installati con XAMPP. Consigliamo vivamente di utilizzare il programma di disinstallazione per rimuovere le installazioni di XAMPP . Effettuate un backup del Installer version.Per salvare tutti i dati che si desidera conservare prima di disinstallare XAMPP.\rSe avete installato XAMPP utilizzando le versioni ZIP e 7zip, arrestare tutti i server XAMPP e chiudere tutti i pannelli. Se avete installato tutti i servizi, disinstallare e farli chiudere.Ora basta eliminare l\'intera cartella dove è installato XAMPP.Non ci sono voci di registro e non variabili d\'ambiente da ripulire.\rQual è la versione \'lite\' di XAMPP?\rXAMPP Lite (significa \'luce\', come in \'leggero\') è un insieme minore di componenti XAMPP, che è raccomandato per un lavoro veloce usando solo PHP e MySQL. Alcuni server o strumenti come Mercury Mail e FileZilla FTP mancano nella versione Lite\rDove devo inserire i miei contenuti web?\rLa directory principale per tutti i documenti WWW è \\\\xampp\\\\htdocs. Se inserisci un file \"test.html\" in questa directory, è possibile consultarlo con l\'URI \"http://localhost/test.html\".\rE \"test.php\"? Basta usare \"http://localhost/test.php\". Un semplice script di test può essere:\r<?php\recho \'Hello world\'; \r?>\rUna nuova sottodirectory per il web? Basta fare una nuova directory (p.e. \"nuova\") all\'interno della directory \"\\\\xampp\\\\htdocs\" (meglio senza spazi vuoti e solo ASCII), creare un file di prova in questa directory e accedervi con \"http://localhost/nuova/test.php\".\rUlteriori specifiche\rHTML:\rEseguibile: \\xampp\\htdocs\rAmmessi finali: .html .htm\r=> Pacchetto basico\rSSI:\rEseguibile: \\xampp\\htdocs\rAmmessi finali: .shtml\r=> Pacchetto basico\rCGI:\rEseguibile: \\xampp\\htdocs and \\xampp\\cgi-bin\rAmmessi finali: .cgi\r=> Pacchetto basico\rPHP:\rEseguibile: \\xampp\\htdocs and \\xampp\\cgi-bin\rAmmessi finali: .php\r=> Pacchetto basico\rPerl:\rEseguibile: \\xampp\\htdocs and \\xampp\\cgi-bin\rAmmessi finali: .pl\r=> Pacchetto basico\rApache::ASP Perl:\rEseguibile: \\xampp\\htdocs\rAmmessi finali: .asp\r=> Pacchetto basico\rJSP Java:\rEseguibile: \\xampp\\tomcat\\webapps\\java (e.g.)\rAmmessi finali: .jsp\r=> Tomcat add-on\rServlets Java:\rEseguibile: \\xampp\\tomcat\\webapps\\java (e.g.)\rAmmessi finali: .html (u.a)\r=> Tomcat add-on\rPosso spostare l\'installazione di XAMPP?\rSì. Dopo lo spostamento della directory XAMPP, è necessario eseguire \'setup_xampp.bat\'. I percorsi dei file di configurazione verranno regolati con questo passo.\rSe avete installato un server come servizio di Windows, è necessario prima rimuovere il servizio Windows, e dopo lo spostamento è possibile installare nuovamente il servizio.\rAttenzione I file di configurazione dei tuoi script, come le applicazioni PHP, non sono adeguati. Ma è possibile scrivere un \'plug-in\' per l\'installatore. Con tale plug-in, l\'installatore può regolare tali file.\rQuali sono le \'pagine avvio automatico »per le directory WWW?\rIl nome del file standard per la funzione di Apache \'DirectoryIndex\' è \'index.html\' o \'index.php\'. Ogni volta che si sta solo navigando in una cartella (ad esempio \'http / / localhost / xampp /\'), e Apache può trovare un file, Apache sta visualizzando questo file invece di un elenco di directory.\rCome posso cambiare la configurazione?\rQuasi tutte le impostazioni di XAMPP si possono modificare dal file di configurazione. Basta aprire il file in TextEdit e modificare l\'impostazione che si desidera. Solo FileZilla e Mercurio devono essere configurati con lo strumento di configurazione dell\'applicazione.\rPerché non è possibile che XAMPP funzioni su Windows XP SP2?\rMicrosoft con Service Pack 2 (SP2), offre un firewall migliore che si avvia automaticamente. Questo firewall blocca le porte necessarie 80 (http) e 443 (https) e Apache non può avviarsi.\rLa soluzione piu veloce:\rDisattivare il firewall di Microsoft dalla barra degli strumenti e tentare di avviare XAMPP un altra volta. La soluzione migliore è quella di definire un\'eccezione all\'interno del centro di sicurezza.\rLe seguenti porte sono utilizzate per le funzionalità di base:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rPerché XAMPP non funziona su Vista?\rControllo dell\'account utente (UAC)\rNella directory \"C: \\\\program files\" non avete i privilegi di scrittura, anche come Admin. O hai solo privilegi limitati (ad esempio per i \' .\\\\xampp\\\\htdocs\" ). In questo caso non è possibile modificare un file.\rSoluzione:\rElevare i tuoi privilegi in explorer (clic tasto destro/protezione) e disattivare il controllo dell\'account utente (UAC).\rÈ stato installato Apache/MySQL in \"C:\\\\xampp\" come servizio di Windows. Ma non è possibile avviare/arrestare i servizi con il \"Pannello di controllo di XAMPP\" o non è possibile disinstallarli.\rSoluzione:\rUtilizzate la console di gestione del servizio da Windows o disabilitare UAC.\rDisabilitare il controllo account utente (UAC)\rPer disabilitare l\'UAC, utilizzare il programma \'msconfig\'. In \'msconfig\' vai a \'Strumenti\', selezionare \'controllo dell\'account utente disabilita\' e verificare la selezione. Ora è necessario riavviare Windows. Allo stesso tempo, è possibile attivare nuovamente l\'UAC.\rCome faccio a controllare il checksum MD5?\rPer confrontare i file, vengono utilizzati spesso i checksum. Uno standard per creare questa checksum MD5 (Message Digest Algorithm 5).\rCon questo md5 checksum è possibile verificare se il download del pacchetto XAMPP è corretta o meno. Naturalmente è necessario un programma che può creare questi checksum. Per Windows è possibile utilizzare uno strumento di Microsoft:\rLa disponibilità e la descrizione del File Integrità Checksum Verifica utility \rÈ anche possibile utilizzare qualsiasi altro programma che può creare md5 checksum, come la GNU md5sum.\rCome avete installato un programma del genere (per esempio fciv.exe), si può fare seguendo i passaggi:\rScarica XAMPP (f.e. xampp-win32-1.8.2-0.exe)\rCreare il checksum con:\rfciv.exe xampp-win32-1.8.2-0.exe\rE ora si può paragonare questo checksum con quello lo puoi trovare su XAMPP per homepage di Windows.\rSe entrambi i checksum sono uguali, tutto è ok. In caso contrario, il download è dannegiato o il file è stato modificato.\rPerché i cambiamenti del mio php.ini non hanno avuto effetto?\rSe una variazione del \"php.ini\" non ha alcun effetto, è possibile che PHP ne stia utilizzando uno differente. È possibile verificarlo con phpinfo(). Vai alla URI http://localhost/xampp/phpinfo.php e cercare\"Loaded Configuration File\". Questo valore indica il \"php.ini\" realmente utilizzato da PHP.\rNote:\rDopo aver modificato la \'php.ini\' si deve riavviare Apache in modo che Apache/PHP possa leggere le nuove impostazioni.\rAiuto! C\'è un virus in XAMPP!\rAlcuni programmi antivirus scambiano XAMPP per un virus, in genere segnalando il file xampp-manager.exe Questo è un significativo falso positivo che l\'antivirus erroneamente identificato come un virus, quando non lo è. Prima di rilasciare ogni nuova versione di XAMPP testiamo attraverso software antivirus. Al momento stiamo utilizzando \rKapersky Online Virus Scanner\r. Puoi utilizzare anche lo strumento in linea \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rCome faccio a configurare il mio antivirus?\rAbbiamo incluso tutte le dipendenze ei server necessari per l\'esecuzione di applicazioni web in bundle, quindi troveremo che XAMPP installa un gran numero di file. Se si installa un\'applicazione XAMPP su una macchina Windows con un app antivirus abilitato, puo \'rallentare l\'installazione in modo significativo, e c\'è anche la possibilità che uno dei server (web server, database server) possono essere bloccati dal software antivirus .Se si dispone di uno strumento antivirus attivato, controllare le seguenti impostazioni per l\'esecuzione XAMPP senza problemi di prestazioni:\rAggiungere eccezioni nel firewall per Apache, MySQL o qualsiasi altro server.\rEseguire la scansione dei file durante l\'esecuzione Se è stata attivata la scansione antivirus di tutti i file, e i file eseguibili per i server si potranno rallentare.\rEseguire la scansione del traffico per URL diversi Se si sta sviluppando con XAMPP sulla propria macchina, è possibile escludere \'localhost\' traffico nelle impostazioni antivirus.\rPerché il server Apache non si avvia sul mio sistema?\rIl problema potrebbe essere uno dei seguenti motivi:\rÈ stato avviato più di un Server HTTP (IIS, Sambar, ZEUS e così via). Solo un Server può utilizzare la porta 80. Questo messaggio di errore di indica il problema:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rSe hai altri software, come Internet Telephone \'Skype\', che blocca anche la porta 80. Se il problema è \'Skype\', si può andare in Skype per Azioni -> Opzioni -> Connessione -> togliere il segno di spunta alla porta 80 per l\'uso di una porta alternativa\' e riavviare Skype. Ora dovrebbe funzionare.\rSe si dispone di un firewall che blocca la porta di Apache. Non tutti i firewall sono compatibili con Apache, e, talvolta, disattivare il firewall non è sufficiente ed è necessario disinstallare esso. Questo messaggio di errore indica un firewall:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rAnche se Apache e\' avviato , ma il vostro browser non riesce a connettersi ad esso potrebbe essere dovuto ad uno dei seguenti casi:\rAlcuni antivirus possono causare quest\' errore nello stesso modo del interferenza dei firewall.\rHai XP Professional senza service pack 1. È necessario avere almeno SP1 per XAMPP.\rSuggerimenti:\rSe hai problemi con le porte usate, puoi provare lo strumento \"xampp-portcheck.exe\". Forse ti può essere d\'aiuto.\rPerché il carico della CPU per Apache e quasi al 99%?\rC\'è uno dei due scenari in gioco. Sia la CPU non più sufficienti, o browser è possibile collegarsi al server, ma non vedo nulla (il sistema tenta unsucessfully per caricare la pagina).In entrambi i casi è possibile trovare il messaggio seguente nel file log di Apache:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rMPM lavora per salvaguardia su un\'implementazione più sicura, ma alcune richieste client non sono state elaborate correttamente. Per evitare questo errore, usa \"AcceptFilter\" con il filtro di accesso \"none\" nel file \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\".\rPerché le immagini e i fogli di stile non vengono visualizzati?\rA volte ci sono problemi con la visualizzazione di immagini e fogli di stile. Soprattutto se questi file si trovano su un\'unità di rete. In questo caso è possibile attivare (o aggiungere) uno se le seguenti righe nel file \'\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\'\rEnableSendfile off\rEnableMMAP off\rQuesto problema può essere causato anche da programmi per la regolazione della larghezza di banda, come NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rCome posso impostare una password di root in MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rPosso utilizzare il mio server MySQL?\rSì. Semplicemente non avviare il MySQL dal pacchetto XAMPP. Si prega di notare che due server non possono essere avviati sulla stessa porta. Se è stata impostata una password per \'root\', si prega di non dimenticare di modificare il file \'\\\\xampp\\\\phpMyAdmin\\\\config.inc.ph\".\rCome faccio a limitare l\'accesso a phpMyAdmin dall\'esterno?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rPrima di poter accedere al server MySQL, phpMyAdmin vi chiederà un nome utente e una password. Non dimenticare di impostare una password per l\'utente \'root\' prima.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rDove si trova il supporto IMAP per PHP?\rCome impostazione predefinita, il supporto IMAP per PHP è disattivato in XAMPP a causa di alcuni errori di inizializzazione misteriosi con alcune versioni home come Windows 98. Se si lavora con sistemi NT, è possibile aprire il file \'\\\\xampp\\\\php\\\\php.ini\'. Per attivare la exstension php rimuovendo il punto e virgola a partire dalla linea \'; estensione php_imap.dll\'. Dovrebbe essere:\rextension=php_imap.dll\rOra riavviate Apache e IMAP dovrebbe funzionare. È possibile utilizzare la stessa procedura per ogni estensione, che non è abilitata nella configurazione predefinita.\rPerché alcune applicazioni open source PHP non lavorano con XAMPP su Windows?\rMolte applicazioni PHP o estensioni che sono state scritte per Linux non sono state portate su di Windows \rEliminare la cartellla \"install\" dopo l\'installazione?\rE \'meglio non farlo. Sono ancora necessari gli script per tutti i pacchetti aggiuntivi (add-on) e aggiornamenti di XAMPP.\rCome faccio ad attivare la eAccelerator?\rCome altri (Zend), le estensioni, è possibile attivarlo in \'php.ini\'. In questo file, abilitare la riga \'; zend_extension\' \\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\'\'. Dovrebbe essere:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rCome posso risolvere un errore di connessione al mio server MS SQL?\rSe l\'estensione mssql è stato caricato nel php.ini, talvolta problemi solo quando viene utilizzato il protocollo TCP/IP. È possibile risolvere il problema con un nuovo \'ntwdblib.dll\" di Microsoft. Sostituire il vecchio file in \'\\\\xampp\\\\apache\\\\bin\' e \'\\\\xampp\\\\php\" con quello nuovo. A causa della licenza, non vi e un pacchetto di una versione più recente del file con XAMPP.\rCome faccio a lavorare con il PHP mcrypt è per lo più una estensione?\rPer questo, abbiamo aperto una discussione nel forum con gli esempi e le possibili soluzioni: % {mcrypt è per lo più una}\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rNo, e Apache::ASP con il Perl Add-on non e uguale.Apache::ASP conosce solo Perl-Script,ma ASP da Internet Information Server (IIS) conosce anche il normale VBScript.Ma per ASP .NET c\'è un modulo di 3rd party Apache disponibile.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica sulla privacy\rCDN fornito da','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(57,'2022-11-22 16:37:13','main','s1|/dashboard/it/howto.html',0,NULL,NULL,NULL,'/dashboard/it/howto.html','XAMPP howto guides','Apache Friends\rMenu\rDomande frequenti\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica sulla privacy\rCDN fornito da','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(58,'2022-11-22 16:37:14','main','s1|/dashboard/it/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/it/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rDomande frequenti\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica sulla privacy\rCDN fornito da','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(59,'2022-11-22 16:37:12','main','s1|/dashboard/it/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/it/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rDomande frequenti\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica sulla privacy\rCDN fornito da','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(60,'2023-11-19 12:10:26','main','s1|/dashboard/it/index.html',0,NULL,NULL,NULL,'/dashboard/it/index.html','Welcome to XAMPP','Apache Friends\rMenu\rDomande frequenti\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rDomande frequenti\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nComunità\rXAMPP è in uso da circa 10 anni ed ha alle sue spalle un\'enorme community. Anche tu puoi farne parte partecipando ai nostri \rForum\r, cliccando mi piace nella nostra pagina \rFacebook\r, oppure seguendo i nostri post su \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica sulla privacy\rCDN fornito da','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(61,'2022-11-22 16:37:11','main','s1|/dashboard/jp/faq.html',0,NULL,NULL,NULL,'/dashboard/jp/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rFAQ\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rよくある質問\rXAMPP のインストール方法\rWindows用のXAMPPを導入する手段は3つあります。\rインストーラを使う方法：\rおそらく最も簡単な方法です。\rZIP:\r補足：XAMPP は通常、ZIP形式で圧縮されています。 \r7zip:\r通信環境が悪い場合：XAMPPの7zip形式の圧縮ファイルを使用してください。\rNote: If you extract the files, there can be false-positives virus warnings.\rUsing the installer:\rXAMPPのコントロールパネルからApache、MySQL、FileZillaとMercury の開始/停止、サービス利用のためのサーバーインストールが行えます。\rInstalling from ZIP\rUnzip the zip archives into the folder of your choice. XAMPP is extracting to the subdirectory \"C:\\xampp\" below the selected target directory. Now start the file \"setup_xampp.bat\", to adjust the XAMPP configuration to your system.\rIf you choose a root directory \"C:\\\" as target, you must not start \"setup_xampp.bat\".\rインストーラのバージョンと同様に、追加のタスクについては、「 XAMPPコントロールパネル」を使用することができます。\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rどうやったらセットアップをすることなくXAMPPを起動することができますか？\rもし上位フォルダ（ \"C:\\\\\"や\"D:\\\\\"など）にXAMPPを展開する場合は、あなたは直接 setup_xampp.bat ファイルを実行することなくApacheやMySQLのようなほとんどのサーバーを起動することができます。\rUSBドライブにXAMPPをインストールしているなら、セットアップスクリプトを使わない、もしくは、セットアップスクリプト内の相対パスを選ばない方が良いです。それぞれのPCのドライブにはそれぞれのドライブ記号があります。セットアップスクリプトを使えばいつでも絶対パスから相対パスに変更することは可能です。 \rXAMPPをインストールする最も簡単な方法は、私たちのダウンロードページからインストーラを起動することです。インストールが完了したら、 スタート→全てのプログラム→XAMPPの中にXAMPPが格納されます 。あなたはXAMPPコントロールパネルを使用して、全てのサーバーの開始/停止、インストール/アンインストールを行うことができます。\rXAMPPのコントロールパネルからApache、MySQL、FileZillaとMercury の開始/停止、サービス利用のためのサーバーインストールが行えます。\rHow do I start and stop XAMPP?\r共通のコントロールセンターは、 「 XAMPPコントロールパネル」 （www.nat32.com）です。以下のように開始されます。\r\\xampp\\xampp-control.exe\rYou can also use some batchfiles to start/stop the servers:\rApache &amp：MySQL の開始：\n\\xampp\\xampp_start.exe\rApache & MySQL stop:\n\\xampp\\xampp_stop.exe\rApache start:\n\\xampp\\apache_start.bat\rApache stop:\n\\xampp\\apache_stop.bat\rMySQL start:\n\\xampp\\mysql_start.bat\rMySQLの停止：\n\\xampp\\mysql_stop.bat\rMercury メールサーバーの開始：\n\\xampp\\mercury_start.bat\rMercury メールサーバーの停止：\n\\xampp\\mercury_stop.bat\rFileZilla サーバーの開始：\n\\xampp\\filezilla_start.bat\rFileZilla サーバーの停止：\n\\xampp\\filezilla_stop.bat\rどのようにすれば、システムが正常に動いていることを確認できますか？ \rウェブブラウザで以下のURLにアクセスしてください：\rhttp://localhost/\rまたは \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rHow can I install a server as a service?\rXAMPP内の各サーバはWindowsサービスとしてもインストールすることができます。また、 XAMPPコントロールパネルからインストールすることができます。この場合には、管理者権限でスクリプトや[コントロールパネル]を実行する必要があります。\rApache サービスのインストール：\\\\xampp\\\\apache\\\\apache_installservice.bat\rApache サービスのアンインストール：\\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rMySQL service install: \\xampp\\mysql\\mysql_installservice.bat \rMySQL service uninstall: \\xampp\\mysql\\mysql_uninstallservice.bat \rFileZilla service (un)install: \\xampp\\filezilla_setup.bat \rMercury: No service installation available\rXAMPPを実際の運用で使用することはできますか？\rXAMPPは製品運用の手段ではなく、開発環境です。開発者の思った通りに何でもできるよう可能な限りオープンに設定されているのがXAMPPです。これは開発環境には素晴らしい事ですが、製品としては致命的です。\rXAMPPのセキュリティ上の脆弱性を以下に示します。\rMySQL の管理者 ID (root) にパスワードが設定されていません。 \rMySQL デーモンは、ネットワークを介してアクセス可能です。\rProFTPD uses the password \"lampp\" for user \"daemon\".\rThe default users of Mercury and FileZilla are known.\rAll points can be a huge security risk. Especially if XAMPP is accessible via network and people outside your LAN. It can also help to use a firewall or a (NAT) router. In case of a router or firewall, your PC is normally not accessible via network. It is up to you to fix these problems. As a small help there is the \"XAMPP Security console\".\rオンラインで何かを公開する前にXAMPPをセキュリティで保護してください。ファイアウォールまたは外部ルータは、セキュリティのレベルが低いためです。もう少しセキュリティを強化するために、 「 XAMPPセキュリティ・コンソール\"を実行し、パスワードを割り当てることができます。\r自分のXAMPPをインターネットからアクセスできるようにさせたいなら、問題を修正できるこのURIへ行って下さい。 \rhttp://localhost/security/\rセキュリティコンソールを使用すると、 MySQLユーザー\"root\" とphpMyAdminのパスワードを設定することができます。また、 XAMPPのデモページの認証を有効にすることができます。\rこのWebベースのツールは、追加のセキュリティ問題を修正しません！特に、 FileZillaのFTPサーバとMercuryメールサーバは、あなた自身でセキュリティ保護する必要があります。\rXAMPPをアンインストールするにはどうしたらよいでしょうか？\rインストーラのバージョンを使用して、 XAMPPをインストールした場合は、アンインストーラを使用してください。アンインストーラは、レジストリからすべてのXAMPPエントリを削除し、それがXAMPPに含まれているいくつかインストールされているサービスをアンインストールします。我々はXAMPPのインストールを除去するためのアンインストールプログラムを使用することを強くお勧めします。XAMPPをアンインストールする前に、保存しておきたいすべてのデータのバックアップを行ってください。\rIf you installed XAMPP using the ZIP and 7zip versions, shut down all XAMPP servers and exit all panels. If you installed any services, uninstall and shut them down too. Now simply delete the entire folder where XAMPP is installed. There are no registry entries and no environment variables to clean up.\rWhat is the \"lite\" version of XAMPP?\rXAMPP Lite (means \"light\" as in \"light-weight\") is a smaller bundle of XAMPP components, which is recommended for quick work using only PHP and MySQL. Some servers or tools such as Mercury Mail and FileZilla FTP are missing in the Lite version.\rWhere should I place my web content?\rThe main directory for all WWW documents is \\xampp\\htdocs. If you put a file \"test.html\" in this directory, you can access it with the URI \"http://localhost/test.html\".\rAnd \"test.php\"? Just use \"http://localhost/test.php\". A simple testscript can be:\r<?php\recho \'Hello world\'; \r?>\rA new subdirectory for your web? Just make a new directory (e.g. \"new\") inside the directory \"\\xampp\\htdocs\" (best without whitespaces and only ASCII), create a test file in this directory and access it with \"http://localhost/new/test.php\".\rFurther specifics\rHTML:\rExecutable: \\xampp\\htdocs\rAllowed endings: .html .htm\r=> basic package\rSSI:\rExecutable: \\xampp\\htdocs\rAllowed endings: .shtml\r=> basic package\rCGI:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .cgi\r=> basic package\rPHP:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .php\r=> basic package\rPerl:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .pl\r=> basic package\rApache::ASP Perl:\rExecutable: \\xampp\\htdocs\rAllowed endings: .asp\r=> basic package\rJSP Java:\rExecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rAllowed endings: .jsp\r=> Tomcat add-on\rServlets Java:\rExecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rAllowed endings: .html (u.a)\r=> Tomcat add-on\rCan I move the XAMPP installation?\rYes. After moving of the XAMPP directory, you must execute \"setup_xampp.bat\". The paths in the configuration files will be adjusted with this step.\rIf you have installed any server as Windows service, you must first remove the Windows service, and after the moving you can install the service again.\rWARNING: The configuration files from your own scripts, like PHP applications, are not adjusted. But it\'s possible to write a \"plug-in\" for the installer. With such a plug-in, the installer can adjust such files too.\rWhat are \"Automatic start pages\" for the WWW directories?\rThe standard filename for the Apache function \"DirectoryIndex\" is \"index.html\" or \"index.php\". Every time you are just browsing to a folder (e.g. \"http://localhost/xampp/\"), and Apache can find such a file, Apache is displaying this file instead of a directory listing.\rWhere can I change the configuration?\rAlmost all settings in XAMPP you can change with configuration files. Just open the file in a textedit and change the setting you want. Only FileZilla and Mercury should be configured with the application config tool.\rWhy can\'t XAMPP work on Windows XP SP2?\rMicrosoft delivers a better firewall with service pack 2 (SP2), which starts automatically. This firewall now blocks the necessary ports 80 (http) and 443 (https) and Apache can\'t start.\rThe fast solution:\rDisable the Microsoft firewall with the toolbar and try to start XAMPP onces more. The better solution is to define an exception within the security center.\rThe following ports are used for basic functionality:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rWhy doesn\'t XAMPP work on Vista?\rUser Account Control (UAC)\rIn the directory \"C:\\program files\" you don\'t have full write privileges, even as Admin. Or you have only limited privileges (e.g. for \".\\xampp\\htdocs\"). In this case you can\'t edit a file.\rSolution:\rRaise your privileges within explorer (right click / security) or deactivate the user account control (UAC).\rYou have installed Apache/MySQL in \"C:\\xampp\" as Windows service. But you can\'t start/stop the services with the \"XAMPP Control Panel\" or can\'t uninstall them.\rSolution:\rUse the service management console from Windows or deactivate UAC.\rDisabling the User Account Control (UAC)\rTo deactivate the UAC, use the program \"msconfig\". In \"msconfig\" go to \"Tools\", select \"disable user account control\" and verify your selection. Now you must restart Windows. At the same time, you can enable the UAC again.\rHow do I check the md5 checksum?\rTo compare files, often checksums are used. A standard to create this checksum md5 (Message Digest Algorithm 5).\rWith this md5 checksum you can test, if your download of the XAMPP package is correct or not. Of course you need a program which can create these checksums. For Windows you can use a tool from Microsoft:\rAvailability and description of the File Checksum Integrity Verifier utility\rIt\'s also possible to use any other program which can create md5 checksums, like the GNU md5sum.\rAs you have installed such a program (e.g. fciv.exe), you can do following steps:\rDownload XAMPP (f.e. xampp-win32-1.8.2-0.exe)\rCreate the checksum with:\rfciv.exe xampp-win32-1.8.2-0.exe\rAnd now you can compare this checksum with that one you can find on the XAMPP for Windows homepage.\rIf both checksums equal, all is ok. If not, the download is broken or the file has been changed.\rWhy have changes in my php.ini not taken effect?\rIf a change in the \"php.ini\" has no effect, it\'s possible PHP is using a different one. You can verify this with phpinfo(). Go to the URI http://localhost/xampp/phpinfo.php and search for \"Loaded Configuration File\". This value shows you the \"php.ini\" PHP is really using.\rNote:\rAfter changing the \"php.ini\" you have to restart Apache so that Apache/PHP can read the new settings.\rHelp! There is a virus in XAMPP!\rSome antivirus programs mistake XAMPP for a virus, typically flagging the file xampp-manager.exe This is a false positive meaning that the antivirus erroneously identified it as a virus, when it is not. Before we release each new version of XAMPP we run it through virus scanning software. At the moment we are using \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rHow do I configure my antivirus application?\rWe have included all dependences and servers required for running the bundled web application, so you will find that XAMPP installs large numbers of files. If you are installing a XAMPP application on a Windows machine with an antivirus app enabled, this may slow down the installation significantly, and there is also a chance that one of the servers (web server, database server) may be blocked by the antivirus software. If you have an antivirus tool enabled, check the following settings for running XAMPP without performance issues:\rAdd exceptions in the firewall: for Apache, MySQL or any other server.\rScan files when executing: If you have enabled the antivirus scan for all files, the executable files for the servers may slow down.\rScan the traffic for different URLs: If you are developing with XAMPP on your own machine, you can exclude \"localhost\" traffic in the Antivirus settings.\rWhy doesn\'t the Apache server start on my system?\rThis problem can be one of several reasons:\rYou have started more then one HTTP Server (IIS, Sambar, ZEUS and so on). Only one Server can use port 80. This error message indicate the problem:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rYou have other software, such as the Internet Telephone \"Skype\" which also blocks the port 80. If the problem is \"Skype\", you can go in Skype to Actions --> Options --> Connection --> remove the check mark at \"use port 80 for an alternate port\" and restart Skype. Now it should work.\rYou have a firewall which blocks the Apache port. Not all firewalls are compatible with Apache, and sometimes deactivating the firewall is not enough and you must deinstall it. This error message indicates a firewall:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rAlso if Apache can start, but your browser can\'t connect to it it could be due to one of the following:\rSome virus scanners can cause this in the same way that firewalls can interfere.\rYou have XP Professional without service pack 1. You must have at least SP1 for XAMPP.\rTip:\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\rWhy is my CPU load for Apache almost 99%?\rThere is one of two scenarios at play here. Either your CPU is maxing out, or you can browser connect to the server, but not see anything (the system is trying unsucessfully to load the page). In either case you can find the following message in the Apache log file:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rThe MPM falls back to a safer implementation, but some client requests were not processed correctly. In order to avoid this error, use \"AcceptFilter\" with accept filter \"none\" in the \"\\xampp\\apache\\conf\\extra\\httpd-mpm.conf\" file.\rWhy are pictures and style-sheets not displayed?\rSometimes there are problems with displaying pictures and style-sheets. Especially if these files are located on a network drive. In this case you can enable (or add) one if the following lines in the file \"\\xampp\\apache\\conf\\httpd.conf\":\rEnableSendfile off\rEnableMMAP off\rThis problem can also be caused by programs for regulating bandwidth, like NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rHow can I set a root password in MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rCan I use my own MySQL server?\rYes. Simply don\'t start the MySQL from the XAMPP package. Please note that two servers cannot be started on the same port. If you have set a password for \"root\", please do not forget to edit the file \"\\xampp\\phpMyAdmin\\config.inc.php\".\rHow do I restrict access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rBefore you can access the MySQL server, phpMyAdmin will prompt you for a user name and password. Don\'t forget to set a password for the user \"root\" first.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rWhere is the IMAP support for PHP?\rAs default, the IMAP support for PHP is deactivated in XAMPP due to some mysterious initialization errors with some home versions like Windows 98. If you work with NT systems, you can open the file \"\\xampp\\php\\php.ini\" to activate the php exstension by removing the beginning semicolon at the line \";extension=php_imap.dll\". It should be:\rextension=php_imap.dll\rNow restart Apache and IMAP should work. You can use the same steps for every extension, which is not enabled in the default configuration.\rWhy don\'t some PHP open source apps work with XAMPP on Windows?\rA lot of PHP applications or extensions that have been written for Linux haven’t been ported to Windows. \rCan I delete the \"install\" directory after installation?\rIt\'s better not to. The scripts here are still needed for all additional packages (add-ons) and upgrades of XAMPP.\rHow do I activate the eaccelerator?\rLike other (Zend) extensions, you can activate it in \"php.ini\". In this file, enable the line \";zend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\". It should be:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rHow do I fix a connection error to my MS SQL server?\rIf the mssql extension was loaded in the php.ini, sometimes problems appear when only TCP/IP is used. You can fix that problem with a newer \"ntwdblib.dll\" from Microsoft. Please replace the older file in \"\\xampp\\apache\\bin\" and \"\\xampp\\php\" with the new one. Because of the license, we can\'t package a newer version of this file with XAMPP.\rHow do I work with the PHP mcrypt extension?\rFor this, we have opened a topic in the forum with examples and possible solutions: \rMCrypt topic\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rNo. And Apache::ASP with the Perl Add-On is not the same. Apache::ASP only knows Perl-Script, but ASP from the Internet Information Server (IIS) also knows the normal VBScript. But for ASP .NET, there is a 3rd party Apache module available.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rブログ\r個人情報保護方針\rCDNから提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(62,'2022-11-22 16:37:13','main','s1|/dashboard/jp/howto.html',0,NULL,NULL,NULL,'/dashboard/jp/howto.html','XAMPP howto guides','Apache Friends\rMenu\rFAQ\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rブログ\r個人情報保護方針\rCDNから提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(63,'2022-11-22 16:37:14','main','s1|/dashboard/jp/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/jp/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rFAQ\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rブログ\r個人情報保護方針\rCDNから提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(64,'2022-11-22 16:37:12','main','s1|/dashboard/jp/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/jp/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rFAQ\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rブログ\r個人情報保護方針\rCDNから提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(65,'2023-11-19 12:10:26','main','s1|/dashboard/jp/index.html',0,NULL,NULL,NULL,'/dashboard/jp/index.html','Welcome to XAMPP','Apache Friends\rMenu\rFAQ\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rFAQ\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nコミュニティー\rXAMPP は10年以上の実績があります &ndash; よってその背後には大きなコミュニティーが存在します。弊社の \rフォーラム\rに参加、 %および \rFacebook\rで「いいね」ボタンを押す、\rTwitter\rでフォロー、このコミュニティーに参加することができます。\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rブログ\r個人情報保護方針\rCDNから提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(66,'2022-11-22 16:37:11','main','s1|/dashboard/pl/faq.html',0,NULL,NULL,NULL,'/dashboard/pl/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rNajczęściej zadawane pytania\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rNajczęściej zadawane pytania\rJak zainstalować XAMPP?\rXAMPP dla Windows występuje w trzech różnych odmianach:\rInstalator:\rPrawdopodobnie najprostszy sposób na zainstalowanie XAMPP.\rZIP:\rDla purystów: XAMPP jako zwyczajne archiwum ZIP.\r7zip:\rDla purystów z niskim transferem internetowym: XAMPP jako archiwum 7zip.\rUwaga: Jeśli wypakujesz pliki, mogą się pojawić fałszywe ostrzeżenia programów antywirusowych.\rUżywając programu instalacyjnego:\rPanel kontrolny XAMPP służy do uruchamiania/zatrzymywania Apache, MySQL, FileZilla & Mercury lub instalacji tych serwerów jako usługi systemowe.\rInstalowanie z pliku ZIP\rWypakuj archiwum zip do wybranego przez siebie folderu. XAMPP jest domyślnie wypakowywany do katalogu \"C:\\\\xampp\". Teraz uruchom plik \"setup_xampp.bat\" aby dostosować konfigurację XAMPP do twojego systemu.\rJeżeli wybrałeś katalog docelowy jako C:\\\\\", nie musisz uruchamiać pliku \"setup_xampp.bat\".\rTak jak w wersji instalacyjnej, możesz teraz użyć \"XAMPP Control Panel\" w celu wykonania dodatkowych zadań.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rJak mogę uruchomić XAMPP bez instalacji?\rJeśli wypakujesz XAMPP do katalogu głównego jak \"C:\\\\\" lub \"D:\\\\\", możesz uruchomić większość serwerów jak Apache czy MySQL bezpośrednio, bez potrzeby uruchamiania pliku \"setup_xampp.bat\".\rNależy nie używać skryptu instalacyjnego lub wybrać ścieżki względne w skrypcie instalacyjnym, jest to korzystne w przypadku instalacji XAMPP na dysku USB, ponieważ na każdym komputerze taki napęd może mieć inną literę napędu. Możesz w każdej chwili przełączyć się pomiędzy ścieżkami relatywnymi a absolutnymi w skrypcie instalacyjnym.\rUżywając instalatora z naszej strony pobierania, łatwo zainstalujesz pakiet XAMPP. Po instalacji XAMPP znajdziesz w Start => Programy => XAMPP. Możesz użyć Panelu Kontrolnego XAMPP, aby uruchamiać/zatrzymywać wszystkie serwery i także instalować/usuwać usługi.\rPanel kontrolny XAMPP służy do uruchamiania/zatrzymywania Apache, MySQL, FileZilla & Mercury lub instalacji tych serwerów jako usługi systemowe.\rJak mogę uruchomić i zatrzymać XAMPP?\rUniwersalne centrum kontroli to \"Panel Kontroli XAMPP\" (dzięki www.nat32.com). Jest uruchamiane z:\r\\xampp\\xampp-control.exe\rMożesz też użyć kilku skryptów by uruchomić lub zatrzymać serwery:\rUruchomienie Apache & MySQL:\n\\xampp\\xampp_start.exe\rZatrzymywanie Apache & MySQL:\n\\xampp\\xampp_stop.exe\rUruchomienie Apache\'a:\n\\xampp\\apache_start.bat\rZatrzymywanie Apache:\n\\xampp\\apache_stop.bat\rUruchamianie MySQL:\n\\xampp\\mysql_start.bat\rZatrzymywanie MySQL:\n\\xampp\\mysql_stop.bat\rUruchomienie serwera mailowego Mercury:\n\\xampp\\mercury_start.bat\rZatrzymywanie serwera mailowego Mercury:\n\\xampp\\mercury_stop.bat\rUruchomienie serwera FileZilla:\n\\xampp\\filezilla_start.bat\rZatrzymanie serwera FileZilla:\n\\xampp\\filezilla_stop.bat\rJak mogę sprawdzić czy wszystko działa?\rWprowadź poniższy URL w swojej ulubionej przeglądarce internetowej:\rhttp://localhost/\rlub \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rJak mogę zainstalować serwer jako usługę?\rKażdy serwer w pakiecie XAMPP może być zainstalowany jako usługa Windows. Możesz tego dokonać przez Panel Kontrolny XAMPP. W większości przypadków uruchomienie skryptów lub Panelu Kontrolnego wymaga uprawnień administratora.\rInstalacja usługi Apache: \\\\xampp\\\\apache\\\\apache_installservice.bat\rDeinstalacja usługi Apache: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rInstalacja usługi MySQL: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rDeinstalacja usługi MySQL: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \r(De)instalacja usługi FileZilla: \\\\xampp\\\\filezilla_setup.bat \rMercury: Brak instalacji usługi\rCzy XAMPP jest gotowy do środowiska produkcyjnego?\rXAMPP nie jest przeznaczony do zastosowań produkcyjnych, ale na środowisko deweloperskie. Sposób w jaki XAMPP jest skonfigurowany by być otwartym jak to tylko możliwe umożliwia deweloperom robić co zechcą. Do zastosowań deweloperskich jest to wspaniałe, ale do zastosowań produkcyjnych może być fatalne.\rTo jest lista pominiętych zabezpieczeń w XAMPP:\rAdministrator MySQL (root) nie ma hasła.\rUsługa MySQL jest dostępna przez sieć.\rProFTPD używa hasła \"lampp\" dla użytkownika \"daemon\".\rDomyślni użytkownicy programu Mercury i FileZilla są znani.\rWszystkie punkty mogą być ogromnym zagrożeniem dla bezpieczeństwa. Zwłaszcza jeżeli XAMPP jest dostępny przez sieć i ludzie mają dostęp do niego poza twoją siecią LAN. Także może być pomocne użycie zapory sieciowej lub routera NAT. W przypadku routera lub zapory twój komputer nie jest normalnie dostępny przez sieć. To do ciebie należy zadanie rozwiązania tych problemów. Jako małą pomoc dajemy \"konsolę bezpieczeństwa XAMPP\".\rProszę zabezpieczyć XAMPP przed opublikowaniem czegokolwiek w Internecie. Zapora sieciowa lub zewnętrzny router wystarczają tylko na niskim poziomie bezpieczeństwa. Aby wpłynąć na nieco większe bezpieczeństwo, można uruchomić konsolę bezpieczeństwa XAMPP i przypisać hasła.\rJeżeli chcesz aby twój XAMPP był dostępny przez internet, powinieneś podążyć za poniższym URI, który może naprawić niektóre problemy:\rhttp://localhost/security/\rZ konsolą bezpieczeństwa możesz ustawić hasło dla administratora MySQL i phpMyAdmina. Możesz także włączyć uwierzytelnianie dla stron z pakietu XAMPP.\rTo narzędzie webowe nie potrafi naprawić każdej dodatkowej kwestii odnośnie bezpieczeństwa. W szczególności musisz sam ustawić serwer FileZilla FTP i serwer mailowy Mercury.\rJak odinstalować XAMPP?\rJeżeli zainstalowałeś pakiet XAMPP używając instalatora, proszę użyj deinstalatora. Deinstalator skasuje wszystkie wpisy XAMPP z twojego rejestru i także deinstaluje jakieś zainstalowane usługi włączone w pakiecie XAMPP. Bardzo polecamy użycie deinstalatora przy usuwaniu instalacji XAMPP. Proszę zrobić kopię zapasową wszystkich swoich danych przed deinstalacją pakietu XAMPP.\rJeżeli zainstalowałeś XAMPP używając programu ZIP i 7zip, wyłącz wszystkie serwery XAMPP i wyłącz wszystkie panele. Jeżeli instalowałeś jakieś usługi, odinstaluj je. Teraz możesz usunąć folder gdzie XAMPP został zainstalowany. Nie trzeba czyścić niczego więcej, ponieważ rejestr nie zawiera żadnych wpisów i zmiennych środowiskowych.\rCo to jest wersja \"lite\" pakietu XAMPP?\rXAMPP Lite (oznacza \"lekki\" w znaczeniu \"lekko ważący\") jest mniejszym zestawem komponentów XAMPP, który jest zalecany dla szybszej pracy, używającej tylko PHP i MySQL. Niektóre serwery lub narzędzia tj. Mercury Mail i FileZilla FTP nie występują w wersji lekkiej.\rGdzie powinienem umieścić pliki z moją aplikacją internetową?\rGłówny folder dla wszystkich dokumentów WWW to \\\\xampp\\\\htdocs. Jeżeli umieścisz w tym katalogu plik \"test.html\", będziesz miał do niego dostęp przez URI: \"http://localhost/test.html\".\rI \"test.php\"? Wystarczy użyć http://localhost/test.php\". Prostym skryptem testowym może być:\r<?php\recho \'Hello world\'; \r?>\rNowy podkatalog dla twojej strony www? Stwórz nowy katalog (np. \"nowy\") wewnątrz katalogu \"\\\\xampp\\\\htdocs\" (najlepiej bez znaków odstępów i tylko używając znaków ASCII), utwórz plik testowy w tym katalogu i spróbuj uzyskać do niego dostęp przez URL: \"http://localhost/nowy/test.php\".\rInne specyfikacje\rHTML:\rWykonywalny: \\xampp\\htdocs\rDozwolone zakończenia: .html .htm\r=> pakiet podstawowy\rSSI:\rWykonywalny: \\xampp\\htdocs\rDozwolone zakończenia: .shtml\r=> pakiet podstawowy\rCGI:\rWykonywalny: \\xampp\\htdocs and \\xampp\\cgi-bin\rDozwolone zakończenia: .cgi\r=> pakiet podstawowy\rPHP:\rWykonywalny: \\xampp\\htdocs and \\xampp\\cgi-bin\rDozwolone zakończenia: .php\r=> pakiet podstawowy\rPerl:\rWykonywalny: \\xampp\\htdocs and \\xampp\\cgi-bin\rDozwolone zakończenia: .pl\r=> pakiet podstawowy\rApache::ASP Perl:\rWykonywalny: \\xampp\\htdocs\rDozwolone zakończenia: .asp\r=> pakiet podstawowy\rJSP Java:\rWykonywalny: \\xampp\\tomcat\\webapps\\java (e.g.)\rDozwolone zakończenia: .jsp\r=> Tomcat add-on\rServlets Java:\rWykonywalny: \\xampp\\tomcat\\webapps\\java (e.g.)\rDozwolone zakończenia: .html (u.a)\r=> Tomcat add-on\rCzy mogę przenieść instalację XAMPP?\rTak. Po przeniesieniu katalogu XAMPP, musisz wykonywać plik setup_xampp.bat\". W tym kroku ścieżki w plikach konfiguracyjnych zostaną zaktualizowane.\rJeżeli masz jakiś serwer zainstalowany jako usługę Windows, musisz najpierw usunąć usługę, a dopiero po przeniesieniu katalogu ponownie zainstalować usługę.\rOstrzeżenie: Pliki konfiguracji z twoich własnych skryptów, tj. aplikacji PHP, nie są aktualizowane. Ale jest możliwość napisania \"wtyczki\" dla instalatora. Z tą wtyczką, instalator może też te pliki zaktualizować.\rCo to są \"Automatyczne strony startowe\" dla katalogów WWW?\rStandardowa nazwa pliku dla funkcji Apache\'a \"DirectoryIndex\" to \"index.html\" lub \"index.php\". Za każdym razem kiedy przeglądasz folder (np. \"http://localhost/xampp/\"), Apache szuka jednego z tych plików, zamiast wyświetlać listę plików z katalogu.\rGdzie mogę zmienić konfigurację?\rPrawie wszystkie ustawienia w XAMPP możesz zmienić w plikach konfiguracyjnych. Otwórz plik w edytorze pliku i zmień wybrane przez siebie ustawienie. Tylko aplikacje FileZilla i Mercury powinne być skonfigurowane wykorzystując wewnętrzne narzędzie do konfiguracji.\rDlaczego XAMPP nie może pracować na Windows XP SP2?\rMicrosoft dostarcza lepszą zaporę sieciową z Service Pack 2 (SP2), która uruchamia się automatycznie przy starcie systemu. Ta zapora sieciowa blokuje teraz potrzebne porty 80 (http) i 443 (https) i Apache nie może się uruchomić.\rSzybkie rozwiązanie:\rWyłącz zaporę sieciową Microsoftu i spróbuj ponownie uruchomić XAMPP. Lepszym rozwiązaniem jest zdefiniowanie wyjątków w centrum zabezpieczeń.\rPoniższe porty są używane dla podstawowej funkcjonalności:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rDlaczego XAMPP nie pracuje na Microsoft Vista?\rKontrola konta użytkownika (UAC)\rW katalogu \"C:\\\\program files\" nie masz pełnych praw zapisu jako administrator. Lub masz ograniczone uprawnienia (np. dla \".\\\\xampp\\\\htdocs\"). W tym przypadku nie można edytować pliku.\rRozwiązanie:\rPodnieść swoje uprawnienia w eksploratorze (prawy klik / bezpieczeństwo) lub wyłącz kontrolę konta użytkownika (UAC).\rMasz zainstalowany Apache/MySQL w \"C:\\\\xampp\" jako usługi Windows. Ale nie uruchomiłeś/zatrzymałeś usługi przez Panel Kontrolny XAMPP lub ich nie odinstalowałeś.\rRozwiązanie:\rUżyj konsoli zarządzania usługami w Windowsie lub wyłącz UAC.\rWyłączanie Kontroli Konta Użytkownika (UAC)\rAby wyłączyć UAC, użyj programu \"msconfig\". W \"msconfig\" idź do \"Narzędzia\", wybierz \"wyłącz kontrolę konta użytkownika\" i zweryfikuj swój wybór. Restartuj Windows. W każdym czasie możesz ponownie włączyć UAC.\rJak mogę sprawdzić sumę kontrolną MD5?\rAby porównać pliki, najczęściej porównuje się ich sumy kontrolne. Do utworzenia tych sum wystarczy standardowo MD5 (Message Digest Algorithm 5).\rZ sumą kontrolną md5 możesz przetestować czy twoja paczka XAMPP została pobrana prawidłowo czy też nie. Oczywiście potrzebujesz programu, który utworzy te sumy kontrolne. Dla Windows możesz użyć narzędzia z Microsoftu:\rDostępność i opis narzędzia integracji weryfikacji sumy kontrolnej pliku\rMożliwe jest również użycie innego programu, który potrafi utworzyć sumę kontrolną md5, np. GNU md5sum.\rJeżeli masz zainstalowany program (np. fciv.exe), wykonaj poniższe kroki:\rPobierz XAMPP (np. xampp-win32-1.8.2-0.exe)\rUtwórz sumę kontrolną z:\rfciv.exe xampp-win32-1.8.2-0.exe\rI teraz możesz porównać swoją sumę kontrolną z tą znalezioną na stronie XAMPP dla Windows.\rJeżeli obie sumy są równe, wszystko jest w porządku. Jeżeli nie, pobrany plik jest uszkodzony lub został zmieniony.\rDlaczego zmiany w php.ini nie przynoszą efektu?\rJeżeli zmiana w \"php.ini\" nie przynosi efektu, możliwe że PHP używa innego pliku. Możesz zweryfikować to na podstawie funkcji phpinfo(). Idź do http://localhost/xampp/phpinfo.php i poszukaj \"Loaded Configuration File\". Ta wartość pokazuje który plik \"php.ini\" jest przez PHP używany.\rUwaga:\rPo zmianach w pliku \"php.ini\" musisz zrestartować Apache, aby Apache i PHP wczytały nowe ustawienia.\rPomocy! W pakiecie XAMPP jest wirus!\rNiektóre programy antywirusowe traktują XAMPP jak wirus, zwykle wskazując na plik xampp-manager.exe. To jest fałszywe powiadomienie ze strony programu antywirusowego, ponieważ pakiet XAMPP nie zawiera wirusów. Przed opublikowaniem nowej wersji XAMPP, przepuszczamy pakiet i pliki przez program antywirusowy. W tym momencie używamy \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rJak mogę skonfigurować mój program antywirusowy?\rWłączyliśmy wszystkie zależności i serwery niezbędne do uruchomienia aplikacji internetowej, więc można zauważyć, że XAMPP instaluje dużą liczbę plików. Jeżeli instalujesz XAMPP na Windowsie z włączonym programem antywirusowym, to może znacznie spowolnić instalację, i jest szansa, że jeden z serwerów (serwer www, serwer bazy danych) może zostać zablokowany przez program antywirusowy. Jeżeli masz włączony program antywirusowy, sprawdź następujące ustawienia by mieć XAMPP działający bez problemów związanych z wydajnością:\rDodaj wyjątki do swojej zapory sieciowej: dla Apache\'a, MySQL i innych serwerów.\rSkanuj pliki podczas uruchamiania: Jeśli włączono skanowanie antywirusowe dla wszystkich plików, pliki wykonywalne serwerów mogą być spowalniane.\rSkanuj ruch dla różnych adresów URL: jeżeli rozwijasz z pakietem XAMPP na swoim komputerze, możesz wykluczyć ruch z \"localhost\" (hosta lokalnego) w ustawieniach programu antywirusowego.\rDlaczego Apache nie uruchamia się w moim systemie?\rTen problem może występować z kilku powodów:\rMożesz mieć uruchomionych więcej niż jeden serwer HTTP (IIS, Sambar, ZEUS, lub inny). Tylko jeden serwer może korzystać z portu 80. Ten komunikat o błędzie wskazuje problem:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rJeżeli masz inne oprogramowanie, tj. telefonię internetową Skype, która też blokuje port 80. Jeżeli problem stwarza Skype, w Skype z menu wybierz Akcje --> Opcje --> Połączenie --> usuń znaczek przy opcji \"użyj portu 80 jako portu alternatywnego\" i zrestartuj Skype. Teraz serwer powinien pracować poprawnie.\rMasz zaporę sieciową, która blokuje port Apache. Nie wszystkie zapory sieciowe są zgodne z Apache, i czasami dezaktywacja zapory nie wystarcza i trzeba ją usunąć. Ten komunikat o błędzie wskazuje zaporę:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rTakże jeżeli Apache może się uruchomić, ale twoja przeglądarka nie może się połączyć, to może być spowodowane przez:\rNiektóre skanery antywirusowe mogą powodować problemy w podobny sposób jak to robią zapory sieciowe.\rMasz Windows XP Professional bez Service Pack 1. Musisz mieć przynajmniej SP1 dla XAMPP.\rPorada:\rJeżeli masz problemy z użyciem portów, możesz spróbować uruchomić narzędzie \"xampp-portcheck.exe\". To może pomóc.\rDlaczego moje obciążenie dla Apache\'a jest bliskie 99%?\rTutaj może wystąpić jeden z dwóch scenariuszy. Jeżeli twój procesor jest maksymalnie wykorzystywany, lub twoja przeglądarka może połączyć się z serwerem, ale nic nie widzisz (system próbuje nieskutecznie załadować stronę). W każdym przypadku znajdziesz poniższą wiadomość w pliku zdarzeń Apache\'a:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rMPM wraca do bezpiecznego wykonania, ale niektóre żądania klientów nie zostały przetworzone w sposób prawidłowy. Aby uniknąć tego błędu, należy użyć \"acceptfilter\" z akceptacją filtra \"none\" w pliku \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\".\rDlaczego zdjęcia i arkusze stylu nie są wyświetlane?\rCzasami są problemy z wyświetleniem obrazków i arkuszy stylów. Zwłaszcza jeśli te pliki znajdują się na dysku sieciowym. W tym przypadku powinieneś włączyć (lub dodać) jedną z poniższych linii w pliku \"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\":\rEnableSendfile off\rEnableMMAP off\rTen problem może być również spowodowany przez programy do regulacji przepustowości pasma, tj. program NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rJak mogę ustawić hasło administratora w MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rCzy mogę użyć swojego własnego serwera MySQL?\rTak. Najprościej nie uruchamiać MySQL z pakietu XAMPP. Proszę zauważyć, że dwa serwery nie mogą być uruchomione na tym samym porcie. Jeżeli masz ustawione hasło dla użytkownika MySQL \"root\", proszę nie zapomnieć zaktualizować pliku \"\\\\xampp\\\\phpMyAdmin\\\\config.inc.php\".\rJak mogę ograniczyć dostęp do phpMyAdmina z zewnątrz?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rPrzed twoim dostępem do serwera MySQL, phpMyAdmin zapyta cię o nazwę użytkownika i hasło. Nie zapomnij najpierw ustawić hasła dla użytkownika \"root\".\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rGdzie jest wsparcie IMAP dla PHP?\rDomyślnie, wsparcie IMAP dla PHP w XAMPP jest wyłączone, ze względu na jakieś tajemnicze błędy inicjalizacji dla wersji domowych podobnych do Windows 98. Jeżeli pracujesz z systemami NT, możesz otworzyć plik \"\\\\xampp\\\\php\\\\php.ini\" i aktywować rozszerzenie PHP przez usunięcie średnika na początku linii \";extension=php_imap.dll\". To powinno być:\rextension=php_imap.dll\rTeraz zrestartuj Apache\'a i IMAP powinien już pracować. Możesz użyć tych samych kroków dla każdego rozszerzenia, który nie jest domyślnie włączony w konfiguracji.\rDlaczego niektóre aplikacje PHP o otwartym kodze źródłowym nie pracują z XAMPP na Windowsie?\rWiele aplikacji PHP lub rozszerzeń, które powstały na system Linux, nie zostało przepisanych na Windowsa. \rCzy mogę usunąć katalog \"install\" po instalacji?\rLepiej nie. Skrypty tutaj są wciąż potrzebne dla wszystkich pakietów dodatkowych (dodatków) i aktualizacji XAMPP.\rJak mogę aktywować eaccelerator?\rPodobnie jak w innych (Zend) rozszerzeniach, musisz aktywować to w pliku php.ini. W tym pliku włącz linię \";zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"\". To powinno wyglądać:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rJak mogę naprawić błędy połączenia do mojego serwera MS SQL?\rJeżeli rozszerzenie mssql zostało załadowane w pliku php.ini, czasami problemy występują kiedy tylko TCP/IP jest używany. Możesz naprawić ten problem z nową wersją \"ntwdblib.dll\" ze strony Microsoftu. Zastąp tym nowszym plikiem, plikami znajdującymi się w \"\\\\xampp\\\\apache\\\\bin\" i \"\\\\xampp\\\\php\". Ze względu na licencję tego pliku, nie możemy spakować jego nowszą wersję z pakietem XAMPP.\rJak mogę pracować z rozszerzeniem PHP mcrypt?\rDla niego otworzyliśmy temat na forum z przykładami i możliwymi rozwiązaniami: \rTemat MCrypt\rCzy Microsoft Active Server Pages (ASP) pracuje z XAMPP?\rNie. Apache::ASP z dodatkiem Perl to nie to samo. Apache::ASP zna tylko skrypty Perl, ale ASP z Internet Information Server (IIS) zna także normalny język VBScript. Ale dla ASP .NET są dostępne moduły Apache firm trzecich.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rPrawa zastrzeżone (c) 2022, Apache Friends\rBlog\rPolityka prywatności\rCDN dostarczone przez','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(67,'2022-11-22 16:37:13','main','s1|/dashboard/pl/howto.html',0,NULL,NULL,NULL,'/dashboard/pl/howto.html','XAMPP howto guides','Apache Friends\rMenu\rNajczęściej zadawane pytania\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rPrawa zastrzeżone (c) 2022, Apache Friends\rBlog\rPolityka prywatności\rCDN dostarczone przez','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(68,'2022-11-22 16:37:14','main','s1|/dashboard/pl/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/pl/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rNajczęściej zadawane pytania\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rPrawa zastrzeżone (c) 2022, Apache Friends\rBlog\rPolityka prywatności\rCDN dostarczone przez','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(69,'2022-11-22 16:37:12','main','s1|/dashboard/pl/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/pl/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rNajczęściej zadawane pytania\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rPrawa zastrzeżone (c) 2022, Apache Friends\rBlog\rPolityka prywatności\rCDN dostarczone przez','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(70,'2023-11-19 12:10:26','main','s1|/dashboard/pl/index.html',0,NULL,NULL,NULL,'/dashboard/pl/index.html','Welcome to XAMPP','Apache Friends\rMenu\rNajczęściej zadawane pytania\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rNajczęściej zadawane pytania\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nSpołeczność\rXAMPP ma już ponad 10 lat &ndash; i posiada ogromną społeczność. Możesz zaangażować się przez dołączenie się do naszego \rFora dyskusyjne\r, i polubiając nas na \rFacebook\rlub przeglądając nasze wyczyny na \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rPrawa zastrzeżone (c) 2022, Apache Friends\rBlog\rPolityka prywatności\rCDN dostarczone przez','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(71,'2022-11-22 16:37:11','main','s1|/dashboard/pt_br/faq.html',0,NULL,NULL,NULL,'/dashboard/pt_br/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rPerguntas Frequentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rPerguntas Mais Frequentes\rComo instalo o XAMPP?\rO XAMPP para Windows existe em três diferentes modalidades:\rInstalador:\rProvavelmente o jeito mais fácil de instalar XAMPP.\rZIP:\rPara os puristas: XAMPP como um arquivo ZIP comum.\r7zip:\rPara os puristas com pouca largura de banda: XAMPP como um arquivo 7zip.\rNota: Se você descompactar os arquivos, pode ser que receba avisos falso-positivos de vírus.\rExecutando o instalador\rPainel de controle do XAMPP para niciar/parar o Apache, MySQL, FileZilla e Mercury ou instalar esses servidores como serviços.\rInstalando a partir de ZIP\rDescompacte os arquivos zip para a pasta de sua escolha. Extraia o XAMPP para o subdiretório \"C:\\\\xampp\", abaixo do diretório de destino selecionado. Agora inicie o arquivo \"setup_xampp.bat\", para ajustar a configuração do XAMPP para seu sistema.\rSe você escolher um diretório raiz \"C:\\\\\" como alvo, você não deve começar o \"setup_xampp.bat\".\rDa mesma forma que a versão do instalador, agora você pode usar o \"Painel de Controle\" do XAMPP para tarefas adicionais.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rComo posso inicializar o XAMPP sem instalação?\rSe você extrair o XAMPP em uma pasta na raiz de qualquer unidade, como \"C:\\\\\" ou \"D:\\\\\", por exemplo, você pode executar a maioria dos servidores como Apache ou MySQL diretamente sem antes ter de executar o arquivo \"setup_xampp.bat\".\rCaso esteja instalando o XAMPP em um drive USB, é preferível que você não use o script de instalação e se mesmo assim quiser usá-lo, selecione caminhos relativos no script de instalação. Isto, porque para cada pc o mesmo drive pode ter uma outra letra de unidade, diferente daquela especificada no caminho absoluto. Você poderá trocar os caminhos de relativo para absoluto a qualquer momento com o script de instalação.\rA maneira mais fácil de instalar o XAMPP é usar o instalador de nossa página de Downloads. Ao completar a instalação, você encontrará o XAMPP em Iniciar > Programas > XAMPP. Você pode usar o Painel de Controle do XAMPP para inicializar/interromper todos os servidores e também para instalar/desinstalar os servidores como serviços do sistema.\rPainel de controle do XAMPP para niciar/parar o Apache, MySQL, FileZilla e Mercury ou instalar esses servidores como serviços.\rComo inicio e paro o XAMPP?\rO centro de controle universal é o \"Painel de Controle XAMPP\" (Obrigado www.nat32.com). Ele é iniciado com:\r\\xampp\\xampp-control.exe\rVocê pode ainda usar alguns batchfiles para Iniciar/Parar os servidores:\rIniciar MySQL e Apache:\n\\xampp\\xampp_start.exe\rParar MySQL e Apache:\n\\xampp\\xampp_stop.exe\rIniciar Apache:\n\\xampp\\apache_start.bat\rParar o Apache:\n\\xampp\\apache_stop.bat\rIniciar o MySQL:\n\\xampp\\mysql_start.bat\rParar o MySQL:\n\\xampp\\mysql_stop.bat\rInicializar o Mercury Mailserver:\n\\xampp\\mercury_start.bat\rParar Mercury Mailserver:\n\\xampp\\mercury_stop.bat\rIniciar FileZilla:\n\\xampp\\filezilla_start.bat\rParar FileZilla:\n\\xampp\\filezilla_stop.bat\rComo posso testar se tudo funcionou corretamente?\rEscreva o seguinte URL no seu navegador favorito:\rhttp://localhost/\rou \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rComo posso instalar um servidor como um serviço?\rCada servidor no XAMPP pode também ser instalado como um serviço do Windows. Você pode, ainda, instala-los pelo Painel de Controle do XAMPP. Nesse caso, é necessário rodar os scripts ou o Painel de Controle com privilégios de Adminstrador.\rInstalação do serviço do Apache: \\\\xampp\\\\apache\\\\apache_installservice.bat\rDesinstalação do serviço do Apache: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rInstalação do serviço do MySQL: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rDesinstalar o MySQL como um serviço do sistema: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \rInstalar/Desinstalar o FileZilla como um serviço do sistema: \\\\xampp\\\\filezilla_setup.bat \rMercury: Instalação como um serviço do sistema indisponível\rXAMPP está pronto para produção?\rXAMPP não é destinado para uso em produção, mas apenas para ambientes de desenvolvimento. O XAMPP é configurado para ser o mais aberto possível para permitir ao desenvolvedor qualquer coisa que ele/ela quiser. Para ambientes de desenvolvimento ele é ótimo, mas em um ambiente de produção , ele pode ser fatal. \rAqui uma lista de segurança que faltava no XAMPP:\rO administrador (root) do MySQL não tem senha.\rO daemon do MySQL está acessível pela rede. \rProFTPD usa a senha \"lampp\" para o usuário \"daemon\".\rOs usuários padrão do Mercury e FileZilla são conhecidos.\rTodos os pontos podem ser um grande risco de segurança. Especialmente se o XAMPP está acessível via rede e pessoas fora da sua LAN. Também pode ajudar a usar um firewall ou um roteador (NAT). No caso de um roteador ou firewall, seu PC normalmente não é acessível via rede. É até você para corrigir esses problemas. Como uma pequena ajuda,em \"XAMPP Security console\".\rPor favor, proteja o XAMPP antes de publicar qualquer coisa on-line. Um firewall ou um roteador externo são apenas suficientes para baixos níveis de segurança. Para um pouco mais de segurança, você pode executar o \"XAMPP Security console\" e atribuir senhas.\rSe você quiser ter o seu XAMPP acessível a partir da internet, você deve ir para o seguinte URI que pode corrigir alguns problemas:\rhttp://localhost/security/\rCom o console de segurança, você pode definir uma senha para o usuário MySQL \"root\" e phpMyAdmin. Você também pode ativar a autenticação para o demopages do XAMPP.\rEssa ferramenta baseada em web não corrige nenhum problema adicional de segurança! O servidor FileZilla FTP e o servidor de mensagens Mercury devem, especialmente, serem protegidos por você.\rComo desinstalo o XAMPP?\rSe você instalou a versão do XAMPP com instalador, por favor use o Desinstalador. O Desinstalador irá apagar todas as entradas do XAMPP dos seus registros e irá desinstalar alguns serviços incluídos com o XAMPP. Nós recomendamos que você utilize o programa desinstalador para remover as instalações de XAMPP feitas pelo instalador. Por favor, faça uma cópia de segurança de toda a informação que você deseja manter antes de desinstalar o XAMPP.\rSe você instalou o XAMPP usando as versões em ZIP ou 7zip, desligue todos os servidores XAMPP e saia de todos os painéis. Se você instalou algum serviço, desinstale-os e desligue-os também. Agora, simplesmente apague todo a pasta onde o XAMPP está instalado. Não há entradas de registro ou variáveis de ambiente para limpar.\rO que é a versão \"lite\"de XAMPP?\rXAMPP Lite (significa \"leve\"como em \"peso-leve\") é um pacote menor de componentes do XAMPP que é recomendado para trabalhos rápidos que usem somente PHP e MySQL. Alguns servidores e ferramentas, tais como o Mercury Mail e o FileZilla FTP, não estão presentes da versão Lite.\rOnde devo colocar meu conteúdo web?\rO diretório principal para todos os documentos WWW é \\\\xampp\\\\htdocs. Se você colocar um arquivo \"test.html\"neste diretório, você poderá acessa-lo com a URI \"http://localhost/test.html\".\rE \"test.php\"? Apenas use \"http://localhost/test.php\". Um script de teste simples pode ser:\r<?php\recho \'Hello world\'; \r?>\rUm novo subdiretório para seu web? Basta fazer um novo diretório (por exemplo, \"novo\") dentro do diretório \"\\\\xampp\\\\htdocs\" (melhor sem os espaços em branco e apenas ASCII), criar um arquivo de teste neste diretório e acessá-lo com \"que http://localhost/new/test.php\".\rMais detalhes\rHTML:\rExecutável: \\xampp\\htdocs\rFinais permitidos: .html .htm\r=> pacote básico\rSSI:\rExecutável: \\xampp\\htdocs\rFinais permitidos: .shtml\r=> pacote básico\rCGI:\rExecutável: \\xampp\\htdocs and \\xampp\\cgi-bin\rFinais permitidos: .cgi\r=> pacote básico\rPHP:\rExecutável: \\xampp\\htdocs and \\xampp\\cgi-bin\rFinais permitidos: .php\r=> pacote básico\rPerl:\rExecutável: \\xampp\\htdocs and \\xampp\\cgi-bin\rFinais permitidos: .pl\r=> pacote básico\rApache::ASP Perl:\rExecutável: \\xampp\\htdocs\rFinais permitidos: .asp\r=> pacote básico\rJSP Java:\rExecutável: \\xampp\\tomcat\\webapps\\java (e.g.)\rFinais permitidos: .jsp\r=> Tomcat add-on\rServlets Java:\rExecutável: \\xampp\\tomcat\\webapps\\java (e.g.)\rFinais permitidos: .html (u.a)\r=> Tomcat add-on\rPosso mover a instalação do XAMPP?\rSim. Depois de se mudar do diretório XAMPP, você deve executar \"setup_xampp.bat\". Os caminhos nos arquivos de configuração será ajustado com este passo.\rSe você tiver instalado qualquer servidor como um serviço do Windows, você deve primeiro remover o serviço do Windows, e depois de mover você pode instalar o serviço novamente.\rAviso: Os arquivos de configuração dos teus próprios scripts, como aplicativos PHP, não estão ajustados. Mas é possível escrever um \"plug-in\"para o instalador. Como esse plug-in o instalador pode ajustar esses arquivos também.\rQuais são as \"Paginas iniciais automáticas\"para os diretórios WWW?\rO nome de arquivo padrão para a função do Apache \"DirectoryIndex\" é \"index. html\" ou \"index. php\". Toda vez que você está apenas navegando para uma pasta (\"http://localhost/xampp/\", por exemplo), e Apache pode encontrar tal arquivo, o Apache está exibindo este arquivo em vez de uma listagem de diretório.\rOnde posso alterar a configuração?\rQuase todas as configurações do XAMPP, você pode alterar com arquivos de configuração. Basta abrir o arquivo em um editor de texto e alterar a configuração que você quer. Só o FileZilla e o mercúrio devem ser configurado com a ferramenta de configuração do aplicativo.\rPorque o XAMPP não funciona no Windows XP SP2?\rA Microsoft oferece um melhor firewall com Service Pack 2 (SP2), que inicia automaticamente. Este firewall agora bloqueia as portas necessárias 80 (http) e 443 (https) e Apache não pode iniciar.\rA solução rápida:\rDisabilite o firewall da Microsoft pelo barra de ferramentas e inicie o XAMPP outra vez. COm esta solução será definido uma excessão no centro de segurança.\rAs seguintes portas são usadas para a funcionalidade básica:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rPor que o XAMPP não funciona no Windows Vista?\rControle de Conta de Usuário\rNo diretório \"C:\\\\program files\" você não tem plenos privilégios de escrita, mesmo como Administrador. Ou tem apenas privilégios limitados (e.g. for \".\\\\xampp\\\\htdocs\"). Neste caso você não pode editar um arquivo.\rSolução:\rEleve seus privilégios no explorer (botão direito do mouse / segurança) ou desabilite o controle de conta de usuário (UAC).\rVocê instalou o Apache/MySQL em \"C:\\\\xampp\" como um serviço do sistema mas não consegue inicializar/interromper os serviços com o \"Painel de Controle do XAMPP\" ou não consegue desinstalá-los.\rSolução:\rUse o console de gerenciamento de serviço do Windows ou desabilite o controle de conta de usuário.\rDesabilitando o Controle de Conta de Usuário (UAC)\rPara desabilitar o Controle de Conta de Usuário, use o programa \"msconfig\" (tecla windows + r, digite \"msconfig\" e clique em \"Ok\". No \"msconfig\" vá para \"Ferramentas\", selecione \"Alterar Configurações de UAC\", clique em \"Iniciar\", arraste o indicador para \"Nunca notificar\", clique em \"Ok\" e Reinicie o Windows. Ao mesmo tempo, você pode habilitar o UAC novamente.\rComo faço para verificar a soma de verificação md5?\rMuitas vezes, as somas de verificação são usadas para comparar arquivos. Um padrão para criar esta soma de verificação md5 (Message Digest Algorithm 5).\rCom esta soma de verificação md5 você pode testar se o seu download do XAMPP está correto ou não, porém, você precisará de um programa especifico capaz de criar estas somas de verificação. Para o Windows, você pode usar esta ferramenta da Microsoft:\rDisponibilidade e descrição do Utilitário de Verificação de Integridade de Checksum de Arquivos\rTambém é possível utilizar outros programas capazes de criar somas de verificação md5, como por exemplo, o GNU md5sum.\rComo instalar um programa (por exemplo, fciv.exe), você pode fazer as seguintes etapas:\rFaça o download do XAMPP (f.e. xampp-win32-1.8.2-0.exe)\rCrie a soma de verificação com:\rfciv.exe xampp-win32-1.8.2-0.exe\rE agora você pode comparar esta soma de verificação com aquele que você pode encontrar na homepage do XAMPP para Windows.\rSe ambas as somas de verificação forem iguais, tudo ok. Se não, o download está quebrado ou o arquivo foi alterado.\rPor que as mudanças no meu php.ini não fizeram efeito?\rSe uma mudança no \"php. ini\" não tem nenhum efeito, é possível que o PHP esteja usando um diferente. Você pode verificar isso com phpinfo ().Vá para o URI http://localhost/xampp/phpinfo.php e procure por \"Loaded Configuration File\". Este valor mostra o \"php.ini\" PHP é realmente usando.\rNota:\rDepois de alterar o \"php.ini\" você tem que reiniciar o Apache para que o Apache / PHP possa ler as novas configurações.\rSocorro! Existe um vírus no XAMPP!\rAlguns programas antivírus pode fazer ocorrer algum erro no XAMPP sinalizando algum vírus, geralmente sinalizam o arquivo xampp-manager.exe Este representa um falso positivo que o antivírus erroneamente identifica como um vírus, quando não é. Antes de liberar cada nova versão do XAMPP o executamos através de um software de detecção de vírus. No momento estamos usando \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rComo faço para configurar o meu aplicativo de antivírus?\rIncluímos todas as dependências e servidores necessários para executar o aplicativo web empacotado, então você vai achar que o XAMPP instala um grande número de arquivos. Se você estiver instalando um aplicativo XAMPP em uma máquina Windows com um aplicativo de antivírus ativado, isso pode retardar a instalação de forma significativa, e também há uma chance de que um dos servidores (servidor web e/ou servidor de banco de dados) possam ser bloqueados pelo aplicativo de antivírus . Se você tiver uma ferramenta de antivírus ativado, verifique as seguintes configurações para a execução do XAMPP sem problemas de desempenho:\rAdicionar exceções no firewall: para o Apache, MySQL ou qualquer outro servidor.\rAo executar a varredura de arquivos: se você tiver ativado a verificação antivírus para todos os arquivos, os arquivos executáveis para os servidores podem ficar lentos.\rVerifique o tráfego para URLs diferentes: Se você estiver desenvolvendo com o XAMPP em seu próprio computador, você pode excluir o tráfego de \"localhost\" nas configurações do seu antivírus.\rPor que o servidor Apache não inicializa no meu sistema?\rEste problema pode ser uma de várias razões:\rVocê inicializou mais de um Servidor HTTP (IIS, Sambar, ZEUS e assim por diante). Somente um servidor pode usar a porta 80. Esta mensagem de erro indica o problema:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rVocê tem um outro programa, como por exemplo o \"Skype\", que também bloqueia a porta 80. Se o problema for o Skype, você pode, no Skype, ir para Ações --> Opções --> Conexão --> desmarque \"usar porta 80 para uma porta alternativa\" e reinicie o Skype. Agora deve funcionar.\rVocê tem um firewall que bloqueia a porta do Apache. Nem todos os firewalls são compatíveis com o Apache, e as vezes apenas desativá-lo não será o suficiente e você terá de desinstalá-lo. Esta mensagem de erro indica o firewall:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rAlém disso, se o Apache consegue inicializar, mas o seu navegador não consegue se conectar a ele, pode ser devido a um dos seguintes fatores:\rAlguns rastreadores de vírus podem causar isto da mesma maneira que os firewalls podem interferir.\rVocê tem uma cópia do Windows XP Profissional sem o Service Pack 1 instalado. Você precisa ter, no mínimo, o Service Pack 1 instalado para o funcionamento do XAMPP.\rDica:\rSe você tem proplemas com as portas usadas, você pode tentar a ferramenta \"xampp-portcheck.exe\". Talvez isto possa ajudar.\rPorque é que a minha carga de CPU para o Apache esta quase 99%?\rHá um dos dois cenários em jogo aqui. Sua CPU é estourar o limite, ou você pode navegador conectar ao servidor, mas não vejo nada (o sistema está tentando insatisfatoriamente carregar a página). Em ambos os casos você pode encontrar a seguinte mensagem no Apache arquivo de log:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rO MPM cai de volta para uma implementação mais segura, mas algumas solicitações de clientes não foram processadas corretamente. Para evitar esse erro, use\"AcceptFilter\" com filtro de aceitação \"none\" no arquivo \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\" .\rPor que imagens e folhas de estilo não são exibidos?\rÀs vezes, há problemas com a exibição de imagens e folhas de estilo. Especialmente se esses arquivos estão localizados em uma unidade de rede. Neste caso, você pode ativar (ou adicionar) uma se as seguintes linhas no arquivo \"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\":\rEnableSendfile off\rEnableMMAP off\rEste problema também pode ser causada por programas de regulação da largura de banda, como NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rComo posso definir uma senha de root no MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rPosso usar o meu próprio servidor MySQL?\rSim. Simplesmente não iniciar o MySQL do pacote XAMPP. Por favor, note que os dois servidores não podem ser iniciados na mesma porta. Se você tiver definido uma senha para o \"root\", por favor não se esqueça de editar o arquivo \"\\\\xampp\\\\phpMyAdmin\\\\config.inc.php\".\rComo faço para restringir o acesso ao phpMyAdmin do lado de fora?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rAntes que você possa acessar o servidor MySQL, phpMyAdmin pedirá um nome de usuário e senha. Não se esqueça de definir uma senha para o usuário \"root\" em primeiro lugar.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rOnde está o suporte IMAP para PHP?\rComo padrão, o suporte a IMAP para PHP está desativado no XAMPP devido a alguns erros de inicialização misteriosos com algumas versões home como o Windows 98. Se você trabalha com sistemas NT, você pode abrir o arquivo \"\\\\xampp\\\\php\\\\php.ini\" para ativar a extensão php, removendo o ponto e vírgula do começo da linha \";extension=php_imap.dll\". Deveria ser:\rextension=php_imap.dll\rAgora reinicie o Apache e IMAP deve funcionar. Você pode usar as mesmas etapas para cada extensão, que não está habilitada na configuração padrão.\rPor que não alguns aplicativos de código aberto PHP trabalhar com XAMPP no Windows?\rUm monte de aplicações PHP ou extensões que foram escritas para Linux não foram portadas para o Windows. \rPosso deletar o diretório de \"instalação\" depois da instalação?\rOps, É melhor não. Os scripts aqui ainda são necessários para todos os pacotes adicionais (add-ons) e atualizações do XAMPP.\rComo faço para ativar o eaccelerator?\rComo outras extensões (Zend), você pode ativá-lo no \"php. ini\". Neste arquivo, habilitar a linha\"; zend_extension =\"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"\". Deve ser:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rComo faço para corrigir um erro de conexão ao meu servidor MS SQL?\rSe a extensão mssql foi carregada o php. ini, às vezes, problemas aparecem quando apenas TCP/IP é usado. Você pode corrigir esse problema com um \"ntwdblib.dll\" mais recente da Microsoft. Por favor, substitua o arquivo antigo em \"\\\\xampp\\\\apache\\\\bin\" e \"\\\\xampp\\\\php\" o novo. Por causa da licença, nós não podemos empacotar uma versão mais recente deste arquivo com XAMPP.\rComo eu trabalho com a extensão PHP mcrypt?\rPara isso, abrimos um tópico no fórum com exemplos e possíveis soluções: \rTópico MCrypt\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rN. º E Apache::ASP com o complemento de Perl não é a mesma. Apache::ASP só entende Script em Perl, mas ASP do Internet Information Server (IIS) também conhece o VBScript normal. Mas para ASP-.NET, há um 3o módulo Apache disponível.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de Privacidade\rCDN fornecida pela','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(72,'2022-11-22 16:37:13','main','s1|/dashboard/pt_br/howto.html',0,NULL,NULL,NULL,'/dashboard/pt_br/howto.html','XAMPP howto guides','Apache Friends\rMenu\rPerguntas Frequentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de Privacidade\rCDN fornecida pela','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(73,'2022-11-22 16:37:14','main','s1|/dashboard/pt_br/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/pt_br/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rPerguntas Frequentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de Privacidade\rCDN fornecida pela','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(74,'2022-11-22 16:37:12','main','s1|/dashboard/pt_br/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/pt_br/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rPerguntas Frequentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de Privacidade\rCDN fornecida pela','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(75,'2023-11-19 12:10:26','main','s1|/dashboard/pt_br/index.html',0,NULL,NULL,NULL,'/dashboard/pt_br/index.html','Welcome to XAMPP','Apache Friends\rMenu\rPerguntas Frequentes\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rPerguntas Frequentes\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nComunidade\rXAMPP já existe há mais de 10 anos &ndash; há uma grande comunidade por trás dele. Você pode se envolver associando-se em nosso \rFóruns\r, e curtindo nossa página no \rFacebook\rou seguindo nossas façanhas no \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolítica de Privacidade\rCDN fornecida pela','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(76,'2022-11-22 16:37:11','main','s1|/dashboard/ro/faq.html',0,NULL,NULL,NULL,'/dashboard/ro/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rÎntrebări frecvente - FAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rÎntrebări Frecvente - FAQ\rCum instalez XAMPP?\rExistă trei variante de XAMPP pentru Windows:\rInstaller:\rProbabil cea mai uşoară cale de a instala XAMPP.\rZIP:\rXAMPP în varianta ZIP obişnuită.\r7zip:\rÎn situaţia unei viteze mici de descărcare: XAMPP ca arhivă 7zip.\rNotă: Dacă extrageţi fişierele, puteţi primi un avertisment pozitiv-fals de la antivirus.\rFolosind programul de instalare:\rPanoul de control XAMPP pentru pornirea/oprirea Apache, MySQL, FileZilla & Mercury, sau de instalare a acestor servere drept servicii.\rInstalare din arhivă ZIP\rDezarhivează arhivele ZIP într-un folder la alegerea ta. XAMPP este extras în subdirectorul \"C:\\\\xampp\" sub directorul ţintă selectat. Acum startaţi fişierul \"setup_xampp.bat\", pentru a potrivi configuraţia XAMPP la sistemul vostru.\rDacă alegeţi \"C:\\\\\" drept ţintă a directorului root , nu trebuie să porniţi \"setup_xampp.bat\".\rCa şi cu versiunea de instalare, puteţi folosi acum \"Panoul de XAMPP de control\" pentru sarcini suplimentare.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rCum pot porni XAMPP fără instalare?\rDacă extrageţi XAMPP într-un director principal precum \"C:\\\\\" sau \"D:\\\\\", puteţi porni majoritarea serverelor, cum ar fi Apache sau MySQL, fără executarea fişierului \"setup_xampp.bat\".\rNefolosind scriptul de configurare, sau selectând căi relative în script-ul de configurare, este de preferat pentru istalarea XAMPP pe un drive USB. Pentru că pe fiecare PC o astfel de unitate poate avea o altă literă de alocată. Puteți trece de la absolut la relativ în orice moment, cu script-ul de configurare.\rFolosind programul de instalare de pe pagina noastră Download-uri este cel mai simplu mod de a instala XAMPP. După ce instalarea este completă, veţi găsi XAMPP în Start | Programe | XAMPP. Puteţi utiliza panoul de control XAMPP pentru a porni/opri toate serverele şi de asemenea să instalaţi/dezinstalaţi servicii.\rPanoul de control XAMPP pentru pornirea/oprirea Apache, MySQL, FileZilla & Mercury, sau de instalare a acestor servere drept servicii.\rCum pornesc şi opresc XAMPP?\rCentrul universal de control este \"Control Panel XAMPP\" (mulţumiri www.nat32.com). Se începe cu:\r\\xampp\\xampp-control.exe\rPuteţi folosi, de asemenea, unele fişiere stive de comenzi - batch pentru a porni/opri serverele:\rApache & MySQL start:\n\\xampp\\xampp_start.exe\rApache & MySQL stop:\n\\xampp\\xampp_stop.exe\rApache start:\n\\xampp\\apache_start.bat\rApache stop:\n\\xampp\\apache_stop.bat\rMySQL start:\n\\xampp\\mysql_start.bat\rMySQL stop:\n\\xampp\\mysql_stop.bat\rMercury Mailserver start:\n\\xampp\\mercury_start.bat\rMercury Mailserver stop:\n\\xampp\\mercury_stop.bat\rFileZilla Server start:\n\\xampp\\filezilla_start.bat\rFileZilla Server stop:\n\\xampp\\filezilla_stop.bat\rCom poţi testa dacă totul funcţionază?\rTastează următoarea adresă URL în browser-ul tău favorit:\rhttp://localhost/\rsau \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rCum pot instala serverul drept serviciu?\rPuteţi instala de asemenea fiecare server din XAMPP drept serviciu Windows. Îl puteţi instala dealtfel din Panoul de Control XAMPP. În această situaţie, este necesar a rula scripturile sau Panoul de Control cu drepturi de Administrator.\rInstalare serviciu Apache: \\\\xampp\\\\apache\\\\apache_installservice.bat\rDezinstalare serviciu Apache: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rInstalare serviciu MySQL: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rDezinstalare serviciu MySQL: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \r(Dez)Instalare serviciu FileZilla: \\\\xampp\\\\filezilla_setup.bat \rMercury: Nici o instalare de serviciu disponibilă\rPoate fi folosit în producţie XAMPP?\rXAMPP nu este adecvat utilizării în producţie, ci doar în medii de dezvoltare. El este configurat în modul cel mai deschis, pentru ai permite programatorului tot ce acesta îşi doreşte. Aceasta convine perfect în medii de dezvoltare, dar poate fi un dezastru într-un mediu de producţie.\rIată o listă de vulnerabilităţi ale XAMPP:\rAdministratorul MySQL (contul de root) nu are parolă.\rSe poate accesa în reţea daemon-ul MySQL.\rProFTPD uses the password \"lampp\" for user \"daemon\".\rUtilizatorii impliciţi ai Mercury si FileZilla sunt cunoscuţi.\rToate punctele pot reprezenta un imens risc de securitate. Mai ales dacă XAMPP este accesibil prin intermediul reţelei şi persoanelor din afara LAN-ului vostru. De ajutor poate fi de asemenea utilizarea unui firewall sau a unui router (NAT) . Folosind un router sau un firewall, PC-ul vostru este în mod normal inaccesibil în reţea. Rezolvarea acestor probleme, vă revine. De un oarecare ajutor este \"Consola de securitate XAMPP\".\rVă rugăm să protejaţi XAMPP înainte de a publica on-line. Un firewall sau un router extern sunt suficiente doar pentru un nivel scăzut de securitate. Pentru mai multă siguranţă, puteți rula \"consola XAMPP Security\" unde puteţi atribui parole.\rDacă doriţi să aveţi XAMPP accesibil pe internet, trebuie să mergeţi la următoarea adresă URI care poate rezolva unele probleme:\rhttp://localhost/security/\rCu consola de securitate puteţi seta o parolă pentru utilizator \"root\" MySQL şi phpMyAdmin. Puteţi activa, de asemenea, o autentificare pentru demopages XAMPP.\rAcest instrument bazat pe web nu rezolvă probleme suplimentare de securitate! Mai ales serverul FileZilla FTP şi serverul de mail Mercury securizate de d-voastră.\rCum instalez XAMPP?\rDacă aţi instalat XAMPP folosind versiunea de instalare, vă rugăm să utilizaţi programul de dezinstalare. Dezinstalarea va şterge toate intrările XAMPP în regiştrii şi va dezinstala unele servicii incluse cu XAMPP. Vă recomandăm să utilizaţi programul de dezinstalare pentru îndepărtarea instalărilor XAMPP din versiunea kitului de instalare. Vă rugăm să faceţi copii de siguraţă a datelor pe care doriţi să le păstraţi, înainte de dezinstalarea XAMPP.\rDacă aţi instalat XAMPP folosind versiuni ale ZIP şi 7zip, închideţi toate serverele XAMPP şi ieşiţi din toate panourile. Dacă aţi instalat oricare servicii, opriţi-le şi de asemenea dezinstalaţi-le. Apoi, ştergeţi simplu întregul folder în care s-a instalat XAMPP. Nu există intrări în Registry sau variabile de mediu care să necesite curăţire.\rCe este versiunea \"redusă\" a XAMPP?\rXAMPP Lite (însemnând \"redus\" ca în \"greutate redusă\") este un pachet mai mic de componente XAMPP, recomandat pentru treburi urgente, folosind doar PHP şi MySQL. Unele servere sau instrumente, cum ar fi Mercury Mail şi FileZilla FTP lipsesc din versiunea Lite.\rUnde ar trebui să plasez conţinutul web-ului meu?\rDirectorul principal pentru toate documentele WWW este \\\\xampp\\\\htdocs. Dacă în acest director puneţi un fişier \"test.html\" , îl puteţi accesa cu URI-ul \"http://localhost/test.html\".\rŞi în cazul \"test.php\"? Folosiţi simplu \"http://localhost/test.php\". Un script de test simplu poate fi:\r<?php\recho \'Hello world\'; \r?>\rUn subdirector nou pentru web-ul vostru? Trebuie doar să creeaţi un nou director (de ex. \"new\") în directorul \"\\\\xampp\\\\htdocs\" (cel mai bine fără spaţii albe şi doar ASCII), în acest director creeaţi un fişier de test şi accesaţi-l cu \"http://localhost/new/test.php\".\rSpecificaţii suplimentare\rHTML:\rExecutabil: \\xampp\\htdocs\rTerminatori acceptaţi: .html .htm\r=> pachet de bază\rSSI:\rExecutabil: \\xampp\\htdocs\rTerminatori acceptaţi: .shtml\r=> pachet de bază\rCGI:\rExecutabil: \\xampp\\htdocs and \\xampp\\cgi-bin\rTerminatori acceptaţi: .cgi\r=> pachet de bază\rPHP:\rExecutabil: \\xampp\\htdocs and \\xampp\\cgi-bin\rTerminatori acceptaţi: .php\r=> pachet de bază\rPerl:\rExecutabil: \\xampp\\htdocs and \\xampp\\cgi-bin\rTerminatori acceptaţi: .pl\r=> pachet de bază\rApache::ASP Perl:\rExecutabil: \\xampp\\htdocs\rTerminatori acceptaţi: .asp\r=> pachet de bază\rJSP Java:\rExecutabil: \\xampp\\tomcat\\webapps\\java (e.g.)\rTerminatori acceptaţi: .jsp\r=> Tomcat add-on\rServlets Java:\rExecutabil: \\xampp\\tomcat\\webapps\\java (e.g.)\rTerminatori acceptaţi: .html (u.a)\r=> Tomcat add-on\rPot reloca XAMPP instalat?\rDa. După ce mutaţi directorul XAMPP-ului, trebuie executat \"setup_xampp.bat\". Cu această ocazie, se vor reconfigura căile în fişierele de configurare.\rDacă aţi instalat vreun server ca serviciu Windows, mai întâi trebuie să înlăturaţi serviciul, iar după mutare puteţi instala din nou serviciul.\rAtenţiune: Nu sunt modificate fişierele de configurare din scripturile voastre, precum aplicaţiile PHP. Este însă posibilă scrierea unui \"plug-in\" pentru programul de instalare. Cu un astfel de plug-in, installer-ul poate modifica şi asfel de fişiere.\rCe sunt \"Paginile automate de start\" pentru directoarele WWW?\rNumele fişierului standard pentru funcţia Apache \"DirectoryIndex\" este \"index.html\" sau \"index.php\". Oricând navigaţi la un folder (de ex. \"http://localhost/xampp/\"), iar Apache poate găsi acest fişier, îl va afişa pe acesta, în locul unei listări a directorului.\rDe unde pot să schimb configuraţia?\rDin fişierele de configurare puteţi modifica aproape toate setările din XAMPP. Trebuie doar să deschideţi fişierul într-un editor şi să modificaţi setarea pe care o doriţi. Numai pentru a configura FileZilla şi Mercury este necesară utilizarea aplicaţiei de configurare.\rDe ce nu poate funcţiona XAMPP cu Windows XP SP2?\rOdată cu Service Pack 2 (SP2), Microsoft livrează un firewall mai bun, care porneşte automat. Acest firewall blochează acum porturile necesare 80 (http) şi 443 (https) , astfel încât Apache-ul nu poate starta.\rSoluţia rapidă:\rDezactivaţi firewall-ul Microsoft din bara de unelte şi încercaţi din nou să porniţi XAMPP. O soluţionare mai adecvată o reprezintă definirea unei excepţii, cu ajutorul Centrului de Securitate.\rPentru o funcţionare de bază sunt utilizate următoarele porturi:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rDe ce nu funcţionează XAMPP cu Vista?\rControlul Contului de Utilizator (UAC)\rÎn directorul \"C:\\\\Program Files\" nu aveţi drepturi depline de scriere, chiar fiind Administrator. Sau aveţi doar drepturi limitate (de ex. pentru \".\\\\xampp\\\\htdocs\"). În acest caz, nu puteţi edita fişierul.\rSoluţie:\rDin Explorer, acordaţi-vă drepturi sporite (clic dreapta / securitate) , sau dezactivaţi Controlul Contului de Utilizator (UAC).\rAţi instalat Apache/MySQL în \"C:\\\\xampp\" ca serviciu Windows. Dar nu puteţi porni/opri serviciile din \"Panoul de Control XAMPP\" sau nu le puteţi dezinstala.\rSoluţie:\rFolosiţi consola Windows de administrare a serviciilor, sau dezactivaţi UAC.\rDezactivarea Controlului Cont de Utilizator (UAC)\rPentru dezactivarea UAC, folosiţi programul \"msconfig\". În \"msconfig\" mergeţi la \"Tools\", selectaţi \"dezactivare Control al Contului de Utilizator\" şi verificaţi selecţia. După aceasta, Windows-ul trebuie restartat. În acelaşi mod se poate reactiva UAC.\rCum realizez verificarea sumei de control md5?\rPentru a compara fişiere, adeseori se folosesc sume de control. Un standard pentru a crea această sumă de control md5 (Algoritmul de Rezumare a Mesajului - Message Digest 5).\rCu această sumă de control md5 puteţi verifica integritatea pachetului XAMPP descărcat. Aveţi nevoie desigur, de un program care să poată construi aceste sume de control. În cazul Windows-ului, aveţi la dispoziţie utilitarul Microsoft:\rDisponibilitatea şi descrierea utilitarului de Verificare a Integrităţii Sumei de Control a Fişierului\rDesigur, se poate folosi orice alt program care furnizează sume de control md5, precum md5sum de la GNU.\rOdată ce aţi instalat un astfel de program (de ex. fciv.exe), puteţi continua cu următorii paşi:\rDescarcă XAMPP (de ex. xampp-win32-1.8.2-0.exe)\rPentru obţinerea sumei de control:\rfciv.exe xampp-win32-1.8.2-0.exe\rAcum puteţi compara această sumă de control, cu cea care se află în pagina gazdă principală a XAMPP pentru Windows.\rDacă cele două sume de control sunt egale, este în regulă. Dacă nu, înseamnă fie că descărcarea este invalidată de erori, sau că fişierul a fost modificat.\rDe ce nu au efect modificările aduse fişierului php.ini?\rDacă o modificare a fişierului \"php.ini\" nu are efect, probabil că PHP îl foloseşte pe un altul. Puteţi verifica aceasta cu phpinfo(). Introduceţi adresa URI http://localhost/xampp/phpinfo.php şi căutaţi \"Fişierul de Configurare Încărcat\". Această valoare indică fişierul \"php.ini\" utilizat de PHP în realitate.\rObservaţie:\rDupă modificarea fişierului \"php.ini\" Apache va trebui restartat, astfel ca Apache/PHP să-şi poată actualiza setările.\rAjutor! XAMPP este virusat!\rEste posibil ca programe antivirus să alerteze din greşeală că XAMPP este virusat, marcând de obicei fişierul xampp-manager.exe. Vorbim de un pozitiv fals, însemnând că antivirusul identifică în mod eronat un virus, acolo unde el nu există. Înaintea lansării, scanăm antiviral fiecare nouă versiune de XAMPP. În prezent utilizăm \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rCum îmi configurez aplicaţia antivirus?\rPentru funcţionarea întregului pachet de aplicaţii web, am inclus tot felul de servere şi programe suplimentare, astfel încât instalarea XAMPP se face cu un mare număr de fişiere. Instalarea XAMPP poate fi mult încetinită dacă are loc pe un sistem Windows protejat de un antivirus, acesta putând chiar bloca unele dintre servere (de web, sau de baze de date). Pentru ca XAMPP să funcţioneze fără pierderi de performanţă datorate antivirusului, verificaţi următoarele setări:\rÎn firewall, adăugaţi excepţii: pentru Apache, pentru MySQL sau orice alt server.\rScanarea fişierelor la executare: Dacă aţi activat scanarea antivirus pentru toate fişierele, executabilele serverelor pot incetini.\rScanarea traficului pentru diferite URL-uri: Dacă dezvoltaţi cu XAMPP pe propria maşină, puteţi exclude în setările antivirus traficul cu gazda - \"localhost\".\rDe ce nu porneşte serverul Apache pe sistemul meu?\rAceastă problemă poate avea una dintre următoarele cauze:\rAveţi pornite mai multe Servere HTTP (IIS, Sambar, ZEUS şi aşa mai departe). Doar un singur server poate folosi portul 80. Această problemă este indicată de mesajul de eroare:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rPortul 80 este blocat de un alt program, cum ar fi Telefonia de Internet \"Skype\". În cazul lui \"Skype\" problema se poate evita, mergând în Skype la Acţiuni -> Opţiuni -> Conexiune -> înlăturarea bifei \"foloseşte portul 80 drept port alternativ\" şi restartarea Skype. Acum ar trebui să funcţioneze.\rAveţi un firewall care blochează portul asociat Apache. Nu toate firewall-urile sunt compatibile cu Apache, iar uneori simpla dezactivare a firewall-ului nu este suficientă, ci trebuie să-l dezinstalaţi. Firewall-ul este indicat în mesajul de eroare:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rDe asemenea, dacă Apache porneşte dar nu vă puteţi conecta la el prin browser, cauza poate fi una dintre următoarele:\rŞi unele programe antivirus pot cauza acest lucru, similar acţiunii unui firewall.\rAveţi un XP Profesional căruia îi lipseşte Pachetul de Service nr. 1. Pentru XAMPP, vă este necesar cel puţin SP1.\rSfat:\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\rDe ce are CPU o încărcare de sarcină pentru Apache de aproape 99%?\rExistă una din următoarele două variante: Fie CPU este la maxim, fie puteţi conecta browser-ul la server, dar nu se vede nimic (sistemul încearcă fără succes să încarce pagina). În ambele situaţii puteţi găsi în fişierul de logare Apache mesajul următor:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rMPM revine la o mai sigură punere în aplicare, dar unele cereri ale clientului nu au fost corect procesate. În scopul evitării acestei erori, în fişierul \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\" utilizaţi \"AcceptFilter\", cu filtrul de acceptare \"none\".\rDe ce nu sunt afişate imaginile şi foile-de-stil?\rUneori apar probleme la afişarea imaginilor şi a paginilor-de-stil. În special dacă aceste fişiere sunt localizate pe un disc de reţea. În această situaţie puteţi activa (sau adăuga) în fişierul \"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\" una dintre următoarele linii:\rEnableSendfile off\rEnableMMAP off\rAceastă problemă poate să apară şi de la programele de regularizare a lăţimii de bandă, precum NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rCum pot seta o parolă de root în MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rPot să-mi folosesc propriul server MySQL?\rDa. Pur şi simplu nu porniţi MySQL-ul din pachetul XAMPP. Reţineţi că nu pot fi startate două servere pe un acelaşi port. Dacă aţi setat o parolă de \"root\", nu uitaţi să editaţi fişierul \"\\\\xampp\\\\phpMyAdmin\\\\config.ini.php\".\rCum restricţionez accesul din exterior la phpMyAdmin?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rÎnainte de a putea accesa serverul MySQL, phpMyAdmin va solicita un nume de utilizator şi o parolă. Nu uitaţi ca mai întâi de toate, să setaţi pentru utilizatorul \"root\" o parolă.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rUnde se află suportul IMAP pentru PHP?\rIniţial, suportul IMAP pentru PHP este dezactivat în XAMPP din cauza unor misterioase erori de iniţializare cu unele versiuni casnice precum Windows98. Dacă lucraţi cu sisteme NT, puteţi deschide fişierul \"\\\\xampp\\\\php\\\\php.ini\" pentru activarea extensiei php, prin înlăturarea semnului punct şi virgulă de la începutul liniei \";extension=php_imap.dll\". Trebuie să fie:\rextension=php_imap.dll\rAcum restartaţi Apache, iar IMAP ar trebui să funcţioneze. Puteţi folosi aceiaşi paşi pentru fiecare extensie care nu este validată în configuraţia iniţială.\rDe ce unele aplicaţii PHP open source nu funcţionează cu XAMPP pe Windows?\rO mulţime de aplicaţii PHP sau extensii care au fost scrise pentru Linux, nu au fost portate pe Windows. \rPot şterge directorul \"install\" după instalare?\rE mai bine să nu. Scripturile de aici sunt încă necesare tuturor pachetelor adiţionale (add-onuri) şi upgrade-urilor lui XAMPP.\rCum activez eaccelerator-ul?\rCa şi alte extensii (Zend) le puteţi activa în \"php.ini\". În acest fişier validaţi linia \";zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"\". Ar trebui să fie:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rCum depăşesc o eroare de conectare la serverul meu MySQL?\rDacă extensia mssql a fost încărcată în php.ini, uneori apar probleme când este folosit doar TCP/IP. Puteţi rezolva această problemă cu un mai nou \"ntwdblib.dll\" de la Microsoft. Vă rugăm înlocuiţi vechiul fişier în \"\\\\xampp\\\\apache\\\\bin\" şi \"\\\\xampp\\\\php\" cu unul nou. Din cauză de licenţă, nu putem împacheta o versiune nouă a acestui fişier cu XAMPP.\rCum utilizez extensia PHP mcrypt?\rPentru aceasta, am deschis un subiect în forum, cu exemple şi soluţii posibile: \rSubiect MCrypt\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rNu. Iar Apache::ASP nu-i acelaşi lucru cu suplimentul Perl. Apache::ASP recunoaşte doar Perl-Script, pe când ASP din Internet Information Server (IIS) recunoaşte de asemenea VBScript-ul obişnuit. Dar pentru ASP.NET este disponibil un modul Apache de la terţi.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica de intimitate\rCDN furnizate de','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(77,'2022-11-22 16:37:13','main','s1|/dashboard/ro/howto.html',0,NULL,NULL,NULL,'/dashboard/ro/howto.html','XAMPP howto guides','Apache Friends\rMenu\rÎntrebări frecvente - FAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica de intimitate\rCDN furnizate de','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(78,'2022-11-22 16:37:14','main','s1|/dashboard/ro/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/ro/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rÎntrebări frecvente - FAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica de intimitate\rCDN furnizate de','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(79,'2022-11-22 16:37:12','main','s1|/dashboard/ro/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/ro/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rÎntrebări frecvente - FAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica de intimitate\rCDN furnizate de','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(80,'2023-11-19 12:10:26','main','s1|/dashboard/ro/index.html',0,NULL,NULL,NULL,'/dashboard/ro/index.html','Welcome to XAMPP','Apache Friends\rMenu\rÎntrebări frecvente - FAQs\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rÎntrebări frecvente - FAQs\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nComunitate\rXAMPP este alături de noi de mai bine de 10 ani &ndash; există o imensă comunitate în spatele lui. Poţi să te implici alăturându-te \rForum-uri\rnoastre, ţinând legătura cu noi pe \rFacebook\rsau urmărindu-ne postările pe \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rPolitica de intimitate\rCDN furnizate de','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(81,'2022-11-22 16:37:11','main','s1|/dashboard/ru/faq.html',0,NULL,NULL,NULL,'/dashboard/ru/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rЧаВО\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rЧасто задаваемые Вопросы\rКак мне установить XAMPP?\rXAMPP для Windows существует в трёх рахных пакетах:\rУстановщик:\rВероятно самый простой способ установить XAMPP.\rZIP:\rДля пуристов: XAMPP как обычный ZIP архив.\r7zip:\rДля пуристов с небольшой скоростью интернета: XAMPP как 7zip архив.\rЗаметка: Если вы распакуете файлы, возможно ложное срабатывание антивирусной программы.\rИспользование установщика:\rПанель управления XAMPP для запуска/остановки Apache, MySQL, FileZilla и Mercury или установки этих серверов в качестве сервисов.\rУстановка из ZIP архива\rРаспакуйте zip архивы в выбранную вами папку. XAMPP распакуется в суб-каталог \"C:\\\\xampp\" под выбранной папкой. Теперь запустите файл \"setup_xampp.bat\", чтобы настроить конфигурацию XAMPP для вашей системы.\rЕсли вы выберите корневой каталог \"C:\\\\\" как папку назначения, вы не должны запускать \"setup_xampp.bat\".\rТакже как в версии с установщиком, теперь вы можете использовать контрольную панель XAMPP (XAMPP Control Panel) для дополнительных задач.\rXAMPP включает в себя MySQL или MariaDB?\rС момента выхода XAMPP 5.5.30 и 5.6.14, XAMPP предоставляет MariaDB вместо MySQL. Команды и инструменты для обоих одни и те же.\rКак мне запустить XAMPP без установки?\rЕсли вы распакуете XAMPP в папку верхнего уровня как \"C:\\\\\" или \"D:\\\\\", вы можете запустить большинство серверов как Apache или MySQL сразу без исполнения файла \"setup_xampp.bat\".\rЕсли вы устанавливаете XAMPP на usb носитель желательно не использовать скрипт установки, или выбрать в скрипте установки относительные пути. Так как на каждом ПК такой носитель может иметь разные буквы привода. Вы можете перейти с абсолютных на относительные пути в любой момент с помощью скрипта установки.\rИспользование установщика с нашей страницы скачиваний это самый простой способ установить XAMPP. После завершения установки, вы найдёте XAMPP под Пуск | Все программы | XAMPP. Вы можете использовать панель управления XAMPP для запуска или остановки всех серверов и установки или удаления серфисов.\rПанель управления XAMPP для запуска/остановки Apache, MySQL, FileZilla и Mercury или установки этих серверов в качестве сервисов.\rКак мне запустить и остановить XAMPP?\rУниверсальный центр управления это \"XAMPP Control Panel\" (панель управления XAMPP) (благодаря www.nat32.com). Он запускается с помощью:\r\\xampp\\xampp-control.exe\rТакже вы можете использовать некоторые batch (*.bat) файлы чтобы запускать/останавливать сервера.\rApache & MySQL запуск:\n\\xampp\\xampp_start.exe\rApache & MySQL остановка:\n\\xampp\\xampp_stop.exe\rApache запуск:\n\\xampp\\apache_start.bat\rОстановить Apache:\n\\xampp\\apache_stop.bat\rЗапустить MySQL:\n\\xampp\\mysql_start.bat\rОстановить MySQL:\n\\xampp\\mysql_stop.bat\rЗапустить Mercury Mailserver:\n\\xampp\\mercury_start.bat\rОстановить Mercury Mailserver:\n\\xampp\\mercury_stop.bat\rЗапустить сервер FileZilla:\n\\xampp\\filezilla_start.bat\rОстановить сервер FileZilla:\n\\xampp\\filezilla_stop.bat\rКак мне проверить, что всё сработало?\rВведите следующую URL в ваш любимый браузер:\rhttp://localhost/\rили \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rКак мне установить скрвер как сервис?\rКаждый сервер в XAMPP можно установить как сервис Windows. Вы можете сделать это при помощи XAMPP Control Panel (панель управления XAMPP). В таком случае скрипты или контрольная панель обязательно должны быть запущены с привилегиями администратора.\rУстановка сервиса Apache: \\\\xampp\\\\apache\\\\apache_installservice.bat\rУдаление сервиса Apache: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rУстановка сервиса MySQL: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rУдаление сервиса MySQL: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \rУстановка или удаление сервиса FileZilla: \\\\xampp\\\\filezilla_setup.bat \rДля Mercury нет доступной установки сервиса\rГотов ли XAMPP к производственному использованию?\rXAMPP не предназначен для производственного использования, а только для сред разработки. XAMPP настроен таким образом чтобы быть как можно более открытым и позволять разработчику всё что он/она захочет. Для сред разработки это прекрасно, но в производственной среде это может быть пагубно.\rВот список отсутствующих мер безопасности в XAMPP:\rMySQL администратор (root) не имеет пароля.\rMySQL сервер доступен через сеть.\rProFTPD uses the password \"lampp\" for user \"daemon\".\rПользователи по умолчанию Mercury и FileZilla известны.\rВсё это может быть обширным риском безопасности. Особенно если XAMPP доступен через сеть и людям снаружи LAN. Использование брандмауэра (межсетевой экран) или (NAT) маршрутизатора может помочь. В случае с маршрутизатором или брандмауэром, ваш ПК обычно недоступен через сеть. Решение этих проблем лежит на вас. Как небольшая помощь есть консоль безопасности XAMPP (XAMPP Security console).\rПожалуйста обезопасьте XAMPP прежде чем публиковать что-либо в сети. Использование брандмауэра (межсетевой экран) или маршрутизатора достаточно лиш для низких уровней безопасности. Для немного большей безопасности, вы можете запустить консоль безопасности XAMPP (XAMPP Security console) и установить пароли.\rЕсли вы хотите чтобы ваш XAMPP был доступен через интернет, вам следует посетить следующую URI которая может исправить некоторые проблемы:\rhttp://localhost/security/\rС помощью консоли безопасности вы можете установить пароль для MySQL пользователя \"root\" и phpMyAdmin. Вы также можете включить аутентификацию для демонстративных страниц XAMPP.\rЭтот инструмент на веб-основе не исправляет какие-либо дополнительные проблемы безопасности! Особенно в случае с FileZilla FTP сервером и Mercury почтовым сервером, их вы должы обезопасить сами.\rКак мне удалить XAMPP?\rЕсли вы установили XAMPP используя версию с установщиком, пожалуйста используйте деинсталлятор. Деинсталлятор удалит все записи XAMPP из реестра и удалит некоторые установленные сервисы включенные в XAMPP. Мы настойчиво рекомендуем чтобы вы использовали деинсталлятор для удаления установки XAMPP с версией установщика. Пожалуйста сделайте резервное копирование всех данных которые хотите сохранить прежде чем удалять XAMPP.\rЕсли вы установили XAMPP используя ZIP или 7zip версии, выключите все XAMPP сервера и выйдите из всех панелей. Если вы установили какие-либо сервисы, удалите и отключите их тоже. Теперь просто удалите весь каталог где установлен XAMPP. В данном случае записей в регистре и переменных среды требующих чистку нет.\rЧто такое \"lite\" (лёгкая) версия XAMPP?\rXAMPP Lite (значит \"лёгкий\" как в \"лёгкий вес\") это меньший набор XAMPP компонентов, что рекомендуется для быстрой работы где требуется только PHP и MySQL. Некоторые сервера или инструменты как Mercury Mail и FileZilla FTP отсутствуют в Lite версии.\rГде мне следует поместить моё веб содержимое?\rГлавный каталог для всех WWW документов это \\\\xampp\\\\htdocs. Если вы положите файл \"test.html\" в этот каталог, вы сможете получить доступ к нему по URI \"http://localhost/test.html\".\rИ \"test.php\"? Просто используйте \"http://localhost/test.php\". Простой тест-скритп может быть:\r<?php\recho \'Hello world\'; \r?>\rНовая суб-каталог для вашего веб проекта? Просто создайте новый каталог (пример: \"new\") внутри каталога \"\\\\xampp\\\\htdocs\" (желательно без пробелов и с использованием только ASCII), создайте файл \"test.php\" в этом каталоге, вы сможете получить доступ к нему по URI \"http://localhost/new/test.php\".\rДополнительные особенности\rHTML:\rИсполняемый файл: \\xampp\\htdocs\rРазрешённые окончания: .html .htm\r=> базовый пакет\rSSI:\rИсполняемый файл: \\xampp\\htdocs\rРазрешённые окончания: .shtml\r=> базовый пакет\rCGI:\rИсполняемый файл: \\xampp\\htdocs and \\xampp\\cgi-bin\rРазрешённые окончания: .cgi\r=> базовый пакет\rPHP:\rИсполняемый файл: \\xampp\\htdocs and \\xampp\\cgi-bin\rРазрешённые окончания: .php\r=> базовый пакет\rPerl:\rИсполняемый файл: \\xampp\\htdocs and \\xampp\\cgi-bin\rРазрешённые окончания: .pl\r=> базовый пакет\rApache::ASP Perl:\rИсполняемый файл: \\xampp\\htdocs\rРазрешённые окончания: .asp\r=> базовый пакет\rJSP Java:\rИсполняемый файл: \\xampp\\tomcat\\webapps\\java (e.g.)\rРазрешённые окончания: .jsp\r=> Tomcat add-on\rServlets Java:\rИсполняемый файл: \\xampp\\tomcat\\webapps\\java (e.g.)\rРазрешённые окончания: .html (u.a)\r=> Tomcat add-on\rКак мне переместить установку XAMPP?\rДа. После перемещения каталога XAMPP, вы должны выполнить \"setup_xampp.bat\". Пути в файлах конфигурации будут поправлены при выполнении этого шага.\rЕсли вы установили любой сервер как Windows сервис, сначала вы должны удалить Windows сервис, а после перемещения вы можете снова установить сервис.\rПредупреждение: Файлы конфигурации из ваших скриптов, к примеру PHP приложения, не настроены. Но возможно написать плагин для установщика. С таким плагином установщик может настроить и эти файлы.\rЧто такое \"Automatic start pages\" (страницы автоматического запуска) для WWW каталогов?\rСтандартное имя файла для функции Apache \"DirectoryIndex\" это \"index.html\" или \"index.php\". Каждый раз когда вы открываете в браузере папку (пример: \"http://localhost/xampp/\"), и Apache сможет найти такой файл, Apache отобразит этот файл вместо списка содержимого каталога.\rГде я могу поменять настройки?\rПочти все настройки в XAMPP вы можете поменять при помощи файлов конфигурации. Просто откройте файл в текстовом редакторе и измените что желаете. Только FileZilla и Mercury должны быть настроены при помощи програмного инструмента конфигурации.\rПочему XAMPP не может работать на Windows XP SP2?\rMicrosoft предоставляет более хороший брандмауэр (межсетевой экран) с сервис паком 2 (SP2), который запускается автоматически. Этот брандмауэр теперь блокирует необходимые порты 80 (http) и 443 (https) и Apache не может запустится.\rБыстрое решение:\rОтключите брандмауэр (межсетевой экран) и попробуйте запустить XAMPP ещё раз. Лучшее решение: указать исключение в центре безопасности.\rСледующие порты используются для базовой функциональности:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rПочету XAMPP не работает на Windows Vista?\rКонтроль учётных записей пользователей (UAC)\rВы не имеете полных привилегий записи в каталоге \"C:\\\\program files\", даже как администратор. Или у вас только ограниченные привилегии (к примеру только для \".\\\\xampp\\\\htdocs\"). В таком случае вы не можете редактировать файл.\rРешение:\rПовысьте свои привилегии в проводнике (правый клик / безопасность) или отключите Контроль учётных записей пользователей (UAC).\rВы установили Apache/MySQL в \"C:\\\\xampp\" как Windows сервис. Но вы не можете запускать/останавливать сервисы при помощи панели управления XAMPP (XAMPP Control Panel) или не можете их удалить.\rРешение:\rИспользуйте консоль управления сервисами от Windows или отключите UAC.\rОтключение контроля учётных записей пользователей (UAC)\rЧтобы отключить UAC, используйте программу \"msconfig\". В \"msconfig\" заидите в \"Tools\" (инструменты), выберите \"disable user account control\" (отключить контроль учётных записей пользователей) и подтвердите свой выбор. Теперь вы должны перезапустить Windows. Вы можете включить UAC снова.\rКак мне проверить контрольную сумму md5?\rЧтобы сравнить файлы, часто используются контрольные суммы. Стандарт чтобы создать такую контрольную сумму md5 (Message Digest Algorithm 5).\rПри помощи контрольной суммы md5 вы можете проверить, соответствует ли оригиналу скачанный вами пакет XAMPP. Естественно вам потребуется программа способная создавать такие контрольные суммы. Для Windows вы можете использовать инструмент от Microsoft:\rДоступность и описание утилиты проверки целостности контрольных сумм файлов\rТакже возможно использовать любую другую программу способную создавать md5 контрольные суммы, как GNU md5sum.\rКогда вы установили такую программу (пример: fciv.exe), вы можете выполнить следующие шаги:\rСкачать XAMPP (f.e. xampp-win32-1.8.2-0.exe)\rСоздать контрольную сумму с:\rfciv.exe xampp-win32-1.8.2-0.exe\rТеперь вы можете сравнить эту контрольную сумму с той которую можете найти на домашней странице XAMPP для Windows.\rЕсли обе контрольные суммы равны, всё хорошо. Если нет, скачивание обернулось провалом или файл был изменён.\rПочему изменения в моём php.ini не вступают в действие?\rЕсли изменеие в \"php.ini\" не вступило в действие, возможно PHP использует другой файл. Вы можете проверить это при помощи phpinfo(). Последуйте по URI http://localhost/xampp/phpinfo.php и ищите \"Loaded Configuration File\" (загруженный файл конфигурации). Это значение покажет какой \"php.ini\" PHP действительно использует.\rПримечание:\rПосле изменения \"php.ini\" вы должны перезапустить Apache чтобы Apache/PHP смогли считать новые настройки.\rПомогите! В XAMPP есть вирус!\rНекоторые анти-вирусные программы по ошибке принимают XAMPP за вирус, обычно отмечая файл xampp-manager.exe. Это ложная тревога, что означает анти-вирус ошибочно принял за вирус то что им не является. Прежле чем мы публикуем каждую новую версию XAMPP мы сканируем его на вирусы. В данный момент мы используем \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rКак мне настроить моё анти-вирусное приложение?\rМы включили все зависимости и сервера тревуемые для работы пакета веб приложения, поэтому XAMPP устанавливает большое количество файлов. Если вы устанавливаете XAMPP на Windows машине со включенным анти-вирусом, это может значительно замедлить установку, и ещё есть шанс что один из серверов (веб сервер, сервер баз данных) может быть заблокирован анти-вирусным ПО. Если ваш есть анти-вирус включён, проверьте следующие настройки для запуска XAMPP без проблем с производительностью:\rДобавьте исключения в брандмауэр (межсетевой экран): для Apache, MySQL или любого другого сервера.\rСканирование файлов во время рвботы: Если вы включили в анти-вирусном ПО сканирование всех файлов, работа исполнительных файлов серверов может замедлится.\rСканирование трафика для разных URL: Если вы разрабатываете с использованием XAMPP на своей собственной машине, вы можете исключить проверку трафика для \"localhost\" в настройках вашего анти-вируса.\rПочему Apache сервер не запускается на моей системе?\rЭто проблема может иметь место по одной из нескольких причин:\rВы запустили более одного HTTP Server (IIS, Sambar, ZEUS и так далее). Только один сервер может использовать порт 80. Это сообщение об ошибке указывает на проблему:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rУ вас есть другое ПО, например интернет телефон \"Skype\" (скайп) которое тоже блокирует порт 80. Если проблема в \"Skype\", в Skype вы можете открыть Actions (действия) --> Options (опции) --> Connection (соединение) --> убрать галочку рядом с \"use port 80 for an alternate port\" (использовать порт 80 для альтернативного порта) и перезапустить Skype. Теперь всё должно работать.\rУ вас есть брандмауэр (межсетевой экран) который блокирует порт Apache. Не каждый брандмауэр совместим с Apache, иногда отключить брандмауэр недостаточно и вам придётся его удалить. Это сообщение об ошибке указывает на брандмауэр:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rТакже если Apache может запустится, но ваш браузер не может соединится с ним это может быть по одной из следующих причин:\rНекоторые анти-вирусные программы могут вызвать это, таким же образом как может вмешатся брандмауэр (межсетевой экран).\rУ вас XP Professional без сервис пака 1. Вы должны иметь как минимум SP1 для XAMPP.\rСовет:\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\rПочему Apache грузит мой процессор почти на 99%?\rВ данном случае действует один из двух сценариев. Либо ваш процессор работает на пределе своих возможностей, или вы можете подсоеденится к серверу через браузер, но ничего не видите (система безуспешно пытается загрузить страницу). В любом случае вы можете найти следующее сообщение в лог файле Apache:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rMPM возвращается к более безопасному выполнению, но некоторые клиентские запросы не обрабатывались корректно. Для того чтобы избежать этой ошибки, используйте \"AcceptFilter\" с включенным фильтром \"none\" в файле \"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\".\rПочему картинки и таблицы стилей не отображаются?\rИногда возникают проблемы с отображением картинок и таблиц стилей. Особенно, если эти файлы находятся на сетевом диске. В этом случае вы можете включить (или добавить) одну из следующих строк в файле \"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\":\rEnableSendfile off\rEnableMMAP off\rЭта проблема также может быть вызвана программами регулирования полосы пропускания, например, NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rПерезапустите сервер Apache, используя панель управления XAMPP.\nYou can now use PHP\'s mail() function to send email from your application.\rКак я могу установить пароль root\'а в MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rМогу ли я использовать свой собственный MySQL сервер?\rДа. Просто не запускайте MySQL из пакета XAMPP. Обратите внимание, что два сервера не могут быть запущены на том же порту. Если вы установили пароль для \"root\", пожалуйста, не забудьте отредактировать файл \"\\\\xampp\\\\phpMyAdmin\\\\config.inc.php\".\rКак ограничить доступ к PhpMyAdmin извне?\rВ базовой конфигурации XAMPP phpMyAdmin доступен только с того же хоста, на котором запущен XAMPP, по адресу \rhttp://127.0.0.1\rили \rhttp://localhost\r.\rПрежде чем вы сможете получить доступ к серверу MySQL, PhpMyAdmin запросит у вас имя пользователя и пароль. Не забудьте установить пароль для \"root\" пользователя в первую очередь.\rКак мне включить доступ к phpMyAdmin извне?\rВ базовой конфигурации XAMPP phpMyAdmin доступен только с того же хоста, на котором запущен XAMPP, по адресу \rhttp://127.0.0.1\rили \rhttp://localhost\r.\rВАЖНО: Включение внешнего доступа для phpMyAdmin в производственных средах представляет собой значительный риск для безопасности. Вам настоятельно рекомендуется разрешать доступ только с localhost. Удаленный злоумышленник может воспользоваться любой существующей уязвимостью для выполнения кода или изменения ваших данных.\rЧтобы включить удалённый доступ к phpMyAdmin, следуйте шагам ниже:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rВ этом файле, найдите строки, указанные снизу. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nЗатем, замените \'Require local\' на \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nПерезапустите сервер Apache, используя панель управления XAMPP.\rГде поддержка IMAP для PHP?\rПо умолчанию, поддержка IMAP для PHP отключена в XAMPP из-за некоторых загадочных ошибок инициализации в некоторых домашних версиях, например, Windows 98. Если вы работаете с системами NT, вы можете открыть файл \"\\\\xampp\\\\php\\\\php.ini\", чтобы активировать php расширение, удалив точку с запятой в строке \";extension=php_imap.dll\". Она должна быть:\rextension=php_imap.dll\rТеперь перезагрузите Apache, и IMAP должен работать. Вы можете использовать те же самые шаги для любого расширения, которое не включено в конфигурации по умолчанию.\rПочему некоторые PHP приложения с открытым исходным кодом работают с XAMPP на Windows?\rМного PHP приложений или расширений, которые были написаны для Linux не были портированы на Windows. \rCan I delete the \"install\" directory after installation?\rЛучше этого не делать. Эти скрипты ещё нужны для всех дополнительных пакетов (дополнений) и обновлений XAMPP.\rКак мне активировать eaccelerator?\rКак и другие (Zend) разрешения, вы можете активировать его в \"php.ini\". В этом файле, измените строку \";zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"\". Она должна быть:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rКак мне исправить ошибку соединения с моим MS SQL сервером?\rЕсли mssql расширение было загружено в php.ini, иногда возникают проблемы когда используется только TCP/IP. Вы можете исправить эту проблему при помощи более новой \"ntwdblib.dll\" от Microsoft. Пожалуйста замените старый файл в \"\\\\xampp\\\\apache\\\\bin\" и \"\\\\xampp\\\\php\" более новым. Из за условий лицензии, мы не можем включить более новую версию файла в XAMPP.\rКак мне работать с PHP mcrypt расширением?\rДля этого, мы открыли предмет обсуждения на форуме с примерами и возможными решениями: \rMCrypt топик\rMicrosoft Active Server Pages (ASP) работают с XAMPP?\rНет. И Apache::ASP с Perl дополнением не то же самое. Apache::ASP распознаёт только Perl-Script, а ASP из Internet Information Server (IIS) также распознаёт обычный VBScript. Но для ASP .NET, существует сторонний Apache модуль.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rФайлы конфигурации Apache: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rБлог\rПолитика приватности\rCDN предусмотрено','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(82,'2022-11-22 16:37:13','main','s1|/dashboard/ru/howto.html',0,NULL,NULL,NULL,'/dashboard/ru/howto.html','XAMPP howto guides','Apache Friends\rMenu\rЧаВО\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rБлог\rПолитика приватности\rCDN предусмотрено','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(83,'2022-11-22 16:37:14','main','s1|/dashboard/ru/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/ru/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rЧаВО\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rБлог\rПолитика приватности\rCDN предусмотрено','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(84,'2022-11-22 16:37:12','main','s1|/dashboard/ru/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/ru/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rЧаВО\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rБлог\rПолитика приватности\rCDN предусмотрено','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(85,'2023-11-19 12:10:26','main','s1|/dashboard/ru/index.html',0,NULL,NULL,NULL,'/dashboard/ru/index.html','Welcome to XAMPP','Apache Friends\rMenu\rЧаВО\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rЧаВО\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nСообщество\rXAMPP существует уже более 10 лет &ndash; огромное сообщество работает над ним. Вы можете принять участие, присоединившись к нашему \rФорумы\r, и лайкнув нас на \rFacebook\rили следуя нашим твитам на \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rБлог\rПолитика приватности\rCDN предусмотрено','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(86,'2022-11-22 16:37:11','main','s1|/dashboard/tr/faq.html',0,NULL,NULL,NULL,'/dashboard/tr/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rSSS\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rSıkça Sorulan Sorular\rXAMPP\'ı nasıl yüklerim?\rWindows için XAMPP üç farklı çeşitte bulunmaktadır:\rYükleyici:\rMuhtemelen XAMPP\'i yüklemek için en kolay yol.\rZIP:\rSadelik taraftarları için: Standart ZIP arşivinde XAMPP.\r7zip:\rBant genişliği düşük sadelik taraftarları için: 7zip arşivinde XAMPP.\rNot: Eğer dosyaları çıkarırsanız, yanlış virus uyarıları verebilir.\rYükeyiciyi kullanarak:\rBaşlangıç ​​için XAMPP kontrol paneli / Apache, MySQL, FileZilla ve Merkür durdurmak veya hizmetler gibi bu sunucuyu yükleyin.\rZIP yükleniyor\rSeçtiğiniz klasöre zip arşivleri ayıklayın. Seçilen hedef dizin altında: \"\\\\ xampp \\\\ C\" XAMPP alt \\\\ için açılan bir. Şimdi, dosya \\\\ \"setup_xampp.bat \" start sisteminize XAMPP yapılandırmasını ayarlamak için.\rBir kök dizin \\\\ seçerseniz: hedef olarak \"C \\\\\" ise, \\\\ \"setup_xampp.bat \" start olmamalıdır.\rYükleyici versiyonunda olduğu gibi, şimdi ekstra görevler için \"XAMPP Kontrol Paneli\"nide kullanabilirsiniz.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rXAMPP\'ı yükleme işlemi olmadan nasıl başlatabilirim?\rXAMPP\'ı \"C:\\\\\" veya \"D:\\\\\" gibi üst klasörlere çıkarırsanız, Apache veya MySQL gibi birçok sunucuyu \"setup_xampp.bat\" dosyasını çalıştırmadan başlatabilirsiniz.\rXAMPP\'ı usb sürücüye kurarken, her bilgisayarda farklı sürücü ismi olabileceği için belirsiz yol seçmeniz önerilir. Yükleme işlemiyle klasör yolunu belirli veya belirsiz olarak istediğiniz an değiştirebilirsiniz.\rİndirme sayfamızdaki indirici, XAMPP\'ı kurmanın en kolay yoludur. Yükleme tamamlandıktan sonra XAMPP\'ı Başlat | Programlar | XAMPP klasöründe bulabilirsiniz. XAMPP Kontrol Panel\'ini kullanarak sunucuları başlatıp durdurmanın yanında servis olarak yükleyip kaldırabilirsiniz.\rBaşlangıç ​​için XAMPP kontrol paneli / Apache, MySQL, FileZilla ve Merkür durdurmak veya hizmetler gibi bu sunucuyu yükleyin.\rXAMPP\'i nasıl başlatır ve durdururum?\rEvrensel kontrol merkezi \"XAMPP Kontrol Paneli\" (www.nat32.com \' a Teşekkürler). Şununla başlatılır: \r\\xampp\\xampp-control.exe\rSunucuları başlatmak/durdurmak için ayrıca batchfile dosyaları da kullanabilirsiniz:\rApache & MySQL\' i başlat:\n\\xampp\\xampp_start.exe\rApache & MySQL durdur:\n\\xampp\\xampp_stop.exe\rApache\'yi başlat:\n\\xampp\\apache_start.bat\rApache\'yi durdur:\n\\xampp\\apache_stop.bat\rMySQL\'i başlat:\n\\xampp\\mysql_start.bat\rMySQL\'i durdur:\n\\xampp\\mysql_stop.bat\rMercury Mailserver başlat:\n\\xampp\\mercury_start.bat\rMercury Mailserver durdur:\n\\xampp\\mercury_stop.bat\rFileZilla Server başlat:\n\\xampp\\filezilla_start.bat\rFileZilla Server durdur:\n\\xampp\\filezilla_stop.bat\rHerşeyin çalıştığını nasıl test edebilirim?\rFavori web tarayıcınıza aşağıdaki URL\'yi yazın:\rhttp://localhost/\rya da \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rBir sunucuyu nasıl servis olarak yükleyebilirim?\rXAMPP\'taki her sunucuyu Windows servisi olarak kurabilirsiniz. Bunu XAMPP Kontrol Paneli\'ni kullanarakta yapabilirsiniz. Sunucuları Windows servisi olarak kurabilmek için komut dosyalarının veya Kontrol Panel\'inin Yönetici haklarıyla çalıştırılması gereklidir.\rApache servisini yükle: \\\\xampp\\\\apache\\\\apache_installservice.bat\rApache servisini kaldır: \\\\xampp\\\\apache\\\\apache_uninstallservice.bat \rMySQL servisini yükle: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rMySQL servisini kaldır: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \rFileZilla servisini yükle/kaldır: \\\\xampp\\\\filezilla_setup.bat \rMercury: Servis yüklemesi mevcut değil\rXAMPP hazır mı? \rXAMPP, normal kullanım için değildir, sadece yazılım geliştirme için kullanılır. Bu nedenle bir yazılımcının mümkün olduğunca ihtiyacı olan ayarlar yapılmıştır. Yazıloım geliştirmek için ideal bir ortam olmasına rağmen yazılım yayınlaması için kullanıldığında istenmeyen sorunlara neden olabilir.\rXAMPP içindeki güvenlik eksikliklerinin listesi:\rMySQL yöneticisi (root) şifresi yok. \rMySQL ortamı, ağ üzerinden ulaşılabilir.\rProFTPD uses the password \"lampp\" for user \"daemon\".\rMercury ve FileZilla\'nın varsayılan kullanıcıları tanınmaktadır.\rTüm noktalar büyük güvenlik risklerine sebebiyet verebilir. Özellikle XAMPP, ağ veya dış kaynaklar tarafından erişime açıksa. Güvenlik duvarı veya (NAT) yönlendirici kullanmak buna yardım edebilir. Yönlendirici veya güvenlik duvarı kullanılması durumunda, normal olarak bilgisayarınız ağ tarafından gelen isteklere kapalı olacaktır. Bu problemleri çözmek size düşmektedir. Bir miktar yardım etmek için \"XAMPP Güvenlik Konsolu\" bulunmaktadır.\rHerhangi bir şeyi yayınlamadan önce lütfen XAMPP\'ı güvenli hale getirin. Bir güvenlik duvarı veya harici yönlendirici sadece düşük profil güvenlik sorunlarını önlemeye yardımcı olmakta. Hafif bir güvenlik artışı için, \"XAMPP Güvenlik Konsolu\" ile sunucularınıza gerekli şifreleri atayabilirsiniz.\rEğer internetten erişilebilir XAMPP\' ınız olmasını isterseniz, bazı problemleri çözmek için aşağıdaki bağlantıya gidebilirsiniz:\rhttp://localhost/security/\rGüvenlik konsolu ile MySQL kullanıcısı \"root\" ve phpMyAdmin\'e şifre atayabilirsiniz. Ayrıca, XAMPP demo sayfalarındaki doğrulamayı etkinleştirebilirsiniz.\rBu internet tabanlı araç hiçbir ekstra güvenlik problemini çözmemektedir! Özellikle FileZilla FTP sunucusu ile Mercury mail sunucusunu kendiniz güvenli hale getirmelisiniz.\rXAMPP\'ı nasıl kaldırabilirim?\rXAMPP\'ı yükleyici versiyonuyla yüklediyseniz, lütfen Kaldırıcı\'yı kullanın. Kaldırıcı kayıt defterinizden tüm XAMPP girdilerini ve bazı XAMPP ile gelen servisleri kaldıracaktır. Yükleyici kullanarak yüklediğiniz XAMPP yüklemelerini kesinlikle Kaldırıcı ile kaldırmanız önerilmektedir. Verilerinizi XAMPP\'ı kaldırmadan önce lütfen yedekleyin.\rXAMPP\'ı ZIP ve 7zip versiyonları ile kurduysanız, tüm XAMPP sunucularını kapatın ve tüm panellerden çıkış yapın. Herhangi bir kurulu servisiniz varsa kaldırıp kapatın ve XAMPP\'ın kurulu olduğu klasörü basitçe silin. Temizlemeniz gereken hiçbir kayıt bulunmamakta.\rXAMPP\'ın \"lite\" versiyonu nedir?\rXAMPP Lite (\"hafif\" anlamında), XAMPP\'ın tüm bileşenlerini içermeyen küçültülmüş paketidir. Sadece PHP ve MySQL ile çabuk işlemleri halletmek için önerilir. Bazı, Mercury Mail ve FileZilla FTP gibi sunucu veya araçlar Lite versiyonunda bulunmamakta.\rWeb içeriğimi nereye yerleştirmeliyim?\rTüm Web dökümanları için ana dizin \"\\\\xampp\\\\htdocs\"dur. Eğer \"test.html\" isimli bir dosyayı bu dizine koyarsanız, dosyaya \"http://localhost/test.html\" bağlantısı ile ulaşabilirsiniz. \rVe \"test.php\" sayfası için \": //localhost/test.php\" yeterlidir. Basit bir deneme kodu olarak:\r<?php\recho \'Hello world\'; \r?>\rAlt klasöre mi ihtiyacınız var? //xampp//htdocs klasörünün içine örnek olarak \"yeni\" adlı bir klasör oluşturun(En iyisi boşluksuz ve ASCII Kodlama karekerleri ile olmasıdır). Bu klasör içinde test dosyanızı oluşturun ve ona erişmek için \"http:// localhost/yeni/test.php\" adresini kullanın. \rDiğer özelliklerini\rHTML:\rÇalıştırılabilir: \\xampp\\htdocs\rİzin verilen sonlar: .html .htm\r=> temel paket\rSSI:\rÇalıştırılabilir: \\xampp\\htdocs\rİzin verilen sonlar: .shtml\r=> temel paket\rCGI:\rÇalıştırılabilir: \\xampp\\htdocs and \\xampp\\cgi-bin\rİzin verilen sonlar: .cgi\r=> temel paket\rPHP:\rÇalıştırılabilir: \\xampp\\htdocs and \\xampp\\cgi-bin\rİzin verilen sonlar: .php\r=> temel paket\rPerl:\rÇalıştırılabilir: \\xampp\\htdocs and \\xampp\\cgi-bin\rİzin verilen sonlar: .pl\r=> temel paket\rApache::ASP Perl:\rÇalıştırılabilir: \\xampp\\htdocs\rİzin verilen sonlar: .asp\r=> temel paket\rJSP Java:\rÇalıştırılabilir: \\xampp\\tomcat\\webapps\\java (e.g.)\rİzin verilen sonlar: .jsp\r=> Tomcat add-on\rServlets Java:\rÇalıştırılabilir: \\xampp\\tomcat\\webapps\\java (e.g.)\rİzin verilen sonlar: .html (u.a)\r=> Tomcat add-on\rXAMPP kurulumunu taşıyabilir miyim?\rEvet. XAMPP dizinin taşındıktan sonra \"setup_xampp.bat \" çalıştırmalısınız. Yapılandırma dosyaları bu adımı ile ayarlanacaktır.\rEğer Windows hizmeti olarak herhangi bir sunucu kurduysanız, önce kurulu olan Windows hizmetini kaldırmanız gerekir. Daha sonra yeniden hizmeti yükleyebilirsiniz.\rUyarı: Ayar dosyaları içeren, Php uygulamaları gibi uygulamalarınızdaki ayar dosyaları ayarlanmaz. Ancak yükeyiciye eklenti oluşturarak bunu imkanlı hale getirebilirsiniz. Eklentilerle yükleyici bu dosyaları ayarlayabilir.\rNe WWW dizinleri için \"Otomatik start sayfalarını \" \\\\ var?\rApache işlevi \\\\ \"DirectoryIndex \" için standart dosya adı \\\\ \"index.html \" ya da \\\\ \"index.php \". Sadece bir klasöre geziyor her zaman (örneğin \\\\ \"http: // localhost / xampp / \"), ve Apache gibi bir dosyayı bulabilirsiniz, Apache bu dosyayı yerine dizin listesini görüntülüyor.\rNerede yapılandırmasını değiştirebilir miyim?\rNeredeyse XAMPP tüm ayarları yapılandırma dosyaları ile değiştirebilirsiniz. Sadece bir TextEdit dosyayı açın ve istediğiniz ayarı değiştirin. Sadece FileZilla ve Merkür uygulama yapılandırma aracı ile yapılandırılmalıdır.\rNeden XAMPP Windows XP SP2 üzerinde çalışmak değil mi?\rMicrosoft, otomatik olarak başlar hizmet paketi 2 (SP2), ile daha iyi bir güvenlik duvarı sunar. Bu güvenlik duvarı artık engeller gerekli portları 80 (http) ve 443 (https) ve Apache başlatılamıyor.\rHızlı çözüm:\rMicrosoft, araç çubuğu ile güvenlik duvarı ve XAMPP daha onces başlatmayı deneyin devre dışı bırakın. Daha iyi bir çözüm güvenlik merkezi içinde bir istisna tanımlamaktır.\rAşağıdaki bağlantı noktaları, temel işlevler için kullanılır:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rNeden XAMPP Vista üzerinde çalışmıyor?\rKullanıcı Hesabı Denetimi (UAC)\rDizin \\\\ \"C: \\\\ Program files \" bile Yönetici olarak, tam yazma ayrıcalıklarına sahip değilsiniz. Yoksa (\\\\ örneğin \". \\\\ Xampp \\\\ htdocs \") sadece sınırlı ayrıcalıklara sahip. Bu durumda bir dosyayı düzenleyemezsiniz.\rÇözüm:\rExplorer içinde ayrıcalıkları kaldırın (sağ / güvenlik tıklayın) veya kullanıcı hesabı denetimi (UAC) devre dışı bırakın.\rWindows hizmeti olarak: \"\\\\ xampp \\\\ C\" Sen \\\\ Apache / MySQL yüklediniz. Ama sen start / \\\\ ile hizmetlerini durdurun \"XAMPP Control Panel \" ya da bunları kaldıramazsınız olamaz.\rÇözüm:\rWindows hizmet yönetimi konsolunu kullanın veya UAC devre dışı bırakın.\rKullanıcı Hesabı Denetimi devre dışı bırakma (UAC)\rUAC devre dışı bırakmak için, programı \\\\ \"msconfig \" kullanın. \\\\ \"Msconfig \" \\\\ gidin \"Araçlar \", \\\\ \"devre dışı kullanıcı hesabı denetimi \" seçin ve seçiminizi doğrulayın. Şimdi Windows\'u yeniden başlatmanız gerekir. Aynı zamanda, yine UAC etkinleştirebilir.\rNasıl md5 checksum kontrol edebilirim?\rDosyaları karşılaştırmak için, sık sık sağlama kullanılır. Standart bu sağlama md5 (Message Digest Algorithm 5) oluşturmak için.\rXAMPP paketinin indirme doğru olup olmadığını, bu md5 sağlama ile, test edebilirsiniz. Tabii ki bu sağlama oluşturabilirsiniz bir program gerekiyor. Windows için Microsoft\'tan bir aracı kullanabilirsiniz:\rKullanılabilirlik ve File Checksum Integrity Verifier yardımcı programı açıklaması\rGNU md5sum gibi, md5 toplamlarını oluşturabilir başka bir program kullanmak da mümkündür.\r(Örn fciv.exe) bu tür bir programı kurduktan gibi, adımları izleyerek yapabilirsiniz:\rİndir XAMPP (fe xampp-win32-1.8.2-0.exe)\rIle checksum oluşturun:\rfciv.exe xampp-win32-1.8.2-0.exe\rVe şimdi size XAMPP Windows için ana sayfasında bulabilirsiniz biri ile bu sağlama karşılaştırabilirsiniz.\rHer iki sağlama eşit, tüm ok. Değilse, indir bozuk veya dosya değiştirildi.\rNeden benim php.ini değişikliklerin geçerli değil mi?\r\\\\ \"Php.ini \" bir değişiklik hiçbir etkisi varsa, mümkün PHP farklı bir birini kullanarak mi. Sen phpinfo ile kontrol edebilirsiniz (). URI http: //localhost/xampp/phpinfo.php ve \\\\ \"Loaded Configuration File \" için arama. Bu değer size \"php.ini \" PHP gerçekten kullanıyor \\\\ gösterir.\rNot:\r\\\\ Değiştirdikten sonra \"php.ini \" Apache / PHP yeni ayarları okuyabilir böylece Apache yeniden başlatmanız gerekir.\rYardım Edin! XAMPP bir virüs var!\rBir virüs için bazı antivirüs programları hata XAMPP, genellikle dosya xampp-manager.exe işaretleme Bu olmadığı zaman antivirüs yanlışlıkla bir virüs olarak tanımlanan bir yalancı pozitif anlamıdır. Biz XAMPP her yeni sürüm önce virüs tarama yazılımı aracılığıyla çalıştırın. Şu anda kullanmakta olduğunuz \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rNasıl benim antivirüs uygulamasını yapılandırmak mı?\rBiz birlikte web uygulaması çalıştırmak için gerekli tüm bağımlılıkları ve sunucular dahil ettik, bu yüzden XAMPP çok sayıda dosya yükler bulacaksınız. Etkin bir antivirüs uygulaması ile bir Windows makinede bir XAMPP uygulama yüklüyorsanız, bu anlamlı yüklemeyi yavaşlatabilir ve sunuculardan biri (web sunucusu, veritabanı sunucusu) antivirüs yazılımı tarafından bloke edilebilir bir şans da var . Eğer bir antivirüs aracı etkin varsa, performans sorunları olmadan XAMPP çalıştırmak için aşağıdaki ayarları kontrol edin:\rGüvenlik duvarı özel durumları ekleyin: Apache, MySQL veya başka bir sunucu için.\rTarama dosyalar çalıştırıldığında: Eğer tüm dosyalar için antivirüs taraması etkin varsa, sunucular için çalıştırılabilir dosyaları yavaşlatabilir.\rFarklı URL\'ler için trafiği tarayın: Kendi makinenizde XAMPP gelişmekte iseniz, Antivirüs ayarlarında \\\\ \"localhost \" trafiği hariç tutabilirsiniz.\rNeden Apache sunucusunu benim sistemde başlamıyor?\rBu sorun çeşitli nedenlerle biri olabilir:\rSen (yani IIS, Sambar, ZEUS ve benzeri) daha sonra bir HTTP Sunucusu başladı. Sadece bir Sunucu Bu hata iletisi sorunu gösteriyor port 80 kullanabilirsiniz:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\r-> Seçenekler - Sen böyle bir sorun \\\\ \"Skype \" ise liman 80. Eğer Eylemler Skype gidebilirsiniz ayrıca bloklar Internet Telefon \\\\ \"Skype \" gibi başka yazılımları var> Bağlantı -> \"alternatif bir liman \\\\ için kullanılması port 80 \" de onay işaretini kaldırın ve Skype\'ı yeniden başlatın. Şimdi çalışmalıdır.\rHangi bloklar Apache portu bir güvenlik duvarı var. Tüm güvenlik duvarları, Apache ile uyumlu ve bazen güvenlik duvarını devre dışı bırakılması yeterli değildir ve bunu kaldırmanız gerekir. Bu hata iletisi, bir güvenlik duvarı belirtir:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rApache başlayabilir, ancak tarayıcınız buna bağlanamıyor Ayrıca eğer aşağıdakilerden birine bağlı olabilir:\rBazı virüs tarayıcıları güvenlik duvarları engelleyebilir aynı şekilde bu neden olabilir.\rSen XAMPP için en az SP1 olması gerekir hizmet paketi 1. olmadan XP Professional var.\rİpucu:\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\rNeden Apache neredeyse% 99 benim CPU yükü nedir?\rBurada oynayan iki senaryo biri vardır. Ya CPU maxing edilir veya tarayıcı sunucuya bağlanmak, ancak (sistem sayfasını yüklemek için unsucessfully çalışıyor) bir şey göremiyorum. Her iki durumda da Apache günlük dosyasında aşağıdaki iletiyi bulabilirsiniz:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rMPM geri güvenli uygulanmasına düşüyor, ama bazı istemci istekleri düzgün işlenmez bulundu. Bu hatayı önlemek için, \\\\ \"AcceptFilter \" kullanın filtre \\\\ \\\\ içinde \"yok \" \\\\ \"xampp \\\\ apache \\\\ conf \\\\ extra \\\\ httpd-mpm.conf \" dosyası kabul edin.\rNeden resim ve stil sayfaları değil gösterildi mi?\rBazen görüntüleniyor resim ve stil sayfası ile ilgili sorunlar var. Bu dosyalar bir ağ sürücüsünde bulunan özellikle. Bu durumda dosya \\\\ aşağıdaki satırları eğer birini etkinleştirin (veya eklemek) olabilir \"\\\\ xampp \\\\ apache \\\\ conf \\\\ httpd.conf \":\rEnableSendfile off\rEnableMMAP off\rBu sorun, Netlimiter gibi bant genişliği düzenlemek için programlar tarafından neden olabilir.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rNasıl MySQL bir kök şifre ayarlayabilirsiniz?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rBenim kendi MySQL sunucusu kullanabilir miyim?\rEvet. Basitçe XAMPP paketinden MySQL başlatmayın. İki sunucunun aynı bağlantı noktasında başlamış olamaz unutmayın. Eğer \\\\ \"root \" için bir parola ayarladıysanız, dosya \\\\ \"\\\\ xampp \\\\ phpMyAdmin \\\\ config.inc.php \" düzenlemek unutmayınız.\rNasıl dışarıdan phpMyAdmin erişimi kısıtlamak mı?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rMySQL sunucusuna erişmeden önce, phpMyAdmin kullanıcı adı ve şifre isteyecektir. İlk kullanıcı \\\\ \"root \" için bir şifre koymak unutmayın.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rNerede PHP IMAP desteği nedir?\rEğer, dosya \\\\ açabilirsiniz NT sistemlerinde çalışıyorsanız, varsayılan olarak, PHP IMAP desteği nedeniyle Windows 98 gibi bazı ev sürümleri ile bazı gizemli başlatma hataları XAMPP devre dışı bırakılır \"\\\\ xampp php \\\\ php.ini \\\\ \" \"; extension = php_imap.dll \" hat \\\\ başlayan noktalı virgül kaldırarak php exstension etkinleştirmek için. Olmalı:\rextension=php_imap.dll\rŞimdi Apache yeniden başlatın ve IMAP çalışması gerekir. Varsayılan yapılandırmada etkin değil her uzatma için aynı adımları kullanabilirsiniz.\rNeden bazı PHP açık kaynak uygulamaları Windows üzerinde XAMPP ile çalışmak değil mi?\rLinux için yazılmış PHP uygulamaları veya uzantıları bir sürü Windows taşıdık edilmemiştir. \rCan I delete the \"install\" directory after installation?\rO değil daha iyi. Burada komut dosyaları hala XAMPP tüm ek paketler (add-ons) ve yükseltmeleri için gereklidir.\reAccelerator\'u nasıl etkinleştirebilirim?\rDiğer (Zend) uzantıları gibi, \\\\ \"php.ini \" bunu etkinleştirebilirsiniz. \"; Zend_extension = \" \\\\ php_eaccelerator.dll \\\\ \"\" \\\\ xampp \\\\ php \\\\ ext Bu dosyada, satır \\\\ etkinleştirin. Olmalı:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rNasıl benim SQL sunucusuna MS bir bağlantı hatası düzeltebilirim?\rMssql uzantısı php.ini yüklendiyse yalnızca TCP / IP kullanıldığında bazen sorunlar görünür. Microsoft\'tan yeni bir \\\\ \"ntwdblib.dll \" ile bu sorunu çözebilirsiniz. \\\\ Eski dosyayı değiştirmek Lütfen \"\\\\ xampp apache \\\\ bin \\\\ \" ve \\\\ yenisi ile \"\\\\ xampp \\\\ php \". Çünkü lisans, biz XAMPP ile bu dosyanın daha yeni bir sürümünü paket olamaz.\rNasıl PHP mcrypt uzantısı ile çalışır?\r% {} Mcrypt: Bunun için örnekler ve olası çözümleri ile forumda bir konu açtı\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rPerl ekle-On ile No. Ve Apache :: ASP aynı değildir. Apache :: ASP sadece Perl-Script bilir, ama Internet Information Server (IIS) ASP normal VBScript bilir. Ama ASP .NET için, mevcut bir 3. parti Apache modülü var.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rGizlilik Politikası\rCdn sağladığı','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(87,'2022-11-22 16:37:13','main','s1|/dashboard/tr/howto.html',0,NULL,NULL,NULL,'/dashboard/tr/howto.html','XAMPP howto guides','Apache Friends\rMenu\rSSS\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rGizlilik Politikası\rCdn sağladığı','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(88,'2022-11-22 16:37:14','main','s1|/dashboard/tr/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/tr/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rSSS\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rGizlilik Politikası\rCdn sağladığı','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(89,'2022-11-22 16:37:12','main','s1|/dashboard/tr/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/tr/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rSSS\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rGizlilik Politikası\rCdn sağladığı','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(90,'2023-11-19 12:10:26','main','s1|/dashboard/tr/index.html',0,NULL,NULL,NULL,'/dashboard/tr/index.html','Welcome to XAMPP','Apache Friends\rMenu\rSSS\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rSSS\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nTopluluk\rXAMPP, 10 yılı aşkın süredir piyasada &ndash; Arkasında büyük bir topluluk vardır. Katılmak için \rForumlar\rkayıt olabilir, bizi \rFacebook\rbeğenebilir yada \rTwitter\ristismarlarımızı takip edebilirsiniz.\nFollow us on Twitter\rLike us on Facebook\rCopyright (c) 2022, Apache Friends\rBlog\rGizlilik Politikası\rCdn sağladığı','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(91,'2022-11-22 16:37:12','main','s1|/dashboard/ur/faq.html',0,NULL,NULL,NULL,'/dashboard/ur/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\rاکثر پوچھے گئے سوالات\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rعمومی سوالات\rمیں کس طرح XAMPP کو انسٹال کروں ؟\rونڈوز کے لیے xampp کی تین مختلف ذائقوں میں موجود ہے:\rانسٹالر\rشاید xampp کی نصب کرنے کے لئے سب سے آسان طریقہ.\rZIP:\rpurists کے لئے: xampp کی عام زپ محفوظ شدہ دستاویزات.\r7zip:\rXAMPP کی 7zip محفوظ شدہ دستاویزات کے طور پر: کم بینڈوڈتھ کے ساتھ purists کے لئے.\rنوٹ: اگر آپ فائلوں کو ہٹا دیں، تو، جھوٹے مثبت وائرس انتباہ ہو سکتا ہے.\rانسٹالر استعمال کرتے ہوئے:\rXAMPP کنٹرول پینل Apache, MySQL, FileZilla & Mercury کو شروع کرنے یا روکنے کے لئے یا ان سرورز کو سروس کے طور پر انسٹال کرنے کے لئے استعمال کرتے ہیں\rزپ کی طرف سے نصب\rآپ کی پسند کا فولڈر میں ZIP ابلیھاگار ان زپ. منتخب شدہ ہدف کی ڈائرکٹری ذیل: \"xampp\\C:\" XAMPP کی ذیری ڈائریکٹری پر نکالنے ہے. اب آپ کا سسٹم پر XAMPP کی ترتیب کو ایڈجسٹ کرنے کے لئے، فائل \"setup_xampp.bat\" شروع.\rآپ کو ایک روٹ ڈائریکٹری \"C:\\\" کا انتخاب کرتے ہیں ہدف کے طور پر، آپ کو \"setup_xampp.bat\" شروع نہیں ہونا چاہیے.\rانسٹالر کے ورژن کے ساتھ کی طرح، آپ کو اب اضافی کاموں کے لئے \"XAMPP کی کنٹرول پینل\" استعمال کر سکتے ہیں.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rمیں کس طرح سیٹ اپ کے بغیر XAMPP کی شروع کر سکتے ہیں؟\rاگر آپ XAMPP کو اعلی سطحی فولڈر جیسا کہ ,\"C:\\\\\" or \"D:\\\\\" میں ڈالیں تو آپ بہت سی سروسز جیسا کہ Apeche اور MySQL براہراست شروع کر سکتے ہیں \"setup_xampp.bat\" اس فائل کو چلاے بغیر .\rآپ کو ایک یوایسبی ڈرائیو پر XAMPP کی نصب کر رہے ہیں تو سیٹ اپ سکرپٹ کا استعمال کرتے ہوئے، یا سیٹ اپ سکرپٹ میں رشتہ دار کے راستے کا انتخاب نہیں، ترجیح دی جاتی ہے. ہر کمپیوٹر پر اس طرح کی ایک ڈرائیو ایک دوسرے ڈرائیو خط ہے کر سکتے ہیں. آپ سیٹ اپ سکرپٹ کے ساتھ کسی بھی وقت رشتہ دار راستے پر مطلق کی طرف سے تبدیل کر سکتے ہیں.\rہمارے ڈاؤن لوڈ کے صفحے سے انسٹالر استعمال کرتے ہوئے XAMPP کی نصب کرنے کے لئے کا سب سے آسان طریقہ ہے. XAMPP کی | پروگرام | تنصیب مکمل ہونے کے بعد، آپ کو شروع کرنے کے تحت XAMPP کی مل جائے گا. آپ / شروع تمام سرور کو روکنے کے اور بھی / انسٹال کی خدمات کو انسٹال کرنے کے XAMPP کی کنٹرول پینل استعمال کر سکتے ہیں.\rXAMPP کنٹرول پینل Apache, MySQL, FileZilla & Mercury کو شروع کرنے یا روکنے کے لئے یا ان سرورز کو سروس کے طور پر انسٹال کرنے کے لئے استعمال کرتے ہیں\rمیں کس طرح شروع کرنے اور XAMPP کی روک سکتا ہوں؟\rعالمی کنٹرول سینٹر \"XAMPP کی کنٹرول پینل\" (شکریہ www.nat32.com) ہے. اس کے ساتھ شروع کر دیا ہے:\r\\xampp\\xampp-control.exe\rتم نے بھی سرور کو روکنے / شروع کرنے کے لئے کچھ batchfiles استعمال کر سکتے ہیں:\rاپاچی اور مائی ایس کیو ایل شروع:\n\\xampp\\xampp_start.exe\rاپاچی اور مائی ایس کیو ایل سٹاپ:\n\\xampp\\xampp_stop.exe\rاپاچی شروع:\n\\xampp\\apache_start.bat\rاپاچی سٹاپ:\n\\xampp\\apache_stop.bat\rایس کیو ایل شروع:\n\\xampp\\mysql_start.bat\rایس کیو ایل سٹاپ:\n\\xampp\\mysql_stop.bat\rمرکری Mailserver شروع:\n\\xampp\\mercury_start.bat\rمرکری Mailserver سٹاپ:\n\\xampp\\mercury_stop.bat\rFileZilla کے سرور شروع:\n\\xampp\\filezilla_start.bat\rFileZilla کے سرور سٹاپ:\n\\xampp\\filezilla_stop.bat\rمیں کس طرح جانچ سکتا ہوں کہ سب چیزوں نے کام کیا ؟\rآپ اپنے پسندیدہ ویب براؤزر میں مندرجہ ذیل یو آر ایل لکھیں :\rhttp://localhost/\rیا \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rمیں کس طرح ایک خدمت کے طور پر ایک سرور انسٹال کر سکتے ہیں؟\rxampp کی میں ہر سرور آپ ونڈوز خدمت کے طور پر بھی انسٹال کر سکتے ہیں. تم نے بھی xampp کی کنٹرول پینل سے انسٹال کر سکتے ہیں. اس صورت میں یہ ایڈمنسٹریٹر کی سہولیات کے ساتھ سکرپٹ یا کنٹرول پینل کو چلانے کے لئے ضروری ہے.\rاپاچی سروس انسٹال کریں: xampp\\\\apache\\\\apache_installservice.bat\\\\\rApache سروس انسٹال کریں : xampp\\\\apache\\\\apache_uninstallservice.bat\\\\ \rایس کیو ایل سروس انسٹال کریں: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \rایس کیو ایل سروس انسٹال: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \rFileZilla کے خارج انسٹال کریں: \\\\xampp\\\\filezilla_setup.bat \rمرکری: کوئی سروس کی تنصیب دستیاب\rکیا XAMPP کی پیداوار تیار ہے؟\rXAMPP صرف ترقی کے ماحول کے لئے ہی نہیں ترتیب دیا گیا ہے، لیکن . XAMPP کو جس طرح وہ چاہتا / چاہتی ہے ڈویلپر کچھ بھی اجازت دینے کے لئے ہر ممکن حد تک کھلا ہے. ترقی کے ماحول کے لئے یہ بہت اچھا ہے لیکن پیداوار کے ماحول میں یہ مہلک ہو سکتا ہے.\rیہاں XAMPP کی لاپتہ سلامتی کی فہرست:\rمائی ایس کیو ایل کے منتظم (جڑ)/ (root) کا کوئی پاسوڑد نہیں ہے.\rمائی ایس کیو ایل ڈیمان نیٹ ورک کے ذریعے قابل رسائی ہے.\rProFTPD uses the password \"lampp\" for user \"daemon\".\rمرکری اور FileZilla کے پہلے سے طے شدہ صارفین کے نام سے جانا جاتا.\rتمام پوائنٹس کی ایک بہت بڑی سیکورٹی رسک ہو سکتا ہے. XAMPP کی آپ کے LAN کے باہر نیٹ ورک اور لوگوں کے ذریعے قابل رسائی ہے خاص طور پر اگر. یہ بھی ایک فائر وال یا ایک (NAT) روٹر استعمال کرنے کے لئے مدد کر سکتے ہیں. ایک روٹر یا فائروال کے معاملے میں، آپ کے کمپیوٹر کو عام طور پر نیٹ ورک کے ذریعے قابل رسائی نہیں ہے. یہ ان مسائل کو ٹھیک کرنے کے لئے آپ پر منحصر ہے. ایک چھوٹی سی مدد کے طور پر \"XAMPP کی سیکورٹی کنسول\" ہے.\rآن لائن کچھ بھی شائع کرنے سے پہلے XAMPP کی محفوظ کریں. فائروال یا ایک بیرونی روٹر سیکورٹی کی کم سطح کے لئے صرف کافی ہیں. تھوڑا سا زیادہ حفاظت کے لئے، آپ کو \"XAMPP کی سیکورٹی کنسول\" چلانے اور پاس ورڈ تفویض کر سکتے ہیں.\rآپ انٹرنیٹ سے آپ XAMPP کی قابل رسائی ہے کرنا چاہتے ہیں تو، آپ کو کچھ مسائل کو ٹھیک کر سکتے ہیں جو مندرجہ ذیل URI کو جانا چاہئے:\rhttp://localhost/security/\rسیکورٹی کنسول کے ساتھ آپ ایس کیو ایل صارف \"جڑ\" اور phpMyAdmin کے لئے ایک پاس ورڈ مقرر کر سکتے ہیں. تم نے بھی xampp کی demopages کے لئے ایک کی توثیق چالو کر سکتے ہیں.\rیہ ویب کی بنیاد پر آلے کے کسی بھی اضافی سیکورٹی کے مسائل حل نہیں ہے! خاص طور پر FileZilla کے FTP سرور اور مرکری میل سرور آپ کو اپنے آپ کو محفوظ کرنا ضروری ہے.\rمیں کس طرح اپنے کمپیوٹر سے xampp کی خارج کروں؟\rآپ انسٹالر ورژن استعمال XAMPP کی نصب، کی Uninstaller استعمال کریں. کی Uninstaller آپ کی رجسٹری کی طرف سے تمام XAMPP کی اندراجات کو خارج کر دیں اور اس کے ساتھ XAMPP شامل کچھ نصب خدمات انسٹال کیا جائے گا. ہم انتہائی اگر انسٹالر version.Please بیک اپ سے آپ XAMPP کی ناتنصیب سے پہلے رکھنا چاہتے ہیں تمام اعداد و شمار XAMPP کی تنصیبات کے دور کرنے کے لئے انسٹال پروگرام استعمال کرتے ہیں مشورہ ہے کہ.\rآپ کو زپ اور 7zip ورژن کا استعمال کرتے ہوئے XAMPP کی نصب، تمام XAMPP کی سرورز کو بند اور تمام پینل سے باہر نکلیں. آپ کو کسی بھی خدمات نصب، انسٹال کریں اور انہیں بھی بند. اب صرف XAMPP کی نصب کیا جاتا ہے، جہاں پورے فولڈر کو خارج. صاف کرنے کے لئے کوئی رجسٹری اندراجات اور کوئی ماحول متغیر ہیں.\rXAMPP کی کی \"واپس موضوع پر\" ورژن کیا ہے؟\rXAMPP کی واپس موضوع پر (\"ہلکے وزن\" میں کے طور پر \"روشنی\" کا مطلب ہے) صرف پی ایچ پی اور MySQL کا استعمال کرتے ہوئے فوری کام کے لئے سفارش کی جاتی ہے جس میں XAMPP کی اجزاء، کی ایک چھوٹی بنڈل ہے. اس طرح پارا میل اور FTP FileZilla کے طور پر کچھ سرورز یا فورم کے اوزار واپس موضوع پر ورژن میں یاد کر رہے ہیں.\rمیں اپنے ویب کے مواد کی جگہ چاہئے؟\rتمام ورلڈ وائڈ ویب دستاویزات کے لئے اہم ڈائریکٹری xampp\\\\htdocs\\\\ ہے. اگر آپ ایک فائل \"test.html\" اس ڈائریکٹوری میں ڈالیں, تو آپ اس تک رسائی حاصل کر سکتے ہیں\"URI \"http://localhost/test.html اس کے ساتھ .\rاور \"test.php\"؟ صرف \"http://localhost/test.php\" کا استعمال. ایک سادہ testscript ہو سکتا ہے:\r<?php\recho \'Hello world\'; \r?>\rآپ کی ویب کے لئے ایک نئی ذیلی ڈائریکٹری؟ صرف ایک نئی ڈائریکٹری بنایں (\"e.g. \"new) ڈائریکٹری کے اندر \"xampp\\\\htdocs\\\\\" ایک ٹیسٹ فائل بنایں اور اس سے رسائی حاصل کریں \"http://localhost/new/test.php\".\rمزید تفصیلات\rHTML:\rکارکردگی: \\xampp\\htdocs\rختم اجازت: .html .htm\r=> بنیادی پیکیج\rSSI:\rکارکردگی: \\xampp\\htdocs\rختم اجازت: .shtml\r=> بنیادی پیکیج\rCGI:\rکارکردگی: \\xampp\\htdocs and \\xampp\\cgi-bin\rختم اجازت: .cgi\r=> بنیادی پیکیج\rPHP:\rکارکردگی: \\xampp\\htdocs and \\xampp\\cgi-bin\rختم اجازت: .php\r=> بنیادی پیکیج\rPerl:\rکارکردگی: \\xampp\\htdocs and \\xampp\\cgi-bin\rختم اجازت: .pl\r=> بنیادی پیکیج\rApache::ASP Perl:\rکارکردگی: \\xampp\\htdocs\rختم اجازت: .asp\r=> بنیادی پیکیج\rJSP Java:\rکارکردگی: \\xampp\\tomcat\\webapps\\java (e.g.)\rختم اجازت: .jsp\r=> Tomcat add-on\rServlets Java:\rکارکردگی: \\xampp\\tomcat\\webapps\\java (e.g.)\rختم اجازت: .html (u.a)\r=> Tomcat add-on\rمیں XAMPP کی تنصیب منتقل کر سکتے ہیں؟\rجی ہاں. XAMPP کی ڈائریکٹری کے منتقل کرنے کے بعد، آپ \"setup_xampp.bat\" عملدرآمد ضروری ہے. ترتیب فائل میں راستے اس قدم کے ساتھ ایڈجسٹ کیا جائے گا.\rآپ کو ونڈوز سروس کے طور پر کسی بھی سرور انسٹال کیا ہے تو آپ کو پہلے ونڈوز سروس ہٹانے کے، اور ضروری ہے کے بعد آپ کو دوبارہ سروس انسٹال کر سکتے ہیں منتقل.\rانتباہ: آپ کے اپنے سکرپٹ کی طرف سے ترتیب فائل، پی ایچ پی کی ایپلی کیشنز کی طرح، ایڈجسٹ نہیں کر رہے ہیں. لیکن یہ انسٹالر کے لئے ایک \"پلگ ان\" لکھنے کے لئے ممکن ہے. اس طرح کے ایک پلگ ان کے ساتھ، انسٹالر بھی اس طرح کی فائلوں کو ایڈجسٹ کر سکتے ہیں.\rدیکھیے ورلڈ وائڈ ویب ڈائریکٹریز کے لئے \"خود کار طریقے سے شروع کے صفحات\" کیا ہیں؟\rاپاچی تقریب \"DirectoryIndex\" کے لئے معیاری فائل کا نام \"index.html\" یا \"index.php کو\" ہے. آپ کو صرف ایک فولڈر (مثال کے طور پر \"http://localhost/xampp/\") پر براؤزنگ کر رہے ہیں، اور اپاچی اس طرح ایک فائل تلاش کر سکتے ہیں ہر وقت، اپاچی اس فائل کی بجائے ایک ڈائرکٹری کی لسٹنگ کی نمائش ہے.\rمیں کہاں ترتیب تبدیل کر سکتے ہیں؟\rتقریبا XAMPP کی میں تمام ترتیبات آپ کو ترتیب فائل کے ساتھ تبدیل کر سکتے ہیں. بس ایک textedit میں فائل کو کھولنے اور آپ چاہتے ہیں کی ترتیب کو تبدیل. صرف FileZilla کے اور مرکری کی درخواست کی تشکیل کے آلے کے ساتھ ترتیب دیا جانا چاہئے.\rکیوں XAMPP کی Windows XP SP2 پر کام نہیں کر سکتے ہیں؟\rمائیکروسافٹ خود کار طریقے سے شروع ہوتا ہے جس سروس پیک 2 (SP2)، کے ساتھ ایک بہتر فائروال فراہم کرتا ہے. یہ فائروال اب بلاکس کے لئے ضروری بندرگاہوں 80 (HTTP) اور 443 (HTTPS) اور اپاچی شروع نہیں کر سکتے.\rسب سے تیز حل:\rٹول بار کے ساتھ مائیکروسافٹ فائر وال کو غیر فعال اور XAMPP کی زیادہ onces شروع کرنے کی کوشش کریں. بہتر حل سلامتی کے مرکز کے اندر اندر ایک رعایت کی وضاحت کرنے کے لئے ہے.\rمندرجہ ذیل بندرگاہوں کے بنیادی فعالیت کے لئے استعمال کیا جاتا ہے:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rکیوں XAMPP کی Vista پر کام نہیں کرتا؟\rیوزر اکاؤنٹ کنٹرول (UAC)\rڈائریکٹری \"C: \\\\ \\\\ پروگرام فائلیں\" میں آپ بھی ایڈمن کے طور پر، مکمل لکھنا استحقاق نہیں ہے. یا آپ کو صرف محدود استحقاق ہے (کے لئے مثال کے طور پر \". \\\\ \\\\ xampp کی \\\\ \\\\ htdocs\"). اس صورت میں آپ کو ایک فائل میں ترمیم نہیں کر سکتے ہیں.\rحل:\rایکسپلورر کے اندر اندر آپ کی مراعات میں اضافہ (دائیں / سیکورٹی کلک کریں) یا صارف کے اکاؤنٹ کنٹرول (UAC) کو غیر فعال.\rآپ میں اپاچی / ایس کیو ایل انسٹال کیا ہے \"C: \\\\ \\\\ xampp کی\" ونڈوز سروس کے طور پر. لیکن آپ کو \"xampp کی کنٹرول پینل\" کے ساتھ خدمات روکنے / شروع نہیں کر سکتے یا ان انسٹال نہیں کر سکتے ہیں.\rحل:\rونڈوز یا غیر فعال UAC سے سروس منیجمنٹ کنسول استعمال کرتے ہیں.\rیوزر اکاؤنٹ کنٹرول (UAC) غیر فعال\rUAC کو غیر فعال کرنے کے لئے \"msconfig\" پروگرام استعال کریں. \"msconfig\" میں \"Tools\" میں جایں اور سلیکٹ \"disable user account control\" اور انتخاب کی توثیق کریں.اب آپکو لازمی Windows دوبارہ شروع کرنا پڑے گی پھر آپ دوبارہ UAC فعال کر سکتے ہیں.\rمیں کس طرح MD5 حیض چیک کروں؟\rفائلوں کا آپس میں موازنہ کرنے کے لئے، اکثر checksums کے استعمال کیا جاتا ہے. اس حیض MD5 (پیغام ڈائجسٹ الگورتھم 5) بنانے کے لئے ایک معیار.\rXAMPP کی پیکیج کے آپ کے ڈاؤن لوڈ، اتارنا درست ہے یا نہیں ہے اگر یہ MD5 حیض کے ساتھ آپ کو، ٹیسٹ کر سکتے ہیں. کورس کے آپ ان checksums کے تشکیل دے سکتے ہیں جس میں ایک پروگرام کی ضرورت ہے. Windows کے لیے آپ کو مائیکروسافٹ کی طرف سے ایک آلے کا استعمال کر سکتے ہیں:\rدستیابی اور فائل حیض سالمیت ستیاپک افادیت کی تفصیل\rیہ GNU md5sum طرح، MD5 checksums کے تشکیل دے سکتے ہیں جو کسی بھی دوسرے پروگرام کا استعمال بھی ممکن ہے.\rآپ اس طرح کے ایک پروگرام (مثال کے طور fciv.exe) نصب ہے، آپ کو مندرجہ ذیل اقدامات کر سکتے ہیں:\rDownload XAMPP (f.e. xampp-win32-1.8.2-0.exe)\rکے ساتھ حیض تشکیل دیں:\rfciv.exe xampp-win32-1.8.2-0.exe\rاور اب آپ کو آپ کے Windows ایم کے لئے XAMPP کی پر تلاش کر سکتے ہیں ہے کہ ایک کے ساتھ اس حیض موازنہ کر سکتے ہیں.\rدونوں checksums کے برابر ہیں، تو سب ٹھیک ہے. اگر نہیں تو، ڈاؤن لوڈ، اتارنا ٹوٹ جاتا ہے یا فائل کو تبدیل کر دیا گیا ہے.\rکیوں میرے php.ini میں تبدیلی کا اثر نہیں لیا ہے؟\rاگر \"php.ini\" میں تبدیلی کوئی اثر نہیں ہے، تو یہ ہو سکتا ہے کہ PHP کی ایک مختلف استعمال کر رہا ہو . آپ ()phpinfo کے ساتھ اس بات کی تصدیق کر سکتے ہیں. URI http://localhost/xampp/phpinfo.php پر جائیں اور \"Loaded Configuration File\" کے لئے تلاش کریں. یہ قدر آپ \"php.ini\" PHP کی واقعی استعمال کر رہا ہے سے پتہ چلتا ہے.\rنوٹ:\rفائل \"php.ini\" آپکو Apache دوبارہ سٹارٹ کرنا ہو گا تاکہ Apache/PHP نئی تبدیلیوں کو پڑھ سکے.\rمدد کرو! XAMPP کی میں ایک وائرس ہے!\rSome antivirus programs mistake XAMPP for a virus, typically flagging the file xampp-manager.exe This is a false positive meaning that the antivirus erroneously identified it as a virus, when it is not. Before we release each new version of XAMPP we run it through virus scanning software. At the moment we are using \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rمیں کس طرح اپنے ینٹیوائرس درخواست کی تشکیل کرتے ہیں؟\rہم بنڈل ویب ایپلیکیشن کو چلانے کے لئے ضروری تمام dependences اور سرور شامل ہے، تو آپ XAMPP کی فائلوں کی بڑی تعداد میں انسٹال ہے مل جائے گا. آپ کو فعال ایک ینٹیوائرس اپلی کیشن کے ساتھ ایک Windows مشین پر ایک XAMPP کی درخواست کو انسٹال کر رہے ہیں تو، یہ نمایاں طور پر کی تنصیب کو سست کر سکتے ہیں، اور (ویب سرور، ڈیٹا بیس سرور) کے سرورز کی ایک ینٹیوائرس سافٹ ویئر کی طرف سے بلاک کیا جا سکتا ہے کا ایک موقع بھی ہے . آپ کو فعال ایک ینٹیوائرس آلے کے ہے، کارکردگی کے مسائل کے بغیر XAMPP کی کو چلانے کے لئے مندرجہ ذیل ترتیبات چیک کریں:\rApache، MySQL یا کسی دوسرے سرور کے لئے: فصیل میں مستثنیات شامل کریں.\rعمل جب فائلوں کو اسکین: آپ تمام فائلوں کے لئے ینٹیوائرس سکین فعال ہے تو، سرورز کے لئے فائلوں کو سست کر سکتے ہیں.\rمختلف یو آر ایل کے لئے ٹریفک سکین کریں: آپ کو آپ کے اپنے مشین پر ساتھ XAMPP ترقی کر رہے ہیں، تو آپ ینٹیوائرس کی ترتیبات میں \"لوکل ہوسٹ\" ٹریفک خارج کر سکتے ہیں.\rکیوں Apache سرور اپنے سسٹم پر شروع نہیں ہے؟\rیہ مسئلہ کئی وجوہات میں سے ایک ہو سکتا ہے:\rآپ کو زیادہ تو ایک HTTP سرور (تو IIS، سانبھر، Zeus اور) شروع کر دیا ہے. صرف ایک سرور پورٹ 80 استعمال کر سکتے ہیں. خامی کا یہ پیغام مسئلہ کی طرف اشارہ ہے:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rتم نے اس طرح انٹرنیٹ ٹیلی فون \"اسکائپ\" بھی ہے جس کے بلاکس پورٹ 80 کے طور پر دوسرے سافٹ ویئر، ہے. > \"ایک متبادل پورٹ کے لئے استعمال پورٹ 80\" میں نشان ہٹا دیں اور اسکائپ دوبارہ شروع - کنکشن> -> اختیارات - مسئلہ \"اسکائپ\" ہے تو، آپ کے عوامل کو Skype میں جا سکتے ہیں. اب یہ کام کرنا چاہئے.\rآپ کو ایک فائر وال جس بلاکس Apache بندرگاہ ہے. تمام فائر والز Apache ساتھ ہم آہنگ ہیں، اور کبھی کبھی فائر وال غیر تابکار کافی نہیں ہے اور آپ اس تنصیب ربائی کریں ضروری ہے. خامی کا یہ پیغام ایک فائروال کی طرف اشارہ:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rApache شروع کر سکتے ہیں، لیکن آپ کے براؤزر میں اس سے رابطہ قائم نہیں کر سکتے ہیں اس کے علاوہ مندرجہ ذیل میں سے ایک کی وجہ سے ہو سکتا ہے:\rکچھ وائرس سکینر فائر والز مداخلت کر سکتے ہیں اسی طرح ہے کہ میں اس وجہ سے کر سکتے.\rآپ سروس پیک 1 کے بغیر ایکس پی پروفیشنل ہے. آپ XAMPP کی کم از کم SP1 ہونا ضروری ہے.\rٹپ:\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\rکیوں اپاچی کے لئے اپنے CPU لوڈ تقریبا 99٪ ہے؟\rیہاں کھیل میں دو حالتوں میں سے ایک ہے. اپنے CPU باہر maxing ہے، یا آپ براؤزر سرور سے رابطہ قائم کر سکتے ہیں، لیکن (نظام پیج لوڈ کرنے unsucessfully کوشش کر رہا ہے) کچھ بھی نظر نہیں یا تو. دونوں صورتوں میں آپ اپاچی لاگ فائل میں مندرجہ ذیل پیغام حاصل کر سکتے ہیں:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rMPM ایک محفوظ عمل درآمد کرنے کے لئے واپس آتا ہے، لیکن کچھ کلائنٹ کی درخواستوں کو صحیح طریقے سے عملدرآمد نہیں کیا گیا. اس خرابی سے بچنے کے لئے، میں فلٹر قبول \"کوئی نہیں\" کے ساتھ \"AcceptFilter\" استعمال \"\\\\ \\\\ xampp کی \\\\ \\\\ اپاچی \\\\ \\\\ CONF \\\\ \\\\ اضافی \\\\ httpd پر-mpm.conf \\\\\" فائل.\rکیوں تصاویر اور سٹائل شیٹ ظاہر نہیں کر رہے ہیں؟\rکبھی کبھی کی نمائش تصاویر اور سٹائل شیٹ کے ساتھ مسائل ہیں. ان فائلوں کو ایک نیٹ ورک ڈرائیو پر واقع ہیں خاص طور پر اگر. اس صورت میں آپ کو چالو (یا شامل کریں) ایک فائل میں مندرجہ ذیل لائنوں \"\\xampp\\apache\\CONF \\ httpd.conf\" اگر کر سکتے ہیں:\rEnableSendfile off\rEnableMMAP off\rیہ مسئلہ بھی NetLimiter طرح، بینڈ وڈتھ کو ریگولیٹری کے لئے پروگرام کی وجہ سے کیا جا سکتا ہے.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rمیں کس طرح MySQL میں ایک روٹ کے پاس ورڈ مقرر کر سکتے ہیں؟\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rمیں اپنے MySQL سرور کا استعمال کر سکتے ہیں؟\rجی ہاں. بس XAMPP کی پیکج کی طرف سے MySQL شروع نہیں کرتے. دو سرورز اسی بندرگاہ پر شروع نہیں کیا جا سکتا ہے براہ مہربانی نوٹ. آپ کو \"جڑ\" کے لئے ایک پاس ورڈ مقرر ہے تو، فائل \"\\xampp\\phpMyAdmin کے \\config.inc.php \\\" ترمیم کرنے کے لئے نہیں بھولنا.\rمیں کس طرح باہر سے phpMyAdmin کے تک رسائی کو محدود کرتے ہیں؟\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rآپ MySQL سرور تک رسائی حاصل کر سکتے ہیں اس سے پہلے کہ، phpMyAdmin کے ایک صارف نام اور پاس ورڈ کے لئے آپ کو فوری طور پر کیا جائے گا. سب سے پہلے صارف \"جڑ\" کے لئے ایک پاس ورڈ کو قائم کرنے کے لئے نہیں بھولنا.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rکہاں PHP کے لئے IMAP کی حمایت کی ہے؟\rڈیفالٹ کے طور پر، PHP کے لئے IMAP کی حمایت کی وجہ سے Windows 98 کی طرح کچھ تلاش ہوم ورژن کے ساتھ کچھ پراسرار ابتدا غلطیوں XAMPP کی میں غیر فعال ہے. آپ NT نظام کے ساتھ کام کرتے ہیں تو، آپ فائل کو کھولنے کر سکتے ہیں \"\\ xampp\\PHP \\php.ini\" لائن میں شروع نیم وقفہ اتارنے کی طرف سے PHP کی exstension چالو کرنے کے لئے \"؛ توسیع = php_imap.dll\". یہ ہونا چاہئے:\rextension=php_imap.dll\rاب Apache دوبارہ شروع اور IMAP کام کرنا چاہئے. آپ ڈیفالٹ ترتیب میں فعال نہیں ہے جس میں ہر توسیع، کے لئے ایک ہی اقدامات استعمال کر سکتے ہیں.\rکیوں نہیں کچھ PHP اوپن سورس ایپلی کیشنز Windows کے ساتھ XAMPP کام کرتے ہیں؟\rلینکس کے لئے لکھا گیا ہے کہ PHP کی ایپلی کیشنز یا ملانے کے بہت سے Windows ported کیا نہیں کیا گیا ہے. \rCan I delete the \"install\" directory after installation?\rیہ بہتر ہے. یہاں سکرپٹ بھی تمام اضافی پیکجوں کے (ons شامل) اور XAMPP کی کی اپ گریڈ کے لئے کی ضرورت ہے.\rمیں کس طرح eaccelerator چالو کرتے ہیں؟\rدیگر (Zend) ملانے کی طرح، آپ کو \"php.ini\" میں اسے چالو کر سکتے ہیں. اس فائل میں، لائن کو چالو کرنے کے \"؛ zend_extension =\" \\xampp\\PHP \\ ایکسٹینشن \\php_eaccelerator.dll \"\". یہ ہونا چاہئے:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rمیں کس طرح اپنے MS SQL سرور کے لئے ایک کنکشن کی خرابی ٹھیک کروں؟\rMSSQL توسیع php.ini میں لوڈ کیا گیا تو صرف TCP / IP استعمال کیا جاتا ہے، بعض اوقات مسائل نظر آتے ہیں. آپ مائیکروسافٹ کی طرف سے ایک نئے \"ntwdblib.dll\" کے ساتھ اس مسئلہ کو حل کر سکتے ہیں. نئے ایک کے ساتھ \"PHP \\xampp\\ \\\" \"Apache \\بن \\xampp\\\" میں بڑی عمر کے فائل کی جگہ اور براہ مہربانی. کیونکہ لائسنس کی، ہم ساتھ XAMPP اس فائل کا نیا ورژن پیکج نہیں کر سکتے ہیں.\rمیں کس طرح PHP mcrypt توسیع کے ساتھ کام کرتے ہیں؟\rاس کے لئے، ہم نے مثالیں اور ممکنہ حل کے ساتھ فورم میں موضوع کھول دیا ہے:٪ {mcrypt}\rمائیکروسافٹ Active سرور (صفحات یسپ) کے ساتھ XAMPP کام کرتے ہیں؟\rPerl شامل کریں پر کے ساتھ نمبر اور Apache :: یسپ ہی نہیں ہے. Apache :: یسپ صرف Perl سکرپٹ جانتا ہے، لیکن انٹرنیٹ انفارمیشن سرور (IIS) سے یسپ بھی عام ہے VbScript جانتا ہے. لیکن یسپ NET. لئے، دستیاب 3rd پارٹی Apache ماڈیول ہے.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\rکاپی رائٹ 2022, Apache Friends\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(92,'2022-11-22 16:37:13','main','s1|/dashboard/ur/howto.html',0,NULL,NULL,NULL,'/dashboard/ur/howto.html','XAMPP howto guides','Apache Friends\rMenu\rاکثر پوچھے گئے سوالات\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rکاپی رائٹ 2022, Apache Friends\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(93,'2022-11-22 16:37:14','main','s1|/dashboard/ur/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/ur/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\rاکثر پوچھے گئے سوالات\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\rکاپی رائٹ 2022, Apache Friends\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(94,'2022-11-22 16:37:12','main','s1|/dashboard/ur/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/ur/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\rاکثر پوچھے گئے سوالات\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\rکاپی رائٹ 2022, Apache Friends\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(95,'2023-11-19 12:10:26','main','s1|/dashboard/ur/index.html',0,NULL,NULL,NULL,'/dashboard/ur/index.html','Welcome to XAMPP','Apache Friends\rMenu\rاکثر پوچھے گئے سوالات\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \rاکثر پوچھے گئے سوالات\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\nکمیونٹی\rXAMPP has been around for more than 10 years &ndash; there is a huge community behind it. You can get involved by joining our \rفورم\r, liking us on \rFacebook\r, or following our exploits on \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\rکاپی رائٹ 2022, Apache Friends\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(96,'2022-11-22 16:37:12','main','s1|/dashboard/zh_cn/faq.html',0,NULL,NULL,NULL,'/dashboard/zh_cn/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\r常见问题\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \r经常提到的问题\r如何安装XAMPP？\rXAMPP在Windows平台有三个不同版本：\r安装程序：\r大概是安装XAMPP最容易的方法了。\rZIP:\r为纯净软件爱好者提供的：XAMPP的标准zip压缩包。\r7zip:\r为网速慢的纯净软件爱好者提供的：XAMPP的7zip压缩包。\r注意：如果你解压文件的话，可能会被杀软误报毒。\r使用安装程序：\rXAMPP控制面板可以用于启动/停止Apache, MySQL, FileZilla和Mercury以及将它们安装为服务。\r通过ZIP安装\r解压ZIP压缩文件到您选择的文件夹中。 XAMPP被提取到子目录\"C:\\\\xampp\"选定的目标目录下。然后启动文件“setup_xampp.bat”进行配置以便XAMPP的配置调整到系统中。\r如果你选择根目录\"C:\\\\\"作为安装目标，你绝对不要启动\"setup_xampp.bat\"。\r就像安装版一样，你现在可以使用XAMPP控制面板来完成更多工作。\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\r我如何免安装启动XAMPP？\r如果你将XAMPP解压到一个根目录，比如\"C:\\\\\"或者是\"D:\\\\\"，你就可以直接启动大多数服务器例如Apache或者MySQL而无需执行文件\"setup_xampp.bat\"。\r如果你想在一个U盘上面安装XAMPP的话，不使用安装脚本，或者在安装脚本里面选择相对路径应该会是更好的做法。因为在不同的PC上面U盘的盘符应该都是不一样的。你可以通过安装脚本在任何时候从绝对路径切换到相对路径。\r下载页面上的安装包版本应该是安装XAMPP的最简单的方式了。安装过程结束之后，你会在开始菜单-程序-XAMPP下找到XAMPP。你可以使用XAMPP的控制面板来启动/停止任意一个服务器或者是安装/卸载服务。\rXAMPP控制面板可以用于启动/停止Apache, MySQL, FileZilla和Mercury以及将它们安装为服务。\r我如何启动和停止XAMPP？\r通用的控制中心位于XAMPP控制面板(感谢www.nat32.com)。它开始于：\r\\xampp\\xampp-control.exe\r您也可以使用一些批处理文件来启动/停止服务器：\rApache & MySQL 启动:\n\\xampp\\xampp_start.exe\rApache & MySQL 停止:\n\\xampp\\xampp_stop.exe\r启动Apache\n\\xampp\\apache_start.bat\r停止Apache\n\\xampp\\apache_stop.bat\r启动MySQL：\n\\xampp\\mysql_start.bat\r停止MySQL：\n\\xampp\\mysql_stop.bat\r启动Mercury邮件服务器：\n\\xampp\\mercury_start.bat\r停止Mercury邮件服务器：\n\\xampp\\mercury_stop.bat\r启动FileZilla服务器：\n\\xampp\\filezilla_start.bat\r停止FileZilla服务器：\n\\xampp\\filezilla_stop.bat\r我如何检查是否一切正常？\r在你喜欢的浏览器中输入下面的链接：\rhttp://localhost/\r或 \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\r我如何将一个服务器安装成为服务？\r你可以将XAMPP中的每一个服务器安装成为Windows服务。你也可以从XAMPP控制面板里面安装它。在这种情况下必须通过管理员权限运行控制面板或脚本。\r安装Apache服务：\\\\xampp\\\\apache\\\\apache_installservice.bat\r卸载Apache服务：\\\\xampp\\\\apache\\\\apache_uninstallservice.bat \r安装MySQL服务: \\\\xampp\\\\mysql\\\\mysql_installservice.bat \r卸载MySQL服务: \\\\xampp\\\\mysql\\\\mysql_uninstallservice.bat \r安装/卸载FileZilla服务: \\\\xampp\\\\filezilla_setup.bat \rMercury: 没有服务可供安装\rXAMPP准备好了吗？\rXAMPP是一个非常优秀而又实用的开发测试环境，XAMPP的配置是开放的，允许开发者任意去修改或配置适合您的开发环境。XAMPP并非商业运行环境，用于商业运作将是一个致命的环境！\r如下是XAMPP不安全的配置：\rMySQL数据库管理帐号 (root)没设置密码。\rMySQL数据库可以通过网络打开。\rProFTPD uses the password \"lampp\" for user \"daemon\".\rMercury和FileZilla的默认用户是已知的。\r所有的点都可能成为一个巨大的安全隐患。尤其是如果XAMPP是可以通过网络或你的局域网外的人访问的话。使用防火墙或一个（带NAT的）路由器也是有帮助的。在有路由器或者防火墙的情况下，你的电脑正常情况下是无法从外部互联网访问的。是否修复这些问题要取决于你。XAMPP安全控制台可以提供一点小的帮助。\r请在发布任何东西到网上之前做好XAMPP的安全。一个防火墙或者一个外部路由器只能让你达到一个比较低的安全水平。需要高一点的安全的话，你可以运行下XAMPP安全控制台并设置密码。\r如果你想要让你的XAMPP通过互联网访问的话，你需要访问下述网站来修复一些问题：\rhttp://localhost/security/\r借助安全控制台，您可以设置MySQL的“root”用户和phpMyAdmin的密码。您还可以给XAMPP的演示页启用一个认证。\r这个基于网络的工具不能修复任何附加的安全问题！尤其是FileZilla FTP服务器和Mercury邮件服务器，你必须自行保护它们。\r如何卸载XAMPP？\r如果你使用安装包版本安装了XAMPP，请使用卸载工具卸载。卸载工具会删除掉所有的XAMPP的文件并会卸载掉已经安装的服务，包括XAMPP自身。我们强烈推荐你使用卸载程序移除XAMPP的安装。请在卸载之前备份你所有想保留的文件。\r如果你使用zip或者7zip版本安装了XAMPP，请关掉所有的XAMPP服务器并退出控制面板。如果你安装了服务，也需要卸载并关闭他们。现在只需要简单的把XAMPP所在文件夹一删就完事了，不会再有需要清理的任何注册表项或者环境变量啦。\rXAMPP的“lite”版本是什么玩意？\rXAMPP Lite（意思是“轻的”或者“轻量级的”）是一个更小的XAMPP的组件合集，推荐用来做一些只需要PHP和MySQL的快速的工作。像Mercury邮件或者是FileZilla的FTP服务器在这个版本里都是没有的。\r我应该把我的web内容放在哪里呢？\r所有www文档的根目录都是\\\\xampp\\\\htdocs。如果你在目录里放一个文件“test.html”，你可以通过这个URL访问它：http://localhost/test.html。\r至于\"test.php\"呢？用\"http://localhost/test.php\"就可以啦。一个简单的测试脚本可以这么写：\r<?php\recho \'Hello world\'; \r?>\r想给你的web服务器设一个新的子目录？只需要在目录\\\\xampp\\\\htdocs新建个文件夹就行了（最好不要空格并且只使用英文字母和数字），并且建一个测试文件然后访问它，例如http://localhost/new/test.php。\r更多细节\rHTML:\r可执行的： \\xampp\\htdocs\r允许的结尾： .html .htm\r=> 基本的包\rSSI:\r可执行的： \\xampp\\htdocs\r允许的结尾： .shtml\r=> 基本的包\rCGI:\r可执行的： \\xampp\\htdocs and \\xampp\\cgi-bin\r允许的结尾： .cgi\r=> 基本的包\rPHP:\r可执行的： \\xampp\\htdocs and \\xampp\\cgi-bin\r允许的结尾： .php\r=> 基本的包\rPerl:\r可执行的： \\xampp\\htdocs and \\xampp\\cgi-bin\r允许的结尾： .pl\r=> 基本的包\rApache::ASP Perl:\r可执行的： \\xampp\\htdocs\r允许的结尾： .asp\r=> 基本的包\rJSP Java:\r可执行的： \\xampp\\tomcat\\webapps\\java (e.g.)\r允许的结尾： .jsp\r=> Tomcat add-on\rServlets Java:\r可执行的： \\xampp\\tomcat\\webapps\\java (e.g.)\r允许的结尾： .html (u.a)\r=> Tomcat add-on\r我可以移动XAMPP安装文件么？\r是的，当移动XAMPP文件目录之后，你必须执行一下\"setup_xampp.bat\"。在配置文件里的路径会在这一步之后被改变。\r如果你已经将任意一个服务器安装成了Windows服务，你必须先移除服务，移动之后你可以重新安装服务。\r警告：你自己的脚本的配置文件，例如你的PHP应用，是不会被调整的。但是你可以为安装工具写一个插件，借助这样一个插件，安装工具就也可以同时调整这些文件了。\r访问WWW目录的时候指向的“默认起始页”的名称是什么呢？\rApache的\"DirectoryIndex\"（目录起始页）功能的预设文件名是“index.html”或者“index.php”。每次当你访问一个文件夹的时候（例如http://localhost/xampp/），Apache会先找一下指定名称的文件，并且找的话会默认显示那个文件而不会再显示目录的文件列表啦。\r我可以在哪儿修改配置呢？\rXAMPP几乎所有的设置都可以在配置文件里修改。只需要在文本编辑器里打开文件然后就可以按你的需要修改设置了。只有Filezilla和Mercury需要使用应用配置工具里自定义设置。\r为啥XAMPP不能在Windows XP SP2下工作呢？\r微软在service pack 2 (SP2)里面提供了一个更加高大上的会自动启动的防火墙，这个防火墙会拦截掉Apache必需的80和443端口，然后Apache就启动不了了。\r最快的解决方案：\r把微软那个防火墙给它关了，然后再启动一下XAMPP试试。更好的解决办法是在安全中心里面给XAMPP定义一个例外。\r下述端口是提供给基本功能用的：\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\r为什么XAMPP不能在Vista上工作？\r用户帐户控制（UAC）\r在目录\"C:\\\\program files\"当中你是没有完整的写权限的，即便管理员也不行。或者你就只有有限的权限（例如\".\\\\xampp\\\\htdocs\"）了。在这种情况下你就不能编辑文件了。\r解决方案：\r通过浏览器（右键-安全）来提高你的权限或者禁用用户帐户控制（UAC）\r你已经在\"C:\\\\xampp\"将Apache/MySQL安装成Windows服务但你不能通过\"XAMPP控制面板\"启动/停止这些服务或者不能卸载它们。\r解决方案：\r从Windows使用服务管理控制台或禁用UAC。\r禁用用户帐户控制（UAC）\r为了禁用UAC，你需要使用程序“msconfig”。在msconfig当中找到“工具”，选择“禁用用户账户控制”然后保存你的更改。现在你必须重启一下电脑。同时你也可以再次启动UAC。\r我如何检查md5校验值呢？\r想要比较文件，通常使用的办法是计算校验值。md5（消息摘要算法5）就是其中的一个生成校验值的标准。\r使用这个md5校验值你可以检查出来你下载的XAMPP包是不是完好的。当然你需要有一个工具来生成这个校验值。Windows用户可以使用微软的一个工具：\r可用性和文件校验和完整性验证程序的描述\r也可以使用其他能够生成md5的程序，例如GNU md5sum。\r安装好这样的一个程序（例如fciv.exe）之后，你可以完成如下的步骤：\r下载XAMPP（例如xampp-win32-1.8.2-0.exe）\r用于生成校验值的：\rfciv.exe xampp-win32-1.8.2-0.exe\r然后你就可以用你的校验值和在XAMPP主页找到的校验值进行比较了。\r如果两个校验值是一样的，就是好的。否则，要么下载文件损坏了要么是文件被修改过。\r为啥我在php.ini里做的修改没有生效?\r如果在\"php.ini\"里做的修改没有生效，很可能是因为PHP用的是另外一个。你可以通过phpinfo()来检查这一点。访问这个网址 http://localhost/xampp/phpinfo.php 并找到Loaded Configuration File。这个值会告诉你PHP实际使用的php.ini。\r注意：\r在修改php.ini之后你必须重启Apache这样Apache/PHP才能够读取设置。\r卧槽！XAMPP里头有病毒！\r有些杀软会误报你懂的。通常他们会把xampp-manager.exe这个文件当成病毒。误报的意思就是本来不是病毒的东西被杀软错误的看做了病毒。我们每次发布新版XAMPP的时候都会用杀软扫一遍的。我们目前使用的是 \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\r我如何配置我的杀软？\r我们已经添加好了所有运行这个打包好的web应用所需的必要组件和服务器软件，所以你会发现XAMPP会安装一大堆文件。如果你在一个开着杀软的Windows的机器上安装XAMPP应用，可能会明显的拖缓安装进程的速度，而且还可能会有服务器（如web服务器，数据库服务器）被杀软阻塞了。如果你有开着的杀软，请检查下列可以保证运行XAMPP而不造成性能问题的设置：\r给防火墙添加例外：针对Apache，MySQL或者其他任何的服务器。\r执行的时候扫描文件：如果你对所有文件都启动了杀软的扫描功能，服务器的可执行文件可能会被拖慢。\r扫描不同网址的流量：如果你在自己的机器上用XAMPP做开发，你可以在杀软的设置里排除掉localhost的流量监测。\r为什么Apache服务器在我的系统上启动不了呢？\r这个问题可能是由这几种原因之一造成的：\r你开启了不止一个HTTP的服务器(IIS, Sambar, ZEUS以及别的什么)。只有一个服务器可以占用80端口。这个错误消息指出了这个问题：\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\r你有其他的软件，例如也会阻断80端口的互联网电话软件“skype”。如果问题来源于skype，你可以进入skype找到操作 - >选项 - >连接 - >取消勾选“使用端口80作为备用端口”，然后重新启动Skype。现在应该可以正常工作了。\r你有一个阻断了Apache端口的防火墙。不是所有的防火墙都兼容Apache，而有的时候禁用防火墙是不够的，还得卸载掉它才行。这个错误信息是指向防火墙的：\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\r此外，如果Apache可以启动，但您的浏览器无法连接到它可能是由于以下原因之一：\r有些病毒扫描程序可能会像防火墙一样产生干扰并导致这个问题。\r你的XP Professional没有安装sp1。你必须至少安装一个SP1才能用XAMPP。\r提示：\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\r为什么我的Apache占用的CPU负载接近99%呢？\r有两种情况，要么是你的CPU确实达到上限了，要么你的浏览器能够连接到服务器但是啥也看不到（系统尝试加载页面但是失败了），不管是哪种情况你都可以在Apache的log文件里面找到下述信息：\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\r多道处理模块（MPM）回归到一个更加安全的执行模式，从而导致一些客户端的请求没有没有正确的执行。为了避免这样的错误，可以在\"\\\\xampp\\\\apache\\\\conf\\\\extra\\\\httpd-mpm.conf\"文件当中将可接受的过滤器\"AcceptFilter\"置为\"none\"。\r为什么图片和样式表显示不出来？\r有时候显示图片和样式表会有问题，特别是如果这些文件位于网络驱动器上的时候。在这种情况下，您可以启用（或增加）一行，如果文件\"\\\\xampp\\\\apache\\\\conf\\\\httpd.conf\"中的以下行:\rEnableSendfile off\rEnableMMAP off\r这个问题也可能是由带宽调整软件，例如NetLimiter导致的。\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\r我如何在MySQL里面设置一个root的密码？\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\r我可以使用自己的MySQL服务器么？\r可以的，只是不要启动XAMPP包里的MySQL就够了。请注意两个服务器不能在同一个端口上同时启动如果你已经设置了一个root的密码，请不要忘记修改这个文件：\\\\xampp\\\\phpMyAdmin\\\\config.inc.php。\r我如何限制phpMyAdmin的外部访问呢？\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\r当你能访问MySQL服务器之前，phpMyAdmin会提示你输入用户名和密码。不要忘记先给用户\"root\"设个密码哦。\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rPHP的IMAP支持在哪儿呢？\r默认的话，在XAMPP里面PHP对IMAP的支持是被停用的，因为对于某些家用的系统版本比如Windows 98会出现一些诡异的初始化错误。如果你用的是Windows NT系统的话，你可以打开文件\"\\\\xampp\\\\php\\\\php.ini\"并去掉\";extension=php_imap.dll\"这一行前面的分号来激活这个PHP扩展。它应该是这样的：\rextension=php_imap.dll\r现在重启一下Apache然后IMAP就好使啦。你可以使用同样的步骤来操作任何一个在默认配置里没有激活的扩展。\r为什么一些PHP开源应用不能在Windows版的XAMPP工作呢？\r许多PHP应用或者扩展都是为linux写的，还没有被移植到Windows。 \rCan I delete the \"install\" directory after installation?\r最好不要这样。所有的附加组件和XAMPP的升级仍然是需要使用这个脚本的。\r我如何激活eaccelerator？\r就像很多(Zend)扩展一样，你可以在\"php.ini\"里激活它。在这个文件里，启用这一行\";zend_extension = \"\\\\xampp\\\\php\\\\ext\\\\php_eaccelerator.dll\"\"。它应该是这样子的：\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\r我如何修复我的MS SQL服务器的连接错误？\r如果mssql扩展加载到了php.ini，有时候当只有TCP/IP使用的时候会出问题。你可以从微软获取一个新的“ntwdblib.dll”来修复这个问题。请用新的替换掉位于\"\\\\xampp\\\\apache\\\\bin\"和\"\\\\xampp\\\\php\"的旧的文件。因为许可证问题，我们不能把这个文件的更新版本打包进XAMPP。\r我如何使用PHP mcrypt扩展？\r为了这个，我们已经在社区里开了一个话题，关于例子和有效的解决方案：\rMCrypt主题\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\r不行。那个和带有Perl的Apache::ASP附加组件是不一样的。Apache::ASP只能运行Perl脚本，但是IIS上的ASP文件还会有正常的VBScript。不过对于ASP .NET，有一个第三方的Apache扩展模块可以使用。\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\r版权所有(c) 2022, Apache Friends\r博客\r隐私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(97,'2022-11-22 16:37:13','main','s1|/dashboard/zh_cn/howto.html',0,NULL,NULL,NULL,'/dashboard/zh_cn/howto.html','XAMPP howto guides','Apache Friends\rMenu\r常见问题\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\r版权所有(c) 2022, Apache Friends\r博客\r隐私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(98,'2022-11-22 16:37:14','main','s1|/dashboard/zh_cn/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/zh_cn/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\r常见问题\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\r版权所有(c) 2022, Apache Friends\r博客\r隐私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(99,'2022-11-22 16:37:12','main','s1|/dashboard/zh_cn/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/zh_cn/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\r常见问题\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\r版权所有(c) 2022, Apache Friends\r博客\r隐私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(100,'2023-11-19 12:10:26','main','s1|/dashboard/zh_cn/index.html',0,NULL,NULL,NULL,'/dashboard/zh_cn/index.html','Welcome to XAMPP','Apache Friends\rMenu\r常见问题\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \r常见问题\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\n社区\rXAMPP已经存在了大约十多年——在它背后有一个巨大的社区。你可以通过加入我们的\r论坛\r，在\rFacebook\r上喜欢我们，在\rTwitter\r上关注我们的成就。\nFollow us on Twitter\rLike us on Facebook\r版权所有(c) 2022, Apache Friends\r博客\r隐私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(101,'2022-11-22 16:37:12','main','s1|/dashboard/zh_tw/faq.html',0,NULL,NULL,NULL,'/dashboard/zh_tw/faq.html','XAMPP FAQs for Windows','Apache Friends\rMenu\r常見問題\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rFrequently Asked Questions\rHow do I install XAMPP?\rXAMPP for Windows exists in three different flavors:\rInstaller:\rProbably the easiest way to install XAMPP.\rZIP:\rFor purists: XAMPP as ordinary ZIP archive.\r7zip:\rFor purists with low bandwidth: XAMPP as 7zip archive.\rNote: If you extract the files, there can be false-positives virus warnings.\rUsing the installer:\rThe XAMPP control panel for start/stop Apache, MySQL, FileZilla & Mercury or install these server as services.\rInstalling from ZIP\rUnzip the zip archives into the folder of your choice. XAMPP is extracting to the subdirectory \"C:\\xampp\" below the selected target directory. Now start the file \"setup_xampp.bat\", to adjust the XAMPP configuration to your system.\rIf you choose a root directory \"C:\\\" as target, you must not start \"setup_xampp.bat\".\rLike with the installer version, you can now use the \"XAMPP Control Panel\" for additional tasks.\rDoes XAMPP include MySQL or MariaDB?\rSince XAMPP 5.5.30 and 5.6.14, XAMPP ships MariaDB instead of MySQL. The commands and tools are the same for both.\rHow can I start XAMPP without setup?\rIf you extract XAMPP in a top level folder like \"C:\\\" or \"D:\\\", you can start most servers like Apache or MySQL directly without execution of the file \"setup_xampp.bat\".\rNot using the setup script, or selecting relative paths in the setup script, is preferred if you are installing XAMPP on a usb drive. Because on each pc such a drive can have an other drive letter. You can switch from absolute to relative paths at any time with the setup script.\rUsing the installer from our Downloads page is the easiest way to install XAMPP. After the installation is complete, you will find XAMPP under Start | Programs | XAMPP. You can use the XAMPP Control Panel to start/stop all server and also install/uninstall services.\rThe XAMPP control panel for start/stop Apache, MySQL, FileZilla & Mercury or install these server as services.\rHow do I start and stop XAMPP?\rThe universal control center is the \"XAMPP Control Panel\" (thanks www.nat32.com). It is started with:\r\\xampp\\xampp-control.exe\rYou can also use some batchfiles to start/stop the servers:\rApache & MySQL start:\n\\xampp\\xampp_start.exe\rApache & MySQL stop:\n\\xampp\\xampp_stop.exe\rApache start:\n\\xampp\\apache_start.bat\rApache stop:\n\\xampp\\apache_stop.bat\rMySQL start:\n\\xampp\\mysql_start.bat\rMySQL stop:\n\\xampp\\mysql_stop.bat\rMercury Mailserver start:\n\\xampp\\mercury_start.bat\rMercury Mailserver stop:\n\\xampp\\mercury_stop.bat\rFileZilla Server start:\n\\xampp\\filezilla_start.bat\rFileZilla Server stop:\n\\xampp\\filezilla_stop.bat\rHow can I test that everything worked?\rType in the following URL at your favourite web browser:\rhttp://localhost/\ror \rhttp://127.0.0.1/\rYou should see the XAMPP start page, as shown below.\rHow can I install a server as a service?\rEach server in XAMPP you can install also as Windows service. You can also install it from the XAMPP Control Panel. In this case it is necessary to run the scripts or the Control Panel with Administrator privileges.\rApache service install: \\xampp\\apache\\apache_installservice.bat\rApache service uninstall: \\xampp\\apache\\apache_uninstallservice.bat \rMySQL service install: \\xampp\\mysql\\mysql_installservice.bat \rMySQL service uninstall: \\xampp\\mysql\\mysql_uninstallservice.bat \rFileZilla service (un)install: \\xampp\\filezilla_setup.bat \rMercury: No service installation available\rIs XAMPP production ready?\rXAMPP is not meant for production use but only for development environments. XAMPP is configured to be open as possible to allow the developer anything he/she wants. For development environments, this is great but in a production environment, it could be fatal.\rHere a list of missing security in XAMPP:\rThe MySQL administrator (root) has no password.\rThe MySQL daemon is accessible via network.\rProFTPD uses the password \"lampp\" for user \"daemon\".\rThe default users of Mercury and FileZilla are known.\rAll points can be a huge security risk. Especially if XAMPP is accessible via network and people outside your LAN. It can also help to use a firewall or a (NAT) router. In case of a router or firewall, your PC is normally not accessible via network. It is up to you to fix these problems. As a small help there is the \"XAMPP Security console\".\rPlease secure XAMPP before publishing anything online. A firewall or an external router are only sufficient for low levels of security. For slightly more security, you can run the \"XAMPP Security console\" and assign passwords.\rIf you want have your XAMPP accessible from the internet, you should go to the following URI which can fix some problems:\rhttp://localhost/security/\rWith the security console you can set a password for the MySQL user \"root\" and phpMyAdmin. You can also enable a authentication for the XAMPP demopages.\rThis web based tool does not fix any additional security issues! Especially the FileZilla FTP server and the Mercury mail server you must secure yourself.\rHow do I uninstall XAMPP?\rIf you installed XAMPP using the installer version, please use the Uninstaller. The Uninstaller will delete all XAMPP entries from your registry and it will uninstall some installed services included with XAMPP. We highly recommend that you use the Uninstall program for removing XAMPP installations from the Installer version.Please backup all the data you want to keep before uninstalling XAMPP.\rIf you installed XAMPP using the ZIP and 7zip versions, shut down all XAMPP servers and exit all panels. If you installed any services, uninstall and shut them down too. Now simply delete the entire folder where XAMPP is installed. There are no registry entries and no environment variables to clean up.\rWhat is the \"lite\" version of XAMPP?\rXAMPP Lite (means \"light\" as in \"light-weight\") is a smaller bundle of XAMPP components, which is recommended for quick work using only PHP and MySQL. Some servers or tools such as Mercury Mail and FileZilla FTP are missing in the Lite version.\rWhere should I place my web content?\rThe main directory for all WWW documents is \\xampp\\htdocs. If you put a file \"test.html\" in this directory, you can access it with the URI \"http://localhost/test.html\".\rAnd \"test.php\"? Just use \"http://localhost/test.php\". A simple testscript can be:\r<?php\recho \'Hello world\'; \r?>\rA new subdirectory for your web? Just make a new directory (e.g. \"new\") inside the directory \"\\xampp\\htdocs\" (best without whitespaces and only ASCII), create a test file in this directory and access it with \"http://localhost/new/test.php\".\rFurther specifics\rHTML:\rExecutable: \\xampp\\htdocs\rAllowed endings: .html .htm\r=> basic package\rSSI:\rExecutable: \\xampp\\htdocs\rAllowed endings: .shtml\r=> basic package\rCGI:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .cgi\r=> basic package\rPHP:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .php\r=> basic package\rPerl:\rExecutable: \\xampp\\htdocs and \\xampp\\cgi-bin\rAllowed endings: .pl\r=> basic package\rApache::ASP Perl:\rExecutable: \\xampp\\htdocs\rAllowed endings: .asp\r=> basic package\rJSP Java:\rExecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rAllowed endings: .jsp\r=> Tomcat add-on\rServlets Java:\rExecutable: \\xampp\\tomcat\\webapps\\java (e.g.)\rAllowed endings: .html (u.a)\r=> Tomcat add-on\rCan I move the XAMPP installation?\rYes. After moving of the XAMPP directory, you must execute \"setup_xampp.bat\". The paths in the configuration files will be adjusted with this step.\rIf you have installed any server as Windows service, you must first remove the Windows service, and after the moving you can install the service again.\rWARNING: The configuration files from your own scripts, like PHP applications, are not adjusted. But it\'s possible to write a \"plug-in\" for the installer. With such a plug-in, the installer can adjust such files too.\rWhat are \"Automatic start pages\" for the WWW directories?\rThe standard filename for the Apache function \"DirectoryIndex\" is \"index.html\" or \"index.php\". Every time you are just browsing to a folder (e.g. \"http://localhost/xampp/\"), and Apache can find such a file, Apache is displaying this file instead of a directory listing.\rWhere can I change the configuration?\rAlmost all settings in XAMPP you can change with configuration files. Just open the file in a textedit and change the setting you want. Only FileZilla and Mercury should be configured with the application config tool.\rWhy can\'t XAMPP work on Windows XP SP2?\rMicrosoft delivers a better firewall with service pack 2 (SP2), which starts automatically. This firewall now blocks the necessary ports 80 (http) and 443 (https) and Apache can\'t start.\rThe fast solution:\rDisable the Microsoft firewall with the toolbar and try to start XAMPP onces more. The better solution is to define an exception within the security center.\rThe following ports are used for basic functionality:\rApache (HTTP): Port 80\rApache (WebDAV): Port 81\rApache (HTTPS): Port 443\rMySQL: Port 3306\rFileZilla (FTP): Port 21\rFileZilla (Admin): Port 14147\rMercury (SMTP): Port 25\rMercury (POP3): Port 110\rMercury (IMAP): Port 143\rMercury (HTTP): Port 2224\rMercury (Finger): Port 79\rMercury (PH): Port 105\rMercury (PopPass): Port 106\rTomcat (AJP/1.3): Port 8009\rTomcat (HTTP): Port 8080\rWhy doesn\'t XAMPP work on Vista?\rUser Account Control (UAC)\rIn the directory \"C:\\program files\" you don\'t have full write privileges, even as Admin. Or you have only limited privileges (e.g. for \".\\xampp\\htdocs\"). In this case you can\'t edit a file.\rSolution:\rRaise your privileges within explorer (right click / security) or deactivate the user account control (UAC).\rYou have installed Apache/MySQL in \"C:\\xampp\" as Windows service. But you can\'t start/stop the services with the \"XAMPP Control Panel\" or can\'t uninstall them.\rSolution:\rUse the service management console from Windows or deactivate UAC.\rDisabling the User Account Control (UAC)\rTo deactivate the UAC, use the program \"msconfig\". In \"msconfig\" go to \"Tools\", select \"disable user account control\" and verify your selection. Now you must restart Windows. At the same time, you can enable the UAC again.\rHow do I check the md5 checksum?\rTo compare files, often checksums are used. A standard to create this checksum md5 (Message Digest Algorithm 5).\rWith this md5 checksum you can test, if your download of the XAMPP package is correct or not. Of course you need a program which can create these checksums. For Windows you can use a tool from Microsoft:\rAvailability and description of the File Checksum Integrity Verifier utility\rIt\'s also possible to use any other program which can create md5 checksums, like the GNU md5sum.\rAs you have installed such a program (e.g. fciv.exe), you can do following steps:\rDownload XAMPP (f.e. xampp-win32-1.8.2-0.exe)\rCreate the checksum with:\rfciv.exe xampp-win32-1.8.2-0.exe\rAnd now you can compare this checksum with that one you can find on the XAMPP for Windows homepage.\rIf both checksums equal, all is ok. If not, the download is broken or the file has been changed.\rWhy have changes in my php.ini not taken effect?\rIf a change in the \"php.ini\" has no effect, it\'s possible PHP is using a different one. You can verify this with phpinfo(). Go to the URI http://localhost/xampp/phpinfo.php and search for \"Loaded Configuration File\". This value shows you the \"php.ini\" PHP is really using.\rNote:\rAfter changing the \"php.ini\" you have to restart Apache so that Apache/PHP can read the new settings.\rHelp! There is a virus in XAMPP!\rSome antivirus programs mistake XAMPP for a virus, typically flagging the file xampp-manager.exe This is a false positive meaning that the antivirus erroneously identified it as a virus, when it is not. Before we release each new version of XAMPP we run it through virus scanning software. At the moment we are using \rKapersky Online Virus Scanner\r. You can also use the online tool \rVirus Total\rfor scanning XAMPP or send us an email to security (at) apachefriends (dot) org if you find any issue.\rHow do I configure my antivirus application?\rWe have included all dependences and servers required for running the bundled web application, so you will find that XAMPP installs large numbers of files. If you are installing a XAMPP application on a Windows machine with an antivirus app enabled, this may slow down the installation significantly, and there is also a chance that one of the servers (web server, database server) may be blocked by the antivirus software. If you have an antivirus tool enabled, check the following settings for running XAMPP without performance issues:\rAdd exceptions in the firewall: for Apache, MySQL or any other server.\rScan files when executing: If you have enabled the antivirus scan for all files, the executable files for the servers may slow down.\rScan the traffic for different URLs: If you are developing with XAMPP on your own machine, you can exclude \"localhost\" traffic in the Antivirus settings.\rWhy doesn\'t the Apache server start on my system?\rThis problem can be one of several reasons:\rYou have started more then one HTTP Server (IIS, Sambar, ZEUS and so on). Only one Server can use port 80. This error message indicate the problem:\r(OS 10048)... make_sock: could not bind to adress 0.0.0.0:80\nno listening sockets available, shutting down\rYou have other software, such as the Internet Telephone \"Skype\" which also blocks the port 80. If the problem is \"Skype\", you can go in Skype to Actions --> Options --> Connection --> remove the check mark at \"use port 80 for an alternate port\" and restart Skype. Now it should work.\rYou have a firewall which blocks the Apache port. Not all firewalls are compatible with Apache, and sometimes deactivating the firewall is not enough and you must deinstall it. This error message indicates a firewall:\r(OS 10038)Socket operation on non-socket: make_sock: for address 0.0.0.0:80,\napr_socket_opt_set: (SO_KEEPALIVE)\rAlso if Apache can start, but your browser can\'t connect to it it could be due to one of the following:\rSome virus scanners can cause this in the same way that firewalls can interfere.\rYou have XP Professional without service pack 1. You must have at least SP1 for XAMPP.\rTip:\rIf you have problems with used ports, you can try the tool \"xampp-portcheck.exe\". Maybe it can help.\rWhy is my CPU load for Apache almost 99%?\rThere is one of two scenarios at play here. Either your CPU is maxing out, or you can browser connect to the server, but not see anything (the system is trying unsucessfully to load the page). In either case you can find the following message in the Apache log file:\rChild: Encountered too many AcceptEx faults accepting client connections.\nwinnt_mpm: falling back to \'AcceptFilter none\'.\rThe MPM falls back to a safer implementation, but some client requests were not processed correctly. In order to avoid this error, use \"AcceptFilter\" with accept filter \"none\" in the \"\\xampp\\apache\\conf\\extra\\httpd-mpm.conf\" file.\rWhy are pictures and style-sheets not displayed?\rSometimes there are problems with displaying pictures and style-sheets. Especially if these files are located on a network drive. In this case you can enable (or add) one if the following lines in the file \"\\xampp\\apache\\conf\\httpd.conf\":\rEnableSendfile off\rEnableMMAP off\rThis problem can also be caused by programs for regulating bandwidth, like NetLimiter.\rHow do I send email with XAMPP?\rTo configure XAMPP to use the included sendmail.exe binary for email delivery, follow these steps:\rEdit the XAMPP \"php.ini\" file. Within this file, find the [mail function] section and replace it with the following directives. Change the XAMPP installation path if needed.\nsendmail_path = \"\\\"C:\\xampp\\sendmail\\sendmail.exe\\\" -t\"\nEdit the XAMPP \"sendmail.ini\" file. Within this file, find the [sendmail] section and replace it with the following directives:\nsmtp_server=smtp.gmail.com\nsmtp_port=465\nsmtp_ssl=auto\nerror_logfile=error.log\nauth_username=your-gmail-username@gmail.com\nauth_password=your-gmail-password\nRemember to replace the dummy values shown with your actual Gmail address and account password. If you don\'t plan to use Gmail\'s SMTP server, replace the SMTP host details with appropriate values for your organization or ISP\'s SMTP server.\rRestart the Apache server using the XAMPP control panel.\nYou can now use PHP\'s mail() function to send email from your application.\rHow can I set a root password in MySQL?\rConfigure it with the \"XAMPP Shell\" (command prompt). Open the shell from the XAMPP control pane and execute this command:\rmysqladmin.exe -u root password secret\rThis sets the root password to \'secret\'.\rCan I use my own MySQL server?\rYes. Simply don\'t start the MySQL from the XAMPP package. Please note that two servers cannot be started on the same port. If you have set a password for \"root\", please do not forget to edit the file \"\\xampp\\phpMyAdmin\\config.inc.php\".\rHow do I restrict access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rBefore you can access the MySQL server, phpMyAdmin will prompt you for a user name and password. Don\'t forget to set a password for the user \"root\" first.\rHow do I enable access to phpMyAdmin from the outside?\rIn the basic configuration of XAMPP, phpMyAdmin is accessible only from the same host that XAMPP is running on, at http://127.0.0.1 or http://localhost.\rIMPORTANT: Enabling external access for phpMyAdmin in production environments is a significant security risk. You are strongly advised to only allow access from localhost. A remote attacker could take advantage of any existing vulnerability for executing code or for modifying your data.\rTo enable remote access to phpMyAdmin, follow these steps:\rEdit the apache\\conf\\extra\\httpd-xampp.conf file in your XAMPP installation directory.\rWithin this file, find the lines below. \nAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire local\nThen replace \'Require local\' with \'Require all granted\'.\rAlias /phpmyadmin \"C:/xampp/phpMyAdmin/\"\n<Directory \"C:/xampp/phpMyAdmin\">\nAllowOverride AuthConfig\nRequire all granted\nRestart the Apache server using the XAMPP control panel.\rWhere is the IMAP support for PHP?\rAs default, the IMAP support for PHP is deactivated in XAMPP due to some mysterious initialization errors with some home versions like Windows 98. If you work with NT systems, you can open the file \"\\xampp\\php\\php.ini\" to activate the php exstension by removing the beginning semicolon at the line \";extension=php_imap.dll\". It should be:\rextension=php_imap.dll\rNow restart Apache and IMAP should work. You can use the same steps for every extension, which is not enabled in the default configuration.\rWhy don\'t some PHP open source apps work with XAMPP on Windows?\rA lot of PHP applications or extensions that have been written for Linux haven’t been ported to Windows. \rCan I delete the \"install\" directory after installation?\rIt\'s better not to. The scripts here are still needed for all additional packages (add-ons) and upgrades of XAMPP.\rHow do I activate the eaccelerator?\rLike other (Zend) extensions, you can activate it in \"php.ini\". In this file, enable the line \";zend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\". It should be:\rzend_extension = \"\\xampp\\php\\ext\\php_eaccelerator.dll\"\rHow do I fix a connection error to my MS SQL server?\rIf the mssql extension was loaded in the php.ini, sometimes problems appear when only TCP/IP is used. You can fix that problem with a newer \"ntwdblib.dll\" from Microsoft. Please replace the older file in \"\\xampp\\apache\\bin\" and \"\\xampp\\php\" with the new one. Because of the license, we can\'t package a newer version of this file with XAMPP.\rHow do I work with the PHP mcrypt extension?\rFor this, we have opened a topic in the forum with examples and possible solutions: \rMCrypt topic\rDo Microsoft Active Server Pages (ASP) work with XAMPP?\rNo. And Apache::ASP with the Perl Add-On is not the same. Apache::ASP only knows Perl-Script, but ASP from the Internet Information Server (IIS) also knows the normal VBScript. But for ASP .NET, there is a 3rd party Apache module available.\rHow can I get XAMPP working on port 80 under Windows 10?\rBy default, Windows 10 starts Microsoft IIS on port 80, which is the same default port used by Apache in XAMPP. As a result, Apache cannot bind to port 80.\rTo deactivate IIS from running on port 80, follow these steps:\rOpen the Services panel in Computer Management.\rSearch for the \'World Wide Web Publishing Service\' and select it.\rClick the link to \'Stop the service\'.\rDouble-click the service name.\rIn the \'Startup type\' field, change the startup type to \'Disabled\'.\rClick \'OK\' to save your changes.\rYou should now be able to start Apache in XAMPP on port 80.\rFor more information, refer to the \'Troubleshoot Apache Startup Problems\' guide included with XAMPP or \rthis forum post\r.\rHow can I use Microsoft Edge to access local addresses under Windows 10?\rIf your local machine has the host name \'myhost\', you will not be able to access URLs such as http://myhost in Microsoft Edge. To resolve this, you should instead use the addresses http://127.0.0.1 or http://localhost.\rWhere are the main XAMPP configuration files?\rThe main XAMPP configuration files are located as follows:\rApache configuration file: \\xampp\\apache\\conf\\httpd.conf, \\xampp\\apache\\conf\\extra\\httpd-xampp.conf\rPHP configuration file: \\xampp\\php\\php.ini\rMySQL configuration file: \\xampp\\mysql\\bin\\my.ini\rFileZilla Server configuration file: \\xampp\\FileZillaFTP\\FileZilla Server.xml\rApache Tomcat configuration file: \\xampp\\tomcat\\conf\\server.xml\rApache Tomcat configuration file: \\xampp\\sendmail\\sendmail.ini\rMercury Mail configuration file: \\xampp\\MercuryMail\\MERCURY.INI\rFollow us on Twitter\rLike us on Facebook\r版權所有(c) 2022, Apache Friends\r部落格\r隱私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(102,'2022-11-22 16:37:13','main','s1|/dashboard/zh_tw/howto.html',0,NULL,NULL,NULL,'/dashboard/zh_tw/howto.html','XAMPP howto guides','Apache Friends\rMenu\r常見問題\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rWindows \rHOW-TO Guides\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\r版權所有(c) 2022, Apache Friends\r部落格\r隱私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(103,'2022-11-22 16:37:14','main','s1|/dashboard/zh_tw/howto_platform_links.html',0,NULL,NULL,NULL,'/dashboard/zh_tw/howto_platform_links.html','Apache Friends','Apache Friends\rMenu\r常見問題\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rUse a Different PHP Version\rRun PHP under FastCGI\rConfigure and Use Apache Tomcat\rFollow us on Twitter\rLike us on Facebook\r版權所有(c) 2022, Apache Friends\r部落格\r隱私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(104,'2022-11-22 16:37:12','main','s1|/dashboard/zh_tw/howto_shared_links.html',0,NULL,NULL,NULL,'/dashboard/zh_tw/howto_shared_links.html','Apache Friends','Apache Friends\rMenu\r常見問題\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rBackup and Restore MySQL/MariaDB Databases\rConfigure FTP Access\rConfigure Virtual Hosts\rConfigure Wildcard-Based Subdomains\rDeploy an Application Using Git\rReset the MySQL/MariaDB Root Password\rSend Mail with PHP\rUse SQLite with PHP\rActivate and Use Xdebug\rStart a New Zend Framework 1.x Project\rStart a New Zend Framework 2.x Project\rTroubleshoot Apache Startup Problems\rChange the MySQL Temporary Files Directory\rIncrease the PHP File Upload Limit\rEnable Remote Access to phpMyAdmin\rAuto-Start XAMPP\rFollow us on Twitter\rLike us on Facebook\r版權所有(c) 2022, Apache Friends\r部落格\r隱私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(105,'2023-11-19 12:10:26','main','s1|/dashboard/zh_tw/index.html',0,NULL,NULL,NULL,'/dashboard/zh_tw/index.html','Welcome to XAMPP','Apache Friends\rMenu\r常見問題\rHOW-TO Guides\rPHPInfo\rphpMyAdmin\rXAMPP \rApache + MariaDB + PHP + Perl\rWelcome to XAMPP for Windows 8.2.12\rYou have successfully installed XAMPP on this system! Now you can start using Apache, MariaDB, PHP and other components.\nYou can find more info in the \r常見問題\rsection or check the \rHOW-TO Guides\rfor getting started with PHP applications.\nXAMPP is meant only for development purposes. It has certain configuration settings that make it easy to develop locally but that are insecure if you want to have your installation accessible to others.\nStart the XAMPP Control Panel to check the server status.\n社區\rXAMPP has been around for more than 10 years &ndash; there is a huge community behind it. You can get involved by joining our \r論壇\r, liking us on \rFacebook\r, or following our exploits on \rTwitter\r.\nFollow us on Twitter\rLike us on Facebook\r版權所有(c) 2022, Apache Friends\r部落格\r隱私政策\rCDN提供','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(106,'2026-04-05 15:46:41','main','s1|/news/index.php',0,NULL,NULL,NULL,'/news/index.php','Новости компании','','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(107,'2026-04-05 15:46:41','main','s1|/search/index.php',0,NULL,NULL,NULL,'/search/index.php','Поиск','','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(108,'2026-04-05 15:46:41','main','s1|/search/map.php',0,NULL,NULL,NULL,'/search/map.php','Карта сайта','','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(109,'2026-04-05 15:46:41','main','s1|/services/corp/ibank.php',0,NULL,NULL,NULL,'/services/corp/ibank.php','Интернет-банкинг','\"Интернет-Банк\" — это полнофункциональная, удобная и безопасная система дистанционного банковского обслуживания, с ее помощью вы можете в полном объеме управлять банковскими счетами в режиме реального времени. Понятный для клиента интерфейс позволяет не тратить время на обучение работе с Системой. Система снабжена внутренними подсказками.\r\"Интернет-Банк\" позволяет:\rчерез сайт Банка в Интернете получить доступ к Вашим банковским счетам практически с любого компьютера в любой точке земного шара, где есть доступ в Интернет \rвводить, редактировать и печатать платежные документы \rподписывать каждый платежный документ персонифицированной электронной-цифровой подписью \rнаправлять документы в Банк на исполнение \r«визировать» направляемые в Банк платежные документы уполномоченным лицом \rполучать выписки со всеми приложениями по счетам за определенный период времени \rосуществлять покупку/продажу иностранной валюты, конвертацию валют в режиме on-line по текущему рыночному курсу \rрезервировать на счете временно свободные денежные средства и получать дополнительный доход в виде начисленных процентов \rотслеживать текущее состояние счетов\rполучать актуальную информацию о платежах контрагентов из других банков, которые зачисляются на счет Клиента в момент поступления в Банк \rнаправлять в Банк бухгалтерскую отчетность в электронном виде \rконтролировать состояние ссудных счетов, погашение и уплату процентов \rПодключение к Системе, в том числе генерация ключей для формирования электронно-цифровой подписи, бесплатно. Абонентская плата за обслуживание не взимается.\rТехнические требования\rДля полноценной работы с Системой необходим компьютер с ОС Windows ,не ниже Windows 2000; Программа просмотра Интернет-страниц Internet Explorer версии не ниже 6.0; Приложение Java Runtime Environment (JRE) Version 1.5.0','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(110,'2026-04-05 15:46:41','main','s1|/services/corp/incass.php',0,NULL,NULL,NULL,'/services/corp/incass.php','Инкассация','Инкассация\r– доставка ценностей и денежных средств.\rБанк предлагает воспользоваться услугами службы инкассации. Служба инкассации Банка обеспечит:\rинкассацию наличных денежных средств, доставку их на специально оборудованном транспорте в Банк, по согласованному с Клиентом, графику работы;\rсопровождение ценностей и денежных средств Клиента по маршруту, указанному Клиентом; \rдоставку наличных денежных средств Клиенту; \rдоставку Клиенту разменной монеты.\rУслуги предоставляются как собственной службой инкассации, так и через другие специализированные организации.\rНеобходимая документация:\rДоговор на сбор (инкассацию) денежной выручки и доставку разменной монеты;\rЗаявка на инкассацию;\rПредварительная заявка на оказание услуг по доставке денежной наличности;\rДоговор на оказание услуг по доставке наличных денежных средств.\rОбъем инкассируемых денежных средств\rТарифы по ставке процента от объема инкассации\rТарифы от количества выездов\rТарифы с фиксированной стоимостью\rдо 0,5 млн. руб.\r0,45%\rот 120 руб/заезд\rНе менее 2500 руб. в месяц\rот 0,5 до 1,0 млн. руб.\r0,4 - 0,35%\rот 140 руб/заезд\rНе менее 3500 руб. в месяц\rот 1,0 до 1,5 млн. руб.\r0,35 -0,3%\rот 160 руб/заезд\rНе менее 4500 руб. в месяц\rот 1,5 до 2,0 млн. руб.\r0,3 -0,25%\rот 180 руб/заезд\rНе менее 5000 руб. в месяц\rот 2,0 млн до 3,0 млн. руб.\r0,25 - 0,2 %\rот 200 руб/заезд\rНе менее 6000 руб. в месяц\rот 4,0 млн. до 6 млн. руб.\r0,2 -0,15%\rот 220 руб/заезд\rНе менее 7000 руб. в месяц\rот 6,0 млн. до 10 млн. руб.\r0,15 -0,1 %\rот 240 руб/заезд\rНе менее 8000 руб. в месяц\rсвыше 10 млн. руб.\r0,1 - 0,05%\rот 260 руб/заезд\rНе менее 9000 руб. в месяц\rДругие условия\rИнкассация 5-10 торговых точек клиента\rплюс 5 % от тарифной ставки за каждую последующую точку\rИнкассация свыше 10 торговых точек клиента\rплюс 10 % от тарифной ставки за каждую последующую точку\rВремя инкассации устанавливает клиент\rплюс 10 % от тарифной ставки\rНочная инкассация (с 22:00)\rплюс 20% от тарифной ставки\rУтренняя инкассация для зачисления в 1ой половине дня\rбесплатно\rЕсли сдают на одном объекте несколько юридических лиц\rбесплатно\rДоставка разменной монеты\r0,4 % от суммы доставки\rРасходный материал\rбесплатно\rХранение денежных средств в ночное время, праздничные и выходные\rбесплатно\rЗагрузка банкоматов, подкрепление дополнительных офисов\rот 350 руб/час\rДоставка денежных средств из банка Клиенту\r0,5 % от суммы, либо по соглашению сторон','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(111,'2026-04-05 15:46:41','main','s1|/services/corp/index.php',0,NULL,NULL,NULL,'/services/corp/index.php','Корпоративным клиентам','Банк является одним из лидеров банковского рынка по обслуживанию корпоративных клиентов. \rКомплексное банковское обслуживание на основе максимального использования конкурентных преимуществ и возможностей Банка позволяет создать устойчивую \rфинансовую платформу для развития бизнеса предприятий и холдингов различных отраслей экономики. Уже более 15 лет Банк работает для своих клиентов, \rявляясь образцом надежности и высокого профессионализма.\rНаш Банк предлагает корпоративным клиентам следующие виды услуг:\rРасчетно-кассовое обслуживание\rИнкассация\rИнтернет-банкинг','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(112,'2026-04-05 15:46:41','main','s1|/services/corp/rko.php',0,NULL,NULL,NULL,'/services/corp/rko.php','Расчетно-кассовое обслуживание','Во всех странах мира самой распространенной функцией банков являются расчеты. Большинство оказываемых банком услуг связаны с быстрым и качественным проведением расчетных операций. Каждый клиент, независимо от вида осуществляемых в Банке операций, пользуется переводом средств.\rКорпоративным клиентам Банк оказывает следующие услуги:\rоткрытие и ведение счетов юридических лиц - резидентов и нерезидентов Российской Федерации — в валюте РФ и иностранной валюте; \rвсе виды расчетов в рублях и иностранной валюте; \rкассовое обслуживание в рублях и иностранной валюте; \rускоренные платежи по России по системе межрегиональных электронных платежей; \rплатежи в любую страну мира в кратчайшие сроки \rпроведение конверсионных операций по счетам Клиентов \rинкассация и доставка наличных денег и ценностей \rраспоряжение счетом посредством системы «Интернет-Банк» \rОперационный день в Банке установлен: ежедневно с 09.00 до 16.00, в пятницу и предпраздничные дни с 09.00 до 15.00.\rКассовое обслуживание осуществляется на договорной основе, плата взимается по факту совершения каждой операции в соответствии с утвержденными Банком Тарифами за услуги корпоративным клиентам.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(113,'2026-04-05 15:46:41','main','s1|/services/financialorg/depservices.php',0,NULL,NULL,NULL,'/services/financialorg/depservices.php','Депозитарные услуги','Депозитарий Банка имеет корреспондентские отношения со всеми крупными расчетными и уполномоченными депозитариями. Разветвленная сеть корреспондентских счетов позволяет клиентам депозитария осуществлять операции практически с любыми инструментами фондового рынка.\rУслуги депозитария Банка:\rоткрытие и ведение счетов депо клиентов;\rхранение и учет всех видов ценных бумаг, включая акции, облигации, паи, векселя, международных финансовых инструментов (еврооблигации, АДР, ГДР);\rконсультирование и проведение комплексных структурированных операций с ценными бумагами;\rперерегистрация прав собственности на ценные бумаги, в том числе при выполнении определенного условия;\rоформление и учет залоговых операций с ценными бумагами депонентов;\rпредоставление информации об эмитенте;\rпомощь депонентам в реализации прав, закрепленных за ними как за владельцами ценных бумаг;\rконсультационная поддержка при проведении операций по счетам депо;\rвыполнение функций платежного агента:\rхранение ценных бумаг на основании договоров ответственного хранения;\rпроведение экспертизы ценных бумаг;\rдругие услуги.\rСпособы обмена документов с Депозитарием:\rв бумажном виде с оригинальными подписями и печатями;\rпо факсу (поручения на зачисление ценных бумаг и предоставление выписок) с последующим предоставлением оригинала;\rпо системам S.W.I.F.T. и TELEX.\rТарифы на депозитарное обслуживание\rНаименование услуги\rТариф\rОткрытие счета депо для физических лиц (резидентов и нерезидентов)\n150 руб.\nОткрытие счета депо для юридических лиц – резидентов\n400 руб.\nОткрытие счета депо для юридических лиц – нерезидентов\n1600 руб.\nЗакрытие счета депо\nНе взимается\nВнесение изменения в Анкету Депонента\nНе взимается\nАбонентская плата в месяц за ведение счета депо для юридических лиц - резидентов,\nпри наличии остатка на счете депо\n500 руб.\nАбонентская плата в месяц за ведение счета депо для юридических лиц - нерезидентов,\nпри наличии остатка на счете депо\n2 500 руб.\nАбонентская плата в месяц за ведение счета депо для Депонентов, находящихся на брокерском\nобслуживании, при наличии движения по счету депо\n150 руб.\nФормирование отчета о совершенных по счету депо операциях за период после проведения\nоперации\nНе взимается\nФормирование отчета о совершенных по счету депо операциях за период, выписки о состоянии\nсчета (раздела счета) депо по информационному запросу Депонента\n150 руб.\nЗачисление (списание) бездокументарных ценных бумаг, за одно поручение\n300 руб.\nЗачисление (списание) документарных ценных бумаг, за одну ценную бумагу\n580 руб.\nПеревод (внутри Депозитария) бездокументарных и документарных ценных бумаг, за одно\nпоручение (взимается с Депонента - Инициатора операции)\n300 руб.\nИзменение мест хранения бездокументарных ценных бумаг (за одно поручение) и документарных\nценных бумаг (за одну ценную бумагу)\n580 руб.\nБлокировка (разблокировка), регистрация залога (возврата залога) бездокументарных\nценных бумаг\n870 руб.\nБлокировка (разблокировка), регистрация заклада (возврата заклада) документарных\nценных бумаг\n870 руб.\n*При взимании тарифов дополнительно взимается налог на добавленную стоимость по ставке 18%.\rПлата за иные услуги, не оговоренные в данных Тарифах Депозитария, за исключением услуг, оказываемых при проведении операций Депонента другими депозитариями и Реестродержателями, не взимается.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(114,'2026-04-05 15:46:41','main','s1|/services/financialorg/docoper.php',0,NULL,NULL,NULL,'/services/financialorg/docoper.php','Документарные операции','Наш Банк предлагает широкий спектр банковских услуг по проведению документарных расчетов в области международных торгово-экономических отношений ,в том числе по нестандартным и сложно структурированным схемам.\rБезусловным преимуществом работы с нашим Банком является возможность проводить операции в предельно сжатые сроки по конкурентоспособным тарифам, а также их обширная география: страны СНГ и Балтии, ближнего и дальнего зарубежья.\rСпектр услуг по банковским гарантиям: \rвыдача любых видов гарантий под контргарантии банков-корреспондентов в счет установленных на них документарных лимитов: 									 \nгарантии надлежащего исполнения контрактов;\rгарантии платежа (т.е. выполнения платежных обязательств по контрактам);\rгарантии возврата авансового платежа;\rгарантии в пользу таможенных органов;\rгарантии в пользу налоговых органов;\rтендерные гарантии (т.е. гарантии участия в торгах/конкурсах);\rгарантии возврата кредита;\rгарантии оплаты акций;\rгарантии, предоставляемые в качестве встречного обеспечения судебных исков;\rавизование гарантий иностранных и российских банков-корреспондентов в пользу отечественных и зарубежных бенефициаров;\rпредъявление требования платежа по поручению бенефициаров в счет банковских гарантий;\rзаверка подлинности подписей на гарантиях иностранных и российских банков по просьбе бенефициара;\rв случае необходимости иные виды операций, включая предварительную проработку условий гарантийной сделки.\rПредоставляемые услуги по документарным (в том числе резервным) аккредитивам:\rавизование аккредитивов иностранных и российских банков-корреспондентов в пользу отечественных и зарубежных бенефициаров;\rподтверждение аккредитивов банков-корреспондентов под предоставленное денежное покрытие или в счет документарных лимитов, установленных на банк-эмитент;\rподтверждение экспортных аккредитивов Котнрагента;\rисполнение аккредитивов;\rвыполнение функции рамбурсирующего банка на основании предоставленных полномочий по аккредитивам иностранных и российских банков-корреспондентов (при наличии у банка-эмитента корреспондентского счета ЛОРО в Газпромбанке);\rвыдача безотзывных рамбурсных обязательств по аккредитивам, открытым банками-корреспондентами, в счет документарных лимитов, установленных на банк-эмитент (при наличии у банка-эмитента корреспондентского счета ЛОРО в Газпромбанке);\rоформление трансферации и переуступки выручки по аккредитивам;\rоткрытие аккредитивов/предоставление платежных гарантий в рамках операций торгового финансирования;\rиные виды операций, включая предварительную проработку схемы расчетов и условий аккредитивной сделки.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(115,'2026-04-05 15:46:41','main','s1|/services/financialorg/index.php',0,NULL,NULL,NULL,'/services/financialorg/index.php','Финансовым организациям','Активное сотрудничество на финансовых рынках представляет собой одну из наиболее важных сторон бизнеса и является перспективным направлением деятельности нашего Банка. Политика банка направлена на расширение сотрудничества, увеличение объемов взаимных кредитных линий. Солидная деловая репутация Банка на рынке межбанковских операций способствует налаживанию стабильных и взаимовыгодных партнерских отношений с самыми крупными и надежными банками страны.\rОсобое внимание Банк уделяет развитию взаимоотношений с международными финансовыми институтами. Финансирование долгосрочных и среднесрочных проектов клиентов за счет привлечения средств на международных рынках капитала - одно из приоритетных направлений деятельности Банка. Наш Банк имеет развитую сеть корреспондентских счетов, что позволяет быстро и качественно осуществлять расчеты в различных валютах. Поручения клиентов могут быть исполнены Банком в сжатые сроки.\rВ целях минимизации рисков при поведении операций на финансовых рынках наш Банк максимально требовательно подходит к выбору своих банков-контрагентов. \rВ данном направлении Банк предлагает финансовым организациям следующие услуги:\rУслуги на межбанковском рынке\rДепозитарные услуги\rДокументарные операции','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(116,'2026-04-05 15:46:41','main','s1|/services/financialorg/mbank.php',0,NULL,NULL,NULL,'/services/financialorg/mbank.php','Услуги на межбанковском рынке','Межбанковское кредитование\rВид услуги\nОписание\nКредитование под валютный депозит\nКредиты выдаются в рублях на срок от 1 дня до 1 месяца с возможностью дальнейшей\nпролонгации. Тарифные ставки зависят от конкретных условий сделки.\nКредитование под залог ОВГВЗ\nКредиты выдаются в рублях и валюте на срок до 1 месяца с возможной пролонгацией.\nСтавка дисконта составляет 25—30%.\nКредитование под залог государственных ценных бумаг\nВ залог принимаются облигации федерального займа (ОФЗ) любого выпуска. Ставка дисконта:\nОФЗ с датой погашения до 91 дня — 5%;\rОФЗ с датой погашения до 365 дней — 8%;\rОФЗ с датой погашения свыше 365 дней — 13%.\rКредиты выдаются на срок до2 недель.\nКредитование под залог векселей\nДля консультаций по этому виду кредитования обратитесь в Управление вексельного\nобращения и работы с долговыми обязательствами по телефону (495) 978-78-78.\nКонверсионные операции\rНа внутреннем денежном рынке Банк осуществляет:\rБрокерское обслуживание банков по их участию в торгах ЕТС на ММВБ. Ставки комиссионного вознаграждения варьируются в зависимости от объема операций (в пределах 0,147—0,18%).\rКонверсионные операции. Банк предлагает банкам-контрагентам работу на валютном рынке по покупке и продаже иностранной валюты за российские рубли по текущим рыночным ценам. При отсутствии открытых линий при продаже иностранной валюты банк-контрагент производит предоплату по заключенной сделке, возможна работа под кредитовое авизо.\rБанкнотные операции\rпокупка и продажа наличной валюты за безналичную валюту;\rпродажа новых банкнот в упаковке американского банка-эмитента;\rпокупка и продажа банкнот, бывших в употреблении.\rУровень комиссионных зависит от объемов и конкретных условий сделки.\rДокументарные операции\rМеждународные расчеты:\nАккредитив\r- это условное денежное обязательство, принимаемое банком (банком-эмитентом) по поручению плательщика, произвести платежи в пользу получателя средств по предъявлении последним документов, соответствующих условиям аккредитива, или предоставить полномочия другому банку (исполняющему банку) произвести такие платежи.\rИнкассо\r- это расчетная операция, посредством которой банк на основании расчетных документов по поручению клиента получает причитающиеся клиенту денежные средства от плательщика за поступившие в адрес плательщика товары или оказанные ему услуги, после чего эти средства зачисляются на счет клиента в банке.\rОперации с векселями банка\rВексели нашего банка являются простыми векселями.\rПростой вексель — документ установленной законом формы, дающий его держателю (векселедержателю) безусловное право требовать с лица, указанного в данном документе (плательщика), уплаты оговоренной суммы по наступлению некоторого срока. Обязательство по простому векселю возникает с момента его составления и передачи первому векселедержателю.\rПеречень проводимых банком операций с собственными векселями:\nвыпуск векселей;\rпогашение векселей;\rдосрочный учет векселей;\rответственное хранение векселей;\rкредитование под залог векселей;\rвыдача кредитов на приобретение векселей;\rновация и размен векселей;\rпроверка подлинности векселей.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(117,'2026-04-05 15:46:41','main','s1|/services/fiz/cards.php',0,NULL,NULL,NULL,'/services/fiz/cards.php','Банковские карты','Кредитные Карты\rСрок действия Карты\r3 года\rКомиссия за ежегодное осуществление расчетов по операциям с Основной Картой.\r600 руб. / 25 долл. США / 25 евро\rЛьготный период оплаты\rдо 50 календарных дней\rЕжемесячный минимальный платеж \r(в процентах от суммы задолженности по Овердрафтам):\r10% \rДополнительные проценты/штрафы/комиссии/ на сумму неразрешенного Овердрафта\rне взимается (отменена с 1 марта) \rКомиссия за учет Отчетной суммы задолженности, непогашенной на последний календарный день Льготного периода оплаты.\rдля 1-6-го месяцев\rдля 6-го и последующих месяцев\r12% / 15% \r21% / 24% \rв пунктах выдачи наличных или банкоматах \"Банка\" \rв банкоматах банков-партнеров \"Объединенной расчетной системы (ОРС)\" \rв пунктах выдачи наличных или банкоматах иного банка \r0%\r0,5%\r2,5%\rМинимальная сумма комиссии по операциям получения наличных денежных средств в пунктах выдачи наличных или банкоматах иного банка. \r150 рублей\rКомиссия за осуществление конвертации по трансграничным операциям (совершенным за пределами территории РФ). \r0,75% \rРасчетные карты Банка\rВалюта Картсчета\rроссийские рубли / доллары США / евро\rСрок действия карты\r3 года\rКомиссия за осуществление расчетов в течение одного года по операциям с Основной Картой при ее первичном выпуске.\rВзимается перед началом каждого года расчетов по действующей Карте из средств на Картсчете.\r500 рублей/20 долл. США/20 евро\rКомиссия за операцию получения наличных денежных средств:\rдо 300 000 рублей (включительно)\rв пунктах выдачи наличных или банкоматах «Банка»\rв банкоматах банков-партнеров\rв пунктах выдачи наличных или банкоматах иного банка\r0%\r0,5%\r1,5% мин. 90 руб.\rот 300 001 до 10 000 000 рублей (включительно)\r2,5% \rот 10 000 001 рубля и выше\r5%\rМинимальная сумма комиссии по операциям получения наличных денежных средств в пунктах выдачи наличных или банкоматах иного банка. \r90 рублей\rКомиссия за перечисление и конверсию денежных средств в Интернет-банке. \r0%\rКомиссия за остановку операций по Картсчету, совершаемых с использованием Карты, при ее утрате. \r600 рублей/25 долл. США/25 евро\rКомиссия за осуществление конверсии по трансграничным операциям (совершенным за пределами территории РФ).\r0,75%\rВыдача Карточки доступа.\rБесплатно\rКомиссия за оплату услуг в Интернет - банке и в банкоматах Банка. \rБесплатно\rКомиссия за учет перерасхода средств (в процентах годовых от суммы перерасхода). \r36%\rКомиссия за отправку SMS сообщений о суммах проведенных по Карте операций и доступном балансе в течение ее срока действия.\rБесплатно','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(118,'2026-04-05 15:46:41','main','s1|/services/fiz/credit.php',0,NULL,NULL,NULL,'/services/fiz/credit.php','Потребительский кредит','Не важно, для чего вам нужны деньги — мы доверяем вам и не тратим время на лишние процедуры.\rТарифы кредитования физических лиц\rВ рублях\rСумма кредита: от 150 000 до 1 500 000 рублей\rСрок кредита: от 6 до 36 месяцев\r% ставка: от 18 до 21,5% годовых\rЕдиновременная комиссия за выдачу кредита: 2% от суммы кредита\rВ долларах США\rСумма кредита: от 5 000 до 50 000 долларов США\rСрок кредита: от 6 до 24 месяцев\r% ставка: от 14,5 до 16,5% годовых\rЕдиновременная комиссия за выдачу кредита: 2% от суммы кредита\rУсловия кредитного договора и применяемый тарифный план и/или тарифы определяются в индивидуальном порядке, в том числе в зависимости от подтвержденного дохода клиента. Изложенная информация не является публичной офертой и не влечет возникновения у ЗАО «Банк Интеза» обязанности предоставить кредит, как на указанных, так и на любых иных условиях.\rМинимальные требования к заемщику\rВы гражданин России.\rВам сейчас больше 23 лет и вам будет меньше 60 (для мужчин) или меньше 55 (для женщин) на момент погашения (то есть полной оплаты) кредита.\rУ вас есть официальное место работы, и вы работаете на нем по найму не менее шести месяцев и прошли испытательный срок.\rВаш общий трудовой стаж составляет не менее двух лет\rВы можете подтвердить свой доход официально при помощи стандартной формы 2НДФЛ или справкой по форме банка.\rВы обратились в отделение банка в том же городе, в котором вы работаете.\rС вами можно связаться по городскому телефону по месту работы.\rТелефон горячей линии: \r8 800 2002 808\r( Звонок по России бесплатный)','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(119,'2026-04-05 15:46:41','main','s1|/services/fiz/index.php',0,NULL,NULL,NULL,'/services/fiz/index.php','Частным лицам','Наш Банк предоставляет физическим лицам большое число различных возможностей, связанных с сохранением средств и совершением различных сделок. В частности, банк предлагает своим клиентам широкую линейку разнообразных вкладов, способных удовлетворить как долгосрочные, так и краткосрочные интересы, касающиеся размещения свободных средств по выгодным ставкам. В своей работе Банк активно применяет инновационные технологии динамично развивающейся банковской сферы.\rБанк предлагает своим клиентам качественный универсальный сервис по следующим направлениям:\rБанковские карты\rПотребительский кредит','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(120,'2026-04-05 15:46:41','main','s1|/services/index.php',0,NULL,NULL,NULL,'/services/index.php','Услуги','Наш Банк предоставляет физическим лицам большое число различных возможностей, связанных с сохранением средств и совершением различных сделок. В частности, банк предлагает своим клиентам широкую линейку разнообразных вкладов, способных удовлетворить как долгосрочные, так и краткосрочные интересы, касающиеся размещения свободных средств по выгодным ставкам. В своей работе Банк активно применяет инновационные технологии динамично развивающейся банковской сферы.\rБанк предлагает своим клиентам качественный универсальный сервис по следующим направлениям:\rБанковские карты\rПотребительский кредит\rМалому и среднему бизнесу\rРабота с предприятиями малого и среднего бизнеса - одно из стратегически важных направлений деятельности Банка. Наш Банк представляет современные программы обслуживания малого и среднего бизнеса, обеспечивает оптимальные и взаимовыгодные варианты сотрудничества, в основе которых лежит профессионализм сотрудников и высокое качество банковских услуг. Услуги нашего Банка отличаются оперативностью и надежностью, так как ориентированы на деловых людей - на тех, кто ценит свое время и деньги.\rБанк предлагает следующие виды услуг для предприятий малого и среднего бизнеса:\rКредитование\rЛизинг\rДепозиты\rПластиковые карты\rКорпоративным клиентам\rБанк является одним из лидеров банковского рынка по обслуживанию корпоративных клиентов. \rКомплексное банковское обслуживание на основе максимального использования конкурентных преимуществ и возможностей Банка позволяет создать устойчивую \rфинансовую платформу для развития бизнеса предприятий и холдингов различных отраслей экономики. Уже более 15 лет Банк работает для своих клиентов, \rявляясь образцом надежности и высокого профессионализма.\rНаш Банк предлагает корпоративным клиентам следующие виды услуг:\rРасчетно-кассовое обслуживание\rИнкассация\rИнтернет-банкинг\rФинансовым организациям\rАктивное сотрудничество на финансовых рынках представляет собой одну из наиболее важных сторон бизнеса и является перспективным направлением деятельности нашего Банка. Политика банка направлена на расширение сотрудничества, увеличение объемов взаимных кредитных линий. Солидная деловая репутация Банка на рынке межбанковских операций способствует налаживанию стабильных и взаимовыгодных партнерских отношений с самыми крупными и надежными банками страны.\rОсобое внимание Банк уделяет развитию взаимоотношений с международными финансовыми институтами. Финансирование долгосрочных и среднесрочных проектов клиентов за счет привлечения средств на международных рынках капитала - одно из приоритетных направлений деятельности Банка. Наш Банк имеет развитую сеть корреспондентских счетов, что позволяет быстро и качественно осуществлять расчеты в различных валютах. Поручения клиентов могут быть исполнены Банком в сжатые сроки.\rВ целях минимизации рисков при поведении операций на финансовых рынках наш Банк максимально требовательно подходит к выбору своих банков-контрагентов. \rВ данном направлении Банк предлагает финансовым организациям следующие услуги:\rУслуги на межбанковском рынке\rДепозитарные услуги\rДокументарные операции','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(121,'2026-04-05 15:46:41','main','s1|/services/smallbusiness/cards.php',0,NULL,NULL,NULL,'/services/smallbusiness/cards.php','Пластиковые карты','Наш Банк проводит операции с пластиковыми картами с 1997 г. Сегодня мы предлагаем пластиковые карты основных международных платёжных систем – Visa и MasterCard; от самых демократичных Еlеctron до элитных Gold и Platinum. В рамках персонального обслуживания В рамках персонального банковского обслуживания Банк дополнительно предлагает эксклюзивные карты Visa Infinite с бриллиантами и платиновым орнаментом.\rЗаказать международную пластиковую карту можно в любом отделении нашего Банка. Ваша карта будет готова уже через 3-5 дней. Наш Банк один из немногих в России, кто выдает карту сроком на два года, как и крупнейшие зарубежные банки.Каждый Пакет услуг Банка включает одну основную и до трех дополнительных пластиковых карт для вас и для членов вашей семьи (включая детей старше 14 лет). Вы сами устанавливаете ограничения: кто и сколько может потратить по карте.\rТеряя пластиковую карту, вы не теряете деньги. Потому что карты нашего Банка надежно защищены от незаконного использования. Просто соблюдайте правила безопасности при обращении со своей картой, а в случае ее пропажи или хищения без промедления обратитесь в Банк.\rПреимущества пластиковых карт Банка\rполучение наличных без комиссии в широкой сети банкоматов;\rсведения об остатке и совершённых операциях по карте приходят по SMS;\rсистема интернет-банкинга позволяет владельцу карты контролировать расходы и управлять средствами на карточных счетах.\rвсем владельцам карт Банка доступны cкидки и бонусные программы.\rВиды пластиковых карт\rДебетовые карты:\rудобство безналичной оплаты товаров и услуг\rбезопасное хранение собственных средств\rначисление процентов на остаток по карте\rконтроль над расходами и управление своими деньгами\rКредитные карты:\rкредитование без процентов до 55 дней\rпользоваться кредитом можно многократно, не обращаясь в Банк\rбезналичная оплата товаров и услуг без комиссий в любой точке мира\rпровоз денег через границу без таможенного оформления\rне нужно покупать валюту для выезда в другие страны\rвсе полезные функции дебетовых карт','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(122,'2026-04-05 15:46:41','main','s1|/services/smallbusiness/credit.php',0,NULL,NULL,NULL,'/services/smallbusiness/credit.php','Кредитование','Кредитование малого и среднего бизнеса является одним из стратегических направлений Банка.\rДанное направление включает в себя:\nкредитование юридических лиц\rкредитование индивидуальных предпринимателей\rВ зависимости от пожеланий клиента кредиты для бизнеса предоставляются в разных валютах: в рублях РФ, долларах США и евро. \nПреимущества получения кредита в нашем Банке:\rСрок рассмотрения кредитной заявки от 2-х рабочих дней; \rОтсутствие ежемесячной платы за ведение ссудного счета;\rОтсутствие требований по предоставлению бизнес-плана;\rПринимается к рассмотрению управленческая отчетность;\rВ качестве залога рассматриваются товары в обороте, автотранспорт, оборудование, недвижимость и другое ликвидное имущество; \rГибкие условия погашения кредита. \rДля получения кредита:\rПозвоните нам по телефону +7 (495) 757-57-57, обратитесь в ближайшее к Вам отделение Банка или заполните on-line заявку. \rНаши специалисты помогут Вам выбрать удобные условия кредитования и ответят на интересующие Вас вопросы.\rПодготовьте необходимые для рассмотрения кредитной заявки документы и договоритесь о встрече с кредитным экспертом Банка.\rПокажите кредитному эксперту Ваше предприятие и имущество, предлагаемое в залог.\rПолучите кредит на развитие Вашего бизнеса! \nПрограммы кредитования малого и среднего бизнеса:\rПрограмма\nСумма кредита\nПроцентная ставка\nСрок кредита\n«Овердрафт»\rот 300 000\nдо 5 000 000 рублей\nот 18% годовых\nдо 12 месяцев\n«Миникредит»\rот 150 000\nдо 1 000 000 рублей\nот 24% годовых\nдо 36 месяцев\n«Развитие»\nот 1 000 000\nдо 15 000 000 рублей\nот 17% годовых\nдо 36 месяцев\n«Инвест»\nот 1 000 000\nдо 30 000 000 рублей\nот 15% годовых\nдо 72 месяцев','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(123,'2026-04-05 15:46:41','main','s1|/services/smallbusiness/deposits.php',0,NULL,NULL,NULL,'/services/smallbusiness/deposits.php','Депозиты','Наш Банк предлагает вам эффективно разместить свободные деньги на банковском депозите и получить дополнительную прибыль.\rДепозитные продукты\r \rДосрочное расторжение\rПополнение\rЧастичное изъятие\rВыплата процентов\rДепозит с выплатой процентов в конце срока\rНе предусмотрено.\rНе предусмотрено.\rНе предусмотрено.\rВ конце срока.\rДепозит с выплатой процентов ежемесячно\rНе предусмотрено.\rНе предусмотрено.\rНе предусмотрено.\rЕжемесячно.\rДепозит с возможностью пополнения\rНе предусмотрено.\rПрекращается за 2 месяца до окончания срока действия депозита. \rНе предусмотрено \rВ конце срока. \rДепозит с возможностью пополнения и изъятия\rНе предусмотрено.\rПрекращается за 2 месяца до окончания срока действия депозита.\rНе более 40% от первоначальной суммы вклада за весь срок депозита \rВ конце срока. \rДепозит с возможностью досрочного расторжения \rВозможно при размещении на 12 месяцев, но не ранее чем через 6 месяцев.\rНе предусмотрено.\rНе предусмотрено. \rВ конце срока.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(124,'2026-04-05 15:46:41','main','s1|/services/smallbusiness/index.php',0,NULL,NULL,NULL,'/services/smallbusiness/index.php','Малому и среднему бизнесу','Работа с предприятиями малого и среднего бизнеса - одно из стратегически важных направлений деятельности Банка. Наш Банк представляет современные программы обслуживания малого и среднего бизнеса, обеспечивает оптимальные и взаимовыгодные варианты сотрудничества, в основе которых лежит профессионализм сотрудников и высокое качество банковских услуг. Услуги нашего Банка отличаются оперативностью и надежностью, так как ориентированы на деловых людей - на тех, кто ценит свое время и деньги.\rБанк предлагает следующие виды услуг для предприятий малого и среднего бизнеса:\rКредитование\rЛизинг\rДепозиты\rПластиковые карты','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(125,'2026-04-05 15:46:41','main','s1|/services/smallbusiness/leazing.php',0,NULL,NULL,NULL,'/services/smallbusiness/leazing.php','Лизинг','Наш Банк оказывает весь спектр услуг по финансовой аренде (лизингу) отечественного и импортного оборудования, транспорта и недвижимости.\rЛизинг оборудования и транспорта\rОсновные условия:\rСрок финансирования:\nоборудование и транспорт - до 5 лет\rж/д подвижной состав - до 10 лет\rВалюта финансирования: рубли, доллары США, евро\rМинимальная сумма финансирования: от 4,5 млн.руб.\rАванс: от 0%\rУдорожание: от 9%\rСрок принятия решения: от 14 дней\rФинансирование импортных поставок\rМы предоставляем предприятиям доступ к льготному финансированию импортных поставок оборудования и транспорта с использованием механизма лизинга при участии экспортных кредитных агентств.\rОсновные условия:\rСрок финансирования: до 7 лет\rВалюта финансирования: рубли, доллары США, евро\rМинимальная сумма финансирования: от 15 млн.руб. \rАванс: от 15% (без учета таможенных пошлин) \rУдорожание: от 5%\rСрок принятия решения: от 14 дней\rЛизинг коммерческой недвижимости\rПозволяет предприятиям приобрести объекты коммерческой недвижимости без единовременного отвлечения значительных средств.\rВ качестве предмета лизинга могут выступать:\rофисные здания;\rторговые, складские и производственные помещения;\rдругие объекты коммерческой недвижимости.\rОсновные условия:\rСрок финансирования: от 5 лет\rВалюта финансирования: рубли, доллары США, евро\rМинимальная сумма финансирования: от 50 млн.руб.* \rАванс: от 0%\rУдорожание: от 7%\rСрок принятия решения: от 14 дней\r* Размер суммы финансирования зависит от региона, в котором находится объект недвижимости.\rОсновным требованием, предъявляемым нашим Банком для рассмотрения заявки на лизинг коммерческой недвижимости, является наличие полного комплекта правоустанавливающих документов на недвижимость и наличие отчета независимого оценщика.','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(126,'2026-04-05 15:46:41','main','s1|/_index.php',0,NULL,NULL,NULL,'/_index.php','Новости банка','','','','','4a413f21a243d6e98ba451885215ab83',NULL,NULL),(127,'2010-05-28 00:00:00','iblock','1',0,NULL,NULL,NULL,'=ID=1&EXTERNAL_ID=1&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=1&IBLOCK_CODE=corporate_news&IBLOCK_EXTERNAL_ID=corporate_news&CODE=','Банк переносит дату вступления в действие тарифов на услуги в иностранной валюте','Уважаемые клиенты,\rсообщаем Вам, что Банк переносит дату вступления в действие тарифов на услуги для юридических лиц и индивидуальных предпринимателей в иностранной валюте. В связи с этим до даты введения в действие новой редакции тарифов, услуги юридическим лицам и индивидуальным предпринимателям будут оказываться в рамках действующих тарифов. \rИнформация о дате введения новой редакции тарифов будет сообщена дополнительно.\r\nУважаемые клиенты,\rсообщаем Вам, что Банк переносит дату вступления в действие тарифов на услуги для юридических лиц и индивидуальных предпринимателей в иностранной валюте. В связи с этим до даты введения в действие новой редакции тарифов, услуги юридическим лицам и индивидуальным предпринимателям будут оказываться в рамках действующих тарифов. \rИнформация о дате введения новой редакции тарифов будет сообщена дополнительно.','','news','1',NULL,'2010-05-28 00:00:00',NULL),(128,'2010-05-27 00:00:00','iblock','2',0,NULL,NULL,NULL,'=ID=2&EXTERNAL_ID=2&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=1&IBLOCK_CODE=corporate_news&IBLOCK_EXTERNAL_ID=corporate_news&CODE=','Начать работать с системой «Интернет-Клиент» стало еще проще','Наш Банк предлагает своим клиентам Мастер Установки «Интернет-Клиент», который существенно упростит начало работы с системой. Теперь достаточно скачать и запустить Мастер Установки, и все настройки будут произведены автоматически. Вам больше не нужно тратить время на изучение объемных инструкций, или звонить в службу техподдержки, чтобы начать работать с системой.\r\nНаш Банк предлагает своим клиентам Мастер Установки «Интернет-Клиент», который существенно упростит начало работы с системой. Теперь достаточно скачать и запустить Мастер Установки, и все настройки будут произведены автоматически. Вам больше не нужно тратить время на изучение объемных инструкций, или звонить в службу техподдержки, чтобы начать работать с системой.','','news','1',NULL,'2010-05-27 00:00:00',NULL),(129,'2010-05-24 00:00:00','iblock','3',0,NULL,NULL,NULL,'=ID=3&EXTERNAL_ID=3&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=1&IBLOCK_CODE=corporate_news&IBLOCK_EXTERNAL_ID=corporate_news&CODE=','Реорганизация сети отделений Банка','В ближайшее время будет значительно расширен продуктовый ряд и перечень предоставляемых банковских услуг, которые Банк сможет предлагать во всех своих дополнительных офисах. Теперь наши клиенты смогут получить полный перечень услуг в любом из отделений Банка. \rБыло проведено комплексное всестороннее исследование функционирования региональных офисов на предмет соответствия возросшим требованиям. В результате, принято решение о временном закрытии офисов, не соответствующих высоким стандартам и не приспособленных к требованиям растущего бизнеса. Офисы постепенно будут отремонтированы и переоборудованы, станут современными и удобными. \rПриносим свои извинения за временно доставленные неудобства. \r\nВ ближайшее время будет значительно расширен продуктовый ряд и перечень предоставляемых банковских услуг, которые Банк сможет предлагать во всех своих дополнительных офисах. Теперь наши клиенты смогут получить полный перечень услуг в любом из отделений Банка. \rБыло проведено комплексное всестороннее исследование функционирования региональных офисов на предмет соответствия возросшим требованиям. В результате, принято решение о временном закрытии офисов, не соответствующих высоким стандартам и не приспособленных к требованиям растущего бизнеса. Офисы постепенно будут отремонтированы и переоборудованы, станут современными и удобными. \rПриносим свои извинения за временно доставленные неудобства.','','news','1',NULL,'2010-05-24 00:00:00',NULL),(130,'2010-05-01 00:00:00','iblock','4',0,NULL,NULL,NULL,'=ID=4&EXTERNAL_ID=2&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=vacancies&IBLOCK_ID=2&IBLOCK_CODE=corp_vacancies&IBLOCK_EXTERNAL_ID=corp_vacancies&CODE=','Главный специалист Отдела анализа кредитных проектов региональной сети','Требования\rВысшее экономическое/финансовое образование, опыт в банках топ-100 не менее 3-х лет в кредитном отделе (анализ заемщиков), желателен опыт работы с кредитными заявками филиалов, знание технологий АФХД предприятий, навыки написания экспертного заключения, знание законодательства (в т.ч. Положение ЦБ № 254-П).\rОбязанности\rАнализ кредитных проектов филиалов Банка, подготовка предложений по структурированию кредитных проектов, оценка полноты и качества формируемых филиалами заключений, выявление стоп-факторов, доработка заявок филиалов в соответствии со стандартами Банка, подготовка заключения (рекомендаций) на КК по заявкам филиалов в части оценки финансово-экономического состояния заемщика, защита проектов на КК Банка, консультирование и методологическая помощь филиалам Банка в части корпоративного кредитования.\rУсловия\rМесто работы: М.Парк Культуры. Графики работы: пятидневная рабочая неделя, с 9:00 до 18:00, пт. до 16:45. Зарплата: 50000 руб. оклад + премии, полный соц. пакет,оформление согласно ТК РФ','','vacancies','2',NULL,'2010-05-01 00:00:00',NULL),(131,'2010-05-01 00:00:00','iblock','5',0,NULL,NULL,NULL,'=ID=5&EXTERNAL_ID=3&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=vacancies&IBLOCK_ID=2&IBLOCK_CODE=corp_vacancies&IBLOCK_EXTERNAL_ID=corp_vacancies&CODE=','Специалист по продажам розничных банковских продуктов','Требования\rВысшее экономического образования ‚ опыт работы в сфере продаж банковских продуктов‚ опытный пользователь ПК‚ этика делового общения‚ ответственность‚ инициативность‚ активность.\rОбязанности\rПродажа розничных банковских продуктов, оформление документов.\rУсловия\rТрудоустройство по ТК РФ‚ полный соц. пакет. График работы: пятидневная рабочая неделя. Зарплата: 20000 руб. оклад + премии','','vacancies','2',NULL,'2010-05-01 00:00:00',NULL),(132,'2010-05-01 00:00:00','iblock','6',0,NULL,NULL,NULL,'=ID=6&EXTERNAL_ID=4&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=vacancies&IBLOCK_ID=2&IBLOCK_CODE=corp_vacancies&IBLOCK_EXTERNAL_ID=corp_vacancies&CODE=','Специалист Отдела андеррайтинга','Требования\rВысшее профессиональное образование, опыт работы от 2 лет в отделе по работе с физическими и юридическими лицами Банков, связанных с анализом платёжеспособности и кредитоспособности физических и юридических лиц.\rОбязанности\rПроверка соответствия документов, предоставленных клиентами Банка, анализ информации о риске\rУсловия\rТрудоустройство по ТК РФ‚ полный соц. пакет. График работы: пятидневная рабочая неделя. Зарплата: оклад 25000 руб.','','vacancies','2',NULL,'2010-05-01 00:00:00',NULL),(133,'2026-04-05 00:00:00','iblock','7',0,NULL,NULL,NULL,'=ID=7&EXTERNAL_ID=7&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=1&IBLOCK_CODE=corporate_news_s1&IBLOCK_EXTERNAL_ID=corporate_news_s1&CODE=','Моя новость','Я сделал сайт и создал новость.\r\nЯ сделал сайт и создал новость.','','news','1',NULL,'2026-04-05 00:00:00',NULL),(135,'2026-04-07 00:00:00','iblock','9',0,NULL,NULL,NULL,'=ID=9&EXTERNAL_ID=9&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=vacancies&IBLOCK_ID=2&IBLOCK_CODE=corp_vacancies_s1&IBLOCK_EXTERNAL_ID=corp_vacancies_s1&CODE=','junior PHP','','','vacancies','2',NULL,'2026-04-07 00:00:00',NULL),(136,'2026-04-07 15:44:03','main','s1|/index.php',0,NULL,NULL,NULL,'/index.php','Новости банка','Новости банка\rВакансии','','','',NULL,NULL,NULL),(137,'2026-04-14 16:48:54','iblock','10',0,NULL,NULL,NULL,'=ID=10&EXTERNAL_ID=10&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=3&IBLOCK_CODE=requests&IBLOCK_EXTERNAL_ID=&CODE=','ВОВА','','','news','3',NULL,NULL,NULL),(138,'2026-04-14 16:55:02','iblock','11',0,NULL,NULL,NULL,'=ID=11&EXTERNAL_ID=11&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=3&IBLOCK_CODE=requests&IBLOCK_EXTERNAL_ID=&CODE=','ВОВА','','','news','3',NULL,NULL,NULL),(139,'2026-04-14 16:57:12','iblock','12',0,NULL,NULL,NULL,'=ID=12&EXTERNAL_ID=12&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=3&IBLOCK_CODE=requests&IBLOCK_EXTERNAL_ID=&CODE=','Вова','','','news','3',NULL,NULL,NULL),(140,'2026-04-14 17:41:20','iblock','13',0,NULL,NULL,NULL,'=ID=13&EXTERNAL_ID=13&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=3&IBLOCK_CODE=requests&IBLOCK_EXTERNAL_ID=&CODE=','wwwwwww','','','news','3',NULL,NULL,NULL),(141,'2026-04-14 17:42:41','iblock','14',0,NULL,NULL