INSERT INTO `b_search_content_text` VALUES (1,'adb27eea179be3c992aeb74e1acb2c41','ИСТОРИЯ КОМПАНИИ\r\nЗАО «БАНК» ОСНОВАН 18 ЯНВАРЯ 1993 ГОДА.\rДО 1996 ГОДА БАНК РАЗВИВАЛСЯ КАК НЕБОЛЬШОЙ КОММЕРЧЕСКИЙ БАНК.\r1996 ГОД. ОТКРЫВАЕТСЯ ПЕРВЫЙ ДОПОЛНИТЕЛЬНЫЙ ОФИС ПО РАБОТЕ С НАСЕЛЕНИЕМ. БАНК ПРИСТУПАЕТ К АКТИВНОМУ РАЗВИТИЮ ФИЛИАЛЬНОЙ СЕТИ. \r1997 ГОД. БАНК НАЧИНАЕТ ВЫПУСК И ОБСЛУЖИВАНИЕ ПЛАСТИКОВЫХ КАРТ, ИСПОЛЬЗОВАНИЕ КОТОРЫХ ПОЗВОЛЯЕТ ВЫНЕСТИ ФИНАНСОВЫЙ СЕРВИС ЗА ПРЕДЕЛЫ ПРИВЫЧНЫХ ОПЕРАЦИОННЫХ ЗАЛОВ БАНКА И ФИЛИАЛОВ НА МЕСТА ФАКТИЧЕСКОГО ВОСТРЕБОВАНИЯ УСЛУГ.\rЯНВАРЬ 1998 ГОДА. БАНК ПОЛУЧАЕТ ЛИЦЕНЗИЮ ПРОФЕССИОНАЛЬНОГО УЧАСТНИКА РЫНКА ЦЕННЫХ БУМАГ. ПО РЕЗУЛЬТАТАМ АНАЛИЗА БУХГАЛТЕРСКОЙ И ФИНАНСОВОЙ ОТЧЁТНОСТИ БАНК ОТНОСИТСЯ ПО КРИТЕРИЯМ ЦБ РФ К ПЕРВОЙ КАТЕГОРИИ – ФИНАНСОВО СТАБИЛЬНЫЕ БАНКИ.\r1999 ГОД. БАНК, УСПЕШНО ПРЕОДОЛЕВ КРИЗИС, ПРОДОЛЖАЕТ АКТИВНОЕ РАЗВИТИЕ ФИЛИАЛЬНОЙ СЕТИ. В ЭТОМ ЖЕ ГОДУ БАНК ПРИСТУПАЕТ К РЕАЛИЗАЦИИ ПРОГРАММЫ ИПОТЕЧНОГО КРЕДИТОВАНИЯ МУНИЦИПАЛЬНЫХ СЛУЖАЩИХ.\r2004ГОД. БАНК ПРИСТУПАЕТ К ВЫПУСКУ КАРТ ПЛАТЁЖНОЙ СИСТЕМЫ VISA INTERNATIONAL. В ТЕЧЕНИЕ 2004 ГОДА БАНК ПРЕДСТАВИЛ КЛИЕНТАМ РЯД ВЫСОКОТЕХНОЛОГИЧНЫХ ПРОДУКТОВ. В ОБЛАСТИ КРЕДИТОВАНИЯ ФИЗИЧЕСКИХ ЛИЦ – СИСТЕМУ ИНТЕРНЕТ-КРЕДИТОВАНИЯ НА ПРИОБРЕТЕНИЕ АВТОМОБИЛЕЙ, ОБУЧЕНИЕ В ВУЗЕ, ОТДЫХ И ТУРИЗМ. \r2006 ГОД. ДЕСЯТЬ ЛЕТ С НАЧАЛА РАБОТЫ БАНКА В ОБЛАСТИ ПРЕДОСТАВЛЕНИЯ ФИНАНСОВЫХ УСЛУГ НАСЕЛЕНИЮ. ЗА ЭТО ВРЕМЯ В БАНКЕ ВЗЯЛИ КРЕДИТ БОЛЕЕ 50 000 ЧЕЛОВЕК, БОЛЕЕ 200 000 ЧЕЛОВЕК ДОВЕРИЛИ СВОИ ДЕНЬГИ, СДЕЛАВ ВКЛАДЫ, БОЛЕЕ 50 000 ЧЕЛОВЕК СТАЛИ ДЕРЖАТЕЛЯМИ ПЛАСТИКОВЫХ КАРТ БАНКА.\r2007 ГОД. БАНК ПОЛУЧАЕТ ГЛАВНУЮ ВСЕРОССИЙСКУЮ ПРЕМИЮ «РОССИЙСКИЙ НАЦИОНАЛЬНЫЙ ОЛИМП» В ЧИСЛЕ ЛУЧШИХ ПРЕДПРИЯТИЙ МАЛОГО И СРЕДНЕГО БИЗНЕСА РОССИИ.\r2008 ГОД. ПО РЕЗУЛЬТАТАМ МЕЖДУНАРОДНОГО КОНКУРСА \"ЗОЛОТАЯ МЕДАЛЬ \"ЕВРОПЕЙСКОЕ КАЧЕСТВО\", ПРОВЕДЕННОГО МЕЖДУНАРОДНОЙ АКАДЕМИЕЙ КАЧЕСТВА И МАРКЕТИНГА\" И АССОЦИАЦИЕЙ КАЧЕСТВЕННОЙ ПРОДУКЦИИ БАНК СТАНОВИТСЯ ЛАУРЕАТОМ МЕЖДУНАРОДНОЙ НАГРАДЫ \"ЗОЛОТАЯ МЕДАЛЬ \"ЕВРОПЕЙСКОЕ КАЧЕСТВО\".\r2009 ГОД. ПЕРЕХОД НА НОВУЮ АВТОМАТИЗИРОВАННУЮ БАНКОВСКУЮ СИСТЕМУ IBANK SYSTEM РОССИЙСКОЙ КОМПАНИИ «МКТ».\r2010 ГОД. ПО ДАННЫМ ФИНАНСОВОЙ ОТЧЁТНОСТИ НА 1 ЯНВАРЯ 2010 ГОДА БАНК ЗАВЕРШАЕТ 2009 ГОД С ПОЛОЖИТЕЛЬНЫМИ РЕЗУЛЬТАТАМИ. РАЗМЕР ПРИБЫЛИ ЗА 2009 ГОД СОСТАВЛЯЕТ 95 149 ТЫС. РУБЛЕЙ. ПОЛОЖИТЕЛЬНУЮ ДИНАМИКУ РОСТА ПОКАЗЫВАЮТ ПОЧТИ ВСЕ ФИНАНСОВЫЕ ПОКАЗАТЕЛИ.УСТАВНЫЙ КАПИТАЛ БАНКА УВЕЛИЧИВАЕТСЯ НА 20 % И НА ДАННЫЙ МОМЕНТ СОСТАВЛЯЕТ 415 240 ТЫСЯЧ РУБЛЕЙ.РАЗМЕР СОБСТВЕННОГО КАПИТАЛА БАНКА СОСТАВЛЯЕТ 1 535 522 ТЫСЯЧИ РУБЛЕЙ, ЧТО НА 31 % БОЛЬШЕ ЧЕМ В ПРОШЛОМ ГОДУ. \rЧАСТЬ ДОХОДА ЗА 2009 ГОД БАНК НАПРАВЛЯЕТ НА ФОРМИРОВАНИЕ РЕЗЕРВА НА ВОЗМОЖНЫЕ ПОТЕРИ ПО ССУДАМ, ССУДНОЙ И ПРИРАВНЕННОЙ К НЕЙ ЗАДОЛЖЕННОСТИ. ОБЪЁМ ТАКОГО РЕЗЕРВА ПО СОСТОЯНИЮ НА 1 ФЕВРАЛЯ 2010 ГОДА СОСТАВЛЯЕТ ПОРЯДКА 650 МЛН. РУБЛЕЙ.\rСВОЕ ДАЛЬНЕЙШЕЕ РАЗВИТИЕ БАНК СВЯЗЫВАЕТ С ПОВЫШЕНИЕМ КАЧЕСТВА И НАРАЩИВАНИЕМ ОБЪЕМОВ УСЛУГ, СОБСТВЕННОГО КАПИТАЛА, ВНЕДРЕНИЕМ НОВЕЙШИХ ТЕХНОЛОГИЙ, СОВЕРШЕНСТВОВАНИЕМ ФОРМ ОБСЛУЖИВАНИЯ КЛИЕНТОВ И РАЗВИТИЕМ НОВЫХ ПЕРСПЕКТИВНЫХ НАПРАВЛЕНИЙ В РАБОТЕ.\r\n'),(2,'faaa1838323144017f3af9a3b40d7ced','ИНФОРМАЦИЯ О КОМПАНИИ\r\nБАНК\r ОДИН ИЗ КРУПНЕЙШИХ УЧАСТНИКОВ РОССИЙСКОГО РЫНКА БАНКОВСКИХ УСЛУГ. БАНК РАБОТАЕТ В РОССИИ С 1997 ГОДА И НА СЕГОДНЯШНИЙ ДЕНЬ ОСУЩЕСТВЛЯЕТ ВСЕ ОСНОВНЫЕ ВИДЫ БАНКОВСКИХ ОПЕРАЦИЙ, ПРЕДСТАВЛЕННЫХ НА РЫНКЕ ФИНАНСОВЫХ УСЛУГ. СЕТЬ БАНКА ФОРМИРУЮТ 490 ФИЛИАЛОВ И ДОПОЛНИТЕЛЬНЫХ ОФИСОВ В 70 РЕГИОНАХ СТРАНЫ. МЫ ПРЕДЛАГАЕМ КЛИЕНТАМ ОСНОВНЫЕ БАНКОВСКИЕ ПРОДУКТЫ, ПРИНЯТЫЕ В МЕЖДУНАРОДНОЙ ФИНАНСОВОЙ ПРАКТИКЕ.\nЗАО БАНК ЗАНИМАЕТ 7-Е МЕСТО ПО РАЗМЕРУ АКТИВОВ ПО РЕЗУЛЬТАТАМ 2009 ГОДА. БАНК НАХОДИТСЯ НА 5-М МЕСТЕ В РОССИИ ПО ОБЪЕМУ ЧАСТНЫХ ДЕПОЗИТОВ И НА 4-М МЕСТЕ ПО ОБЪЕМУ КРЕДИТОВ ДЛЯ ЧАСТНЫХ ЛИЦ ПО РЕЗУЛЬТАТАМ 2009 ГОДА. 									\rБАНК\rЯВЛЯЕТСЯ УНИВЕРСАЛЬНЫМ БАНКОМ И ОКАЗЫВАЕТ ПОЛНЫЙ СПЕКТР УСЛУГ, ВКЛЮЧАЯ ОБСЛУЖИВАНИЕ ЧАСТНЫХ И КОРПОРАТИВНЫХ КЛИЕНТОВ, ИНВЕСТИЦИОННЫЙ БАНКОВСКИЙ БИЗНЕС, ТОРГОВОЕ ФИНАНСИРОВАНИЕ И УПРАВЛЕНИЕ АКТИВАМИ.\rВ ЧИСЛЕ ПРЕДОСТАВЛЯЕМЫХ УСЛУГ: 									\nВЫПУСК БАНКОВСКИХ КАРТ;\rИПОТЕЧНОЕ И ПОТРЕБИТЕЛЬСКОЕ КРЕДИТОВАНИЕ;\rАВТОКРЕДИТОВАНИЕ;\rУСЛУГИ ДИСТАНЦИОННОГО УПРАВЛЕНИЯ СЧЕТАМИ;\rКРЕДИТНЫЕ КАРТЫ С ЛЬГОТНЫМ ПЕРИОДОМ;\rСРОЧНЫЕ ВКЛАДЫ, АРЕНДА СЕЙФОВЫХ ЯЧЕЕК;\rДЕНЕЖНЫЕ ПЕРЕВОДЫ.\rЧАСТЬ УСЛУГ ДОСТУПНА НАШИМ КЛИЕНТАМ В КРУГЛОСУТОЧНОМ РЕЖИМЕ, ДЛЯ ЧЕГО ИСПОЛЬЗУЮТСЯ СОВРЕМЕННЫЕ ТЕЛЕКОММУНИКАЦИОННЫЕ ТЕХНОЛОГИИ.\rБАНК\rЯВЛЯЕТСЯ ОДНИМ ИЗ САМЫХ НАДЕЖНЫХ БАНКОВ НАШЕЙ СТРАНЫ. ОСНОВНЫМИ ЦЕННОСТЯМИ, КОТОРЫМИ МЫ РУКОВОДСТВУЕМСЯ В СВОЕЙ ДЕЯТЕЛЬНОСТИ ЯВЛЯЮТСЯ \rСПРАВЕДЛИВОСТЬ\r,\rПРОЗРАЧНОСТЬ\r, \rУВАЖЕНИЕ\r, \rСОТРУДНИЧЕСТВО\r,\rСВОБОДА\rИ\rДОВЕРИЕ\r. ОДНОЙ ИЗ ГЛАВНЫХ ЗАДАЧ \rБАНК\rВИДИТ ПОДДЕРЖАНИЕ И СОВЕРШЕНСТВОВАНИЕ РАЗВИТОЙ ФИНАНСОВОЙ СИСТЕМЫ РОССИИ.\rВ КАЧЕСТВЕ ОДНОГО ИЗ ПРИОРИТЕТНЫХ НАПРАВЛЕНИЙ КУЛЬТУРНО-ПРОСВЕТИТЕЛЬСКОЙ ДЕЯТЕЛЬНОСТИ \rБАНК\rОСУЩЕСТВЛЯЕТ ПОДДЕРЖКУ НАЦИОНАЛЬНОГО. ПРИ НАШЕМ СОДЕЙСТВИИ РОССИЮ ПОСЕТИЛИ МНОГИЕ ВСЕМИРНО ИЗВЕСТНЫЕ ЗАРУБЕЖНЫЕ МУЗЫКАНТЫ, В РЕГИОНАХ РОССИИ ЕЖЕГОДНО ПРОХОДЯТ ТЕАТРАЛЬНЫЕ ФЕСТИВАЛИ, КОНЦЕРТЫ И МНОГОЧИСЛЕННЫЕ ВЫСТАВКИ.\r\n'),(3,'04af3cb7a7124d187c790f71d33d78bb','РУКОВОДСТВО\r\nКОЛЛЕГИАЛЬНЫЙ ИСПОЛНИТЕЛЬНЫЙ ОРГАН ПРАВЛЕНИЯ БАНКА\rДОЛЖНОСТЬ\rОБРАЗОВАНИЕ\rПЛЕШКОВ ЮРИЙ ГРИГОРЬЕВИЧ \rНАЧАЛЬНИК ЭКОНОМИЧЕСКОГО УПРАВЛЕНИЯ \rВ 1996 ГОДУ ОКОНЧИЛ ИРКУТСКУЮ ГОСУДАРСТВЕННУЮ ЭКОНОМИЧЕСКУЮ АКАДЕМИЮ ПО СПЕЦИАЛЬНОСТИ ФИНАНСЫ И КРЕДИТ \rСМИРНОВ ВЯЧЕСЛАВ ЕВГЕНЬЕВИЧ \rЗАМЕСТИТЕЛЬ ПРЕДСЕДАТЕЛЯ ПРАВЛЕНИЯ \rВ 1991 ГОДУ ОКОНЧИЛ УНИВЕРСИТЕТ ДРУЖБЫ НАРОДОВ (МОСКВА). В 2000 ГОДУ ПОЛУЧИЛ СТЕПЕНЬ MBA В БИЗНЕС-ШКОЛЕ INSEAD. \rКОРНЕВА ИРИНА СТАНИСЛАВОВНА \rЗАМЕСТИТЕЛЬ ПРЕДСЕДАТЕЛЯ ПРАВЛЕНИЯ \rВ 1997 ГОДУ ОКОНЧИЛА МОСКОВСКУЮ ГОСУДАРСТВЕННУЮ ЮРИДИЧЕСКУЮ АКАДЕМИЮ ПО СПЕЦИАЛЬНОСТИ «БАНКОВСКОЕ ДЕЛО» \rИГНАТЬЕВ ВАДИМ МИХАЙЛОВИЧ \rПЕРВЫЙ ЗАМЕСТИТЕЛЬ ПРЕДСЕДАТЕЛЯ ПРАВЛЕНИЯ \rВ 1988 ГОДУ ОКОНЧИЛ ИРКУТСКУЮ ГОСУДАРСТВЕННУЮ ЭКОНОМИЧЕСКУЮ АКАДЕМИЮ ПО СПЕЦИАЛЬНОСТИ «ЭКОНОМИКА И УПРАВЛЕНИЕ ПРОИЗВОДСТВОМ» \rВОЛОШИН СТАНИСЛАВ СЕМЕНОВИЧ \rПРЕДСЕДАТЕЛЬ ПРАВЛЕНИЯ \rВ 1986 ГОДУ ОКОНЧИЛ СВЕРДЛОВСКИЙ ЮРИДИЧЕСКИЙ ИНСТИТУТ ПО СПЕЦИАЛЬНОСТИ «ПРАВОВЕДЕНИЕ» И МОСКОВСКИЙ ИНДУСТРИАЛЬНЫЙ ИНСТИТУТ ПО СПЕЦИАЛЬНОСТИ «ЭКОНОМИКА И УПРАВЛЕНИЕ НА ПРЕДПРИЯТИИ» \rСПИСОК ЧЛЕНОВ СОВЕТА ДИРЕКТОРОВ БАНКА\rДОЛЖНОСТЬ\rОБРАЗОВАНИЕ\rМИХАЙЛОВА ТАТЬЯНА ВАСИЛЬЕВНА \rДИРЕКТОР ПО ФИНАНСАМ \rВ 1996 ГОДУ ОКОНЧИЛА РОССИЙСКУЮ ЭКОНОМИЧЕСКУЮ АКАДЕМИЮ ИМ. Г.В. ПЛЕХАНОВА ПО СПЕЦИАЛЬНОСТИ «БАНКОВСКОЕ ДЕЛО». \rЛЯХ ЕВГЕНИЙ ВИКТОРОВИЧ \rДИРЕКТОР ПО ОБЕСПЕЧЕНИЮ БАНКОВСКОЙ ДЕЯТЕЛЬНОСТИ \rВ 1993 ГОДУ ОКОНЧИЛ РОССИЙСКУЮ ЭКОНОМИЧЕСКУЮ АКАДЕМИЮ ИМ. ПЛЕХАНОВА, ПО СПЕЦИАЛЬНОСТИ МВА «СТРАТЕГИЧЕСКИЙ МЕНЕДЖМЕНТ». \rКОНДРУСЕВ РОМАН АЛЕКСАНДРОВИЧ \rДИРЕКТОР КАЗНАЧЕЙСТВА \rВ 1993 ГОДУ ОКОНЧИЛ КЕМЕРОВСКИЙ ГОСУДАРСТВЕННЫЙ УНИВЕРСИТЕТ ПО СПЕЦИАЛЬНОСТИ «ПРАВОВЕДЕНИЕ» \rХРАМОВ АНАТОЛИЙ ФЁДОРОВИЧ \rДИРЕКТОР ПО РАБОТЕ С ПЕРСОНАЛОМ \rВ 1996 ГОДУ ОКОНЧИЛ ГОСУДАРСТВЕННЫЙ УНИВЕРСИТЕТ УПРАВЛЕНИЯ ПО СПЕЦИАЛИЗАЦИИ «УПРАВЛЕНИЕ ПЕРСОНАЛОМ». В 2002 ПРОШЕЛ ПРОГРАММУ ПОВЫШЕНИЯ КВАЛИФИКАЦИИ «СОВРЕМЕННЫЕ ТЕХНОЛОГИИ УПРАВЛЕНИЯ ЧЕЛОВЕЧЕСКИМИ РЕСУРСАМИ» \rЖУРАВЛЕВА ОЛЬГА НИКОЛАЕВНА \rГЛАВНЫЙ БУХГАЛТЕР \rВ 1985 ГОДУ ОКОНЧИЛА САНКТ-ПЕТЕРБУРГСКИЙ ИНСТИТУТ НАРОДНОГО ХОЗЯЙСТВА ПО СПЕЦИАЛЬНОСТИ «БУХГАЛТЕРСКИЙ УЧЕТ» \rКАЛИНИН АНДРЕЙ ГЕННАДЬЕВИЧ \rДИРЕКТОР ДЕПАРТАМЕНТА КОРПОРАТИВНОГО БИЗНЕСА \rВ 1998 ГОДУ ЗАКОНЧИЛ МОСКОВСКИЙ ГОСУДАРСТВЕННЫЙ ИНСТИТУТ МЕЖДУНАРОДНЫХ ОТНОШЕНИЙ, В 2002  ШКОЛУ МЕНЕДЖМЕНТА УНИВЕРСИТЕТА АНТВЕРПЕНА (UAMS) ПО СПЕЦИАЛЬНОСТИ MBA.\r\n'),(4,'17c27477cd3b1c927b1f739b9300ef80','МИССИЯ\r\nМИССИЯ БАНКА - ПРЕДОСТАВЛЯТЬ КАЖДОМУ КЛИЕНТУ МАКСИМАЛЬНО ВОЗМОЖНЫЙ НАБОР БАНКОВСКИХ УСЛУГ ВЫСОКОГО КАЧЕСТВА И НАДЕЖНОСТИ,СЛЕДУЯ\rМИРОВЫМ СТАНДАРТАМ И ПРИНЦИПАМ КОРПОРАТИВНОЙ ЭТИКИ. НАШ БАНК - ЭТО СОВРЕМЕННЫЙ ВЫСОКОТЕХНОЛОГИЧНЫЙ БАНК,СОЧЕТАЮЩИЙ\rВ СЕБЕ НОВЕЙШИЕ ТЕХНОЛОГИИ ОКАЗАНИЯ УСЛУГ И ЛУЧШИЕ ТРАДИЦИИ БАНКОВСКОГО СООБЩЕСТВА И РОССИЙСКОГО ПРЕДПРИНИМАТЕЛЬСТВА.\rИНДИВИДУАЛЬНЫЙ ПОДХОД\rНАША ЦЕЛЬ — ПРЕДОСТАВЛЕНИЕ КАЖДОМУ КЛИЕНТУ ПОЛНОГО КОМПЛЕКСА СОВРЕМЕННЫХ БАНКОВСКИХ ПРОДУКТОВ И УСЛУГ С ИСПОЛЬЗОВАНИЕМ ПОСЛЕДНИХ ДОСТИЖЕНИЙ И ИННОВАЦИЙ В СФЕРЕ ФИНАНСОВЫХ ТЕХНОЛОГИЙ. ИНДИВИДУАЛЬНЫЙ ПОДХОД К СИТУАЦИИ И ПРОБЛЕМАТИКЕ КАЖДОГО КЛИЕНТА И ФИЛОСОФИЯ ПАРТНЕРСТВА - ОСНОВЫ ВЗАИМОДЕЙСТВИЯ С НАШИМИ КЛИЕНТАМИ.\rУНИВЕРСАЛЬНОСТЬ\rБАНК ОБЕСПЕЧИВАЕТ СВОИМ КЛИЕНТАМ — ЧАСТНЫМ ЛИЦАМ, КРУПНЕЙШИМ ОТРАСЛЕВЫМ КОМПАНИЯМ, ПРЕДПРИЯТИЯМ СРЕДНЕГО И МАЛОГО БИЗНЕСА, ГОСУДАРСТВЕННЫМ СТРУКТУРАМ — ШИРОКИЙ СПЕКТР УСЛУГ. ЧТОБЫ МАКСИМАЛЬНО ПОЛНО ОБЕСПЕЧИТЬ ПОТРЕБНОСТИ КЛИЕНТОВ, МЫ АКТИВНО РАЗВИВАЕМ ФИЛИАЛЬНУЮ СЕТЬ В РОССИИ И ЗА ЕЕ ПРЕДЕЛАМИ. ЭТО ПОЗВОЛЯЕТ НАШИМ КЛИЕНТАМ ВСЕГДА И ВЕЗДЕ ПОЛУЧАТЬ СОВРЕМЕННЫЕ БАНКОВСКИЕ УСЛУГИ НА УРОВНЕ МИРОВЫХ СТАНДАРТОВ.\rБАНК — НАДЕЖНЫЙ ПАРТНЕР ПРИ РЕАЛИЗАЦИИ КРУПНЫХ СОЦИАЛЬНО-ЭКОНОМИЧЕСКИХ ПРОЕКТОВ РОССИИ И ЯВЛЯЕТСЯ ОДНИМ ИЗ ЛИДЕРОВ НА РЫНКЕ ИНВЕСТИЦИОННОГО ОБЕСПЕЧЕНИЯ РЕГИОНАЛЬНЫХ ПРОГРАММ.\rПАРТНЕРСТВО И ПОМОЩЬ В РАЗВИТИИ БИЗНЕСА\rВ СВОЕЙ ДЕЯТЕЛЬНОСТИ МЫ ОПИРАЕМСЯ НА ВЫСОЧАЙШИЕ СТАНДАРТЫ ПРЕДОСТАВЛЕНИЯ ФИНАНСОВЫХ УСЛУГ И ТЩАТЕЛЬНЫЙ АНАЛИЗ РЫНКА.\rПРЕДЛАГАЯ АДРЕСНЫЕ РЕШЕНИЯ И СОБЛЮДАЯ КОНФИДЕНЦИАЛЬНОСТЬ ВЗАИМООТНОШЕНИЙ С ПАРТНЕРАМИ, БАНК ПРОЯВЛЯЕТ ГИБКИЙ ПОДХОД К ЗАПРОСАМ КЛИЕНТОВ, КАК РОЗНИЧНЫХ, ТАК И КОРПОРАТИВНЫХ. ВНЕДРЯЯ ПЕРЕДОВЫЕ ТЕХНОЛОГИИ И ИННОВАЦИОННЫЕ РЕШЕНИЯ, БАНК ГАРАНТИРУЕТ КЛИЕНТАМ ВЫСОКОЕ КАЧЕСТВО ОБСЛУЖИВАНИЯ И СТАБИЛЬНЫЙ ДОХОД.\rМЫ ЧЕСТНЫ И ОТКРЫТЫ ПО ОТНОШЕНИЮ КО ВСЕМ НАШИМ ПАРТНЕРАМ И СТРЕМИМСЯ БЫТЬ ПРИМЕРОМ НАДЕЖНОСТИ И ЭФФЕКТИВНОСТИ ДЛЯ ВСЕХ, КТО С НАМИ СОТРУДНИЧАЕТ.\rСОЦИАЛЬНАЯ ОТВЕТСТВЕННОСТЬ\rБАНК ОРИЕНТИРОВАН НА ПОДДЕРЖКУ СОЦИАЛЬНО-ЭКОНОМИЧЕСКОГО РАЗВИТИЯ КЛИЕНТОВ. МЫ ВНОСИМ ВКЛАД В ПОВЫШЕНИЕ БЛАГОСОСТОЯНИЯ ОБЩЕСТВА, ПРЕДОСТАВЛЯЯ НАШИМ КЛИЕНТАМ ПЕРВОКЛАССНЫЕ ЭКОНОМИЧЕСКИЕ ВОЗМОЖНОСТИ, А ТАКЖЕ РЕАЛИЗУЯ ЭКОЛОГИЧЕСКИЕ ПРОГРАММЫ, ОБРАЗОВАТЕЛЬНЫЕ И КУЛЬТУРНЫЕ ПРОЕКТЫ. БАНК ОКАЗЫВАЕТ БЛАГОТВОРИТЕЛЬНУЮ ПОМОЩЬ СОЦИАЛЬНО НЕЗАЩИЩЕННЫМ СЛОЯМ ОБЩЕСТВА, УЧРЕЖДЕНИЯМ МЕДИЦИНЫ, ОБРАЗОВАНИЯ И КУЛЬТУРЫ, СПОРТИВНЫМ И РЕЛИГИОЗНЫМ ОРГАНИЗАЦИЯМ В РЕГИОНАХ РОССИИ. \rНАШ БАНК — ЭТО БАНК, РАБОТАЮЩИЙ НА БЛАГО ОБЩЕСТВА, CТРАНЫ И КАЖДОГО ЕЕ ЖИТЕЛЯ.\r\n'),(5,'d6ae18283686e0f65091531174c8b418','ВАКАНСИИ\r\n\r\n'),(6,'40a0a3a7a7f2cee820a4d86c53d6b827','BITNAMI: OPEN SOURCE. SIMPLIFIED\r\nAPACHE FRIENDS\rMENU\rAPPLICATIONS\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rAPACHE FRIENDS AND BITNAMI ARE COOPERATING TO MAKE DOZENS OF OPEN SOURCE APPLICATIONS AVAILABLE ON XAMPP, FOR FREE. BITNAMI-PACKAGED APPLICATIONS INCLUDE WORDPRESS, DRUPAL, JOOMLA! AND DOZENS OF OTHERS AND CAN BE DEPLOYED WITH ONE-CLICK INSTALLERS. VISIT THE \rBITNAMI XAMPP PAGE\rFOR DETAILS ON THE CURRENTLY AVAILABLE APPS.\rCHECK OUT OUR \rBITNAMI FOR XAMPP START GUIDE\rFOR MORE INFORMATION ABOUT THE APPLICATIONS INSTALLED.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rADD US TO YOUR G+ CIRCLES\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\nCOPYRIGHT (C) 2015, APACHE FRIENDS\r\n'),(7,'06cecc23c5cc18e8d1e0166639dc5c25','АВТОРИЗАЦИЯ\r\nВЫ ЗАРЕГИСТРИРОВАНЫ И УСПЕШНО АВТОРИЗОВАЛИСЬ.\rИСПОЛЬЗУЙТЕ АДМИНИСТРАТИВНУЮ ПАНЕЛЬ В ВЕРХНЕЙ ЧАСТИ ЭКРАНА ДЛЯ БЫСТРОГО ДОСТУПА К ФУНКЦИЯМ УПРАВЛЕНИЯ СТРУКТУРОЙ И ИНФОРМАЦИОННЫМ НАПОЛНЕНИЕМ САЙТА. НАБОР КНОПОК ВЕРХНЕЙ ПАНЕЛИ ОТЛИЧАЕТСЯ ДЛЯ РАЗЛИЧНЫХ РАЗДЕЛОВ САЙТА. ТАК ОТДЕЛЬНЫЕ НАБОРЫ ДЕЙСТВИЙ ПРЕДУСМОТРЕНЫ ДЛЯ УПРАВЛЕНИЯ СТАТИЧЕСКИМ СОДЕРЖИМЫМ СТРАНИЦ, ДИНАМИЧЕСКИМИ ПУБЛИКАЦИЯМИ (НОВОСТЯМИ, КАТАЛОГОМ, ФОТОГАЛЕРЕЕЙ) И Т.П.\rВЕРНУТЬСЯ НА ГЛАВНУЮ СТРАНИЦУ\r\n'),(8,'ea6b7e8f2315bef45aff06046bff51b8','ЗАДАТЬ ВОПРОС\r\n\r\n'),(9,'7535a1f25a1d9dccc214848d4086e066','КОНТАКТНАЯ ИНФОРМАЦИЯ\r\nОБРАТИТЕСЬ К НАШИМ СПЕЦИАЛИСТАМ И ПОЛУЧИТЕ ПРОФЕССИОНАЛЬНУЮ КОНСУЛЬТАЦИЮ ПО УСЛУГАМ НАШЕГО БАНКА.\rВЫ МОЖЕТЕ ОБРАТИТЬСЯ К НАМ ПО ТЕЛЕФОНУ, ПО ЭЛЕКТРОННОЙ ПОЧТЕ ИЛИ ДОГОВОРИТЬСЯ О ВСТРЕЧЕ В НАШЕМ ОФИСЕ. БУДЕМ РАДЫ ПОМОЧЬ ВАМ И ОТВЕТИТЬ НА ВСЕ ВАШИ ВОПРОСЫ. \rТЕЛЕФОНЫ\rТЕЛЕФОН/ФАКС: \n(495) 212-85-06\rТЕЛЕФОНЫ: \n(495) 212-85-07\r(495) 212-85-08\rНАШ ОФИС В МОСКВЕ\r\n'),(10,'5cb3783e398e7c6ed1983ad2cd1d6419','НАШИ РЕКВИЗИТЫ\r\nНАИМЕНОВАНИЕ БАНКА\rЗАКРЫТОЕ АКЦИОНЕРНОЕ ОБЩЕСТВО \"НАЗВАНИЕ БАНКА\"\rСОКРАЩЕННОЕ НАЗВАНИЕ\rЗАО \"НАЗВАНИЕ БАНКА\"\rПОЛНОЕ НАИМЕНОВАНИЕ НА АНГЛИЙСКОМ ЯЗЫКЕ\r\"THE NAME OF BANK\"\rОСНОВНОЙ ГОСУДАРСТВЕННЫЙ РЕГИСТРАЦИОННЫЙ НОМЕР\r152073950937987\rTELEX\r911156 IRS RU\rS.W.I.F.T.\rIISARUMM\rSPRINT\rRU.BANK/BITEX\rЮРИДИЧЕСКИЙ АДРЕС: \r175089, РОССИЯ, Г. МОСКВА, УЛ. БОЛЬШАЯ ДМИТРОВКА, Д. 15, СТР. 1\rКОР/СЧЕТ: \r30102810000000000569\rИНН:\r7860249880\rБИК:\r044591488\rОКПО:\r11806935\rОКОНХ:\r98122\rКПП:\r775021017\rПРОЧАЯ ИНФОРМАЦИЯ\rБАНКОВСКИЙ ИДЕНТИФИКАЦИОННЫЙ КОД: 0575249000\rПОЧТОВЫЙ АДРЕС: 115035, РОССИЯ, Г. МОСКВА, УЛ. БАЛЧУГ, Д. 2\rТЕЛЕФОН: (495) 960-10-12\rФАКС: (495) 240-38-12\rE-MAIL: \rRUSBK@MAIL.RUSBANK.RU\r\n'),(11,'d623ef4c3f60a35a346a9111abfab1bc','404 NOT FOUND\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\r404 \rNOT FOUND\rTHE PAGE YOU WERE LOOKING FOR DOESN\'T EXIST.\rTHINK THIS IS AN ERROR? PLEASE \rLET US KNOW\r.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(12,'5419290a090db48ca775f2e80922cad1','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rHÄUFIG GESTELLTE FRAGEN\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHÄUFIG GESTELLTE FRAGEN\rWIE INSTALLIERE ICH XAMPP?\rXAMPP FÜR WINDOWS GIBT ES IN DREI VERSCHIEDENEN VERSIONEN:\rINSTALLATIONSPROGRAMM:\rWAHRSCHEINLICH DER EINFACHSTE WEG, UM XAMPP ZU INSTALLIEREN.\rZIP:\rFÜR PURISTEN: XAMPP ALS ZIP-ARCHIV.\r7ZIP:\rFÜR PURISTEN MIT GERINGER BANDBREITE: XAMPP ALS 7ZIP-ARCHIV.\rHINWEIS: WENN SIE DIE DATEIEN ENTPACKEN, KANN ES ZU FALSCHEN WARNUNGEN IHRES ANTI-VIREN-PROGRAMMS KOMMEN.\rMIT DEM INSTALLER:\rDAS XAMPP-CONTROL-PANEL ZUM STARTEN UND BEENDEN VON APACHE, MYSQL, FILEZILLA & MERCURY ODER ZUM INSTALLIEREN DIESER SERVER ALS DIENSTE.\rINSTALLATION MIT EINER ZIP-DATEI\rPACKEN SIE DAS ZIP-ARCHIV IN DEN ORDNER IHRER WAHL AUS. XAMPP EXTRAHIERT SICH IN DAS UNTERVERZEICHNIS \"\\\\XAMPP\" UNTERHALB DES GEWÄHLTEN ZIELVERZEICHNISSES. STARTEN SIE DANN DIE DATEI \"SETUP_XAMPP.BAT\", UM DIE XAMPP-EINSTELLUNGEN AN IHR SYSTEM ANZUPASSEN.\rWENN SIE EIN WURZEL-VERZEICHNIS \"C:\\\\\" ALS ZIEL WÄHLEN, MÜSSEN SIE DIE \"SETUP_XAMPP.BAT\" NICHT STARTEN.\rWIE MIT DEM INSTALLATIONSPROGRAMM KÖNNEN SIE NUN DAS \"XAMPP-CONTROL-PANEL\" FÜR WEITERE AUFGABEN BENUTZEN.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rWIE KANN ICH XAMPP OHNE SETUP STARTEN?\rWENN SIE XAMPP IN EINEN TOP-LEVEL-ORDNER WIE \"C:\\\\\" ODER \"D:\\\\\" ENTPACKEN, KÖNNEN SIE DIE MEISTEN SERVER WIE APACHE ODER MYSQL DIREKT STARTEN, OHNE DIE DATEI \"SETUP_XAMPP.BAT\" AUSZUFÜHREN.\rWENN SIE XAMPP AUF EIN USB-LAUFWERK INSTALLIEREN, WIRD EMPFOHLEN, DAS SETUP-SKRIPT NICHT ZU BENUTZEN ODER DARIN RELATIVE PFADE AUSZUWÄHLEN, DA EIN SOLCHES LAUFWERK AUF JEDEM PC EINEN ANDEREN LAUFWERKSBUCHSTABEN HABEN KANN. SIE KÖNNEN MIT DEM SETUP-SCRIPT JEDERZEIT VON ABSOLUTEN AUF RELATIVE PFADE WECHSELN.\rDER EINFACHSTE WEG IST, DIE INSTALLER-VERSION VON DER DOWNLOAD-SEITE ZU NUTZEN, UM XAMPP ZU INSTALLIEREN. NACH DEM FERTIGSTELLEN DER INSTALLATION FINDEN SIE XAMPP UNTER START  PROGRAMME  XAMPP. MAN KANN DAS XAMPP-CONTROLL-PANEL BENUTZEN, UM DIE SERVER MANUELL ZU STARTEN ODER ZU BEENDEN, ALS AUCH DIESE PROGRAMME ALS WINDOWS-DIENSTE ZU INSTALLIEREN ODER ZU DEINSTALLIEREN.\rDAS XAMPP-CONTROL-PANEL ZUM STARTEN UND BEENDEN VON APACHE, MYSQL, FILEZILLA & MERCURY ODER ZUM INSTALLIEREN DIESER SERVER ALS DIENSTE.\rWIE STARTE / STOPPE ICH XAMPP?\rDAS UNIVERSELLE KONTROLLZENTRUM IST DAS \"XAMPP CONTROL PANEL\" (DANK AN WWW.NAT32.COM). ES WIRD MIT FOLGENDEM BEFEHL GESTARTET:\r\\XAMPP\\XAMPP-CONTROL.EXE\rSIE KÖNNEN AUCH EINIGE BATCHDATEIEN BENUTZEN, UM DIE SERVERDIENSTE ZU STARTEN/STOPPEN:\rAPACHE- & MYSQL-START:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE- & MYSQL-STOPP:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE-START:\n\\XAMPP\\APACHE_START.BAT\rAPACHE-STOPP:\n\\XAMPP\\APACHE_STOP.BAT\rMYSQL-START:\n\\XAMPP\\MYSQL_START.BAT\rMYSQL-STOPP:\n\\XAMPP\\MYSQL_STOP.BAT\rMERCURY-MAILSERVER-START:\n\\XAMPP\\MERCURY_START.BAT\rMERCURY-MAILSERVER-STOPP:\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA-SERVER-START:\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA-SERVER-STOPP:\n\\XAMPP\\FILEZILLA_STOP.BAT\rWIE KANN ICH TESTEN, OB ALLES FUNKTIONIERT?\rGEBEN SIE FOLGENDE URL IN IHREM LIEBLINGS-WEB-BROWSER EIN:\rHTTP://LOCALHOST/\rODER \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rWIE KANN ICH EIN SERVERPROGRAMM ALS WINDOWSDIENST INSTALLIEREN?\rJEDES SERVERPROGRAMM IN XAMPP KANN ALS WINDOWSDIENST INSTALLIERT WERDEN. DIESE INSTALLATION KANN ÜBER DAS XAMPP-CONTROL-PANEL DURCHGEFÜHRT WERDEN. ES IST NÖTIG ADMINISTRATIONSRECHTE ZU HABEN, UM DAS XAMPP-CONTROLL-PANEL UND DESSEN SKRIPTEN ZU NUTZEN.\rMANUELLE INSTALLATION DES APACHE ALS WINDOWSDIENST: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rMANUELLE DEINSTALLATION DES APACHE ALS WINDOWSDIENST: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rMANUELLE INSTALLATION DES MYSQL-SERVERS ALS WINDOWSDIENST: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rMANUELLE DEINSTALLATION DES MYSQL-SERVERS ALS WINDOWSDIENST: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA (FTP SERVER) ALS WINDOWSDIENST INSTALLIEREN UND DEINSTALLIEREN: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY-MAIL-SERVER: EINE WINDOWSDIENST-INSTALLATION GIBT ES NICHT\rIST XAMPP ZUM PRODUKTIVEINSATZ GEEIGNET?\rXAMPP IST NICHT FÜR DEN EINSATZ IN PRODUKTIVUMGEBUNGEN, SONDERN AUSSCHLIESSLICH FÜR DEN EINSATZ ALS ENTWICKLUNGSUMGEBUNG GEDACHT. XAMPP IST SO OFFEN WIE MÖGLICH KONFIGURIERT, UM DEM ENTWICKLER ALLES, WAS ER/SIE MÖCHTE, ZU ERLAUBEN. DIES IST FÜR ENTWICKLUNGSUMGEBUNGEN GROSSARTIG, KANN ABER IM PRODUKTIVEINSATZ FATALE AUSWIRKUNGEN HABEN.\rHIER IST EINE LISTE FEHLENDER SICHERHEITSEINSTELLUNGEN IN XAMPP:\rDER MYSQL-ADMINISTRATOR (ROOT) HAT KEIN PASSWORT.\rDER MYSQL-DAEMON IST ÜBERS NETZWERK ERREICHBAR.\rPROFTPD NUTZT DAS PASSWORT \"LAMPP\" FÜR DEN BENUTZER \"DAEMON\".\rDIE STANDARD-BENUTZER VON MERCURY UND FILEZILLA SIND BEKANNT.\rALLE EINSTELLUNGEN BEINHALTEN EINEN HOHEN SICHERHEITSRISIKO, BESONDERS WENN XAMPP ÜBER DAS NETZ UND VON ANDEREN PERSONEN AUSSERHALB IHRES LOKALEN NETZES ERREICHBAR IST. ES KANN AUCH HELFEN, EINE FIREWALL ODER EINEN (NAT-) ROUTER ZU NUTZEN. IM FALLE, DASS SIE EINE FIREWALL ODER EINEN ROUTER NUTZEN, IST IHR PC, AUF DEM XAMPP LÄUFT, NORMALERWEISE NICHT MEHR AUS DEM INTERNET ERREICHBAR. ES LIEGT AN IHNEN, DIESE PROBLEME ZU LÖSEN. EINE KLEINE HILFE DAZU IST UNTER DER \"XAMPP-SICHERHEITS-KONSOLE\" ZU FINDEN.\rBITTE SICHERN SIE XAMPP AB, BEVOR SIE ETWAS FÜR ALLE ONLINE ZUR VERFÜGUNG STELLEN. EINE FIREWALL UND EIN EXTERNER ROUTER SIND NUR FÜR EINE UNTERSTE EBENE AN SICHERHEIT AUSREICHEND. FÜR ETWAS MEHR SICHERHEIT SOLLTEN SIE DIE \"XAMPP-SICHERHEITS-KONSOLE\" AUFRUFEN UND PASSWÖRTER VERGEBEN.\rWENN SIE MÖCHTEN, DASS IHR XAMPP AUCH AUS DEM INTERNET ERREICHBAR IST, SO BESUCHEN SIE BITTE FOLGENDEN URI, DER EINIGE PROBLEME LÖSEN KANN:\rHTTP://LOCALHOST/SECURITY/\rMIT DER SICHERHEITSKONSOLE KÖNNEN SIE EIN PASSWORT FÜR DEN MYSQL-BENUTZER \"ROOT\" UND FÜR PHPMYADMIN SETZEN. SIE KÖNNEN AUCH EINE AUTHENTIFIKATION FÜR DIE DEMOSEITEN VON XAMPP AKTIVIEREN.\rDIESES WEB-BASIERTE WERKZEUG LÖST KEINE WEITERGEHENDEN SICHERHEITSLÜCKEN. INSBESONDERE DEN FILEZILLA-FTP-SERVER UND DEN MERCURY-MAIL-SERVER MÜSSEN SIE SELBST ABSICHERN.\rWIE DEINSTALLIERE ICH XAMPP?\rWENN SIE XAMPP MIT HILFE DER INSTALLER-VERSION INSTALLIERT HABEN, VERWENDEN SIE UNBEDINGT DEN \"UNINSTALLER\" (DE-INSTALLATIONSASSISTENT), ALSO NICHT NUR LÖSCHEN. DURCH DEN \"UNINSTALLER\" WERDEN ALLE EINSTELLUNGEN IN DER WINDOWSREGISTRIERUNG ZURÜCKGENOMMEN, GLEICHZEITIG WERDEN ALLE ANWENDUNGEN DEINSTALLIERT, DIE ZU XAMPP GEHÖREN. WIR EMPFEHLEN DRINGEND, DAS \"UNINSTALL\"-PROGRAMM AUS DER VERSION DES INSTALLERS ZU BENUTZEN, MIT DEM SIE XAMPP INSTALLIERT HABEN. BITTE SICHERN SIE ALLE WICHTIGEN DATEN, DIE SIE BEHALTEN MÖCHTEN, BEVOR SIE XAMPP DEINSTALLIEREN.\rWENN SIE XAMPP MIT HILFE DER ZIP- ODER 7ZIP-VERSION INSTALLIERT HABEN, FAHREN SIE ALLE XAMPP-SERVER HERUNTER UND VERLASSEN SIE ALLE FENSTER. WENN SIE IRGENDWELCHE DIENSTE EINGERICHTET HABEN, MACHEN SIE AUCH DAS RÜCKGÄNGIG. DANN LÖSCHEN SIE EINFACH DEN GESAMTEN ORDNER, IN DEM XAMPP INSTALLIERT WAR. ES GIBT KEINE REGISTRY-EINTRÄGE UND KEINE ENVIRONMENT-VARIABLEN, DIE GELÖSCHT WERDEN MÜSSTEN.\rWAS IST DIE \"LITE\"-VERSION VON XAMPP?\rXAMPP LITE (DAS BEDEUTET \"LIGHT\" (LEICHT) WIE IN \"LEICHTGEWICHT\") IST EIN KLEINERES BÜNDEL AUS XAMPP-KOMPONENTEN, DAS EMPFOHLEN WIRD FÜR RASCHE ARBEITEN, DIE NUR PHP UND MYSQL BRAUCHEN. EINIGE DIENSTE WIE MERCURY-MAIL UND FILEZILLA-FTP FEHLEN IN DER LITE-VERSION.\rWOHIN GEHÖRT MEIN WEB-INHALT?\rDAS STAMMVERZEICHNIS FÜR ALLE WWW-DOKUMENTE IST \\\\XAMPP\\\\HTDOCS. WENN SIE EINE DATEI \"TEST.HTML\" IN DIESES VERZEICHNIS LEGEN, KÖNNEN SIE DARAUF MIT DER URI \"HTTP://LOCALHOST/TEST.HTML\" ZUGREIFEN.\rUND \"TEST.PHP\"? EINFACH FOLGENDE ADRESSE AUFRUFEN \"HTTP://LOCALHOST/TEST.PHP\". EIN EINFACHES TESTSKRIPT KANN SO AUSSEHEN:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rEINE NEUES UNTERVERZEICHNIS FÜR IHR EIGENES WEB? EINFACH EIN NEUES VERZEICHNIS (Z. B. \"NEU\") INNERHALB DES VERZEICHNISSES \"\\\\XAMPP\\\\HTDOCS\" ANLEGEN (AM BESTEN OHNE LEERZEICHEN UND NUR ASCII-ZEICHEN), ERSTELLEN SIE DANN EINFACH EINE TESTDATEI IN DIESEM NEUEN VERZEICHNIS UND RUFEN SIE SIE MIT \"HTTP://LOCALHOST/NEU/TEST.PHP\" AUF.\rZUSÄTZLICHE EINZELHEITEN\rHTML:\rAUSFÜHRBAR: \\XAMPP\\HTDOCS\rERLAUBTE ENDUNGEN: .HTML .HTM\r=> BASISPAKET\rSSI:\rAUSFÜHRBAR: \\XAMPP\\HTDOCS\rERLAUBTE ENDUNGEN: .SHTML\r=> BASISPAKET\rCGI:\rAUSFÜHRBAR: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rERLAUBTE ENDUNGEN: .CGI\r=> BASISPAKET\rPHP:\rAUSFÜHRBAR: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rERLAUBTE ENDUNGEN: .PHP\r=> BASISPAKET\rPERL:\rAUSFÜHRBAR: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rERLAUBTE ENDUNGEN: .PL\r=> BASISPAKET\rAPACHE::ASP PERL:\rAUSFÜHRBAR: \\XAMPP\\HTDOCS\rERLAUBTE ENDUNGEN: .ASP\r=> BASISPAKET\rJSP JAVA:\rAUSFÜHRBAR: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rERLAUBTE ENDUNGEN: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rAUSFÜHRBAR: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rERLAUBTE ENDUNGEN: .HTML (U.A)\r=> TOMCAT ADD-ON\rKANN ICH DIE XAMPP-INSTALLATION WOANDERS HIN LEGEN?\rJA. NACHDEM SIE DAS XAMPP-VERZEICHNIS WOANDERS HIN GELEGT HABEN, MÜSSEN SIE DIE \"SETUP_XAMPP.BAT\"-DATEI AUSFÜHREN. DIE VERZEICHNISPFADE IN DEN KONFIGURATIONSDATEIEN WERDEN DURCH DIESEN SCHRITT ANGEPASST.\rWURDEN SERVER ALS WINDOWSDIENST INSTALLIERT, SO IST ES WICHTIG, DIESE VORHER ZU DEINSTALLIEREN, NACH DEM VERLEGEN DER XAMPP-INSTALLATION KANN MAN DANN DIE WINDOWSDIENSTE WIEDER INSTALLIEREN.\rACHTUNG: DIE KONFIGURATIONSDATEIEN IHRER EIGENEN SKRIPTEN - WIE PHP-ANWENDUNGEN - WERDEN NICHT GEÄNDERT. ABER ES IST MÖGLICH, EIN \"PLUG-IN\" FÜR DEN INSTALLER ZU SCHREIBEN. MIT EINEM SOLCHEN PLUG-IN KANN DER INSTALLER AUCH SOLCHE DATEIEN ANPASSEN.\rWAS SIND \"AUTOMATISCHE STARTSEITEN\" FÜR DIE WWW-VERZEICHNISSE?\rDER STANDARD-DATEINAME FÜR DIE APPACHEFUNKTION \"DIRECTORYINDEX\" IST \"INDEX.HTML\" ODER \"INDEX.PHP\". JEDES MAL, WENN SIE LEDIGLICH EIN VERZEICHNIS IM BROWSER AUFRUFEN (Z. B. \"HTTP://LOCALHOST/XAMPP/\") UND APACHE FINDET DARIN EINE SOLCHE DATEI, WIRD DIESE DATEI ANSTELLE EINES INHALTSVERZEICHNISSES ANGEZEIGT.\rWO KANN ICH DIE KONFIGURATIONEN ÄNDERN?\rFAST ALLE EINSTELLUNGEN IN XAMPP KÖNNEN SIE MIT KONFIGURATIONSDATEIEN ÄNDERN. ÖFFNEN SIE EINFACH DIE DATEI IN EINEM TEXT-EDITOR UND ÄNDERN SIE DIE GEWÜNSCHTE EINSTELLUNG. NUR FILEZILLA UND MERCURY SOLLTEN SIE MIT DEM KONFIGURATIONSWERKZEUG KONFIGURIEREN.\rWARUM LÄUFT XAMPP NICHT AUF WINDOWS XP SP2?\rMICROSOFT LIEFERT MIT SERVICE PACK 2 (SP2) EINE BESSERE FIREWALL, DIE AUTOMATISCH STARTET. DIESE FIREWALL BLOCKIERT JEDOCH DIE ERFORDERLICHEN PORTS 80 (HTTP) UND 443 (HTTPS), SODASS APACHE NICHT STARTEN KANN.\rDIE SCHNELLE LÖSUNG:\rDEAKTIVIEREN SIE DIE MICROSOFT-FIREWALL MIT DER SYSTEMSTEUERUNG  WINDOWS-FIREWALL UND VERSUCHEN SIE, XAMPP ERNEUT ZU STARTEN. BESSER WÄRE ES, EINE AUSNAHME IM SICHERHEITSCENTER EINZURICHTEN.\rDIE FOLGENDEN PORTS SIND IN BENUTZUNG FÜR BASIS-FUNKTIONALITÄTEN:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rWARUM FUNKTIONIERT XAMPP NICHT BEI WINDOWS VISTA?\rBENUTZERKONTENSTEUERUNG (UAC)\rIM VERZEICHNIS \"C:\\\\PROGRAMME\" HABEN SIE NICHT ALLE ZUGRIFFSRECHTE, NICHT EINMAL ALS ADMINISTRATOR. ODER SIE HABEN EINGESCHRÄNKTE ZUGRIFFSRECHTE (Z. B. FÜR \"\\\\XAMPP\\\\HTDOCS\"). IN DIESEM FALL KÖNNEN SIE DIE DATEI NICHT VERÄNDERN.\rLÖSUNG:\rERHÖHEN SIE IHRE ZUGRIFFSRECHTE ÜBER DEN DATEIMANAGER (RECHTE MAUSTASTE / SICHERHEIT) ODER SCHALTEN SIE DIE BENUTZERKONTENSTEUERUNG (UAC) AB.\rSIE HABEN APACHE/MYSQL IN \"C:\\\\XAMPP\" ALS WINDOWSDIENSTE INSTALLIERT. ABER SIE KÖNNEN DIESE WINDOWSDIENSTE NICHT MEHR ÜBER DAS \"XAMPP-CONTROLL-PANEL\" STARTEN/ANHALTEN ODER SIE KÖNNEN SIE NICHT DEINSTALLIEREN.\rLÖSUNG:\rBENUTZEN SIE DIE SYSTEMSTEUERUNG  VERWALTUNG  DIENSTE-KONSOLE VON WINDOWS ODER DEAKTIVIEREN SIE DIE BENUTZERKONTENSTEUERUNG UAC.\rDEAKTIVIEREN DER BENUTZERKONTENSTEUERUNG (UAC)\rVERWENDEN SIE DAS PROGRAMM \"MSCONFIG\", UM DIE BENUTZERKONTENSTEUERUNG ZU DEAKTIVIEREN. IN \"MSCONFIG\" GEHEN SIE AUF \"TOOLS\", WÄHLEN \"UAC-EINSTELLUNGEN ÄNDERN\", KLICKEN AUF \"STARTEN\" UND ÜBERPRÜFEN IHRE AUSWAHL. DANACH MÜSSEN SIE WINDOWS NEU STARTEN. ZUR GLEICHEN ZEIT KÖNNEN SIE DIE BENUTZERKONTENSTEUERUNG WIEDER AKTIVIEREN.\rWIE ÜBERPRÜFE ICH DIE MD5-PRÜFSUMME (MD5_CHECKSUM)?\rUM DATEIEN ZU VERGLEICHEN, WERDEN OFT PRÜFSUMMEN (CHECKSUMS) BENUTZT. ÜBLICHERWEISE ERZEUGT MAN EINE MD5-PRÜFSUMME (MESSAGE DIGEST ALGORITHM 5).\rMIT DIESER MD5-PRÜFSUMME KÖNNEN SIE TESTEN, OB IHR DOWNLOAD DES XAMPP-PAKETS KORREKT IST ODER NICHT. NATÜRLICH BENÖTIGEN SIE EIN PROGRAMM, DAS DIESE PRÜFSUMMEN ERSTELLEN KANN. FÜR WINDOWS KÖNNEN SIE EIN KOMMANDOZEILENWERKZEUG VON MICROSOFT VERWENDEN:\rVERFÜGBARKEIT UND BESCHREIBUNG DES PRÜFSUMMEN-DIENSTPROGRAMMS \"FILE CHECKSUM INTEGRITY VERIFIER UTILITY\" - FCIV\rES IST AUCH MÖGLICH, EIN ANDERES PROGRAMM ZU BENUTZEN, DAS EINE MD5-PRÜFSUMME ERZEUGEN KANN, Z. B. \"GNU MD5SUM\" ODER \"WINMD5SUM.EXE\".\rWENN SIE EIN SOLCHES PROGRAMM INSTALLIERT HABEN (Z.B. FCIV.EXE), KÖNNEN SIE DIE FOLGENDEN SCHRITTE AUSFÜHREN:\rLADEN SIE XAMPP (Z. B. XAMPP-WIN32-1.8.2-0.EXE) HERUNTER\rERSTELLEN SIE EINE PRÜFSUMME MIT:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rUND NUN KÖNNEN SIE IHRE PRÜFSUMME MIT DER ANGEZEIGTEN PRÜFSUMME AUF DER XAMPP_FÜR_WINDOWS-HOMEPAGE VERGLEICHEN.\rWENN BEIDE PRÜFSUMMEN GLEICH SIND, DANN IST ALLES IN ORDNUNG. WENN NICHT, SO KANN DER DOWNLOAD ABGEBROCHEN SEIN ODER DIE DATEI WURDE VERÄNDERT.\rWARUM HABEN ÄNDERUNGEN IN DER PHP.INI KEINE AUSWIRKUNGEN?\rWENN ÄNDERUNGEN IN DER PHP.INI KEINE WIRKUNG ZEIGEN, SO IST ES MÖGLICH, DASS EINE ANDERE PHP.INI BENUTZT WIRD. EINE PRÜFUNG KANN MIT PHPINFO() VOLLZOGEN WERDEN. GEHEN SIE AUF DIE URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP UND SUCHEN SIE NACH \"LOADED CONFIGURATION FILE\". IN DIESEM EINTRAG IST DER DATEIPFAD DER PHP.INI ABZULESEN, DER WIRKLICH BENUTZT WIRD.\rHINWEIS:\rNACH ÄNDERUNGEN IN DER PHP.INI IST ES WICHTIG, DEN APACHE NEU ZU STARTEN, DAMIT DER APACHE DEN PHP-PARSER VERANLASST, DIE NEUEN EINSTELLUNGEN EINZULESEN.\rHILFE! HIER IST EIN VIRUS IM XAMPP!\rEINIGE ANTIVIRUS PROGRAMME HALTEN XAMPP FÜR EINEN VIRUS, TYPISCHERWEISE MIT DEM HINWEIS AUF DEN XAMPP-MANAGER.EXE. DAS IST EINE FALSCHE POSITIV-MELDUNG DES ANTIVIRUS-PROGRAMMS, DAS BEDEUTET, DASS DAS ANTIVIRUS-PROGRAMM XAMPP IRRTÜMLICH ALS VIRUS IDENTIFIZIERT HAT, OBWOHL XAMPP KEINES IST. BEVOR WIR EINE NEUE VERSION VON XAMPP HERAUSGEBEN, TESTEN WIR SIE MIT UNTERSCHIEDLICHEN VIRENSCANNERN, DIE ZU DIESEM ZEITPUNKT AKTUELL VORHANDEN SIND. IM AUGENBLICK BENUTZEN WIR \rKAPERSKY ONLINE VIRUS SCANNER\r. SIE KÖNNEN AUCH DAS ONLINEWERKZEUG BENUTZEN, \rVIRUS TOTAL\rUM XAMPP ZU UNTERSUCHEN ODER SIE SENDEN UNS EINE E-MAIL AN SECURITY (AT) APACHEFRIENDS (DOT) ORG, WENN SIE EIN PROBLEM GEFUNDEN HABEN.\rWIE KONFIGURIERE ICH MEIN ANTIVIRUSPROGRAMM?\rWIR HABEN ALLE ZUM AUSFÜHREN DER GEBÜNDELTEN WEBANWENDUNG BENÖTIGTEN SERVER UND DIE DAMIT VERBUNDENEN DATEIEN EINGEFÜGT, SIE WERDEN ALSO BEMERKEN, DASS XAMPP EINE GROSSE ANZAHL AN DATEIEN INSTALLIERT. WENN SIE EINE XAMPP-ANWENDUNG AUF EINEM WINDOWSRECHNER MIT EINEM AKTIVEN ANTIVIRUSPROGRAMM INSTALLIEREN, DANN KANN DAS DIE INSTALLATION MERKLICH VERLANGSAMEN UND ES KANN SEIN, DASS EINER DER SERVER (WEB-SERVER, DATENBANKSERVER) VON DER ANTIVIRUSSOFTWARE BLOCKIERT WIRD. WENN SIE EIN ANTIVIRUSPROGRAMM AKTIVIERT HABEN, PRÜFEN SIE DIE FOLGENDEN EINSTELLUNGEN, DAMIT XAMPP OHNE LEISTUNGSEINBUSSEN AUSGEFÜHRT WIRD:\rFÜGEN SIE AUSNAHMEN IN DER FIREWALL HINZU: FÜR APACHE, MYSQL ODER JEDEN WEITEREN SERVER.\rDATEIEN UNTERSUCHEN BEIM AUFRUF: WENN SIE DIE VIRUSUNTERSUCHUNG FÜR ALLE DATEIEN AKTIVIERT HABEN, KÖNNEN DIE AUSFÜHRBAREN DATEIEN FÜR DEN SERVER LANGSAMER WERDEN.\rUNTERSUCHEN SIE DEN VERKEHR FÜR UNTERSCHIEDLICHE URLS: WENN SIE MIT XAMPP AUF IHREM EIGENEN RECHNER ENTWICKELN, KÖNNEN SIE DEN \"LOCALHOST\"-VERKEHR IN DEN ANTIVIRUSEINSTELLUNGEN AUSSCHLIESSEN.\rWARUM STARTET DER APACHE SERVER AUF MEINEM SYSTEM NICHT?\rDIES PROBLEM KANN EINEN VON MEHRERE GRÜNDEN HABE:\rSIE HABEN MEHR ALS EINEN HTTP-SERVER (IIS, SAMBAR, ZEUS USW.) GESTARTET. NUR EIN SERVER KANN PORT 80 VERWENDEN. DIESE FEHLERMELDUNG WEIST AUF DAS PROBLEM HIN:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rSIE HABEN EINE ANDERE SOFTWARE WIE DAS INTERNETTELEFON \"SKYPE\", DIE AUCH DEN PORT 80 BESETZT. WENN \"SKYPE\" DAS PROBLEM IST, GEHEN SIE IN SKYPE AUF AKTIONEN  VERBINDUNGSOPTIONEN  VERBINDUNG  ENTFERNEN SIE DAS HÄKCHEN BEI \"PORTS 80 UND 443 FÜR ZUSÄTZLICHE EINGEHENDE VERBINDUNGEN VERWENDEN\" UND STARTEN SIE SKYPE ERNEUT. JETZT SOLLTE ES FUNKTIONIEREN.\rSIE HABEN EINE FIREWALL, DIE DEN PORT VON APACHE BLOCKIERT. NICHT ALLE FIREWALLS SIND KOMPATIBEL MIT APACHE, UND ES KOMMT MANCHMAL VOR, DASS MAN DIE FIREWALL ABSCHALTEN MUSS UND WENN DAS NICHT REICHT, SOGAR EINE DEINSTALLATION DURCHFÜHREN MUSS. DIESE MELDUNG ZEIGT EINE FIREWALLBLOCKADE AN:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rAUCH WENN DER APACHE GESTARTET WERDEN KANN, ABER IHR BROWSER KANN NICHT DARAUF ZUGREIFEN (HTTP://LOCALHOST/), SO KÖNNTE ES EINEN DER FOLGENDEN GRÜNDE HABEN:\rEINIGE VIRUSSCANNER KÖNNEN DAS IN DER GLEICHER WEISE VERURSACHEN, WIE EINE FIREWALL STÖREN KANN.\rSIE BENUTZEN WINDOWS XP PROFESSIONAL OHNE SERVICEPACK 1. SIE MÜSSEN WENIGSTENS DAS SERVICEPACK 1 HABEN, DAMIT XAMPP FUNKTIONIERT.\rTIPP:\rWENN SIE PROBLEME MIT BELEGTEN PORTS HABEN, KÖNNEN SIE DAS TOOL \"XAMPP-PORTCHECK.EXE\" AUSPROBIEREN. MANCHMAL HILFT ES.\rWARUM IST MEINE CPU-AUSLASTUNG MIT APACHE BEI 99%?\rEINES VON ZWEI SZENARIEN SPIEL HIER EIN ROLLE. ENTWEDER IHRE CPU IST AM LIMIT ODER SIE RUFEN EINE SEITE AUF, SEHEN ABER NICHTS (DAS SYSTEM VERSUCHT VERGEBLICH DIE SEITE ZU LADEN). IN BEIDEN FÄLLEN KÖNNEN SIE DIE FOLGENDE NACHRICHT IN IHRER APACHE-LOGDATEI FINDEN:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rDER MPM FÄLLT ZURÜCK IN EINE SICHERERE IMPLEMENTIERUNG, ABER EINIGE CLIENTS WERDEN NICHT KORREKT BEHANDELT. UM DIESEN FEHLER ZU VERMEIDEN, SETZEN SIE \"ACCEPTFILTER\" MIT ACCEPT FILTER \"NONE\" IN DER \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\"-DATEI.\rWARUM WERDEN BILDER UND STYLESHEETS-FORMATE NICHT ANGEZEIGT?\rGELEGENTLICH GIBT ES PROBLEME MIT DER ANZEIGE VON BILDERN UND STYLESHEETS, INSBESONDERE WENN DIESE DATEIEN AUF EINEM NETZWERKLAUFWERK LIEGEN. IN DIESEM FALL KÖNNEN SIE EINE DER FOLGENDEN ZEILEN IN DER DATEI \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\" AKTIVIEREN (ODER HINZUFÜGEN):\rENABLESENDFILE OFF\rENABLEMMAP OFF\rDAS PROBLEM KANN AUCH VON PROGRAMMEN VERURSACHT WERDEN, DIE DIE BANDBREITE DER ÜBERTRAGUNG REGULIEREN (Z. B. NETLIMITER).\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rWIE KANN ICH EIN ROOT-PASSWORT FÜR DIE MYSQL-DATENBANK SETZEN?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rKANN ICH MEINEN EIGENEN MYSQL-SERVER NUTZEN?\rJA. STARTEN SIE EINFACH NICHT DEN MYSQL VOM XAMPP-PAKET. BITTE BEACHTEN SIE, DASS NICHT ZWEI SERVER AM GLEICHEN PORT LAUSCHEN KÖNNEN. WENN SIE EIN PASSWORT FÜR \"ROOT\" GESETZT HABEN, VERGESSEN SIE BITTE NICHT, DIE DATEI \"\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP\" ANZUPASSEN.\rWIE SCHRÄNKE ICH DEN ZUGRIFF AUF PHPMYADMIN VON AUSSEN EIN?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rBEVOR SIE AUF DEN MYSQL-SERVER ZUGREIFEN KÖNNEN, WIRD PHPMYADMIN NACH EINEM BENUTZERNAMEN UND EINEM PASSWORT FRAGEN. VERGESSEN SIE NICHT, ZUERST EIN PASSWORT FÜR DEN BENUTZER \"ROOT\" ZU SETZEN.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rWO IST DER IMAP-SUPPORT BEI PHP?\rIN DER STANDARDEINSTELLUNG IST DIE IMAP-UNTERSTÜTZUNG AUFGRUND EINIGER MYSTERIÖSER INITIALISIERUNGSFEHLER MIT EINIGEN HOMEVERSIONEN WIE WINDOWS_98 DEAKTIVIERT. WENN SIE MIT NT-SYSTEMEN ARBEITEN, KÖNNEN SIE DIE DATEI \"\\\\XAMPP\\\\PHP\\\\PHP.INI\" ÖFFNEN, DAMIT SIE DIE PHP-ERWEITERUNG DURCH ENTFERNEN DES SEMIKOLONS AM BEGINN DER ZEILE \";EXTENSION=PHP_IMAP.DLL\" AKTIVIEREN KÖNNEN. ES SOLLTE SEIN:\rEXTENSION=PHP_IMAP.DLL\rJETZT STARTEN SIE DEN APACHE NEU UND IMAP SOLLTE FUNKTIONIEREN. SIE KÖNNEN DIE GLEICHEN SCHRITTE FÜR ALLE ERWEITERUNGEN ANWENDEN, DIE IN DER STANDARDEINSTELLUNG NICHT AKTIVIERT SIND.\rWARUM FUNKTIONIEREN EINIGE PHP-OPEN-SOURCE-ANWENDUNGEN NICHT MIT XAMPP FÜR WINDOWS?\rVIELE PHP-ANWENDUNGEN ODER ERWEITERUNGEN, DIE FÜR LINUX GESCHRIEBEN WORDEN SIND, WURDEN NICHT AUF WINDOWS ÜBERTRAGEN. \rKANN ICH DAS VERZEICHNIS \"INSTALL\" NACH DER INSTALLATION LÖSCHEN?\rBESSER NICHT. DIE SKRIPTEN DARIN WERDEN NOCH FÜR ALLE ZUSATZPAKETE (ADD-ONS) UND UPGRADES VON XAMPP GEBRAUCHT.\rWIE AKTIVIERE ICH DEN EACCELERATOR?\rWIE ANDERE (ZEND-) ERWEITERUNGEN KÖNNEN SIE SIE IN IN DER \"PHP.INI\"-DATEI AKTIVIEREN. AKTIVIEREN SIE IN DIESER DATEI DIE ZEILE \";ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\". ES SOLLTE SEIN:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rWIE BEHEBE ICH VERBINDUNGSFEHLER ZUM MS_SQL-SERVER?\rWENN DIE MSSQL-ERWEITERUNG IN DER PHP.INI GELADEN WIRD, ERSCHEINEN GELEGENTLICH PROBLEME, WENN NUR TCP/IP BENUTZT WIRD. SIE KÖNNEN DAS PROBLEM MIT EINER NEUEREN VERSION DER \"NTWDBLIB.DLL\" VON MICROSOFT LÖSEN. BITTE ERSETZEN SIE DIE ÄLTERE DATEI IN \"\\\\XAMPP\\\\APACHE\\\\BIN\" UND \"\\\\XAMPP\\\\PHP\" MIT DER NEUEREN. WEGEN DER LIZENZ KÖNNEN WIR NICHT SELBST EINE NEUERE VERSION MIT XAMPP AUSLIEFERN.\rWIE ARBEITE ICH MIT DER PHP-MCRYPT-ERWEITERUNG?\rDAFÜR HABEN WIR EINEN BETREFF IM FORUM MIT BEISPIELEN UND MÖGLICHEN LÖSUNGEN GEÖFFNET: \rMCRYPT-EINTRAG\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rNEIN. UND APACHE::ASP MIT DEM PERL_ ADD-ON IST NICHT DAS GLEICHE. APACHE::ASP KENNT NUR PERL-SKRIPTEN, WOHINGEGEN ASP DES INTERNET-INFORMATION-SERVERS (IIS) AUCH NORMALES VBSCRIPT BEHERRSCHT. ALLERDINGS IST EIN APACHE-MODUL FÜR APS .NET VON EINEM DRITTANBIETER VERFÜGBAR.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rDATENSCHUTZBESTIMMUNGEN\rCDN BEREITGESTELLT DURCH\r\n'),(13,'528db97bbba10b38b6a22336af175cce','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rHÄUFIG GESTELLTE FRAGEN\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rDATENSCHUTZBESTIMMUNGEN\rCDN BEREITGESTELLT DURCH\r\n'),(14,'fd3f93cd178114e6b6adc3696093652a','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rHÄUFIG GESTELLTE FRAGEN\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rDATENSCHUTZBESTIMMUNGEN\rCDN BEREITGESTELLT DURCH\r\n'),(15,'7402e1fd6ce5502f0e36d6ac2b8e4fb3','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rHÄUFIG GESTELLTE FRAGEN\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rDATENSCHUTZBESTIMMUNGEN\rCDN BEREITGESTELLT DURCH\r\n'),(16,'be41ea1d52e90f9bd4db96b89af791bb','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rHÄUFIG GESTELLTE FRAGEN\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rHÄUFIG GESTELLTE FRAGEN\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nGEMEINSCHAFT\rXAMPP GIBT ES SEIT MEHR ALS 10 JAHREN  EINE RIESIGE GEMEINSCHAFT STEHT DAHINTER. AUCH DU KANNST EIN TEIL DAVON WERDEN, DURCH TEILNAHME AN UNSEREN \rFOREN\r, UNS AUF \rFACEBOOK\rLIKEST, ODER UNSEREN TÄTIGKEITEN AUF \rTWITTER\rFOLGST.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rDATENSCHUTZBESTIMMUNGEN\rCDN BEREITGESTELLT DURCH\r\n'),(17,'0db4067ecbe0a833035c3d9fd4f02138','ENABLE REMOTE ACCESS TO PHPMYADMIN\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nACCESS-PHPMYADMIN-REMOTELY.PDF\rENABLE REMOTE ACCESS TO PHPMYADMIN\rXAMPP INCLUDES \rPHPMYADMIN\r, AN OPEN-SOURCE, BROWSER-BASED TOOL FOR MANAGING MYSQL/MARIADB DATABASE SERVERS. BY DEFAULT, FOR SECURITY REASONS, PHPMYADMIN IS CONFIGURED TO ONLY ACCEPT CONNECTIONS FROM THE HOST ON WHICH XAMPP IS INSTALLED. ATTEMPTING TO ACCESS PHPMYADMIN FROM ANY OTHER HOST WILL PRODUCE THE ERROR BELOW:\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN FROM OTHER HOSTS, FOLLOW THESE STEPS:\rEDIT THE \rAPACHE/CONF/EXTRA/HTTPD-XAMPP.CONF\rFILE IN YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r).\rWITHIN THIS FILE, FIND THE BLOCK BELOW:\r<DIRECTORY \"/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\n...\rUPDATE THIS BLOCK AND REPLACE \rREQUIRE LOCAL\rWITH \rREQUIRE ALL GRANTED\r, SO THAT IT LOOKS LIKE THIS:\r<DIRECTORY \"/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\n...\rSAVE THE FILE AND RESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rYOU SHOULD NOW BE ABLE TO ACCESS PHPMYADMIN FROM OTHER HOSTS.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(18,'2755e05205e82705e98bf45a0a06de18','ACTIVATE AND USE XDEBUG\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nACTIVATE-USE-XDEBUG.PDF\rACTIVATE AND USE XDEBUG\rXDEBUG\rIS A POWERFUL OPEN SOURCE DEBUGGER AND PROFILER FOR PHP. IT IS INCLUDED WITH XAMPP AND CAN BE USED TO DISPLAY STACK TRACES, ANALYZE CODE COVERAGE AND PROFILE YOUR PHP CODE.\rTO ACTIVATE XDEBUG, FOLLOW THESE STEPS:\rEDIT THE \rPHP.INI\rFILE IN THE \rPHP\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r). WITHIN THIS FILE, FIND THE [XDEBUG] SECTION AND WITHIN IT, ADD THE FOLLOWING CONFIGURATION DIRECTIVE (OR MODIFY THE EXISTING ONE):\rZEND_EXTENSION = \"C:/XAMPP/PHP/EXT/PHP_XDEBUG.DLL\"\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rXDEBUG SHOULD NOW BE ACTIVE. TO VERIFY THIS, BROWSE TO THE URL \rHTTP://LOCALHOST/XAMPP/PHPINFO.PHP\r, WHICH DISPLAYS THE OUTPUT OF THE \rPHPINFO(\r) COMMAND. LOOK THROUGH THE SCRIPT AND VERIFY THAT THE XDEBUG EXTENSION IS NOW ACTIVE.\rXDEBUG OVERLOADS THE DEFAULT \rVAR_DUMP(\r) FUNCTION WITH ITS OWN VERSION THAT INCLUDES (AMONG OTHER THINGS) COLOR CODING FOR DIFFERENT PHP TYPES, SO YOU CAN SEE IT IN ACTION IMMEDIATELY BY USING THE \rVAR_DUMP()\rFUNCTION IN A PHP SCRIPT. FOR EXAMPLE, CREATE A SIMPLE PHP SCRIPT IN THE \rHTDOCS\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY WITH THE FOLLOWING CONTENT:\r<?PHP\nVAR_DUMP($_SERVER);\rWHEN YOU VIEW YOUR SCRIPT THROUGH A BROWSER, HERES AN EXAMPLE OF WHAT YOU MIGHT SEE:\rONE OF XDEBUGS MOST POWERFUL FEATURES IS ITS ABILITY TO PROFILE A PHP SCRIPT AND PRODUCE DETAILED STATISTICS ON HOW LONG EACH FUNCTION CALL OR LINE OF CODE TAKES TO EXECUTE. THIS CAN BE VERY USEFUL FOR PERFORMANCE ANALYSIS OF COMPLEX SCRIPTS. TO TURN ON SCRIPT PROFILING, FOLLOW THESE STEPS:\rEDIT THE \rPHP.INI\rFILE IN THE \rPHP\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. WITHIN THIS FILE, FIND THE [XDEBUG] SECTION AND WITHIN IT, UNCOMMENT AND MODIFY THE LINES BELOW SO THAT THEY LOOK LIKE THIS:\rXDEBUG.PROFILER_APPEND = 0\nXDEBUG.PROFILER_ENABLE = 1\nXDEBUG.PROFILER_ENABLE_TRIGGER = 0\nXDEBUG.PROFILER_OUTPUT_DIR = \"C:/XAMPP/TMP\"\nXDEBUG.PROFILER_OUTPUT_NAME = \"CACHEGRIND.OUT.%T-%S\"\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rAT THIS POINT, XDEBUG PROFILING IS ACTIVE. EVERY PHP SCRIPT THAT YOU RUN WILL BE PROFILED AND THE RESULTS WILL BE PLACED IN THE \rC:\\XAMPP\\TMP\rAS A SO-CALLED CACHEGRIND FILE. YOU CAN VIEW THIS CACHEGRIND FILE WITH A TOOL LIKE \rWINCACHEGRIND\r, WHICH YOU MUST DOWNLOAD AND INSTALL SEPARATELY.\rTO ILLUSTRATE HOW THIS WORKS, CONSIDER THE SCREENSHOT BELOW, WHICH SHOWS THE PROFILED OUTPUT OF A SCRIPT USING WINCACHEGRIND. AS THE SCREENSHOT ILLUSTRATES, ITS EASY TO SEE THE ENTIRE LIFE CYCLE OF A PHP SCRIPT, INCLUDING THE CALL SEQUENCE AND THE AMOUNT OF TIME TAKEN BY EACH FUNCTION, AND THEREBY FIND TARGETS FOR FURTHER OPTIMIZATION.\rTO FIND OUT MORE ABOUT XDEBUG’S POWERFUL FEATURES, \rREAD THE XDEBUG DOCUMENTATION\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(19,'21748912f3492c1885833decc004dbf7','AUTO-START XAMPP\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nAUTO-START-XAMPP.PDF\rAUTO-START XAMPP\rBY DEFAULT, YOU HAVE TO START XAMPP OR ITS COMPONENTS MANUALLY EVERY TIME YOU REBOOT YOUR SYSTEM. HOWEVER, YOU CAN ALSO CONFIGURE XAMPP COMPONENTS TO START AUTOMATICALLY ON SYSTEM BOOT. FOLLOW THE STEPS BELOW.\rLAUNCH THE XAMPP CONTROL PANEL.\rSTOP ALL THE RUNNING XAMPP COMPONENTS BY CLICKING THE \"STOP\" BUTTON NEXT TO EACH COMPONENT.\rCLICK THE \"SERVICE\" BUTTON NEXT TO EACH COMPONENT TO INSTALL IT AS A SERVICE. CLICK \"YES\" WHEN PROMPTED TO CONFIRM. THIS WILL INSTALL THE CORRESPONDING SERVICE AND SET IT TO START AUTOMATICALLY ON BOOT.\rREBOOT YOUR SYSTEM AND THE SELECTED COMPONENTS SHOULD START AUTOMATICALLY.\rTO REVERT THE CHANGES, SIMPLY UNCHECK THE SELECTED SERVICES IN THE XAMPP CONTROL PANEL.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(20,'6bcf82e13f235ce6e729160e1647cd2f','BACKUP AND RESTORE MYSQL/MARIADB DATABASES\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nBACKUP-RESTORE-MYSQL.PDF\rCONTENTS\rUSING PHPMYADMIN\rUSING COMMAND-LINE TOOLS\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rAS YOU USE XAMPP, YOU MIGHT FIND THAT YOU NEED TO BACKUP OR RESTORE A MYSQL OR MARIADB DATABASE. THERE ARE TWO EASY WAYS TO DO THIS WITH XAMPP: USING THE BROWSER-BASED PHPMYADMIN TOOL OR USING MYSQL/MARIADBS COMMAND-LINE TOOLS. THIS GUIDE DESCRIBES BOTH OPTIONS.\rTHIS GUIDE ASSUMES THAT YOU ALREADY HAVE A PHP APPLICATION THAT USES A MYSQL/MARIADB DATABASE DEPLOYED ON XAMPP. THE EXAMPLE APPLICATION USED IN THIS GUIDE IS WORDPRESS, ALTHOUGH THE STEPS OUTLINED BELOW WILL WORK FOR ANY APPLICATION.\rREMEMBER THAT YOU CAN INSTALL WORDPRESS QUICKLY USING THE \rBITNAMI WORDPRESS MODULE FOR XAMPP\r.\nUSING PHPMYADMIN\rXAMPP INCLUDES \rPHPMYADMIN\r, AN OPEN-SOURCE, BROWSER-BASED TOOL FOR MANAGING MYSQL/MARIADB DATABASE SERVERS. TO BACKUP A MYSQL/MARIADB DATABASE USING PHPMYADMIN, FOLLOW THESE STEPS:\rBROWSE TO \rHTTP://LOCALHOST/PHPMYADMIN\rOR \rHTTP://127.0.0.1/PHPMYADMIN\r. IF REQUIRED, LOG IN USING YOUR DATABASE ACCESS CREDENTIALS. ON A FRESH XAMPP INSTALLATION WITHOUT ANY CHANGES, YOU CAN LOG IN AS \rROOT\rWITH A BLANK PASSWORD.\rSELECT THE DATABASE TO BE BACKED UP FROM THE LIST IN THE LEFT NAVIGATION PANE. IN THIS CASE, WERE BACKING UP THE WORDPRESS DATABASE, WHICH IS NAMED \rBITNAMI_WORDPRESS\r.\rSELECT THE \"EXPORT\" COMMAND IN THE TOP NAVIGATION BAR.\rON THE RESULTING PAGE, SELECT \"QUICK\" AS THE EXPORT METHOD AND \"SQL\" AS THE OUTPUT FORMAT. CLICK \"GO\" TO PROCEED.\rPHPMYADMIN WILL EXPORT THE DATABASE TO A TEXT FILE AS A SERIES OF SQL STATEMENTS. ONCE DONE, THE BROWSER WILL PROMPT YOU TO DOWNLOAD IT TO THE DESKTOP. THIS TEXT FILE IS YOUR BACKUP, SO STORE IT SAFELY!\rAT A LATER POINT, YOU MAY WISH TO RESTORE THE DATABASE. TO RESTORE THE DATA TO A FRESH MYSQL/MARIADB DATABASE USING PHPMYADMIN, FOLLOW THESE STEPS:\rBROWSE TO \rHTTP://LOCALHOST/PHPMYADMIN\rOR \rHTTP://127.0.0.1/PHPMYADMIN\r. IF REQUIRED, LOG IN USING YOUR DATABASE ACCESS CREDENTIALS.\rSELECT THE \"NEW\" COMMAND IN THE LEFT NAVIGATION PANE.\rON THE RESULTING PAGE, ENTER A NAME FOR THE NEW DATABASE (IN THIS CASE, \rMYBLOG\r). SELECT THE COLLATION \"UTF8_GENERAL_CI\". CLICK \"CREATE\" TO CREATE THE DATABASE.\rONCE THE DATABASE HAS BEEN CREATED, IT WILL APPEAR IN THE LEFT NAVIGATION PANE.\rSELECT THE NEW DATABASE FROM THE LEFT NAVIGATION PANE. IN THE RESULTING PAGE, SELECT THE \"IMPORT\" COMMAND IN THE TOP NAVIGATION BAR.\rCLICK THE \"BROWSE&\" BUTTON AND SELECT THE BACKUP FILE CREATED EARLIER. CLICK \"GO\" TO PROCEED.\rPHPMYADMIN WILL IMPORT THE DATA FROM THE BACKUP FILE. ONCE COMPLETE, YOU WILL SEE A SCREEN INDICATING THE STATUS OF THE IMPORT.\rIF YOU BROWSE THE CONTENTS OF THE DATABASE, YOU SHOULD NOW SEE YOUR ORIGINAL DATA.\rYOU SHOULD NOW UPDATE YOUR APPLICATIONS CONFIGURATION AND POINT IT TO YOUR NEWLY-CREATED DATABASE. FOR EXAMPLE, WITH THE BITNAMI WORDPRESS MODULE, YOU WILL NEED TO EDIT THE \rWP-CONFIG.PHP\rFILE IN THE \rAPPS\\WORDPRESS\\HTDOCS\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. WITHIN THIS FILE, YOU WILL NEED TO UPDATE THE \rDB_NAME\rCONSTANT TO USE THE NEW DATABASE NAME.\rBY DEFAULT, PHP (AND THEREFORE PHPMYADMIN) IS CONFIGURED TO ONLY ACCEPT UPLOADS UP TO 2 MB IN SIZE. IF YOUR DATABASE IS LARGER THAN THIS, YOU NEED TO MODIFY THE PHP CONFIGURATION FILE TO ACCEPT A LARGER UPLOAD SIZE. TO DO THIS, EDIT THE \rPHP.INI\rFILE IN THE \rPHP\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY AND INCREASE THE VALUES OF THE \rPOST_MAX_SIZE\rAND \rUPLOAD_MAX_FILESIZE\rVARIABLES. SAVE YOUR CHANGES AND RESTART APACHE FOR THE CHANGES TO TAKE EFFECT.\nUSING COMMAND-LINE TOOLS\rMYSQL AND MARIADB INCLUDE TWO COMMAND-LINE TOOLS THAT YOU CAN USE TO QUICKLY BACKUP AND RESTORE DATABASES. THE \rMYSQLDUMP\rTOOL IS USED TO EXPORT THE CONTENTS OF A DATABASE TO A TEXT FILE, WHILE THE \rMYSQL\rCLIENT CAN BE USED TO IMPORT DATA FROM A TEXT FILE INTO A MYSQL/MARIADB DATABASE.\rTO BACKUP A MYSQL/MARIADB DATABASE FROM THE COMMAND LINE, FOLLOW THESE STEPS:\rLAUNCH A NEW WINDOWS COMMAND SHELL USING THE \"SHELL\" BUTTON IN THE XAMPP CONTROL PANEL.\rUSE THE COMMAND BELOW TO EXPORT THE CONTENTS OF THE SELECTED DATABASE. IN THIS EXAMPLE, WERE BACKING UP THE WORDPRESS DATABASE, WHICH IS NAMED \rBITNAMI_WORDPRESS\r, TO A FILE NAMED \rBITNAMI_WORDPRESS.SQL\r. THIS TEXT FILE IS YOUR BACKUP, SO STORE IT SAFELY!\rMYSQLDUMP --USER=ROOT --PASSWORD=\"\" BITNAMI_WORDPRESS > BITNAMI_WORDPRESS.SQL\rAT A LATER POINT, YOU MAY WISH TO RESTORE THE DATABASE. TO RESTORE THE DATA TO A FRESH MYSQL/MARIADB DATABASE FROM THE COMMAND LINE, FOLLOW THESE STEPS:\rLAUNCH A NEW WINDOWS COMMAND SHELL USING THE \"SHELL\" BUTTON IN THE XAMPP CONTROL PANEL.\rUSE THE \rMYSQL\rCLIENT TO CREATE A NEW, EMPTY DATABASE TO HOLD YOUR DATA. IN THIS EXAMPLE, THE NEW DATABASE IS NAMED \rMYBLOG\r.\rMYSQL --USER=ROOT --PASSWORD=\"\" -E \"CREATE DATABASE MYBLOG\"\rREMEMBER TO USE THE CORRECT DATABASE ACCESS CREDENTIALS IN THE COMMAND. ON A FRESH XAMPP INSTALLATION WITHOUT ANY CHANGES, YOU CAN USUALLY LOG IN AS ROOT WITH A BLANK PASSWORD.\rUSE THE \rMYSQL\rCLIENT TO IMPORT THE CONTENTS OF THE BACKUP FILE INTO THE NEW DATABASE.\rMYSQL --USER=ROOT --PASSWORD=\"\" --DATABASE=MYBLOG < BITNAMI_WORDPRESS.SQL\rTHE COMMAND-LINE CLIENT WILL NOW IMPORT THE DATA FROM THE BACKUP FILE.\rIF YOU BROWSE THE CONTENTS OF THE DATABASE, YOU SHOULD NOW SEE YOUR ORIGINAL DATA.\rYOU SHOULD NOW UPDATE YOUR APPLICATIONS CONFIGURATION AND POINT IT TO YOUR NEWLY-CREATED DATABASE. FOR EXAMPLE, WITH THE BITNAMI WORDPRESS MODULE, YOU WILL NEED TO EDIT THE \rWP-CONFIG.PHP\rFILE IN THE \rAPPS\\WORDPRESS\\HTDOCS\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. WITHIN THIS FILE, YOU WILL NEED TO UPDATE THE \rDB_NAME\rCONSTANT TO USE THE NEW DATABASE NAME.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(21,'c9329b3cbf4509c3a34e9a3998581d70','CHANGE THE MYSQL TEMPORARY FILES DIRECTORY\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nCHANGE-MYSQL-TEMP-DIR.PDF\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rBY DEFAULT, MYSQLS TEMPORARY FILES ARE STORED IN THE \rTMP\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r). IN CASE YOU WISH TO CHANGE THE LOCATION OF THIS DIRECTORY, FOLLOW THESE STEPS:\rEDIT THE \rMY.INI\rFILE IN THE \rMYSQL\\BIN\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. WITHIN THIS FILE, FIND THE \rTMPDIR\rVARIABLE IN THE [MYSQLD] SECTION AND CHANGE IT TO REFLECT YOUR NEW DESIRED LOCATION. FOR EXAMPLE:\rTMPDIR = \"D:/TEMP\"\rSAVE YOUR CHANGES TO THE FILE.\rRESTART THE MYSQL SERVER USING THE XAMPP CONTROL PANEL.\rMYSQLS TEMPORARY FILES SHOULD NOW GET CREATED IN THE NEW LOCATION.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(22,'76e4b8e057abd839942a688ff20091b4','CONFIGURE AND USE APACHE TOMCAT\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nCONFIGURE-USE-TOMCAT.PDF\rCONFIGURE AND USE APACHE TOMCAT\rXAMPP FOR WINDOWS COMES WITH APACHE TOMCAT BUILT IN, MAKING IT EASY TO GET STARTED WITH JAVA-BASED WEB APPLICATIONS. THIS GUIDE WILL WALK YOU THROUGH THE PROCESS OF USING APACHE TOMCAT WITH XAMPP.\rXAMPP FOR WINDOWS DOES NOT INCLUDE JAVA, WHICH IS A PRE-REQUISITE FOR USING APACHE TOMCAT. IF YOU DO NOT ALREADY HAVE JAVA INSTALLED, YOU WILL SEE AN ERROR SIMILAR TO THE BELOW WHEN YOU ATTEMPT TO START APACHE TOMCAT THROUGH THE XAMPP CONTROL PANEL.\rTO CORRECT THIS, INSTALL JAVA AND THEN ATTEMPT TO USE APACHE TOMCAT, AS BELOW:\rBROWSE TO \rHTTPS://WWW.JAVA.COM/EN/DOWNLOAD/\rAND FOLLOW THE INSTRUCTIONS TO DOWNLOAD THE LATEST VERSION OF THE JAVA RUNTIME ENVIRONMENT.\rFOLLOW THE ON-SCREEN INSTRUCTIONS TO INSTALL JAVA.\rONCE INSTALLED, YOU WILL SEE A MESSAGE LIKE THE ONE BELOW:\rON SOME VERSIONS OF WINDOWS, YOU WILL NOT BE ABLE TO INSTALL JAVA WITHOUT ADMINISTRATOR PRIVILEGES. YOU MAY EITHER NEED TO LOG IN AS A USER WITH ADMINISTRATIVE RIGHTS OR, IF YOU ARE USING THE OFFLINE JAVA INSTALLER, YOU MAY NEED TO RIGHT-CLICK THE INSTALLER FILE AND SELECT THE \"RUN AS ADMINISTRATOR\" MENU OPTION, THEN ENTER ADMINISTRATOR CREDENTIALS (IF REQUIRED) TO PROCEED.\nSTART THE APACHE TOMCAT SERVER USING THE XAMPP CONTROL PANEL.\rYOU SHOULD NOW BE ABLE TO ACCESS APACHE TOMCAT BY BROWSING TO \rHTTP://LOCALHOST:8080/\rIN YOUR BROWSERS ADDRESS BAR. HERES AN EXAMPLE OF WHAT YOU SHOULD SEE:\rAPACHE TOMCAT INCLUDES TWO APPLICATIONS, THE \"MANAGER\" APPLICATION AND THE \"HOST-MANAGER\" APPLICATION, THAT SIMPLIFY MANAGEMENT AND DEPLOYMENT OF WEB APPLICATIONS AND PROVIDE DETAILED INFORMATION ON SERVER STATUS. THESE APPLICATIONS CAN BE ACCESSED FROM THE APACHE TOMCAT WELCOME PAGE, AS HIGHLIGHTED IN THE IMAGE ABOVE.\rACCESS TO THE ABOVE APPLICATIONS IS BLOCKED BY DEFAULT. TO ACCESS THEM, YOU MUST CONFIGURE ONE OR MORE SETS OF ADMINISTRATOR ACCOUNTS AND THEN ASSIGN THE ROLES \"MANAGER-GUI\" AND/OR \"ADMIN-GUI\" TO THESE ACCOUNTS. ACCOUNTS WITH THE \"MANAGER-GUI\" ROLE WOULD HAVE ACCESS TO THE \"MANAGER\" APPLICATION, AND THOSE WITH THE \"ADMIN-GUI\" ROLE WOULD HAVE ACCESS TO THE \"HOST-MANAGER\" APPLICATION.\rTO CONFIGURE THESE ACCOUNTS, FOLLOW THE STEPS BELOW:\rEDIT THE \rTOMCAT-USERS.XML\rFILE IN THE \rTOMCAT/CONF\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (TYPICALLY \rC:\\XAMPP\r) AND ADD THE LINE BELOW, BEFORE THE CLOSING \r</TOMCAT-USERS>\rELEMENT:\r<USER USERNAME=\"ADMIN\" PASSWORD=\"ADMIN\" ROLES=\"MANAGER-GUI,ADMIN-GUI\" />\rTHIS CONFIGURES AN ACCOUNT WITH USERNAME \"ADMIN\" AND PASSWORD \"ADMIN\", WITH ACCESS TO BOTH THE APACHE TOMCAT WEB APPLICATIONS. REMEMBER TO REPLACE THE USERNAME AND PASSWORD WITH VALUES SPECIFIC TO YOUR INSTALLATION.\rIF YOU PREFER TO HAVE A SEPARATE ACCOUNT FOR EACH APPLICATION, REPLACE THE PREVIOUS CONFIGURATION WITH THIS EXAMPLE:\r<USER USERNAME=\"MANAGER\" PASSWORD=\"MANAGER\" ROLES=\"MANAGER-GUI\" />\n<USER USERNAME=\"ADMIN\" PASSWORD=\"ADMIN\" ROLES=\"ADMIN-GUI\" />\rSAVE THE CHANGES.\rRESTART THE APACHE TOMCAT SERVER USING THE XAMPP CONTROL PANEL.\rYOU SHOULD NOW BE ABLE TO ACCESS THE APACHE TOMCAT WEB APPLICATIONS USING THE CONFIGURED CREDENTIALS. HERES AN EXAMPLE OF THE MANAGEMENT WEB APPLICATION, WHICH INCLUDES CONTROLS TO DEPLOY NEW WAR APPLICATIONS.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(23,'38928a91b1d4753d85beae1a7f4c7233','CONFIGURE VIRTUAL HOSTS\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nCONFIGURE-VHOSTS.PDF\rCONFIGURE VIRTUAL HOSTS\rAPACHE MAKES IT EASY TO HAVE MULTIPLE WEBSITES OR WEB APPLICATIONS RUNNING ON THE SAME PHYSICAL SERVER, AND ACCESS EACH USING A CUSTOM DOMAIN NAME. THIS IS KNOWN AS \rVIRTUAL HOSTING\r, AND EACH VIRTUAL HOST CAN BE MAPPED TO A DIFFERENT SUBDIRECTORY OF THE SERVER.\rTHIS FEATURE IS ESPECIALLY USEFUL IN DEVELOPMENT SCENARIOS, AS IT ALLOWS DEVELOPERS TO ISOLATE AND ACCESS DIFFERENT APPLICATIONS USING UNIQUE DOMAIN NAMES. FOR EXAMPLE, THE DOMAINS \rHTTP://APP01.LOCALHOST\rAND \rHTTP://APP02.LOCALHOST\rCOULD POINT TO TWO SEPARATE APPLICATIONS ON THE SAME SERVER. OR, YOU COULD CREATE SEPARATE DOMAINS, SUCH AS \rHTTP://CLIENT1/\r, \rHTTP://CLIENT2/\rAND SO ON, FOR MULTIPLE CLIENT WEBSITES HOSTED ON THE SAME SERVER.\rVIRTUAL HOSTS CREATED IN THIS MANNER WILL NOT BE ACCESSIBLE FROM OTHER SYSTEMS, UNLESS THOSE SYSTEMS ARE SEPARATELY CONFIGURED TO ASSOCIATE THE CUSTOM DOMAIN USED BY THE VIRTUAL HOST WITH THE IP ADDRESS OF THE XAMPP SERVER.\nTHIS GUIDE WALKS YOU THROUGH THE PROCESS OF SETTING UP A NEW VIRTUAL HOST WITH XAMPP, BY CREATING AND CONFIGURING AN EXAMPLE HOST NAMED \rWORDPRESS.LOCALHOST\rFOR A WORDPRESS INSTALLATION. IT ASSUMES THAT YOU HAVE AN EXISTING WORDPRESS INSTALLATION AT \rC:\\XAMPP\\APPS\\WORDPRESS\\HTDOCS\\\rAND ACCESSIBLE VIA THE URL \rHTTP://LOCALHOST/WORDPRESS\r.\nYOU CAN INSTALL WORDPRESS WITH JUST A FEW CLICKS USING THE \rBITNAMI WORDPRESS MODULE FOR XAMPP\r.\nFOLLOW THE STEPS BELOW TO CREATE A VIRTUAL HOST:\rCHANGE TO YOUR XAMPP INSTALLATION DIRECTORY (TYPICALLY, \rC:\\XAMPP\r) AND OPEN THE \rHTTPD-VHOSTS.CONF\rFILE IN THE \rAPACHE\\CONF\\EXTRA\\\rSUBDIRECTORY USING YOUR FAVOURITE TEXT EDITOR.\rREPLACE THE CONTENTS OF THIS FILE WITH THE FOLLOWING DIRECTIVES:\r<VIRTUALHOST *:80>\nDOCUMENTROOT \"C:/XAMPP/HTDOCS/\"\nSERVERNAME LOCALHOST\n</VIRTUALHOST>\n<VIRTUALHOST *:80>\nDOCUMENTROOT \"C:/XAMPP/APPS/WORDPRESS/HTDOCS\"\nSERVERNAME WORDPRESS.LOCALHOST\n</VIRTUALHOST>\rTHIS CONTAINS TWO VIRTUAL HOST CONFIGURATION BLOCKS:\rTHE FIRST BLOCK IS THE DEFAULT OR FALLBACK VIRTUAL HOST, WHICH IS USED FOR ALL REQUESTS THAT ARE NOT MATCHED BY SUBSEQUENT BLOCKS.\rTHE SECOND BLOCK SETS UP A VIRTUAL HOST NAMED \rWORDPRESS.LOCALHOST\r. THE DOCUMENTROOT DIRECTIVE SPECIFIES THE DIRECTORY TO BE USED WHEN SERVING REQUESTS FOR THIS VIRTUAL HOST (IN THIS CASE, THE WORDPRESS INSTALLATION DIRECTORY), WHILE THE SERVERNAME DIRECTIVE SPECIFIES THE CUSTOM DOMAIN NAME FOR THE VIRTUAL HOST.\rTO ADD MORE VIRTUAL HOSTS, SIMPLY DUPLICATE THE SECOND VIRTUAL HOST BLOCK AND MODIFY THE PORT NUMBER, DOCUMENTROOT AND SERVERNAME DIRECTIVES AS PER YOUR REQUIREMENTS. FOR EXAMPLE, IF YOU WANT TO USE SSL WITH YOUR CUSTOM DOMAIN NAME, YOU CAN ADD A NEW VIRTUAL HOST BLOCK FOR PORT 443.\rIF YOU PLAN TO HAVE A LARGE NUMBER OF VIRTUAL HOSTS WITH VERY SIMILAR CONFIGURATION, CONSIDER USING WILDCARD-BASED SUBDOMAINS WITH YOUR VIRTUAL HOSTS.\nRESTART APACHE USING THE XAMPP CONTROL PANEL FOR YOUR CHANGES TO TAKE EFFECT.\rAT THIS POINT, YOUR VIRTUAL HOST IS CONFIGURED. HOWEVER, IF YOU TRY BROWSING TO THE \rWORDPRESS.LOCALHOST\rDOMAIN, YOUR BROWSER WILL SHOW A FAILURE NOTICE, SINCE THIS DOMAIN DOES NOT EXIST IN REALITY. TO RESOLVE THIS, IT IS NECESSARY TO MAP THE CUSTOM DOMAIN TO THE LOCAL IP ADDRESS. TO DO THIS, OPEN THE FILE \rC:\\WINDOWS\\SYSTEM32\\DRIVERS\\ETC\\HOSTS\rAND ADD THE FOLLOWING LINE TO IT:\r127.0.0.1 WORDPRESS.LOCALHOST\rTHIS TAKES CARE OF MAPPING THE \rWORDPRESS.LOCALHOST\rDOMAIN NAME TO THE LOCAL MACHINE, WHICH ALWAYS HAS THE IP ADDRESS 127.0.0.1.\rON SOME VERSIONS OF WINDOWS, YOU WILL NOT BE ABLE TO EDIT THE \rC:\\WINDOWS\\SYSTEM32\\DRIVERS\\ETC\\HOSTS\rFILE WITHOUT ADMINISTRATOR PRIVILEGES. YOU CAN EDIT THE FILE BY RIGHT-CLICKING THE NOTEPAD ICON AND SELECTED THE \"RUN AS ADMINISTRATOR\" MENU OPTION, THEN ENTERING ADMINISTRATOR CREDENTIALS (IF REQUIRED) AND CLICKING \"OK\" OR \"YES\" TO PROCEED.\nAT THIS POINT, YOU SHOULD BE ABLE TO ENTER THE URL \rHTTP://WORDPRESS.LOCALHOST\rIN YOUR BROWSERS ADDRESS BAR AND SEE YOUR WORDPRESS INSTALLATION. HERES AN EXAMPLE OF WHAT YOU SHOULD SEE:\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(24,'b7e174add1652d22b82fa9689d7c0dd0','CONFIGURE WILDCARD-BASED SUBDOMAINS\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nCONFIGURE-WILDCARD-SUBDOMAINS.PDF\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rAPACHES VIRTUAL HOSTING FEATURE MAKES IT EASY TO HOST MULTIPLE WEBSITES OR WEB APPLICATIONS ON THE SAME SERVER, EACH ACCESSIBLE WITH A DIFFERENT DOMAIN NAME. HOWEVER, WHEN YOU HAVE A LARGE NUMBER OF VIRTUAL HOSTS SHARING ALMOST-IDENTICAL CONFIGURATION, WILDCARD-BASED SUBDOMAINS SIMPLIFY MAINTENANCE AND REDUCE THE EFFORT INVOLVED IN ADDING A NEW VIRTUAL HOST.\rWITH WILDCARD SUBDOMAINS, ITS NO LONGER NECESSARY TO EDIT THE APACHE CONFIGURATION FILE OR RESTART THE SERVER TO INITIALIZE A NEW VIRTUAL HOST. INSTEAD, YOU SIMPLY NEED TO CREATE A SUBDIRECTORY MATCHING THE SUBDOMAIN NAME ON THE SERVER WITH YOUR CONTENT, AND APACHE WILL AUTOMATICALLY USE THAT DIRECTORY TO SERVE REQUESTS FOR THE CORRESPONDING SUBDOMAIN.\rVIRTUAL HOSTS CREATED IN THIS MANNER WILL NOT BE ACCESSIBLE FROM OTHER SYSTEMS, UNLESS THOSE SYSTEMS ARE SEPARATELY CONFIGURED TO ASSOCIATE THE CUSTOM DOMAINS USED BY VIRTUAL HOSTS WITH THE IP ADDRESS OF THE XAMPP SERVER.\nTHIS GUIDE WALKS YOU THROUGH THE PROCESS OF SETTING UP WILDCARD VIRTUAL HOSTS WITH XAMPP, SUCH THAT REQUESTS FOR \rSUBDOMAIN.LOCALHOST\rARE AUTOMATICALLY SERVED BY THE \rSUBDOMAIN/\rDIRECTORY OF THE MAIN SERVER DOCUMENT ROOT. FOLLOW THE STEPS BELOW:\n. CHANGE TO YOUR XAMPP INSTALLATION DIRECTORY (TYPICALLY, \rC:\\XAMPP\r) AND OPEN THE \rHTTPD.CONF\rFILE IN THE \rAPACHE\\CONF\\\rSUBDIRECTORY USING YOUR FAVOURITE TEXT EDITOR. WITHIN THE FILE, FIND THE FOLLOWING LINE AND UNCOMMENT IT BY REMOVING THE HASH SYMBOL (#) AT THE BEGINNING OF THE LINE.\rLOADMODULE VHOST_ALIAS_MODULE MODULES/MOD_VHOST_ALIAS.SO\rNEXT, EDIT THE \rHTTPD-VHOSTS.CONF\rFILE IN THE \rAPACHE\\CONF\\EXTRA\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY.\rREPLACE THE CONTENTS OF THIS FILE WITH THE FOLLOWING DIRECTIVES:\rUSECANONICALNAME OFF\n<VIRTUALHOST *:80>\nDOCUMENTROOT \"C:/XAMPP/HTDOCS/\"\nSERVERNAME LOCALHOST\n</VIRTUALHOST>\n<VIRTUALHOST *:80>\nSERVERALIAS *.LOCALHOST\nVIRTUALDOCUMENTROOT \"C:/XAMPP/HTDOCS/%1/\"\n</VIRTUALHOST>\rIN THIS CONFIGURATION, THE FIRST VIRTUAL HOST BLOCK CONFIGURES HOW REQUESTS ARE HANDLED BY DEFAULT. THE SECOND BLOCK CONFIGURES WILDCARD VIRTUAL HOSTING FOR SUBDOMAINS, SUCH THAT REQUESTS FOR \rSUBDOMAIN.LOCALHOST\rARE AUTOMATICALLY SERVED BY THE \rSUBDOMAIN\\\rDIRECTORY OF THE \rC:\\XAMPP\\HTDOCS\\\rDIRECTORY. IN PARTICULAR, NOTICE THE %1 PLACEHOLDER, WHICH MATCHES THE SUBDOMAIN NAME FROM THE REQUEST URL.\rRESTART APACHE USING THE XAMPP CONTROL PANEL FOR YOUR CHANGES TO TAKE EFFECT.\rAT THIS POINT, YOUR WILDCARD SUBDOMAINS ARE CONFIGURED. YOU CAN EASILY TEST THIS BY USING THE WINDOWS EXPLORER TO CREATE TWO NEW SUBDIRECTORIES AT \rC:\\XAMPP\\HTDOCS\\APP01\\\rAND \rC:\\XAMPP\\HTDOCS\\APP02\\\r. WITHIN EACH SUBDIRECTORY, CREATE A FILE NAMED \rINDEX.HTML\rAND FILL IT WITH SOME SAMPLE HTML CONTENT. USE DIFFERENT CONTENT FOR EACH FILE, SO THAT YOU CAN EASILY DISTINGUISH THAT THEYRE BEING SERVED FROM DIFFERENT DIRECTORIES - FOR EXAMPLE:\r<!-- INDEX.HTML IN APP01 DIRECTORY -->\n<HTML>\n<HEAD></HEAD>\n<BODY>\n<H1>WELCOME TO APP01.LOCALHOST!</H1>\n</BODY>\n</HTML>\r<!-- INDEX.HTML IN APP02 DIRECTORY -->\n<HTML>\n<HEAD></HEAD>\n<BODY>\n<H1>HELLO FROM APP02.LOCALHOST!</H1>\n</BODY>\n</HTML>\rSINCE THESE DOMAINS DO NOT ACTUALLY EXIST IN REALITY, YOU ALSO NEED TO MAP THEM TO THE LOCAL IP ADDRESS. OPEN THE FILE \rC:\\WINDOWS\\SYSTEM32\\DRIVERS\\ETC\\HOSTS\rIN A TEXT EDITOR AND ADD THE FOLLOWING LINE TO IT:\r127.0.0.1 APP01.LOCALHOST APP02.LOCALHOST\rYOU WILL NEED TO DO THIS EVERY TIME YOU WANT TO CONFIGURE A NEW WILDCARD VIRTUAL HOST, BECAUSE THE WINDOWS \rHOSTS\rFILE DOES NOT SUPPORT WILDCARD ENTRIES. TO AVOID THIS STEP, YOU CAN USE A DNS SERVER OR LOCAL DNS PROXY THAT SUPPORTS WILDCARDS AND THEREFORE TAKES CARE OF AUTOMATICALLY RESOLVING REQUESTS FOR \r*.LOCALHOST\rTO THE LOCAL IP ADDRESS.\nON SOME VERSIONS OF WINDOWS, YOU WILL NOT BE ABLE TO EDIT THE \rC:\\WINDOWS\\SYSTEM32\\DRIVERS\\ETC\\HOSTS\rFILE WITHOUT ADMINISTRATOR PRIVILEGES. YOU CAN EDIT THE FILE BY RIGHT-CLICKING THE NOTEPAD ICON AND SELECTED THE \"RUN AS ADMINISTRATOR\" MENU OPTION, THEN ENTERING ADMINISTRATOR CREDENTIALS (IF REQUIRED) AND CLICKING \"OK\" OR \"YES\" TO PROCEED.\nAT THIS POINT, YOU SHOULD BE ABLE TO ENTER THE URLS \rHTTP://APP01.LOCALHOST\rOR \rHTTP://APP02.LOCALHOST\rIN YOUR BROWSERS ADDRESS BAR, AND YOU SHOULD THEN SEE THE CORRESPONDING HTML PAGE.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(25,'469a33698988904f7214762a7d78839c','START A NEW ZEND FRAMEWORK 1 PROJECT\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nCREATE-FRAMEWORK-PROJECT-ZF1.PDF\rSTART A NEW ZEND FRAMEWORK 1 PROJECT\rXAMPP MAKES IT EASY TO START DEVELOPING WITH PHP, AND \rZEND FRAMEWORK\rIS ONE OF THE MOST POPULAR PHP DEVELOPMENT FRAMEWORKS. THIS GUIDE WALKS YOU THROUGH THE PROCESS OF INITIALIZING A NEW ZEND FRAMEWORK 1 PROJECT WITH XAMPP.\rTHIS GUIDE ASSUMES THAT THE NEW ZEND FRAMEWORK APPLICATION WILL BE ACCESSIBLE AT THE URL \rHTTP://LOCALHOST/MYAPP/\r.\nDOWNLOAD THE LATEST VERSION OF THE ZEND FRAMEWORK 1 MINIMAL PACKAGE\rAS A ZIP ARCHIVE.\rWITHIN YOUR XAMPP INSTALLATION DIRECTORY (USUALLY \rC:\\XAMPP\r), CREATE A NEW DIRECTORY NAMED \rAPPS\\\r(IF IT DOESNT ALREADY EXIST). THEN, WITHIN THIS NEW \rAPPS\\\rDIRECTORY, CREATE A DIRECTORY TO HOLD YOUR ZEND FRAMEWORK APPLICATION AND ITS RELATED XAMPP CONFIGURATION FILES. IN THIS EXAMPLE, CALL THE DIRECTORY \rMYAPP\\\r.\rEXTRACT THE CONTENTS OF THE ZIP ARCHIVE TO THE \rMYAPP\\ DIRECTORY. THIS WILL PRODUCE A _ZENDFRAMEWORK-[X.Y]-MINIMAL.ZIP\\\rSUBDIRECTORY IN THE \rMYAPP\r\\ DIRECTORY. RENAME THIS NEWLY-CREATED SUBDIRECTORY TO \rHTDOCS\r.\rTHIS NEW \rHTDOCS\rDIRECTORY WILL BE THE MAIN WORKING DIRECTORY FOR YOUR ZEND FRAMEWORK PROJECT.\nWITHIN THE \rMYAPP\\\rDIRECTORY, CREATE A NEW \rCONF\\\rSUBDIRECTORY.\rWITHIN THE NEW \rCONF\r\\ SUBDIRECTORY, USE YOUR TEXT EDITOR TO CREATE AND POPULATE A FILE NAMED \rTTPD-PREFIX.CONF\rWITH THE FOLLOWING CONTENT:\rALIAS /MYAPP/ \"C:/XAMPP/APPS/MYAPP/HTDOCS/PUBLIC/\"\nALIAS /MYAPP \"C:/XAMPP/APPS/MYAPP/HTDOCS/PUBLIC\"\nINCLUDE \"C:/XAMPP/APPS/MYAPP/CONF/HTTPD-APP.CONF\"\rWITHIN THE \rCONF\r\\ SUBDIRECTORY, ALSO CREATE AND POPULATE A FILE NAMED \rHTTPD-APP.CONF\rWITH THE FOLLOWING CONTENT:\r<DIRECTORY C:/XAMPP/APPS/MYAPP/HTDOCS/PUBLIC>\nOPTIONS +FOLLOWSYMLINKS\nALLOWOVERRIDE ALL\nREQUIRE ALL GRANTED\n</DIRECTORY>\rEDIT THE \rHTTPD-XAMPP.CONF\rFILE IN THE \rAPACHE\\CONF\\EXTRA\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY AND ADD THE FOLLOWING LINE AT THE END TO INCLUDE THE \rHTTPD-PREFIX.CONF\rFILE CREATED EARLIER.\rINCLUDE \"C:/XAMPP/APPS/MYAPP/CONF/HTTPD-PREFIX.CONF\"\rREMEMBER TO UPDATE THE ABOVE FILE AND DIRECTORY PATHS SO THAT THEYRE VALID FOR YOUR SYSTEM.\nLAUNCH A NEW WINDOWS COMMAND SHELL USING THE \"SHELL\" BUTTON IN THE XAMPP CONTROL PANEL.\rWITHIN THE COMMAND SHELL, CHANGE TO THE \rMYAPP\\HTDOCS\\\rDIRECTORY AND RUN THE FOLLOWING COMMANDS TO CREATE A NEW STUB PROJECT.\rBIN\\ZF.BAT CREATE PROJECT .\rCHECK THAT YOU HAVE A DIRECTORY STRUCTURE LIKE THIS:\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rYOU SHOULD BE ABLE TO ACCESS THE ZEND FRAMEWORK SKELETON APPLICATION BY BROWSING TO \rHTTP://LOCALHOST/MYAPP\r. HERES WHAT THE DEFAULT WELCOME PAGE LOOKS LIKE:\rYOU CAN NOW BEGIN DEVELOPING YOUR ZEND FRAMEWORK APPLICATION BY MODIFYING THE SKELETON APPLICATION CODE. FOR MORE INFORMATION, \rREFER TO THE ZEND FRAMEWORK DOCUMENTATION\r.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(26,'e3fb625bd49936679de451cc456eba4c','START A NEW ZEND FRAMEWORK 2 PROJECT\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nCREATE-FRAMEWORK-PROJECT-ZF2.PDF\rSTART A NEW ZEND FRAMEWORK 2 PROJECT\rXAMPP MAKES IT EASY TO START DEVELOPING WITH PHP, AND \rZEND FRAMEWORK 2\rIS ONE OF THE MOST POPULAR PHP DEVELOPMENT FRAMEWORKS. THIS GUIDE WALKS YOU THROUGH THE PROCESS OF INITIALIZING A NEW ZEND FRAMEWORK 2 PROJECT WITH XAMPP.\rTHIS GUIDE ASSUMES THAT YOU HAVE ALREADY DOWNLOADED AND INSTALLED GIT FOR WINDOWS, AND THAT THE GIT BINARY IS IN YOUR WINDOWS PATH. IF YOU DONT HAVE GIT FOR WINDOWS, YOU CAN \rDOWNLOAD AND INSTALL IT FROM HERE\r. IT ALSO ASSUMES THAT THE NEW ZEND FRAMEWORK 2 APPLICATION WILL BE ACCESSIBLE AT THE URL \rHTTP://LOCALHOST/MYAPP/\r.\nFOLLOW THESE STEPS:\rDOWNLOAD THE ZEND FRAMEWORK 2 SKELETON APPLICATION\rAS A ZIP ARCHIVE FROM GITHUB.\rWITHIN YOUR XAMPP INSTALLATION DIRECTORY (USUALLY \rC:\\XAMPP\r), CREATE A NEW DIRECTORY NAMED \rAPPS\\\r(IF IT DOESNT ALREADY EXIST). THEN, WITHIN THIS NEW \rAPPS\\\rDIRECTORY, CREATE A DIRECTORY TO HOLD YOUR ZEND FRAMEWORK 2 APPLICATION AND ITS RELATED XAMPP CONFIGURATION FILES. IN THIS EXAMPLE, CALL THE DIRECTORY \rMYAPP\\\r.\rEXTRACT THE CONTENTS OF THE ZIP ARCHIVE TO THE \rMYAPP\\\rDIRECTORY. THIS WILL PRODUCE A \rZENDFRAMEWORK-ZENDSKELETONAPPLICATION-[XX]\\\rSUBDIRECTORY IN THE \rMYAPP\\\rDIRECTORY. RENAME THIS NEWLY-CREATED SUBDIRECTORY TO \rHTDOCS\r.\rTHIS NEW \rHTDOCS\rDIRECTORY WILL BE THE MAIN WORKING DIRECTORY FOR YOUR ZEND FRAMEWORK 2 PROJECT.\nWITHIN THE \rMYAPP\\\rDIRECTORY, CREATE A NEW \rCONF\\\rSUBDIRECTORY.\rWITHIN THE NEW \rCONF\\\rSUBDIRECTORY, USE YOUR TEXT EDITOR TO CREATE AND POPULATE A FILE NAMED \rHTTPD-PREFIX.CONF\rWITH THE FOLLOWING CONTENT:\rALIAS /MYAPP/ \"C:/XAMPP/APPS/MYAPP/HTDOCS/PUBLIC/\"\nALIAS /MYAPP \"C:/XAMPP/APPS/MYAPP/HTDOCS/PUBLIC\"\nINCLUDE \"C:/XAMPP/APPS/MYAPP/CONF/HTTPD-APP.CONF\"\rWITHIN THE \rCONF\\\rSUBDIRECTORY, ALSO CREATE AND POPULATE A FILE NAMED \rHTTPD-APP.CONF\rWITH THE FOLLOWING CONTENT:\r<DIRECTORY C:/XAMPP/APPS/MYAPP/HTDOCS/PUBLIC>\nOPTIONS +FOLLOWSYMLINKS\nALLOWOVERRIDE ALL\nREQUIRE ALL GRANTED\n</DIRECTORY>\rEDIT THE \rHTTPD-XAMPP.CONF\rFILE IN THE \rAPACHE\\CONF\\EXTRA\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY AND ADD THE FOLLOWING LINE AT THE END TO INCLUDE THE \rHTTPD-PREFIX.CONF\rFILE CREATED EARLIER.\rINCLUDE \"C:/XAMPP/APPS/MYAPP/CONF/HTTPD-PREFIX.CONF\"\rREMEMBER TO UPDATE THE ABOVE FILE AND DIRECTORY PATHS SO THAT THEYRE VALID FOR YOUR SYSTEM.\nCHECK THAT YOU HAVE A DIRECTORY STRUCTURE LIKE THIS:\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rLAUNCH A NEW WINDOWS COMMAND SHELL USING THE \"SHELL\" BUTTON IN THE XAMPP CONTROL PANEL.\rWITHIN THE COMMAND SHELL, CHANGE TO THE \rMYAPP\\HTDOCS\\\rDIRECTORY AND RUN THE FOLLOWING COMMANDS TO UPDATE \rCOMPOSER\r(THE PHP DEPENDENCY MANAGER) AND INSTALL THE ZEND FRAMEWORK 2 COMPONENTS.\rPHP COMPOSER.PHAR SELF-UPDATE\nPHP COMPOSER.PHAR INSTALL\rHERES AN EXAMPLE OF WHAT YOU MIGHT SEE AS COMPOSER DOWNLOADS AND INSTALLS DEPENDENCIES.\rONCE COMPOSER IS DONE, YOU SHOULD BE ABLE TO ACCESS THE ZEND FRAMEWORK 2 SKELETON APPLICATION BY BROWSING TO \rHTTP://LOCALHOST/MYAPP\r. HERE IS AN EXAMPLE OF THE DEFAULT WELCOME PAGE YOU SHOULD SEE:\rYOU CAN NOW BEGIN DEVELOPING YOUR ZEND FRAMEWORK 2 APPLICATION BY MODIFYING THE SKELETON APPLICATION CODE. FOR MORE INFORMATION, \rREFER TO THE ZEND FRAMEWORK 2 USER GUIDE\r.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(27,'d877b83a1702762df9729f3ab71ab00d','DEPLOY AN APPLICATION USING GIT\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nDEPLOY-GIT-APP.PDF\rDEPLOY AN APPLICATION USING GIT\rGIT\rIS A POPULAR DISTRIBUTED VERSION CONTROL SYSTEM. AS YOU WORK WITH XAMPP, YOU MIGHT OFTEN FIND YOURSELF NEEDING TO DOWNLOAD AND INSTALL APPLICATIONS OR CODE LIBRARIES FROM A DEVELOPERS PUBLIC GIT REPOSITORY.\rTHIS GUIDE WALKS YOU THROUGH THE PROCESS, SHOWING YOU HOW TO USE A GIT CLIENT TO TRANSFER CODE FROM A PUBLIC ONLINE GIT REPOSITORY TO YOUR XAMPP SERVER. AS AN EXAMPLE, THIS GUIDE ASSUMES THAT YOU WISH TO DOWNLOAD THE LATEST VERSION OF \rSLIM\r, A POPULAR PHP MICRO-FRAMEWORK FOR WEB APPLICATION DEVELOPMENT THAT ALSO HAS ITS OWN GITHUB REPOSITORY.\nNOTE: THIS GUIDE USES \rGIT EXTENSIONS\r, AN OPEN SOURCE GIT CLIENT THATS AVAILABLE FOR WINDOWS, LINUX AND MAC OS, AND ASSUMES THAT YOU HAVE ALREADY DOWNLOADED AND INSTALLED THIS SOFTWARE. IF YOU DONT ALREADY HAVE THIS, YOU CAN \rDOWNLOAD IT FROM THE OFFICIAL GIT EXTENSIONS WEBSITE\r, AND \rINSTALL IT USING THESE INSTRUCTIONS\r.\rTO DOWNLOAD SLIM (OR ANY OTHER APPLICATION) FROM ITS GIT REPOSITORY, FOLLOW THESE STEPS:\rENSURE THAT YOUR APACHE SERVER IS RUNNING.\rOBTAIN THE REPOSITORYS CLONE URL. ON GITHUB, THIS CAN BE EASILY OBTAINED BY VISITING THE PROJECTS GITHUB PAGE AND COPYING THE CLONE URL FROM THE RIGHT SIDE OF THE PAGE. FOR THIRD-PARTY OR PRIVATE GIT REPOSITORIES, YOU CAN OBTAIN THE CLONE URL BY ASKING THE PROJECT TEAM DIRECTLY. MAKE A NOTE OF THE CLONE URL, AS YOULL NEED IT IN SUBSEQUENT STEPS.\rLAUNCH GIT EXTENSIONS BY DOUBLE-CLICKING THE ICON IN THE WINDOWS START MENU OR START SCREEN.\rCLICK THE \"CLONE REPOSITORY\" LINK OR USE THE \"START ? CLONE REPOSITORY&\" MENU ITEM.\rIN THE RESULTING \"CLONE\" DIALOG BOX, ENTER THE CLONE URL OBTAINED IN THE FIRST STEP. SET THE DESTINATION DIRECTORY TO THE \rHTDOCS\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (TYPICALLY, \rC:\\XAMPP\r). OPTIONALLY, CHANGE THE NAME OF THE SUBDIRECTORY THAT WILL HOLD THE DOWNLOADED CODE.\rCLICK THE \"CLONE\" BUTTON TO START CLONING THE REPOSITORY. GIT EXTENSIONS WILL DISPLAY A PROGRESS DIALOG AS IT DOWNLOADS THE CODE FROM THE SOURCE REPOSITORY.\rONCE THE REPOSITORY HAS BEEN CLONED, GIT EXTENSIONS WILL PROMPT YOU TO OPEN THE NEW REPOSITORY. CLICK \"YES\".\rYOU SHOULD NOW SEE THE ENTIRE COMMIT HISTORY OF THE REPOSITORY IN A GRAPHICAL TREE STRUCTURE, TOGETHER WITH DETAILS ON THE CHANGES MADE IN EACH COMMIT.\rAT THIS POINT, THE CODE HAS BEEN DOWNLOADED FROM THE REMOTE GIT REPOSITORY AND YOU CAN BEGIN USING IT. IN THIS PARTICULAR CASE, SINCE THE SLIM FRAMEWORK INCLUDES A STARTER APPLICATION, YOU CAN SIMPLY BROWSE TO THE URL \rHTTP://LOCALHOST/SLIM\rAND YOU SHOULD SEE THE EXAMPLE APPLICATIONS WELCOME PAGE, AS SHOWN BELOW.\rYOU CAN USE GIT EXTENSIONS TO CREATE A NEW BRANCH OF THE CODEBASE SHOULD YOU WISH TO MAKE ANY CHANGES TO IT. ANY CHANGES YOU MAKE WILL BE AUTOMATICALLY REFLECTED IN THE GIT EXTENSIONS INTERFACE, AND IF YOU HAVE APPROPRIATE PRIVILEGES, YOU CAN ALSO COMMIT YOUR CHANGES BACK TO THE REMOTE REPOSITORY. \rLEARN MORE ABOUT GIT\r, OR \rREAD THE GIT EXTENSIONS DOCUMENTATION\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(28,'e2e51cd7f4bb6508d1e20565da90d47f','INCREASE THE PHP FILE UPLOAD LIMIT\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nINCREASE-PHP-FILE-UPLOAD-LIMIT.PDF\rINCREASE THE PHP FILE UPLOAD LIMIT\rTO INCREASE THE ALLOWED FILE SIZE FOR UPLOADS THROUGH PHP, FOLLOW THESE STEPS:\rEDIT THE \rPHP.INI\rFILE IN THE \rPHP/\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r). WITHIN THIS FILE, FIND THE \rPOST_MAX_SIZE\rAND \rUPLOAD_MAX_FILESIZE\rVARIABLES AND CHANGE THEM TO REFLECT THE NEW FILE UPLOAD LIMIT. FOR EXAMPLE, TO RESTRICT UPLOADS TO NOT MORE THAN 16M, CHANGE THESE VARIABLES AS SHOWN BELOW:\r; MAXIMUM SIZE OF POST DATA THAT PHP WILL ACCEPT.\n; HTTP://PHP.NET/POST-MAX-SIZE\nPOST_MAX_SIZE=16M\n...\n; MAXIMUM ALLOWED SIZE FOR UPLOADED FILES.\n; HTTP://PHP.NET/UPLOAD-MAX-FILESIZE\nUPLOAD_MAX_FILESIZE=16M\rSAVE YOUR CHANGES TO THE FILE.\rRESTART THE APACHE SERVER.\rTHE NEW FILE UPLOAD LIMIT WILL NOW COME INTO EFFECT.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(29,'7a60ca87cfd0abf3d3aa6f0fb7b4f59e','RESET THE MYSQL/MARIADB ROOT PASSWORD\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nRESET-MYSQL-PASSWORD.PDF\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rBY DEFAULT, THE MYSQL/MARIADB INSTALLATION THAT SHIPS WITH XAMPP HAS AN EMPTY ROOT PASSWORD. THIS IS A SERIOUS SECURITY RISK, ESPECIALLY IF YOU PLAN TO USE XAMPP IN PRODUCTION SCENARIOS.\rTO CHANGE THE MYSQL/MARIADB ROOT PASSWORD, FOLLOW THESE STEPS:\rENSURE THAT THE MYSQL/MARIADB SERVER IS RUNNING.\rOPEN YOUR WINDOWS COMMAND PROMPT BY CLICKING THE \"SHELL\" BUTTON IN THE XAMPP CONTROL PANEL.\rUSE THE \rMYSQLADMIN\rCOMMAND-LINE UTILITY TO ALTER THE MYSQL/MARIADB PASSWORD, USING THE FOLLOWING SYNTAX:\rMYSQLADMIN --USER=ROOT PASSWORD \"NEWPASSWORD\"\rFOR EXAMPLE, TO CHANGE THE MYSQL/MARIADB ROOT PASSWORD FROM ITS DEFAULT EMPTY VALUE TO THE PASSWORD \rGUE55ME\r, YOU WOULD EXECUTE:\rMYSQLADMIN --USER=ROOT PASSWORD \"GUE55ME\"\rOR, IF A PASSWORD HAS ALREADY BEEN PREVIOUSLY SET AND YOUD LIKE TO CHANGE IT TO A NEW ONE, YOU CAN USE THE FOLLOWING SYNTAX:\rMYSQLADMIN --USER=ROOT --PASSWORD=OLDPASSWORD PASSWORD \"NEWPASSWORD\"\rFOR EXAMPLE, TO CHANGE THE ROOT PASSWORD FROM \r12345\rTO \rGUE55ME\r, YOU WOULD EXECUTE:\rMYSQLADMIN --USER=ROOT --PASSWORD=12345 PASSWORD \"GUE55ME\"\rTEST THAT YOUR PASSWORD CHANGE HAS BEEN ACCEPTED, BY ATTEMPTING TO CONNECT TO THE MYSQL/MARIADB SERVER USING THE \rMYSQL\rCOMMAND-LINE CLIENT IN THE SAME DIRECTORY. FOR EXAMPLE, YOU COULD USE THE COMMAND BELOW TO CONNECT TO THE SERVER AND RETURN THE RESULTS OF A CALCULATION:\rMYSQL --USER=ROOT --PASSWORD=GUE55ME -E \"SELECT 1+1\"\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(30,'822314b202d3c9c44bd80949674d7cd6','SEND MAIL WITH PHP\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nSEND-MAIL.PDF\rSEND MAIL WITH PHP\rIF YOURE A PHP APPLICATION DEVELOPER, YOU MIGHT NEED TO SEND EMAIL NOTIFICATIONS THROUGH YOUR CUSTOM PHP APPLICATIONS. WITH XAMPP, THERE ARE TWO WAYS TO DO THIS: YOU CAN USE THE INCLUDED \rSENDMAIL.EXE\rBINARY, OR YOU CAN USE THE THIRD-PARTY \rPHPMAILER\rCLASS. THIS GUIDE WALKS YOU THROUGH BOTH OPTIONS.\rTHIS GUIDE ASSUMES THAT YOU HAVE AN EXISTING GMAIL ACCOUNT, AND THAT YOU WILL USE GMAILS SMTP SERVER TO TRANSMIT EMAIL. YOU CAN ALSO USE YOUR ORGANIZATION OR ISPS MAIL SERVER, ALTHOUGH YOULL NEED TO REPLACE KEY DETAILS, SUCH AS THE SMTP SERVER NAME AND PORT, WITH APPROPRIATE VALUES FOR YOUR ENVIRONMENT. YOUR NETWORK ADMINISTRATOR OR ISP SUPPORT DESK WILL TYPICALLY BE ABLE TO PROVIDE THIS INFORMATION. THE EXAMPLE CODE PROVIDED IN THIS TUTORIAL IS ILLUSTRATIVE ONLY AND SHOULD NOT BE USED IN PRODUCTION ENVIRONMENTS.\nTO CONFIGURE XAMPP TO USE \rSENDMAIL.EXE\rFOR EMAIL NOTIFICATIONS, FOLLOW THESE STEPS:\rEDIT THE \rPHP.INI\rFILE IN THE \rPHP\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r). WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\rSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\rEDIT THE \rSENDMAIL.INI\rFILE IN THE \rSENDMAIL\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\rSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\rREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rYOU CAN NOW USE PHPS \rMAIL()\rFUNCTION TO SEND EMAIL FROM YOUR APPLICATION. TO ILLUSTRATE HOW IT CAN BE USED WITH YOUR GMAIL ACCOUNT, USE YOUR TEXT EDITOR TO CREATE AN EXAMPLE SCRIPT NAMED \rSENDMAIL.PHP\rIN THE \rHTDOCS\\\rSUBDIRECTORY AND FILL IT WITH THE FOLLOWING CODE. ONCE DONE, SAVE YOUR CHANGES.\r<?PHP\n$TO = \'RECIPIENTS@EMAIL-ADDRESS.COM\';\n$SUBJECT = \'HELLO FROM XAMPP!\';\n$MESSAGE = \'THIS IS A TEST\';\n$HEADERS = \"FROM: YOUR@EMAIL-ADDRESS.COM\\R\\N\";\nIF (MAIL($TO, $SUBJECT, $MESSAGE, $HEADERS)) {\nECHO \"SUCCESS\";\n} ELSE {\nECHO \"ERROR\";\n}\rREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH VALID EMAIL ADDRESSES. FOR THIS SIMPLE TEST, USE YOUR OWN EMAIL ADDRESS AS THE RECIPIENT ADDRESS.\rNOW, BROWSE TO THE URL \rHTTP://LOCALHOST/SENDMAIL.PHP\rTO EXECUTE THE SCRIPT AND SEND THE EMAIL MESSAGE. IF ALL GOES WELL, YOU SHOULD SEE A SUCCESS NOTIFICATION IN YOUR BROWSER. IF YOU USED YOUR OWN EMAIL ADDRESS FOR THE RECIPIENT ADDRESS, YOU SHOULD ALSO RECEIVE THE EMAIL MESSAGE.\rTO CONFIGURE XAMPP TO USE PHPMAILER FOR EMAIL NOTIFICATIONS, FOLLOW THESE STEPS:\rDOWNLOAD PHPMAILER FROM ITS GITHUB REPOSITORY USING THE \"DOWNLOAD ZIP\" BUTTON.\rCREATE A DIRECTORY FOR YOUR NEW APPLICATION WITHIN THE \rHTDOCS\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. IN THIS TUTORIAL, THE APPLICATION DIRECTORY IS NAMED \rEXAMPLE\\\r.\rEXTRACT THE CONTENTS OF THE PHPMAILER ZIP ARCHIVE TO THE APPLICATION DIRECTORY.\rYOU CAN NOW USE PHPMAILER TO SEND EMAIL FROM YOUR APPLICATION. TO ILLUSTRATE HOW IT CAN BE USED WITH YOUR GMAIL ACCOUNT, USE YOUR TEXT EDITOR TO CREATE AN EXAMPLE SCRIPT NAMED \rPHPMAILER.PHP\rIN THE APPLICATION DIRECTORY, AND FILL IT WITH THE FOLLOWING CODE. ONCE DONE, SAVE YOUR CHANGES.\r<?PHP\nREQUIRE \'PHPMAILER-MASTER/PHPMAILERAUTOLOAD.PHP\';\n$MAIL = NEW PHPMAILER;\n$MAIL->ISSMTP();\n$MAIL->SMTPSECURE = \'SSL\';\n$MAIL->SMTPAUTH = TRUE;\n$MAIL->HOST = \'SMTP.GMAIL.COM\';\n$MAIL->PORT = 465;\n$MAIL->USERNAME = \'YOUR-GMAIL-USERNAME@GMAIL.COM\';\n$MAIL->PASSWORD = \'YOUR-GMAIL-PASSWORD\';\n$MAIL->SETFROM(\'YOUR@EMAIL-ADDRESS.COM\');\n$MAIL->ADDADDRESS(\'RECIPIENTS@EMAIL-ADDRESS.COM\');\n$MAIL->SUBJECT = \'HELLO FROM PHPMAILER!\';\n$MAIL->BODY = \'THIS IS A TEST.\';\n//SEND THE MESSAGE, CHECK FOR ERRORS\nIF (!$MAIL->SEND()) {\nECHO \"ERROR: \" . $MAIL->ERRORINFO;\n} ELSE {\nECHO \"SUCCESS\";\n}\rREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. YOU SHOULD ALSO USE A VALID SENDER AND RECIPIENT ADDRESS. FOR THIS SIMPLE TEST, USE YOUR OWN EMAIL ADDRESS AS THE RECIPIENT ADDRESS.\rNOW, BROWSE TO THE URL \rHTTP://LOCALHOST/EXAMPLE/PHPMAILER.PHP\r. THIS SHOULD EXECUTE THE SCRIPT AND SEND THE EMAIL MESSAGE. IF ALL GOES WELL, YOU SHOULD SEE A SUCCESS NOTIFICATION IN YOUR BROWSER. IF YOU USED YOUR OWN EMAIL ADDRESS FOR THE RECIPIENT ADDRESS, YOU SHOULD ALSO RECEIVE THE EMAIL MESSAGE.\rAS A SECURITY PRECAUTION, GMAIL WILL AUTOMATICALLY REWRITE THE FROM: AND REPLY-TO: HEADERS IN YOUR EMAIL MESSAGE TO REFLECT YOUR GMAIL ADDRESS. IF YOU WANT TO AVOID THIS, YOU MUST ADD AND VALIDATE YOUR CUSTOM EMAIL ADDRESS IN YOUR GMAIL ACCOUNT AS A SENDER. REFER TO \rGMAILS DOCUMENTATION FOR MORE INFORMATION AND IMPORTANT RESTRICTIONS\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(31,'710c217ba39d69aef662b98d23c527b6','CONFIGURE FTP ACCESS\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nTRANSFER-FILES-FTP.PDF\rCONFIGURE FTP ACCESS\rXAMPP INCLUDES THE SERVER VERSION OF \rFILEZILLA\r, AN OPEN-SOURCE FTP SOLUTION. THIS MAKES IT EASY TO TRANSFER FILES TO AND FROM A XAMPP ENVIRONMENT USING FTP.\rTO ILLUSTRATE, ASSUME THAT YOU HAVE A SIMPLE PHP SCRIPT NAMED \rEXAMPLE.PHP\rON YOUR WINDOWS DESKTOP CONTAINING THE FOLLOWING CODE, THAT YOU WISH TO TRANSFER TO THE XAMPP SERVER.\r<!-- EXAMPLE.PHP -->\n<HTML>\n<HEAD></HEAD>\n<BODY>\n<H2><?PHP ECHO \"HELLO. TODAY IS \" . DATE(\'L\'); ?>.</H2>\n</BODY>\n</HTML>\rTO TRANSFER FILES USING FTP, YOU MUST FIRST CONFIGURE THE FILEZILLA FTP SERVER. FOLLOW THE STEPS BELOW.\rENSURE THAT FILEZILLA IS RUNNING.\rSTART THE FILEZILLA ADMINISTRATION INTERFACE BY CLICKING THE \"ADMIN\" BUTTON IN THE XAMPP CONTROL PANEL.\rIN THE RESULTING \"CONNECT TO SERVER\" DIALOG BOX, LEAVE ALL VALUES AT THEIR DEFAULT VALUES AND CLICK \"OK\".\rYOU SHOULD NOW ARRIVE AT THE FILEZILLA SERVER CONSOLE.\rYOU NOW NEED TO SET UP AT LEAST ONE FTP USER. TO DO THIS, CLICK THE \"EDIT ? USERS\" MENU ITEM. THIS WILL BRING YOU TO THE USER MANAGEMENT INTERFACE.\rCLICK THE \"ADD\" BUTTON TO ADD A NEW USER ACCOUNT. ENTER A NAME FOR THE NEW USER ACCOUNT.\rSELECT AND CHECK THE \"PASSWORD\" FIELD AND ENTER A PASSWORD FOR THE NEW USER.\rNEXT, YOU NEED TO DEFINE WHICH FOLDERS THE USER HAS ACCESS TO. TO DO THIS, CLICK THE \"SHARED FOLDER\" SUB-ITEM IN THE LEFT NAVIGATION MENU.\rCLICK THE \"ADD\" BUTTON AND SELECT THE \rHTDOCS\\\rSUBDIRECTORY OF THE XAMPP INSTALLATION DIRECTORY AS THE USERS HOME DIRECTORY.\rGRANT THE USER ALL AVAILABLE RIGHTS TO THIS DIRECTORY.\rCLICK \"OK\" TO SAVE YOUR CHANGES.\rUSE THE \"FILE ? QUIT\" MENU ITEM TO DISCONNECT FROM THE FILEZILLA ADMINISTRATION INTERFACE.\rYOU CAN NOW TRANSFER FILES TO THE XAMPP SERVER BY FOLLOWING THE STEPS BELOW:\rLAUNCH YOUR FTP CLIENT AND ENTER CONNECTION DETAILS AS BELOW.\rIF YOU’RE CONNECTING TO THE SERVER FROM THE SAME SYSTEM, USE \"127.0.0.1\" AS THE HOST ADDRESS. IF YOU’RE CONNECTING FROM A DIFFERENT SYSTEM, USE THE NETWORK HOSTNAME OR IP ADDRESS OF THE XAMPP SERVER.\rUSE \"21\" AS THE PORT.\rSPECIFY THE USERNAME AND PASSWORD CONFIGURED PREVIOUSLY AS YOUR FTP CREDENTIALS.\rYOUR FTP CLIENT SHOULD NOW CONNECT TO THE SERVER AND ENTER THE \rC:\\XAMPP\\HTDOCS\rDIRECTORY, WHICH IS THE DEFAULT WEB SERVER DOCUMENT ROOT.\rTRANSFER THE FILE FROM YOUR HOME DIRECTORY TO THE SERVER USING NORMAL FTP TRANSFER CONVENTIONS. IF YOU’RE USING A GRAPHICAL FTP CLIENT, YOU CAN USUALLY DRAG AND DROP THE FILE FROM ONE DIRECTORY TO THE OTHER. IF YOU’RE USING A COMMAND-LINE FTP CLIENT, YOU CAN USE THE FTP PUT COMMAND.\rONCE THE FILE IS SUCCESSFULLY TRANSFERRED, YOU SHOULD BE ABLE TO SEE IT IN ACTION BY BROWSING TO \rHTTP://LOCALHOST/EXAMPLE.PHP\r, AS SHOWN BELOW:\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(32,'738bd55915ba8ecd88510c11f4954c90','TROUBLESHOOT APACHE STARTUP PROBLEMS\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nTROUBLESHOOT-APACHE.PDF\rCONTENTS\rPORT 80 IN USE BY PID 4\rPORTS 80 AND 443 IN USE BY SKYPE\rPORT 443 IN USE BY VMWARE\rSERVERROOT MUST BE A VALID DIRECTORY\rXAMPP CANNOT START ON PORT 80 (WINDOWS 10)\rTHE MICROSOFT EDGE BROWSER CANNOT BE USED TO ACCESS LOCAL ADDRESSES USING THE MACHINE HOST NAME.\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rARE YOU HAVING DIFFICULTY GETTING YOUR APACHE SERVER STARTED? HERE IS A LIST OF COMMON PROBLEMS AND THEIR SOLUTIONS.\rTHE INFORMATION IN THIS DOCUMENT IS BASED ON \rTHIS APACHEFRIENDS COMMUNITY FORUM THREAD\r.\nPORT 80 IN USE BY PID 4\rYOUR XAMPP CONTROL PANEL DISPLAYS THIS MESSAGE:\rXX:XX:XX [APACHE] PORT 80 IN USE BY \"UNABLE TO OPEN PROCESS\" WITH PID 4!\rTO SOLVE THIS PROBLEM, FOLLOW THESE STEPS:\rRIGHT-CLICK THE XAMPP CONTROL PANEL ICON AND SELECT \"RUN AS ADMINISTRATOR\". ENTER ADMINISTRATOR CREDENTIALS (IF REQUIRED) AND CLICK \"OK\" OR \"YES\" TO PROCEED.\rOPEN YOUR WINDOWS COMMAND PROMPT BY CLICKING THE \"SHELL\" BUTTON IN THE XAMPP CONTROL PANEL.\rAT THE COMMAND PROMPT, ENTER THIS COMMAND:\rNETSH HTTP ADD IPLISTEN IPADDRESS=::\rOPEN THE FILE \rC:\\WINDOWS\\SYSTEM32\\DRIVERS\\ETC\\HOSTS\rAND ADD THE FOLLOWING LINE TO IT. THEN, SAVE THE FILE.\r127.0.0.1 LOCALHOST\rTHIS TAKES CARE OF MAPPING THE \rLOCALHOST\rDOMAIN NAME TO THE LOCAL MACHINE, WHICH ALWAYS HAS THE IP ADDRESS 127.0.0.1.\rON SOME VERSIONS OF WINDOWS, YOU WILL NOT BE ABLE TO EDIT THE \rC:\\WINDOWS\\SYSTEM32\\DRIVERS\\ETC\\HOSTS\rFILE WITHOUT ADMINISTRATOR PRIVILEGES. YOU CAN EDIT THE FILE BY RIGHT-CLICKING THE NOTEPAD ICON AND SELECTED THE \"RUN AS ADMINISTRATOR\" MENU OPTION, THEN ENTERING ADMINISTRATOR CREDENTIALS (IF REQUIRED) AND CLICKING \"OK\" OR \"YES\" TO PROCEED.\nIF THE PROBLEM PERSISTS EVEN AFTER PERFORMING THESE STEPS, IT COULD BE DUE TO A PROBLEM WITH MICROSOFT INTERNET INFORMATION SERVICES (IIS), WITH WINDOWS WORK FOLDERS OR WITH THIRD-PARTY SERVICES. \rREFER TO THIS PAGE FOR ALTERNATIVE SOLUTIONS\r.\nPORTS 80 AND 443 IN USE BY SKYPE\rYOUR XAMPP CONTROL PANEL DISPLAYS THESE MESSAGES:\rXX:XX:XX [APACHE] PORT 80 IN USE BY \"C:\\PROGRAM FILES (X86)\\SKYPE\\PHONE\\SKYPE.EXE\" WITH PID XXXX!\nXX:XX:XX [APACHE] PORT 443 IN USE BY \"C:\\PROGRAM FILES (X86)\\SKYPE\\PHONE\\SKYPE.EXE\" WITH PID XXXX!\rTO SOLVE THIS PROBLEM, FOLLOW THESE STEPS:\rLAUNCH SKYPE.\rSELECT THE \"TOOLS ? OPTIONS ? ADVANCED ? CONNECTION\" MENU ITEM AND IN THE RESULTING SCREEN, DISABLE THE USE OF PORTS 80 AND 443 FOR INCOMING SKYPE CONNECTIONS.\rCLICK \"SAVE\". RESTART SKYPE FOR YOUR CHANGE TO TAKE EFFECT.\rPORT 443 IN USE BY VMWARE\rYOUR XAMPP CONTROL PANEL DISPLAYS THESE MESSAGES:\rXX:XX:XX [APACHE] PORT 443 IN USE BY \"\"C:\\PROGRAM FILES (X86)\\VMWARE\\VMWARE WORKSTATION\\VMWARE-HOSTD.EXE\" -U \"C:\\PROGRAMDATA\\VMWARE\\HOSTD\\CONFIG.XML\"\" WITH PID XXXX!\rTO SOLVE THIS PROBLEM, FOLLOW THESE STEPS:\rLAUNCH VMWARE WORKSTATION.\rUSE THE \"EDIT ? PREFERENCES ? SHARED VMS\" MENU AND IN THE RESULTING DIALOG, ENTER A NEW PORT NUMBER FOR THE VMWARE WORKSTATION SERVER.\rCLICK \"OK\" TO SAVE YOUR CHANGES. RESTART VMWARE WORKSTATION FOR YOUR CHANGE TO TAKE EFFECT.\rSERVERROOT MUST BE A VALID DIRECTORY\rAPACHE STARTUP INCLUDES AN ERROR MESSAGE LIKE THE ONE BELOW:\rHTTPD.EXE: SYNTAX ERROR ON LINE XX OF X:/XAMPP/APACHE/CONF/HTTPD.CONF: SERVERROOT MUST BE A VALID DIRECTORY\rTHIS IS A COMMON ISSUE FOR XAMPP INSTALLATIONS ON PORTABLE DEVICES. IT OCCURS IF THE APACHE CONFIGURATION FILE POINTS TO A DIRECTORY THAT NO LONGER EXISTS (FOR EXAMPLE, DUE TO A DRIVE LETTER CHANGE WHEN A PORTABLE DEVICE IS REMOVED AND REINSERTED). TO SOLVE THIS PROBLEM, FOLLOW THESE STEPS:\rIF THE APACHE SERVICE IS REGISTERED (INDICATED BY A GREEN CHECK MARK NEXT TO ITS NAME IN THE XAMPP CONTROL PANEL), UNREGISTER IT BY CLICKING THE CHECK MARK AND ANSWERING \"YES\" IN THE RESULTING DIALOG BOX.\rEDIT THE \rSETUP_XAMPP.BAT\rFILE IN YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r). WITHIN THE FILE, FIND THIS LINE:\r%PHP_BIN% -N -D OUTPUT_BUFFERING=0 %CONFIG_PHP%\rEDIT THE LINE TO INCLUDE THE SPECIAL DIRECTIVE \"USB\" AT THE END, SO THAT IT LOOKS LIKE THIS.\r%PHP_BIN% -N -D OUTPUT_BUFFERING=0 %CONFIG_PHP% USB\rSAVE YOUR CHANGES. THE, EXECUTE THE FILE BY DOUBLE-CLICKING IT IN THE WINDOWS EXPLORER OR EXECUTING IT AT THE COMMAND PROMPT. THIS WILL FIX ANY AND ALL WRONG BASE PATHS.\rXAMPP CANNOT START ON PORT 80 (WINDOWS 10)\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO CHECK WHETHER PORT 80 IS IN USE, OPEN A COMMAND PROMPT AND RUN THESE COMMANDS:\rNETSTAT -O -N -A | FINDSTR 0.0.0.0:80\nNETSTAT -O -N -A | FINDSTR 127.0.0.1:80\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \"WORLD WIDE WEB PUBLISHING SERVICE\" AND SELECT IT.\rCLICK THE LINK TO \"STOP THE SERVICE\".\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \"STARTUP TYPE\" FIELD, CHANGE THE STARTUP TYPE TO \"DISABLED\".\rCLICK \"OK\" TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rTHE MICROSOFT EDGE BROWSER CANNOT BE USED TO ACCESS LOCAL ADDRESSES USING THE MACHINE HOST NAME.\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS \rHTTP://MYHOST\rIN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES \rHTTP://127.0.0.1\rOR \rHTTP://LOCALHOST\r.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(33,'0b8f9c9a1663f5be068f9974bed308a3','USE A DIFFERENT PHP VERSION\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nUSE-DIFFERENT-PHP-VERSION.PDF\rUSE A DIFFERENT PHP VERSION\rIN MANY CASES, YOU MIGHT WANT TO USE XAMPP WITH A DIFFERENT PHP VERSION THAN THE ONE THAT COMES PRE-INSTALLED. YOU MIGHT DO THIS TO GET THE BENEFITS OF A NEWER VERSION OF PHP, OR TO REPRODUCE BUGS USING AN EARLIER VERSION OF PHP.\rTO USE A DIFFERENT VERSION OF PHP WITH XAMPP, FOLLOW THESE STEPS:\rDOWNLOAD A BINARY BUILD OF THE PHP VERSION THAT YOU WISH TO USE FROM THE PHP WEBSITE, AND EXTRACT THE CONTENTS OF THE COMPRESSED ARCHIVE FILE TO YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r). ENSURE THAT YOU GIVE IT A DIFFERENT DIRECTORY NAME TO AVOID OVERWRITING THE EXISTING PHP VERSION. FOR EXAMPLE, IN THIS TUTORIAL, WELL CALL THE NEW DIRECTORY \rC:\\XAMPP\\PHP5-6-0\r.\rENSURE THAT THE PHP BUILD YOU DOWNLOAD MATCHES THE APACHE BUILD (VC9 OR VC11) IN YOUR XAMPP PLATFORM.\nWITHIN THE NEW DIRECTORY, RENAME THE \rPHP.INI-DEVELOPMENT\rFILE TO \rPHP.INI\r. IF YOU PREFER TO USE PRODUCTION SETTINGS, YOU COULD INSTEAD RENAME THE \rPHP.INI-PRODUCTION\rFILE TO \rPHP.INI\r.\rEDIT THE \rHTTPD-XAMPP.CONF\rFILE IN THE \rAPACHE\\CONF\\EXTRA\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. WITHIN THIS FILE, SEARCH FOR ALL INSTANCES OF THE OLD PHP DIRECTORY PATH AND REPLACE THEM WITH THE PATH TO THE NEW PHP DIRECTORY CREATED IN STEP 1.\rIN PARTICULAR, BE SURE TO CHANGE THE LINES\rLOADFILE \"/XAMPP/PHP/PHP5TS.DLL\"\nLOADFILE \"/XAMPP/PHP/LIBPQ.DLL\"\nLOADMODULE PHP5_MODULE \"/XAMPP/PHP/PHP5APACHE2_4.DLL\"\rTO\rLOADFILE \"/XAMPP/PHP5-6-0/PHP5TS.DLL\"\nLOADFILE \"/XAMPP/PHP5-6-0/LIBPQ.DLL\"\nLOADMODULE PHP5_MODULE \"/XAMPP/PHP5-6-0/PHP5APACHE2_4.DLL\"\rREMEMBER TO ADJUST THE FILE AND DIRECTORY PATHS ABOVE TO REFLECT VALID PATHS ON YOUR SYSTEM.\nRESTART YOUR APACHE SERVER THROUGH THE XAMPP CONTROL PANEL FOR YOUR CHANGES TO TAKE EFFECT.\rTHE NEW VERSION OF PHP SHOULD NOW BE ACTIVE. TO VERIFY THIS, BROWSE TO THE URL \rHTTP://LOCALHOST/XAMPP/PHPINFO.PHP\r, WHICH DISPLAYS THE OUTPUT OF THE \rPHPINFO()\rCOMMAND, AND CHECK THE VERSION NUMBER AT THE TOP OF THE PAGE.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(34,'082db3f1b44a309187539b32109fffa6','RUN PHP UNDER FASTCGI\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nUSE-PHP-FCGI.PDF\rRUN PHP UNDER FASTCGI\rBY DEFAULT, XAMPP RUNS PHP AS AN APACHE HANDLER. AN ALTERNATIVE APPROACH IS TO RUN PHP UNDER FASTCGI, WHICH CAN PRODUCE BETTER PERFORMANCE IN CERTAIN SCENARIOS. TO DO THIS, FOLLOW THESE STEPS:\rDOWNLOAD A BINARY VERSION OF THE \rMOD_FCGID\rAPACHE MODULE FROM \rTHE APACHELOUNGE WEBSITE\r. THIS MODULE IS INCLUDED IN THE \rMODULES-2.4.X-WIN32-VC11.ZIP\rARCHIVE.\rXAMPP FOR WINDOWS ONLY USES 32-BIT APACHE BUILDS.\nEXTRACT THE \rMOD_FCGID.SO\rFILE FROM THE DOWNLOADED ARCHIVE FILE AND COPY IT TO THE \rAPACHE\\MODULES\r\\ SUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (USUALLY, \rC:\\XAMPP\r).\rEDIT THE \rHTTPD-XAMPP.CONF\rFILE IN THE \rAPACHE\\CONF\\EXTRA\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY. WITHIN THIS FILE, MAKE THE FOLLOWING CHANGES:\rSEARCH FOR THE LINE\rLOADMODULE PHP5_MODULE \"/XAMPP/PHP/PHP5APACHE2_4.DLL\"\rAND MODIFY IT TO READ\rLOADMODULE FCGID_MODULE MODULES/MOD_FCGID.SO\rFIND AND DELETE THE FOLLOWING LINES:\r<FILESMATCH \"\\.PHP$\">\nSETHANDLER APPLICATION/X-HTTPD-PHP\n</FILESMATCH>\n<FILESMATCH \"\\.PHPS$\">\nSETHANDLER APPLICATION/X-HTTPD-PHP-SOURCE\n</FILESMATCH>\rADD THE FOLLOWING LINES:\rFCGIDINITIALENV PHPRC \"C:/XAMPP/PHP\"\nADDHANDLER FCGID-SCRIPT .PHP\nFCGIDWRAPPER \"C:/XAMPP/PHP/PHP-CGI.EXE\" .PHP\rREMEMBER TO ADJUST THE FILE AND DIRECTORY PATHS ABOVE TO REFLECT VALID PATHS ON YOUR SYSTEM.\nRESTART YOUR APACHE SERVER THROUGH THE XAMPP CONTROL PANEL FOR YOUR CHANGES TO TAKE EFFECT.\rPHP SHOULD NOW BE ACTIVE USING FASTCGI. TO VERIFY THIS, BROWSE TO THE URL \rHTTP://LOCALHOST/XAMPP/PHPINFO.PHP\r, WHICH DISPLAYS THE OUTPUT OF THE \rPHPINFO()\rCOMMAND, AND CHECK THE \"SERVER API\" VALUE NEAR THE TOP OF THE PAGE.\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(35,'570260340967eb32d1555634307c9201','USE SQLITE AND PHP\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rDOCUMENTATION\rDOWNLOAD PDF\nUSE-SQLITE.PDF\rUSE SQLITE AND PHP\rXAMPP COMES WITH BUILT-IN SUPPORT FOR SQLITE, MAKING IT EASY TO GET STARTED BUILDING DATABASE-POWERED APPLICATIONS WITH PHP. THIS GUIDE WILL WALK YOU THROUGH THE PROCESS OF CREATING AND POPULATING A NEW SQLITE DATABASE USING XAMPP, THEN ACCESSING THE DATA WITHIN IT USING PHP.\rBEGIN BY CREATING AND POPULATING A NEW DATABASE USING THE SQLITE COMMAND-LINE CLIENT, AS BELOW:\rOPEN YOUR WINDOWS COMMAND PROMPT BY CLICKING THE “SHELL” BUTTON IN THE XAMPP CONTROL PANEL.\rCHANGE TO THE \rHTDOCS\\\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY (TYPICALLY \rC:\\XAMPP\r) AND CREATE A NEW SQLITE DATABASE FILE NAMED \rMYDB.SQ3\rWITH THE SQLITE COMMAND-LINE CLIENT:\rCD C:\\XAMPP\\HTDOCS\nSQLITE3 MYDB.SQ3\rYOU SHOULD NOW SEE AN SQLITE PROMPT, AS BELOW:\rAT THE \rSQLITE>\rPROMPT, CREATE A NEW TABLE TO HOLD YOUR DATA. IN THIS EXAMPLE, THE TABLE IS NAMED ITEMS AND IT CONTAINS 3 COLUMNS, FOR ITEM ID, ITEM NAME AND ITEM COST. YOU CAN USE STANDARD CREATE TABLE SYNTAX TO CREATE THE TABLE, AND YOU CAN \rLEARN MORE ABOUT SQLITES BUILT-IN DATATYPES HERE\r.\rCREATE TABLE ITEMS (ID INTEGER PRIMARY KEY, NAME TEXT, PRICE REAL);\rADD SOME DATA TO THE NEW INVENTORY TABLE USING INSERT COMMANDS, AS SHOWN BELOW:\rINSERT INTO ITEMS VALUES (\'1001\', \'SALT\', 3.15);\nINSERT INTO ITEMS VALUES (\'1002\', \'PEPPER\', 2.75);\nINSERT INTO ITEMS VALUES (\'1003\', \'EGGS\', 2.00);\nINSERT INTO ITEMS VALUES (\'1004\', \'BACON\', 7.25);\nINSERT INTO ITEMS VALUES (\'1005\', \'MILK\', 1.15);\nINSERT INTO ITEMS VALUES (\'1006\', \'STRAWBERRIES\', 8.73);\nINSERT INTO ITEMS VALUES (\'1007\', \'CEREAL\', 2.65);\rYOU CAN NOW ALSO RUN A SELECT QUERY ON THE DATA. FOR EXAMPLE, THE QUERY BELOW RETURNS ALL ITEMS THAT COST LESS THAN $3:\rSELECT * FROM ITEMS WHERE PRICE < 3.00;\rONCE YOURE DONE USING THE DATABASE, EXIT IT BY TYPING \r.QUIT\rAT THE \rSQLITE>\rPROMPT.\rTHE DATABASE FILE (IN THIS EXAMPLE, \rMYDB.SQ3\r) CONTAINS ALL YOUR TABLES AND DATA, SO YOU SHOULD REMEMBER TO BACK IT UP REGULARLY.\nTHE PREVIOUS STEPS DISCUSSED HOW TO CREATE AND USE AN SQLITE DATABASE USING THE COMMAND-LINE CLIENT. HOWEVER, MORE OFTEN THAN NOT, YOULL BE USING AN SQLITE DATABASE IN COMBINATION WITH A PHP-POWERED WEB APPLICATION. XAMPP INCLUDES THE PHP SQLITE EXTENSION, SO DOING THIS IS NOT VERY DIFFICULT AT ALL.\rTO CONNECT TO YOUR SQLITE DATABASE AND EXECUTE QUERIES ON IT WITH PHP, USE YOUR TEXT EDITOR TO CREATE AN EXAMPLE SCRIPT NAMED \rSQLITE.PHP\rIN THE \rHTDOCS\rSUBDIRECTORY OF YOUR XAMPP INSTALLATION DIRECTORY AND FILL IT WITH THE FOLLOWING CODE:\r<?PHP\n$DB = NEW SQLITE3(\'MYDB.SQ3\');\n$SQL = \"SELECT * FROM ITEMS WHERE PRICE < 3.00\";\n$RESULT = $DB->QUERY($SQL);\nWHILE ($ROW = $RESULT->FETCHARRAY(SQLITE3_ASSOC)){\nECHO $ROW[\'NAME\'] . \': $\' . $ROW[\'PRICE\'] . \'<BR/>\';\n}\nUNSET($DB);\rTHE FIRST LINE OF CODE CREATES A NEW SQLITE3 OBJECT, USING THE \rMYDB.SQ3\rDATABASE FILE YOU CREATED EARLIER. THEN, THE OBJECTS \rQUERY()\rMETHOD IS USED TO EXECUTE A SELECT QUERY ON THE DATABASE, AND THE RESULT OBJECTS \rFETCHARRAY()\rMETHOD IS USED TO ITERATE OVER THE RESULT SET. ADDING THE SQLITE3_ASSOC PARAMETER TO THE \rFETCHARRAY()\rMETHOD TELLS PHP TO RETURN THE RESULTS AS AN ASSOCIATIVE ARRAY, MAKING IT EASY TO ACCESS INDIVIDUAL FIELDS OF THE RESULT SET AND DISPLAY THEM ON A WEB PAGE.\rONCE DONE, SAVE YOUR CHANGES AND ENSURE THAT YOUR APACHE SERVER IS RUNNING. THEN, BROWSE TO \rHTTP://LOCALHOST/SQLITE.PHP\rTO EXECUTE THE SCRIPT. YOU SHOULD SEE SOMETHING LIKE THIS:\rTO FIND OUT MORE ABOUT SQLITE’S POWERFUL FEATURES, \rREAD THE SQLITE DOCUMENTATION\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(36,'c7dc304781b1f806db2c5e70293da113','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rPREGUNTAS FRECUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rPREGUNTAS FRECUENTES\r¿CÓMO INSTALO XAMPP?\rEXISTEN TRES TIPOS DIFERENTES DE XAMPP PARA WINDOWS:\rINSTALADOR:\rPROBABLEMENTE LA FORMA MÁS FÁCIL DE INSTALAR XAMPP.\rZIP:\rPARA PURISTAS: XAMPP COMO ARCHIVO ZIP.\r7ZIP:\rPARA PURISTAS CON ANCHO DE BANDA BAJO: XAMPP COMO ARCHIVO 7ZIP.\rNOTA: SI EXTRAES LOS FICHEROS, PUEDE HABER FALSOS AVISOS DE VIRUS.\rUSANDO EL INSTALADOR:\rEL PANEL DE CONTROL DE XAMPP PARA INICIAR/DETENER APACHE, MYSQL, FILEZILLA Y MERCURY O INSTALAR ESOS SERVIDORES COMO SERVICIOS.\rINSTALANDO DESDE ZIP\rDESCOMPRIME LOS ARCHIVOS ZIP EN LA CARPETA QUE ELIJAS. XAMPP ES EXTRAIDO EN EL SUBDIRECTORIO \"C:\\\\XAMPP\" EN EL DIRECTORIO DE DESTINO SELECCIONADO. AHORA EJECUTA EL FICHERO \"SETUP_XAMPP.BAT\" PARA AJUSTAR LA CONFIGURACIÓN DE XAMPP EN TU SISTEMA.\rSI ELIJES UN DIRECTORIO RAÍZ, COMO \"C:\\\\\", NO DEBES EJECUTAR \"SETUP_XAMPP.BAT\".\rAL IGUAL QUE CON EL INSTALADOR, PUEDES USAR AHORA EL \"XAMPP CONTROL PANEL\" PARA TAREAS ADICIONALES.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\r¿CÓMO INICIO XAMPP SIN INSTALAR?\rSI EXTRAES XAMPP EN UN DIRECTORIO PRINCIPAL COMO \"C:\\\\\" O \"D:\\\\\", PUEDES INICIAR LA MAYORÍA DE LOS SERVIDORES COMO APACHE O MYSQL DIRECTAMENTE SIN EJECUTAR EL ARCHIVO \"SETUP_XAMPP.BAT\".\rNO USAR EL SCRIPT DE INSTALACIÓN, O SELECCIONAR PATHS RELATIVOS EN EL SCRIPT DE INSTALACIÓN, ES PREFERIBLE SI ESTÁS INSTALANDO XAMPP EN UN DISCO DURO USB, DEBIDO A QUE EN CADA ORDENADOR ESE DISPOSITIVO PUEDE ESTAR EN UNA UNIDAD DISTINTA. PUEDES CAMBIAR DE PATHS ABSOLUTOS A RELATIVOS CUANDO QUIERAS CON EL SCRIPT DE INSTALACIÓN.\rUSAR EL INSTALADOR DE NUESTRA PÁGINA DE DESCARGAS ES LA FORMA MÁS FÁCIL DE INSTALAR XAMPP. CUANDO LA INSTALACIÓN SE COMPLETE, ENCONTRARÁS XAMPP EN INICIO | PROGRAMAS | XAMPP. PUEDES USAR EL PANEL DE CONTROL DE XAMPP PARA INICIAR/PARAR TODOS LOS SERVIDORES Y TAMBIÉN PARA INSTALAR/DESINSTALAR SERVICIOS.\rEL PANEL DE CONTROL DE XAMPP PARA INICIAR/DETENER APACHE, MYSQL, FILEZILLA Y MERCURY O INSTALAR ESOS SERVIDORES COMO SERVICIOS.\r¿CÓMO INICIO Y PARO XAMPP?\rEL CENTRO DE CONTROL PRINCIPAL ES EL \"XAMPP CONTROL PANEL\" (GRACIAS WWW.NAT32.COM). SE INICIA CON:\r\\XAMPP\\XAMPP-CONTROL.EXE\rPUEDES TAMBIÉN USAR ALGUNOS FICHEROS BATCH PARA INICIAR/PARAR SERVIDORES:\rINICIAR APACHE Y MYSQL:\n\\XAMPP\\XAMPP_START.EXE\rPARAR APACHE Y MYSQL:\n\\XAMPP\\XAMPP_STOP.EXE\rINICIAR APACHE:\n\\XAMPP\\APACHE_START.BAT\rDETENER APACHE:\n\\XAMPP\\APACHE_STOP.BAT\rINICIAR MYSQL:\n\\XAMPP\\MYSQL_START.BAT\rPARA MYSQL:\n\\XAMPP\\MYSQL_STOP.BAT\rINICIAR MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_START.BAT\rPARAR MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_STOP.BAT\rINICIAR SERVIDOR FILEZILLA:\n\\XAMPP\\FILEZILLA_START.BAT\rPARAR SERVIDOR FILEZILLA:\n\\XAMPP\\FILEZILLA_STOP.BAT\r¿CÓMO COMPRUEBO QUE TODO HA IDO BIEN?\rESCRIBE LA SIGUIENTE URL EN TU NAVEGADOR FAVORITO:\rHTTP://LOCALHOST/\rO \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\r¿CÓMO PUEDO INSTALAR UN SERVIDOR COMO SERVICIO?\rPUEDES INSTALAR CADA SERVIDOR EN XAMPP COMO SERVICIO DE WINDOWS. TAMBIÉN PUEDES INSTALARLO DESDE EL PANEL DE CONTROL DE XAMPP. EN ESTE CASO, ES NECESARIO EJECUTAR LOS SCRIPTS O EL PANEL DE CONTROL CON PRIVILEGIOS DE ADMINISTRADOR.\rINSTALAR EL SERVICIO APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rDESINSTALAR EL SERVICIO APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rINSTALAR EL SERVICIO MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rDESINSTALAR EL SERVICIO MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \r(DES)INSTALACIÓN DEL SERVICIO FILEZILLA: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: NO DISPONIBLE LA INSTALACIÓN DE SERVICIO\r¿ESTÁ XAMPP LISTO PARA PRODUCCIÓN?\rXAMPP NO ESTÁ PENSADO PARA USO EN PRODUCCIÓN, SINO PARA ENTORNOS DE DESARROLLO. XAMPP ESTÁ CONFIGURADO DE FORMA QUE SEA TAN ABIERTO COMO SEA POSIBLE, PERMITIENDO AL DESARROLLADOR HACER LO QUE QUIERA. EN ENTORNOS DE DESARROLLO ESTO ES MAGNÍFICO PERO EN UN ENTORNO DE PRODUCCIÓN PUEDE SER FATAL.\rA CONTINUACIÓN SE MUESTRA UNA LISTA DE POSIBLES FALLOS DE SEGURIDAD EN XAMPP:\rEL ADMINISTRADOR DE MYSQL (ROOT) NO TIENE PASSWORD.\rEL PROCESO MYSQL ESTÁ ACCESIBLE A TRAVÉS DE LA RED.\rPROFTPD USA LA CONTRASEÑA \"LAMPP\" PARA EL USUARIO \"DAEMON\".\rLOS USUARIOS POR DEFECTO DE MERCURY Y FILEZILLA SON CONOCIDOS.\rTODO ESTO PUEDE SER UN ENORME RIESGO DE SEGURIDAD. ESPECIALMENTE SI XAMPP ESTÁ ACCESIBLE A TRAVÉS DE LA RED Y GENTE FUERA DE TU LAN. PARA MEJORAR LA SEGURIDAD, PUEDE AYUDAR EL USO DE UN FIREWALL O UN ROUTER (NAT). EN EL CASO DE UN ROUTER O FIREWALL, TU PC NO ESTARÁ NORMALMENTE ACCESIBLE A TRAVÉS DE LA RED. DEPENDE DE TI ARREGLAR ESTOS PROBLEMAS. UNA PEQUEÑA AYUDA ES LA \"CONSOLA DE SEGURIDAD DE XAMPP\".\rPOR FAVOR, ESTABLECE SEGURIDAD EN XAMPP ANTES DE PUBLICAR NADA ONLINE. UN FIREWALL O UN ROUTER SÓLO SON CORRECTOS PARA BAJOS NIVELES DE SEGURIDAD. PARA ALGO MÁS DE SEGURIDAD, PUEDES EJECUTAR LA \"CONSOLA DE SEGURIDAD DE XAMPP\" Y ASIGNAR CONTRASEÑAS.\rSI QUIERES TENER TU XAMPP ACCESIBLE DESDE INTERNET, VE A LA SIGUIENTE URI QUE PUEDE ARREGLAR ALGUNOS PROBLEMAS:\rHTTP://LOCALHOST/SECURITY/\rCON LA CONSOLA DE SEGURIDAD PUEDES ESTABLECER UNA CONTRASEÑA PARA EL USUARIO \"ROOT\" DE MYSQL Y PHPMYADMIN. PUEDES TAMBIÉN HABILITAR AUTENTICACIÓN PARA LAS PÁGINAS DE EJEMPLO DE XAMPP.\r¡ESTA HERRAMIENTA WEB NO CORRIGE NINGÚN PROBLEMA ADICIONAL DE SEGURIDAD! ESPECIALMENTE, DEBES ESTABLECER TU PROPIA SEGURIDAD EN LOS SERVIDORES FILEZILLA FTP Y MERCURY.\r¿CÓMO DESINSTALO XAMPP?\rSI INSTALASTE XAMPP USANDO LA VERSIÓN DE INSTALADOR, POR FAVOR, USA EL DESINSTALADOR. EL DESINSTALADOR ELIMINARÁ TODAS LAS ENTRADAS DE XAMPP DE TU REGISTRO Y DESINSTALARÁ ALGUNOS SERVICIOS INCLUIDOS CON XAMPP. RECOMENDAMOS FERVIENTEMENTE QUE USES EL PROGRAMA DE DESINSTALACIÓN PARA ELIMINAR LAS INSTALACIONES DE XAMPP REALIZADAS CON EL INSTALADOR. POR FAVOR, HAZ COPIA DE SEGURIDAD DE TODOS LOS DATOS QUE QUIERAS MANTENER ANTES DE DESINSTALAR XAMPP.\rSI INSTALASTE XAMPP USANDO LAS VERSIONES ZIP O 7ZIP, APAGA TODOS LOS SERVIDORES DE XAMPP Y SAL DE TODOS LOS PANELES. SI INSTALASTE ALGÚN SERVICIO, APÁGALO Y DESINSTÁLALO TAMBIÉN. AHORA SIMPLEMENTE BORRA EL DIRECTORIO COMPLETO DONDE XAMPP ESTÁ INSTALADO. NO HAY ENTRADAS NI VARIABLES DE ENTORNO QUE DEBAS BORRAR.\r¿QUÉ ES LA VERSIÓN \"LITE\" DE XAMPP?\rXAMPP LITE (SIGNIFICA \"LIGERO\" COMO EN \"PESO LIGERO\") ES UN CONJUNTO MÁS PEQUEÑO DE LOS COMPONENTES DE XAMPP, EL CUAL ES RECOMENDADO PARA TRABAJO RÁPIDO USANDO SÓLO PHP Y MYSQL. ALGUNOS SERVIDORES O HERRAMIENTAS COMO MERCURY MAIL Y FILEZILLA FTP NO ESTÁN INCLUIDOS EN LA VERSIÓN LITE.\r¿DÓNDE DEBO COLOCAR MI CONTENIDO WEB?\rEL DIRECTORIO PRINCIPAL PARA LOS DOCUMENTOS WWW ES \\\\XAMPP\\\\HTDOCS. SI PONES UN FICHERO \"TEST.HTML\" EN ESTE DIRECTORIO, PUEDES ACCEDER A ÉL CON LA URI \"HTTP://LOCALHOST/TEST.HTML\".\r¿Y \"TEST.PHP\"? SIMPLEMENTE USA \"HTTP://LOCALHOST/TEST.PHP\". UN FICHERO DE TEST SIMPLE PUEDE SER:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\r¿UN NUEVO SUBDIRECTORIO PARA TU WEB? SIMPLEMENTE CREA UN NUEVO DIRECTORIO (P.EJ. \"NEW\") DENTRO DEL DIRECTORIO \"\\\\XAMPP\\\\HTDOCS\" (MEJOR SIN ESPACIOS Y SÓLO CARACTERES ASCII), CREA UN FICHERO DE EJEMPLO EN ESTE DIRECTORIO Y ACCEDE A EL CON \"HTTP://LOCALHOST/NEW/TEST.PHP\".\rESPECÍFICAMENTE\rHTML:\rEJECUTABLE: \\XAMPP\\HTDOCS\rFINALES PERMITIDOS: .HTML .HTM\r=> PAQUETE BASICO\rSSI:\rEJECUTABLE: \\XAMPP\\HTDOCS\rFINALES PERMITIDOS: .SHTML\r=> PAQUETE BASICO\rCGI:\rEJECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rFINALES PERMITIDOS: .CGI\r=> PAQUETE BASICO\rPHP:\rEJECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rFINALES PERMITIDOS: .PHP\r=> PAQUETE BASICO\rPERL:\rEJECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rFINALES PERMITIDOS: .PL\r=> PAQUETE BASICO\rAPACHE::ASP PERL:\rEJECUTABLE: \\XAMPP\\HTDOCS\rFINALES PERMITIDOS: .ASP\r=> PAQUETE BASICO\rJSP JAVA:\rEJECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rFINALES PERMITIDOS: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rEJECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rFINALES PERMITIDOS: .HTML (U.A)\r=> TOMCAT ADD-ON\r¿PUEDO MOVER LA INSTALACIÓN DE XAMPP?\rSÍ. TRAS MOVER EL DIRECTORIO DE XAMPP, DEBES EJECUTAR \"SETUP_XAMPP.BAT\". LOS PATHS DE LOS DIRECTORIOS DE CONFIGURACIÓN SE AJUSTARÁN CON ESTE PASO.\rSI HAS INSTALADO ALGÚN SERVIDOR COMO SERVICIO DE WINDOWS, DEBES PRIMERO ELIMINAR EL SERVICIO DE WINDOWS Y DESPUÉS DE MOVER, PODRÁS INSTALAR EL SERVICIO DE NUEVO.\rAVISO: LOS FICHEROS DE CONFIGURACIÓN DE TUS PROPIOS SCRIPTS, COMO APLICACIONES PHP, NO SERÁN AJUSTADOS. PERO ES POSIBLE ESCRIBIR UN \"PLUG-IN\" PARA EL INSTALADOR. CON ESE PLUG-IN, EL INSTALADOR PUEDE AJUSTAR ESOS FICHEROS TAMBIÉN.\r¿QUÉ SON LAS \"PÁGINAS DE INICIO AUTOMÁTICO\" DE LOS DIRECTORIOS WWW?\rEL NOMBRE DEL FICHERO POR DEFECTO PARA LA FUNCIÓN DE APACHE \"DIRECTORYINDEX\" ES \"INDEX.HTML\" O \"INDEX.PHP\". CADA VEZ QUE NAVEGAS A UNA CARPETA (E.J. \"HTTP://LOCALHOST/XAMPP/\"), Y APACHE PUEDE ENCONTRAR ESE FICHERO, APACHE LO MUESTRA EN EN LUGAR DE UN LISTADO DE DIRECTORIO.\r¿DÓNDE PUEDO CAMBIAR LA CONFIGURACIÓN?\rCASI TODAS LAS OPCIONES DE XAMPP PUEDEN CAMBIARSE CON FICHEROS DE CONFIGURACIÓN. SIMPLEMENTE ABRE EL FICHERO EN UN EDITOR DE TEXTO Y CAMBIA LAS OPCIONES QUE QUIERAS. SÓLO FILEZILLA Y MERCURY DEBERÍAN SER CONFIGURADAS CON LA HERRAMIENTA DE CONFIGURACIÓN DE APLICACIONES.\r¿POR QUÉ NO FUNCIONA XAMPP EN WINDOWS XP SP2?\rMICROSOFT INCLUYE UN MEJOR FIREWALL CON SERVICE PACK 2 (SP2), QUE SE INICIA AUTOMÁTICAMENTE. ESTE FIREWALL BLOQUEA LOS PUERTOS 80 (HTTP) Y 443 (HTTPS), NECESARIOS PARA APACHE, QUE NO PUEDE INICIARSE.\rLA SOLUCIÓN RÁPIDA:\rDESHABILITA EL FIREWALL DE MICROSOFT CON EL BARRA DE HERRAMIENTAS E INTENTA INICIAR XAMPP OTRA VEZ. LA MEJOR SOLUCIÓN ES DEFINIR UNA EXCEPCIÓN EN EL CENTRO DE SEGURIDAD.\rLOS SIGUIENTES PUERTOS SON USADOS PARA FUNCIONALIDADES BÁSICAS:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\r¿POR QUÉ NO FUNCIONA XAMPP EN VISTA?\rCONTROL DE CUENTAS DE USUARIO (UAC)\rNO TIENES TOTALES PRIVILEGIOS DE ESCRITURA EN EL DIRECTORIO \"C:\\\\ARCHIVOS DE PROGRAMAS\", NI SIQUIERA COMO ADMINISTRADOR. O TIENES SÓLO PRIVILEGIOS LIMITADOS (P.EJ. EN \".\\\\XAMPP\\\\HTDOCS\"). ES ESTE CASO, NO PUEDES EDITAR UN FICHERO.\rSOLUCIÓN:\rAUMENTA TUS PRIVILEGIOS EN EL EXPLORADOR (BOTÓN DERECHO / SEGURIDAD) O DESHABILITA EL CONTROL DE CUENTAS DE USUARIO (UAC).\rHAS INSTALADO APACHE/MYSQL EN \"C:\\\\XAMPP\" COMO SERVICIO DE WINDOWS. PERO NO PUEDES INICIAR/PARAR LOS SERVICIOS CON EL \"XAMPP CONTROL PANEL\" O NO PUEDES DESINSTALARLOS.\rSOLUCIÓN:\rUSA LA CONSOLA DE ADMINISTRACIÓN DE WINDOWS O DESHABILITA UAC.\rDESHABILITANDO EL CONTROL DE CUENTA DE USUARIO (UAC)\rPARA DESHABILITAR EL UAC, USA EL PROGRAMA \"MSCONFIG\". EN \"MSCONFIG\" VE A \"HERRAMIENTAS\", SELECCIONA \"DESHABILITAR EL CONTROL DE CUENTAS DE USUARIO\" Y VERIFICA TU SELECCIÓN. AHORA DEBES REINICIAR WINDOWS. SI QUIERES VOLVER A HABILITA LA UAC, PUEDES HACERLO DEL MISMO MODO.\r¿CÓMO COMPRUEBO EL CHECKSUM MD5?\rPARA COMPARAR FICHEROS, NORMALMENTE SE USAN CHECKSUMS. UN ESTÁNDAR PARA CREAR ESTE CHECKSUM ES MD5 (MESSAGE DIGEST ALGORITHM 5).\rCON ESTE CHECKSUM MD5 PUEDES COMPROBAR SI TU DESCARGA DEL PAQUETE XAMPP ES CORRECTO O NO. POR SUPUESTO, NECESITAS UN PROGRAMA QUE PUEDE CREAR ESTOS CHECKSUMS. PARA WINDOWS PUEDES USAR UNA HERRAMIENTA DE MICROSOFT:\rDISPONIBILIDAD Y DESCRIPCIÓN DE LA UTILIDAD FILE CHECKSUM INTEGRITY VERIFIER\rTAMBIÉN ES POSIBLE USAR CUALQUIER OTRO PROGRAMA QUE CREE CHECKSUMS MD5, COMO GNU MD5SUM.\rPARA INSTALAR UN PROGRAMA ASÍ (P.EJ. FCIV.EXE), PUEDES SEGUIR LOS SIGUIENTES PASOS:\rDESCARGA XAMPP (P.EJ. XAMPP-WIN32-1.8.2-0.EXE)\rCREA EL CHECKSUM CON:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rY AHORA PUEDES COMPARAR ESTE CHECKSUM CON EL QUE PUEDES ENCONTRAR EN LA PÁGINA DE XAMPP PARA WINDOWS.\rSI AMBOS CHECKSUMS SON IGUALES, TODO ESTÁ BIEN. SI NO, LA DESCARGA ESTÁ DAÑADA O EL FICHERO HA SIDO MODIFICADO.\r¿POR QUÉ LO CAMBIOS REALIZADOS EN MI PHP.INI NO TIENEN EFECTO?\rSI UN CAMBIO EN EL \"PHP.INI\" NO TIENE EFECTO, ES POSIBLE QUE PHP ESTÉ USANDO UNO DIFERENTE. PUEDES VERIFICARLO CON PHPINFO(). VE A LA URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP Y BUSCA \"LOADED CONFIGURATION FILE\". ESTE VALOR MUESTRA EL \"PHP.INI\" QUE PHP ESTÁ USANDO REALMENTE.\rNOTA:\rTRAS CAMBIAR EL \"PHP.INI\" DEBES REINICIAR APACHE PARA QUE APACHE/PHP PUEDAN LEER LA NUEVA CONFIGURACIÓN.\r¡AYUDA! ¡HAY UN VIRUS EN XAMPP!\rALGUNOS PROGRAMAS DE ANTIVIRUS CONFUNDEN XAMPP CON UN VIRUS, NORMALMENTE APUNTANDO AL FICHERO XAMPP-MANAGER.EXE. ESTO ES UN FALSO POSITIVO, LO QUE SIGNIFICA QUE EL ANTIVIRUS LO IDENTIFICA ERRÓNEAMENTE COMO UN VIRUS, CUANDO NO ES ASÍ. ANTES DE LANZAR CADA VERSIÓN DE XAMPP LA EJECUTAMOS CON UN PROGRAMA DE ESCANEO DE VIRUS. EN ESTOS MOMENTOS USAMOS \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\r¿CÓMO CONFIGURO MI APLICACIÓN DE ANTIVIRUS?\rHEMOS INCLUIDO TODAS LAS DEPENDENCIAS Y SERVIDORES REQUERIDOS PARA EJECUTAR LA APLICACIÓN WEB INCLUIDA, POR LO QUE COMPROBARÁS QUE XAMPP INSTALA UN GRAN NÚMERO DE FICHEROS. SI ESTÁS INSTALANDO UNA APLICACIÓN XAMPP EN UNA MÁQUINA DE WINDOWS CON UN ANTIVIRUS ACTIVADO, PUEDE RALENTIZAR LA INSTALACIÓN SIGNIFICATIVAMENTE, Y HAY TAMBIÉN POSIBILIDADES DE QUE UNO DE LOS SERVIDORES (SERVIDOR WEB, SERVIDOR DE BASE DE DATOS) SEA BLOQUEADO POR EL ANTIVIRUS. SI TIENES UNA HERRAMIENTA DE ANTIVIRUS HABILITADA, COMPRUEBA LAS SIGUIENTES OPCIONES PARA EJECUTAR XAMPP SIN PROBLEMAS DE RENDIMIENTO:\rAÑADE EXCEPCIONES EN EL FIREWALL: PARA APACHE, MYSQL O CUALQUIER OTRO SERVIDOR.\rESCANEAR LOS FICHEROS MIENTRAS SE EJECUTAN: SI TIENES HABILITADO QUE EL ANTIVIRUS ESCANEE TODOS LOS FICHEROS, LOS FICHEROS EJECUTABLES DE LOS SERVIDORES PUEDEN RALENTIZARSE.\rESCANEAR EL TRÁFICO DE LAS DISTINTAS URLS: SI ESTÁS DESARROLLANDO CON XAMPP EN TU PROPIA MÁQUINA, PUEDES EXCLUIR EL TRÁFICO DE \"LOCALHOST\" EN LAS OPCIONES DE TU ANTIVIRUS.\r¿POR QUÉ NO SE INICIA EL SERVIDOR DE APACHE EN MI SISTEMA?\rESTE PROBLEMA PUEDE DEBERSE A VARIAS RAZONES:\rHAS INICIADO MÁS DE UN SERVIDOR HTTP (IIS, SAMBAR, ZEUS AND SO ON). SÓLO PUEDE HABER UN SERVIDOR USANDO EL PUERTO 80. ESTE MENSAJE DE ERROR INDICA EL PROBLEMA:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rTIENES OTRO SOFTWARE, COMO \"SKYPE\" QUE TAMBIÉN BLOQUEA EL PUERTO 80. SI EL PROBLEMA ES \"SKYPE\", PUEDES IR EN SKYPE A ACCIONES->OPCIONES->CONEXIÓN->ELIMINAR LA MARCA DE VERIFICACIÓN EN \"USAR PUERTO 80 EN LUGAR DE OTRO PUERTO\" Y REINICIAR SKYPE. AHORA DEBERÍA FUNCIONAR.\rTIENES UN FIREWALL QUE BLOQUEA EL PUERTO APACHE. NO TODOS LOS FIREWALLS SON COMPATIBLES CON APACHE, Y A VECES DESACTIVAR EL FIREWALL NO ES SUFICIENTE Y DEBES DESINSTALARLO. ESTE MENSAJE DE ERROR INDICA QUE HAY UN FIREWALL:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rSI APACHE PUEDE INICIARSE, PERO TU NAVEGADOR NO PUEDE CONECTARSE A ÉL, TAMBIÉN PUEDE DEBERSE A UNO DE LOS SIGUIENTES MOTIVOS:\rALGUNOS ANTIVIRUS Y FIREWALLS PUEDEN CAUSAR ESTE PROBLEMA.\rTIENES XP PROFESSIONAL SIN EL SERVICE PACK 1. DEBES TENER AL MENOS SP1 PARA USAR XAMPP.\rCONSEJO:\rSI TIENES PROBLEMAS CON LOS PUERTOS USADOS, PUEDES USAR LA HERRAMIENTA \"XAMPP-PORTCHECK.EXE\". TAL VEZ TE AYUDE.\r¿POR QUÉ MI CARGA DE CPU EN APACHE ESTÁ CASI AL 99%?\rHAY DOS OPCIONES AQUÍ. O LA CPU HA ALCANZADO SU MÁXIMO, O PUEDES CONECTARTE AL SERVIDOR, PERO NO VES NADA (EL SISTEMA ESTÁ INTENTANDO SIN ÉXITO CARGAR LA PÁGINA). EN CUALQUIER CASO, PUEDES ENCONTRAR EL SIGUIENTE MENSAJE EN EL FICHERO LOG DE APACHE:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rMPM RECURRE A UNA IMPLEMENTACIÓN MÁS SEGURA, PERO ALGUNAS PETICIONES DE CLIENTES NO FUERON PROCESADAS CORRECTAMENTE. PARA EVITAR ESTE ERROR, USA \"ACCEPTFILTER\" CON EL FILTRO \"NONE\" IN EL FICHERO \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\".\r¿POR QUÉ LAS IMÁGENES Y LAS HOJAS DE ESTILO NO SE MUESTRAN?\rA VECES HAY PROBLEMAS MOSTRANDO IMÁGENES Y HOJAS DE ESTILO. ESPECIALMENTE SI ESTOS FICHEROS ESTÁN ALMACENADOS EN UN DISPOSITIVO EN RED. EN ESTE CASO, PUEDES ACTIVAR (O AÑADIR) UNA DE LAS SIGUIENTES LÍNEAS EN EL FICHERO \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rESTE PROBLEMA TAMBIÉN PUEDE ESTAR CAUSADO POR PROGRAMAS DE REGULACIÓN DE ANCHO DE BANDA, COMO NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rREINICIA EL SERVIDOR DE XAMPP USANDO EL PANEL DE CONTROL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\r¿CÓMO PUEDO ESTABLECER LA CONTRASEÑA DE ROOT DE MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\r¿PUEDO USAR MI PROPIO SERVIDOR DE MYSQL?\rSÍ. SIMPLEMENTE NO INICIES MYSQL DESDE EL PAQUETE XAMPP. POR FAVOR, TEN EN CUENTA QUE DOS SERVIDORES NO PUEDEN INICIARSE EN EL MISMO PUERTO. SI HAS SELECCIONADO UNA CONTRASEÑA PARA \"ROOT\", NO OLVIDES EDITAR EL FICHERO \"\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP\".\r¿CÓMO RESTRINJO EL ACCESO A PHPMYADMIN DESDE EL EXTERIOR?\rEN LA CONFIGURACIÓN BÁSICA DE XAMPP, PHPMYADMIN ES ACCESSIBLE SÓLO DESDE LA MÁQUINA DONDE ESTÁ INSTALADA EN HTTP://127.0.0.1 O HTTP://LOCALHOST.\rPARA ACCEDER AL SERVIDOR MYSQL, PHPMYADMIN TE PREGUNTARÁ POR UN NOMBRE DE USUARIO Y CONTRASEÑA. NO OLVIDES FIJAR LA CONTRASEÑA DEL USUARIO \"ROOT\" ANTES.\r¿CÓMO HABILITAR EL ACCESSO A PHPMYADMIN DESDE FUERA?\rEN LA CONFIGURACIÓN BÁSICA DE XAMPP, PHPMYADMIN ES ACCESSIBLE SÓLO DESDE LA MÁQUINA DONDE ESTÁ INSTALADA EN HTTP://127.0.0.1 O HTTP://LOCALHOST.\rIMPORTANTE: HABILITAR EL ACCESSO DE PHPMYADMIN PARA USUARIOS EXTERNOS NO ESTÁ RECOMENDADO PARA ENTORNOS DE PRODUCCIÓN. UN ATACANTE PODRÍA USAR CUALQUIER VULNERABILIDAD DE LA APLICACIÓN PARA EJECUTAR CÓDIGO O MODIFICAR DATOS.\rPARA HABILITAR EL ACCESO REMOTE A PHPMYADMIN, SIGUE ESTOS PASOS:\rEDITA EL FICHERO APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF EN TU DIRECTORIO DE INSTALACIÓN.\rEN ESTE FICHERO ENCUENTRA LAS SIGUIENTES LÍNEAS. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nREEMPLAZA \'REQUIRE LOCAL\' POR \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nREINICIA EL SERVIDOR DE XAMPP USANDO EL PANEL DE CONTROL.\r¿DÓNDE SE ENCUENTRA EL SOPORTE A IMAP PARA PHP?\rPOR DEFECTO, EL SOPORTE A IMAP PARA PHP ESTÁ DESACTIVADO EN XAMPP DEBIDO A ALGUNOS EXTRAÑOS ERRORES DE INICIALIZACIÓN CON ALGUNAS VERSIONES HOME, COMO WINDOWS 98. SI TRABAJAS CON SISTEMAS NT, PUEDES ABRIR EL FICHERO \"\\\\XAMPP\\\\PHP\\\\PHP.INI\" PARA ACTIVAR LA EXTENSIÓN PHP ELIMINANDO EL PUNTO Y COMA INICIAL EN LA LÍNEA \";EXTENSION=PHP_IMAP.DLL\". DEBERÍA SER:\rEXTENSION=PHP_IMAP.DLL\rAHORA REINICIA APACHE E IMAP DEBERÍA FUNCIONAR. PUEDES USAR LOS MISMOS PASOS PARA CUALQUIER EXTENSIÓN QUE NO ESTÉ HABILITADA EN LA CONFIGURACIÓN POR DEFECTO.\r¿POR QUÉ ALGUNAS APLICACIONES OPEN SOURCE DE PHP NO FUNCIONAN CON XAMPP EN WINDOWS?\rMUCHAS DE LAS APLICACIONES DE PHP O EXTENSIONES QUE HAN SIDO ESCRITAS PARA LINUX NO HAN SIDO PORTADAS A WINDOWS. \r¿PUEDO BORRAR EL DIRECTORIO \"INSTALL\" DESPUÉS DE LA INSTALACIÓN?\rES MEJOR QUE NO. LOS SCRIPTS QUE SE ENCUENTRAN AQUÍ AÚN SON NECESARIOS PARA TODOS LOS PAQUETES ADICIONALES (ADD-ONS) Y ACTIALIZACIONES DE XAMPP.\r¿CÓMO ACTIVO EL EACCELERATOR?\rCOMO OTRAS EXTENSIONES (ZEND) , PUEDES ACTIVARLA EN \"PHP.INI\". EN ESTE FICHERO, DESCOMENTA LA LÍNEA \";ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"\". DEBE SER:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\r¿CÓMO ARREGLO EL ERROR DE CONEXIÓN A MI SERVIDOR MS SQL?\rSI LA EXTENSIÓN MSSQL NO SE CARGÓ EN EL PHP.INI, A VECES APARECERÁN PROBLEMAS CUANDO SÓLO SE USE TCP/IP. PUEDES ARREGLAR ESTE PROBLEMA CON UN \"NTWDBLIB.DLL\" DE MICROSOFT MÁS NUEVO. POR FAVOR, SUSTITUYE EL FICHERO ANTERIOR EN \"\\\\XAMPP\\\\APACHE\\\\BIN\" Y \"\\\\XAMPP\\\\PHP\" POR EL NUEVO. DEBIDO A LA LICENCIA, NO PODEMOS EMPAQUETAR NUEVAS VERSIONES DE ESTE FICHERO EN XAMPP.\r¿CÓMO USO LA EXTENSIÓN MCRYPT DE PHP?\rPARA ELLO, HEMOS ABIERTO UN TOPIC EN EL FORO CON EJEMPLOS Y POSIBLES SOLUCIONES: \rTOPIC DE MCRYPT\r¿FUNCIONA MICROSOFT ACTIVE SERVER PAGES (ASP) CON XAMPP?\rNO. Y APACHE::ASP CON EL ADD-ON DE PERL TAMPOCO. APACHE::ASP SÓLO USA PERL-SCRIPT PERO EL ASP DE INTERNET INFORMATION SERVER (IIS) TAMBIÉN USA VBSCRIPT. PERO PARA ASP .NET HAY UN MÓDULO DE APACHE DE TERCEROS DISPONIBLE.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDAD\rCDN PROPORCIONADO POR\r\n'),(37,'a67f5e1fc8eed5236c7c870c185ce00c','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rPREGUNTAS FRECUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDAD\rCDN PROPORCIONADO POR\r\n'),(38,'12813ce3f2e00ca403964774f8da7988','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rPREGUNTAS FRECUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDAD\rCDN PROPORCIONADO POR\r\n'),(39,'9a7c4ddab222f8b617dbfb7f3c37c353','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rPREGUNTAS FRECUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDAD\rCDN PROPORCIONADO POR\r\n'),(40,'87c9ebc83bdbfbe4f6116ba2f9d28c6b','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rPREGUNTAS FRECUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rPREGUNTAS FRECUENTES\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nCOMUNIDAD\rXAMPP TIENE MÁS DE 10 AÑOS  HAY UNA GRAN COMUNIDAD DETRÁS DEL PROYECTO. PUEDES PARTICIPAR UNIÉNDOTE A NUESTROS \rFOROS\r, UNIÉNDOTE A NUESTRO \rFACEBOOK\r, O SIGUIENDO NUESTRAS HAZAÑAS EN \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDAD\rCDN PROPORCIONADO POR\r\n'),(41,'860f73901da967cddbc33b3ebc99f45e','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rFREQUENTLY ASKED QUESTIONS\rHOW DO I INSTALL XAMPP?\rXAMPP FOR WINDOWS EXISTS IN THREE DIFFERENT FLAVORS:\rINSTALLER:\rPROBABLY THE EASIEST WAY TO INSTALL XAMPP.\rZIP:\rFOR PURISTS: XAMPP AS ORDINARY ZIP ARCHIVE.\r7ZIP:\rFOR PURISTS WITH LOW BANDWIDTH: XAMPP AS 7ZIP ARCHIVE.\rNOTE: IF YOU EXTRACT THE FILES, THERE CAN BE FALSE-POSITIVES VIRUS WARNINGS.\rUSING THE INSTALLER:\rTHE XAMPP CONTROL PANEL FOR START/STOP APACHE, MYSQL, FILEZILLA & MERCURY OR INSTALL THESE SERVER AS SERVICES.\rINSTALLING FROM ZIP\rUNZIP THE ZIP ARCHIVES INTO THE FOLDER OF YOUR CHOICE. XAMPP IS EXTRACTING TO THE SUBDIRECTORY \"C:\\XAMPP\" BELOW THE SELECTED TARGET DIRECTORY. NOW START THE FILE \"SETUP_XAMPP.BAT\", TO ADJUST THE XAMPP CONFIGURATION TO YOUR SYSTEM.\rIF YOU CHOOSE A ROOT DIRECTORY \"C:\\\" AS TARGET, YOU MUST NOT START \"SETUP_XAMPP.BAT\".\rLIKE WITH THE INSTALLER VERSION, YOU CAN NOW USE THE \"XAMPP CONTROL PANEL\" FOR ADDITIONAL TASKS.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rHOW CAN I START XAMPP WITHOUT SETUP?\rIF YOU EXTRACT XAMPP IN A TOP LEVEL FOLDER LIKE \"C:\\\" OR \"D:\\\", YOU CAN START MOST SERVERS LIKE APACHE OR MYSQL DIRECTLY WITHOUT EXECUTION OF THE FILE \"SETUP_XAMPP.BAT\".\rNOT USING THE SETUP SCRIPT, OR SELECTING RELATIVE PATHS IN THE SETUP SCRIPT, IS PREFERRED IF YOU ARE INSTALLING XAMPP ON A USB DRIVE. BECAUSE ON EACH PC SUCH A DRIVE CAN HAVE AN OTHER DRIVE LETTER. YOU CAN SWITCH FROM ABSOLUTE TO RELATIVE PATHS AT ANY TIME WITH THE SETUP SCRIPT.\rUSING THE INSTALLER FROM OUR DOWNLOADS PAGE IS THE EASIEST WAY TO INSTALL XAMPP. AFTER THE INSTALLATION IS COMPLETE, YOU WILL FIND XAMPP UNDER START | PROGRAMS | XAMPP. YOU CAN USE THE XAMPP CONTROL PANEL TO START/STOP ALL SERVER AND ALSO INSTALL/UNINSTALL SERVICES.\rTHE XAMPP CONTROL PANEL FOR START/STOP APACHE, MYSQL, FILEZILLA & MERCURY OR INSTALL THESE SERVER AS SERVICES.\rHOW DO I START AND STOP XAMPP?\rTHE UNIVERSAL CONTROL CENTER IS THE \"XAMPP CONTROL PANEL\" (THANKS WWW.NAT32.COM). IT IS STARTED WITH:\r\\XAMPP\\XAMPP-CONTROL.EXE\rYOU CAN ALSO USE SOME BATCHFILES TO START/STOP THE SERVERS:\rAPACHE & MYSQL START:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL STOP:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE START:\n\\XAMPP\\APACHE_START.BAT\rAPACHE STOP:\n\\XAMPP\\APACHE_STOP.BAT\rMYSQL START:\n\\XAMPP\\MYSQL_START.BAT\rMYSQL STOP:\n\\XAMPP\\MYSQL_STOP.BAT\rMERCURY MAILSERVER START:\n\\XAMPP\\MERCURY_START.BAT\rMERCURY MAILSERVER STOP:\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA SERVER START:\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA SERVER STOP:\n\\XAMPP\\FILEZILLA_STOP.BAT\rHOW CAN I TEST THAT EVERYTHING WORKED?\rTYPE IN THE FOLLOWING URL AT YOUR FAVOURITE WEB BROWSER:\rHTTP://LOCALHOST/\rOR \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rHOW CAN I INSTALL A SERVER AS A SERVICE?\rEACH SERVER IN XAMPP YOU CAN INSTALL ALSO AS WINDOWS SERVICE. YOU CAN ALSO INSTALL IT FROM THE XAMPP CONTROL PANEL. IN THIS CASE IT IS NECESSARY TO RUN THE SCRIPTS OR THE CONTROL PANEL WITH ADMINISTRATOR PRIVILEGES.\rAPACHE SERVICE INSTALL: \\XAMPP\\APACHE\\APACHE_INSTALLSERVICE.BAT\rAPACHE SERVICE UNINSTALL: \\XAMPP\\APACHE\\APACHE_UNINSTALLSERVICE.BAT \rMYSQL SERVICE INSTALL: \\XAMPP\\MYSQL\\MYSQL_INSTALLSERVICE.BAT \rMYSQL SERVICE UNINSTALL: \\XAMPP\\MYSQL\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA SERVICE (UN)INSTALL: \\XAMPP\\FILEZILLA_SETUP.BAT \rMERCURY: NO SERVICE INSTALLATION AVAILABLE\rIS XAMPP PRODUCTION READY?\rXAMPP IS NOT MEANT FOR PRODUCTION USE BUT ONLY FOR DEVELOPMENT ENVIRONMENTS. XAMPP IS CONFIGURED TO BE OPEN AS POSSIBLE TO ALLOW THE DEVELOPER ANYTHING HE/SHE WANTS. FOR DEVELOPMENT ENVIRONMENTS, THIS IS GREAT BUT IN A PRODUCTION ENVIRONMENT, IT COULD BE FATAL.\rHERE A LIST OF MISSING SECURITY IN XAMPP:\rTHE MYSQL ADMINISTRATOR (ROOT) HAS NO PASSWORD.\rTHE MYSQL DAEMON IS ACCESSIBLE VIA NETWORK.\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rTHE DEFAULT USERS OF MERCURY AND FILEZILLA ARE KNOWN.\rALL POINTS CAN BE A HUGE SECURITY RISK. ESPECIALLY IF XAMPP IS ACCESSIBLE VIA NETWORK AND PEOPLE OUTSIDE YOUR LAN. IT CAN ALSO HELP TO USE A FIREWALL OR A (NAT) ROUTER. IN CASE OF A ROUTER OR FIREWALL, YOUR PC IS NORMALLY NOT ACCESSIBLE VIA NETWORK. IT IS UP TO YOU TO FIX THESE PROBLEMS. AS A SMALL HELP THERE IS THE \"XAMPP SECURITY CONSOLE\".\rPLEASE SECURE XAMPP BEFORE PUBLISHING ANYTHING ONLINE. A FIREWALL OR AN EXTERNAL ROUTER ARE ONLY SUFFICIENT FOR LOW LEVELS OF SECURITY. FOR SLIGHTLY MORE SECURITY, YOU CAN RUN THE \"XAMPP SECURITY CONSOLE\" AND ASSIGN PASSWORDS.\rIF YOU WANT HAVE YOUR XAMPP ACCESSIBLE FROM THE INTERNET, YOU SHOULD GO TO THE FOLLOWING URI WHICH CAN FIX SOME PROBLEMS:\rHTTP://LOCALHOST/SECURITY/\rWITH THE SECURITY CONSOLE YOU CAN SET A PASSWORD FOR THE MYSQL USER \"ROOT\" AND PHPMYADMIN. YOU CAN ALSO ENABLE A AUTHENTICATION FOR THE XAMPP DEMOPAGES.\rTHIS WEB BASED TOOL DOES NOT FIX ANY ADDITIONAL SECURITY ISSUES! ESPECIALLY THE FILEZILLA FTP SERVER AND THE MERCURY MAIL SERVER YOU MUST SECURE YOURSELF.\rHOW DO I UNINSTALL XAMPP?\rIF YOU INSTALLED XAMPP USING THE INSTALLER VERSION, PLEASE USE THE UNINSTALLER. THE UNINSTALLER WILL DELETE ALL XAMPP ENTRIES FROM YOUR REGISTRY AND IT WILL UNINSTALL SOME INSTALLED SERVICES INCLUDED WITH XAMPP. WE HIGHLY RECOMMEND THAT YOU USE THE UNINSTALL PROGRAM FOR REMOVING XAMPP INSTALLATIONS FROM THE INSTALLER VERSION.PLEASE BACKUP ALL THE DATA YOU WANT TO KEEP BEFORE UNINSTALLING XAMPP.\rIF YOU INSTALLED XAMPP USING THE ZIP AND 7ZIP VERSIONS, SHUT DOWN ALL XAMPP SERVERS AND EXIT ALL PANELS. IF YOU INSTALLED ANY SERVICES, UNINSTALL AND SHUT THEM DOWN TOO. NOW SIMPLY DELETE THE ENTIRE FOLDER WHERE XAMPP IS INSTALLED. THERE ARE NO REGISTRY ENTRIES AND NO ENVIRONMENT VARIABLES TO CLEAN UP.\rWHAT IS THE \"LITE\" VERSION OF XAMPP?\rXAMPP LITE (MEANS \"LIGHT\" AS IN \"LIGHT-WEIGHT\") IS A SMALLER BUNDLE OF XAMPP COMPONENTS, WHICH IS RECOMMENDED FOR QUICK WORK USING ONLY PHP AND MYSQL. SOME SERVERS OR TOOLS SUCH AS MERCURY MAIL AND FILEZILLA FTP ARE MISSING IN THE LITE VERSION.\rWHERE SHOULD I PLACE MY WEB CONTENT?\rTHE MAIN DIRECTORY FOR ALL WWW DOCUMENTS IS \\XAMPP\\HTDOCS. IF YOU PUT A FILE \"TEST.HTML\" IN THIS DIRECTORY, YOU CAN ACCESS IT WITH THE URI \"HTTP://LOCALHOST/TEST.HTML\".\rAND \"TEST.PHP\"? JUST USE \"HTTP://LOCALHOST/TEST.PHP\". A SIMPLE TESTSCRIPT CAN BE:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rA NEW SUBDIRECTORY FOR YOUR WEB? JUST MAKE A NEW DIRECTORY (E.G. \"NEW\") INSIDE THE DIRECTORY \"\\XAMPP\\HTDOCS\" (BEST WITHOUT WHITESPACES AND ONLY ASCII), CREATE A TEST FILE IN THIS DIRECTORY AND ACCESS IT WITH \"HTTP://LOCALHOST/NEW/TEST.PHP\".\rFURTHER SPECIFICS\rHTML:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .HTML .HTM\r=> BASIC PACKAGE\rSSI:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .SHTML\r=> BASIC PACKAGE\rCGI:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .CGI\r=> BASIC PACKAGE\rPHP:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .PHP\r=> BASIC PACKAGE\rPERL:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .PL\r=> BASIC PACKAGE\rAPACHE::ASP PERL:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .ASP\r=> BASIC PACKAGE\rJSP JAVA:\rEXECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rALLOWED ENDINGS: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rEXECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rALLOWED ENDINGS: .HTML (U.A)\r=> TOMCAT ADD-ON\rCAN I MOVE THE XAMPP INSTALLATION?\rYES. AFTER MOVING OF THE XAMPP DIRECTORY, YOU MUST EXECUTE \"SETUP_XAMPP.BAT\". THE PATHS IN THE CONFIGURATION FILES WILL BE ADJUSTED WITH THIS STEP.\rIF YOU HAVE INSTALLED ANY SERVER AS WINDOWS SERVICE, YOU MUST FIRST REMOVE THE WINDOWS SERVICE, AND AFTER THE MOVING YOU CAN INSTALL THE SERVICE AGAIN.\rWARNING: THE CONFIGURATION FILES FROM YOUR OWN SCRIPTS, LIKE PHP APPLICATIONS, ARE NOT ADJUSTED. BUT IT\'S POSSIBLE TO WRITE A \"PLUG-IN\" FOR THE INSTALLER. WITH SUCH A PLUG-IN, THE INSTALLER CAN ADJUST SUCH FILES TOO.\rWHAT ARE \"AUTOMATIC START PAGES\" FOR THE WWW DIRECTORIES?\rTHE STANDARD FILENAME FOR THE APACHE FUNCTION \"DIRECTORYINDEX\" IS \"INDEX.HTML\" OR \"INDEX.PHP\". EVERY TIME YOU ARE JUST BROWSING TO A FOLDER (E.G. \"HTTP://LOCALHOST/XAMPP/\"), AND APACHE CAN FIND SUCH A FILE, APACHE IS DISPLAYING THIS FILE INSTEAD OF A DIRECTORY LISTING.\rWHERE CAN I CHANGE THE CONFIGURATION?\rALMOST ALL SETTINGS IN XAMPP YOU CAN CHANGE WITH CONFIGURATION FILES. JUST OPEN THE FILE IN A TEXTEDIT AND CHANGE THE SETTING YOU WANT. ONLY FILEZILLA AND MERCURY SHOULD BE CONFIGURED WITH THE APPLICATION CONFIG TOOL.\rWHY CAN\'T XAMPP WORK ON WINDOWS XP SP2?\rMICROSOFT DELIVERS A BETTER FIREWALL WITH SERVICE PACK 2 (SP2), WHICH STARTS AUTOMATICALLY. THIS FIREWALL NOW BLOCKS THE NECESSARY PORTS 80 (HTTP) AND 443 (HTTPS) AND APACHE CAN\'T START.\rTHE FAST SOLUTION:\rDISABLE THE MICROSOFT FIREWALL WITH THE TOOLBAR AND TRY TO START XAMPP ONCES MORE. THE BETTER SOLUTION IS TO DEFINE AN EXCEPTION WITHIN THE SECURITY CENTER.\rTHE FOLLOWING PORTS ARE USED FOR BASIC FUNCTIONALITY:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rWHY DOESN\'T XAMPP WORK ON VISTA?\rUSER ACCOUNT CONTROL (UAC)\rIN THE DIRECTORY \"C:\\PROGRAM FILES\" YOU DON\'T HAVE FULL WRITE PRIVILEGES, EVEN AS ADMIN. OR YOU HAVE ONLY LIMITED PRIVILEGES (E.G. FOR \".\\XAMPP\\HTDOCS\"). IN THIS CASE YOU CAN\'T EDIT A FILE.\rSOLUTION:\rRAISE YOUR PRIVILEGES WITHIN EXPLORER (RIGHT CLICK / SECURITY) OR DEACTIVATE THE USER ACCOUNT CONTROL (UAC).\rYOU HAVE INSTALLED APACHE/MYSQL IN \"C:\\XAMPP\" AS WINDOWS SERVICE. BUT YOU CAN\'T START/STOP THE SERVICES WITH THE \"XAMPP CONTROL PANEL\" OR CAN\'T UNINSTALL THEM.\rSOLUTION:\rUSE THE SERVICE MANAGEMENT CONSOLE FROM WINDOWS OR DEACTIVATE UAC.\rDISABLING THE USER ACCOUNT CONTROL (UAC)\rTO DEACTIVATE THE UAC, USE THE PROGRAM \"MSCONFIG\". IN \"MSCONFIG\" GO TO \"TOOLS\", SELECT \"DISABLE USER ACCOUNT CONTROL\" AND VERIFY YOUR SELECTION. NOW YOU MUST RESTART WINDOWS. AT THE SAME TIME, YOU CAN ENABLE THE UAC AGAIN.\rHOW DO I CHECK THE MD5 CHECKSUM?\rTO COMPARE FILES, OFTEN CHECKSUMS ARE USED. A STANDARD TO CREATE THIS CHECKSUM MD5 (MESSAGE DIGEST ALGORITHM 5).\rWITH THIS MD5 CHECKSUM YOU CAN TEST, IF YOUR DOWNLOAD OF THE XAMPP PACKAGE IS CORRECT OR NOT. OF COURSE YOU NEED A PROGRAM WHICH CAN CREATE THESE CHECKSUMS. FOR WINDOWS YOU CAN USE A TOOL FROM MICROSOFT:\rAVAILABILITY AND DESCRIPTION OF THE FILE CHECKSUM INTEGRITY VERIFIER UTILITY\rIT\'S ALSO POSSIBLE TO USE ANY OTHER PROGRAM WHICH CAN CREATE MD5 CHECKSUMS, LIKE THE GNU MD5SUM.\rAS YOU HAVE INSTALLED SUCH A PROGRAM (E.G. FCIV.EXE), YOU CAN DO FOLLOWING STEPS:\rDOWNLOAD XAMPP (F.E. XAMPP-WIN32-1.8.2-0.EXE)\rCREATE THE CHECKSUM WITH:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rAND NOW YOU CAN COMPARE THIS CHECKSUM WITH THAT ONE YOU CAN FIND ON THE XAMPP FOR WINDOWS HOMEPAGE.\rIF BOTH CHECKSUMS EQUAL, ALL IS OK. IF NOT, THE DOWNLOAD IS BROKEN OR THE FILE HAS BEEN CHANGED.\rWHY HAVE CHANGES IN MY PHP.INI NOT TAKEN EFFECT?\rIF A CHANGE IN THE \"PHP.INI\" HAS NO EFFECT, IT\'S POSSIBLE PHP IS USING A DIFFERENT ONE. YOU CAN VERIFY THIS WITH PHPINFO(). GO TO THE URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP AND SEARCH FOR \"LOADED CONFIGURATION FILE\". THIS VALUE SHOWS YOU THE \"PHP.INI\" PHP IS REALLY USING.\rNOTE:\rAFTER CHANGING THE \"PHP.INI\" YOU HAVE TO RESTART APACHE SO THAT APACHE/PHP CAN READ THE NEW SETTINGS.\rHELP! THERE IS A VIRUS IN XAMPP!\rSOME ANTIVIRUS PROGRAMS MISTAKE XAMPP FOR A VIRUS, TYPICALLY FLAGGING THE FILE XAMPP-MANAGER.EXE THIS IS A FALSE POSITIVE MEANING THAT THE ANTIVIRUS ERRONEOUSLY IDENTIFIED IT AS A VIRUS, WHEN IT IS NOT. BEFORE WE RELEASE EACH NEW VERSION OF XAMPP WE RUN IT THROUGH VIRUS SCANNING SOFTWARE. AT THE MOMENT WE ARE USING \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rHOW DO I CONFIGURE MY ANTIVIRUS APPLICATION?\rWE HAVE INCLUDED ALL DEPENDENCES AND SERVERS REQUIRED FOR RUNNING THE BUNDLED WEB APPLICATION, SO YOU WILL FIND THAT XAMPP INSTALLS LARGE NUMBERS OF FILES. IF YOU ARE INSTALLING A XAMPP APPLICATION ON A WINDOWS MACHINE WITH AN ANTIVIRUS APP ENABLED, THIS MAY SLOW DOWN THE INSTALLATION SIGNIFICANTLY, AND THERE IS ALSO A CHANCE THAT ONE OF THE SERVERS (WEB SERVER, DATABASE SERVER) MAY BE BLOCKED BY THE ANTIVIRUS SOFTWARE. IF YOU HAVE AN ANTIVIRUS TOOL ENABLED, CHECK THE FOLLOWING SETTINGS FOR RUNNING XAMPP WITHOUT PERFORMANCE ISSUES:\rADD EXCEPTIONS IN THE FIREWALL: FOR APACHE, MYSQL OR ANY OTHER SERVER.\rSCAN FILES WHEN EXECUTING: IF YOU HAVE ENABLED THE ANTIVIRUS SCAN FOR ALL FILES, THE EXECUTABLE FILES FOR THE SERVERS MAY SLOW DOWN.\rSCAN THE TRAFFIC FOR DIFFERENT URLS: IF YOU ARE DEVELOPING WITH XAMPP ON YOUR OWN MACHINE, YOU CAN EXCLUDE \"LOCALHOST\" TRAFFIC IN THE ANTIVIRUS SETTINGS.\rWHY DOESN\'T THE APACHE SERVER START ON MY SYSTEM?\rTHIS PROBLEM CAN BE ONE OF SEVERAL REASONS:\rYOU HAVE STARTED MORE THEN ONE HTTP SERVER (IIS, SAMBAR, ZEUS AND SO ON). ONLY ONE SERVER CAN USE PORT 80. THIS ERROR MESSAGE INDICATE THE PROBLEM:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rYOU HAVE OTHER SOFTWARE, SUCH AS THE INTERNET TELEPHONE \"SKYPE\" WHICH ALSO BLOCKS THE PORT 80. IF THE PROBLEM IS \"SKYPE\", YOU CAN GO IN SKYPE TO ACTIONS --> OPTIONS --> CONNECTION --> REMOVE THE CHECK MARK AT \"USE PORT 80 FOR AN ALTERNATE PORT\" AND RESTART SKYPE. NOW IT SHOULD WORK.\rYOU HAVE A FIREWALL WHICH BLOCKS THE APACHE PORT. NOT ALL FIREWALLS ARE COMPATIBLE WITH APACHE, AND SOMETIMES DEACTIVATING THE FIREWALL IS NOT ENOUGH AND YOU MUST DEINSTALL IT. THIS ERROR MESSAGE INDICATES A FIREWALL:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rALSO IF APACHE CAN START, BUT YOUR BROWSER CAN\'T CONNECT TO IT IT COULD BE DUE TO ONE OF THE FOLLOWING:\rSOME VIRUS SCANNERS CAN CAUSE THIS IN THE SAME WAY THAT FIREWALLS CAN INTERFERE.\rYOU HAVE XP PROFESSIONAL WITHOUT SERVICE PACK 1. YOU MUST HAVE AT LEAST SP1 FOR XAMPP.\rTIP:\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\rWHY IS MY CPU LOAD FOR APACHE ALMOST 99%?\rTHERE IS ONE OF TWO SCENARIOS AT PLAY HERE. EITHER YOUR CPU IS MAXING OUT, OR YOU CAN BROWSER CONNECT TO THE SERVER, BUT NOT SEE ANYTHING (THE SYSTEM IS TRYING UNSUCESSFULLY TO LOAD THE PAGE). IN EITHER CASE YOU CAN FIND THE FOLLOWING MESSAGE IN THE APACHE LOG FILE:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rTHE MPM FALLS BACK TO A SAFER IMPLEMENTATION, BUT SOME CLIENT REQUESTS WERE NOT PROCESSED CORRECTLY. IN ORDER TO AVOID THIS ERROR, USE \"ACCEPTFILTER\" WITH ACCEPT FILTER \"NONE\" IN THE \"\\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-MPM.CONF\" FILE.\rWHY ARE PICTURES AND STYLE-SHEETS NOT DISPLAYED?\rSOMETIMES THERE ARE PROBLEMS WITH DISPLAYING PICTURES AND STYLE-SHEETS. ESPECIALLY IF THESE FILES ARE LOCATED ON A NETWORK DRIVE. IN THIS CASE YOU CAN ENABLE (OR ADD) ONE IF THE FOLLOWING LINES IN THE FILE \"\\XAMPP\\APACHE\\CONF\\HTTPD.CONF\":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rTHIS PROBLEM CAN ALSO BE CAUSED BY PROGRAMS FOR REGULATING BANDWIDTH, LIKE NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rHOW CAN I SET A ROOT PASSWORD IN MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rCAN I USE MY OWN MYSQL SERVER?\rYES. SIMPLY DON\'T START THE MYSQL FROM THE XAMPP PACKAGE. PLEASE NOTE THAT TWO SERVERS CANNOT BE STARTED ON THE SAME PORT. IF YOU HAVE SET A PASSWORD FOR \"ROOT\", PLEASE DO NOT FORGET TO EDIT THE FILE \"\\XAMPP\\PHPMYADMIN\\CONFIG.INC.PHP\".\rHOW DO I RESTRICT ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rBEFORE YOU CAN ACCESS THE MYSQL SERVER, PHPMYADMIN WILL PROMPT YOU FOR A USER NAME AND PASSWORD. DON\'T FORGET TO SET A PASSWORD FOR THE USER \"ROOT\" FIRST.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rWHERE IS THE IMAP SUPPORT FOR PHP?\rAS DEFAULT, THE IMAP SUPPORT FOR PHP IS DEACTIVATED IN XAMPP DUE TO SOME MYSTERIOUS INITIALIZATION ERRORS WITH SOME HOME VERSIONS LIKE WINDOWS 98. IF YOU WORK WITH NT SYSTEMS, YOU CAN OPEN THE FILE \"\\XAMPP\\PHP\\PHP.INI\" TO ACTIVATE THE PHP EXSTENSION BY REMOVING THE BEGINNING SEMICOLON AT THE LINE \";EXTENSION=PHP_IMAP.DLL\". IT SHOULD BE:\rEXTENSION=PHP_IMAP.DLL\rNOW RESTART APACHE AND IMAP SHOULD WORK. YOU CAN USE THE SAME STEPS FOR EVERY EXTENSION, WHICH IS NOT ENABLED IN THE DEFAULT CONFIGURATION.\rWHY DON\'T SOME PHP OPEN SOURCE APPS WORK WITH XAMPP ON WINDOWS?\rA LOT OF PHP APPLICATIONS OR EXTENSIONS THAT HAVE BEEN WRITTEN FOR LINUX HAVEN’T BEEN PORTED TO WINDOWS. \rCAN I DELETE THE \"INSTALL\" DIRECTORY AFTER INSTALLATION?\rIT\'S BETTER NOT TO. THE SCRIPTS HERE ARE STILL NEEDED FOR ALL ADDITIONAL PACKAGES (ADD-ONS) AND UPGRADES OF XAMPP.\rHOW DO I ACTIVATE THE EACCELERATOR?\rLIKE OTHER (ZEND) EXTENSIONS, YOU CAN ACTIVATE IT IN \"PHP.INI\". IN THIS FILE, ENABLE THE LINE \";ZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\". IT SHOULD BE:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rHOW DO I FIX A CONNECTION ERROR TO MY MS SQL SERVER?\rIF THE MSSQL EXTENSION WAS LOADED IN THE PHP.INI, SOMETIMES PROBLEMS APPEAR WHEN ONLY TCP/IP IS USED. YOU CAN FIX THAT PROBLEM WITH A NEWER \"NTWDBLIB.DLL\" FROM MICROSOFT. PLEASE REPLACE THE OLDER FILE IN \"\\XAMPP\\APACHE\\BIN\" AND \"\\XAMPP\\PHP\" WITH THE NEW ONE. BECAUSE OF THE LICENSE, WE CAN\'T PACKAGE A NEWER VERSION OF THIS FILE WITH XAMPP.\rHOW DO I WORK WITH THE PHP MCRYPT EXTENSION?\rFOR THIS, WE HAVE OPENED A TOPIC IN THE FORUM WITH EXAMPLES AND POSSIBLE SOLUTIONS: \rMCRYPT TOPIC\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rNO. AND APACHE::ASP WITH THE PERL ADD-ON IS NOT THE SAME. APACHE::ASP ONLY KNOWS PERL-SCRIPT, BUT ASP FROM THE INTERNET INFORMATION SERVER (IIS) ALSO KNOWS THE NORMAL VBSCRIPT. BUT FOR ASP .NET, THERE IS A 3RD PARTY APACHE MODULE AVAILABLE.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(42,'cdf976aa74b79c7810559ef0ebefb9aa','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rQUESTIONS FRÉQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rQUESTIONS FRÉQUENTES\rCOMMENT INSTALLÉ-JE XAMPP ?\rXAMPP POUR WINDOWS EXISTE EN TROIS DÉCLINAISONS:\rINSTALLATEUR :\rPROBABLEMENT LE PLUS FACILE POUR INSTALLER XAMPP.\rZIP:\rPOUR LES PURISTES: XAMPP DANS UNE ARCHIVE ZIP.\r7ZIP:\rPOUR LES PURISTES EN BAS DÉBIT: XAMPP EN ARCHIVE 7ZIP.\rNOTE: SI VOUS EXTRAYEZ LES FICHIERS, DE FAUSSES ALERTES VIRUS PEUVENT SURVENIR.\rUTILISATION DE L\'INSTALLATEUR :\rLE PANNEAU DE CONTRÔLE XAMPP POUR DÉMARRER/STOPPER APACHE, MYSQL, FILEZILLA ET MERCURY OU INSTALLER CES SERVEURS COMME SERVICES.\rINSTALLATION À PARTIR DE ZIP\rDÉZIPPEZ L\'ARCHIVE ZIP DANS LE DOSSIER DE VOTRE CHOIX. XAMPP S\'EXTRAIT DANS LE SOUS-RÉPERTOIRE \"C:\\\\XAMPP\" DU RÉPERTOIRE CIBLE SÉLECTIONNÉ. LANCEZ LE FICHIER \"SETUP_XAMPP.BAT\" POUR ADAPTER LA CONFIGURATION DE XAMPP À VOTRE SYSTÈME.\rSI VOUS CHOISISSEZ COMME CIBLE UN RÉPERTOIRE RACINE \"C:\\\\\", VOUS NE DEVEZ PAS LANCER \"SETUP_XAMPP.BAT\".\rCOMME AVEC L\'INSTALLATEUR, LE \"PANNEAU DE CONTRÔLE XAMPP\" PERMET DES TÂCHES ADDITIONELLES.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rCOMMENT UTILISER XAMPP SANS L\'INSTALLER?\rSI VOUS EXTRAYEZ XAMPP SOUS LA RACINE COMME \"C:\\\\\" OU \"D:\\\\\", VOUS LANCEREZ LA PLUPART DES SERVEURS COMME APACHE OU MYSQL SANS EXÉCUTION DE \"SETUP_XAMPP.BAT\".\rPOUR UNE INSTALLATION SUR UNE CLÉ USB, NE PAS UTILISER LE SCRIPT D\'INSTALLATION OU UTILISER DES CHEMINS RELATIFS EST PRÉFÉRABLE. PARCE QUE SUR CHAQUE PC CE TYPE DE DRIVE PEUT AVOIR UNE LETTRE DIFFÉRENTE. A TOUT MOMENT, VOUS POURREZ PASSEZ AU CHEMINS RELATIFS AVEC LE SCRIPT D\'INSTALLATION.\rLE PLUS FACILE EST D\'INSTALLER XAMPP AVEC L\'INSTALLATEUR DE LA PAGE DE TÉLÉCHARGEMENT. ENSUITE, VOUS TROUVEREZ DÉMARRER | PROGRAMMES | XAMPP. LE PANNEAU DE CONTRÔLE XAMPP PERMET DE DÉMARRER/STOPPER TOUS LES SERVEURS ET INSTALLER/DÉSINSTALLER LES SERVICES.\rLE PANNEAU DE CONTRÔLE XAMPP POUR DÉMARRER/STOPPER APACHE, MYSQL, FILEZILLA ET MERCURY OU INSTALLER CES SERVEURS COMME SERVICES.\rCOMMENT LANCER/ARRÊTER XAMPP ?\rLE CENTRE DE CONTRÔLE UNIVERSEL EST LE \"PANNEAU DE CONTRÔLE XAMPP\" (GRÂCE À WWW.NAT32.COM). IL EST LANCÉ AVEC :\r\\XAMPP\\XAMPP-CONTROL.EXE\rDES FICHIERS BATCH PERMETTENT AUSSI DE DÉMARRER/STOPPER LES SERVEURS:\rDÉMARRER APACHE & MYSQL:\n\\XAMPP\\XAMPP_START.EXE\rARRÊTER APACHE & MYSQL:\n\\XAMPP\\XAMPP_STOP.EXE\rDÉMARRER APACHE:\n\\XAMPP\\APACHE_START.BAT\rARRÊT DE APACHE:\n\\XAMPP\\APACHE_STOP.BAT\rDÉMARRER MYSQL:\n\\XAMPP\\MYSQL_START.BAT\rARRÊTER MYSQL:\n\\XAMPP\\MYSQL_STOP.BAT\rDÉMARRER MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_START.BAT\rARRÊTER MERCURY MAILSEVER:\n\\XAMPP\\MERCURY_STOP.BAT\rDÉMARRER FILEZILLO SERVER:\n\\XAMPP\\FILEZILLA_START.BAT\rARRÊTER FILEZILLA SERVER:\n\\XAMPP\\FILEZILLA_STOP.BAT\rCOMMENT TESTER SI TOUT A FONCTIONNÉ ?\rCONSULTEZ AVEC VOTRE NAVIGATEUR CETTE URL:\rHTTP://LOCALHOST/\rOU \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rCOMMENT INSTALLER UN SERVEUR COMME SERVICE?\rCHAQUE SERVEUR DANS XAMPP PEUT DEVENIR UN SERVICE WINDOWS. C\'EST POSSIBLE DEPUIS LE PANNEAU DE CONTRÔLE XAMPP. IL EST ALORS NÉCESSAIRE DE DÉMARRER LE PANNEAU DE CONTRÔLE EN TANT QU\'ADMINISTRATEUR.\rINSTALLATION DU SERVICE APACHE : \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rDÉSINSTALLATION DU SERVICE APACHE : \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rINSTALLATION DU SERVICE MYSQL : \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rDÉSINSTALLATION DU SERVICE MYSQL : \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \r(DÉS)INSTALLATION DU SERVICE FILEZILLA: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: SERVICE D\'INSTALLATION NON DISPONIBLE\rXAMPP DESTINÉ À LA PRODUCTION?\rXAMPP EST DESTINÉ EXCLUSIVEMENT AUX DÉVELOPPEURS. LA MANIÈRE DONT XAMPP EST CONFIGURÉ DONNE UN MAXIMUM DE LIBERTÉS EN COURS DE DÉVELOPPEMENT. CECI PERMET DE GAGNER DU TEMPS EN PHASE DE DÉVELOPPEMENT, MAIS PEUT ÊTRE FATAL EN ENVIRONNEMENT DE PRODUCTION.\rLISTE DES TROUS DE SÉCURITÉ DANS XAMPP:\rL\'ADMINISTRATEUR MYSQL (ROOT) SANS MOT DE PASSE.\rLE DÉMON MYSQL EST ACCESSIBLE VIA LE RÉSEAU.\rPROFTPD UTILISE LE MOT DE PASSE \"LAMPP\" POUR L\'UTILISATEUR \"DAEMON\".\rLES UTILISATEURS PAR DÉFAUT DE MERCURY ET FILEZILLA SONT CONNUS.\rTOUT PEUT ÊTRE UNE FAILLE DE SÉCURITÉ. SPÉCIALEMENT SI XAMPP EST ACCESSIBLE EN RÉSEAU LOCAL OU AU DELÀ. LA PRÉSENCE D\'UN PARE-FEU OU D\'UN ROUTEUR (NAT) PEUT AIDER, CAR DANS CE CAS VOTRE PC EST NORMALEMENT INACCESSIBLE VIA LE RÉSEAU. C\'EST À VOUS DE RÉSOUDRE CES QUESTIONS. LA \"CONSOLE DE SÉCURITÉ XAMPP\" APPORTERA UNE PETITE AIDE.\rSÉCURISEZ XAMPP AVANT TOUTE PUBLICATION EN LIGNE. UN PARE-FEU OU UN ROUTEUR SUFFISENT POUR DE FAIBLES NIVEAUX DE SÉCURITÉ. POUR PLUS DE SÉCURITÉ, UTILISEZ LA \"CONSOLE DE SÉCURITÉ XAMPP\" ET CHOISISSEZ DES MOTS DE PASSES.\rSI VOUS DÉSIREZ QUE VOTRE XAMPP SOIT ACCESSIBLE DEPUIS INTERNET, VISITEZ L\'URI SUIVANTE POUR RÉSOUDRE CERTAINS PROBLÈMES :\rHTTP://LOCALHOST/SECURITY/\rDANS LA CONSOLE DE SÉCURITÉ VOUS POURREZ CHOISIR UN MOT DE PASSE POUR L\'UTILISATEUR \"ROOT\" DE MYSQL ET PHPMYADMIN. OU ACTIVER UNE IDENTIFICATION POUR LES PAGES DE DÉMO XAMPP.\rCET OUTIL EN LIGNE NE RÉSOUT AUCUNE QUESTION DE SÉCURITÉ SUPPLÉMENTAIRE ! VEILLEZ SPÉCIALEMENT À SÉCURISER VOUS-MÊME LE SERVEUR FTP FILEZILLA ET LE SERVEUR MAIL MERCURY.\rCOMMENT DÉSINSTALLER XAMPP ?\rNOUS RECOMMANDONS FORTEMENT D\'UTILISER L\'OUTIL DE DÉSINSTALLATION POUR SUPPRIMER UNE INSTALLATION XAMPP FAITE AVEC L\'INSTALLATEUR. CET OUTIL DE DÉSINSTALLATION SUPPRIMERA LES ENTRÉES DE LA BASE DE REGISTRE AINSI QUE CERTAINS SERVICES INSTALLÉS AVEC XAMPP. AVANT D\'UTILISER CET OUTIL DE DÉSINSTALLATION, AYEZ SOIN DE SAUVEGARDER LES DONNÉES QUE VOUS DÉSIREZ CONSERVER.\rSI VOUS AVIEZ INSTALLÉ XAMPP EN UTILISANT LES VERSIONS ZIP ET 7ZIP, ARRÊTEZ TOUS LES SERVEURS XAMPP ET FERMEZ TOUS LES PANNEAUX. SI VOUS AVIEZ INSTALLÉ DES SERVICES, ARRÊTEZ LES ET DÉSINSTALLEZ LES AUSSI. ENSUITE, SUPPRIMEZ LE RÉPERTOIRE XAMPP. IL N\'Y A PAS D\'ENTRÉES DE REGISTRE NI DE VARIABLES D\'ENVIRONNEMENT À NETTOYER.\rQU\'EST CE QUE LA VERSION \"LITE\" DE XAMPP?\rXAMPP LITE (SIGNIFIE \"LÉGER\" COMME \"POIDS LÉGER\") EST UN SOUS-ENSEMBLE DE COMPOSANTS XAMPP, RECOMMANDÉ POUR DU TRAVAIL RAPIDE AVEC SEULEMENT PHP ET MYSQL. CERTAINS SERVEURS OU OUTILS COMME MERCURY MAIL ET FILEZILLA FTP SONT ABSENTS DE LA VERSION LITE.\rOÙ DEVRAIS-JE PLACER MON CONTENU WEB?\rLE RÉPERTOIRE PRINCIPAL POUR LES DOCUMENTS WWW EST \\\\XAMPP\\\\HTDOCS. PLACEZ-Y UN FICHIER \"TEST.HTML\" DANS CE RÉPERTOIRE, ET ACCÉDEZ-Y AVEC L\'URI \"HTTP://LOCALHOST/TEST.HTML\".\rET \"TEST.PHP\" ? UTILISEZ \"HTTP://LOCALHOST/TEST.PHP\". UN SCRIPT DE TEST PEUT ÊTRE:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rUN NOUVEAU SOUS-RÉPERTOIRE POUR VOTRE WEB? CRÉEZ UN RÉPERTOIRE (PAR EX. \"NOUVEAU\") DANS \"\\\\XAMPP\\\\HTDOCS\" (DE PRÉFÉRENCE SANS ESPACES ET SEULEMENT EN ASCII), CRÉEZ-Y UN FICHIER DE TEST ACCESSIBLE AVEC \"HTTP://LOCALHOST/NOUVEAU/TEST.PHP\".\rAUTRES SPÉCIFICITÉS\rHTML:\rEXÉCUTABLE: \\XAMPP\\HTDOCS\rSUFFIXES AUTORISÉS: .HTML .HTM\r=> PAQUETAGE DE BASE\rSSI:\rEXÉCUTABLE: \\XAMPP\\HTDOCS\rSUFFIXES AUTORISÉS: .SHTML\r=> PAQUETAGE DE BASE\rCGI:\rEXÉCUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rSUFFIXES AUTORISÉS: .CGI\r=> PAQUETAGE DE BASE\rPHP:\rEXÉCUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rSUFFIXES AUTORISÉS: .PHP\r=> PAQUETAGE DE BASE\rPERL:\rEXÉCUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rSUFFIXES AUTORISÉS: .PL\r=> PAQUETAGE DE BASE\rAPACHE::ASP PERL:\rEXÉCUTABLE: \\XAMPP\\HTDOCS\rSUFFIXES AUTORISÉS: .ASP\r=> PAQUETAGE DE BASE\rJSP JAVA:\rEXÉCUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rSUFFIXES AUTORISÉS: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rEXÉCUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rSUFFIXES AUTORISÉS: .HTML (U.A)\r=> TOMCAT ADD-ON\rPUIS JE DÉPLACER L\'INSTALLATION XAMPP?\rOUI. D\'ABORD, DÉPLACEZ LE RÉPERTOIRE XAMPP, ENSUITE EXÉCUTEZ \"SETUP_XAMPP.BAT\". LES CHEMINS DANS LES FICHIERS DE CONFIGURATION SERONT ACTUALISÉS.\rSI VOUS AVEZ INSTALLÉ UN SERVEUR COMME SERVICE WINDOWS, VOUS DEVEZ D\'ABORD SUPPRIMER LE SERVICE ET APRÈS DÉPLACEMENT, VOUS POUVEZ RÉINSTALLER LE SERVICE.\rATTENTION : VOS FICHIERS DE CONFIGURATION, COMME CEUX DE VOS APPLICATIONS PHP, NE SONT PAS ACTUALISÉS. MAIS IL EST POSSIBLE D\'ÉCRIRE UN \"PLUG-IN\" POUR L\'INSTALLATEUR, AVEC LEQUEL L\'INSTALLATEUR PEUT AJUSTER CES FICHIERS.\rQUE SONT LES \"PAGES DE DÉMARRAGE AUTOMATIQUE\" DES RÉPERTOIRES WWW ?\rLE NOM DE FICHIER STANDARD DE LA FONCTION APACHE \"DIRECTORYINDEX\" EST \"INDEX.HTML\" OU \"INDEX.PHP\". CHAQUE FOIS QUE VOUS NAVIGUEZ VERS UN DOSSIER (PAR EX. \"HTTP://LOCALHOST/XAMPP/\") OÙ APACHE PEUT TROUVER UN TEL FICHIER, APACHE L\'AFFICHERA AU LIEU DE LA LISTE DES FICHIERS DU RÉPERTOIRE.\rOÙ PUIS-JE CHANGER LA CONFIGURATION ?\rPRATIQUEMENT TOUS LES PARAMÈTRES DE XAMPP PEUVENT ÊTRE MODIFIÉS AVEC LES FICHIERS DE CONFIGURATION. OUVREZ SIMPLEMENT LE FICHIER DANS UN ÉDITEUR DE TEXTE ET CHANGEZ LE PARAMÈTRE DÉSIRÉ. SEULS FILEZILLA ET MERCURY DOIVENT ÊTRE CONFIGURÉS AVEC L\'OUTIL DE CONFIGURATION DE L\'APPLICATION.\rPOURQUOI XAMPP NE PEUT IL FONCTIONNER SUR WINDOWS XP SP2 ?\rAVEC LE SERVICE PACK 2 (SP2), MICROSOFT FOURNIT UN MEILLEUR FIREWALL QUI DÉMARRE AUTOMATIQUEMENT. CE FIREWALL BLOQUE LES INDISPENSABLES PORTS 80 (HTTP) ET 443 (HTTPS) ET APACHE NE PEUT PAS DÉMARRER.\rSOLUTION RAPIDE :\rDÉSACTIVEZ LE PARE-FEU DE MICROSOFT À L\'AIDE DE LA BARRE D\'OUTILS ET ESSAYEZ DE RELANCER XAMPP. LA MEILLEURE SOLUTION EST DE DÉFINIR UNE EXCEPTION DANS LE CENTRE DE SÉCURITÉ.\rLES PORTS SUIVANTS SONT UTILISÉS POUR UN FONCTIONNEMENT DE BASE :\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rPOURQUOI XAMPP NE FONCTIONNE-T-IL PAS SUR VISTA ?\rCONTRÔLE DES COMPTES D\'UTILISATEURS (UAC)\rDANS LE RÉPERTOIRE \"C:\\\\PROGRAM FILES\", VOUS N\'AVEZ PAS LES DROITS D\'ÉCRITURE COMPLETS, MÊME EN TANT QU\'ADMINISTRATEUR. OU BIEN VOUS N\'AVEZ QUE DES DROITS LIMITÉS (PAR EX. POUR \".\\\\XAMPP\\\\HTDOCS\"). DANS CE CAS, VOUS NE POUVEZ PAS ÉDITER UN FICHIER.\rSOLUTION :\rAUGMENTEZ VOS DROITS DANS L\'EXPLORATEUR (CLIC DROIT / SÉCURITÉ) OU DÉSACTIVEZ LE CONTRÔLE DES COMPTES D\'UTILISATEURS (UAC).\rVOUS AVEZ INSTALLÉ APACHE/MYSQL DANS \"C:\\\\XAMPP\" COMME UN SERVICE WINDOWS MAIS VOUS NE POUVEZ DÉMARRER/ARRÊTER LES SERVICES AVEC LE \"PANNEAU DE CONTRÔLE XAMPP\" OU VOUS NE POUVEZ PAS LES DÉSINSTALLER.\rSOLUTION :\rUTILISEZ LA CONSOLE DE GESTION DES SERVICES DE WINDOWS OU DÉSACTIVEZ L\'UAC.\rDÉSACTIVATION DU CONTRÔLE DE COMPTE D\'UTILISATEUR (UAC)\rPOUR DÉSACTIVER L\'UAC, UTILISEZ LE PROGRAMME \"MSCONFIG\". DANS \"MSCONFIG\", ALLEZ DANS \"OUTILS\", SÉLECTIONNEZ \"DÉSACTIVER LE CONTRÔLE DE COMPTE D\'UTILISATEUR\" ET VÉRIFIEZ VOTRE SÉLECTION. VOUS DEVEZ REDÉMARRER WINDOWS. DANS LE MÊME TEMPS, VOUS POUVEZ RÉACTIVER L\'UAC.\rCOMMENT VÉRIFIÉ-JE L\'EMPREINTE MD5 ?\rPOUR COMPARER LES FICHIERS, DES EMPREINTES SONT SOUVENT UTILISÉES. UNE NORME POUR CRÉER CETTE EMPREINTE MD5 (MESSAGE DIGEST ALGORITHM 5).\rAVEC CETTE EMPREINTE MD5 VOUS POUVEZ VÉRIFIER SI VOTRE PAQUETAGE XAMPP TÉLÉCHARGÉ EST CORRECT. BIEN SÛR VOUS DEVEZ DISPOSER D\'UN PROGRAMME DE CRÉATION DE TELLES EMPREINTES. POUR WINDOWS, VOUS POUVEZ UTILISER UN OUTIL DE MICROSOFT :\rDISPONIBILITÉ ET DESCRIPTION DE L\'UTILITAIRE DE VÉRIFICATION DE L\'INTÉGRITÉ DE L\'EMPREINTE\rIL EST AUSSI POSSIBLE D\'UTILISER N\'IMPORTE QUEL AUTRE PROGRAMME QUI PEUT GÉNÉRER UNE EMPREINTE MD5, COMME LE GNU MD5SUM.\rCOMME VOUS AVEZ INSTALLÉ UN TEL PROGRAMME (PAR EX. FCIV.EXE), VOUS POUVEZ SUIVRE LES ÉTAPES SUIVANTES :\rTÉLÉCHARGEZ XAMPP (PAR EX. XAMPP-WIN32-1.8.2-0.EXE)\rGÉNÉREZ L\'EMPREINTE AVEC :\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rET MAINTENANT VOUS POUVEZ COMPARER L\'EMPREINTE AVEC CELLE QUI SE TROUVE SUR LA PAGE D\'ACCUEIL DE XAMPP POUR WINDOWS.\rSI LES DEUX EMPREINTES SONT IDENTIQUES, TOUT VA BIEN. SINON, LE TÉLÉCHARGEMENT EST CORROMPU OU LE FICHIER A ÉTÉ MODIFIÉ.\rPOURQUOI LES CHANGEMENTS DE MON PHP.INI N\'ONT ILS PAS ÉTÉ PRIS EN COMPTE ?\rSI UN CHANGEMENT DU \"PHP.INI\" DEMEURE SANS EFFET, IL EST POSSIBLE QUE PHP EN UTILISE UN AUTRE. VOUS POUVEZ LE VÉRIFIER PAR PHPINFO(). RENDEZ VOUS À L\'URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP ET RECHERCHEZ \"FICHIER DE CONFIGURATION CHARGÉ\". LA VALEUR VOUS INDIQUE LE \"PHP.INI\" RÉELLEMENT UTILISÉ.\rNOTA :\rAPRÈS MODIFICATION DE \"PHP.INI\" VOUS DEVEZ REDÉMARRER APACHE POUR QUE LES NOUVEAUX PARAMÈTRES SOIENT LUS.\rAU SECOURS ! IL Y A UN VIRUS DANS XAMPP !\rQUELQUES PROGRAMMES ANTIVIRUS PRENNENT À TORT XAMPP POUR UN VIRUS, EN POINTANT GÉNÉRALEMENT LE FICHIER XAMPP-MANAGER.EXE. CECI EST UN FAUX POSITIF, CAR CE FICHIER N\'EST PAS UN VIRUS. AVANT DE DIFFUSER TOUTE NOUVELLE VERSION DE XAMPP, NOUS LA SCANNONS AVEC UN LOGICIEL DE DÉTECTION DE VIRUS. ACTUELLEMENT, NOUS UTILISONS \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rCOMMENT CONFIGURER MON ANTIVIRUS ?\rNOUS AVONS INCLUS TOUTES LES DÉPENDANCES ET SERVEURS REQUIS POUR EXÉCUTER L\'APPLICATION WEB EMPAQUETÉE, VOUS TROUVEREZ DONC QUE XAMPP INSTALLE UN GRAND NOMBRE DE FICHIERS. SI VOUS INSTALLEZ UNE APPLICATION XAMPP SUR UNE MACHINE WINDOWS AVEC UN ANTIVIRUS ACTIF, L\'INSTALLATION PEUT ÊTRE SIGNIFICATIVEMENT RALENTIE ET IL EST POSSIBLE QU\'UN DES SERVEURS (SERVEUR WEB, SERVEUR DE BASE DE DONNÉES) SOIT BLOQUÉ PAR L\'ANTIVIRUS. SI VOTRE ANTIVIRUS EST ACTIVÉ, VÉRIFIEZ LES PARAMÈTRES SUIVANTS POUR EXÉCUTER XAMPP SANS PROBLÈME DE PERFORMANCE :\rAJOUTEZ DES EXCEPTIONS DANS LE FIREWALL : POUR APACHE, MYSQL OU TOUT AUTRE SERVEUR.\rANALYSEZ LES FICHIERS LORS DE L\'EXÉCUTION : SI VOUS AVEZ ACTIVÉ L\'ANALYSE ANTIVIRUS POUR TOUS LES FICHIERS, LES FICHIERS EXÉCUTABLES POUR LES SERVEURS PEUVENT RALENTIR.\rANALYSEZ LE TRAFIC POUR DIFFÉRENTES URL : SI VOUS DÉVELOPPEZ AVEC XAMPP SUR VOTRE PROPRE MACHINE, VOUS POUVEZ EXCLURE LE TRAFIC \"LOCALHOST\" DES PARAMÈTRES DE L\'ANTIVIRUS.\rPOURQUOI LE SERVEUR APACHE NE DÉMARRE-T-IL PAS SUR MON SYSTÈME ?\rCE PROBLÈME PEUT AVOIR PLUSIEURS CAUSES :\rVOUS AVEZ LANCÉ PLUS D\'UN SERVEUR HTTP (IIS, SAMBAR, ZEUS ET AUTRES). UN SEUL SERVEUR PEUT UTILISER LE PORT 80. LE MESSAGE D\'ERREUR INDIQUE LE PROBLÈME :\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rVOUS AVEZ UN AUTRE LOGICIEL, COMME LE TÉLÉPHONE PAR INTERNET \"SKYPE\" QUI BLOQUE ÉGALEMENT LE PORT 80. SI LE PROBLÈME EST \"SKYPE\", VOUS POUVEZ ALLER DANS SKYPE JUSQU\'À ACTIONS --> OPTIONS --> CORRECTION --> DÉCOCHER LA CASE \"UTILISER LE PORT 80 COMME PORT ALTERNATIF\" AVANT DE REDÉMARRER SKYPE. MAINTENANT ÇA DEVRAIT FONCTIONNER.\rVOTRE FIREWALL BLOQUE LE PORT APACHE. TOUS LES FIREWALLS NE SONT PAS COMPATIBLES AVEC APACHE, ET PARFOIS LA DÉSACTIVATION DU FIREWALL NE SUFFIT PAS ET VOUS DEVEZ LE DÉSINSTALLER. CE MESSAGE D\'ERREUR SIGNALE UN FIREWALL :\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rSI APACHE DÉMARRE, MAIS QUE VOTRE NAVIGATEUR NE PEUT PAS S\'Y CONNECTER, CELA PEUT AVOIR L\'UNE DES CAUSES SUIVANTES :\rCERTAINS SCANNERS DE VIRUS PEUVENT LE PROVOQUER DE LA MÊME MANIÈRE QUE LES FIREWALLS PEUVENT INTERFÉRER.\rVOUS AVEZ XP PROFESSIONNEL SANS LE SERVICE PACK 1. VOUS DEVEZ AU MOINS DISPOSER DE SP1 POUR XAMPP.\rASTUCE :\rSI VOUS AVEZ DES PROBLÈMES AVEC LES PORTS UTILISÉS, VOUS POUVEZ UTILISER L\'OUTIL \"XAMPP-PORTCHECK.EXE\". CELA VOUS AIDERA PEUT ÊTRE.\rPOURQUOI MA CHARGE CPU POUR APACHE ATTEINT ELLE PRESQUE 99% ?\rL\'UN DES DEUX SCENARIOS EST EN JEU ICI. SOIT VOTRE CPU PLAFONNE, SOIT VOTRE NAVIGATEUR SE CONNECTE AU SERVEUR, MAIS NE VOIT RIEN (LE SYSTÈME ESSAIE SANS SUCCÈS DE CHARGER LA PAGE). DANS LES DEUX CAS, VOUS POUVEZ TROUVER LE MESSAGE SUIVANT DANS LE FICHIER JOURNAL D\'APACHE :\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rLE MPM A RECOURS À UNE IMPLÉMENTATION PLUS SÛRE, MAIS CERTAINES REQUÊTES DE CLIENTS N\'ONT PAS ÉTÉ TRAITÉES CORRECTEMENT. POUR ÉVITER CETTE ERREUR, UTILISEZ \"ACCEPTFILTER\" AVEC L\'OPTION \"AUCUN\" DANS LE FICHIER \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\".\rPOURQUOI LES IMAGES ET LES FEUILLES DE STYLE NE S\'AFFICHENT ELLES PAS ?\rQUELQUEFOIS IL Y A DES PROBLÈMES AVEC L\'AFFICHAGE DES IMAGES ET DES FEUILLES DE STYLE. SURTOUT SI CES FICHIERS SONT SITUÉS SUR UN PÉRIPHÉRIQUE RÉSEAU. DANS CE CAS, VOUS POUVEZ ACTIVER (OU AJOUTER) L\'UNE DES LIGNES SUIVANTES DANS LE FICHIER \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\" :\rENABLESENDFILE OFF\rENABLEMMAP OFF\rCE PROBLÈME PEUT AUSSI ÊTRE CAUSÉ PAR DES PROGRAMMES DE RÉGULATION DE LA BANDE PASSANTE, TELS QUE NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rCOMMENT PUIS JE ATTRIBUER UN MOT DE PASSE À ROOT DANS MYSQL ?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rPUIS-JE UTILISER MON PROPRE SERVEUR MYSQL ?\rOUI. IL SUFFIT DE NE PAS LANCER MYSQL À PARTIR DU PAQUETAGE XAMPP. NOTEZ QUE DEUX SERVEURS NE PEUVENT PAS ÊTRE DÉMARRÉS SUR LE MÊME PORT. SI VOUS AVEZ ATTRIBUÉ UN MOT DE PASSE À \"ROOT\", N\'OUBLIEZ PAS DE MODIFIER LE FICHIER \"\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP\".\rCOMMENT RESTREINDRE L\'ACCÈS À PHPMYADMIN DEPUIS L\'EXTÉRIEUR ?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rAVANT DE VOUS LAISSER ACCÉDER AU SERVEUR MYSQL, PHPMYADMIN VOUS DEMANDERA UN NOM D\'UTILISATEUR ET UN MOT DE PASSE. N\'OUBLIEZ PAS EN PREMIER D\'ATTRIBUER UN MOT DE PASSE À L\'UTILISATEUR \"ROOT\".\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rOÙ EST LE SUPPORT IMAP DE PHP ?\rA DÉFAUT, LE SUPPORT IMAP DE PHP EST DÉSACTIVÉ DANS XAMPP EN RAISON D\"ERREURS MYSTÉRIEUSES D\'INITIALISATION AVEC CERTAINES VERSIONS FAMILIALES COMME WINDOWS 98. SI VOUS TRAVAILLEZ AVEC LES SYSTÈMES NT, VOUS POUVEZ OUVRIR LE FICHIER \"\\\\XAMPP\\\\PHP\\\\PHP.INI\" POUR ACTIVER L\'EXTENSION PHP EN SUPPRIMANT LE POINT-VIRGULE AU DÉBUT DE LA LIGNE \";EXTENSION=PHP_IMAP.DLL\". CA DEVRAIT ÊTRE :\rEXTENSION=PHP_IMAP.DLL\rREDÉMARREZ APACHE ET IMAP DEVRAIT FONCTIONNER. VOUS POUVEZ SUIVRE LES MÊMES ÉTAPES POUR CHAQUE EXTENSION QUI N\'EST PAS ACTIVÉE DANS LA CONFIGURATION PAR DÉFAUT.\rPOURQUOI CERTAINES APPLICATIONS PHP LIBRES NE FONCTIONNENT ELLES PAS AVEC XAMPP SOUS WINDOWS ?\rUN GRAND NOMBRE D\'APPLICATIONS OU D\'EXTENSIONS PHP ÉCRITES POUR LINUX N\'ONT PAS ÉTÉ PORTÉES SOUS WINDOWS. \rPUIS-JE SUPPRIMER LE RÉPERTOIRE \"INSTALL\' APRÈS L\'INSTALLATION ?\rIL NE VAUT MIEUX PAS. LES SCRIPTS QU\'IL CONTIENT RESTENT NÉCESSAIRES AUX PAQUETAGES ADDITIONNELS (ADD-ONS) ET AUX MISES À JOUR DE XAMPP.\rCOMMENT ACTIVÉ-JE L\'EACCELERATOR ?\rCOMME D\'AUTRES EXTENSIONS (ZEND), VOUS POUVEZ L\'ACTIVER DANS \"PHP.INI\". DANS CE FICHIER, ACTIVEZ LA LIGNE \";ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"\". CE DEVRAIT ÊTRE :\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rCOMMENT PUIS-JE CORRIGER UNE ERREUR DE CONNEXION À MON SERVEUR MS SQL ?\rSI L\'EXTENSION MSSQL A ÉTÉ CHARGÉE DANS LE PHP.INI, DES PROBLÈMES PEUVENT APPARAÎTRE QUAND SEUL TCP/IP EST UTILISÉ. VOUS POUVEZ CORRIGER CE PROBLÈME AVEC UN NOUVEAU \"NTWDBLIB.DLL\" DE MICROSOFT. REMPLACEZ L\'ANCIEN FICHIER DANS \"\\\\XAMPP\\\\APACHE\\\\BIN\" ET DANS \"\\\\XAMPP\\\\PHP\" PAR LE NOUVEAU. EN RAISON DE LA LICENCE, NOUS NE POUVONS PAS EMPAQUETER UNE NOUVELLE VERSION DE CE FICHIER DANS XAMPP.\rCOMMENT FAIS-JE POUR TRAVAILLER AVEC L\'EXTENSION MCRYPT DE PHP ?\rPOUR CELA, NOUS AVONS OUVERT UN SUJET DANS LE FORUM AVEC DES EXEMPLES ET DES SOLUTIONS POSSIBLES : \rSUJET MCRYPT\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rNON. ET APACHE::ASP AVEC LE COMPLÉMENT PERL N\'EST PAS PAREIL. APACHE::ASP NE CONNAÎT QUE LE PERL-SCRIPT, MAIS ASP DE INTERNET INFORMATION SERVER (IIS) CONNAÎT AUSSI LE VBSCRIPT NORMAL. MAIS POUR ASP .NET, UN MODULE APACHE TIERS EST DISPONIBLE.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITIQUE DE CONFIDENTIALITÉ\rCDN FOURNI PAR\r\n'),(43,'05721c6b89251bcd66a46527fe0bd0ef','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rQUESTIONS FRÉQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITIQUE DE CONFIDENTIALITÉ\rCDN FOURNI PAR\r\n'),(44,'331a5f7e1f782f2fe2401641ca507b79','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rQUESTIONS FRÉQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITIQUE DE CONFIDENTIALITÉ\rCDN FOURNI PAR\r\n'),(45,'852ae75c135f707177272e67103a0ef1','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rQUESTIONS FRÉQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITIQUE DE CONFIDENTIALITÉ\rCDN FOURNI PAR\r\n'),(46,'b9cc09ea3d32195b582eb5d177c4e4b8','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rQUESTIONS FRÉQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rQUESTIONS FRÉQUENTES\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nCOMMUNAUTÉ\rXAMPP EXISTE DEPUIS PLUS DE 10 ANS  UNE ÉNORME COMMUNAUTÉ L\'APPUIE. VOUS POUVEZ EN FAIRE PARTIE EN REJOIGNANT NOS \rFORUMS\r, EN NOUS APPRÉCIANT SUR \rFACEBOOK\r, OU EN SUIVANT NOS EXPLOITS SUR \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITIQUE DE CONFIDENTIALITÉ\rCDN FOURNI PAR\r\n'),(47,'c98fdb255172f551bdc2765a11132fa1','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(48,'4e86cf127a9c707e9b4d5eeb430acdaf','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(49,'a5c0bb34ea39e4022e777b737a6f7373','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(50,'2821c3a5be76d397ce6273c8099c1c9b','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rGYAKORI KÉRDÉSEK\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rGYAKRAN ISMÉTELT KÉRDÉSEK\rHOGYAN TELEPÍTSEM A XAMPP-OT?\rA XAMPP WINDOWS VÁLTOZATA HÁROM KÜLÖNBÖZŐ FORMÁBAN LÉTEZIK:\rTELEPÍTŐ:\rVALÓSZÍNŰLEG A LEGEGYSZERŰBB MÓDJA A XAMPP TELEPÍTÉSÉNEK.\rZIP:\rPURISTÁKNAK: A XAMPP SZOKÁSOS ZIP ARCHÍVUMKÉNT.\r7ZIP:\rPURISTÁKNAK KIS SÁVSZÉLESSÉGGEL: A XAMPP 7ZIP ARCHÍVUMKÉNT.\rMEGJEGYZÉS: A FÁJLOK KIBONTÁSAKOR ELŐFORDULHATNAK HAMIS POZITÍV VÍRUSRIASZTÁSOK.\rA TELEPÍTŐ HASZNÁLATA:\rHASZNÁLJA A XAMPP VEZÉRLŐPULTOT AZ APACHE, MYSQL, FILEZILLAÉS A MERCURY SZOLGÁLTATÁSOK ELINDÍTÁSÁHOZ ÉS LEÁLLÍTÁSÁHOZ VAGY A SERVER SZOLGÁLTATÁSOK TELEPÍTÉSÉHEZ.\rTELEPÍTÉS ZIP-BŐL\rBONTSA KI A ZIP ARCHÍVUMOKAT A VÁLASZTOTT MAPPÁBA. A XAMPP A „C:\\\\XAMPP” ALKÖNYVTÁRBA KERÜL KIBONTÁSRA A VÁLASZTOTT CÉLKÖNYVTÁR ALÁ. MOST INDÍTSA EL A „SETUP_XAMPP.BAT” FÁJLT, HOGY ELVÉGEZZE A XAMPP BEÁLLÍTÁSÁT A RENDSZERÉHEZ.\rHA A „C:\\\\” GYÖKÉRKÖNYVTÁRAT VÁLASSZA CÉLNAK, AKKOR NEM SZABAD A „SETUP_XAMPP.BAT” FÁJLT FUTTATNIA.\rMINT A TELEPÍTŐ VERZIÓBAN, MOST MÁR HASZNÁLHATJA A „XAMPP VEZÉRLŐPULTOT” A TOVÁBBI FELADATOKHOZ.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rHOGYAN INDÍTHATOM A XAMPP PROGRAMOT BEÁLLÍTÁS NÉLKÜL?\rHA A XAMPP PROGRAMOT EGY FELSŐSZINTŰ MAPPÁBA BONTOTTA KI, MINT PÉLDÁUL „C:\\\\” VAGY „D:\\\\”, AKKOR A LEGTÖBB SZOLGÁLTATÁST - ÚGYMINT APACHE VAGY MYSQL - KÖZVETLENÜL IS EL TUDJA INDÍTANI A „SETUP_XAMPP.BAT” FÁJL FUTTATÁSA NÉLKÜL.\rNEM JAVASOLT A BEÁLLÍTÓ PARANCSFÁJL HASZNÁLATA, VAGY RELATÍV ELÉRÉSI UTAK KIVÁLASZTÁSA A BEÁLLÍTÓ PARANCSFÁJLBAN, HA A XAMPP PROGRAMOT USB-MEGHAJTÓRA TELEPÍTETTE. ENNEK OKA, HOGY MINDEN PC MÁS MEGHAJTÓBETŰT RENDELHET A MEGHAJTÓNAK. BÁRMIKOR ÁTVÁLTHAT ABSZOLÚT ÚTVONALAKRÓL RELATÍVAKRA A BEÁLLÍTÓ PARANCSFÁJLLAL.\rA LETÖLTÉSEK OLDALRÓL ELÉRHETŐ TELEPÍTŐ HASZNÁLATA A LEGEGYSZERŰBB MÓDJA A XAMPP TELEPÍTÉSÉNEK. A TELEPÍTÉS BEFEJEZÉSE UTÁN A START | PROGRAMOK | XAMPP HELYEN FOGJA MEGTALÁLNI A XAMPP PROGRAMOT. A XAMPP VEZÉRLŐPULTOT HASZNÁLHATJA AZ ÖSSZES KISZOLGÁLÓ INDÍTÁSÁHOZ ÉS LEÁLLÍTÁSÁHOZ, VALAMINT SZOLGÁLTATÁSOK TELEPÍTÉSÉHEZ ÉS ELTÁVOLÍTÁSÁHOZ.\rHASZNÁLJA A XAMPP VEZÉRLŐPULTOT AZ APACHE, MYSQL, FILEZILLAÉS A MERCURY SZOLGÁLTATÁSOK ELINDÍTÁSÁHOZ ÉS LEÁLLÍTÁSÁHOZ VAGY A SERVER SZOLGÁLTATÁSOK TELEPÍTÉSÉHEZ.\rHOGYAN INDÍTHATOM EL ÉS ÁLLÍTHATOM LE A XAMPP-OT?\rAZ EGYETEMES VEZÉRLŐPULT A „XAMPP VEZÉRLŐPULT” (KÖSZÖNET: WWW.NAT32.COM). AZ ALÁBBI MÓDON INDÍTHATÓ:\r\\XAMPP\\XAMPP-CONTROL.EXE\rHASZNÁLHAT NÉHÁNY KÖTEGFÁJLT IS A KISZOLGÁLÓK INDÍTÁSÁHOZ ÉS LEÁLLÍTÁSÁHOZ:\rAPACHE ÉS MYSQL INDÍTÁS:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE ÉS MYSQL LEÁLLÍTÁS:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE INDÍTÁS:\n\\XAMPP\\APACHE_START.BAT\rAPACHE LEÁLLÍTÁS:\n\\XAMPP\\APACHE_STOP.BAT\rMYSQL INDÍTÁS:\n\\XAMPP\\MYSQL_START.BAT\rMYSQL LEÁLLÍTÁS:\n\\XAMPP\\MYSQL_STOP.BAT\rMERCURY LEVELEZŐKISZOLGÁLÓ INDÍTÁS:\n\\XAMPP\\MERCURY_START.BAT\rMERCURY LEVELEZŐKISZOLGÁLÓ LEÁLLÍTÁS:\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA KISZOLGÁLÓ INDÍTÁS:\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA KISZOLGÁLÓ LEÁLLÍTÁS:\n\\XAMPP\\FILEZILLA_STOP.BAT\rHOGYAN ELLENŐRIZHETEM, HOGY MINDEN MŰKÖDIK-E?\rGÉPELJE BE A KÖVETKEZŐ URL-T A KEDVENC WEBBÖNGÉSZŐJÉBE:\rHTTP://LOCALHOST/\rVAGY \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rHOGYAN TUDOK EGY KISZOLGÁLÓT SZOLGÁLTATÁSKÉNT TELEPÍTENI?\rA XAMPP MINDEN KISZOLGÁLÓJA WINDOWS SZOLGÁLTATÁSKÉNT IS TELEPÍTHETŐ. EZT IS A XAMPP VEZÉRLŐPULTBÓL TUDJA TELEPÍTENI. EBBEN AZ ESETBEN A PARANCSFÁJLOK VAGY A VEZÉRLŐPULT FUTTATÁSA RENDSZERGAZDAI JOGOSULTSÁGOKKAL SZÜKSÉGES.\rAPACHE SZOLGÁLTATÁS TELEPÍTÉS: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rAPACHE SZOLGÁLTATÁS ELTÁVOLÍTÁS: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rMYSQL SZOLGÁLTATÁS TELEPÍTÉS: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rMYSQL SZOLGÁLTATÁS ELTÁVOLÍTÁS: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA SZOLGÁLTATÁS TELEPÍTÉS ÉS ELTÁVOLÍTÁS: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: NEM ÉRHETŐ EL SZOLGÁLTATÁS TELEPÍTÉS\rA XAMPP KÉSZEN ÁLL A MUNKÁHOZ?\rA XAMPP NEM A PRODUKTÍV HASZNÁLATOT JELENTI, EZ CSAK EGY FEJLESZTŐI KÖRNYEZET. A XAMPP OLY MÓDON LETT BEÁLLÍTVA, HOGY ANNYIRA NYITOTT LEGYEN, AMENNYIRE CSAK LEHETSÉGES, HOGY LEHETŐVÉ TEGYEN A FEJLESZTŐKNEK BÁRMIT, AMIT SZERETNÉNEK. EZ NAGYSZERŰ EGY FEJLESZTŐI KÖRNYEZETHEZ, DE PRODUKTÍV KÖRNYEZETBEN VÉGZETES LEHET.\rITT EGY LISTA A XAMPP HIÁNYZÓ BIZTONSÁGI DOLGAIRÓL:\rA MYSQL ADMINISZTRÁTORNAK (ROOT) NINCS JELSZAVA.\rA MYSQL DÉMON ELÉRHETŐ A HÁLÓZATON KERESZTÜL.\rA PROFTPD A „LAMPP” JELSZÓT HASZNÁLJA A „DAEMON” FELHASZNÁLÓHOZ.\rA MERCURY ÉS FILEZILLA ALAPÉRTELMEZETT FELHASZNÁLÓI ISMERTEK.\rMINDEN PONT HATALMAS BIZTONSÁGI KOCKÁZAT LEHET. KÜLÖNÖSEN AKKOR, HA A XAMPP ELÉRHETŐ A HÁLÓZATON KERESZTÜL ÉS A LAN-ON KÍVÜLI EMBEREK SZÁMÁRA. SEGÍTHET AZONBAN EGY TŰZFAL VAGY EGY ROUTER (NAT) HASZNÁLATA. EGY ROUTER VAGY EGY TŰZFAL ESETÉN A PC NORMÁLIS ESETBEN NEM ÉRHETŐ EL A HÁLÓZATON KERESZTÜL. ÖNTŐL FÜGG, HOGY KIJAVÍTJA-E EZEKET A HIBÁKAT. EGY KIS SEGÍTSÉGKÉNT LÉTEZIK EGY „XAMPP BIZTONSÁGI KONZOL”.\rKÉRJÜK TEGYE BIZTONSÁGOSSÁ A XAMPP PROGRAMOT, MIELŐTT BÁRMIT KÖZZÉTENNE ONLINE. EGY TŰZFAL VAGY EGY KÜLSŐ ROUTER CSAK ALACSONY SZINTŰ BIZTONSÁGHOZ ELEGENDŐ. A VALAMIVEL NAGYOBB BIZTONSÁG ÉRDEKÉBEN FUTTASSA A „XAMPP BIZTONSÁGI KONZOLT” ÉS RENDELJEN HOZZÁ JELSZAVAKAT.\rHA ELÉRHETŐVÉ SZERETNÉ TENNI A XAMPP PROGRAMOT AZ INTERNETEN, AKKOR LÁTOGASSA MEG A KÖVETKEZŐ URI-T, AMELY KIJAVÍTHAT NÉHÁNY PROBLÉMÁT:\rHTTP://LOCALHOST/SECURITY/\rA BIZTONSÁGI KONZOLLAL BEÁLLÍTHATJA A MYSQL „ROOT” FELHASZNÁLÓ ÉS A PHPMYADMIN JELSZAVÁT. TOVÁBBÁ BEKAPCSOLHATJA A HITELESÍTÉST A XAMPP BEMUTATÓ OLDALAKHOZ.\rEZ A WEBALAPÚ ESZKÖZ NEM JAVÍT KI SEMMILYEN EGYÉB BIZTONSÁGI PROBLÉMÁT! KÜLÖNÖSEN A FILEZILLA FTP-KISZOLGÁLÓ ÉS A MERCURY LEVELEZŐKISZOLGÁLÓ BIZTONSÁGÁRÓL KELL ÖNNEK GONDOSKODNIA.\rHOGYAN TÁVOLÍTHATOM EL A XAMPP-OT?\rAMENNYIBEN A TELEPÍTŐS VERZIÓVAL TELEPÍTETTE A XAMPP PROGRAMOT, HASZNÁLJA AZ ELTÁVOLÍTÓT. AZ ELTÁVOLÍTÓ EL FOG TÁVOLÍTANI MINDEN XAMPP BEJEGYZÉST A RENDSZERLEÍRÓ ADATBÁZISBÓL, ILLETVE EL FOGJA TÁVOLÍTANI A XAMPP RÉSZEKÉNT TELEPÍTETT SZOLGÁLTATÁSOKAT. ERŐSEN AJÁNLJUK, HOGY AZ ELTÁVOLÍTÓ HASZNÁLATÁVAL TÁVOLÍTSA EL A TELEPÍTŐS VERZIÓJÚ XAMPP TELEPÍTÉST. KÉSZÍTSEN BIZTONSÁGI MENTÉST A XAMPP ELTÁVOLÍTÁSA ELŐTT MINDEN OLYAN ADATRÓL, AMELYET MEG SZERETNE TARTANI.\rAMENNYIBEN A ZIP ÉS A 7ZIP VERZIÓKKAL TELEPÍTETTE A XAMPP PROGRAMOT, ÁLLÍTSON LE MINDEN XAMPP KISZOLGÁLÓT ÉS LÉPJEN KI MINDEN PANELBŐL. HA TELEPÍTETT VALAMILYEN SZOLGÁLTATÁST, TÁVOLÍTSA EL ÉS ÁLLÍTSA LE AZOKAT IS. MOST EGYSZERŰEN TÖRÖLJE AZ EGÉSZ MAPPÁT, AHOVA A XAMPP PROGRAMOT TELEPÍTETTE. NINCSENEK TÖRLENDŐ RENDSZERLEÍRÓ ADATBÁZIS BEJEGYZÉSEK ÉS NINCSENEK TÖRLENDŐ KÖRNYEZETI VÁLTOZÓK.\rMI A XAMPP „LITE” VERZIÓJA?\rA XAMPP LITE (AMELY „KÖNNYŰT” JELENT, ÚGYMINT „KÖNNYŰSÚLYÚ”) A XAMPP KOMPONENSEK KISEBB CSOMAGJA, AMELY KIZÁRÓLAG PHP ÉS MYSQL HASZNÁLATÁVAL TÖRTÉNŐ GYORS MUNKAVÉGZÉSHEZ AJÁNLOTT. NÉHÁNY KISZOLGÁLÓ VAGY ESZKÖZ, MINT PÉLDÁUL A MERCURY LEVELEZŐ ÉS A FILEZILLA FTP HIÁNYOZNAK A LITE VERZIÓBÓL.\rHOVÁ TEGYEM A WEBES TARTALMAKAT?\rMINDEN WWW DOKUMENTUM FŐ KÖNYVTÁRA A \\\\XAMPP\\\\HTDOCS. HA EBBE A KÖNYVTÁRBA TESZI A „TESZT.HTML” FÁJLT, AKKOR A „HTTP://LOCALHOST/TESZT.HTML” URI SEGÍTSÉGÉVEL FÉRHET HOZZÁ.\rÉS A „TESZT.PHP”? CSAK HASZNÁLJA A „HTTP://LOCALHOST/TESZT.PHP” HIVATKOZÁST. EGY EGYSZERŰ TESZT-PARANCSFÁJL LEHET:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rEGY ÚJ ALKÖNYVTÁR A WEBHEZ? CSAK HOZZON LÉTRE EGY ÚJ KÖNYVTÁRAT (PÉLDÁUL „VALAMI”) A „\\\\XAMPP\\\\HTDOCS” KÖNYVTÁRON BELÜL (A LEGJOBB SZÓKÖZÖK NÉLKÜL ÉS CSAK ASCII KARAKTEREKKEL), HOZZON LÉTRE EGY TESZTFÁJLT EBBEN A KÖNYVTÁRBAN ÉS ELÉRHETI A „HTTP://LOCALHOST/VALAMI/TESZT.PHP” CÍMEN.\rTOVÁBBI SPECIFIKÁCIÓK\rHTML:\rPROGRAMFÁJL: \\XAMPP\\HTDOCS\rENGEDÉLYEZETT VÉGZŐDÉSEK: .HTML .HTM\r=> ALAP CSOMAG\rSSI:\rPROGRAMFÁJL: \\XAMPP\\HTDOCS\rENGEDÉLYEZETT VÉGZŐDÉSEK: .SHTML\r=> ALAP CSOMAG\rCGI:\rPROGRAMFÁJL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rENGEDÉLYEZETT VÉGZŐDÉSEK: .CGI\r=> ALAP CSOMAG\rPHP:\rPROGRAMFÁJL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rENGEDÉLYEZETT VÉGZŐDÉSEK: .PHP\r=> ALAP CSOMAG\rPERL:\rPROGRAMFÁJL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rENGEDÉLYEZETT VÉGZŐDÉSEK: .PL\r=> ALAP CSOMAG\rAPACHE::ASP PERL:\rPROGRAMFÁJL: \\XAMPP\\HTDOCS\rENGEDÉLYEZETT VÉGZŐDÉSEK: .ASP\r=> ALAP CSOMAG\rJSP JAVA:\rPROGRAMFÁJL: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rENGEDÉLYEZETT VÉGZŐDÉSEK: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rPROGRAMFÁJL: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rENGEDÉLYEZETT VÉGZŐDÉSEK: .HTML (U.A)\r=> TOMCAT ADD-ON\rÁTHELYEZHETEM A XAMPP TELEPÍTÉSÉT?\rIGEN. A XAMPP KÖNYVTÁR ÁTHELYEZÉSE UTÁN LE KELL FUTTATNIA A „SETUP_XAMPP.BAT” PARANCSFÁJLT. A BEÁLLÍTÓFÁJLBAN LÉVŐ ELÉRÉSI ÚT EHHEZ A LÉPÉSHEZ LESZ IGAZÍTVA.\rAMENNYIBEN VALAMILYEN KISZOLGÁLÓT WINDOWS SZOLGÁLTATÁSKÉNT TELEPÍTETT, AKKOR ELŐSZÖR EL KELL TÁVOLÍTANIA A WINDOWS SZOLGÁLTATÁST, MAJD AZ ÁTHELYEZÉS UTÁN ISMÉT TELEPÍTHETI AZT.\rFIGYELEM: A SAJÁT PARANCSFÁJLJAIBAN LÉVŐ BEÁLLÍTÓFÁJLOK, MINT PÉLDÁUL PHP ALKALMAZÁSOK, NEM LESZNEK HOZZÁIGAZÍTVA. DE LEHETSÉGES EGY „BŐVÍTMÉNY” ÍRÁSA A TELEPÍTŐHÖZ. EGY ILYEN BŐVÍTMÉNNYEL A TELEPÍTŐ EZEKET A FÁJLOKAT IS HOZZÁ TUDJA IGAZÍTANI.\rMIK AZ „AUTOMATIKUS NYITÓOLDALAK” A WWW KÖNYVTÁRAKHOZ?\rA SZABVÁNYOS FÁJLNÉV A „DIRECTORYINDEX” APACHE FÜGGVÉNYHEZ „INDEX.HTML” VAGY „INDEX.PHP”. MINDEN ESETBEN, AMIKOR RÁTALLÓZ EGY MAPPÁRA (PÉLDÁUL „HTTP://LOCALHOST/XAMPP/”), ÉS AZ APACHE TALÁL EGY ILYEN FÁJLT, AKKOR AZ APACHE EZT A FÁJLT JELENÍTI MEG A KÖNYVTÁR LISTÁZÁSA HELYETT.\rHOL TUDOM MEGVÁLTOZTATNI A BEÁLLÍTÁSOKAT?\rA XAMPP MAJDNEM MINDEN BEÁLLÍTÁSA MEGVÁLTOZTATHATÓ BEÁLLÍTÓFÁJLOKKAL. CSAK NYISSA MEG A FÁJLT EGY SZÖVEGSZERKESZTŐVEL ÉS VÁLTOZTASSA MEG AZT A BEÁLLÍTÁST, AMELYET SZERETNE. CSAK A FILEZILLA ÉS A MERCURY BEÁLLÍTÁSÁT KELL AZ ALKALMAZÁSBEÁLLÍTÓ ESZKÖZZEL ELVÉGEZNI.\rMIÉRT NEM MŰKÖDIK A XAMPP WINDOWS XP SP2 ALATT?\rA MICROSOFT EGY JOBB TŰZFALAT SZÁLLÍTOTT A 2. JAVÍTÓCSOMAGGAL (SP2), AMELY AUTOMATIKUSAN ELINDUL. EZ A TŰZFAL MÁR BLOKKOLJA A SZÜKSÉGES 80-AS (HTTP) ÉS 443-AS (HTTPS) PORTOKAT, ÉS AZ APACHE NEM TUD ELINDULNI.\rA GYORS MEGOLDÁS:\rTILTSA LE A MICROSOFT TŰZFALAT AZ ESZKÖZTÁRRAL, ÉS PRÓBÁLJA MEG MÉG EGYSZER ELINDÍTANI A XAMPP PROGRAMOT. A JOBB MEGOLDÁS EGY KIVÉTEL MEGHATÁROZÁSA A BIZTONSÁGI KÖZPONTON BELÜL.\rA KÖVETKEZŐ PORTOK VANNAK HASZNÁLATBAN AZ ALAP MŰKÖDÉSHEZ:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rMIÉRT NEM MŰKÖDIK A XAMPP VISTÁN?\rFELHASZNÁLÓI FIÓKOK FELÜGYELETE (UAC)\rA „C:\\\\PROGRAM FILES” KÖNYVTÁRRA NINCS TELJES ÍRÁSI JOGOSULTSÁGA, KIVÉVE RENDSZERGAZDAKÉNT. VAGY CSAK KORLÁTOZOTT JOGOSULTSÁGAI VANNAK (PÉLDÁUL A „.\\\\XAMPP\\\\HTDOCS” MAPPÁRA). EBBEN AZ ESETBEN NEM TUDJA SZERKESZTENI A FÁJLT.\rMEGOLDÁS:\rEMELJE MEG A JOGOSULTSÁGAIT AZ EXPLOREREN BELÜL (JOBB KATTINTÁS / BIZTONSÁG), VAGY TILTSA LE A FELHASZNÁLÓI FIÓKOK FELÜGYELETÉT (UAC).\rAZ APACHE/MYSQL KISZOLGÁLÓKAT A „C:\\\\XAMPP” HELYRE TELEPÍTETTE WINDOWS SZOLGÁLTATÁSKÉNT. DE NEM TUDJA ELINDÍTANI VAGY LEÁLLÍTANI A SZOLGÁLTATÁSOKAT A „XAMPP VEZÉRLŐPULTTAL”, VAGY NEM TUDJA ELTÁVOLÍTANI AZOKAT.\rMEGOLDÁS:\rHASZNÁLJA A WINDOWS SZOLGÁLTATÁSKEZELŐ KONZOLJÁT VAGY TILTSA LE AZ UAC-OT.\rA FELHASZNÁLÓI FIÓKOK FELÜGYELETÉNEK (UAC) LETILTÁSA\rAZ UAC LETILTÁSÁHOZ HASZNÁLJA AZ „MSCONFIG” PROGRAMOT. AZ „MSCONFIG” PROGRAMBAN MENJEN AZ „ESZKÖZÖKRE”, VÁLASSZA A „FELHASZNÁLÓI FIÓKOK FELÜGYELETÉNEK LETILTÁSA” LEHETŐSÉGET, ÉS ERŐSÍTSE MEG A VÁLASZTÁSÁT. EZUTÁN ÚJRA KELL INDÍTANIA A WINDOWST. EZZEL EGY IDŐBEN ISMÉT ENGEDÉLYEZHETI AZ UAC-OT.\rHOGYAN ELLENŐRIZHETEM AZ MD5 ELLENŐRZŐÖSSZEGET?\rFÁJLOK ÖSSZEHASONLÍTÁSÁHOZ GYAKRAN ELLENŐRZŐÖSSZEGEKET HASZNÁLNAK. A SZABVÁNY AZ MD5 (MESSAGE DIGEST ALGORITHM 5) ELLENŐRZŐÖSSZEG LÉTREHOZÁSA.\rEZZEL AZ MD5 ELLENŐRZŐÖSSZEGGEL TESZTELHETI, HOGY A XAMPP CSOMAG LETÖLTÉSE HELYES VOLT-E VAGY SEM. TERMÉSZETESEN SZÜKSÉGE VAN EGY OLYAN PROGRAMRA, AMELY ELŐ TUDJA ÁLLÍTANI EZEKET AZ ELLENŐRZŐÖSSZEGEKET. A WINDOWSNÁL HASZNÁLHATJA A MICROSOFT ESZKÖZÉT:\rELÉRHETŐSÉG ÉS FÁJL ELLENŐRZŐÖSSZEG INTEGRITÁS LEÍRÁSA ELLENŐRZŐ SEGÉDPROGRAM\rLEHETSÉGES BÁRMELY MÁS OLYAN PROGRAM HASZNÁLATA IS, AMELY LÉTRE TUD HOZNI MD5 ELLENŐRZŐÖSSZEGEKET, ÚGYMINT A GNU MD5SUM.\rHA TELEPÍTETT EGY ILYEN PROGRAMOT (PÉLDÁUL FCIV.EXE), VÉGEZZE EL A KÖVETKEZŐ LÉPÉSEKET:\rTÖLTSE LE A XAMPP CSOMAGOT (PÉLDÁUL XAMPP-WIN32-1.8.2-0.EXE)\rHOZZA LÉTRE AZ ELLENŐRZŐÖSSZEGET EZZEL:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rÉS MOST MÁR ÖSSZE TUDJA HASONLÍTANI EZT AZ ELLENŐRZŐÖSSZEGET AZZAL, AMELYET A WINDOWS RENDSZERRE KÉSZÍTETT XAMPP HONLAPJÁN TALÁL.\rHA MINDKÉT ELLENŐRZŐÖSSZEG AZONOS, AKKOR MINDEN RENDBEN VAN. HA NEM, AKKOR A LETÖLTÖTT FÁJL SÉRÜLT VAGY A FÁJL MÓDOSULT.\rMIÉRT NEM ÉRVÉNYESÜLNEK A PHP.INI FÁJLBAN ELVÉGZETT MÓDOSÍTÁSOK?\rHA A „PHP.INI” FÁJLBAN ELVÉGZETT MÓDOSÍTÁSNAK NINCS HATÁSA, LEHETSÉGES, HOGY A PHP EGY MÁSIKAT HASZNÁL. EZT A PHPINFO() FÜGGVÉNNYEL ELLENŐRIZHETI. LÁTOGASSA MEG A HTTP://LOCALHOST/XAMPP/PHPINFO.PHP OLDALT, ÉS KERESSEN RÁ A „LOADED CONFIGURATION FILE” KIFEJEZÉSRE. EZ AZ ÉRTÉK JELENÍTI MEG AZT A „PHP.INI” FÁJLT, AMELYET A PHP IGAZÁBÓL HASZNÁL.\rMEGJEGYZÉS:\rA „PHP.INI” MÓDOSÍTÁSA UTÁN ÚJRA KELL INDÍTANIA AZ APACHE WEBKISZOLGÁLÓT, HOGY AZ APACHE/PHP BE TUDJA OLVASNI AZ ÚJ BEÁLLÍTÁSOKAT.\rSEGÍTSÉG! VÍRUSOS A XAMPP!\rNÉHÁNY VÍRUSIRTÓ PROGRAM HIBÁSAN VÍRUSNAK ÉRZÉKELI A XAMPP-OT, TIPIKUSAN A XAMPP-MANAGER.EXE FÁJLT MEGJELÖLVE. EZ EGY VAKRIASZTÁS, AMELY AZT JELENTI, HOGY A VÍRUSIRTÓ TÉVESEN VÍRUSKÉNT AZONOSÍTJA, MIKÖZBEN NEM AZ. A XAMPP MINDEN EGYES ÚJ VERZIÓJÁNAK KIADÁSA ELŐTT LEFUTTATUNK EGY VÍRUSKERESŐ PROGRAMOT. JELENLEG EZT HASZNÁLJUK: \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rHOGYAN ÁLLÍTSAM BE A VÍRUSIRTÓ ALKALMAZÁSOMAT?\rMINDEN FÜGGŐSÉGET ÉS KISZOLGÁLÓT MELLÉKELÜNK, AMELY A CSOMAGOLT WEBALKALMAZÁS FUTTATÁSÁHOZ SZÜKSÉGES, ÍGY A XAMPP TELEPÍTÉSBEN NAGY SZÁMÚ FÁJLT FOG TALÁLNI. AMENNYIBEN A XAMPP ALKALMAZÁST EGY OLYAN WINDOWST FUTTATÓ SZÁMÍTÓGÉPRE TELEPÍTI, AMELYEN BEKAPCSOLT VÍRUSIRTÓ ALKALMAZÁS VAN, AKKOR EZ JELENTŐSEN LELASSÍTHATJA A TELEPÍTÉST, ÉS MEGVAN AZ ESÉLY ARRA, HOGY A KISZOLGÁLÓK EGYIKÉT (WEBKISZOLGÁLÓ, ADATBÁZIS-KISZOLGÁLÓ) BLOKKOLJA A VÍRUSIRTÓ PROGRAM. HA ENGEDÉLYEZVE VAN EGY VÍRUSIRTÓ ESZKÖZ, ELLENŐRIZZE A KÖVETKEZŐ BEÁLLÍTÁSOKAT A XAMPP TELJESÍTMÉNYPROBLÉMÁK NÉLKÜLI FUTTATÁSÁHOZ:\rKIVÉTELEK HOZZÁADÁSA A TŰZFALHOZ: AZ APACHE, A MYSQL VAGY BÁRMELY MÁS KISZOLGÁLÓHOZ.\rFÁJLOK VIZSGÁLATA VÉGREHAJTÁSKOR: HA ENGEDÉLYEZVE VAN A VÍRUSIRTÓ VIZSGÁLATA MINDEN FÁJLRA, A KISZOLGÁLÓK VÉGREHAJTHATÓ FÁJLJAIT LELASSÍTHATJA.\rA FORGALOM VIZSGÁLATA KÜLÖNBÖZŐ URL-EKNÉL: HA A SAJÁT GÉPÉN FEJLESZT A XAMPP PROGRAMMAL, ZÁRJA KI A „LOCALHOST” FORGALMÁT A VÍRUSIRTÓ BEÁLLÍTÁSAIBAN.\rMIÉRT NEM INDUL AZ APACHE KISZOLGÁLÓ A RENDSZEREMEN?\rENNEK A PROBLÉMÁNAK SZÁMOS OKA LEHET:\rEGYNÉL TÖBB HTTP KISZOLGÁLÓT INDÍTOTT EL (IIS, SAMBAR, ZEUS, STB.). CSAK EGYETLEN KISZOLGÁLÓ HASZNÁLHATJA A 80-AS PORTOT. EZ A HIBAÜZENET JELZI A PROBLÉMÁT:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rMÁS SZOFTVEREI IS VANNAK, MINT PÉLDÁUL A „SKYPE” INTERNETTELEFON, AMELY SZINTÉN BLOKKOLJA A 80-AS PORTOT. HA A „SKYPE” A PROBLÉMA, MENJEN A SKYPE PROGRAMBAN A MŰVELETEK --> BEÁLLÍTÁSOK --> KAPCSOLAT MENÜPONTRA, ÉS TÁVOLÍTSA EL A PIPÁT A „80-AS PORT HASZNÁLATA TARTALÉK PORTKÉNT” LEHETŐSÉGBŐL, MAJD INDÍTSA ÚJRA A SKYPE PROGRAMOT. EZUTÁN MŰKÖDNIE KELLENE.\rTŰZFALA VAN, AMELY BLOKKOLJA AZ APACHE PORTJÁT. NEM MINDEN TŰZFAL KOMPATIBILIS AZ APACHE KISZOLGÁLÓVAL, ÉS NÉHA A TŰZFAL KIKAPCSOLÁSA NEM ELEGENDŐ, EL KELL TÁVOLÍTANIA AZT. EZ A HIBAÜZENET JELZI A TŰZFALAT:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rHA AZ APACHE EL TUD UGYAN INDULNI, DE A BÖNGÉSZŐ NEM TUD CSATLAKOZNI HOZZÁ, AKKOR EZ A KÖVETKEZŐK EGYIKE MIATT LEHET:\rNÉHÁNY VÍRUSIRTÓ OKOZHATJA EZT UGYANOLYAN MÓDON, AHOGY A TŰZFALAK ZAVARHATJÁK.\rXP PROFESSIONAL RENDSZERE VAN 1. JAVÍTÓCSOMAG NÉLKÜL. LEGALÁBB SP1 SZÜKSÉGES A XAMPP PROGRAMHOZ.\rTIPP:\rHA PROBLÉMÁI VANNAK A PORTOK HASZNÁLATÁVAL, MEGPRÓBÁLHATJA A „XAMPP-PORTCHECK.EXE” ESZKÖZT. TALÁN SEGÍTHET.\rMIÉRT VAN MAJDNEM 99%-OS CPU TERHELÉS AZ APACHE HASZNÁLATAKOR?\rKÉT FORGATÓKÖNYV JÁTSZHAT ITT SZEREPET. VAGY A CPU VAN MAXIMÁLISAN KIHASZNÁLVA, VAGY A BÖNGÉSZŐ KÉPES UGYAN CSATLAKOZNI A KISZOLGÁLÓHOZ, DE NEM LÁT SEMMIT (A RENDSZER SIKERTELENÜL PRÓBÁLJA BETÖLTENI AZ OLDALT). MINDKÉT ESETBEN A KÖVETKEZŐ ÜZENETET LÁTHATJA AZ APACHE NAPLÓFÁJLJÁBAN:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rAZ MPM VISSZAÁLL EGY BIZTONSÁGOSABB MEGVALÓSÍTÁSRA, DE NÉHÁNY KLIENSKÉRÉS NEM LETT HELYESEN FELDOLGOZVA. EZEN HIBA ELKERÜLÉSÉNEK ÉRDEKÉBEN HASZNÁLJA AZ „ACCEPTFILTER” BEÁLLÍTÁST A „NONE” ELFOGADÁSSZŰRŐVEL A „\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF” FÁJLBAN.\rMIÉRT NEM JELENNEK MEG A KÉPEK ÉS A STÍLUSLAPOK?\rNÉHA PROBLÉMÁK VANNAK A KÉPEK ÉS A STÍLUSLAPOK MEGJELENÍTÉSÉVEL. KÜLÖNÖSEN AKKOR, HA EZEK A FÁJLOK EGY HÁLÓZATI ESZKÖZÖN TALÁLHATÓK. EBBEN AZ ESETBEN ENGEDÉLYEZHET (VAGY HOZZÁADHAT) EGYET, HA A KÖVETKEZŐ SOROK A „\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF” FÁJLBAN VANNAK:\rENABLESENDFILE OFF\rENABLEMMAP OFF\rEZT A HIBÁT OKOZHATJÁK SÁVSZÉLESSÉG-SZABÁLYZÓ PROGRAMOK IS, MINT PÉLDÁUL A NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rHOGYAN ÁLLÍTHATOK BE RENDSZERGAZDA JELSZÓT A MYSQL-BEN?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rHASZNÁLHATOM A SAJÁT MYSQL KISZOLGÁLÓMAT?\rIGEN. EGYSZERŰEN NE INDÍTSA EL A MYSQL KISZOLGÁLÓT A XAMPP CSOMAGBÓL. VEGYE FIGYELEMBE, HOGY NEM LEHET KÉT KISZOLGÁLÓT ELINDÍTANI UGYANAZON A PORTON. HA A „ROOT” FELHASZNÁLÓNAK ÁLLÍTOTT BE JELSZÓT, NE FELEJTSE EL SZERKESZTENI A „\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP” FÁJLT.\rHOGYAN TUDOM KORLÁTOZNI A PHPMYADMIN KÍVÜLRŐL VALÓ HOZZÁFÉRÉSÉT?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rMIELŐTT HOZZÁFÉRNE A MYSQL KISZOLGÁLÓHOZ, A PHPMYADMIN KÉRNI FOG ÖNTŐL EGY FELHASZNÁLÓNEVET ÉS EGY JELSZÓT. NE FELEJTSEN EL ELŐSZÖR BEÁLLÍTANI JELSZÓT A „ROOT” FELHASZNÁLÓNAK.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rHOL VAN AZ IMAP TÁMOGATÁS A PHP-HOZ?\rALAPÉRTELMEZETTEN AZ IMAP TÁMOGATÁS NINCS AKTIVÁLVA A PHP-HOZ AZ XAMPP PROGRAMBAN NÉHÁNY MEGMAGYARÁZHATATLAN ELŐKÉSZÍTÉSI HIBA MIATT EGY-KÉT OTTHONI VERZIÓBAN, MINT PÉLDÁUL A WINDOWS 98-BAN. HA NT RENDSZEREKKEL DOLGOZIK, MEGNYITHATJA A „\\\\XAMPP\\\\PHP\\\\PHP.INI” FÁJLT A PHP-KITERJESZTÉS AKTIVÁLÁSÁHOZ A KEZDŐ PONTOSVESSZŐ ELTÁVOLÍTÁSÁVAL A „;EXTENSION=PHP_IMAP.DLL” SOR ELEJÉRŐL. ILYENNEK KELL LENNIE:\rEXTENSION=PHP_IMAP.DLL\rMOST INDÍTSA ÚJRA AZ APACHE KISZOLGÁLÓT ÉS AZ IMAP MŰKÖDNI FOG. UGYANEZEKET A LÉPÉSEKET HASZNÁLHATJA MINDEN OLYAN KITERJESZTÉSNÉL, AMELY NINCS ENGEDÉLYEZVE AZ ALAPÉRTELMEZETT BEÁLLÍTÁSBAN.\rMIÉRT NEM MŰKÖDIK NÉHÁNY NYÍLT FORRÁSÚ PHP ALKALMAZÁS A XAMPP PROGRAMMAL WINDOWSON?\rSZÁMOS LINUXHOZ ÍRT PHP ALKALMAZÁST VAGY KITERJESZTÉST MÉG NEM ÍRTAK ÁT WINDOWSRA. \rTÖRÖLHETEM AZ „INSTALL” KÖNYVTÁRAT A TELEPÍTÉS UTÁN?\rJOBBAN TENNÉ, HA NEM. AZ ITT LÉVŐ PARANCSFÁJLOK MÉG SZÜKSÉGESEK A XAMPP MINDEN TOVÁBBI CSOMAGJÁHOZ (KIEGÉSZÍTŐKHÖZ) ÉS FRISSÍTÉSÉHEZ.\rHOGYAN AKTIVÁLHATOM AZ EACCELERATOR KITERJESZTÉST?\rMINT A TÖBBI (ZEND) KITERJESZTÉST, A „PHP.INI” FÁJLBAN AKTIVÁLHATJA. EBBEN A FÁJLBAN ENGEDÉLYEZZE A „;ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"” SORT. ILYENNEK KELL LENNIE:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rHOGYAN TUDOM JAVÍTANI A CSATLAKOZÁSI HIBÁT AZ MS SQL KISZOLGÁLÓMHOZ?\rHA AZ MSSQL KITERJESZTÉS BE LETT TÖLTVE A PHP.INI FÁJLBAN, NÉHA PROBLÉMA JELENTKEZIK, AMIKOR KIZÁRÓLAG TCP/IP VAN HASZNÁLVA. KIJAVÍTHATJA EZT A HIBÁT A MICROSOFT ÁLTAL KÖZZÉTETT ÚJABB „NTWDBLIB.DLL” FÁJLLAL. CSERÉLJE LE A RÉGEBBI FÁJLT A „\\\\XAMPP\\\\APACHE\\\\BIN” ÉS A „\\\\XAMPP\\\\PHP” KÖNYVTÁRBAN AZ ÚJRA. A LICENC MIATT NEM CSOMAGOLHATJUK A XAMPP-HOZ ENNEK A FÁJLNAK AZ ÚJABB VERZIÓJÁT.\rHOGYAN DOLGOZHATOK A PHP MCRYPT KITERJESZTÉSSEL?\rEHHEZ NYITOTTUNK EGY TÉMÁT A FÓRUMBAN PÉLDÁKKAL ÉS LEHETSÉGES MEGOLDÁSOKKAL: \rMCRYPT TÉMA\rMŰKÖDIK A MICROSOFT ACTIVE SERVER PAGES (ASP) XAMPP-ON?\rNEM. ÉS AZ APACHE::ASP A PERL KIEGÉSZÍTŐVEL NEM UGYANAZ. AZ APACHE::ASP CSAK ISMERI A PERL-PARANCSFÁJLOKAT, DE AZ INTERNET INFORMATION SERVER (IIS) ÁLTAL TARTALMAZOTT ASP SZINTÉN ISMERI A NORMÁL VBSCRIPTET. AZONBAN AZ ASP .NET-HEZ ELÉRHETŐ HARMADIK FÉL ÁLTAL KÉSZÍTETT APACHE-MODUL.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT © APACHE FRIENDS, 2022.\rBLOG\rADATVÉDELMI IRÁNYELV\rCDN ÁLTAL NYÚJTOTT\r\n'),(51,'ae5ce320c0cae4deec2bc4d579db92fa','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rGYAKORI KÉRDÉSEK\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT © APACHE FRIENDS, 2022.\rBLOG\rADATVÉDELMI IRÁNYELV\rCDN ÁLTAL NYÚJTOTT\r\n'),(52,'85b93789cecfb1f8cc705da0267aa665','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rGYAKORI KÉRDÉSEK\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT © APACHE FRIENDS, 2022.\rBLOG\rADATVÉDELMI IRÁNYELV\rCDN ÁLTAL NYÚJTOTT\r\n'),(53,'582d82a64bbf12bc62bf85de39ce3ce8','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rGYAKORI KÉRDÉSEK\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT © APACHE FRIENDS, 2022.\rBLOG\rADATVÉDELMI IRÁNYELV\rCDN ÁLTAL NYÚJTOTT\r\n'),(54,'be2bc265a2c7d94cf92c3dbeadd46637','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rGYAKORI KÉRDÉSEK\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rGYAKORI KÉRDÉSEK\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nKÖZÖSSÉG\rA XAMPP MÁR TÖBB MINT 10 ÉVES  EGY HATALMAS KÖZÖSSÉG ÁLL MÖGÖTTE. RÉSZT VEHET BENNE, HA CSATLAKOZIK ÉS IGÉNYBE VESZI A \rFÓRUMOK\rSZOLGÁLTATÁSÁT, LÁJKOL MINKET A \rFACEBOOK\rKÖZÖSSÉGI OLDALÁN VAGY KÖVETI A KÖZZÉTÉTELEINKET A \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT © APACHE FRIENDS, 2022.\rBLOG\rADATVÉDELMI IRÁNYELV\rCDN ÁLTAL NYÚJTOTT\r\n'),(55,'688f22a9b97b2843c85803bb70963a4b','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rFAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rFAQS\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nCOMMUNITY\rXAMPP HAS BEEN AROUND FOR MORE THAN 10 YEARS  THERE IS A HUGE COMMUNITY BEHIND IT. YOU CAN GET INVOLVED BY JOINING OUR \rFORUMS\r, LIKING US ON \rFACEBOOK\r, OR FOLLOWING OUR EXPLOITS ON \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPRIVACY POLICY\rCDN PROVIDED BY\r\n'),(56,'9e2d4d1fa1afc1005a6a9bb629af04a7','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rDOMANDE FREQUENTI\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rDOMANDE FREQUENTI\rCOME FACCIO AD INSTALLARE XAMPP?\rXAMPP PER WINDOWS ESISTE IN TRE DIVERSI MODELLI:\rINSTALLATORE\rPROBABILMENTE IL MODO PIÙ SEMPLICE PER INSTALLARE XAMPP.\rZIP:\rIL PANNELLO DI CONTROLLO XAMPP PER AVVIARE ED INTERROMPERE APACHE, MYSQL, FILEZILLA & MERCURY O PER INSTALLARE QUESTI SERVER COME SERVIZI.\r7ZIP:\rPER I PURISTI CON BASSA LARGHEZZA DI BANDA XAMPP E DISPONIBILE COME ARCHIVIO 7ZIP.\rNOTA: SE AVETE ESTRATTO I FILE, POSSONO ESSERE PRESENTI DEGLI AVVISI DI VIRUS FALSI-POSITIVI.\rUTILIZZARE IL PROGRAMMA DI INSTALLAZIONE:\rIL PANNELLO DI CONTROLLO DI XAMPP PER AVVIARE ED INTERROMPERE APACHE, MYSQL, FILEZILLA & MERCURY OD INSTALLARE QUESTI SERVER COME SERVIZI.\rINSTALLAZIONE DA FILE ZIP\rDECOMPRIMERE GLI ARCHIVI ZIP NELLA CARTELLA DI VOSTRA SCELTA. XAMPP VERRÀ ESTRATTO NELLA SOTTODIRECTORY \"C:\\\\XAMPP\" SOTTO LA DIRECTORY DI DESTINAZIONE SELEZIONATA. ORA AVVIARE IL FILE \"SETUP_XAMPP.BAT\", PER REGOLARE LA CONFIGURAZIONE XAMPP AL VOSTRO SISTEMA.\rSE SI SCEGLIE UNA RADICE DIRECTORY \'C \\\\ \' COME OBBIETIVO, NON DEVI AVVIARE \'SETUP_XAMPP.BAT\'.\rCOME CON LA VERSIONE INSTALLER, È ORA POSSIBILE UTILIZZARE IL \'PANNELLO DI CONTROLLO DI XAMPP\' PER ULTERIORI COMPITI.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rCOME POSSO AVVIARE XAMPP SENZA INSTALLAZIONE?\rSE SI ESTRAE XAMPP IN UNA CARTELLA DI LIVELLO SUPERIORE COME \'C \\\\ \' O \'D \\\\ \', È POSSIBILE AVVIARE LA MAGGIOR PARTE DEI SERVER COME APACHE O MYSQL DIRETTAMENTE SENZA L\'ESECUZIONE DEL FILE \'SETUP_XAMPP.BAT\'.\rNON USANDO LO SCRIPT DI INSTALLAZIONE, OPPURE SELEZIONANDO I PERCORSI RELATIVI NELLO SCRIPT DI SETUP, È PREFERIBILE SE SI STA INSTALLANDO XAMPP SU UN DRIVE USB. PERCHÉ SU OGNI PC UNA TALE UNITÀ POSSA AVERE UN\'ALTRA LETTERA DI UNITÀ. È POSSIBILE PASSARE DA ASSOLUTO A PERCORSI RELATIVI IN ​​OGNI MOMENTO CON LO SCRIPT DI INSTALLAZIONE.\rUTILIZZANDO IL PROGRAMMA DI INSTALLAZIONE DALLA NOSTRA PAGINA DI DOWNLOAD È IL MODO PIÙ SEMPLICE PER INSTALLARE XAMPP.DOPO AVER COMPLETATO L\'INSTALLAZIONE, TROVERETE XAMPP SOTTO START | PROGRAMMI | XAMPP. È POSSIBILE UTILIZZARE IL PANNELLO DI CONTROLLO DI XAMPP PER AVVIARE / ARRESTARE TUTTI I SERVER E ANCHE INSTALLARE / DISINSTALLARE SERVIZI.\rIL PANNELLO DI CONTROLLO DI XAMPP PER AVVIARE ED INTERROMPERE APACHE, MYSQL, FILEZILLA & MERCURY OD INSTALLARE QUESTI SERVER COME SERVIZI.\rCOME FACCIO AD AVVIARE O STOPPARE XAMPP?\rIL CENTRO DI CONTROLLO UNIVERSALE È IL \'PANNELLO DI XAMPP CONTROL\' (GRAZIE WWW.NAT32.COM). SI È INIZIATO CON:\r\\XAMPP\\XAMPP-CONTROL.EXE\rÈ INOLTRE POSSIBILE UTILIZZARE ALCUNI BATCHFILES PER AVVIARE/ARRESTARE I SERVER:\rAVVIO APACHE & MYSQL:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL STOP:\n\\XAMPP\\XAMPP_STOP.EXE\rAVVIA APACHE:\n\\XAMPP\\APACHE_START.BAT\rFERMA APACHE:\n\\XAMPP\\APACHE_STOP.BAT\rAVVIA MYSQL:\n\\XAMPP\\MYSQL_START.BAT\rFERMA MYSQL:\n\\XAMPP\\MYSQL_STOP.BAT\rAVVIA MERCURY MAILSERVE:\n\\XAMPP\\MERCURY_START.BAT\rFERMA MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_STOP.BAT\rAVVIA FILEZILLA SERVER:\n\\XAMPP\\FILEZILLA_START.BAT\rFERMA FILEZILLA SERVER:\n\\XAMPP\\FILEZILLA_STOP.BAT\rCOME POSSO VERIFICARE CHE TUTTO FUNZIONI?\rDIGITARE IL SEGUENTE URL SUL VOSTRO BROWSER WEB PREFERITO:\rHTTP://LOCALHOST/\rOPPURE \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rCOME POSSO INSTALLARE UN SERVER COME SERVIZIO?\rPER OGNI SERVER XAMPP È POSSIBILE INSTALLARE COME SERVIZIO DI WINDOWS. È INOLTRE POSSIBILE INSTALLARE DAL PANNELLO DI CONTROLLO DI XAMPP. IN QUESTO CASO È NECESSARIO ESEGUIRE GLI SCRIPT O IL PANNELLO DI CONTROLLO CON PRIVILEGI DI AMMINISTRATORE.\rINSTALLARE IL SERVIZIO APACHE:\\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rDISINSTALLAZIONE DEL SERVIZIO APACHE:\\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rINSTALLAZIONE DEL SERVIZIO MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rDISINSTALLAZIONE SEL SERVIZIO MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA (SERVER FTP) INSTALLAZIONE/DISINSTALLAZIONE DEL SERVIZIO: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY NESSUNA INSTALLAZIONE DISPONIBILE PER IL SERVIZIO\rIL PRODOTTO XAMPP E\' PRONTO?\rXAMPP NON È INTESO PER LA PRODUZIONE MA SOLO PER AMBIENTI DI SVILUPPO. IL MODO IN CUI XAMPP È CONFIGURATO È QUELLO DI ESSERE PIÙ APERTO POSSIBILE PER PERMETTERE ALLO SVILUPPATORE LUI/LEI DI PERSONALIZZARLO. PER AMBIENTI DI SVILUPPO QUESTO È OTTIMO MA IN UN AMBIENTE DI PRODUZIONE POTREBBE ESSERE PERICOLOSO.\rECCO UNA LISTA DELLE IMPOSTAZIONI DI SICUREZZA MANCANTI IN XAMPP:\rL\'AMMINISTRATORE DI MYSQL (ROOT) NON HA PASSWORD.\rIL DEMONE MYSQL È ACCESSIBILE VIA RETE.\rPROFTPD USA COME PASSWORD \"LAMPP\" E COME USER \"DAEMON\".\rL\'IMPOSTAZIONE PREDEFINITA, GLI UTENTI DI MERCURY E FILEZILLA SONO NOTI.\rTUTTI I PUNTI POSSONO ESSERE UN ENORME RISCHIO PER LA SICUREZZA. SOPRATTUTTO SE XAMPP È ACCESSIBILE TRAMITE LA RETE E LE PERSONE AL DI FUORI DELLA LAN. PUÒ INOLTRE ESSERE UTILE PER UTILIZZARE UN FIREWALL O UN ROUTER NAT (NETWORK ADDRESS TRANSLATION). IN CASO DI UN ROUTER O UN FIREWALL, IL PC È NORMALMENTE NON ACCESSIBILI TRAMITE LA RETE. A VOI IL COMPITO DI RISOLVERE QUESTI PROBLEMI. COME UN PICCOLO AIUTO C\'È IL \"XAMPP SECURITY CONSOLE\".\rMETTERE IN SICUREZZA XAMPP PRIMA DI PUBBLICARE QUALCOSA ONLINE. UN FIREWALL O UN ROUTER ESTERNO SONO SUFFICIENTI SOLO PER BASSI LIVELLI DI SICUREZZA. PER PIÙ SICUREZZA, È POSSIBILE ESEGUIRE IL \"XAMPP SECURITY CONSOLE\' E ASSEGNARE LE PASSWORD.\rSE VOLETE AVERE IL VOSTRO XAMPP ACCESSIBILI DA INTERNET, SI DOVREBBE ANDARE AL SEGUENTE URI CHE PUÒ RISOLVERE ALCUNI PROBLEMI\rHTTP://LOCALHOST/SECURITY/\rCON LA CONSOLE DI SICUREZZA È POSSIBILE IMPOSTARE UNA PASSWORD PER L\'UTENTE \'ROOT\' MYSQL E PHPMYADMIN. È INOLTRE POSSIBILE ATTIVARE L\'AUTENTICAZIONE PER I DEMOPAGES XAMPP.\rQUESTO STRUMENTO WEB-BASED NON RISOLVE TUTTI I PROBLEMI DI SICUREZZA AGGIUNTIVI! SOPRATTUTTO IL SERVER FILEZILLA FTP E IL SERVER DI POSTA MERCURY È NECESSARIO PROTEGGERTI.\rCOME FACCIO A DISINSTALLARE XAMPP?\rSE AVETE INSTALLATO XAMPP UTILIZZANDO LA VERSIONE INSTALLER, SI PREGA DI UTILIZZARE IL PROGRAMMA DI DISINSTALLAZIONE. IL PROGRAMMA DI DISINSTALLAZIONE CANCELLA TUTTE LE VOCI DI XAMPP DAL REGISTRO DI SISTEMA E DISINSTALLERA\' ALCUNI SERVIZI INSTALLATI CON XAMPP. CONSIGLIAMO VIVAMENTE DI UTILIZZARE IL PROGRAMMA DI DISINSTALLAZIONE PER RIMUOVERE LE INSTALLAZIONI DI XAMPP . EFFETTUATE UN BACKUP DEL INSTALLER VERSION.PER SALVARE TUTTI I DATI CHE SI DESIDERA CONSERVARE PRIMA DI DISINSTALLARE XAMPP.\rSE AVETE INSTALLATO XAMPP UTILIZZANDO LE VERSIONI ZIP E 7ZIP, ARRESTARE TUTTI I SERVER XAMPP E CHIUDERE TUTTI I PANNELLI. SE AVETE INSTALLATO TUTTI I SERVIZI, DISINSTALLARE E FARLI CHIUDERE.ORA BASTA ELIMINARE L\'INTERA CARTELLA DOVE È INSTALLATO XAMPP.NON CI SONO VOCI DI REGISTRO E NON VARIABILI D\'AMBIENTE DA RIPULIRE.\rQUAL È LA VERSIONE \'LITE\' DI XAMPP?\rXAMPP LITE (SIGNIFICA \'LUCE\', COME IN \'LEGGERO\') È UN INSIEME MINORE DI COMPONENTI XAMPP, CHE È RACCOMANDATO PER UN LAVORO VELOCE USANDO SOLO PHP E MYSQL. ALCUNI SERVER O STRUMENTI COME MERCURY MAIL E FILEZILLA FTP MANCANO NELLA VERSIONE LITE\rDOVE DEVO INSERIRE I MIEI CONTENUTI WEB?\rLA DIRECTORY PRINCIPALE PER TUTTI I DOCUMENTI WWW È \\\\XAMPP\\\\HTDOCS. SE INSERISCI UN FILE \"TEST.HTML\" IN QUESTA DIRECTORY, È POSSIBILE CONSULTARLO CON L\'URI \"HTTP://LOCALHOST/TEST.HTML\".\rE \"TEST.PHP\"? BASTA USARE \"HTTP://LOCALHOST/TEST.PHP\". UN SEMPLICE SCRIPT DI TEST PUÒ ESSERE:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rUNA NUOVA SOTTODIRECTORY PER IL WEB? BASTA FARE UNA NUOVA DIRECTORY (P.E. \"NUOVA\") ALL\'INTERNO DELLA DIRECTORY \"\\\\XAMPP\\\\HTDOCS\" (MEGLIO SENZA SPAZI VUOTI E SOLO ASCII), CREARE UN FILE DI PROVA IN QUESTA DIRECTORY E ACCEDERVI CON \"HTTP://LOCALHOST/NUOVA/TEST.PHP\".\rULTERIORI SPECIFICHE\rHTML:\rESEGUIBILE: \\XAMPP\\HTDOCS\rAMMESSI FINALI: .HTML .HTM\r=> PACCHETTO BASICO\rSSI:\rESEGUIBILE: \\XAMPP\\HTDOCS\rAMMESSI FINALI: .SHTML\r=> PACCHETTO BASICO\rCGI:\rESEGUIBILE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rAMMESSI FINALI: .CGI\r=> PACCHETTO BASICO\rPHP:\rESEGUIBILE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rAMMESSI FINALI: .PHP\r=> PACCHETTO BASICO\rPERL:\rESEGUIBILE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rAMMESSI FINALI: .PL\r=> PACCHETTO BASICO\rAPACHE::ASP PERL:\rESEGUIBILE: \\XAMPP\\HTDOCS\rAMMESSI FINALI: .ASP\r=> PACCHETTO BASICO\rJSP JAVA:\rESEGUIBILE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rAMMESSI FINALI: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rESEGUIBILE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rAMMESSI FINALI: .HTML (U.A)\r=> TOMCAT ADD-ON\rPOSSO SPOSTARE L\'INSTALLAZIONE DI XAMPP?\rSÌ. DOPO LO SPOSTAMENTO DELLA DIRECTORY XAMPP, È NECESSARIO ESEGUIRE \'SETUP_XAMPP.BAT\'. I PERCORSI DEI FILE DI CONFIGURAZIONE VERRANNO REGOLATI CON QUESTO PASSO.\rSE AVETE INSTALLATO UN SERVER COME SERVIZIO DI WINDOWS, È NECESSARIO PRIMA RIMUOVERE IL SERVIZIO WINDOWS, E DOPO LO SPOSTAMENTO È POSSIBILE INSTALLARE NUOVAMENTE IL SERVIZIO.\rATTENZIONE I FILE DI CONFIGURAZIONE DEI TUOI SCRIPT, COME LE APPLICAZIONI PHP, NON SONO ADEGUATI. MA È POSSIBILE SCRIVERE UN \'PLUG-IN\' PER L\'INSTALLATORE. CON TALE PLUG-IN, L\'INSTALLATORE PUÒ REGOLARE TALI FILE.\rQUALI SONO LE \'PAGINE AVVIO AUTOMATICO »PER LE DIRECTORY WWW?\rIL NOME DEL FILE STANDARD PER LA FUNZIONE DI APACHE \'DIRECTORYINDEX\' È \'INDEX.HTML\' O \'INDEX.PHP\'. OGNI VOLTA CHE SI STA SOLO NAVIGANDO IN UNA CARTELLA (AD ESEMPIO \'HTTP / / LOCALHOST / XAMPP /\'), E APACHE PUÒ TROVARE UN FILE, APACHE STA VISUALIZZANDO QUESTO FILE INVECE DI UN ELENCO DI DIRECTORY.\rCOME POSSO CAMBIARE LA CONFIGURAZIONE?\rQUASI TUTTE LE IMPOSTAZIONI DI XAMPP SI POSSONO MODIFICARE DAL FILE DI CONFIGURAZIONE. BASTA APRIRE IL FILE IN TEXTEDIT E MODIFICARE L\'IMPOSTAZIONE CHE SI DESIDERA. SOLO FILEZILLA E MERCURIO DEVONO ESSERE CONFIGURATI CON LO STRUMENTO DI CONFIGURAZIONE DELL\'APPLICAZIONE.\rPERCHÉ NON È POSSIBILE CHE XAMPP FUNZIONI SU WINDOWS XP SP2?\rMICROSOFT CON SERVICE PACK 2 (SP2), OFFRE UN FIREWALL MIGLIORE CHE SI AVVIA AUTOMATICAMENTE. QUESTO FIREWALL BLOCCA LE PORTE NECESSARIE 80 (HTTP) E 443 (HTTPS) E APACHE NON PUÒ AVVIARSI.\rLA SOLUZIONE PIU VELOCE:\rDISATTIVARE IL FIREWALL DI MICROSOFT DALLA BARRA DEGLI STRUMENTI E TENTARE DI AVVIARE XAMPP UN ALTRA VOLTA. LA SOLUZIONE MIGLIORE È QUELLA DI DEFINIRE UN\'ECCEZIONE ALL\'INTERNO DEL CENTRO DI SICUREZZA.\rLE SEGUENTI PORTE SONO UTILIZZATE PER LE FUNZIONALITÀ DI BASE:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rPERCHÉ XAMPP NON FUNZIONA SU VISTA?\rCONTROLLO DELL\'ACCOUNT UTENTE (UAC)\rNELLA DIRECTORY \"C: \\\\PROGRAM FILES\" NON AVETE I PRIVILEGI DI SCRITTURA, ANCHE COME ADMIN. O HAI SOLO PRIVILEGI LIMITATI (AD ESEMPIO PER I \' .\\\\XAMPP\\\\HTDOCS\" ). IN QUESTO CASO NON È POSSIBILE MODIFICARE UN FILE.\rSOLUZIONE:\rELEVARE I TUOI PRIVILEGI IN EXPLORER (CLIC TASTO DESTRO/PROTEZIONE) E DISATTIVARE IL CONTROLLO DELL\'ACCOUNT UTENTE (UAC).\rÈ STATO INSTALLATO APACHE/MYSQL IN \"C:\\\\XAMPP\" COME SERVIZIO DI WINDOWS. MA NON È POSSIBILE AVVIARE/ARRESTARE I SERVIZI CON IL \"PANNELLO DI CONTROLLO DI XAMPP\" O NON È POSSIBILE DISINSTALLARLI.\rSOLUZIONE:\rUTILIZZATE LA CONSOLE DI GESTIONE DEL SERVIZIO DA WINDOWS O DISABILITARE UAC.\rDISABILITARE IL CONTROLLO ACCOUNT UTENTE (UAC)\rPER DISABILITARE L\'UAC, UTILIZZARE IL PROGRAMMA \'MSCONFIG\'. IN \'MSCONFIG\' VAI A \'STRUMENTI\', SELEZIONARE \'CONTROLLO DELL\'ACCOUNT UTENTE DISABILITA\' E VERIFICARE LA SELEZIONE. ORA È NECESSARIO RIAVVIARE WINDOWS. ALLO STESSO TEMPO, È POSSIBILE ATTIVARE NUOVAMENTE L\'UAC.\rCOME FACCIO A CONTROLLARE IL CHECKSUM MD5?\rPER CONFRONTARE I FILE, VENGONO UTILIZZATI SPESSO I CHECKSUM. UNO STANDARD PER CREARE QUESTA CHECKSUM MD5 (MESSAGE DIGEST ALGORITHM 5).\rCON QUESTO MD5 CHECKSUM È POSSIBILE VERIFICARE SE IL DOWNLOAD DEL PACCHETTO XAMPP È CORRETTA O MENO. NATURALMENTE È NECESSARIO UN PROGRAMMA CHE PUÒ CREARE QUESTI CHECKSUM. PER WINDOWS È POSSIBILE UTILIZZARE UNO STRUMENTO DI MICROSOFT:\rLA DISPONIBILITÀ E LA DESCRIZIONE DEL FILE INTEGRITÀ CHECKSUM VERIFICA UTILITY \rÈ ANCHE POSSIBILE UTILIZZARE QUALSIASI ALTRO PROGRAMMA CHE PUÒ CREARE MD5 CHECKSUM, COME LA GNU MD5SUM.\rCOME AVETE INSTALLATO UN PROGRAMMA DEL GENERE (PER ESEMPIO FCIV.EXE), SI PUÒ FARE SEGUENDO I PASSAGGI:\rSCARICA XAMPP (F.E. XAMPP-WIN32-1.8.2-0.EXE)\rCREARE IL CHECKSUM CON:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rE ORA SI PUÒ PARAGONARE QUESTO CHECKSUM CON QUELLO LO PUOI TROVARE SU XAMPP PER HOMEPAGE DI WINDOWS.\rSE ENTRAMBI I CHECKSUM SONO UGUALI, TUTTO È OK. IN CASO CONTRARIO, IL DOWNLOAD È DANNEGIATO O IL FILE È STATO MODIFICATO.\rPERCHÉ I CAMBIAMENTI DEL MIO PHP.INI NON HANNO AVUTO EFFETTO?\rSE UNA VARIAZIONE DEL \"PHP.INI\" NON HA ALCUN EFFETTO, È POSSIBILE CHE PHP NE STIA UTILIZZANDO UNO DIFFERENTE. È POSSIBILE VERIFICARLO CON PHPINFO(). VAI ALLA URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP E CERCARE\"LOADED CONFIGURATION FILE\". QUESTO VALORE INDICA IL \"PHP.INI\" REALMENTE UTILIZZATO DA PHP.\rNOTE:\rDOPO AVER MODIFICATO LA \'PHP.INI\' SI DEVE RIAVVIARE APACHE IN MODO CHE APACHE/PHP POSSA LEGGERE LE NUOVE IMPOSTAZIONI.\rAIUTO! C\'È UN VIRUS IN XAMPP!\rALCUNI PROGRAMMI ANTIVIRUS SCAMBIANO XAMPP PER UN VIRUS, IN GENERE SEGNALANDO IL FILE XAMPP-MANAGER.EXE QUESTO È UN SIGNIFICATIVO FALSO POSITIVO CHE L\'ANTIVIRUS ERRONEAMENTE IDENTIFICATO COME UN VIRUS, QUANDO NON LO È. PRIMA DI RILASCIARE OGNI NUOVA VERSIONE DI XAMPP TESTIAMO ATTRAVERSO SOFTWARE ANTIVIRUS. AL MOMENTO STIAMO UTILIZZANDO \rKAPERSKY ONLINE VIRUS SCANNER\r. PUOI UTILIZZARE ANCHE LO STRUMENTO IN LINEA \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rCOME FACCIO A CONFIGURARE IL MIO ANTIVIRUS?\rABBIAMO INCLUSO TUTTE LE DIPENDENZE EI SERVER NECESSARI PER L\'ESECUZIONE DI APPLICAZIONI WEB IN BUNDLE, QUINDI TROVEREMO CHE XAMPP INSTALLA UN GRAN NUMERO DI FILE. SE SI INSTALLA UN\'APPLICAZIONE XAMPP SU UNA MACCHINA WINDOWS CON UN APP ANTIVIRUS ABILITATO, PUO \'RALLENTARE L\'INSTALLAZIONE IN MODO SIGNIFICATIVO, E C\'È ANCHE LA POSSIBILITÀ CHE UNO DEI SERVER (WEB SERVER, DATABASE SERVER) POSSONO ESSERE BLOCCATI DAL SOFTWARE ANTIVIRUS .SE SI DISPONE DI UNO STRUMENTO ANTIVIRUS ATTIVATO, CONTROLLARE LE SEGUENTI IMPOSTAZIONI PER L\'ESECUZIONE XAMPP SENZA PROBLEMI DI PRESTAZIONI:\rAGGIUNGERE ECCEZIONI NEL FIREWALL PER APACHE, MYSQL O QUALSIASI ALTRO SERVER.\rESEGUIRE LA SCANSIONE DEI FILE DURANTE L\'ESECUZIONE SE È STATA ATTIVATA LA SCANSIONE ANTIVIRUS DI TUTTI I FILE, E I FILE ESEGUIBILI PER I SERVER SI POTRANNO RALLENTARE.\rESEGUIRE LA SCANSIONE DEL TRAFFICO PER URL DIVERSI SE SI STA SVILUPPANDO CON XAMPP SULLA PROPRIA MACCHINA, È POSSIBILE ESCLUDERE \'LOCALHOST\' TRAFFICO NELLE IMPOSTAZIONI ANTIVIRUS.\rPERCHÉ IL SERVER APACHE NON SI AVVIA SUL MIO SISTEMA?\rIL PROBLEMA POTREBBE ESSERE UNO DEI SEGUENTI MOTIVI:\rÈ STATO AVVIATO PIÙ DI UN SERVER HTTP (IIS, SAMBAR, ZEUS E COSÌ VIA). SOLO UN SERVER PUÒ UTILIZZARE LA PORTA 80. QUESTO MESSAGGIO DI ERRORE DI INDICA IL PROBLEMA:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rSE HAI ALTRI SOFTWARE, COME INTERNET TELEPHONE \'SKYPE\', CHE BLOCCA ANCHE LA PORTA 80. SE IL PROBLEMA È \'SKYPE\', SI PUÒ ANDARE IN SKYPE PER AZIONI -> OPZIONI -> CONNESSIONE -> TOGLIERE IL SEGNO DI SPUNTA ALLA PORTA 80 PER L\'USO DI UNA PORTA ALTERNATIVA\' E RIAVVIARE SKYPE. ORA DOVREBBE FUNZIONARE.\rSE SI DISPONE DI UN FIREWALL CHE BLOCCA LA PORTA DI APACHE. NON TUTTI I FIREWALL SONO COMPATIBILI CON APACHE, E, TALVOLTA, DISATTIVARE IL FIREWALL NON È SUFFICIENTE ED È NECESSARIO DISINSTALLARE ESSO. QUESTO MESSAGGIO DI ERRORE INDICA UN FIREWALL:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rANCHE SE APACHE E\' AVVIATO , MA IL VOSTRO BROWSER NON RIESCE A CONNETTERSI AD ESSO POTREBBE ESSERE DOVUTO AD UNO DEI SEGUENTI CASI:\rALCUNI ANTIVIRUS POSSONO CAUSARE QUEST\' ERRORE NELLO STESSO MODO DEL INTERFERENZA DEI FIREWALL.\rHAI XP PROFESSIONAL SENZA SERVICE PACK 1. È NECESSARIO AVERE ALMENO SP1 PER XAMPP.\rSUGGERIMENTI:\rSE HAI PROBLEMI CON LE PORTE USATE, PUOI PROVARE LO STRUMENTO \"XAMPP-PORTCHECK.EXE\". FORSE TI PUÒ ESSERE D\'AIUTO.\rPERCHÉ IL CARICO DELLA CPU PER APACHE E QUASI AL 99%?\rC\'È UNO DEI DUE SCENARI IN GIOCO. SIA LA CPU NON PIÙ SUFFICIENTI, O BROWSER È POSSIBILE COLLEGARSI AL SERVER, MA NON VEDO NULLA (IL SISTEMA TENTA UNSUCESSFULLY PER CARICARE LA PAGINA).IN ENTRAMBI I CASI È POSSIBILE TROVARE IL MESSAGGIO SEGUENTE NEL FILE LOG DI APACHE:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rMPM LAVORA PER SALVAGUARDIA SU UN\'IMPLEMENTAZIONE PIÙ SICURA, MA ALCUNE RICHIESTE CLIENT NON SONO STATE ELABORATE CORRETTAMENTE. PER EVITARE QUESTO ERRORE, USA \"ACCEPTFILTER\" CON IL FILTRO DI ACCESSO \"NONE\" NEL FILE \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\".\rPERCHÉ LE IMMAGINI E I FOGLI DI STILE NON VENGONO VISUALIZZATI?\rA VOLTE CI SONO PROBLEMI CON LA VISUALIZZAZIONE DI IMMAGINI E FOGLI DI STILE. SOPRATTUTTO SE QUESTI FILE SI TROVANO SU UN\'UNITÀ DI RETE. IN QUESTO CASO È POSSIBILE ATTIVARE (O AGGIUNGERE) UNO SE LE SEGUENTI RIGHE NEL FILE \'\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\'\rENABLESENDFILE OFF\rENABLEMMAP OFF\rQUESTO PROBLEMA PUÒ ESSERE CAUSATO ANCHE DA PROGRAMMI PER LA REGOLAZIONE DELLA LARGHEZZA DI BANDA, COME NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rCOME POSSO IMPOSTARE UNA PASSWORD DI ROOT IN MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rPOSSO UTILIZZARE IL MIO SERVER MYSQL?\rSÌ. SEMPLICEMENTE NON AVVIARE IL MYSQL DAL PACCHETTO XAMPP. SI PREGA DI NOTARE CHE DUE SERVER NON POSSONO ESSERE AVVIATI SULLA STESSA PORTA. SE È STATA IMPOSTATA UNA PASSWORD PER \'ROOT\', SI PREGA DI NON DIMENTICARE DI MODIFICARE IL FILE \'\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PH\".\rCOME FACCIO A LIMITARE L\'ACCESSO A PHPMYADMIN DALL\'ESTERNO?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rPRIMA DI POTER ACCEDERE AL SERVER MYSQL, PHPMYADMIN VI CHIEDERÀ UN NOME UTENTE E UNA PASSWORD. NON DIMENTICARE DI IMPOSTARE UNA PASSWORD PER L\'UTENTE \'ROOT\' PRIMA.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rDOVE SI TROVA IL SUPPORTO IMAP PER PHP?\rCOME IMPOSTAZIONE PREDEFINITA, IL SUPPORTO IMAP PER PHP È DISATTIVATO IN XAMPP A CAUSA DI ALCUNI ERRORI DI INIZIALIZZAZIONE MISTERIOSI CON ALCUNE VERSIONI HOME COME WINDOWS 98. SE SI LAVORA CON SISTEMI NT, È POSSIBILE APRIRE IL FILE \'\\\\XAMPP\\\\PHP\\\\PHP.INI\'. PER ATTIVARE LA EXSTENSION PHP RIMUOVENDO IL PUNTO E VIRGOLA A PARTIRE DALLA LINEA \'; ESTENSIONE PHP_IMAP.DLL\'. DOVREBBE ESSERE:\rEXTENSION=PHP_IMAP.DLL\rORA RIAVVIATE APACHE E IMAP DOVREBBE FUNZIONARE. È POSSIBILE UTILIZZARE LA STESSA PROCEDURA PER OGNI ESTENSIONE, CHE NON È ABILITATA NELLA CONFIGURAZIONE PREDEFINITA.\rPERCHÉ ALCUNE APPLICAZIONI OPEN SOURCE PHP NON LAVORANO CON XAMPP SU WINDOWS?\rMOLTE APPLICAZIONI PHP O ESTENSIONI CHE SONO STATE SCRITTE PER LINUX NON SONO STATE PORTATE SU DI WINDOWS \rELIMINARE LA CARTELLLA \"INSTALL\" DOPO L\'INSTALLAZIONE?\rE \'MEGLIO NON FARLO. SONO ANCORA NECESSARI GLI SCRIPT PER TUTTI I PACCHETTI AGGIUNTIVI (ADD-ON) E AGGIORNAMENTI DI XAMPP.\rCOME FACCIO AD ATTIVARE LA EACCELERATOR?\rCOME ALTRI (ZEND), LE ESTENSIONI, È POSSIBILE ATTIVARLO IN \'PHP.INI\'. IN QUESTO FILE, ABILITARE LA RIGA \'; ZEND_EXTENSION\' \\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\'\'. DOVREBBE ESSERE:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rCOME POSSO RISOLVERE UN ERRORE DI CONNESSIONE AL MIO SERVER MS SQL?\rSE L\'ESTENSIONE MSSQL È STATO CARICATO NEL PHP.INI, TALVOLTA PROBLEMI SOLO QUANDO VIENE UTILIZZATO IL PROTOCOLLO TCP/IP. È POSSIBILE RISOLVERE IL PROBLEMA CON UN NUOVO \'NTWDBLIB.DLL\" DI MICROSOFT. SOSTITUIRE IL VECCHIO FILE IN \'\\\\XAMPP\\\\APACHE\\\\BIN\' E \'\\\\XAMPP\\\\PHP\" CON QUELLO NUOVO. A CAUSA DELLA LICENZA, NON VI E UN PACCHETTO DI UNA VERSIONE PIÙ RECENTE DEL FILE CON XAMPP.\rCOME FACCIO A LAVORARE CON IL PHP MCRYPT È PER LO PIÙ UNA ESTENSIONE?\rPER QUESTO, ABBIAMO APERTO UNA DISCUSSIONE NEL FORUM CON GLI ESEMPI E LE POSSIBILI SOLUZIONI: % {MCRYPT È PER LO PIÙ UNA}\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rNO, E APACHE::ASP CON IL PERL ADD-ON NON E UGUALE.APACHE::ASP CONOSCE SOLO PERL-SCRIPT,MA ASP DA INTERNET INFORMATION SERVER (IIS) CONOSCE ANCHE IL NORMALE VBSCRIPT.MA PER ASP .NET C\'È UN MODULO DI 3RD PARTY APACHE DISPONIBILE.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA SULLA PRIVACY\rCDN FORNITO DA\r\n'),(57,'5298a51d00a817a6ec5619b5f7460955','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rDOMANDE FREQUENTI\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA SULLA PRIVACY\rCDN FORNITO DA\r\n'),(58,'a80b457ffb65fc092d6c161479c18f1c','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rDOMANDE FREQUENTI\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA SULLA PRIVACY\rCDN FORNITO DA\r\n'),(59,'5cb8304b891037b0750bd33eb281bdfc','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rDOMANDE FREQUENTI\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA SULLA PRIVACY\rCDN FORNITO DA\r\n'),(60,'59969d7bef630bc71a0e914af0bfef7e','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rDOMANDE FREQUENTI\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rDOMANDE FREQUENTI\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nCOMUNITÀ\rXAMPP È IN USO DA CIRCA 10 ANNI ED HA ALLE SUE SPALLE UN\'ENORME COMMUNITY. ANCHE TU PUOI FARNE PARTE PARTECIPANDO AI NOSTRI \rFORUM\r, CLICCANDO MI PIACE NELLA NOSTRA PAGINA \rFACEBOOK\r, OPPURE SEGUENDO I NOSTRI POST SU \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA SULLA PRIVACY\rCDN FORNITO DA\r\n'),(61,'1d2d14880fdc56b44820e639f95e0538','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rFAQ\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rよくある質問\rXAMPP のインストール方法\rWINDOWS用のXAMPPを導入する手段は3つあります。\rインストーラを使う方法：\rおそらく最も簡単な方法です。\rZIP:\r補足：XAMPP は通常、ZIP形式で圧縮されています。 \r7ZIP:\r通信環境が悪い場合：XAMPPの7ZIP形式の圧縮ファイルを使用してください。\rNOTE: IF YOU EXTRACT THE FILES, THERE CAN BE FALSE-POSITIVES VIRUS WARNINGS.\rUSING THE INSTALLER:\rXAMPPのコントロールパネルからAPACHE、MYSQL、FILEZILLAとMERCURY の開始/停止、サービス利用のためのサーバーインストールが行えます。\rINSTALLING FROM ZIP\rUNZIP THE ZIP ARCHIVES INTO THE FOLDER OF YOUR CHOICE. XAMPP IS EXTRACTING TO THE SUBDIRECTORY \"C:\\XAMPP\" BELOW THE SELECTED TARGET DIRECTORY. NOW START THE FILE \"SETUP_XAMPP.BAT\", TO ADJUST THE XAMPP CONFIGURATION TO YOUR SYSTEM.\rIF YOU CHOOSE A ROOT DIRECTORY \"C:\\\" AS TARGET, YOU MUST NOT START \"SETUP_XAMPP.BAT\".\rインストーラのバージョンと同様に、追加のタスクについては、「 XAMPPコントロールパネル」を使用することができます。\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rどうやったらセットアップをすることなくXAMPPを起動することができますか？\rもし上位フォルダ（ \"C:\\\\\"や\"D:\\\\\"など）にXAMPPを展開する場合は、あなたは直接 SETUP_XAMPP.BAT ファイルを実行することなくAPACHEやMYSQLのようなほとんどのサーバーを起動することができます。\rUSBドライブにXAMPPをインストールしているなら、セットアップスクリプトを使わない、もしくは、セットアップスクリプト内の相対パスを選ばない方が良いです。それぞれのPCのドライブにはそれぞれのドライブ記号があります。セットアップスクリプトを使えばいつでも絶対パスから相対パスに変更することは可能です。 \rXAMPPをインストールする最も簡単な方法は、私たちのダウンロードページからインストーラを起動することです。インストールが完了したら、 スタート→全てのプログラム→XAMPPの中にXAMPPが格納されます 。あなたはXAMPPコントロールパネルを使用して、全てのサーバーの開始/停止、インストール/アンインストールを行うことができます。\rXAMPPのコントロールパネルからAPACHE、MYSQL、FILEZILLAとMERCURY の開始/停止、サービス利用のためのサーバーインストールが行えます。\rHOW DO I START AND STOP XAMPP?\r共通のコントロールセンターは、 「 XAMPPコントロールパネル」 （WWW.NAT32.COM）です。以下のように開始されます。\r\\XAMPP\\XAMPP-CONTROL.EXE\rYOU CAN ALSO USE SOME BATCHFILES TO START/STOP THE SERVERS:\rAPACHE &AMP：MYSQL の開始：\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL STOP:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE START:\n\\XAMPP\\APACHE_START.BAT\rAPACHE STOP:\n\\XAMPP\\APACHE_STOP.BAT\rMYSQL START:\n\\XAMPP\\MYSQL_START.BAT\rMYSQLの停止：\n\\XAMPP\\MYSQL_STOP.BAT\rMERCURY メールサーバーの開始：\n\\XAMPP\\MERCURY_START.BAT\rMERCURY メールサーバーの停止：\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA サーバーの開始：\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA サーバーの停止：\n\\XAMPP\\FILEZILLA_STOP.BAT\rどのようにすれば、システムが正常に動いていることを確認できますか？ \rウェブブラウザで以下のURLにアクセスしてください：\rHTTP://LOCALHOST/\rまたは \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rHOW CAN I INSTALL A SERVER AS A SERVICE?\rXAMPP内の各サーバはWINDOWSサービスとしてもインストールすることができます。また、 XAMPPコントロールパネルからインストールすることができます。この場合には、管理者権限でスクリプトや[コントロールパネル]を実行する必要があります。\rAPACHE サービスのインストール：\\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rAPACHE サービスのアンインストール：\\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rMYSQL SERVICE INSTALL: \\XAMPP\\MYSQL\\MYSQL_INSTALLSERVICE.BAT \rMYSQL SERVICE UNINSTALL: \\XAMPP\\MYSQL\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA SERVICE (UN)INSTALL: \\XAMPP\\FILEZILLA_SETUP.BAT \rMERCURY: NO SERVICE INSTALLATION AVAILABLE\rXAMPPを実際の運用で使用することはできますか？\rXAMPPは製品運用の手段ではなく、開発環境です。開発者の思った通りに何でもできるよう可能な限りオープンに設定されているのがXAMPPです。これは開発環境には素晴らしい事ですが、製品としては致命的です。\rXAMPPのセキュリティ上の脆弱性を以下に示します。\rMYSQL の管理者 ID (ROOT) にパスワードが設定されていません。 \rMYSQL デーモンは、ネットワークを介してアクセス可能です。\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rTHE DEFAULT USERS OF MERCURY AND FILEZILLA ARE KNOWN.\rALL POINTS CAN BE A HUGE SECURITY RISK. ESPECIALLY IF XAMPP IS ACCESSIBLE VIA NETWORK AND PEOPLE OUTSIDE YOUR LAN. IT CAN ALSO HELP TO USE A FIREWALL OR A (NAT) ROUTER. IN CASE OF A ROUTER OR FIREWALL, YOUR PC IS NORMALLY NOT ACCESSIBLE VIA NETWORK. IT IS UP TO YOU TO FIX THESE PROBLEMS. AS A SMALL HELP THERE IS THE \"XAMPP SECURITY CONSOLE\".\rオンラインで何かを公開する前にXAMPPをセキュリティで保護してください。ファイアウォールまたは外部ルータは、セキュリティのレベルが低いためです。もう少しセキュリティを強化するために、 「 XAMPPセキュリティ・コンソール\"を実行し、パスワードを割り当てることができます。\r自分のXAMPPをインターネットからアクセスできるようにさせたいなら、問題を修正できるこのURIへ行って下さい。 \rHTTP://LOCALHOST/SECURITY/\rセキュリティコンソールを使用すると、 MYSQLユーザー\"ROOT\" とPHPMYADMINのパスワードを設定することができます。また、 XAMPPのデモページの認証を有効にすることができます。\rこのWEBベースのツールは、追加のセキュリティ問題を修正しません！特に、 FILEZILLAのFTPサーバとMERCURYメールサーバは、あなた自身でセキュリティ保護する必要があります。\rXAMPPをアンインストールするにはどうしたらよいでしょうか？\rインストーラのバージョンを使用して、 XAMPPをインストールした場合は、アンインストーラを使用してください。アンインストーラは、レジストリからすべてのXAMPPエントリを削除し、それがXAMPPに含まれているいくつかインストールされているサービスをアンインストールします。我々はXAMPPのインストールを除去するためのアンインストールプログラムを使用することを強くお勧めします。XAMPPをアンインストールする前に、保存しておきたいすべてのデータのバックアップを行ってください。\rIF YOU INSTALLED XAMPP USING THE ZIP AND 7ZIP VERSIONS, SHUT DOWN ALL XAMPP SERVERS AND EXIT ALL PANELS. IF YOU INSTALLED ANY SERVICES, UNINSTALL AND SHUT THEM DOWN TOO. NOW SIMPLY DELETE THE ENTIRE FOLDER WHERE XAMPP IS INSTALLED. THERE ARE NO REGISTRY ENTRIES AND NO ENVIRONMENT VARIABLES TO CLEAN UP.\rWHAT IS THE \"LITE\" VERSION OF XAMPP?\rXAMPP LITE (MEANS \"LIGHT\" AS IN \"LIGHT-WEIGHT\") IS A SMALLER BUNDLE OF XAMPP COMPONENTS, WHICH IS RECOMMENDED FOR QUICK WORK USING ONLY PHP AND MYSQL. SOME SERVERS OR TOOLS SUCH AS MERCURY MAIL AND FILEZILLA FTP ARE MISSING IN THE LITE VERSION.\rWHERE SHOULD I PLACE MY WEB CONTENT?\rTHE MAIN DIRECTORY FOR ALL WWW DOCUMENTS IS \\XAMPP\\HTDOCS. IF YOU PUT A FILE \"TEST.HTML\" IN THIS DIRECTORY, YOU CAN ACCESS IT WITH THE URI \"HTTP://LOCALHOST/TEST.HTML\".\rAND \"TEST.PHP\"? JUST USE \"HTTP://LOCALHOST/TEST.PHP\". A SIMPLE TESTSCRIPT CAN BE:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rA NEW SUBDIRECTORY FOR YOUR WEB? JUST MAKE A NEW DIRECTORY (E.G. \"NEW\") INSIDE THE DIRECTORY \"\\XAMPP\\HTDOCS\" (BEST WITHOUT WHITESPACES AND ONLY ASCII), CREATE A TEST FILE IN THIS DIRECTORY AND ACCESS IT WITH \"HTTP://LOCALHOST/NEW/TEST.PHP\".\rFURTHER SPECIFICS\rHTML:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .HTML .HTM\r=> BASIC PACKAGE\rSSI:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .SHTML\r=> BASIC PACKAGE\rCGI:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .CGI\r=> BASIC PACKAGE\rPHP:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .PHP\r=> BASIC PACKAGE\rPERL:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .PL\r=> BASIC PACKAGE\rAPACHE::ASP PERL:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .ASP\r=> BASIC PACKAGE\rJSP JAVA:\rEXECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rALLOWED ENDINGS: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rEXECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rALLOWED ENDINGS: .HTML (U.A)\r=> TOMCAT ADD-ON\rCAN I MOVE THE XAMPP INSTALLATION?\rYES. AFTER MOVING OF THE XAMPP DIRECTORY, YOU MUST EXECUTE \"SETUP_XAMPP.BAT\". THE PATHS IN THE CONFIGURATION FILES WILL BE ADJUSTED WITH THIS STEP.\rIF YOU HAVE INSTALLED ANY SERVER AS WINDOWS SERVICE, YOU MUST FIRST REMOVE THE WINDOWS SERVICE, AND AFTER THE MOVING YOU CAN INSTALL THE SERVICE AGAIN.\rWARNING: THE CONFIGURATION FILES FROM YOUR OWN SCRIPTS, LIKE PHP APPLICATIONS, ARE NOT ADJUSTED. BUT IT\'S POSSIBLE TO WRITE A \"PLUG-IN\" FOR THE INSTALLER. WITH SUCH A PLUG-IN, THE INSTALLER CAN ADJUST SUCH FILES TOO.\rWHAT ARE \"AUTOMATIC START PAGES\" FOR THE WWW DIRECTORIES?\rTHE STANDARD FILENAME FOR THE APACHE FUNCTION \"DIRECTORYINDEX\" IS \"INDEX.HTML\" OR \"INDEX.PHP\". EVERY TIME YOU ARE JUST BROWSING TO A FOLDER (E.G. \"HTTP://LOCALHOST/XAMPP/\"), AND APACHE CAN FIND SUCH A FILE, APACHE IS DISPLAYING THIS FILE INSTEAD OF A DIRECTORY LISTING.\rWHERE CAN I CHANGE THE CONFIGURATION?\rALMOST ALL SETTINGS IN XAMPP YOU CAN CHANGE WITH CONFIGURATION FILES. JUST OPEN THE FILE IN A TEXTEDIT AND CHANGE THE SETTING YOU WANT. ONLY FILEZILLA AND MERCURY SHOULD BE CONFIGURED WITH THE APPLICATION CONFIG TOOL.\rWHY CAN\'T XAMPP WORK ON WINDOWS XP SP2?\rMICROSOFT DELIVERS A BETTER FIREWALL WITH SERVICE PACK 2 (SP2), WHICH STARTS AUTOMATICALLY. THIS FIREWALL NOW BLOCKS THE NECESSARY PORTS 80 (HTTP) AND 443 (HTTPS) AND APACHE CAN\'T START.\rTHE FAST SOLUTION:\rDISABLE THE MICROSOFT FIREWALL WITH THE TOOLBAR AND TRY TO START XAMPP ONCES MORE. THE BETTER SOLUTION IS TO DEFINE AN EXCEPTION WITHIN THE SECURITY CENTER.\rTHE FOLLOWING PORTS ARE USED FOR BASIC FUNCTIONALITY:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rWHY DOESN\'T XAMPP WORK ON VISTA?\rUSER ACCOUNT CONTROL (UAC)\rIN THE DIRECTORY \"C:\\PROGRAM FILES\" YOU DON\'T HAVE FULL WRITE PRIVILEGES, EVEN AS ADMIN. OR YOU HAVE ONLY LIMITED PRIVILEGES (E.G. FOR \".\\XAMPP\\HTDOCS\"). IN THIS CASE YOU CAN\'T EDIT A FILE.\rSOLUTION:\rRAISE YOUR PRIVILEGES WITHIN EXPLORER (RIGHT CLICK / SECURITY) OR DEACTIVATE THE USER ACCOUNT CONTROL (UAC).\rYOU HAVE INSTALLED APACHE/MYSQL IN \"C:\\XAMPP\" AS WINDOWS SERVICE. BUT YOU CAN\'T START/STOP THE SERVICES WITH THE \"XAMPP CONTROL PANEL\" OR CAN\'T UNINSTALL THEM.\rSOLUTION:\rUSE THE SERVICE MANAGEMENT CONSOLE FROM WINDOWS OR DEACTIVATE UAC.\rDISABLING THE USER ACCOUNT CONTROL (UAC)\rTO DEACTIVATE THE UAC, USE THE PROGRAM \"MSCONFIG\". IN \"MSCONFIG\" GO TO \"TOOLS\", SELECT \"DISABLE USER ACCOUNT CONTROL\" AND VERIFY YOUR SELECTION. NOW YOU MUST RESTART WINDOWS. AT THE SAME TIME, YOU CAN ENABLE THE UAC AGAIN.\rHOW DO I CHECK THE MD5 CHECKSUM?\rTO COMPARE FILES, OFTEN CHECKSUMS ARE USED. A STANDARD TO CREATE THIS CHECKSUM MD5 (MESSAGE DIGEST ALGORITHM 5).\rWITH THIS MD5 CHECKSUM YOU CAN TEST, IF YOUR DOWNLOAD OF THE XAMPP PACKAGE IS CORRECT OR NOT. OF COURSE YOU NEED A PROGRAM WHICH CAN CREATE THESE CHECKSUMS. FOR WINDOWS YOU CAN USE A TOOL FROM MICROSOFT:\rAVAILABILITY AND DESCRIPTION OF THE FILE CHECKSUM INTEGRITY VERIFIER UTILITY\rIT\'S ALSO POSSIBLE TO USE ANY OTHER PROGRAM WHICH CAN CREATE MD5 CHECKSUMS, LIKE THE GNU MD5SUM.\rAS YOU HAVE INSTALLED SUCH A PROGRAM (E.G. FCIV.EXE), YOU CAN DO FOLLOWING STEPS:\rDOWNLOAD XAMPP (F.E. XAMPP-WIN32-1.8.2-0.EXE)\rCREATE THE CHECKSUM WITH:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rAND NOW YOU CAN COMPARE THIS CHECKSUM WITH THAT ONE YOU CAN FIND ON THE XAMPP FOR WINDOWS HOMEPAGE.\rIF BOTH CHECKSUMS EQUAL, ALL IS OK. IF NOT, THE DOWNLOAD IS BROKEN OR THE FILE HAS BEEN CHANGED.\rWHY HAVE CHANGES IN MY PHP.INI NOT TAKEN EFFECT?\rIF A CHANGE IN THE \"PHP.INI\" HAS NO EFFECT, IT\'S POSSIBLE PHP IS USING A DIFFERENT ONE. YOU CAN VERIFY THIS WITH PHPINFO(). GO TO THE URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP AND SEARCH FOR \"LOADED CONFIGURATION FILE\". THIS VALUE SHOWS YOU THE \"PHP.INI\" PHP IS REALLY USING.\rNOTE:\rAFTER CHANGING THE \"PHP.INI\" YOU HAVE TO RESTART APACHE SO THAT APACHE/PHP CAN READ THE NEW SETTINGS.\rHELP! THERE IS A VIRUS IN XAMPP!\rSOME ANTIVIRUS PROGRAMS MISTAKE XAMPP FOR A VIRUS, TYPICALLY FLAGGING THE FILE XAMPP-MANAGER.EXE THIS IS A FALSE POSITIVE MEANING THAT THE ANTIVIRUS ERRONEOUSLY IDENTIFIED IT AS A VIRUS, WHEN IT IS NOT. BEFORE WE RELEASE EACH NEW VERSION OF XAMPP WE RUN IT THROUGH VIRUS SCANNING SOFTWARE. AT THE MOMENT WE ARE USING \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rHOW DO I CONFIGURE MY ANTIVIRUS APPLICATION?\rWE HAVE INCLUDED ALL DEPENDENCES AND SERVERS REQUIRED FOR RUNNING THE BUNDLED WEB APPLICATION, SO YOU WILL FIND THAT XAMPP INSTALLS LARGE NUMBERS OF FILES. IF YOU ARE INSTALLING A XAMPP APPLICATION ON A WINDOWS MACHINE WITH AN ANTIVIRUS APP ENABLED, THIS MAY SLOW DOWN THE INSTALLATION SIGNIFICANTLY, AND THERE IS ALSO A CHANCE THAT ONE OF THE SERVERS (WEB SERVER, DATABASE SERVER) MAY BE BLOCKED BY THE ANTIVIRUS SOFTWARE. IF YOU HAVE AN ANTIVIRUS TOOL ENABLED, CHECK THE FOLLOWING SETTINGS FOR RUNNING XAMPP WITHOUT PERFORMANCE ISSUES:\rADD EXCEPTIONS IN THE FIREWALL: FOR APACHE, MYSQL OR ANY OTHER SERVER.\rSCAN FILES WHEN EXECUTING: IF YOU HAVE ENABLED THE ANTIVIRUS SCAN FOR ALL FILES, THE EXECUTABLE FILES FOR THE SERVERS MAY SLOW DOWN.\rSCAN THE TRAFFIC FOR DIFFERENT URLS: IF YOU ARE DEVELOPING WITH XAMPP ON YOUR OWN MACHINE, YOU CAN EXCLUDE \"LOCALHOST\" TRAFFIC IN THE ANTIVIRUS SETTINGS.\rWHY DOESN\'T THE APACHE SERVER START ON MY SYSTEM?\rTHIS PROBLEM CAN BE ONE OF SEVERAL REASONS:\rYOU HAVE STARTED MORE THEN ONE HTTP SERVER (IIS, SAMBAR, ZEUS AND SO ON). ONLY ONE SERVER CAN USE PORT 80. THIS ERROR MESSAGE INDICATE THE PROBLEM:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rYOU HAVE OTHER SOFTWARE, SUCH AS THE INTERNET TELEPHONE \"SKYPE\" WHICH ALSO BLOCKS THE PORT 80. IF THE PROBLEM IS \"SKYPE\", YOU CAN GO IN SKYPE TO ACTIONS --> OPTIONS --> CONNECTION --> REMOVE THE CHECK MARK AT \"USE PORT 80 FOR AN ALTERNATE PORT\" AND RESTART SKYPE. NOW IT SHOULD WORK.\rYOU HAVE A FIREWALL WHICH BLOCKS THE APACHE PORT. NOT ALL FIREWALLS ARE COMPATIBLE WITH APACHE, AND SOMETIMES DEACTIVATING THE FIREWALL IS NOT ENOUGH AND YOU MUST DEINSTALL IT. THIS ERROR MESSAGE INDICATES A FIREWALL:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rALSO IF APACHE CAN START, BUT YOUR BROWSER CAN\'T CONNECT TO IT IT COULD BE DUE TO ONE OF THE FOLLOWING:\rSOME VIRUS SCANNERS CAN CAUSE THIS IN THE SAME WAY THAT FIREWALLS CAN INTERFERE.\rYOU HAVE XP PROFESSIONAL WITHOUT SERVICE PACK 1. YOU MUST HAVE AT LEAST SP1 FOR XAMPP.\rTIP:\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\rWHY IS MY CPU LOAD FOR APACHE ALMOST 99%?\rTHERE IS ONE OF TWO SCENARIOS AT PLAY HERE. EITHER YOUR CPU IS MAXING OUT, OR YOU CAN BROWSER CONNECT TO THE SERVER, BUT NOT SEE ANYTHING (THE SYSTEM IS TRYING UNSUCESSFULLY TO LOAD THE PAGE). IN EITHER CASE YOU CAN FIND THE FOLLOWING MESSAGE IN THE APACHE LOG FILE:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rTHE MPM FALLS BACK TO A SAFER IMPLEMENTATION, BUT SOME CLIENT REQUESTS WERE NOT PROCESSED CORRECTLY. IN ORDER TO AVOID THIS ERROR, USE \"ACCEPTFILTER\" WITH ACCEPT FILTER \"NONE\" IN THE \"\\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-MPM.CONF\" FILE.\rWHY ARE PICTURES AND STYLE-SHEETS NOT DISPLAYED?\rSOMETIMES THERE ARE PROBLEMS WITH DISPLAYING PICTURES AND STYLE-SHEETS. ESPECIALLY IF THESE FILES ARE LOCATED ON A NETWORK DRIVE. IN THIS CASE YOU CAN ENABLE (OR ADD) ONE IF THE FOLLOWING LINES IN THE FILE \"\\XAMPP\\APACHE\\CONF\\HTTPD.CONF\":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rTHIS PROBLEM CAN ALSO BE CAUSED BY PROGRAMS FOR REGULATING BANDWIDTH, LIKE NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rHOW CAN I SET A ROOT PASSWORD IN MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rCAN I USE MY OWN MYSQL SERVER?\rYES. SIMPLY DON\'T START THE MYSQL FROM THE XAMPP PACKAGE. PLEASE NOTE THAT TWO SERVERS CANNOT BE STARTED ON THE SAME PORT. IF YOU HAVE SET A PASSWORD FOR \"ROOT\", PLEASE DO NOT FORGET TO EDIT THE FILE \"\\XAMPP\\PHPMYADMIN\\CONFIG.INC.PHP\".\rHOW DO I RESTRICT ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rBEFORE YOU CAN ACCESS THE MYSQL SERVER, PHPMYADMIN WILL PROMPT YOU FOR A USER NAME AND PASSWORD. DON\'T FORGET TO SET A PASSWORD FOR THE USER \"ROOT\" FIRST.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rWHERE IS THE IMAP SUPPORT FOR PHP?\rAS DEFAULT, THE IMAP SUPPORT FOR PHP IS DEACTIVATED IN XAMPP DUE TO SOME MYSTERIOUS INITIALIZATION ERRORS WITH SOME HOME VERSIONS LIKE WINDOWS 98. IF YOU WORK WITH NT SYSTEMS, YOU CAN OPEN THE FILE \"\\XAMPP\\PHP\\PHP.INI\" TO ACTIVATE THE PHP EXSTENSION BY REMOVING THE BEGINNING SEMICOLON AT THE LINE \";EXTENSION=PHP_IMAP.DLL\". IT SHOULD BE:\rEXTENSION=PHP_IMAP.DLL\rNOW RESTART APACHE AND IMAP SHOULD WORK. YOU CAN USE THE SAME STEPS FOR EVERY EXTENSION, WHICH IS NOT ENABLED IN THE DEFAULT CONFIGURATION.\rWHY DON\'T SOME PHP OPEN SOURCE APPS WORK WITH XAMPP ON WINDOWS?\rA LOT OF PHP APPLICATIONS OR EXTENSIONS THAT HAVE BEEN WRITTEN FOR LINUX HAVEN’T BEEN PORTED TO WINDOWS. \rCAN I DELETE THE \"INSTALL\" DIRECTORY AFTER INSTALLATION?\rIT\'S BETTER NOT TO. THE SCRIPTS HERE ARE STILL NEEDED FOR ALL ADDITIONAL PACKAGES (ADD-ONS) AND UPGRADES OF XAMPP.\rHOW DO I ACTIVATE THE EACCELERATOR?\rLIKE OTHER (ZEND) EXTENSIONS, YOU CAN ACTIVATE IT IN \"PHP.INI\". IN THIS FILE, ENABLE THE LINE \";ZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\". IT SHOULD BE:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rHOW DO I FIX A CONNECTION ERROR TO MY MS SQL SERVER?\rIF THE MSSQL EXTENSION WAS LOADED IN THE PHP.INI, SOMETIMES PROBLEMS APPEAR WHEN ONLY TCP/IP IS USED. YOU CAN FIX THAT PROBLEM WITH A NEWER \"NTWDBLIB.DLL\" FROM MICROSOFT. PLEASE REPLACE THE OLDER FILE IN \"\\XAMPP\\APACHE\\BIN\" AND \"\\XAMPP\\PHP\" WITH THE NEW ONE. BECAUSE OF THE LICENSE, WE CAN\'T PACKAGE A NEWER VERSION OF THIS FILE WITH XAMPP.\rHOW DO I WORK WITH THE PHP MCRYPT EXTENSION?\rFOR THIS, WE HAVE OPENED A TOPIC IN THE FORUM WITH EXAMPLES AND POSSIBLE SOLUTIONS: \rMCRYPT TOPIC\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rNO. AND APACHE::ASP WITH THE PERL ADD-ON IS NOT THE SAME. APACHE::ASP ONLY KNOWS PERL-SCRIPT, BUT ASP FROM THE INTERNET INFORMATION SERVER (IIS) ALSO KNOWS THE NORMAL VBSCRIPT. BUT FOR ASP .NET, THERE IS A 3RD PARTY APACHE MODULE AVAILABLE.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rブログ\r個人情報保護方針\rCDNから提供\r\n'),(62,'4237863204a2e7707add041da4b80f19','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rFAQ\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rブログ\r個人情報保護方針\rCDNから提供\r\n'),(63,'e8c0e3e706859bed08103b050acffbb7','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rFAQ\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rブログ\r個人情報保護方針\rCDNから提供\r\n'),(64,'ba9d6ef9ff753676d8a6f548829915ae','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rFAQ\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rブログ\r個人情報保護方針\rCDNから提供\r\n'),(65,'08c71ec832ce2c366c54c777ff6ad776','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rFAQ\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rFAQ\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nコミュニティー\rXAMPP は10年以上の実績があります  よってその背後には大きなコミュニティーが存在します。弊社の \rフォーラム\rに参加、 %および \rFACEBOOK\rで「いいね」ボタンを押す、\rTWITTER\rでフォロー、このコミュニティーに参加することができます。\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rブログ\r個人情報保護方針\rCDNから提供\r\n'),(66,'2940552d193b7182f02a5b346677dd56','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rNAJCZĘŚCIEJ ZADAWANE PYTANIA\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rNAJCZĘŚCIEJ ZADAWANE PYTANIA\rJAK ZAINSTALOWAĆ XAMPP?\rXAMPP DLA WINDOWS WYSTĘPUJE W TRZECH RÓŻNYCH ODMIANACH:\rINSTALATOR:\rPRAWDOPODOBNIE NAJPROSTSZY SPOSÓB NA ZAINSTALOWANIE XAMPP.\rZIP:\rDLA PURYSTÓW: XAMPP JAKO ZWYCZAJNE ARCHIWUM ZIP.\r7ZIP:\rDLA PURYSTÓW Z NISKIM TRANSFEREM INTERNETOWYM: XAMPP JAKO ARCHIWUM 7ZIP.\rUWAGA: JEŚLI WYPAKUJESZ PLIKI, MOGĄ SIĘ POJAWIĆ FAŁSZYWE OSTRZEŻENIA PROGRAMÓW ANTYWIRUSOWYCH.\rUŻYWAJĄC PROGRAMU INSTALACYJNEGO:\rPANEL KONTROLNY XAMPP SŁUŻY DO URUCHAMIANIA/ZATRZYMYWANIA APACHE, MYSQL, FILEZILLA & MERCURY LUB INSTALACJI TYCH SERWERÓW JAKO USŁUGI SYSTEMOWE.\rINSTALOWANIE Z PLIKU ZIP\rWYPAKUJ ARCHIWUM ZIP DO WYBRANEGO PRZEZ SIEBIE FOLDERU. XAMPP JEST DOMYŚLNIE WYPAKOWYWANY DO KATALOGU \"C:\\\\XAMPP\". TERAZ URUCHOM PLIK \"SETUP_XAMPP.BAT\" ABY DOSTOSOWAĆ KONFIGURACJĘ XAMPP DO TWOJEGO SYSTEMU.\rJEŻELI WYBRAŁEŚ KATALOG DOCELOWY JAKO C:\\\\\", NIE MUSISZ URUCHAMIAĆ PLIKU \"SETUP_XAMPP.BAT\".\rTAK JAK W WERSJI INSTALACYJNEJ, MOŻESZ TERAZ UŻYĆ \"XAMPP CONTROL PANEL\" W CELU WYKONANIA DODATKOWYCH ZADAŃ.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rJAK MOGĘ URUCHOMIĆ XAMPP BEZ INSTALACJI?\rJEŚLI WYPAKUJESZ XAMPP DO KATALOGU GŁÓWNEGO JAK \"C:\\\\\" LUB \"D:\\\\\", MOŻESZ URUCHOMIĆ WIĘKSZOŚĆ SERWERÓW JAK APACHE CZY MYSQL BEZPOŚREDNIO, BEZ POTRZEBY URUCHAMIANIA PLIKU \"SETUP_XAMPP.BAT\".\rNALEŻY NIE UŻYWAĆ SKRYPTU INSTALACYJNEGO LUB WYBRAĆ ŚCIEŻKI WZGLĘDNE W SKRYPCIE INSTALACYJNYM, JEST TO KORZYSTNE W PRZYPADKU INSTALACJI XAMPP NA DYSKU USB, PONIEWAŻ NA KAŻDYM KOMPUTERZE TAKI NAPĘD MOŻE MIEĆ INNĄ LITERĘ NAPĘDU. MOŻESZ W KAŻDEJ CHWILI PRZEŁĄCZYĆ SIĘ POMIĘDZY ŚCIEŻKAMI RELATYWNYMI A ABSOLUTNYMI W SKRYPCIE INSTALACYJNYM.\rUŻYWAJĄC INSTALATORA Z NASZEJ STRONY POBIERANIA, ŁATWO ZAINSTALUJESZ PAKIET XAMPP. PO INSTALACJI XAMPP ZNAJDZIESZ W START => PROGRAMY => XAMPP. MOŻESZ UŻYĆ PANELU KONTROLNEGO XAMPP, ABY URUCHAMIAĆ/ZATRZYMYWAĆ WSZYSTKIE SERWERY I TAKŻE INSTALOWAĆ/USUWAĆ USŁUGI.\rPANEL KONTROLNY XAMPP SŁUŻY DO URUCHAMIANIA/ZATRZYMYWANIA APACHE, MYSQL, FILEZILLA & MERCURY LUB INSTALACJI TYCH SERWERÓW JAKO USŁUGI SYSTEMOWE.\rJAK MOGĘ URUCHOMIĆ I ZATRZYMAĆ XAMPP?\rUNIWERSALNE CENTRUM KONTROLI TO \"PANEL KONTROLI XAMPP\" (DZIĘKI WWW.NAT32.COM). JEST URUCHAMIANE Z:\r\\XAMPP\\XAMPP-CONTROL.EXE\rMOŻESZ TEŻ UŻYĆ KILKU SKRYPTÓW BY URUCHOMIĆ LUB ZATRZYMAĆ SERWERY:\rURUCHOMIENIE APACHE & MYSQL:\n\\XAMPP\\XAMPP_START.EXE\rZATRZYMYWANIE APACHE & MYSQL:\n\\XAMPP\\XAMPP_STOP.EXE\rURUCHOMIENIE APACHE\'A:\n\\XAMPP\\APACHE_START.BAT\rZATRZYMYWANIE APACHE:\n\\XAMPP\\APACHE_STOP.BAT\rURUCHAMIANIE MYSQL:\n\\XAMPP\\MYSQL_START.BAT\rZATRZYMYWANIE MYSQL:\n\\XAMPP\\MYSQL_STOP.BAT\rURUCHOMIENIE SERWERA MAILOWEGO MERCURY:\n\\XAMPP\\MERCURY_START.BAT\rZATRZYMYWANIE SERWERA MAILOWEGO MERCURY:\n\\XAMPP\\MERCURY_STOP.BAT\rURUCHOMIENIE SERWERA FILEZILLA:\n\\XAMPP\\FILEZILLA_START.BAT\rZATRZYMANIE SERWERA FILEZILLA:\n\\XAMPP\\FILEZILLA_STOP.BAT\rJAK MOGĘ SPRAWDZIĆ CZY WSZYSTKO DZIAŁA?\rWPROWADŹ PONIŻSZY URL W SWOJEJ ULUBIONEJ PRZEGLĄDARCE INTERNETOWEJ:\rHTTP://LOCALHOST/\rLUB \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rJAK MOGĘ ZAINSTALOWAĆ SERWER JAKO USŁUGĘ?\rKAŻDY SERWER W PAKIECIE XAMPP MOŻE BYĆ ZAINSTALOWANY JAKO USŁUGA WINDOWS. MOŻESZ TEGO DOKONAĆ PRZEZ PANEL KONTROLNY XAMPP. W WIĘKSZOŚCI PRZYPADKÓW URUCHOMIENIE SKRYPTÓW LUB PANELU KONTROLNEGO WYMAGA UPRAWNIEŃ ADMINISTRATORA.\rINSTALACJA USŁUGI APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rDEINSTALACJA USŁUGI APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rINSTALACJA USŁUGI MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rDEINSTALACJA USŁUGI MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \r(DE)INSTALACJA USŁUGI FILEZILLA: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: BRAK INSTALACJI USŁUGI\rCZY XAMPP JEST GOTOWY DO ŚRODOWISKA PRODUKCYJNEGO?\rXAMPP NIE JEST PRZEZNACZONY DO ZASTOSOWAŃ PRODUKCYJNYCH, ALE NA ŚRODOWISKO DEWELOPERSKIE. SPOSÓB W JAKI XAMPP JEST SKONFIGUROWANY BY BYĆ OTWARTYM JAK TO TYLKO MOŻLIWE UMOŻLIWIA DEWELOPEROM ROBIĆ CO ZECHCĄ. DO ZASTOSOWAŃ DEWELOPERSKICH JEST TO WSPANIAŁE, ALE DO ZASTOSOWAŃ PRODUKCYJNYCH MOŻE BYĆ FATALNE.\rTO JEST LISTA POMINIĘTYCH ZABEZPIECZEŃ W XAMPP:\rADMINISTRATOR MYSQL (ROOT) NIE MA HASŁA.\rUSŁUGA MYSQL JEST DOSTĘPNA PRZEZ SIEĆ.\rPROFTPD UŻYWA HASŁA \"LAMPP\" DLA UŻYTKOWNIKA \"DAEMON\".\rDOMYŚLNI UŻYTKOWNICY PROGRAMU MERCURY I FILEZILLA SĄ ZNANI.\rWSZYSTKIE PUNKTY MOGĄ BYĆ OGROMNYM ZAGROŻENIEM DLA BEZPIECZEŃSTWA. ZWŁASZCZA JEŻELI XAMPP JEST DOSTĘPNY PRZEZ SIEĆ I LUDZIE MAJĄ DOSTĘP DO NIEGO POZA TWOJĄ SIECIĄ LAN. TAKŻE MOŻE BYĆ POMOCNE UŻYCIE ZAPORY SIECIOWEJ LUB ROUTERA NAT. W PRZYPADKU ROUTERA LUB ZAPORY TWÓJ KOMPUTER NIE JEST NORMALNIE DOSTĘPNY PRZEZ SIEĆ. TO DO CIEBIE NALEŻY ZADANIE ROZWIĄZANIA TYCH PROBLEMÓW. JAKO MAŁĄ POMOC DAJEMY \"KONSOLĘ BEZPIECZEŃSTWA XAMPP\".\rPROSZĘ ZABEZPIECZYĆ XAMPP PRZED OPUBLIKOWANIEM CZEGOKOLWIEK W INTERNECIE. ZAPORA SIECIOWA LUB ZEWNĘTRZNY ROUTER WYSTARCZAJĄ TYLKO NA NISKIM POZIOMIE BEZPIECZEŃSTWA. ABY WPŁYNĄĆ NA NIECO WIĘKSZE BEZPIECZEŃSTWO, MOŻNA URUCHOMIĆ KONSOLĘ BEZPIECZEŃSTWA XAMPP I PRZYPISAĆ HASŁA.\rJEŻELI CHCESZ ABY TWÓJ XAMPP BYŁ DOSTĘPNY PRZEZ INTERNET, POWINIENEŚ PODĄŻYĆ ZA PONIŻSZYM URI, KTÓRY MOŻE NAPRAWIĆ NIEKTÓRE PROBLEMY:\rHTTP://LOCALHOST/SECURITY/\rZ KONSOLĄ BEZPIECZEŃSTWA MOŻESZ USTAWIĆ HASŁO DLA ADMINISTRATORA MYSQL I PHPMYADMINA. MOŻESZ TAKŻE WŁĄCZYĆ UWIERZYTELNIANIE DLA STRON Z PAKIETU XAMPP.\rTO NARZĘDZIE WEBOWE NIE POTRAFI NAPRAWIĆ KAŻDEJ DODATKOWEJ KWESTII ODNOŚNIE BEZPIECZEŃSTWA. W SZCZEGÓLNOŚCI MUSISZ SAM USTAWIĆ SERWER FILEZILLA FTP I SERWER MAILOWY MERCURY.\rJAK ODINSTALOWAĆ XAMPP?\rJEŻELI ZAINSTALOWAŁEŚ PAKIET XAMPP UŻYWAJĄC INSTALATORA, PROSZĘ UŻYJ DEINSTALATORA. DEINSTALATOR SKASUJE WSZYSTKIE WPISY XAMPP Z TWOJEGO REJESTRU I TAKŻE DEINSTALUJE JAKIEŚ ZAINSTALOWANE USŁUGI WŁĄCZONE W PAKIECIE XAMPP. BARDZO POLECAMY UŻYCIE DEINSTALATORA PRZY USUWANIU INSTALACJI XAMPP. PROSZĘ ZROBIĆ KOPIĘ ZAPASOWĄ WSZYSTKICH SWOICH DANYCH PRZED DEINSTALACJĄ PAKIETU XAMPP.\rJEŻELI ZAINSTALOWAŁEŚ XAMPP UŻYWAJĄC PROGRAMU ZIP I 7ZIP, WYŁĄCZ WSZYSTKIE SERWERY XAMPP I WYŁĄCZ WSZYSTKIE PANELE. JEŻELI INSTALOWAŁEŚ JAKIEŚ USŁUGI, ODINSTALUJ JE. TERAZ MOŻESZ USUNĄĆ FOLDER GDZIE XAMPP ZOSTAŁ ZAINSTALOWANY. NIE TRZEBA CZYŚCIĆ NICZEGO WIĘCEJ, PONIEWAŻ REJESTR NIE ZAWIERA ŻADNYCH WPISÓW I ZMIENNYCH ŚRODOWISKOWYCH.\rCO TO JEST WERSJA \"LITE\" PAKIETU XAMPP?\rXAMPP LITE (OZNACZA \"LEKKI\" W ZNACZENIU \"LEKKO WAŻĄCY\") JEST MNIEJSZYM ZESTAWEM KOMPONENTÓW XAMPP, KTÓRY JEST ZALECANY DLA SZYBSZEJ PRACY, UŻYWAJĄCEJ TYLKO PHP I MYSQL. NIEKTÓRE SERWERY LUB NARZĘDZIA TJ. MERCURY MAIL I FILEZILLA FTP NIE WYSTĘPUJĄ W WERSJI LEKKIEJ.\rGDZIE POWINIENEM UMIEŚCIĆ PLIKI Z MOJĄ APLIKACJĄ INTERNETOWĄ?\rGŁÓWNY FOLDER DLA WSZYSTKICH DOKUMENTÓW WWW TO \\\\XAMPP\\\\HTDOCS. JEŻELI UMIEŚCISZ W TYM KATALOGU PLIK \"TEST.HTML\", BĘDZIESZ MIAŁ DO NIEGO DOSTĘP PRZEZ URI: \"HTTP://LOCALHOST/TEST.HTML\".\rI \"TEST.PHP\"? WYSTARCZY UŻYĆ HTTP://LOCALHOST/TEST.PHP\". PROSTYM SKRYPTEM TESTOWYM MOŻE BYĆ:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rNOWY PODKATALOG DLA TWOJEJ STRONY WWW? STWÓRZ NOWY KATALOG (NP. \"NOWY\") WEWNĄTRZ KATALOGU \"\\\\XAMPP\\\\HTDOCS\" (NAJLEPIEJ BEZ ZNAKÓW ODSTĘPÓW I TYLKO UŻYWAJĄC ZNAKÓW ASCII), UTWÓRZ PLIK TESTOWY W TYM KATALOGU I SPRÓBUJ UZYSKAĆ DO NIEGO DOSTĘP PRZEZ URL: \"HTTP://LOCALHOST/NOWY/TEST.PHP\".\rINNE SPECYFIKACJE\rHTML:\rWYKONYWALNY: \\XAMPP\\HTDOCS\rDOZWOLONE ZAKOŃCZENIA: .HTML .HTM\r=> PAKIET PODSTAWOWY\rSSI:\rWYKONYWALNY: \\XAMPP\\HTDOCS\rDOZWOLONE ZAKOŃCZENIA: .SHTML\r=> PAKIET PODSTAWOWY\rCGI:\rWYKONYWALNY: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rDOZWOLONE ZAKOŃCZENIA: .CGI\r=> PAKIET PODSTAWOWY\rPHP:\rWYKONYWALNY: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rDOZWOLONE ZAKOŃCZENIA: .PHP\r=> PAKIET PODSTAWOWY\rPERL:\rWYKONYWALNY: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rDOZWOLONE ZAKOŃCZENIA: .PL\r=> PAKIET PODSTAWOWY\rAPACHE::ASP PERL:\rWYKONYWALNY: \\XAMPP\\HTDOCS\rDOZWOLONE ZAKOŃCZENIA: .ASP\r=> PAKIET PODSTAWOWY\rJSP JAVA:\rWYKONYWALNY: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rDOZWOLONE ZAKOŃCZENIA: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rWYKONYWALNY: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rDOZWOLONE ZAKOŃCZENIA: .HTML (U.A)\r=> TOMCAT ADD-ON\rCZY MOGĘ PRZENIEŚĆ INSTALACJĘ XAMPP?\rTAK. PO PRZENIESIENIU KATALOGU XAMPP, MUSISZ WYKONYWAĆ PLIK SETUP_XAMPP.BAT\". W TYM KROKU ŚCIEŻKI W PLIKACH KONFIGURACYJNYCH ZOSTANĄ ZAKTUALIZOWANE.\rJEŻELI MASZ JAKIŚ SERWER ZAINSTALOWANY JAKO USŁUGĘ WINDOWS, MUSISZ NAJPIERW USUNĄĆ USŁUGĘ, A DOPIERO PO PRZENIESIENIU KATALOGU PONOWNIE ZAINSTALOWAĆ USŁUGĘ.\rOSTRZEŻENIE: PLIKI KONFIGURACJI Z TWOICH WŁASNYCH SKRYPTÓW, TJ. APLIKACJI PHP, NIE SĄ AKTUALIZOWANE. ALE JEST MOŻLIWOŚĆ NAPISANIA \"WTYCZKI\" DLA INSTALATORA. Z TĄ WTYCZKĄ, INSTALATOR MOŻE TEŻ TE PLIKI ZAKTUALIZOWAĆ.\rCO TO SĄ \"AUTOMATYCZNE STRONY STARTOWE\" DLA KATALOGÓW WWW?\rSTANDARDOWA NAZWA PLIKU DLA FUNKCJI APACHE\'A \"DIRECTORYINDEX\" TO \"INDEX.HTML\" LUB \"INDEX.PHP\". ZA KAŻDYM RAZEM KIEDY PRZEGLĄDASZ FOLDER (NP. \"HTTP://LOCALHOST/XAMPP/\"), APACHE SZUKA JEDNEGO Z TYCH PLIKÓW, ZAMIAST WYŚWIETLAĆ LISTĘ PLIKÓW Z KATALOGU.\rGDZIE MOGĘ ZMIENIĆ KONFIGURACJĘ?\rPRAWIE WSZYSTKIE USTAWIENIA W XAMPP MOŻESZ ZMIENIĆ W PLIKACH KONFIGURACYJNYCH. OTWÓRZ PLIK W EDYTORZE PLIKU I ZMIEŃ WYBRANE PRZEZ SIEBIE USTAWIENIE. TYLKO APLIKACJE FILEZILLA I MERCURY POWINNE BYĆ SKONFIGUROWANE WYKORZYSTUJĄC WEWNĘTRZNE NARZĘDZIE DO KONFIGURACJI.\rDLACZEGO XAMPP NIE MOŻE PRACOWAĆ NA WINDOWS XP SP2?\rMICROSOFT DOSTARCZA LEPSZĄ ZAPORĘ SIECIOWĄ Z SERVICE PACK 2 (SP2), KTÓRA URUCHAMIA SIĘ AUTOMATYCZNIE PRZY STARCIE SYSTEMU. TA ZAPORA SIECIOWA BLOKUJE TERAZ POTRZEBNE PORTY 80 (HTTP) I 443 (HTTPS) I APACHE NIE MOŻE SIĘ URUCHOMIĆ.\rSZYBKIE ROZWIĄZANIE:\rWYŁĄCZ ZAPORĘ SIECIOWĄ MICROSOFTU I SPRÓBUJ PONOWNIE URUCHOMIĆ XAMPP. LEPSZYM ROZWIĄZANIEM JEST ZDEFINIOWANIE WYJĄTKÓW W CENTRUM ZABEZPIECZEŃ.\rPONIŻSZE PORTY SĄ UŻYWANE DLA PODSTAWOWEJ FUNKCJONALNOŚCI:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rDLACZEGO XAMPP NIE PRACUJE NA MICROSOFT VISTA?\rKONTROLA KONTA UŻYTKOWNIKA (UAC)\rW KATALOGU \"C:\\\\PROGRAM FILES\" NIE MASZ PEŁNYCH PRAW ZAPISU JAKO ADMINISTRATOR. LUB MASZ OGRANICZONE UPRAWNIENIA (NP. DLA \".\\\\XAMPP\\\\HTDOCS\"). W TYM PRZYPADKU NIE MOŻNA EDYTOWAĆ PLIKU.\rROZWIĄZANIE:\rPODNIEŚĆ SWOJE UPRAWNIENIA W EKSPLORATORZE (PRAWY KLIK / BEZPIECZEŃSTWO) LUB WYŁĄCZ KONTROLĘ KONTA UŻYTKOWNIKA (UAC).\rMASZ ZAINSTALOWANY APACHE/MYSQL W \"C:\\\\XAMPP\" JAKO USŁUGI WINDOWS. ALE NIE URUCHOMIŁEŚ/ZATRZYMAŁEŚ USŁUGI PRZEZ PANEL KONTROLNY XAMPP LUB ICH NIE ODINSTALOWAŁEŚ.\rROZWIĄZANIE:\rUŻYJ KONSOLI ZARZĄDZANIA USŁUGAMI W WINDOWSIE LUB WYŁĄCZ UAC.\rWYŁĄCZANIE KONTROLI KONTA UŻYTKOWNIKA (UAC)\rABY WYŁĄCZYĆ UAC, UŻYJ PROGRAMU \"MSCONFIG\". W \"MSCONFIG\" IDŹ DO \"NARZĘDZIA\", WYBIERZ \"WYŁĄCZ KONTROLĘ KONTA UŻYTKOWNIKA\" I ZWERYFIKUJ SWÓJ WYBÓR. RESTARTUJ WINDOWS. W KAŻDYM CZASIE MOŻESZ PONOWNIE WŁĄCZYĆ UAC.\rJAK MOGĘ SPRAWDZIĆ SUMĘ KONTROLNĄ MD5?\rABY PORÓWNAĆ PLIKI, NAJCZĘŚCIEJ PORÓWNUJE SIĘ ICH SUMY KONTROLNE. DO UTWORZENIA TYCH SUM WYSTARCZY STANDARDOWO MD5 (MESSAGE DIGEST ALGORITHM 5).\rZ SUMĄ KONTROLNĄ MD5 MOŻESZ PRZETESTOWAĆ CZY TWOJA PACZKA XAMPP ZOSTAŁA POBRANA PRAWIDŁOWO CZY TEŻ NIE. OCZYWIŚCIE POTRZEBUJESZ PROGRAMU, KTÓRY UTWORZY TE SUMY KONTROLNE. DLA WINDOWS MOŻESZ UŻYĆ NARZĘDZIA Z MICROSOFTU:\rDOSTĘPNOŚĆ I OPIS NARZĘDZIA INTEGRACJI WERYFIKACJI SUMY KONTROLNEJ PLIKU\rMOŻLIWE JEST RÓWNIEŻ UŻYCIE INNEGO PROGRAMU, KTÓRY POTRAFI UTWORZYĆ SUMĘ KONTROLNĄ MD5, NP. GNU MD5SUM.\rJEŻELI MASZ ZAINSTALOWANY PROGRAM (NP. FCIV.EXE), WYKONAJ PONIŻSZE KROKI:\rPOBIERZ XAMPP (NP. XAMPP-WIN32-1.8.2-0.EXE)\rUTWÓRZ SUMĘ KONTROLNĄ Z:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rI TERAZ MOŻESZ PORÓWNAĆ SWOJĄ SUMĘ KONTROLNĄ Z TĄ ZNALEZIONĄ NA STRONIE XAMPP DLA WINDOWS.\rJEŻELI OBIE SUMY SĄ RÓWNE, WSZYSTKO JEST W PORZĄDKU. JEŻELI NIE, POBRANY PLIK JEST USZKODZONY LUB ZOSTAŁ ZMIENIONY.\rDLACZEGO ZMIANY W PHP.INI NIE PRZYNOSZĄ EFEKTU?\rJEŻELI ZMIANA W \"PHP.INI\" NIE PRZYNOSI EFEKTU, MOŻLIWE ŻE PHP UŻYWA INNEGO PLIKU. MOŻESZ ZWERYFIKOWAĆ TO NA PODSTAWIE FUNKCJI PHPINFO(). IDŹ DO HTTP://LOCALHOST/XAMPP/PHPINFO.PHP I POSZUKAJ \"LOADED CONFIGURATION FILE\". TA WARTOŚĆ POKAZUJE KTÓRY PLIK \"PHP.INI\" JEST PRZEZ PHP UŻYWANY.\rUWAGA:\rPO ZMIANACH W PLIKU \"PHP.INI\" MUSISZ ZRESTARTOWAĆ APACHE, ABY APACHE I PHP WCZYTAŁY NOWE USTAWIENIA.\rPOMOCY! W PAKIECIE XAMPP JEST WIRUS!\rNIEKTÓRE PROGRAMY ANTYWIRUSOWE TRAKTUJĄ XAMPP JAK WIRUS, ZWYKLE WSKAZUJĄC NA PLIK XAMPP-MANAGER.EXE. TO JEST FAŁSZYWE POWIADOMIENIE ZE STRONY PROGRAMU ANTYWIRUSOWEGO, PONIEWAŻ PAKIET XAMPP NIE ZAWIERA WIRUSÓW. PRZED OPUBLIKOWANIEM NOWEJ WERSJI XAMPP, PRZEPUSZCZAMY PAKIET I PLIKI PRZEZ PROGRAM ANTYWIRUSOWY. W TYM MOMENCIE UŻYWAMY \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rJAK MOGĘ SKONFIGUROWAĆ MÓJ PROGRAM ANTYWIRUSOWY?\rWŁĄCZYLIŚMY WSZYSTKIE ZALEŻNOŚCI I SERWERY NIEZBĘDNE DO URUCHOMIENIA APLIKACJI INTERNETOWEJ, WIĘC MOŻNA ZAUWAŻYĆ, ŻE XAMPP INSTALUJE DUŻĄ LICZBĘ PLIKÓW. JEŻELI INSTALUJESZ XAMPP NA WINDOWSIE Z WŁĄCZONYM PROGRAMEM ANTYWIRUSOWYM, TO MOŻE ZNACZNIE SPOWOLNIĆ INSTALACJĘ, I JEST SZANSA, ŻE JEDEN Z SERWERÓW (SERWER WWW, SERWER BAZY DANYCH) MOŻE ZOSTAĆ ZABLOKOWANY PRZEZ PROGRAM ANTYWIRUSOWY. JEŻELI MASZ WŁĄCZONY PROGRAM ANTYWIRUSOWY, SPRAWDŹ NASTĘPUJĄCE USTAWIENIA BY MIEĆ XAMPP DZIAŁAJĄCY BEZ PROBLEMÓW ZWIĄZANYCH Z WYDAJNOŚCIĄ:\rDODAJ WYJĄTKI DO SWOJEJ ZAPORY SIECIOWEJ: DLA APACHE\'A, MYSQL I INNYCH SERWERÓW.\rSKANUJ PLIKI PODCZAS URUCHAMIANIA: JEŚLI WŁĄCZONO SKANOWANIE ANTYWIRUSOWE DLA WSZYSTKICH PLIKÓW, PLIKI WYKONYWALNE SERWERÓW MOGĄ BYĆ SPOWALNIANE.\rSKANUJ RUCH DLA RÓŻNYCH ADRESÓW URL: JEŻELI ROZWIJASZ Z PAKIETEM XAMPP NA SWOIM KOMPUTERZE, MOŻESZ WYKLUCZYĆ RUCH Z \"LOCALHOST\" (HOSTA LOKALNEGO) W USTAWIENIACH PROGRAMU ANTYWIRUSOWEGO.\rDLACZEGO APACHE NIE URUCHAMIA SIĘ W MOIM SYSTEMIE?\rTEN PROBLEM MOŻE WYSTĘPOWAĆ Z KILKU POWODÓW:\rMOŻESZ MIEĆ URUCHOMIONYCH WIĘCEJ NIŻ JEDEN SERWER HTTP (IIS, SAMBAR, ZEUS, LUB INNY). TYLKO JEDEN SERWER MOŻE KORZYSTAĆ Z PORTU 80. TEN KOMUNIKAT O BŁĘDZIE WSKAZUJE PROBLEM:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rJEŻELI MASZ INNE OPROGRAMOWANIE, TJ. TELEFONIĘ INTERNETOWĄ SKYPE, KTÓRA TEŻ BLOKUJE PORT 80. JEŻELI PROBLEM STWARZA SKYPE, W SKYPE Z MENU WYBIERZ AKCJE --> OPCJE --> POŁĄCZENIE --> USUŃ ZNACZEK PRZY OPCJI \"UŻYJ PORTU 80 JAKO PORTU ALTERNATYWNEGO\" I ZRESTARTUJ SKYPE. TERAZ SERWER POWINIEN PRACOWAĆ POPRAWNIE.\rMASZ ZAPORĘ SIECIOWĄ, KTÓRA BLOKUJE PORT APACHE. NIE WSZYSTKIE ZAPORY SIECIOWE SĄ ZGODNE Z APACHE, I CZASAMI DEZAKTYWACJA ZAPORY NIE WYSTARCZA I TRZEBA JĄ USUNĄĆ. TEN KOMUNIKAT O BŁĘDZIE WSKAZUJE ZAPORĘ:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rTAKŻE JEŻELI APACHE MOŻE SIĘ URUCHOMIĆ, ALE TWOJA PRZEGLĄDARKA NIE MOŻE SIĘ POŁĄCZYĆ, TO MOŻE BYĆ SPOWODOWANE PRZEZ:\rNIEKTÓRE SKANERY ANTYWIRUSOWE MOGĄ POWODOWAĆ PROBLEMY W PODOBNY SPOSÓB JAK TO ROBIĄ ZAPORY SIECIOWE.\rMASZ WINDOWS XP PROFESSIONAL BEZ SERVICE PACK 1. MUSISZ MIEĆ PRZYNAJMNIEJ SP1 DLA XAMPP.\rPORADA:\rJEŻELI MASZ PROBLEMY Z UŻYCIEM PORTÓW, MOŻESZ SPRÓBOWAĆ URUCHOMIĆ NARZĘDZIE \"XAMPP-PORTCHECK.EXE\". TO MOŻE POMÓC.\rDLACZEGO MOJE OBCIĄŻENIE DLA APACHE\'A JEST BLISKIE 99%?\rTUTAJ MOŻE WYSTĄPIĆ JEDEN Z DWÓCH SCENARIUSZY. JEŻELI TWÓJ PROCESOR JEST MAKSYMALNIE WYKORZYSTYWANY, LUB TWOJA PRZEGLĄDARKA MOŻE POŁĄCZYĆ SIĘ Z SERWEREM, ALE NIC NIE WIDZISZ (SYSTEM PRÓBUJE NIESKUTECZNIE ZAŁADOWAĆ STRONĘ). W KAŻDYM PRZYPADKU ZNAJDZIESZ PONIŻSZĄ WIADOMOŚĆ W PLIKU ZDARZEŃ APACHE\'A:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rMPM WRACA DO BEZPIECZNEGO WYKONANIA, ALE NIEKTÓRE ŻĄDANIA KLIENTÓW NIE ZOSTAŁY PRZETWORZONE W SPOSÓB PRAWIDŁOWY. ABY UNIKNĄĆ TEGO BŁĘDU, NALEŻY UŻYĆ \"ACCEPTFILTER\" Z AKCEPTACJĄ FILTRA \"NONE\" W PLIKU \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\".\rDLACZEGO ZDJĘCIA I ARKUSZE STYLU NIE SĄ WYŚWIETLANE?\rCZASAMI SĄ PROBLEMY Z WYŚWIETLENIEM OBRAZKÓW I ARKUSZY STYLÓW. ZWŁASZCZA JEŚLI TE PLIKI ZNAJDUJĄ SIĘ NA DYSKU SIECIOWYM. W TYM PRZYPADKU POWINIENEŚ WŁĄCZYĆ (LUB DODAĆ) JEDNĄ Z PONIŻSZYCH LINII W PLIKU \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rTEN PROBLEM MOŻE BYĆ RÓWNIEŻ SPOWODOWANY PRZEZ PROGRAMY DO REGULACJI PRZEPUSTOWOŚCI PASMA, TJ. PROGRAM NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rJAK MOGĘ USTAWIĆ HASŁO ADMINISTRATORA W MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rCZY MOGĘ UŻYĆ SWOJEGO WŁASNEGO SERWERA MYSQL?\rTAK. NAJPROŚCIEJ NIE URUCHAMIAĆ MYSQL Z PAKIETU XAMPP. PROSZĘ ZAUWAŻYĆ, ŻE DWA SERWERY NIE MOGĄ BYĆ URUCHOMIONE NA TYM SAMYM PORCIE. JEŻELI MASZ USTAWIONE HASŁO DLA UŻYTKOWNIKA MYSQL \"ROOT\", PROSZĘ NIE ZAPOMNIEĆ ZAKTUALIZOWAĆ PLIKU \"\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP\".\rJAK MOGĘ OGRANICZYĆ DOSTĘP DO PHPMYADMINA Z ZEWNĄTRZ?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rPRZED TWOIM DOSTĘPEM DO SERWERA MYSQL, PHPMYADMIN ZAPYTA CIĘ O NAZWĘ UŻYTKOWNIKA I HASŁO. NIE ZAPOMNIJ NAJPIERW USTAWIĆ HASŁA DLA UŻYTKOWNIKA \"ROOT\".\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rGDZIE JEST WSPARCIE IMAP DLA PHP?\rDOMYŚLNIE, WSPARCIE IMAP DLA PHP W XAMPP JEST WYŁĄCZONE, ZE WZGLĘDU NA JAKIEŚ TAJEMNICZE BŁĘDY INICJALIZACJI DLA WERSJI DOMOWYCH PODOBNYCH DO WINDOWS 98. JEŻELI PRACUJESZ Z SYSTEMAMI NT, MOŻESZ OTWORZYĆ PLIK \"\\\\XAMPP\\\\PHP\\\\PHP.INI\" I AKTYWOWAĆ ROZSZERZENIE PHP PRZEZ USUNIĘCIE ŚREDNIKA NA POCZĄTKU LINII \";EXTENSION=PHP_IMAP.DLL\". TO POWINNO BYĆ:\rEXTENSION=PHP_IMAP.DLL\rTERAZ ZRESTARTUJ APACHE\'A I IMAP POWINIEN JUŻ PRACOWAĆ. MOŻESZ UŻYĆ TYCH SAMYCH KROKÓW DLA KAŻDEGO ROZSZERZENIA, KTÓRY NIE JEST DOMYŚLNIE WŁĄCZONY W KONFIGURACJI.\rDLACZEGO NIEKTÓRE APLIKACJE PHP O OTWARTYM KODZE ŹRÓDŁOWYM NIE PRACUJĄ Z XAMPP NA WINDOWSIE?\rWIELE APLIKACJI PHP LUB ROZSZERZEŃ, KTÓRE POWSTAŁY NA SYSTEM LINUX, NIE ZOSTAŁO PRZEPISANYCH NA WINDOWSA. \rCZY MOGĘ USUNĄĆ KATALOG \"INSTALL\" PO INSTALACJI?\rLEPIEJ NIE. SKRYPTY TUTAJ SĄ WCIĄŻ POTRZEBNE DLA WSZYSTKICH PAKIETÓW DODATKOWYCH (DODATKÓW) I AKTUALIZACJI XAMPP.\rJAK MOGĘ AKTYWOWAĆ EACCELERATOR?\rPODOBNIE JAK W INNYCH (ZEND) ROZSZERZENIACH, MUSISZ AKTYWOWAĆ TO W PLIKU PHP.INI. W TYM PLIKU WŁĄCZ LINIĘ \";ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"\". TO POWINNO WYGLĄDAĆ:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rJAK MOGĘ NAPRAWIĆ BŁĘDY POŁĄCZENIA DO MOJEGO SERWERA MS SQL?\rJEŻELI ROZSZERZENIE MSSQL ZOSTAŁO ZAŁADOWANE W PLIKU PHP.INI, CZASAMI PROBLEMY WYSTĘPUJĄ KIEDY TYLKO TCP/IP JEST UŻYWANY. MOŻESZ NAPRAWIĆ TEN PROBLEM Z NOWĄ WERSJĄ \"NTWDBLIB.DLL\" ZE STRONY MICROSOFTU. ZASTĄP TYM NOWSZYM PLIKIEM, PLIKAMI ZNAJDUJĄCYMI SIĘ W \"\\\\XAMPP\\\\APACHE\\\\BIN\" I \"\\\\XAMPP\\\\PHP\". ZE WZGLĘDU NA LICENCJĘ TEGO PLIKU, NIE MOŻEMY SPAKOWAĆ JEGO NOWSZĄ WERSJĘ Z PAKIETEM XAMPP.\rJAK MOGĘ PRACOWAĆ Z ROZSZERZENIEM PHP MCRYPT?\rDLA NIEGO OTWORZYLIŚMY TEMAT NA FORUM Z PRZYKŁADAMI I MOŻLIWYMI ROZWIĄZANIAMI: \rTEMAT MCRYPT\rCZY MICROSOFT ACTIVE SERVER PAGES (ASP) PRACUJE Z XAMPP?\rNIE. APACHE::ASP Z DODATKIEM PERL TO NIE TO SAMO. APACHE::ASP ZNA TYLKO SKRYPTY PERL, ALE ASP Z INTERNET INFORMATION SERVER (IIS) ZNA TAKŻE NORMALNY JĘZYK VBSCRIPT. ALE DLA ASP .NET SĄ DOSTĘPNE MODUŁY APACHE FIRM TRZECICH.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rPRAWA ZASTRZEŻONE (C) 2022, APACHE FRIENDS\rBLOG\rPOLITYKA PRYWATNOŚCI\rCDN DOSTARCZONE PRZEZ\r\n'),(67,'83885140c160c80b0c7ddde38ea036a6','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rNAJCZĘŚCIEJ ZADAWANE PYTANIA\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rPRAWA ZASTRZEŻONE (C) 2022, APACHE FRIENDS\rBLOG\rPOLITYKA PRYWATNOŚCI\rCDN DOSTARCZONE PRZEZ\r\n'),(68,'d7a0056d4f0339601d0407d36b18ac8a','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rNAJCZĘŚCIEJ ZADAWANE PYTANIA\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rPRAWA ZASTRZEŻONE (C) 2022, APACHE FRIENDS\rBLOG\rPOLITYKA PRYWATNOŚCI\rCDN DOSTARCZONE PRZEZ\r\n'),(69,'3e4ee9ccad490c95c7cfab28173fe72c','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rNAJCZĘŚCIEJ ZADAWANE PYTANIA\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rPRAWA ZASTRZEŻONE (C) 2022, APACHE FRIENDS\rBLOG\rPOLITYKA PRYWATNOŚCI\rCDN DOSTARCZONE PRZEZ\r\n'),(70,'2c4d9466975b7d41aec7913d071ff7ee','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rNAJCZĘŚCIEJ ZADAWANE PYTANIA\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rNAJCZĘŚCIEJ ZADAWANE PYTANIA\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nSPOŁECZNOŚĆ\rXAMPP MA JUŻ PONAD 10 LAT  I POSIADA OGROMNĄ SPOŁECZNOŚĆ. MOŻESZ ZAANGAŻOWAĆ SIĘ PRZEZ DOŁĄCZENIE SIĘ DO NASZEGO \rFORA DYSKUSYJNE\r, I POLUBIAJĄC NAS NA \rFACEBOOK\rLUB PRZEGLĄDAJĄC NASZE WYCZYNY NA \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rPRAWA ZASTRZEŻONE (C) 2022, APACHE FRIENDS\rBLOG\rPOLITYKA PRYWATNOŚCI\rCDN DOSTARCZONE PRZEZ\r\n'),(71,'150bc2ac6e56354eb615659c2053f0fe','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rPERGUNTAS FREQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rPERGUNTAS MAIS FREQUENTES\rCOMO INSTALO O XAMPP?\rO XAMPP PARA WINDOWS EXISTE EM TRÊS DIFERENTES MODALIDADES:\rINSTALADOR:\rPROVAVELMENTE O JEITO MAIS FÁCIL DE INSTALAR XAMPP.\rZIP:\rPARA OS PURISTAS: XAMPP COMO UM ARQUIVO ZIP COMUM.\r7ZIP:\rPARA OS PURISTAS COM POUCA LARGURA DE BANDA: XAMPP COMO UM ARQUIVO 7ZIP.\rNOTA: SE VOCÊ DESCOMPACTAR OS ARQUIVOS, PODE SER QUE RECEBA AVISOS FALSO-POSITIVOS DE VÍRUS.\rEXECUTANDO O INSTALADOR\rPAINEL DE CONTROLE DO XAMPP PARA NICIAR/PARAR O APACHE, MYSQL, FILEZILLA E MERCURY OU INSTALAR ESSES SERVIDORES COMO SERVIÇOS.\rINSTALANDO A PARTIR DE ZIP\rDESCOMPACTE OS ARQUIVOS ZIP PARA A PASTA DE SUA ESCOLHA. EXTRAIA O XAMPP PARA O SUBDIRETÓRIO \"C:\\\\XAMPP\", ABAIXO DO DIRETÓRIO DE DESTINO SELECIONADO. AGORA INICIE O ARQUIVO \"SETUP_XAMPP.BAT\", PARA AJUSTAR A CONFIGURAÇÃO DO XAMPP PARA SEU SISTEMA.\rSE VOCÊ ESCOLHER UM DIRETÓRIO RAIZ \"C:\\\\\" COMO ALVO, VOCÊ NÃO DEVE COMEÇAR O \"SETUP_XAMPP.BAT\".\rDA MESMA FORMA QUE A VERSÃO DO INSTALADOR, AGORA VOCÊ PODE USAR O \"PAINEL DE CONTROLE\" DO XAMPP PARA TAREFAS ADICIONAIS.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rCOMO POSSO INICIALIZAR O XAMPP SEM INSTALAÇÃO?\rSE VOCÊ EXTRAIR O XAMPP EM UMA PASTA NA RAIZ DE QUALQUER UNIDADE, COMO \"C:\\\\\" OU \"D:\\\\\", POR EXEMPLO, VOCÊ PODE EXECUTAR A MAIORIA DOS SERVIDORES COMO APACHE OU MYSQL DIRETAMENTE SEM ANTES TER DE EXECUTAR O ARQUIVO \"SETUP_XAMPP.BAT\".\rCASO ESTEJA INSTALANDO O XAMPP EM UM DRIVE USB, É PREFERÍVEL QUE VOCÊ NÃO USE O SCRIPT DE INSTALAÇÃO E SE MESMO ASSIM QUISER USÁ-LO, SELECIONE CAMINHOS RELATIVOS NO SCRIPT DE INSTALAÇÃO. ISTO, PORQUE PARA CADA PC O MESMO DRIVE PODE TER UMA OUTRA LETRA DE UNIDADE, DIFERENTE DAQUELA ESPECIFICADA NO CAMINHO ABSOLUTO. VOCÊ PODERÁ TROCAR OS CAMINHOS DE RELATIVO PARA ABSOLUTO A QUALQUER MOMENTO COM O SCRIPT DE INSTALAÇÃO.\rA MANEIRA MAIS FÁCIL DE INSTALAR O XAMPP É USAR O INSTALADOR DE NOSSA PÁGINA DE DOWNLOADS. AO COMPLETAR A INSTALAÇÃO, VOCÊ ENCONTRARÁ O XAMPP EM INICIAR > PROGRAMAS > XAMPP. VOCÊ PODE USAR O PAINEL DE CONTROLE DO XAMPP PARA INICIALIZAR/INTERROMPER TODOS OS SERVIDORES E TAMBÉM PARA INSTALAR/DESINSTALAR OS SERVIDORES COMO SERVIÇOS DO SISTEMA.\rPAINEL DE CONTROLE DO XAMPP PARA NICIAR/PARAR O APACHE, MYSQL, FILEZILLA E MERCURY OU INSTALAR ESSES SERVIDORES COMO SERVIÇOS.\rCOMO INICIO E PARO O XAMPP?\rO CENTRO DE CONTROLE UNIVERSAL É O \"PAINEL DE CONTROLE XAMPP\" (OBRIGADO WWW.NAT32.COM). ELE É INICIADO COM:\r\\XAMPP\\XAMPP-CONTROL.EXE\rVOCÊ PODE AINDA USAR ALGUNS BATCHFILES PARA INICIAR/PARAR OS SERVIDORES:\rINICIAR MYSQL E APACHE:\n\\XAMPP\\XAMPP_START.EXE\rPARAR MYSQL E APACHE:\n\\XAMPP\\XAMPP_STOP.EXE\rINICIAR APACHE:\n\\XAMPP\\APACHE_START.BAT\rPARAR O APACHE:\n\\XAMPP\\APACHE_STOP.BAT\rINICIAR O MYSQL:\n\\XAMPP\\MYSQL_START.BAT\rPARAR O MYSQL:\n\\XAMPP\\MYSQL_STOP.BAT\rINICIALIZAR O MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_START.BAT\rPARAR MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_STOP.BAT\rINICIAR FILEZILLA:\n\\XAMPP\\FILEZILLA_START.BAT\rPARAR FILEZILLA:\n\\XAMPP\\FILEZILLA_STOP.BAT\rCOMO POSSO TESTAR SE TUDO FUNCIONOU CORRETAMENTE?\rESCREVA O SEGUINTE URL NO SEU NAVEGADOR FAVORITO:\rHTTP://LOCALHOST/\rOU \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rCOMO POSSO INSTALAR UM SERVIDOR COMO UM SERVIÇO?\rCADA SERVIDOR NO XAMPP PODE TAMBÉM SER INSTALADO COMO UM SERVIÇO DO WINDOWS. VOCÊ PODE, AINDA, INSTALA-LOS PELO PAINEL DE CONTROLE DO XAMPP. NESSE CASO, É NECESSÁRIO RODAR OS SCRIPTS OU O PAINEL DE CONTROLE COM PRIVILÉGIOS DE ADMINSTRADOR.\rINSTALAÇÃO DO SERVIÇO DO APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rDESINSTALAÇÃO DO SERVIÇO DO APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rINSTALAÇÃO DO SERVIÇO DO MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rDESINSTALAR O MYSQL COMO UM SERVIÇO DO SISTEMA: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \rINSTALAR/DESINSTALAR O FILEZILLA COMO UM SERVIÇO DO SISTEMA: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: INSTALAÇÃO COMO UM SERVIÇO DO SISTEMA INDISPONÍVEL\rXAMPP ESTÁ PRONTO PARA PRODUÇÃO?\rXAMPP NÃO É DESTINADO PARA USO EM PRODUÇÃO, MAS APENAS PARA AMBIENTES DE DESENVOLVIMENTO. O XAMPP É CONFIGURADO PARA SER O MAIS ABERTO POSSÍVEL PARA PERMITIR AO DESENVOLVEDOR QUALQUER COISA QUE ELE/ELA QUISER. PARA AMBIENTES DE DESENVOLVIMENTO ELE É ÓTIMO, MAS EM UM AMBIENTE DE PRODUÇÃO , ELE PODE SER FATAL. \rAQUI UMA LISTA DE SEGURANÇA QUE FALTAVA NO XAMPP:\rO ADMINISTRADOR (ROOT) DO MYSQL NÃO TEM SENHA.\rO DAEMON DO MYSQL ESTÁ ACESSÍVEL PELA REDE. \rPROFTPD USA A SENHA \"LAMPP\" PARA O USUÁRIO \"DAEMON\".\rOS USUÁRIOS PADRÃO DO MERCURY E FILEZILLA SÃO CONHECIDOS.\rTODOS OS PONTOS PODEM SER UM GRANDE RISCO DE SEGURANÇA. ESPECIALMENTE SE O XAMPP ESTÁ ACESSÍVEL VIA REDE E PESSOAS FORA DA SUA LAN. TAMBÉM PODE AJUDAR A USAR UM FIREWALL OU UM ROTEADOR (NAT). NO CASO DE UM ROTEADOR OU FIREWALL, SEU PC NORMALMENTE NÃO É ACESSÍVEL VIA REDE. É ATÉ VOCÊ PARA CORRIGIR ESSES PROBLEMAS. COMO UMA PEQUENA AJUDA,EM \"XAMPP SECURITY CONSOLE\".\rPOR FAVOR, PROTEJA O XAMPP ANTES DE PUBLICAR QUALQUER COISA ON-LINE. UM FIREWALL OU UM ROTEADOR EXTERNO SÃO APENAS SUFICIENTES PARA BAIXOS NÍVEIS DE SEGURANÇA. PARA UM POUCO MAIS DE SEGURANÇA, VOCÊ PODE EXECUTAR O \"XAMPP SECURITY CONSOLE\" E ATRIBUIR SENHAS.\rSE VOCÊ QUISER TER O SEU XAMPP ACESSÍVEL A PARTIR DA INTERNET, VOCÊ DEVE IR PARA O SEGUINTE URI QUE PODE CORRIGIR ALGUNS PROBLEMAS:\rHTTP://LOCALHOST/SECURITY/\rCOM O CONSOLE DE SEGURANÇA, VOCÊ PODE DEFINIR UMA SENHA PARA O USUÁRIO MYSQL \"ROOT\" E PHPMYADMIN. VOCÊ TAMBÉM PODE ATIVAR A AUTENTICAÇÃO PARA O DEMOPAGES DO XAMPP.\rESSA FERRAMENTA BASEADA EM WEB NÃO CORRIGE NENHUM PROBLEMA ADICIONAL DE SEGURANÇA! O SERVIDOR FILEZILLA FTP E O SERVIDOR DE MENSAGENS MERCURY DEVEM, ESPECIALMENTE, SEREM PROTEGIDOS POR VOCÊ.\rCOMO DESINSTALO O XAMPP?\rSE VOCÊ INSTALOU A VERSÃO DO XAMPP COM INSTALADOR, POR FAVOR USE O DESINSTALADOR. O DESINSTALADOR IRÁ APAGAR TODAS AS ENTRADAS DO XAMPP DOS SEUS REGISTROS E IRÁ DESINSTALAR ALGUNS SERVIÇOS INCLUÍDOS COM O XAMPP. NÓS RECOMENDAMOS QUE VOCÊ UTILIZE O PROGRAMA DESINSTALADOR PARA REMOVER AS INSTALAÇÕES DE XAMPP FEITAS PELO INSTALADOR. POR FAVOR, FAÇA UMA CÓPIA DE SEGURANÇA DE TODA A INFORMAÇÃO QUE VOCÊ DESEJA MANTER ANTES DE DESINSTALAR O XAMPP.\rSE VOCÊ INSTALOU O XAMPP USANDO AS VERSÕES EM ZIP OU 7ZIP, DESLIGUE TODOS OS SERVIDORES XAMPP E SAIA DE TODOS OS PAINÉIS. SE VOCÊ INSTALOU ALGUM SERVIÇO, DESINSTALE-OS E DESLIGUE-OS TAMBÉM. AGORA, SIMPLESMENTE APAGUE TODO A PASTA ONDE O XAMPP ESTÁ INSTALADO. NÃO HÁ ENTRADAS DE REGISTRO OU VARIÁVEIS DE AMBIENTE PARA LIMPAR.\rO QUE É A VERSÃO \"LITE\"DE XAMPP?\rXAMPP LITE (SIGNIFICA \"LEVE\"COMO EM \"PESO-LEVE\") É UM PACOTE MENOR DE COMPONENTES DO XAMPP QUE É RECOMENDADO PARA TRABALHOS RÁPIDOS QUE USEM SOMENTE PHP E MYSQL. ALGUNS SERVIDORES E FERRAMENTAS, TAIS COMO O MERCURY MAIL E O FILEZILLA FTP, NÃO ESTÃO PRESENTES DA VERSÃO LITE.\rONDE DEVO COLOCAR MEU CONTEÚDO WEB?\rO DIRETÓRIO PRINCIPAL PARA TODOS OS DOCUMENTOS WWW É \\\\XAMPP\\\\HTDOCS. SE VOCÊ COLOCAR UM ARQUIVO \"TEST.HTML\"NESTE DIRETÓRIO, VOCÊ PODERÁ ACESSA-LO COM A URI \"HTTP://LOCALHOST/TEST.HTML\".\rE \"TEST.PHP\"? APENAS USE \"HTTP://LOCALHOST/TEST.PHP\". UM SCRIPT DE TESTE SIMPLES PODE SER:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rUM NOVO SUBDIRETÓRIO PARA SEU WEB? BASTA FAZER UM NOVO DIRETÓRIO (POR EXEMPLO, \"NOVO\") DENTRO DO DIRETÓRIO \"\\\\XAMPP\\\\HTDOCS\" (MELHOR SEM OS ESPAÇOS EM BRANCO E APENAS ASCII), CRIAR UM ARQUIVO DE TESTE NESTE DIRETÓRIO E ACESSÁ-LO COM \"QUE HTTP://LOCALHOST/NEW/TEST.PHP\".\rMAIS DETALHES\rHTML:\rEXECUTÁVEL: \\XAMPP\\HTDOCS\rFINAIS PERMITIDOS: .HTML .HTM\r=> PACOTE BÁSICO\rSSI:\rEXECUTÁVEL: \\XAMPP\\HTDOCS\rFINAIS PERMITIDOS: .SHTML\r=> PACOTE BÁSICO\rCGI:\rEXECUTÁVEL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rFINAIS PERMITIDOS: .CGI\r=> PACOTE BÁSICO\rPHP:\rEXECUTÁVEL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rFINAIS PERMITIDOS: .PHP\r=> PACOTE BÁSICO\rPERL:\rEXECUTÁVEL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rFINAIS PERMITIDOS: .PL\r=> PACOTE BÁSICO\rAPACHE::ASP PERL:\rEXECUTÁVEL: \\XAMPP\\HTDOCS\rFINAIS PERMITIDOS: .ASP\r=> PACOTE BÁSICO\rJSP JAVA:\rEXECUTÁVEL: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rFINAIS PERMITIDOS: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rEXECUTÁVEL: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rFINAIS PERMITIDOS: .HTML (U.A)\r=> TOMCAT ADD-ON\rPOSSO MOVER A INSTALAÇÃO DO XAMPP?\rSIM. DEPOIS DE SE MUDAR DO DIRETÓRIO XAMPP, VOCÊ DEVE EXECUTAR \"SETUP_XAMPP.BAT\". OS CAMINHOS NOS ARQUIVOS DE CONFIGURAÇÃO SERÁ AJUSTADO COM ESTE PASSO.\rSE VOCÊ TIVER INSTALADO QUALQUER SERVIDOR COMO UM SERVIÇO DO WINDOWS, VOCÊ DEVE PRIMEIRO REMOVER O SERVIÇO DO WINDOWS, E DEPOIS DE MOVER VOCÊ PODE INSTALAR O SERVIÇO NOVAMENTE.\rAVISO: OS ARQUIVOS DE CONFIGURAÇÃO DOS TEUS PRÓPRIOS SCRIPTS, COMO APLICATIVOS PHP, NÃO ESTÃO AJUSTADOS. MAS É POSSÍVEL ESCREVER UM \"PLUG-IN\"PARA O INSTALADOR. COMO ESSE PLUG-IN O INSTALADOR PODE AJUSTAR ESSES ARQUIVOS TAMBÉM.\rQUAIS SÃO AS \"PAGINAS INICIAIS AUTOMÁTICAS\"PARA OS DIRETÓRIOS WWW?\rO NOME DE ARQUIVO PADRÃO PARA A FUNÇÃO DO APACHE \"DIRECTORYINDEX\" É \"INDEX. HTML\" OU \"INDEX. PHP\". TODA VEZ QUE VOCÊ ESTÁ APENAS NAVEGANDO PARA UMA PASTA (\"HTTP://LOCALHOST/XAMPP/\", POR EXEMPLO), E APACHE PODE ENCONTRAR TAL ARQUIVO, O APACHE ESTÁ EXIBINDO ESTE ARQUIVO EM VEZ DE UMA LISTAGEM DE DIRETÓRIO.\rONDE POSSO ALTERAR A CONFIGURAÇÃO?\rQUASE TODAS AS CONFIGURAÇÕES DO XAMPP, VOCÊ PODE ALTERAR COM ARQUIVOS DE CONFIGURAÇÃO. BASTA ABRIR O ARQUIVO EM UM EDITOR DE TEXTO E ALTERAR A CONFIGURAÇÃO QUE VOCÊ QUER. SÓ O FILEZILLA E O MERCÚRIO DEVEM SER CONFIGURADO COM A FERRAMENTA DE CONFIGURAÇÃO DO APLICATIVO.\rPORQUE O XAMPP NÃO FUNCIONA NO WINDOWS XP SP2?\rA MICROSOFT OFERECE UM MELHOR FIREWALL COM SERVICE PACK 2 (SP2), QUE INICIA AUTOMATICAMENTE. ESTE FIREWALL AGORA BLOQUEIA AS PORTAS NECESSÁRIAS 80 (HTTP) E 443 (HTTPS) E APACHE NÃO PODE INICIAR.\rA SOLUÇÃO RÁPIDA:\rDISABILITE O FIREWALL DA MICROSOFT PELO BARRA DE FERRAMENTAS E INICIE O XAMPP OUTRA VEZ. COM ESTA SOLUÇÃO SERÁ DEFINIDO UMA EXCESSÃO NO CENTRO DE SEGURANÇA.\rAS SEGUINTES PORTAS SÃO USADAS PARA A FUNCIONALIDADE BÁSICA:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rPOR QUE O XAMPP NÃO FUNCIONA NO WINDOWS VISTA?\rCONTROLE DE CONTA DE USUÁRIO\rNO DIRETÓRIO \"C:\\\\PROGRAM FILES\" VOCÊ NÃO TEM PLENOS PRIVILÉGIOS DE ESCRITA, MESMO COMO ADMINISTRADOR. OU TEM APENAS PRIVILÉGIOS LIMITADOS (E.G. FOR \".\\\\XAMPP\\\\HTDOCS\"). NESTE CASO VOCÊ NÃO PODE EDITAR UM ARQUIVO.\rSOLUÇÃO:\rELEVE SEUS PRIVILÉGIOS NO EXPLORER (BOTÃO DIREITO DO MOUSE / SEGURANÇA) OU DESABILITE O CONTROLE DE CONTA DE USUÁRIO (UAC).\rVOCÊ INSTALOU O APACHE/MYSQL EM \"C:\\\\XAMPP\" COMO UM SERVIÇO DO SISTEMA MAS NÃO CONSEGUE INICIALIZAR/INTERROMPER OS SERVIÇOS COM O \"PAINEL DE CONTROLE DO XAMPP\" OU NÃO CONSEGUE DESINSTALÁ-LOS.\rSOLUÇÃO:\rUSE O CONSOLE DE GERENCIAMENTO DE SERVIÇO DO WINDOWS OU DESABILITE O CONTROLE DE CONTA DE USUÁRIO.\rDESABILITANDO O CONTROLE DE CONTA DE USUÁRIO (UAC)\rPARA DESABILITAR O CONTROLE DE CONTA DE USUÁRIO, USE O PROGRAMA \"MSCONFIG\" (TECLA WINDOWS + R, DIGITE \"MSCONFIG\" E CLIQUE EM \"OK\". NO \"MSCONFIG\" VÁ PARA \"FERRAMENTAS\", SELECIONE \"ALTERAR CONFIGURAÇÕES DE UAC\", CLIQUE EM \"INICIAR\", ARRASTE O INDICADOR PARA \"NUNCA NOTIFICAR\", CLIQUE EM \"OK\" E REINICIE O WINDOWS. AO MESMO TEMPO, VOCÊ PODE HABILITAR O UAC NOVAMENTE.\rCOMO FAÇO PARA VERIFICAR A SOMA DE VERIFICAÇÃO MD5?\rMUITAS VEZES, AS SOMAS DE VERIFICAÇÃO SÃO USADAS PARA COMPARAR ARQUIVOS. UM PADRÃO PARA CRIAR ESTA SOMA DE VERIFICAÇÃO MD5 (MESSAGE DIGEST ALGORITHM 5).\rCOM ESTA SOMA DE VERIFICAÇÃO MD5 VOCÊ PODE TESTAR SE O SEU DOWNLOAD DO XAMPP ESTÁ CORRETO OU NÃO, PORÉM, VOCÊ PRECISARÁ DE UM PROGRAMA ESPECIFICO CAPAZ DE CRIAR ESTAS SOMAS DE VERIFICAÇÃO. PARA O WINDOWS, VOCÊ PODE USAR ESTA FERRAMENTA DA MICROSOFT:\rDISPONIBILIDADE E DESCRIÇÃO DO UTILITÁRIO DE VERIFICAÇÃO DE INTEGRIDADE DE CHECKSUM DE ARQUIVOS\rTAMBÉM É POSSÍVEL UTILIZAR OUTROS PROGRAMAS CAPAZES DE CRIAR SOMAS DE VERIFICAÇÃO MD5, COMO POR EXEMPLO, O GNU MD5SUM.\rCOMO INSTALAR UM PROGRAMA (POR EXEMPLO, FCIV.EXE), VOCÊ PODE FAZER AS SEGUINTES ETAPAS:\rFAÇA O DOWNLOAD DO XAMPP (F.E. XAMPP-WIN32-1.8.2-0.EXE)\rCRIE A SOMA DE VERIFICAÇÃO COM:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rE AGORA VOCÊ PODE COMPARAR ESTA SOMA DE VERIFICAÇÃO COM AQUELE QUE VOCÊ PODE ENCONTRAR NA HOMEPAGE DO XAMPP PARA WINDOWS.\rSE AMBAS AS SOMAS DE VERIFICAÇÃO FOREM IGUAIS, TUDO OK. SE NÃO, O DOWNLOAD ESTÁ QUEBRADO OU O ARQUIVO FOI ALTERADO.\rPOR QUE AS MUDANÇAS NO MEU PHP.INI NÃO FIZERAM EFEITO?\rSE UMA MUDANÇA NO \"PHP. INI\" NÃO TEM NENHUM EFEITO, É POSSÍVEL QUE O PHP ESTEJA USANDO UM DIFERENTE. VOCÊ PODE VERIFICAR ISSO COM PHPINFO ().VÁ PARA O URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP E PROCURE POR \"LOADED CONFIGURATION FILE\". ESTE VALOR MOSTRA O \"PHP.INI\" PHP É REALMENTE USANDO.\rNOTA:\rDEPOIS DE ALTERAR O \"PHP.INI\" VOCÊ TEM QUE REINICIAR O APACHE PARA QUE O APACHE / PHP POSSA LER AS NOVAS CONFIGURAÇÕES.\rSOCORRO! EXISTE UM VÍRUS NO XAMPP!\rALGUNS PROGRAMAS ANTIVÍRUS PODE FAZER OCORRER ALGUM ERRO NO XAMPP SINALIZANDO ALGUM VÍRUS, GERALMENTE SINALIZAM O ARQUIVO XAMPP-MANAGER.EXE ESTE REPRESENTA UM FALSO POSITIVO QUE O ANTIVÍRUS ERRONEAMENTE IDENTIFICA COMO UM VÍRUS, QUANDO NÃO É. ANTES DE LIBERAR CADA NOVA VERSÃO DO XAMPP O EXECUTAMOS ATRAVÉS DE UM SOFTWARE DE DETECÇÃO DE VÍRUS. NO MOMENTO ESTAMOS USANDO \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rCOMO FAÇO PARA CONFIGURAR O MEU APLICATIVO DE ANTIVÍRUS?\rINCLUÍMOS TODAS AS DEPENDÊNCIAS E SERVIDORES NECESSÁRIOS PARA EXECUTAR O APLICATIVO WEB EMPACOTADO, ENTÃO VOCÊ VAI ACHAR QUE O XAMPP INSTALA UM GRANDE NÚMERO DE ARQUIVOS. SE VOCÊ ESTIVER INSTALANDO UM APLICATIVO XAMPP EM UMA MÁQUINA WINDOWS COM UM APLICATIVO DE ANTIVÍRUS ATIVADO, ISSO PODE RETARDAR A INSTALAÇÃO DE FORMA SIGNIFICATIVA, E TAMBÉM HÁ UMA CHANCE DE QUE UM DOS SERVIDORES (SERVIDOR WEB E/OU SERVIDOR DE BANCO DE DADOS) POSSAM SER BLOQUEADOS PELO APLICATIVO DE ANTIVÍRUS . SE VOCÊ TIVER UMA FERRAMENTA DE ANTIVÍRUS ATIVADO, VERIFIQUE AS SEGUINTES CONFIGURAÇÕES PARA A EXECUÇÃO DO XAMPP SEM PROBLEMAS DE DESEMPENHO:\rADICIONAR EXCEÇÕES NO FIREWALL: PARA O APACHE, MYSQL OU QUALQUER OUTRO SERVIDOR.\rAO EXECUTAR A VARREDURA DE ARQUIVOS: SE VOCÊ TIVER ATIVADO A VERIFICAÇÃO ANTIVÍRUS PARA TODOS OS ARQUIVOS, OS ARQUIVOS EXECUTÁVEIS PARA OS SERVIDORES PODEM FICAR LENTOS.\rVERIFIQUE O TRÁFEGO PARA URLS DIFERENTES: SE VOCÊ ESTIVER DESENVOLVENDO COM O XAMPP EM SEU PRÓPRIO COMPUTADOR, VOCÊ PODE EXCLUIR O TRÁFEGO DE \"LOCALHOST\" NAS CONFIGURAÇÕES DO SEU ANTIVÍRUS.\rPOR QUE O SERVIDOR APACHE NÃO INICIALIZA NO MEU SISTEMA?\rESTE PROBLEMA PODE SER UMA DE VÁRIAS RAZÕES:\rVOCÊ INICIALIZOU MAIS DE UM SERVIDOR HTTP (IIS, SAMBAR, ZEUS E ASSIM POR DIANTE). SOMENTE UM SERVIDOR PODE USAR A PORTA 80. ESTA MENSAGEM DE ERRO INDICA O PROBLEMA:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rVOCÊ TEM UM OUTRO PROGRAMA, COMO POR EXEMPLO O \"SKYPE\", QUE TAMBÉM BLOQUEIA A PORTA 80. SE O PROBLEMA FOR O SKYPE, VOCÊ PODE, NO SKYPE, IR PARA AÇÕES --> OPÇÕES --> CONEXÃO --> DESMARQUE \"USAR PORTA 80 PARA UMA PORTA ALTERNATIVA\" E REINICIE O SKYPE. AGORA DEVE FUNCIONAR.\rVOCÊ TEM UM FIREWALL QUE BLOQUEIA A PORTA DO APACHE. NEM TODOS OS FIREWALLS SÃO COMPATÍVEIS COM O APACHE, E AS VEZES APENAS DESATIVÁ-LO NÃO SERÁ O SUFICIENTE E VOCÊ TERÁ DE DESINSTALÁ-LO. ESTA MENSAGEM DE ERRO INDICA O FIREWALL:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rALÉM DISSO, SE O APACHE CONSEGUE INICIALIZAR, MAS O SEU NAVEGADOR NÃO CONSEGUE SE CONECTAR A ELE, PODE SER DEVIDO A UM DOS SEGUINTES FATORES:\rALGUNS RASTREADORES DE VÍRUS PODEM CAUSAR ISTO DA MESMA MANEIRA QUE OS FIREWALLS PODEM INTERFERIR.\rVOCÊ TEM UMA CÓPIA DO WINDOWS XP PROFISSIONAL SEM O SERVICE PACK 1 INSTALADO. VOCÊ PRECISA TER, NO MÍNIMO, O SERVICE PACK 1 INSTALADO PARA O FUNCIONAMENTO DO XAMPP.\rDICA:\rSE VOCÊ TEM PROPLEMAS COM AS PORTAS USADAS, VOCÊ PODE TENTAR A FERRAMENTA \"XAMPP-PORTCHECK.EXE\". TALVEZ ISTO POSSA AJUDAR.\rPORQUE É QUE A MINHA CARGA DE CPU PARA O APACHE ESTA QUASE 99%?\rHÁ UM DOS DOIS CENÁRIOS EM JOGO AQUI. SUA CPU É ESTOURAR O LIMITE, OU VOCÊ PODE NAVEGADOR CONECTAR AO SERVIDOR, MAS NÃO VEJO NADA (O SISTEMA ESTÁ TENTANDO INSATISFATORIAMENTE CARREGAR A PÁGINA). EM AMBOS OS CASOS VOCÊ PODE ENCONTRAR A SEGUINTE MENSAGEM NO APACHE ARQUIVO DE LOG:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rO MPM CAI DE VOLTA PARA UMA IMPLEMENTAÇÃO MAIS SEGURA, MAS ALGUMAS SOLICITAÇÕES DE CLIENTES NÃO FORAM PROCESSADAS CORRETAMENTE. PARA EVITAR ESSE ERRO, USE\"ACCEPTFILTER\" COM FILTRO DE ACEITAÇÃO \"NONE\" NO ARQUIVO \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\" .\rPOR QUE IMAGENS E FOLHAS DE ESTILO NÃO SÃO EXIBIDOS?\rÀS VEZES, HÁ PROBLEMAS COM A EXIBIÇÃO DE IMAGENS E FOLHAS DE ESTILO. ESPECIALMENTE SE ESSES ARQUIVOS ESTÃO LOCALIZADOS EM UMA UNIDADE DE REDE. NESTE CASO, VOCÊ PODE ATIVAR (OU ADICIONAR) UMA SE AS SEGUINTES LINHAS NO ARQUIVO \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rESTE PROBLEMA TAMBÉM PODE SER CAUSADA POR PROGRAMAS DE REGULAÇÃO DA LARGURA DE BANDA, COMO NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rCOMO POSSO DEFINIR UMA SENHA DE ROOT NO MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rPOSSO USAR O MEU PRÓPRIO SERVIDOR MYSQL?\rSIM. SIMPLESMENTE NÃO INICIAR O MYSQL DO PACOTE XAMPP. POR FAVOR, NOTE QUE OS DOIS SERVIDORES NÃO PODEM SER INICIADOS NA MESMA PORTA. SE VOCÊ TIVER DEFINIDO UMA SENHA PARA O \"ROOT\", POR FAVOR NÃO SE ESQUEÇA DE EDITAR O ARQUIVO \"\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP\".\rCOMO FAÇO PARA RESTRINGIR O ACESSO AO PHPMYADMIN DO LADO DE FORA?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rANTES QUE VOCÊ POSSA ACESSAR O SERVIDOR MYSQL, PHPMYADMIN PEDIRÁ UM NOME DE USUÁRIO E SENHA. NÃO SE ESQUEÇA DE DEFINIR UMA SENHA PARA O USUÁRIO \"ROOT\" EM PRIMEIRO LUGAR.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rONDE ESTÁ O SUPORTE IMAP PARA PHP?\rCOMO PADRÃO, O SUPORTE A IMAP PARA PHP ESTÁ DESATIVADO NO XAMPP DEVIDO A ALGUNS ERROS DE INICIALIZAÇÃO MISTERIOSOS COM ALGUMAS VERSÕES HOME COMO O WINDOWS 98. SE VOCÊ TRABALHA COM SISTEMAS NT, VOCÊ PODE ABRIR O ARQUIVO \"\\\\XAMPP\\\\PHP\\\\PHP.INI\" PARA ATIVAR A EXTENSÃO PHP, REMOVENDO O PONTO E VÍRGULA DO COMEÇO DA LINHA \";EXTENSION=PHP_IMAP.DLL\". DEVERIA SER:\rEXTENSION=PHP_IMAP.DLL\rAGORA REINICIE O APACHE E IMAP DEVE FUNCIONAR. VOCÊ PODE USAR AS MESMAS ETAPAS PARA CADA EXTENSÃO, QUE NÃO ESTÁ HABILITADA NA CONFIGURAÇÃO PADRÃO.\rPOR QUE NÃO ALGUNS APLICATIVOS DE CÓDIGO ABERTO PHP TRABALHAR COM XAMPP NO WINDOWS?\rUM MONTE DE APLICAÇÕES PHP OU EXTENSÕES QUE FORAM ESCRITAS PARA LINUX NÃO FORAM PORTADAS PARA O WINDOWS. \rPOSSO DELETAR O DIRETÓRIO DE \"INSTALAÇÃO\" DEPOIS DA INSTALAÇÃO?\rOPS, É MELHOR NÃO. OS SCRIPTS AQUI AINDA SÃO NECESSÁRIOS PARA TODOS OS PACOTES ADICIONAIS (ADD-ONS) E ATUALIZAÇÕES DO XAMPP.\rCOMO FAÇO PARA ATIVAR O EACCELERATOR?\rCOMO OUTRAS EXTENSÕES (ZEND), VOCÊ PODE ATIVÁ-LO NO \"PHP. INI\". NESTE ARQUIVO, HABILITAR A LINHA\"; ZEND_EXTENSION =\"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"\". DEVE SER:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rCOMO FAÇO PARA CORRIGIR UM ERRO DE CONEXÃO AO MEU SERVIDOR MS SQL?\rSE A EXTENSÃO MSSQL FOI CARREGADA O PHP. INI, ÀS VEZES, PROBLEMAS APARECEM QUANDO APENAS TCP/IP É USADO. VOCÊ PODE CORRIGIR ESSE PROBLEMA COM UM \"NTWDBLIB.DLL\" MAIS RECENTE DA MICROSOFT. POR FAVOR, SUBSTITUA O ARQUIVO ANTIGO EM \"\\\\XAMPP\\\\APACHE\\\\BIN\" E \"\\\\XAMPP\\\\PHP\" O NOVO. POR CAUSA DA LICENÇA, NÓS NÃO PODEMOS EMPACOTAR UMA VERSÃO MAIS RECENTE DESTE ARQUIVO COM XAMPP.\rCOMO EU TRABALHO COM A EXTENSÃO PHP MCRYPT?\rPARA ISSO, ABRIMOS UM TÓPICO NO FÓRUM COM EXEMPLOS E POSSÍVEIS SOLUÇÕES: \rTÓPICO MCRYPT\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rN. º E APACHE::ASP COM O COMPLEMENTO DE PERL NÃO É A MESMA. APACHE::ASP SÓ ENTENDE SCRIPT EM PERL, MAS ASP DO INTERNET INFORMATION SERVER (IIS) TAMBÉM CONHECE O VBSCRIPT NORMAL. MAS PARA ASP-.NET, HÁ UM 3O MÓDULO APACHE DISPONÍVEL.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDADE\rCDN FORNECIDA PELA\r\n'),(72,'61e305df0241a7af45b9298e88e815ef','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rPERGUNTAS FREQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDADE\rCDN FORNECIDA PELA\r\n'),(73,'b0805f6f90757740d4898416c533adbb','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rPERGUNTAS FREQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDADE\rCDN FORNECIDA PELA\r\n'),(74,'cd4e333e8df2f98c0806a7b6c329474f','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rPERGUNTAS FREQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDADE\rCDN FORNECIDA PELA\r\n'),(75,'02ad7e91a89d137e244dc079ca96e14a','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rPERGUNTAS FREQUENTES\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rPERGUNTAS FREQUENTES\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nCOMUNIDADE\rXAMPP JÁ EXISTE HÁ MAIS DE 10 ANOS  HÁ UMA GRANDE COMUNIDADE POR TRÁS DELE. VOCÊ PODE SE ENVOLVER ASSOCIANDO-SE EM NOSSO \rFÓRUNS\r, E CURTINDO NOSSA PÁGINA NO \rFACEBOOK\rOU SEGUINDO NOSSAS FAÇANHAS NO \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLÍTICA DE PRIVACIDADE\rCDN FORNECIDA PELA\r\n'),(76,'5d7e121556de58f8f6fc2ca4ff426726','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rÎNTREBĂRI FRECVENTE - FAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rÎNTREBĂRI FRECVENTE - FAQ\rCUM INSTALEZ XAMPP?\rEXISTĂ TREI VARIANTE DE XAMPP PENTRU WINDOWS:\rINSTALLER:\rPROBABIL CEA MAI UŞOARĂ CALE DE A INSTALA XAMPP.\rZIP:\rXAMPP ÎN VARIANTA ZIP OBIŞNUITĂ.\r7ZIP:\rÎN SITUAŢIA UNEI VITEZE MICI DE DESCĂRCARE: XAMPP CA ARHIVĂ 7ZIP.\rNOTĂ: DACĂ EXTRAGEŢI FIŞIERELE, PUTEŢI PRIMI UN AVERTISMENT POZITIV-FALS DE LA ANTIVIRUS.\rFOLOSIND PROGRAMUL DE INSTALARE:\rPANOUL DE CONTROL XAMPP PENTRU PORNIREA/OPRIREA APACHE, MYSQL, FILEZILLA & MERCURY, SAU DE INSTALARE A ACESTOR SERVERE DREPT SERVICII.\rINSTALARE DIN ARHIVĂ ZIP\rDEZARHIVEAZĂ ARHIVELE ZIP ÎNTR-UN FOLDER LA ALEGEREA TA. XAMPP ESTE EXTRAS ÎN SUBDIRECTORUL \"C:\\\\XAMPP\" SUB DIRECTORUL ŢINTĂ SELECTAT. ACUM STARTAŢI FIŞIERUL \"SETUP_XAMPP.BAT\", PENTRU A POTRIVI CONFIGURAŢIA XAMPP LA SISTEMUL VOSTRU.\rDACĂ ALEGEŢI \"C:\\\\\" DREPT ŢINTĂ A DIRECTORULUI ROOT , NU TREBUIE SĂ PORNIŢI \"SETUP_XAMPP.BAT\".\rCA ŞI CU VERSIUNEA DE INSTALARE, PUTEŢI FOLOSI ACUM \"PANOUL DE XAMPP DE CONTROL\" PENTRU SARCINI SUPLIMENTARE.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rCUM POT PORNI XAMPP FĂRĂ INSTALARE?\rDACĂ EXTRAGEŢI XAMPP ÎNTR-UN DIRECTOR PRINCIPAL PRECUM \"C:\\\\\" SAU \"D:\\\\\", PUTEŢI PORNI MAJORITAREA SERVERELOR, CUM AR FI APACHE SAU MYSQL, FĂRĂ EXECUTAREA FIŞIERULUI \"SETUP_XAMPP.BAT\".\rNEFOLOSIND SCRIPTUL DE CONFIGURARE, SAU SELECTÂND CĂI RELATIVE ÎN SCRIPT-UL DE CONFIGURARE, ESTE DE PREFERAT PENTRU ISTALAREA XAMPP PE UN DRIVE USB. PENTRU CĂ PE FIECARE PC O ASTFEL DE UNITATE POATE AVEA O ALTĂ LITERĂ DE ALOCATĂ. PUTEȚI TRECE DE LA ABSOLUT LA RELATIV ÎN ORICE MOMENT, CU SCRIPT-UL DE CONFIGURARE.\rFOLOSIND PROGRAMUL DE INSTALARE DE PE PAGINA NOASTRĂ DOWNLOAD-URI ESTE CEL MAI SIMPLU MOD DE A INSTALA XAMPP. DUPĂ CE INSTALAREA ESTE COMPLETĂ, VEŢI GĂSI XAMPP ÎN START | PROGRAME | XAMPP. PUTEŢI UTILIZA PANOUL DE CONTROL XAMPP PENTRU A PORNI/OPRI TOATE SERVERELE ŞI DE ASEMENEA SĂ INSTALAŢI/DEZINSTALAŢI SERVICII.\rPANOUL DE CONTROL XAMPP PENTRU PORNIREA/OPRIREA APACHE, MYSQL, FILEZILLA & MERCURY, SAU DE INSTALARE A ACESTOR SERVERE DREPT SERVICII.\rCUM PORNESC ŞI OPRESC XAMPP?\rCENTRUL UNIVERSAL DE CONTROL ESTE \"CONTROL PANEL XAMPP\" (MULŢUMIRI WWW.NAT32.COM). SE ÎNCEPE CU:\r\\XAMPP\\XAMPP-CONTROL.EXE\rPUTEŢI FOLOSI, DE ASEMENEA, UNELE FIŞIERE STIVE DE COMENZI - BATCH PENTRU A PORNI/OPRI SERVERELE:\rAPACHE & MYSQL START:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL STOP:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE START:\n\\XAMPP\\APACHE_START.BAT\rAPACHE STOP:\n\\XAMPP\\APACHE_STOP.BAT\rMYSQL START:\n\\XAMPP\\MYSQL_START.BAT\rMYSQL STOP:\n\\XAMPP\\MYSQL_STOP.BAT\rMERCURY MAILSERVER START:\n\\XAMPP\\MERCURY_START.BAT\rMERCURY MAILSERVER STOP:\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA SERVER START:\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA SERVER STOP:\n\\XAMPP\\FILEZILLA_STOP.BAT\rCOM POŢI TESTA DACĂ TOTUL FUNCŢIONAZĂ?\rTASTEAZĂ URMĂTOAREA ADRESĂ URL ÎN BROWSER-UL TĂU FAVORIT:\rHTTP://LOCALHOST/\rSAU \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rCUM POT INSTALA SERVERUL DREPT SERVICIU?\rPUTEŢI INSTALA DE ASEMENEA FIECARE SERVER DIN XAMPP DREPT SERVICIU WINDOWS. ÎL PUTEŢI INSTALA DEALTFEL DIN PANOUL DE CONTROL XAMPP. ÎN ACEASTĂ SITUAŢIE, ESTE NECESAR A RULA SCRIPTURILE SAU PANOUL DE CONTROL CU DREPTURI DE ADMINISTRATOR.\rINSTALARE SERVICIU APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rDEZINSTALARE SERVICIU APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rINSTALARE SERVICIU MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rDEZINSTALARE SERVICIU MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \r(DEZ)INSTALARE SERVICIU FILEZILLA: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: NICI O INSTALARE DE SERVICIU DISPONIBILĂ\rPOATE FI FOLOSIT ÎN PRODUCŢIE XAMPP?\rXAMPP NU ESTE ADECVAT UTILIZĂRII ÎN PRODUCŢIE, CI DOAR ÎN MEDII DE DEZVOLTARE. EL ESTE CONFIGURAT ÎN MODUL CEL MAI DESCHIS, PENTRU AI PERMITE PROGRAMATORULUI TOT CE ACESTA ÎŞI DOREŞTE. ACEASTA CONVINE PERFECT ÎN MEDII DE DEZVOLTARE, DAR POATE FI UN DEZASTRU ÎNTR-UN MEDIU DE PRODUCŢIE.\rIATĂ O LISTĂ DE VULNERABILITĂŢI ALE XAMPP:\rADMINISTRATORUL MYSQL (CONTUL DE ROOT) NU ARE PAROLĂ.\rSE POATE ACCESA ÎN REŢEA DAEMON-UL MYSQL.\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rUTILIZATORII IMPLICIŢI AI MERCURY SI FILEZILLA SUNT CUNOSCUŢI.\rTOATE PUNCTELE POT REPREZENTA UN IMENS RISC DE SECURITATE. MAI ALES DACĂ XAMPP ESTE ACCESIBIL PRIN INTERMEDIUL REŢELEI ŞI PERSOANELOR DIN AFARA LAN-ULUI VOSTRU. DE AJUTOR POATE FI DE ASEMENEA UTILIZAREA UNUI FIREWALL SAU A UNUI ROUTER (NAT) . FOLOSIND UN ROUTER SAU UN FIREWALL, PC-UL VOSTRU ESTE ÎN MOD NORMAL INACCESIBIL ÎN REŢEA. REZOLVAREA ACESTOR PROBLEME, VĂ REVINE. DE UN OARECARE AJUTOR ESTE \"CONSOLA DE SECURITATE XAMPP\".\rVĂ RUGĂM SĂ PROTEJAŢI XAMPP ÎNAINTE DE A PUBLICA ON-LINE. UN FIREWALL SAU UN ROUTER EXTERN SUNT SUFICIENTE DOAR PENTRU UN NIVEL SCĂZUT DE SECURITATE. PENTRU MAI MULTĂ SIGURANŢĂ, PUTEȚI RULA \"CONSOLA XAMPP SECURITY\" UNDE PUTEŢI ATRIBUI PAROLE.\rDACĂ DORIŢI SĂ AVEŢI XAMPP ACCESIBIL PE INTERNET, TREBUIE SĂ MERGEŢI LA URMĂTOAREA ADRESĂ URI CARE POATE REZOLVA UNELE PROBLEME:\rHTTP://LOCALHOST/SECURITY/\rCU CONSOLA DE SECURITATE PUTEŢI SETA O PAROLĂ PENTRU UTILIZATOR \"ROOT\" MYSQL ŞI PHPMYADMIN. PUTEŢI ACTIVA, DE ASEMENEA, O AUTENTIFICARE PENTRU DEMOPAGES XAMPP.\rACEST INSTRUMENT BAZAT PE WEB NU REZOLVĂ PROBLEME SUPLIMENTARE DE SECURITATE! MAI ALES SERVERUL FILEZILLA FTP ŞI SERVERUL DE MAIL MERCURY SECURIZATE DE D-VOASTRĂ.\rCUM INSTALEZ XAMPP?\rDACĂ AŢI INSTALAT XAMPP FOLOSIND VERSIUNEA DE INSTALARE, VĂ RUGĂM SĂ UTILIZAŢI PROGRAMUL DE DEZINSTALARE. DEZINSTALAREA VA ŞTERGE TOATE INTRĂRILE XAMPP ÎN REGIŞTRII ŞI VA DEZINSTALA UNELE SERVICII INCLUSE CU XAMPP. VĂ RECOMANDĂM SĂ UTILIZAŢI PROGRAMUL DE DEZINSTALARE PENTRU ÎNDEPĂRTAREA INSTALĂRILOR XAMPP DIN VERSIUNEA KITULUI DE INSTALARE. VĂ RUGĂM SĂ FACEŢI COPII DE SIGURAŢĂ A DATELOR PE CARE DORIŢI SĂ LE PĂSTRAŢI, ÎNAINTE DE DEZINSTALAREA XAMPP.\rDACĂ AŢI INSTALAT XAMPP FOLOSIND VERSIUNI ALE ZIP ŞI 7ZIP, ÎNCHIDEŢI TOATE SERVERELE XAMPP ŞI IEŞIŢI DIN TOATE PANOURILE. DACĂ AŢI INSTALAT ORICARE SERVICII, OPRIŢI-LE ŞI DE ASEMENEA DEZINSTALAŢI-LE. APOI, ŞTERGEŢI SIMPLU ÎNTREGUL FOLDER ÎN CARE S-A INSTALAT XAMPP. NU EXISTĂ INTRĂRI ÎN REGISTRY SAU VARIABILE DE MEDIU CARE SĂ NECESITE CURĂŢIRE.\rCE ESTE VERSIUNEA \"REDUSĂ\" A XAMPP?\rXAMPP LITE (ÎNSEMNÂND \"REDUS\" CA ÎN \"GREUTATE REDUSĂ\") ESTE UN PACHET MAI MIC DE COMPONENTE XAMPP, RECOMANDAT PENTRU TREBURI URGENTE, FOLOSIND DOAR PHP ŞI MYSQL. UNELE SERVERE SAU INSTRUMENTE, CUM AR FI MERCURY MAIL ŞI FILEZILLA FTP LIPSESC DIN VERSIUNEA LITE.\rUNDE AR TREBUI SĂ PLASEZ CONŢINUTUL WEB-ULUI MEU?\rDIRECTORUL PRINCIPAL PENTRU TOATE DOCUMENTELE WWW ESTE \\\\XAMPP\\\\HTDOCS. DACĂ ÎN ACEST DIRECTOR PUNEŢI UN FIŞIER \"TEST.HTML\" , ÎL PUTEŢI ACCESA CU URI-UL \"HTTP://LOCALHOST/TEST.HTML\".\rŞI ÎN CAZUL \"TEST.PHP\"? FOLOSIŢI SIMPLU \"HTTP://LOCALHOST/TEST.PHP\". UN SCRIPT DE TEST SIMPLU POATE FI:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rUN SUBDIRECTOR NOU PENTRU WEB-UL VOSTRU? TREBUIE DOAR SĂ CREEAŢI UN NOU DIRECTOR (DE EX. \"NEW\") ÎN DIRECTORUL \"\\\\XAMPP\\\\HTDOCS\" (CEL MAI BINE FĂRĂ SPAŢII ALBE ŞI DOAR ASCII), ÎN ACEST DIRECTOR CREEAŢI UN FIŞIER DE TEST ŞI ACCESAŢI-L CU \"HTTP://LOCALHOST/NEW/TEST.PHP\".\rSPECIFICAŢII SUPLIMENTARE\rHTML:\rEXECUTABIL: \\XAMPP\\HTDOCS\rTERMINATORI ACCEPTAŢI: .HTML .HTM\r=> PACHET DE BAZĂ\rSSI:\rEXECUTABIL: \\XAMPP\\HTDOCS\rTERMINATORI ACCEPTAŢI: .SHTML\r=> PACHET DE BAZĂ\rCGI:\rEXECUTABIL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rTERMINATORI ACCEPTAŢI: .CGI\r=> PACHET DE BAZĂ\rPHP:\rEXECUTABIL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rTERMINATORI ACCEPTAŢI: .PHP\r=> PACHET DE BAZĂ\rPERL:\rEXECUTABIL: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rTERMINATORI ACCEPTAŢI: .PL\r=> PACHET DE BAZĂ\rAPACHE::ASP PERL:\rEXECUTABIL: \\XAMPP\\HTDOCS\rTERMINATORI ACCEPTAŢI: .ASP\r=> PACHET DE BAZĂ\rJSP JAVA:\rEXECUTABIL: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rTERMINATORI ACCEPTAŢI: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rEXECUTABIL: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rTERMINATORI ACCEPTAŢI: .HTML (U.A)\r=> TOMCAT ADD-ON\rPOT RELOCA XAMPP INSTALAT?\rDA. DUPĂ CE MUTAŢI DIRECTORUL XAMPP-ULUI, TREBUIE EXECUTAT \"SETUP_XAMPP.BAT\". CU ACEASTĂ OCAZIE, SE VOR RECONFIGURA CĂILE ÎN FIŞIERELE DE CONFIGURARE.\rDACĂ AŢI INSTALAT VREUN SERVER CA SERVICIU WINDOWS, MAI ÎNTÂI TREBUIE SĂ ÎNLĂTURAŢI SERVICIUL, IAR DUPĂ MUTARE PUTEŢI INSTALA DIN NOU SERVICIUL.\rATENŢIUNE: NU SUNT MODIFICATE FIŞIERELE DE CONFIGURARE DIN SCRIPTURILE VOASTRE, PRECUM APLICAŢIILE PHP. ESTE ÎNSĂ POSIBILĂ SCRIEREA UNUI \"PLUG-IN\" PENTRU PROGRAMUL DE INSTALARE. CU UN ASTFEL DE PLUG-IN, INSTALLER-UL POATE MODIFICA ŞI ASFEL DE FIŞIERE.\rCE SUNT \"PAGINILE AUTOMATE DE START\" PENTRU DIRECTOARELE WWW?\rNUMELE FIŞIERULUI STANDARD PENTRU FUNCŢIA APACHE \"DIRECTORYINDEX\" ESTE \"INDEX.HTML\" SAU \"INDEX.PHP\". ORICÂND NAVIGAŢI LA UN FOLDER (DE EX. \"HTTP://LOCALHOST/XAMPP/\"), IAR APACHE POATE GĂSI ACEST FIŞIER, ÎL VA AFIŞA PE ACESTA, ÎN LOCUL UNEI LISTĂRI A DIRECTORULUI.\rDE UNDE POT SĂ SCHIMB CONFIGURAŢIA?\rDIN FIŞIERELE DE CONFIGURARE PUTEŢI MODIFICA APROAPE TOATE SETĂRILE DIN XAMPP. TREBUIE DOAR SĂ DESCHIDEŢI FIŞIERUL ÎNTR-UN EDITOR ŞI SĂ MODIFICAŢI SETAREA PE CARE O DORIŢI. NUMAI PENTRU A CONFIGURA FILEZILLA ŞI MERCURY ESTE NECESARĂ UTILIZAREA APLICAŢIEI DE CONFIGURARE.\rDE CE NU POATE FUNCŢIONA XAMPP CU WINDOWS XP SP2?\rODATĂ CU SERVICE PACK 2 (SP2), MICROSOFT LIVREAZĂ UN FIREWALL MAI BUN, CARE PORNEŞTE AUTOMAT. ACEST FIREWALL BLOCHEAZĂ ACUM PORTURILE NECESARE 80 (HTTP) ŞI 443 (HTTPS) , ASTFEL ÎNCÂT APACHE-UL NU POATE STARTA.\rSOLUŢIA RAPIDĂ:\rDEZACTIVAŢI FIREWALL-UL MICROSOFT DIN BARA DE UNELTE ŞI ÎNCERCAŢI DIN NOU SĂ PORNIŢI XAMPP. O SOLUŢIONARE MAI ADECVATĂ O REPREZINTĂ DEFINIREA UNEI EXCEPŢII, CU AJUTORUL CENTRULUI DE SECURITATE.\rPENTRU O FUNCŢIONARE DE BAZĂ SUNT UTILIZATE URMĂTOARELE PORTURI:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rDE CE NU FUNCŢIONEAZĂ XAMPP CU VISTA?\rCONTROLUL CONTULUI DE UTILIZATOR (UAC)\rÎN DIRECTORUL \"C:\\\\PROGRAM FILES\" NU AVEŢI DREPTURI DEPLINE DE SCRIERE, CHIAR FIIND ADMINISTRATOR. SAU AVEŢI DOAR DREPTURI LIMITATE (DE EX. PENTRU \".\\\\XAMPP\\\\HTDOCS\"). ÎN ACEST CAZ, NU PUTEŢI EDITA FIŞIERUL.\rSOLUŢIE:\rDIN EXPLORER, ACORDAŢI-VĂ DREPTURI SPORITE (CLIC DREAPTA / SECURITATE) , SAU DEZACTIVAŢI CONTROLUL CONTULUI DE UTILIZATOR (UAC).\rAŢI INSTALAT APACHE/MYSQL ÎN \"C:\\\\XAMPP\" CA SERVICIU WINDOWS. DAR NU PUTEŢI PORNI/OPRI SERVICIILE DIN \"PANOUL DE CONTROL XAMPP\" SAU NU LE PUTEŢI DEZINSTALA.\rSOLUŢIE:\rFOLOSIŢI CONSOLA WINDOWS DE ADMINISTRARE A SERVICIILOR, SAU DEZACTIVAŢI UAC.\rDEZACTIVAREA CONTROLULUI CONT DE UTILIZATOR (UAC)\rPENTRU DEZACTIVAREA UAC, FOLOSIŢI PROGRAMUL \"MSCONFIG\". ÎN \"MSCONFIG\" MERGEŢI LA \"TOOLS\", SELECTAŢI \"DEZACTIVARE CONTROL AL CONTULUI DE UTILIZATOR\" ŞI VERIFICAŢI SELECŢIA. DUPĂ ACEASTA, WINDOWS-UL TREBUIE RESTARTAT. ÎN ACELAŞI MOD SE POATE REACTIVA UAC.\rCUM REALIZEZ VERIFICAREA SUMEI DE CONTROL MD5?\rPENTRU A COMPARA FIŞIERE, ADESEORI SE FOLOSESC SUME DE CONTROL. UN STANDARD PENTRU A CREA ACEASTĂ SUMĂ DE CONTROL MD5 (ALGORITMUL DE REZUMARE A MESAJULUI - MESSAGE DIGEST 5).\rCU ACEASTĂ SUMĂ DE CONTROL MD5 PUTEŢI VERIFICA INTEGRITATEA PACHETULUI XAMPP DESCĂRCAT. AVEŢI NEVOIE DESIGUR, DE UN PROGRAM CARE SĂ POATĂ CONSTRUI ACESTE SUME DE CONTROL. ÎN CAZUL WINDOWS-ULUI, AVEŢI LA DISPOZIŢIE UTILITARUL MICROSOFT:\rDISPONIBILITATEA ŞI DESCRIEREA UTILITARULUI DE VERIFICARE A INTEGRITĂŢII SUMEI DE CONTROL A FIŞIERULUI\rDESIGUR, SE POATE FOLOSI ORICE ALT PROGRAM CARE FURNIZEAZĂ SUME DE CONTROL MD5, PRECUM MD5SUM DE LA GNU.\rODATĂ CE AŢI INSTALAT UN ASTFEL DE PROGRAM (DE EX. FCIV.EXE), PUTEŢI CONTINUA CU URMĂTORII PAŞI:\rDESCARCĂ XAMPP (DE EX. XAMPP-WIN32-1.8.2-0.EXE)\rPENTRU OBŢINEREA SUMEI DE CONTROL:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rACUM PUTEŢI COMPARA ACEASTĂ SUMĂ DE CONTROL, CU CEA CARE SE AFLĂ ÎN PAGINA GAZDĂ PRINCIPALĂ A XAMPP PENTRU WINDOWS.\rDACĂ CELE DOUĂ SUME DE CONTROL SUNT EGALE, ESTE ÎN REGULĂ. DACĂ NU, ÎNSEAMNĂ FIE CĂ DESCĂRCAREA ESTE INVALIDATĂ DE ERORI, SAU CĂ FIŞIERUL A FOST MODIFICAT.\rDE CE NU AU EFECT MODIFICĂRILE ADUSE FIŞIERULUI PHP.INI?\rDACĂ O MODIFICARE A FIŞIERULUI \"PHP.INI\" NU ARE EFECT, PROBABIL CĂ PHP ÎL FOLOSEŞTE PE UN ALTUL. PUTEŢI VERIFICA ACEASTA CU PHPINFO(). INTRODUCEŢI ADRESA URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP ŞI CĂUTAŢI \"FIŞIERUL DE CONFIGURARE ÎNCĂRCAT\". ACEASTĂ VALOARE INDICĂ FIŞIERUL \"PHP.INI\" UTILIZAT DE PHP ÎN REALITATE.\rOBSERVAŢIE:\rDUPĂ MODIFICAREA FIŞIERULUI \"PHP.INI\" APACHE VA TREBUI RESTARTAT, ASTFEL CA APACHE/PHP SĂ-ŞI POATĂ ACTUALIZA SETĂRILE.\rAJUTOR! XAMPP ESTE VIRUSAT!\rESTE POSIBIL CA PROGRAME ANTIVIRUS SĂ ALERTEZE DIN GREŞEALĂ CĂ XAMPP ESTE VIRUSAT, MARCÂND DE OBICEI FIŞIERUL XAMPP-MANAGER.EXE. VORBIM DE UN POZITIV FALS, ÎNSEMNÂND CĂ ANTIVIRUSUL IDENTIFICĂ ÎN MOD ERONAT UN VIRUS, ACOLO UNDE EL NU EXISTĂ. ÎNAINTEA LANSĂRII, SCANĂM ANTIVIRAL FIECARE NOUĂ VERSIUNE DE XAMPP. ÎN PREZENT UTILIZĂM \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rCUM ÎMI CONFIGUREZ APLICAŢIA ANTIVIRUS?\rPENTRU FUNCŢIONAREA ÎNTREGULUI PACHET DE APLICAŢII WEB, AM INCLUS TOT FELUL DE SERVERE ŞI PROGRAME SUPLIMENTARE, ASTFEL ÎNCÂT INSTALAREA XAMPP SE FACE CU UN MARE NUMĂR DE FIŞIERE. INSTALAREA XAMPP POATE FI MULT ÎNCETINITĂ DACĂ ARE LOC PE UN SISTEM WINDOWS PROTEJAT DE UN ANTIVIRUS, ACESTA PUTÂND CHIAR BLOCA UNELE DINTRE SERVERE (DE WEB, SAU DE BAZE DE DATE). PENTRU CA XAMPP SĂ FUNCŢIONEZE FĂRĂ PIERDERI DE PERFORMANŢĂ DATORATE ANTIVIRUSULUI, VERIFICAŢI URMĂTOARELE SETĂRI:\rÎN FIREWALL, ADĂUGAŢI EXCEPŢII: PENTRU APACHE, PENTRU MYSQL SAU ORICE ALT SERVER.\rSCANAREA FIŞIERELOR LA EXECUTARE: DACĂ AŢI ACTIVAT SCANAREA ANTIVIRUS PENTRU TOATE FIŞIERELE, EXECUTABILELE SERVERELOR POT INCETINI.\rSCANAREA TRAFICULUI PENTRU DIFERITE URL-URI: DACĂ DEZVOLTAŢI CU XAMPP PE PROPRIA MAŞINĂ, PUTEŢI EXCLUDE ÎN SETĂRILE ANTIVIRUS TRAFICUL CU GAZDA - \"LOCALHOST\".\rDE CE NU PORNEŞTE SERVERUL APACHE PE SISTEMUL MEU?\rACEASTĂ PROBLEMĂ POATE AVEA UNA DINTRE URMĂTOARELE CAUZE:\rAVEŢI PORNITE MAI MULTE SERVERE HTTP (IIS, SAMBAR, ZEUS ŞI AŞA MAI DEPARTE). DOAR UN SINGUR SERVER POATE FOLOSI PORTUL 80. ACEASTĂ PROBLEMĂ ESTE INDICATĂ DE MESAJUL DE EROARE:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rPORTUL 80 ESTE BLOCAT DE UN ALT PROGRAM, CUM AR FI TELEFONIA DE INTERNET \"SKYPE\". ÎN CAZUL LUI \"SKYPE\" PROBLEMA SE POATE EVITA, MERGÂND ÎN SKYPE LA ACŢIUNI -> OPŢIUNI -> CONEXIUNE -> ÎNLĂTURAREA BIFEI \"FOLOSEŞTE PORTUL 80 DREPT PORT ALTERNATIV\" ŞI RESTARTAREA SKYPE. ACUM AR TREBUI SĂ FUNCŢIONEZE.\rAVEŢI UN FIREWALL CARE BLOCHEAZĂ PORTUL ASOCIAT APACHE. NU TOATE FIREWALL-URILE SUNT COMPATIBILE CU APACHE, IAR UNEORI SIMPLA DEZACTIVARE A FIREWALL-ULUI NU ESTE SUFICIENTĂ, CI TREBUIE SĂ-L DEZINSTALAŢI. FIREWALL-UL ESTE INDICAT ÎN MESAJUL DE EROARE:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rDE ASEMENEA, DACĂ APACHE PORNEŞTE DAR NU VĂ PUTEŢI CONECTA LA EL PRIN BROWSER, CAUZA POATE FI UNA DINTRE URMĂTOARELE:\rŞI UNELE PROGRAME ANTIVIRUS POT CAUZA ACEST LUCRU, SIMILAR ACŢIUNII UNUI FIREWALL.\rAVEŢI UN XP PROFESIONAL CĂRUIA ÎI LIPSEŞTE PACHETUL DE SERVICE NR. 1. PENTRU XAMPP, VĂ ESTE NECESAR CEL PUŢIN SP1.\rSFAT:\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\rDE CE ARE CPU O ÎNCĂRCARE DE SARCINĂ PENTRU APACHE DE APROAPE 99%?\rEXISTĂ UNA DIN URMĂTOARELE DOUĂ VARIANTE: FIE CPU ESTE LA MAXIM, FIE PUTEŢI CONECTA BROWSER-UL LA SERVER, DAR NU SE VEDE NIMIC (SISTEMUL ÎNCEARCĂ FĂRĂ SUCCES SĂ ÎNCARCE PAGINA). ÎN AMBELE SITUAŢII PUTEŢI GĂSI ÎN FIŞIERUL DE LOGARE APACHE MESAJUL URMĂTOR:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rMPM REVINE LA O MAI SIGURĂ PUNERE ÎN APLICARE, DAR UNELE CERERI ALE CLIENTULUI NU AU FOST CORECT PROCESATE. ÎN SCOPUL EVITĂRII ACESTEI ERORI, ÎN FIŞIERUL \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\" UTILIZAŢI \"ACCEPTFILTER\", CU FILTRUL DE ACCEPTARE \"NONE\".\rDE CE NU SUNT AFIŞATE IMAGINILE ŞI FOILE-DE-STIL?\rUNEORI APAR PROBLEME LA AFIŞAREA IMAGINILOR ŞI A PAGINILOR-DE-STIL. ÎN SPECIAL DACĂ ACESTE FIŞIERE SUNT LOCALIZATE PE UN DISC DE REŢEA. ÎN ACEASTĂ SITUAŢIE PUTEŢI ACTIVA (SAU ADĂUGA) ÎN FIŞIERUL \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\" UNA DINTRE URMĂTOARELE LINII:\rENABLESENDFILE OFF\rENABLEMMAP OFF\rACEASTĂ PROBLEMĂ POATE SĂ APARĂ ŞI DE LA PROGRAMELE DE REGULARIZARE A LĂŢIMII DE BANDĂ, PRECUM NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rCUM POT SETA O PAROLĂ DE ROOT ÎN MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rPOT SĂ-MI FOLOSESC PROPRIUL SERVER MYSQL?\rDA. PUR ŞI SIMPLU NU PORNIŢI MYSQL-UL DIN PACHETUL XAMPP. REŢINEŢI CĂ NU POT FI STARTATE DOUĂ SERVERE PE UN ACELAŞI PORT. DACĂ AŢI SETAT O PAROLĂ DE \"ROOT\", NU UITAŢI SĂ EDITAŢI FIŞIERUL \"\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INI.PHP\".\rCUM RESTRICŢIONEZ ACCESUL DIN EXTERIOR LA PHPMYADMIN?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rÎNAINTE DE A PUTEA ACCESA SERVERUL MYSQL, PHPMYADMIN VA SOLICITA UN NUME DE UTILIZATOR ŞI O PAROLĂ. NU UITAŢI CA MAI ÎNTÂI DE TOATE, SĂ SETAŢI PENTRU UTILIZATORUL \"ROOT\" O PAROLĂ.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rUNDE SE AFLĂ SUPORTUL IMAP PENTRU PHP?\rINIŢIAL, SUPORTUL IMAP PENTRU PHP ESTE DEZACTIVAT ÎN XAMPP DIN CAUZA UNOR MISTERIOASE ERORI DE INIŢIALIZARE CU UNELE VERSIUNI CASNICE PRECUM WINDOWS98. DACĂ LUCRAŢI CU SISTEME NT, PUTEŢI DESCHIDE FIŞIERUL \"\\\\XAMPP\\\\PHP\\\\PHP.INI\" PENTRU ACTIVAREA EXTENSIEI PHP, PRIN ÎNLĂTURAREA SEMNULUI PUNCT ŞI VIRGULĂ DE LA ÎNCEPUTUL LINIEI \";EXTENSION=PHP_IMAP.DLL\". TREBUIE SĂ FIE:\rEXTENSION=PHP_IMAP.DLL\rACUM RESTARTAŢI APACHE, IAR IMAP AR TREBUI SĂ FUNCŢIONEZE. PUTEŢI FOLOSI ACEIAŞI PAŞI PENTRU FIECARE EXTENSIE CARE NU ESTE VALIDATĂ ÎN CONFIGURAŢIA INIŢIALĂ.\rDE CE UNELE APLICAŢII PHP OPEN SOURCE NU FUNCŢIONEAZĂ CU XAMPP PE WINDOWS?\rO MULŢIME DE APLICAŢII PHP SAU EXTENSII CARE AU FOST SCRISE PENTRU LINUX, NU AU FOST PORTATE PE WINDOWS. \rPOT ŞTERGE DIRECTORUL \"INSTALL\" DUPĂ INSTALARE?\rE MAI BINE SĂ NU. SCRIPTURILE DE AICI SUNT ÎNCĂ NECESARE TUTUROR PACHETELOR ADIŢIONALE (ADD-ONURI) ŞI UPGRADE-URILOR LUI XAMPP.\rCUM ACTIVEZ EACCELERATOR-UL?\rCA ŞI ALTE EXTENSII (ZEND) LE PUTEŢI ACTIVA ÎN \"PHP.INI\". ÎN ACEST FIŞIER VALIDAŢI LINIA \";ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"\". AR TREBUI SĂ FIE:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rCUM DEPĂŞESC O EROARE DE CONECTARE LA SERVERUL MEU MYSQL?\rDACĂ EXTENSIA MSSQL A FOST ÎNCĂRCATĂ ÎN PHP.INI, UNEORI APAR PROBLEME CÂND ESTE FOLOSIT DOAR TCP/IP. PUTEŢI REZOLVA ACEASTĂ PROBLEMĂ CU UN MAI NOU \"NTWDBLIB.DLL\" DE LA MICROSOFT. VĂ RUGĂM ÎNLOCUIŢI VECHIUL FIŞIER ÎN \"\\\\XAMPP\\\\APACHE\\\\BIN\" ŞI \"\\\\XAMPP\\\\PHP\" CU UNUL NOU. DIN CAUZĂ DE LICENŢĂ, NU PUTEM ÎMPACHETA O VERSIUNE NOUĂ A ACESTUI FIŞIER CU XAMPP.\rCUM UTILIZEZ EXTENSIA PHP MCRYPT?\rPENTRU ACEASTA, AM DESCHIS UN SUBIECT ÎN FORUM, CU EXEMPLE ŞI SOLUŢII POSIBILE: \rSUBIECT MCRYPT\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rNU. IAR APACHE::ASP NU-I ACELAŞI LUCRU CU SUPLIMENTUL PERL. APACHE::ASP RECUNOAŞTE DOAR PERL-SCRIPT, PE CÂND ASP DIN INTERNET INFORMATION SERVER (IIS) RECUNOAŞTE DE ASEMENEA VBSCRIPT-UL OBIŞNUIT. DAR PENTRU ASP.NET ESTE DISPONIBIL UN MODUL APACHE DE LA TERŢI.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA DE INTIMITATE\rCDN FURNIZATE DE\r\n'),(77,'c231b56b0d7235436dedfcbb18753542','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rÎNTREBĂRI FRECVENTE - FAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA DE INTIMITATE\rCDN FURNIZATE DE\r\n'),(78,'f1e89d9ad65abdc89640da7b82857882','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rÎNTREBĂRI FRECVENTE - FAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA DE INTIMITATE\rCDN FURNIZATE DE\r\n'),(79,'1dbe5dc69d162e511d0659d1479b79e6','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rÎNTREBĂRI FRECVENTE - FAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA DE INTIMITATE\rCDN FURNIZATE DE\r\n'),(80,'eb5ff10746bb7cac0c58f6adc453195f','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rÎNTREBĂRI FRECVENTE - FAQS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rÎNTREBĂRI FRECVENTE - FAQS\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nCOMUNITATE\rXAMPP ESTE ALĂTURI DE NOI DE MAI BINE DE 10 ANI  EXISTĂ O IMENSĂ COMUNITATE ÎN SPATELE LUI. POŢI SĂ TE IMPLICI ALĂTURÂNDU-TE \rFORUM-URI\rNOASTRE, ŢINÂND LEGĂTURA CU NOI PE \rFACEBOOK\rSAU URMĂRINDU-NE POSTĂRILE PE \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rPOLITICA DE INTIMITATE\rCDN FURNIZATE DE\r\n'),(81,'4c36c3017164a431df3714437fe1412f','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rЧАВО\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rЧАСТО ЗАДАВАЕМЫЕ ВОПРОСЫ\rКАК МНЕ УСТАНОВИТЬ XAMPP?\rXAMPP ДЛЯ WINDOWS СУЩЕСТВУЕТ В ТРЁХ РАХНЫХ ПАКЕТАХ:\rУСТАНОВЩИК:\rВЕРОЯТНО САМЫЙ ПРОСТОЙ СПОСОБ УСТАНОВИТЬ XAMPP.\rZIP:\rДЛЯ ПУРИСТОВ: XAMPP КАК ОБЫЧНЫЙ ZIP АРХИВ.\r7ZIP:\rДЛЯ ПУРИСТОВ С НЕБОЛЬШОЙ СКОРОСТЬЮ ИНТЕРНЕТА: XAMPP КАК 7ZIP АРХИВ.\rЗАМЕТКА: ЕСЛИ ВЫ РАСПАКУЕТЕ ФАЙЛЫ, ВОЗМОЖНО ЛОЖНОЕ СРАБАТЫВАНИЕ АНТИВИРУСНОЙ ПРОГРАММЫ.\rИСПОЛЬЗОВАНИЕ УСТАНОВЩИКА:\rПАНЕЛЬ УПРАВЛЕНИЯ XAMPP ДЛЯ ЗАПУСКА/ОСТАНОВКИ APACHE, MYSQL, FILEZILLA И MERCURY ИЛИ УСТАНОВКИ ЭТИХ СЕРВЕРОВ В КАЧЕСТВЕ СЕРВИСОВ.\rУСТАНОВКА ИЗ ZIP АРХИВА\rРАСПАКУЙТЕ ZIP АРХИВЫ В ВЫБРАННУЮ ВАМИ ПАПКУ. XAMPP РАСПАКУЕТСЯ В СУБ-КАТАЛОГ \"C:\\\\XAMPP\" ПОД ВЫБРАННОЙ ПАПКОЙ. ТЕПЕРЬ ЗАПУСТИТЕ ФАЙЛ \"SETUP_XAMPP.BAT\", ЧТОБЫ НАСТРОИТЬ КОНФИГУРАЦИЮ XAMPP ДЛЯ ВАШЕЙ СИСТЕМЫ.\rЕСЛИ ВЫ ВЫБЕРИТЕ КОРНЕВОЙ КАТАЛОГ \"C:\\\\\" КАК ПАПКУ НАЗНАЧЕНИЯ, ВЫ НЕ ДОЛЖНЫ ЗАПУСКАТЬ \"SETUP_XAMPP.BAT\".\rТАКЖЕ КАК В ВЕРСИИ С УСТАНОВЩИКОМ, ТЕПЕРЬ ВЫ МОЖЕТЕ ИСПОЛЬЗОВАТЬ КОНТРОЛЬНУЮ ПАНЕЛЬ XAMPP (XAMPP CONTROL PANEL) ДЛЯ ДОПОЛНИТЕЛЬНЫХ ЗАДАЧ.\rXAMPP ВКЛЮЧАЕТ В СЕБЯ MYSQL ИЛИ MARIADB?\rС МОМЕНТА ВЫХОДА XAMPP 5.5.30 И 5.6.14, XAMPP ПРЕДОСТАВЛЯЕТ MARIADB ВМЕСТО MYSQL. КОМАНДЫ И ИНСТРУМЕНТЫ ДЛЯ ОБОИХ ОДНИ И ТЕ ЖЕ.\rКАК МНЕ ЗАПУСТИТЬ XAMPP БЕЗ УСТАНОВКИ?\rЕСЛИ ВЫ РАСПАКУЕТЕ XAMPP В ПАПКУ ВЕРХНЕГО УРОВНЯ КАК \"C:\\\\\" ИЛИ \"D:\\\\\", ВЫ МОЖЕТЕ ЗАПУСТИТЬ БОЛЬШИНСТВО СЕРВЕРОВ КАК APACHE ИЛИ MYSQL СРАЗУ БЕЗ ИСПОЛНЕНИЯ ФАЙЛА \"SETUP_XAMPP.BAT\".\rЕСЛИ ВЫ УСТАНАВЛИВАЕТЕ XAMPP НА USB НОСИТЕЛЬ ЖЕЛАТЕЛЬНО НЕ ИСПОЛЬЗОВАТЬ СКРИПТ УСТАНОВКИ, ИЛИ ВЫБРАТЬ В СКРИПТЕ УСТАНОВКИ ОТНОСИТЕЛЬНЫЕ ПУТИ. ТАК КАК НА КАЖДОМ ПК ТАКОЙ НОСИТЕЛЬ МОЖЕТ ИМЕТЬ РАЗНЫЕ БУКВЫ ПРИВОДА. ВЫ МОЖЕТЕ ПЕРЕЙТИ С АБСОЛЮТНЫХ НА ОТНОСИТЕЛЬНЫЕ ПУТИ В ЛЮБОЙ МОМЕНТ С ПОМОЩЬЮ СКРИПТА УСТАНОВКИ.\rИСПОЛЬЗОВАНИЕ УСТАНОВЩИКА С НАШЕЙ СТРАНИЦЫ СКАЧИВАНИЙ ЭТО САМЫЙ ПРОСТОЙ СПОСОБ УСТАНОВИТЬ XAMPP. ПОСЛЕ ЗАВЕРШЕНИЯ УСТАНОВКИ, ВЫ НАЙДЁТЕ XAMPP ПОД ПУСК | ВСЕ ПРОГРАММЫ | XAMPP. ВЫ МОЖЕТЕ ИСПОЛЬЗОВАТЬ ПАНЕЛЬ УПРАВЛЕНИЯ XAMPP ДЛЯ ЗАПУСКА ИЛИ ОСТАНОВКИ ВСЕХ СЕРВЕРОВ И УСТАНОВКИ ИЛИ УДАЛЕНИЯ СЕРФИСОВ.\rПАНЕЛЬ УПРАВЛЕНИЯ XAMPP ДЛЯ ЗАПУСКА/ОСТАНОВКИ APACHE, MYSQL, FILEZILLA И MERCURY ИЛИ УСТАНОВКИ ЭТИХ СЕРВЕРОВ В КАЧЕСТВЕ СЕРВИСОВ.\rКАК МНЕ ЗАПУСТИТЬ И ОСТАНОВИТЬ XAMPP?\rУНИВЕРСАЛЬНЫЙ ЦЕНТР УПРАВЛЕНИЯ ЭТО \"XAMPP CONTROL PANEL\" (ПАНЕЛЬ УПРАВЛЕНИЯ XAMPP) (БЛАГОДАРЯ WWW.NAT32.COM). ОН ЗАПУСКАЕТСЯ С ПОМОЩЬЮ:\r\\XAMPP\\XAMPP-CONTROL.EXE\rТАКЖЕ ВЫ МОЖЕТЕ ИСПОЛЬЗОВАТЬ НЕКОТОРЫЕ BATCH (*.BAT) ФАЙЛЫ ЧТОБЫ ЗАПУСКАТЬ/ОСТАНАВЛИВАТЬ СЕРВЕРА.\rAPACHE & MYSQL ЗАПУСК:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL ОСТАНОВКА:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE ЗАПУСК:\n\\XAMPP\\APACHE_START.BAT\rОСТАНОВИТЬ APACHE:\n\\XAMPP\\APACHE_STOP.BAT\rЗАПУСТИТЬ MYSQL:\n\\XAMPP\\MYSQL_START.BAT\rОСТАНОВИТЬ MYSQL:\n\\XAMPP\\MYSQL_STOP.BAT\rЗАПУСТИТЬ MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_START.BAT\rОСТАНОВИТЬ MERCURY MAILSERVER:\n\\XAMPP\\MERCURY_STOP.BAT\rЗАПУСТИТЬ СЕРВЕР FILEZILLA:\n\\XAMPP\\FILEZILLA_START.BAT\rОСТАНОВИТЬ СЕРВЕР FILEZILLA:\n\\XAMPP\\FILEZILLA_STOP.BAT\rКАК МНЕ ПРОВЕРИТЬ, ЧТО ВСЁ СРАБОТАЛО?\rВВЕДИТЕ СЛЕДУЮЩУЮ URL В ВАШ ЛЮБИМЫЙ БРАУЗЕР:\rHTTP://LOCALHOST/\rИЛИ \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rКАК МНЕ УСТАНОВИТЬ СКРВЕР КАК СЕРВИС?\rКАЖДЫЙ СЕРВЕР В XAMPP МОЖНО УСТАНОВИТЬ КАК СЕРВИС WINDOWS. ВЫ МОЖЕТЕ СДЕЛАТЬ ЭТО ПРИ ПОМОЩИ XAMPP CONTROL PANEL (ПАНЕЛЬ УПРАВЛЕНИЯ XAMPP). В ТАКОМ СЛУЧАЕ СКРИПТЫ ИЛИ КОНТРОЛЬНАЯ ПАНЕЛЬ ОБЯЗАТЕЛЬНО ДОЛЖНЫ БЫТЬ ЗАПУЩЕНЫ С ПРИВИЛЕГИЯМИ АДМИНИСТРАТОРА.\rУСТАНОВКА СЕРВИСА APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rУДАЛЕНИЕ СЕРВИСА APACHE: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rУСТАНОВКА СЕРВИСА MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rУДАЛЕНИЕ СЕРВИСА MYSQL: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \rУСТАНОВКА ИЛИ УДАЛЕНИЕ СЕРВИСА FILEZILLA: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rДЛЯ MERCURY НЕТ ДОСТУПНОЙ УСТАНОВКИ СЕРВИСА\rГОТОВ ЛИ XAMPP К ПРОИЗВОДСТВЕННОМУ ИСПОЛЬЗОВАНИЮ?\rXAMPP НЕ ПРЕДНАЗНАЧЕН ДЛЯ ПРОИЗВОДСТВЕННОГО ИСПОЛЬЗОВАНИЯ, А ТОЛЬКО ДЛЯ СРЕД РАЗРАБОТКИ. XAMPP НАСТРОЕН ТАКИМ ОБРАЗОМ ЧТОБЫ БЫТЬ КАК МОЖНО БОЛЕЕ ОТКРЫТЫМ И ПОЗВОЛЯТЬ РАЗРАБОТЧИКУ ВСЁ ЧТО ОН/ОНА ЗАХОЧЕТ. ДЛЯ СРЕД РАЗРАБОТКИ ЭТО ПРЕКРАСНО, НО В ПРОИЗВОДСТВЕННОЙ СРЕДЕ ЭТО МОЖЕТ БЫТЬ ПАГУБНО.\rВОТ СПИСОК ОТСУТСТВУЮЩИХ МЕР БЕЗОПАСНОСТИ В XAMPP:\rMYSQL АДМИНИСТРАТОР (ROOT) НЕ ИМЕЕТ ПАРОЛЯ.\rMYSQL СЕРВЕР ДОСТУПЕН ЧЕРЕЗ СЕТЬ.\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rПОЛЬЗОВАТЕЛИ ПО УМОЛЧАНИЮ MERCURY И FILEZILLA ИЗВЕСТНЫ.\rВСЁ ЭТО МОЖЕТ БЫТЬ ОБШИРНЫМ РИСКОМ БЕЗОПАСНОСТИ. ОСОБЕННО ЕСЛИ XAMPP ДОСТУПЕН ЧЕРЕЗ СЕТЬ И ЛЮДЯМ СНАРУЖИ LAN. ИСПОЛЬЗОВАНИЕ БРАНДМАУЭРА (МЕЖСЕТЕВОЙ ЭКРАН) ИЛИ (NAT) МАРШРУТИЗАТОРА МОЖЕТ ПОМОЧЬ. В СЛУЧАЕ С МАРШРУТИЗАТОРОМ ИЛИ БРАНДМАУЭРОМ, ВАШ ПК ОБЫЧНО НЕДОСТУПЕН ЧЕРЕЗ СЕТЬ. РЕШЕНИЕ ЭТИХ ПРОБЛЕМ ЛЕЖИТ НА ВАС. КАК НЕБОЛЬШАЯ ПОМОЩЬ ЕСТЬ КОНСОЛЬ БЕЗОПАСНОСТИ XAMPP (XAMPP SECURITY CONSOLE).\rПОЖАЛУЙСТА ОБЕЗОПАСЬТЕ XAMPP ПРЕЖДЕ ЧЕМ ПУБЛИКОВАТЬ ЧТО-ЛИБО В СЕТИ. ИСПОЛЬЗОВАНИЕ БРАНДМАУЭРА (МЕЖСЕТЕВОЙ ЭКРАН) ИЛИ МАРШРУТИЗАТОРА ДОСТАТОЧНО ЛИШ ДЛЯ НИЗКИХ УРОВНЕЙ БЕЗОПАСНОСТИ. ДЛЯ НЕМНОГО БОЛЬШЕЙ БЕЗОПАСНОСТИ, ВЫ МОЖЕТЕ ЗАПУСТИТЬ КОНСОЛЬ БЕЗОПАСНОСТИ XAMPP (XAMPP SECURITY CONSOLE) И УСТАНОВИТЬ ПАРОЛИ.\rЕСЛИ ВЫ ХОТИТЕ ЧТОБЫ ВАШ XAMPP БЫЛ ДОСТУПЕН ЧЕРЕЗ ИНТЕРНЕТ, ВАМ СЛЕДУЕТ ПОСЕТИТЬ СЛЕДУЮЩУЮ URI КОТОРАЯ МОЖЕТ ИСПРАВИТЬ НЕКОТОРЫЕ ПРОБЛЕМЫ:\rHTTP://LOCALHOST/SECURITY/\rС ПОМОЩЬЮ КОНСОЛИ БЕЗОПАСНОСТИ ВЫ МОЖЕТЕ УСТАНОВИТЬ ПАРОЛЬ ДЛЯ MYSQL ПОЛЬЗОВАТЕЛЯ \"ROOT\" И PHPMYADMIN. ВЫ ТАКЖЕ МОЖЕТЕ ВКЛЮЧИТЬ АУТЕНТИФИКАЦИЮ ДЛЯ ДЕМОНСТРАТИВНЫХ СТРАНИЦ XAMPP.\rЭТОТ ИНСТРУМЕНТ НА ВЕБ-ОСНОВЕ НЕ ИСПРАВЛЯЕТ КАКИЕ-ЛИБО ДОПОЛНИТЕЛЬНЫЕ ПРОБЛЕМЫ БЕЗОПАСНОСТИ! ОСОБЕННО В СЛУЧАЕ С FILEZILLA FTP СЕРВЕРОМ И MERCURY ПОЧТОВЫМ СЕРВЕРОМ, ИХ ВЫ ДОЛЖЫ ОБЕЗОПАСИТЬ САМИ.\rКАК МНЕ УДАЛИТЬ XAMPP?\rЕСЛИ ВЫ УСТАНОВИЛИ XAMPP ИСПОЛЬЗУЯ ВЕРСИЮ С УСТАНОВЩИКОМ, ПОЖАЛУЙСТА ИСПОЛЬЗУЙТЕ ДЕИНСТАЛЛЯТОР. ДЕИНСТАЛЛЯТОР УДАЛИТ ВСЕ ЗАПИСИ XAMPP ИЗ РЕЕСТРА И УДАЛИТ НЕКОТОРЫЕ УСТАНОВЛЕННЫЕ СЕРВИСЫ ВКЛЮЧЕННЫЕ В XAMPP. МЫ НАСТОЙЧИВО РЕКОМЕНДУЕМ ЧТОБЫ ВЫ ИСПОЛЬЗОВАЛИ ДЕИНСТАЛЛЯТОР ДЛЯ УДАЛЕНИЯ УСТАНОВКИ XAMPP С ВЕРСИЕЙ УСТАНОВЩИКА. ПОЖАЛУЙСТА СДЕЛАЙТЕ РЕЗЕРВНОЕ КОПИРОВАНИЕ ВСЕХ ДАННЫХ КОТОРЫЕ ХОТИТЕ СОХРАНИТЬ ПРЕЖДЕ ЧЕМ УДАЛЯТЬ XAMPP.\rЕСЛИ ВЫ УСТАНОВИЛИ XAMPP ИСПОЛЬЗУЯ ZIP ИЛИ 7ZIP ВЕРСИИ, ВЫКЛЮЧИТЕ ВСЕ XAMPP СЕРВЕРА И ВЫЙДИТЕ ИЗ ВСЕХ ПАНЕЛЕЙ. ЕСЛИ ВЫ УСТАНОВИЛИ КАКИЕ-ЛИБО СЕРВИСЫ, УДАЛИТЕ И ОТКЛЮЧИТЕ ИХ ТОЖЕ. ТЕПЕРЬ ПРОСТО УДАЛИТЕ ВЕСЬ КАТАЛОГ ГДЕ УСТАНОВЛЕН XAMPP. В ДАННОМ СЛУЧАЕ ЗАПИСЕЙ В РЕГИСТРЕ И ПЕРЕМЕННЫХ СРЕДЫ ТРЕБУЮЩИХ ЧИСТКУ НЕТ.\rЧТО ТАКОЕ \"LITE\" (ЛЁГКАЯ) ВЕРСИЯ XAMPP?\rXAMPP LITE (ЗНАЧИТ \"ЛЁГКИЙ\" КАК В \"ЛЁГКИЙ ВЕС\") ЭТО МЕНЬШИЙ НАБОР XAMPP КОМПОНЕНТОВ, ЧТО РЕКОМЕНДУЕТСЯ ДЛЯ БЫСТРОЙ РАБОТЫ ГДЕ ТРЕБУЕТСЯ ТОЛЬКО PHP И MYSQL. НЕКОТОРЫЕ СЕРВЕРА ИЛИ ИНСТРУМЕНТЫ КАК MERCURY MAIL И FILEZILLA FTP ОТСУТСТВУЮТ В LITE ВЕРСИИ.\rГДЕ МНЕ СЛЕДУЕТ ПОМЕСТИТЬ МОЁ ВЕБ СОДЕРЖИМОЕ?\rГЛАВНЫЙ КАТАЛОГ ДЛЯ ВСЕХ WWW ДОКУМЕНТОВ ЭТО \\\\XAMPP\\\\HTDOCS. ЕСЛИ ВЫ ПОЛОЖИТЕ ФАЙЛ \"TEST.HTML\" В ЭТОТ КАТАЛОГ, ВЫ СМОЖЕТЕ ПОЛУЧИТЬ ДОСТУП К НЕМУ ПО URI \"HTTP://LOCALHOST/TEST.HTML\".\rИ \"TEST.PHP\"? ПРОСТО ИСПОЛЬЗУЙТЕ \"HTTP://LOCALHOST/TEST.PHP\". ПРОСТОЙ ТЕСТ-СКРИТП МОЖЕТ БЫТЬ:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rНОВАЯ СУБ-КАТАЛОГ ДЛЯ ВАШЕГО ВЕБ ПРОЕКТА? ПРОСТО СОЗДАЙТЕ НОВЫЙ КАТАЛОГ (ПРИМЕР: \"NEW\") ВНУТРИ КАТАЛОГА \"\\\\XAMPP\\\\HTDOCS\" (ЖЕЛАТЕЛЬНО БЕЗ ПРОБЕЛОВ И С ИСПОЛЬЗОВАНИЕМ ТОЛЬКО ASCII), СОЗДАЙТЕ ФАЙЛ \"TEST.PHP\" В ЭТОМ КАТАЛОГЕ, ВЫ СМОЖЕТЕ ПОЛУЧИТЬ ДОСТУП К НЕМУ ПО URI \"HTTP://LOCALHOST/NEW/TEST.PHP\".\rДОПОЛНИТЕЛЬНЫЕ ОСОБЕННОСТИ\rHTML:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\HTDOCS\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .HTML .HTM\r=> БАЗОВЫЙ ПАКЕТ\rSSI:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\HTDOCS\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .SHTML\r=> БАЗОВЫЙ ПАКЕТ\rCGI:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .CGI\r=> БАЗОВЫЙ ПАКЕТ\rPHP:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .PHP\r=> БАЗОВЫЙ ПАКЕТ\rPERL:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .PL\r=> БАЗОВЫЙ ПАКЕТ\rAPACHE::ASP PERL:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\HTDOCS\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .ASP\r=> БАЗОВЫЙ ПАКЕТ\rJSP JAVA:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rИСПОЛНЯЕМЫЙ ФАЙЛ: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rРАЗРЕШЁННЫЕ ОКОНЧАНИЯ: .HTML (U.A)\r=> TOMCAT ADD-ON\rКАК МНЕ ПЕРЕМЕСТИТЬ УСТАНОВКУ XAMPP?\rДА. ПОСЛЕ ПЕРЕМЕЩЕНИЯ КАТАЛОГА XAMPP, ВЫ ДОЛЖНЫ ВЫПОЛНИТЬ \"SETUP_XAMPP.BAT\". ПУТИ В ФАЙЛАХ КОНФИГУРАЦИИ БУДУТ ПОПРАВЛЕНЫ ПРИ ВЫПОЛНЕНИИ ЭТОГО ШАГА.\rЕСЛИ ВЫ УСТАНОВИЛИ ЛЮБОЙ СЕРВЕР КАК WINDOWS СЕРВИС, СНАЧАЛА ВЫ ДОЛЖНЫ УДАЛИТЬ WINDOWS СЕРВИС, А ПОСЛЕ ПЕРЕМЕЩЕНИЯ ВЫ МОЖЕТЕ СНОВА УСТАНОВИТЬ СЕРВИС.\rПРЕДУПРЕЖДЕНИЕ: ФАЙЛЫ КОНФИГУРАЦИИ ИЗ ВАШИХ СКРИПТОВ, К ПРИМЕРУ PHP ПРИЛОЖЕНИЯ, НЕ НАСТРОЕНЫ. НО ВОЗМОЖНО НАПИСАТЬ ПЛАГИН ДЛЯ УСТАНОВЩИКА. С ТАКИМ ПЛАГИНОМ УСТАНОВЩИК МОЖЕТ НАСТРОИТЬ И ЭТИ ФАЙЛЫ.\rЧТО ТАКОЕ \"AUTOMATIC START PAGES\" (СТРАНИЦЫ АВТОМАТИЧЕСКОГО ЗАПУСКА) ДЛЯ WWW КАТАЛОГОВ?\rСТАНДАРТНОЕ ИМЯ ФАЙЛА ДЛЯ ФУНКЦИИ APACHE \"DIRECTORYINDEX\" ЭТО \"INDEX.HTML\" ИЛИ \"INDEX.PHP\". КАЖДЫЙ РАЗ КОГДА ВЫ ОТКРЫВАЕТЕ В БРАУЗЕРЕ ПАПКУ (ПРИМЕР: \"HTTP://LOCALHOST/XAMPP/\"), И APACHE СМОЖЕТ НАЙТИ ТАКОЙ ФАЙЛ, APACHE ОТОБРАЗИТ ЭТОТ ФАЙЛ ВМЕСТО СПИСКА СОДЕРЖИМОГО КАТАЛОГА.\rГДЕ Я МОГУ ПОМЕНЯТЬ НАСТРОЙКИ?\rПОЧТИ ВСЕ НАСТРОЙКИ В XAMPP ВЫ МОЖЕТЕ ПОМЕНЯТЬ ПРИ ПОМОЩИ ФАЙЛОВ КОНФИГУРАЦИИ. ПРОСТО ОТКРОЙТЕ ФАЙЛ В ТЕКСТОВОМ РЕДАКТОРЕ И ИЗМЕНИТЕ ЧТО ЖЕЛАЕТЕ. ТОЛЬКО FILEZILLA И MERCURY ДОЛЖНЫ БЫТЬ НАСТРОЕНЫ ПРИ ПОМОЩИ ПРОГРАМНОГО ИНСТРУМЕНТА КОНФИГУРАЦИИ.\rПОЧЕМУ XAMPP НЕ МОЖЕТ РАБОТАТЬ НА WINDOWS XP SP2?\rMICROSOFT ПРЕДОСТАВЛЯЕТ БОЛЕЕ ХОРОШИЙ БРАНДМАУЭР (МЕЖСЕТЕВОЙ ЭКРАН) С СЕРВИС ПАКОМ 2 (SP2), КОТОРЫЙ ЗАПУСКАЕТСЯ АВТОМАТИЧЕСКИ. ЭТОТ БРАНДМАУЭР ТЕПЕРЬ БЛОКИРУЕТ НЕОБХОДИМЫЕ ПОРТЫ 80 (HTTP) И 443 (HTTPS) И APACHE НЕ МОЖЕТ ЗАПУСТИТСЯ.\rБЫСТРОЕ РЕШЕНИЕ:\rОТКЛЮЧИТЕ БРАНДМАУЭР (МЕЖСЕТЕВОЙ ЭКРАН) И ПОПРОБУЙТЕ ЗАПУСТИТЬ XAMPP ЕЩЁ РАЗ. ЛУЧШЕЕ РЕШЕНИЕ: УКАЗАТЬ ИСКЛЮЧЕНИЕ В ЦЕНТРЕ БЕЗОПАСНОСТИ.\rСЛЕДУЮЩИЕ ПОРТЫ ИСПОЛЬЗУЮТСЯ ДЛЯ БАЗОВОЙ ФУНКЦИОНАЛЬНОСТИ:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rПОЧЕТУ XAMPP НЕ РАБОТАЕТ НА WINDOWS VISTA?\rКОНТРОЛЬ УЧЁТНЫХ ЗАПИСЕЙ ПОЛЬЗОВАТЕЛЕЙ (UAC)\rВЫ НЕ ИМЕЕТЕ ПОЛНЫХ ПРИВИЛЕГИЙ ЗАПИСИ В КАТАЛОГЕ \"C:\\\\PROGRAM FILES\", ДАЖЕ КАК АДМИНИСТРАТОР. ИЛИ У ВАС ТОЛЬКО ОГРАНИЧЕННЫЕ ПРИВИЛЕГИИ (К ПРИМЕРУ ТОЛЬКО ДЛЯ \".\\\\XAMPP\\\\HTDOCS\"). В ТАКОМ СЛУЧАЕ ВЫ НЕ МОЖЕТЕ РЕДАКТИРОВАТЬ ФАЙЛ.\rРЕШЕНИЕ:\rПОВЫСЬТЕ СВОИ ПРИВИЛЕГИИ В ПРОВОДНИКЕ (ПРАВЫЙ КЛИК / БЕЗОПАСНОСТЬ) ИЛИ ОТКЛЮЧИТЕ КОНТРОЛЬ УЧЁТНЫХ ЗАПИСЕЙ ПОЛЬЗОВАТЕЛЕЙ (UAC).\rВЫ УСТАНОВИЛИ APACHE/MYSQL В \"C:\\\\XAMPP\" КАК WINDOWS СЕРВИС. НО ВЫ НЕ МОЖЕТЕ ЗАПУСКАТЬ/ОСТАНАВЛИВАТЬ СЕРВИСЫ ПРИ ПОМОЩИ ПАНЕЛИ УПРАВЛЕНИЯ XAMPP (XAMPP CONTROL PANEL) ИЛИ НЕ МОЖЕТЕ ИХ УДАЛИТЬ.\rРЕШЕНИЕ:\rИСПОЛЬЗУЙТЕ КОНСОЛЬ УПРАВЛЕНИЯ СЕРВИСАМИ ОТ WINDOWS ИЛИ ОТКЛЮЧИТЕ UAC.\rОТКЛЮЧЕНИЕ КОНТРОЛЯ УЧЁТНЫХ ЗАПИСЕЙ ПОЛЬЗОВАТЕЛЕЙ (UAC)\rЧТОБЫ ОТКЛЮЧИТЬ UAC, ИСПОЛЬЗУЙТЕ ПРОГРАММУ \"MSCONFIG\". В \"MSCONFIG\" ЗАИДИТЕ В \"TOOLS\" (ИНСТРУМЕНТЫ), ВЫБЕРИТЕ \"DISABLE USER ACCOUNT CONTROL\" (ОТКЛЮЧИТЬ КОНТРОЛЬ УЧЁТНЫХ ЗАПИСЕЙ ПОЛЬЗОВАТЕЛЕЙ) И ПОДТВЕРДИТЕ СВОЙ ВЫБОР. ТЕПЕРЬ ВЫ ДОЛЖНЫ ПЕРЕЗАПУСТИТЬ WINDOWS. ВЫ МОЖЕТЕ ВКЛЮЧИТЬ UAC СНОВА.\rКАК МНЕ ПРОВЕРИТЬ КОНТРОЛЬНУЮ СУММУ MD5?\rЧТОБЫ СРАВНИТЬ ФАЙЛЫ, ЧАСТО ИСПОЛЬЗУЮТСЯ КОНТРОЛЬНЫЕ СУММЫ. СТАНДАРТ ЧТОБЫ СОЗДАТЬ ТАКУЮ КОНТРОЛЬНУЮ СУММУ MD5 (MESSAGE DIGEST ALGORITHM 5).\rПРИ ПОМОЩИ КОНТРОЛЬНОЙ СУММЫ MD5 ВЫ МОЖЕТЕ ПРОВЕРИТЬ, СООТВЕТСТВУЕТ ЛИ ОРИГИНАЛУ СКАЧАННЫЙ ВАМИ ПАКЕТ XAMPP. ЕСТЕСТВЕННО ВАМ ПОТРЕБУЕТСЯ ПРОГРАММА СПОСОБНАЯ СОЗДАВАТЬ ТАКИЕ КОНТРОЛЬНЫЕ СУММЫ. ДЛЯ WINDOWS ВЫ МОЖЕТЕ ИСПОЛЬЗОВАТЬ ИНСТРУМЕНТ ОТ MICROSOFT:\rДОСТУПНОСТЬ И ОПИСАНИЕ УТИЛИТЫ ПРОВЕРКИ ЦЕЛОСТНОСТИ КОНТРОЛЬНЫХ СУММ ФАЙЛОВ\rТАКЖЕ ВОЗМОЖНО ИСПОЛЬЗОВАТЬ ЛЮБУЮ ДРУГУЮ ПРОГРАММУ СПОСОБНУЮ СОЗДАВАТЬ MD5 КОНТРОЛЬНЫЕ СУММЫ, КАК GNU MD5SUM.\rКОГДА ВЫ УСТАНОВИЛИ ТАКУЮ ПРОГРАММУ (ПРИМЕР: FCIV.EXE), ВЫ МОЖЕТЕ ВЫПОЛНИТЬ СЛЕДУЮЩИЕ ШАГИ:\rСКАЧАТЬ XAMPP (F.E. XAMPP-WIN32-1.8.2-0.EXE)\rСОЗДАТЬ КОНТРОЛЬНУЮ СУММУ С:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rТЕПЕРЬ ВЫ МОЖЕТЕ СРАВНИТЬ ЭТУ КОНТРОЛЬНУЮ СУММУ С ТОЙ КОТОРУЮ МОЖЕТЕ НАЙТИ НА ДОМАШНЕЙ СТРАНИЦЕ XAMPP ДЛЯ WINDOWS.\rЕСЛИ ОБЕ КОНТРОЛЬНЫЕ СУММЫ РАВНЫ, ВСЁ ХОРОШО. ЕСЛИ НЕТ, СКАЧИВАНИЕ ОБЕРНУЛОСЬ ПРОВАЛОМ ИЛИ ФАЙЛ БЫЛ ИЗМЕНЁН.\rПОЧЕМУ ИЗМЕНЕНИЯ В МОЁМ PHP.INI НЕ ВСТУПАЮТ В ДЕЙСТВИЕ?\rЕСЛИ ИЗМЕНЕИЕ В \"PHP.INI\" НЕ ВСТУПИЛО В ДЕЙСТВИЕ, ВОЗМОЖНО PHP ИСПОЛЬЗУЕТ ДРУГОЙ ФАЙЛ. ВЫ МОЖЕТЕ ПРОВЕРИТЬ ЭТО ПРИ ПОМОЩИ PHPINFO(). ПОСЛЕДУЙТЕ ПО URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP И ИЩИТЕ \"LOADED CONFIGURATION FILE\" (ЗАГРУЖЕННЫЙ ФАЙЛ КОНФИГУРАЦИИ). ЭТО ЗНАЧЕНИЕ ПОКАЖЕТ КАКОЙ \"PHP.INI\" PHP ДЕЙСТВИТЕЛЬНО ИСПОЛЬЗУЕТ.\rПРИМЕЧАНИЕ:\rПОСЛЕ ИЗМЕНЕНИЯ \"PHP.INI\" ВЫ ДОЛЖНЫ ПЕРЕЗАПУСТИТЬ APACHE ЧТОБЫ APACHE/PHP СМОГЛИ СЧИТАТЬ НОВЫЕ НАСТРОЙКИ.\rПОМОГИТЕ! В XAMPP ЕСТЬ ВИРУС!\rНЕКОТОРЫЕ АНТИ-ВИРУСНЫЕ ПРОГРАММЫ ПО ОШИБКЕ ПРИНИМАЮТ XAMPP ЗА ВИРУС, ОБЫЧНО ОТМЕЧАЯ ФАЙЛ XAMPP-MANAGER.EXE. ЭТО ЛОЖНАЯ ТРЕВОГА, ЧТО ОЗНАЧАЕТ АНТИ-ВИРУС ОШИБОЧНО ПРИНЯЛ ЗА ВИРУС ТО ЧТО ИМ НЕ ЯВЛЯЕТСЯ. ПРЕЖЛЕ ЧЕМ МЫ ПУБЛИКУЕМ КАЖДУЮ НОВУЮ ВЕРСИЮ XAMPP МЫ СКАНИРУЕМ ЕГО НА ВИРУСЫ. В ДАННЫЙ МОМЕНТ МЫ ИСПОЛЬЗУЕМ \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rКАК МНЕ НАСТРОИТЬ МОЁ АНТИ-ВИРУСНОЕ ПРИЛОЖЕНИЕ?\rМЫ ВКЛЮЧИЛИ ВСЕ ЗАВИСИМОСТИ И СЕРВЕРА ТРЕВУЕМЫЕ ДЛЯ РАБОТЫ ПАКЕТА ВЕБ ПРИЛОЖЕНИЯ, ПОЭТОМУ XAMPP УСТАНАВЛИВАЕТ БОЛЬШОЕ КОЛИЧЕСТВО ФАЙЛОВ. ЕСЛИ ВЫ УСТАНАВЛИВАЕТЕ XAMPP НА WINDOWS МАШИНЕ СО ВКЛЮЧЕННЫМ АНТИ-ВИРУСОМ, ЭТО МОЖЕТ ЗНАЧИТЕЛЬНО ЗАМЕДЛИТЬ УСТАНОВКУ, И ЕЩЁ ЕСТЬ ШАНС ЧТО ОДИН ИЗ СЕРВЕРОВ (ВЕБ СЕРВЕР, СЕРВЕР БАЗ ДАННЫХ) МОЖЕТ БЫТЬ ЗАБЛОКИРОВАН АНТИ-ВИРУСНЫМ ПО. ЕСЛИ ВАШ ЕСТЬ АНТИ-ВИРУС ВКЛЮЧЁН, ПРОВЕРЬТЕ СЛЕДУЮЩИЕ НАСТРОЙКИ ДЛЯ ЗАПУСКА XAMPP БЕЗ ПРОБЛЕМ С ПРОИЗВОДИТЕЛЬНОСТЬЮ:\rДОБАВЬТЕ ИСКЛЮЧЕНИЯ В БРАНДМАУЭР (МЕЖСЕТЕВОЙ ЭКРАН): ДЛЯ APACHE, MYSQL ИЛИ ЛЮБОГО ДРУГОГО СЕРВЕРА.\rСКАНИРОВАНИЕ ФАЙЛОВ ВО ВРЕМЯ РВБОТЫ: ЕСЛИ ВЫ ВКЛЮЧИЛИ В АНТИ-ВИРУСНОМ ПО СКАНИРОВАНИЕ ВСЕХ ФАЙЛОВ, РАБОТА ИСПОЛНИТЕЛЬНЫХ ФАЙЛОВ СЕРВЕРОВ МОЖЕТ ЗАМЕДЛИТСЯ.\rСКАНИРОВАНИЕ ТРАФИКА ДЛЯ РАЗНЫХ URL: ЕСЛИ ВЫ РАЗРАБАТЫВАЕТЕ С ИСПОЛЬЗОВАНИЕМ XAMPP НА СВОЕЙ СОБСТВЕННОЙ МАШИНЕ, ВЫ МОЖЕТЕ ИСКЛЮЧИТЬ ПРОВЕРКУ ТРАФИКА ДЛЯ \"LOCALHOST\" В НАСТРОЙКАХ ВАШЕГО АНТИ-ВИРУСА.\rПОЧЕМУ APACHE СЕРВЕР НЕ ЗАПУСКАЕТСЯ НА МОЕЙ СИСТЕМЕ?\rЭТО ПРОБЛЕМА МОЖЕТ ИМЕТЬ МЕСТО ПО ОДНОЙ ИЗ НЕСКОЛЬКИХ ПРИЧИН:\rВЫ ЗАПУСТИЛИ БОЛЕЕ ОДНОГО HTTP SERVER (IIS, SAMBAR, ZEUS И ТАК ДАЛЕЕ). ТОЛЬКО ОДИН СЕРВЕР МОЖЕТ ИСПОЛЬЗОВАТЬ ПОРТ 80. ЭТО СООБЩЕНИЕ ОБ ОШИБКЕ УКАЗЫВАЕТ НА ПРОБЛЕМУ:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rУ ВАС ЕСТЬ ДРУГОЕ ПО, НАПРИМЕР ИНТЕРНЕТ ТЕЛЕФОН \"SKYPE\" (СКАЙП) КОТОРОЕ ТОЖЕ БЛОКИРУЕТ ПОРТ 80. ЕСЛИ ПРОБЛЕМА В \"SKYPE\", В SKYPE ВЫ МОЖЕТЕ ОТКРЫТЬ ACTIONS (ДЕЙСТВИЯ) --> OPTIONS (ОПЦИИ) --> CONNECTION (СОЕДИНЕНИЕ) --> УБРАТЬ ГАЛОЧКУ РЯДОМ С \"USE PORT 80 FOR AN ALTERNATE PORT\" (ИСПОЛЬЗОВАТЬ ПОРТ 80 ДЛЯ АЛЬТЕРНАТИВНОГО ПОРТА) И ПЕРЕЗАПУСТИТЬ SKYPE. ТЕПЕРЬ ВСЁ ДОЛЖНО РАБОТАТЬ.\rУ ВАС ЕСТЬ БРАНДМАУЭР (МЕЖСЕТЕВОЙ ЭКРАН) КОТОРЫЙ БЛОКИРУЕТ ПОРТ APACHE. НЕ КАЖДЫЙ БРАНДМАУЭР СОВМЕСТИМ С APACHE, ИНОГДА ОТКЛЮЧИТЬ БРАНДМАУЭР НЕДОСТАТОЧНО И ВАМ ПРИДЁТСЯ ЕГО УДАЛИТЬ. ЭТО СООБЩЕНИЕ ОБ ОШИБКЕ УКАЗЫВАЕТ НА БРАНДМАУЭР:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rТАКЖЕ ЕСЛИ APACHE МОЖЕТ ЗАПУСТИТСЯ, НО ВАШ БРАУЗЕР НЕ МОЖЕТ СОЕДИНИТСЯ С НИМ ЭТО МОЖЕТ БЫТЬ ПО ОДНОЙ ИЗ СЛЕДУЮЩИХ ПРИЧИН:\rНЕКОТОРЫЕ АНТИ-ВИРУСНЫЕ ПРОГРАММЫ МОГУТ ВЫЗВАТЬ ЭТО, ТАКИМ ЖЕ ОБРАЗОМ КАК МОЖЕТ ВМЕШАТСЯ БРАНДМАУЭР (МЕЖСЕТЕВОЙ ЭКРАН).\rУ ВАС XP PROFESSIONAL БЕЗ СЕРВИС ПАКА 1. ВЫ ДОЛЖНЫ ИМЕТЬ КАК МИНИМУМ SP1 ДЛЯ XAMPP.\rСОВЕТ:\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\rПОЧЕМУ APACHE ГРУЗИТ МОЙ ПРОЦЕССОР ПОЧТИ НА 99%?\rВ ДАННОМ СЛУЧАЕ ДЕЙСТВУЕТ ОДИН ИЗ ДВУХ СЦЕНАРИЕВ. ЛИБО ВАШ ПРОЦЕССОР РАБОТАЕТ НА ПРЕДЕЛЕ СВОИХ ВОЗМОЖНОСТЕЙ, ИЛИ ВЫ МОЖЕТЕ ПОДСОЕДЕНИТСЯ К СЕРВЕРУ ЧЕРЕЗ БРАУЗЕР, НО НИЧЕГО НЕ ВИДИТЕ (СИСТЕМА БЕЗУСПЕШНО ПЫТАЕТСЯ ЗАГРУЗИТЬ СТРАНИЦУ). В ЛЮБОМ СЛУЧАЕ ВЫ МОЖЕТЕ НАЙТИ СЛЕДУЮЩЕЕ СООБЩЕНИЕ В ЛОГ ФАЙЛЕ APACHE:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rMPM ВОЗВРАЩАЕТСЯ К БОЛЕЕ БЕЗОПАСНОМУ ВЫПОЛНЕНИЮ, НО НЕКОТОРЫЕ КЛИЕНТСКИЕ ЗАПРОСЫ НЕ ОБРАБАТЫВАЛИСЬ КОРРЕКТНО. ДЛЯ ТОГО ЧТОБЫ ИЗБЕЖАТЬ ЭТОЙ ОШИБКИ, ИСПОЛЬЗУЙТЕ \"ACCEPTFILTER\" С ВКЛЮЧЕННЫМ ФИЛЬТРОМ \"NONE\" В ФАЙЛЕ \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\".\rПОЧЕМУ КАРТИНКИ И ТАБЛИЦЫ СТИЛЕЙ НЕ ОТОБРАЖАЮТСЯ?\rИНОГДА ВОЗНИКАЮТ ПРОБЛЕМЫ С ОТОБРАЖЕНИЕМ КАРТИНОК И ТАБЛИЦ СТИЛЕЙ. ОСОБЕННО, ЕСЛИ ЭТИ ФАЙЛЫ НАХОДЯТСЯ НА СЕТЕВОМ ДИСКЕ. В ЭТОМ СЛУЧАЕ ВЫ МОЖЕТЕ ВКЛЮЧИТЬ (ИЛИ ДОБАВИТЬ) ОДНУ ИЗ СЛЕДУЮЩИХ СТРОК В ФАЙЛЕ \"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rЭТА ПРОБЛЕМА ТАКЖЕ МОЖЕТ БЫТЬ ВЫЗВАНА ПРОГРАММАМИ РЕГУЛИРОВАНИЯ ПОЛОСЫ ПРОПУСКАНИЯ, НАПРИМЕР, NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rПЕРЕЗАПУСТИТЕ СЕРВЕР APACHE, ИСПОЛЬЗУЯ ПАНЕЛЬ УПРАВЛЕНИЯ XAMPP.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rКАК Я МОГУ УСТАНОВИТЬ ПАРОЛЬ ROOT\'А В MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rМОГУ ЛИ Я ИСПОЛЬЗОВАТЬ СВОЙ СОБСТВЕННЫЙ MYSQL СЕРВЕР?\rДА. ПРОСТО НЕ ЗАПУСКАЙТЕ MYSQL ИЗ ПАКЕТА XAMPP. ОБРАТИТЕ ВНИМАНИЕ, ЧТО ДВА СЕРВЕРА НЕ МОГУТ БЫТЬ ЗАПУЩЕНЫ НА ТОМ ЖЕ ПОРТУ. ЕСЛИ ВЫ УСТАНОВИЛИ ПАРОЛЬ ДЛЯ \"ROOT\", ПОЖАЛУЙСТА, НЕ ЗАБУДЬТЕ ОТРЕДАКТИРОВАТЬ ФАЙЛ \"\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP\".\rКАК ОГРАНИЧИТЬ ДОСТУП К PHPMYADMIN ИЗВНЕ?\rВ БАЗОВОЙ КОНФИГУРАЦИИ XAMPP PHPMYADMIN ДОСТУПЕН ТОЛЬКО С ТОГО ЖЕ ХОСТА, НА КОТОРОМ ЗАПУЩЕН XAMPP, ПО АДРЕСУ \rHTTP://127.0.0.1\rИЛИ \rHTTP://LOCALHOST\r.\rПРЕЖДЕ ЧЕМ ВЫ СМОЖЕТЕ ПОЛУЧИТЬ ДОСТУП К СЕРВЕРУ MYSQL, PHPMYADMIN ЗАПРОСИТ У ВАС ИМЯ ПОЛЬЗОВАТЕЛЯ И ПАРОЛЬ. НЕ ЗАБУДЬТЕ УСТАНОВИТЬ ПАРОЛЬ ДЛЯ \"ROOT\" ПОЛЬЗОВАТЕЛЯ В ПЕРВУЮ ОЧЕРЕДЬ.\rКАК МНЕ ВКЛЮЧИТЬ ДОСТУП К PHPMYADMIN ИЗВНЕ?\rВ БАЗОВОЙ КОНФИГУРАЦИИ XAMPP PHPMYADMIN ДОСТУПЕН ТОЛЬКО С ТОГО ЖЕ ХОСТА, НА КОТОРОМ ЗАПУЩЕН XAMPP, ПО АДРЕСУ \rHTTP://127.0.0.1\rИЛИ \rHTTP://LOCALHOST\r.\rВАЖНО: ВКЛЮЧЕНИЕ ВНЕШНЕГО ДОСТУПА ДЛЯ PHPMYADMIN В ПРОИЗВОДСТВЕННЫХ СРЕДАХ ПРЕДСТАВЛЯЕТ СОБОЙ ЗНАЧИТЕЛЬНЫЙ РИСК ДЛЯ БЕЗОПАСНОСТИ. ВАМ НАСТОЯТЕЛЬНО РЕКОМЕНДУЕТСЯ РАЗРЕШАТЬ ДОСТУП ТОЛЬКО С LOCALHOST. УДАЛЕННЫЙ ЗЛОУМЫШЛЕННИК МОЖЕТ ВОСПОЛЬЗОВАТЬСЯ ЛЮБОЙ СУЩЕСТВУЮЩЕЙ УЯЗВИМОСТЬЮ ДЛЯ ВЫПОЛНЕНИЯ КОДА ИЛИ ИЗМЕНЕНИЯ ВАШИХ ДАННЫХ.\rЧТОБЫ ВКЛЮЧИТЬ УДАЛЁННЫЙ ДОСТУП К PHPMYADMIN, СЛЕДУЙТЕ ШАГАМ НИЖЕ:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rВ ЭТОМ ФАЙЛЕ, НАЙДИТЕ СТРОКИ, УКАЗАННЫЕ СНИЗУ. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nЗАТЕМ, ЗАМЕНИТЕ \'REQUIRE LOCAL\' НА \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nПЕРЕЗАПУСТИТЕ СЕРВЕР APACHE, ИСПОЛЬЗУЯ ПАНЕЛЬ УПРАВЛЕНИЯ XAMPP.\rГДЕ ПОДДЕРЖКА IMAP ДЛЯ PHP?\rПО УМОЛЧАНИЮ, ПОДДЕРЖКА IMAP ДЛЯ PHP ОТКЛЮЧЕНА В XAMPP ИЗ-ЗА НЕКОТОРЫХ ЗАГАДОЧНЫХ ОШИБОК ИНИЦИАЛИЗАЦИИ В НЕКОТОРЫХ ДОМАШНИХ ВЕРСИЯХ, НАПРИМЕР, WINDOWS 98. ЕСЛИ ВЫ РАБОТАЕТЕ С СИСТЕМАМИ NT, ВЫ МОЖЕТЕ ОТКРЫТЬ ФАЙЛ \"\\\\XAMPP\\\\PHP\\\\PHP.INI\", ЧТОБЫ АКТИВИРОВАТЬ PHP РАСШИРЕНИЕ, УДАЛИВ ТОЧКУ С ЗАПЯТОЙ В СТРОКЕ \";EXTENSION=PHP_IMAP.DLL\". ОНА ДОЛЖНА БЫТЬ:\rEXTENSION=PHP_IMAP.DLL\rТЕПЕРЬ ПЕРЕЗАГРУЗИТЕ APACHE, И IMAP ДОЛЖЕН РАБОТАТЬ. ВЫ МОЖЕТЕ ИСПОЛЬЗОВАТЬ ТЕ ЖЕ САМЫЕ ШАГИ ДЛЯ ЛЮБОГО РАСШИРЕНИЯ, КОТОРОЕ НЕ ВКЛЮЧЕНО В КОНФИГУРАЦИИ ПО УМОЛЧАНИЮ.\rПОЧЕМУ НЕКОТОРЫЕ PHP ПРИЛОЖЕНИЯ С ОТКРЫТЫМ ИСХОДНЫМ КОДОМ РАБОТАЮТ С XAMPP НА WINDOWS?\rМНОГО PHP ПРИЛОЖЕНИЙ ИЛИ РАСШИРЕНИЙ, КОТОРЫЕ БЫЛИ НАПИСАНЫ ДЛЯ LINUX НЕ БЫЛИ ПОРТИРОВАНЫ НА WINDOWS. \rCAN I DELETE THE \"INSTALL\" DIRECTORY AFTER INSTALLATION?\rЛУЧШЕ ЭТОГО НЕ ДЕЛАТЬ. ЭТИ СКРИПТЫ ЕЩЁ НУЖНЫ ДЛЯ ВСЕХ ДОПОЛНИТЕЛЬНЫХ ПАКЕТОВ (ДОПОЛНЕНИЙ) И ОБНОВЛЕНИЙ XAMPP.\rКАК МНЕ АКТИВИРОВАТЬ EACCELERATOR?\rКАК И ДРУГИЕ (ZEND) РАЗРЕШЕНИЯ, ВЫ МОЖЕТЕ АКТИВИРОВАТЬ ЕГО В \"PHP.INI\". В ЭТОМ ФАЙЛЕ, ИЗМЕНИТЕ СТРОКУ \";ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"\". ОНА ДОЛЖНА БЫТЬ:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rКАК МНЕ ИСПРАВИТЬ ОШИБКУ СОЕДИНЕНИЯ С МОИМ MS SQL СЕРВЕРОМ?\rЕСЛИ MSSQL РАСШИРЕНИЕ БЫЛО ЗАГРУЖЕНО В PHP.INI, ИНОГДА ВОЗНИКАЮТ ПРОБЛЕМЫ КОГДА ИСПОЛЬЗУЕТСЯ ТОЛЬКО TCP/IP. ВЫ МОЖЕТЕ ИСПРАВИТЬ ЭТУ ПРОБЛЕМУ ПРИ ПОМОЩИ БОЛЕЕ НОВОЙ \"NTWDBLIB.DLL\" ОТ MICROSOFT. ПОЖАЛУЙСТА ЗАМЕНИТЕ СТАРЫЙ ФАЙЛ В \"\\\\XAMPP\\\\APACHE\\\\BIN\" И \"\\\\XAMPP\\\\PHP\" БОЛЕЕ НОВЫМ. ИЗ ЗА УСЛОВИЙ ЛИЦЕНЗИИ, МЫ НЕ МОЖЕМ ВКЛЮЧИТЬ БОЛЕЕ НОВУЮ ВЕРСИЮ ФАЙЛА В XAMPP.\rКАК МНЕ РАБОТАТЬ С PHP MCRYPT РАСШИРЕНИЕМ?\rДЛЯ ЭТОГО, МЫ ОТКРЫЛИ ПРЕДМЕТ ОБСУЖДЕНИЯ НА ФОРУМЕ С ПРИМЕРАМИ И ВОЗМОЖНЫМИ РЕШЕНИЯМИ: \rMCRYPT ТОПИК\rMICROSOFT ACTIVE SERVER PAGES (ASP) РАБОТАЮТ С XAMPP?\rНЕТ. И APACHE::ASP С PERL ДОПОЛНЕНИЕМ НЕ ТО ЖЕ САМОЕ. APACHE::ASP РАСПОЗНАЁТ ТОЛЬКО PERL-SCRIPT, А ASP ИЗ INTERNET INFORMATION SERVER (IIS) ТАКЖЕ РАСПОЗНАЁТ ОБЫЧНЫЙ VBSCRIPT. НО ДЛЯ ASP .NET, СУЩЕСТВУЕТ СТОРОННИЙ APACHE МОДУЛЬ.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rФАЙЛЫ КОНФИГУРАЦИИ APACHE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rБЛОГ\rПОЛИТИКА ПРИВАТНОСТИ\rCDN ПРЕДУСМОТРЕНО\r\n'),(82,'fbed4726c228b134456675ce3889e83b','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rЧАВО\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rБЛОГ\rПОЛИТИКА ПРИВАТНОСТИ\rCDN ПРЕДУСМОТРЕНО\r\n'),(83,'a9b499d8a602f1a595b31c4ab4fd9b5b','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rЧАВО\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rБЛОГ\rПОЛИТИКА ПРИВАТНОСТИ\rCDN ПРЕДУСМОТРЕНО\r\n'),(84,'bb2a832ab018f0315bebd3231bf67554','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rЧАВО\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rБЛОГ\rПОЛИТИКА ПРИВАТНОСТИ\rCDN ПРЕДУСМОТРЕНО\r\n'),(85,'bbe6c3298c8cfca48cc774a2c15b925e','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rЧАВО\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rЧАВО\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nСООБЩЕСТВО\rXAMPP СУЩЕСТВУЕТ УЖЕ БОЛЕЕ 10 ЛЕТ  ОГРОМНОЕ СООБЩЕСТВО РАБОТАЕТ НАД НИМ. ВЫ МОЖЕТЕ ПРИНЯТЬ УЧАСТИЕ, ПРИСОЕДИНИВШИСЬ К НАШЕМУ \rФОРУМЫ\r, И ЛАЙКНУВ НАС НА \rFACEBOOK\rИЛИ СЛЕДУЯ НАШИМ ТВИТАМ НА \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rБЛОГ\rПОЛИТИКА ПРИВАТНОСТИ\rCDN ПРЕДУСМОТРЕНО\r\n'),(86,'d349a5a3152b50983385271d9b1bfe49','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rSSS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rSIKÇA SORULAN SORULAR\rXAMPP\'I NASIL YÜKLERIM?\rWINDOWS IÇIN XAMPP ÜÇ FARKLI ÇEŞITTE BULUNMAKTADIR:\rYÜKLEYICI:\rMUHTEMELEN XAMPP\'I YÜKLEMEK IÇIN EN KOLAY YOL.\rZIP:\rSADELIK TARAFTARLARI IÇIN: STANDART ZIP ARŞIVINDE XAMPP.\r7ZIP:\rBANT GENIŞLIĞI DÜŞÜK SADELIK TARAFTARLARI IÇIN: 7ZIP ARŞIVINDE XAMPP.\rNOT: EĞER DOSYALARI ÇIKARIRSANIZ, YANLIŞ VIRUS UYARILARI VEREBILIR.\rYÜKEYICIYI KULLANARAK:\rBAŞLANGIÇ ​​IÇIN XAMPP KONTROL PANELI / APACHE, MYSQL, FILEZILLA VE MERKÜR DURDURMAK VEYA HIZMETLER GIBI BU SUNUCUYU YÜKLEYIN.\rZIP YÜKLENIYOR\rSEÇTIĞINIZ KLASÖRE ZIP ARŞIVLERI AYIKLAYIN. SEÇILEN HEDEF DIZIN ALTINDA: \"\\\\ XAMPP \\\\ C\" XAMPP ALT \\\\ IÇIN AÇILAN BIR. ŞIMDI, DOSYA \\\\ \"SETUP_XAMPP.BAT \" START SISTEMINIZE XAMPP YAPILANDIRMASINI AYARLAMAK IÇIN.\rBIR KÖK DIZIN \\\\ SEÇERSENIZ: HEDEF OLARAK \"C \\\\\" ISE, \\\\ \"SETUP_XAMPP.BAT \" START OLMAMALIDIR.\rYÜKLEYICI VERSIYONUNDA OLDUĞU GIBI, ŞIMDI EKSTRA GÖREVLER IÇIN \"XAMPP KONTROL PANELI\"NIDE KULLANABILIRSINIZ.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rXAMPP\'I YÜKLEME IŞLEMI OLMADAN NASIL BAŞLATABILIRIM?\rXAMPP\'I \"C:\\\\\" VEYA \"D:\\\\\" GIBI ÜST KLASÖRLERE ÇIKARIRSANIZ, APACHE VEYA MYSQL GIBI BIRÇOK SUNUCUYU \"SETUP_XAMPP.BAT\" DOSYASINI ÇALIŞTIRMADAN BAŞLATABILIRSINIZ.\rXAMPP\'I USB SÜRÜCÜYE KURARKEN, HER BILGISAYARDA FARKLI SÜRÜCÜ ISMI OLABILECEĞI IÇIN BELIRSIZ YOL SEÇMENIZ ÖNERILIR. YÜKLEME IŞLEMIYLE KLASÖR YOLUNU BELIRLI VEYA BELIRSIZ OLARAK ISTEDIĞINIZ AN DEĞIŞTIREBILIRSINIZ.\rİNDIRME SAYFAMIZDAKI INDIRICI, XAMPP\'I KURMANIN EN KOLAY YOLUDUR. YÜKLEME TAMAMLANDIKTAN SONRA XAMPP\'I BAŞLAT | PROGRAMLAR | XAMPP KLASÖRÜNDE BULABILIRSINIZ. XAMPP KONTROL PANEL\'INI KULLANARAK SUNUCULARI BAŞLATIP DURDURMANIN YANINDA SERVIS OLARAK YÜKLEYIP KALDIRABILIRSINIZ.\rBAŞLANGIÇ ​​IÇIN XAMPP KONTROL PANELI / APACHE, MYSQL, FILEZILLA VE MERKÜR DURDURMAK VEYA HIZMETLER GIBI BU SUNUCUYU YÜKLEYIN.\rXAMPP\'I NASIL BAŞLATIR VE DURDURURUM?\rEVRENSEL KONTROL MERKEZI \"XAMPP KONTROL PANELI\" (WWW.NAT32.COM \' A TEŞEKKÜRLER). ŞUNUNLA BAŞLATILIR: \r\\XAMPP\\XAMPP-CONTROL.EXE\rSUNUCULARI BAŞLATMAK/DURDURMAK IÇIN AYRICA BATCHFILE DOSYALARI DA KULLANABILIRSINIZ:\rAPACHE & MYSQL\' I BAŞLAT:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL DURDUR:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE\'YI BAŞLAT:\n\\XAMPP\\APACHE_START.BAT\rAPACHE\'YI DURDUR:\n\\XAMPP\\APACHE_STOP.BAT\rMYSQL\'I BAŞLAT:\n\\XAMPP\\MYSQL_START.BAT\rMYSQL\'I DURDUR:\n\\XAMPP\\MYSQL_STOP.BAT\rMERCURY MAILSERVER BAŞLAT:\n\\XAMPP\\MERCURY_START.BAT\rMERCURY MAILSERVER DURDUR:\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA SERVER BAŞLAT:\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA SERVER DURDUR:\n\\XAMPP\\FILEZILLA_STOP.BAT\rHERŞEYIN ÇALIŞTIĞINI NASIL TEST EDEBILIRIM?\rFAVORI WEB TARAYICINIZA AŞAĞIDAKI URL\'YI YAZIN:\rHTTP://LOCALHOST/\rYA DA \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rBIR SUNUCUYU NASIL SERVIS OLARAK YÜKLEYEBILIRIM?\rXAMPP\'TAKI HER SUNUCUYU WINDOWS SERVISI OLARAK KURABILIRSINIZ. BUNU XAMPP KONTROL PANELI\'NI KULLANARAKTA YAPABILIRSINIZ. SUNUCULARI WINDOWS SERVISI OLARAK KURABILMEK IÇIN KOMUT DOSYALARININ VEYA KONTROL PANEL\'ININ YÖNETICI HAKLARIYLA ÇALIŞTIRILMASI GEREKLIDIR.\rAPACHE SERVISINI YÜKLE: \\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\rAPACHE SERVISINI KALDIR: \\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \rMYSQL SERVISINI YÜKLE: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rMYSQL SERVISINI KALDIR: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA SERVISINI YÜKLE/KALDIR: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: SERVIS YÜKLEMESI MEVCUT DEĞIL\rXAMPP HAZIR MI? \rXAMPP, NORMAL KULLANIM IÇIN DEĞILDIR, SADECE YAZILIM GELIŞTIRME IÇIN KULLANILIR. BU NEDENLE BIR YAZILIMCININ MÜMKÜN OLDUĞUNCA IHTIYACI OLAN AYARLAR YAPILMIŞTIR. YAZILOIM GELIŞTIRMEK IÇIN IDEAL BIR ORTAM OLMASINA RAĞMEN YAZILIM YAYINLAMASI IÇIN KULLANILDIĞINDA ISTENMEYEN SORUNLARA NEDEN OLABILIR.\rXAMPP IÇINDEKI GÜVENLIK EKSIKLIKLERININ LISTESI:\rMYSQL YÖNETICISI (ROOT) ŞIFRESI YOK. \rMYSQL ORTAMI, AĞ ÜZERINDEN ULAŞILABILIR.\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rMERCURY VE FILEZILLA\'NIN VARSAYILAN KULLANICILARI TANINMAKTADIR.\rTÜM NOKTALAR BÜYÜK GÜVENLIK RISKLERINE SEBEBIYET VEREBILIR. ÖZELLIKLE XAMPP, AĞ VEYA DIŞ KAYNAKLAR TARAFINDAN ERIŞIME AÇIKSA. GÜVENLIK DUVARI VEYA (NAT) YÖNLENDIRICI KULLANMAK BUNA YARDIM EDEBILIR. YÖNLENDIRICI VEYA GÜVENLIK DUVARI KULLANILMASI DURUMUNDA, NORMAL OLARAK BILGISAYARINIZ AĞ TARAFINDAN GELEN ISTEKLERE KAPALI OLACAKTIR. BU PROBLEMLERI ÇÖZMEK SIZE DÜŞMEKTEDIR. BIR MIKTAR YARDIM ETMEK IÇIN \"XAMPP GÜVENLIK KONSOLU\" BULUNMAKTADIR.\rHERHANGI BIR ŞEYI YAYINLAMADAN ÖNCE LÜTFEN XAMPP\'I GÜVENLI HALE GETIRIN. BIR GÜVENLIK DUVARI VEYA HARICI YÖNLENDIRICI SADECE DÜŞÜK PROFIL GÜVENLIK SORUNLARINI ÖNLEMEYE YARDIMCI OLMAKTA. HAFIF BIR GÜVENLIK ARTIŞI IÇIN, \"XAMPP GÜVENLIK KONSOLU\" ILE SUNUCULARINIZA GEREKLI ŞIFRELERI ATAYABILIRSINIZ.\rEĞER INTERNETTEN ERIŞILEBILIR XAMPP\' INIZ OLMASINI ISTERSENIZ, BAZI PROBLEMLERI ÇÖZMEK IÇIN AŞAĞIDAKI BAĞLANTIYA GIDEBILIRSINIZ:\rHTTP://LOCALHOST/SECURITY/\rGÜVENLIK KONSOLU ILE MYSQL KULLANICISI \"ROOT\" VE PHPMYADMIN\'E ŞIFRE ATAYABILIRSINIZ. AYRICA, XAMPP DEMO SAYFALARINDAKI DOĞRULAMAYI ETKINLEŞTIREBILIRSINIZ.\rBU INTERNET TABANLI ARAÇ HIÇBIR EKSTRA GÜVENLIK PROBLEMINI ÇÖZMEMEKTEDIR! ÖZELLIKLE FILEZILLA FTP SUNUCUSU ILE MERCURY MAIL SUNUCUSUNU KENDINIZ GÜVENLI HALE GETIRMELISINIZ.\rXAMPP\'I NASIL KALDIRABILIRIM?\rXAMPP\'I YÜKLEYICI VERSIYONUYLA YÜKLEDIYSENIZ, LÜTFEN KALDIRICI\'YI KULLANIN. KALDIRICI KAYIT DEFTERINIZDEN TÜM XAMPP GIRDILERINI VE BAZI XAMPP ILE GELEN SERVISLERI KALDIRACAKTIR. YÜKLEYICI KULLANARAK YÜKLEDIĞINIZ XAMPP YÜKLEMELERINI KESINLIKLE KALDIRICI ILE KALDIRMANIZ ÖNERILMEKTEDIR. VERILERINIZI XAMPP\'I KALDIRMADAN ÖNCE LÜTFEN YEDEKLEYIN.\rXAMPP\'I ZIP VE 7ZIP VERSIYONLARI ILE KURDUYSANIZ, TÜM XAMPP SUNUCULARINI KAPATIN VE TÜM PANELLERDEN ÇIKIŞ YAPIN. HERHANGI BIR KURULU SERVISINIZ VARSA KALDIRIP KAPATIN VE XAMPP\'IN KURULU OLDUĞU KLASÖRÜ BASITÇE SILIN. TEMIZLEMENIZ GEREKEN HIÇBIR KAYIT BULUNMAMAKTA.\rXAMPP\'IN \"LITE\" VERSIYONU NEDIR?\rXAMPP LITE (\"HAFIF\" ANLAMINDA), XAMPP\'IN TÜM BILEŞENLERINI IÇERMEYEN KÜÇÜLTÜLMÜŞ PAKETIDIR. SADECE PHP VE MYSQL ILE ÇABUK IŞLEMLERI HALLETMEK IÇIN ÖNERILIR. BAZI, MERCURY MAIL VE FILEZILLA FTP GIBI SUNUCU VEYA ARAÇLAR LITE VERSIYONUNDA BULUNMAMAKTA.\rWEB IÇERIĞIMI NEREYE YERLEŞTIRMELIYIM?\rTÜM WEB DÖKÜMANLARI IÇIN ANA DIZIN \"\\\\XAMPP\\\\HTDOCS\"DUR. EĞER \"TEST.HTML\" ISIMLI BIR DOSYAYI BU DIZINE KOYARSANIZ, DOSYAYA \"HTTP://LOCALHOST/TEST.HTML\" BAĞLANTISI ILE ULAŞABILIRSINIZ. \rVE \"TEST.PHP\" SAYFASI IÇIN \": //LOCALHOST/TEST.PHP\" YETERLIDIR. BASIT BIR DENEME KODU OLARAK:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rALT KLASÖRE MI IHTIYACINIZ VAR? //XAMPP//HTDOCS KLASÖRÜNÜN IÇINE ÖRNEK OLARAK \"YENI\" ADLI BIR KLASÖR OLUŞTURUN(EN IYISI BOŞLUKSUZ VE ASCII KODLAMA KAREKERLERI ILE OLMASIDIR). BU KLASÖR IÇINDE TEST DOSYANIZI OLUŞTURUN VE ONA ERIŞMEK IÇIN \"HTTP:// LOCALHOST/YENI/TEST.PHP\" ADRESINI KULLANIN. \rDIĞER ÖZELLIKLERINI\rHTML:\rÇALIŞTIRILABILIR: \\XAMPP\\HTDOCS\rİZIN VERILEN SONLAR: .HTML .HTM\r=> TEMEL PAKET\rSSI:\rÇALIŞTIRILABILIR: \\XAMPP\\HTDOCS\rİZIN VERILEN SONLAR: .SHTML\r=> TEMEL PAKET\rCGI:\rÇALIŞTIRILABILIR: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rİZIN VERILEN SONLAR: .CGI\r=> TEMEL PAKET\rPHP:\rÇALIŞTIRILABILIR: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rİZIN VERILEN SONLAR: .PHP\r=> TEMEL PAKET\rPERL:\rÇALIŞTIRILABILIR: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rİZIN VERILEN SONLAR: .PL\r=> TEMEL PAKET\rAPACHE::ASP PERL:\rÇALIŞTIRILABILIR: \\XAMPP\\HTDOCS\rİZIN VERILEN SONLAR: .ASP\r=> TEMEL PAKET\rJSP JAVA:\rÇALIŞTIRILABILIR: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rİZIN VERILEN SONLAR: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rÇALIŞTIRILABILIR: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rİZIN VERILEN SONLAR: .HTML (U.A)\r=> TOMCAT ADD-ON\rXAMPP KURULUMUNU TAŞIYABILIR MIYIM?\rEVET. XAMPP DIZININ TAŞINDIKTAN SONRA \"SETUP_XAMPP.BAT \" ÇALIŞTIRMALISINIZ. YAPILANDIRMA DOSYALARI BU ADIMI ILE AYARLANACAKTIR.\rEĞER WINDOWS HIZMETI OLARAK HERHANGI BIR SUNUCU KURDUYSANIZ, ÖNCE KURULU OLAN WINDOWS HIZMETINI KALDIRMANIZ GEREKIR. DAHA SONRA YENIDEN HIZMETI YÜKLEYEBILIRSINIZ.\rUYARI: AYAR DOSYALARI IÇEREN, PHP UYGULAMALARI GIBI UYGULAMALARINIZDAKI AYAR DOSYALARI AYARLANMAZ. ANCAK YÜKEYICIYE EKLENTI OLUŞTURARAK BUNU IMKANLI HALE GETIREBILIRSINIZ. EKLENTILERLE YÜKLEYICI BU DOSYALARI AYARLAYABILIR.\rNE WWW DIZINLERI IÇIN \"OTOMATIK START SAYFALARINI \" \\\\ VAR?\rAPACHE IŞLEVI \\\\ \"DIRECTORYINDEX \" IÇIN STANDART DOSYA ADI \\\\ \"INDEX.HTML \" YA DA \\\\ \"INDEX.PHP \". SADECE BIR KLASÖRE GEZIYOR HER ZAMAN (ÖRNEĞIN \\\\ \"HTTP: // LOCALHOST / XAMPP / \"), VE APACHE GIBI BIR DOSYAYI BULABILIRSINIZ, APACHE BU DOSYAYI YERINE DIZIN LISTESINI GÖRÜNTÜLÜYOR.\rNEREDE YAPILANDIRMASINI DEĞIŞTIREBILIR MIYIM?\rNEREDEYSE XAMPP TÜM AYARLARI YAPILANDIRMA DOSYALARI ILE DEĞIŞTIREBILIRSINIZ. SADECE BIR TEXTEDIT DOSYAYI AÇIN VE ISTEDIĞINIZ AYARI DEĞIŞTIRIN. SADECE FILEZILLA VE MERKÜR UYGULAMA YAPILANDIRMA ARACI ILE YAPILANDIRILMALIDIR.\rNEDEN XAMPP WINDOWS XP SP2 ÜZERINDE ÇALIŞMAK DEĞIL MI?\rMICROSOFT, OTOMATIK OLARAK BAŞLAR HIZMET PAKETI 2 (SP2), ILE DAHA IYI BIR GÜVENLIK DUVARI SUNAR. BU GÜVENLIK DUVARI ARTIK ENGELLER GEREKLI PORTLARI 80 (HTTP) VE 443 (HTTPS) VE APACHE BAŞLATILAMIYOR.\rHIZLI ÇÖZÜM:\rMICROSOFT, ARAÇ ÇUBUĞU ILE GÜVENLIK DUVARI VE XAMPP DAHA ONCES BAŞLATMAYI DENEYIN DEVRE DIŞI BIRAKIN. DAHA IYI BIR ÇÖZÜM GÜVENLIK MERKEZI IÇINDE BIR ISTISNA TANIMLAMAKTIR.\rAŞAĞIDAKI BAĞLANTI NOKTALARI, TEMEL IŞLEVLER IÇIN KULLANILIR:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rNEDEN XAMPP VISTA ÜZERINDE ÇALIŞMIYOR?\rKULLANICI HESABI DENETIMI (UAC)\rDIZIN \\\\ \"C: \\\\ PROGRAM FILES \" BILE YÖNETICI OLARAK, TAM YAZMA AYRICALIKLARINA SAHIP DEĞILSINIZ. YOKSA (\\\\ ÖRNEĞIN \". \\\\ XAMPP \\\\ HTDOCS \") SADECE SINIRLI AYRICALIKLARA SAHIP. BU DURUMDA BIR DOSYAYI DÜZENLEYEMEZSINIZ.\rÇÖZÜM:\rEXPLORER IÇINDE AYRICALIKLARI KALDIRIN (SAĞ / GÜVENLIK TIKLAYIN) VEYA KULLANICI HESABI DENETIMI (UAC) DEVRE DIŞI BIRAKIN.\rWINDOWS HIZMETI OLARAK: \"\\\\ XAMPP \\\\ C\" SEN \\\\ APACHE / MYSQL YÜKLEDINIZ. AMA SEN START / \\\\ ILE HIZMETLERINI DURDURUN \"XAMPP CONTROL PANEL \" YA DA BUNLARI KALDIRAMAZSINIZ OLAMAZ.\rÇÖZÜM:\rWINDOWS HIZMET YÖNETIMI KONSOLUNU KULLANIN VEYA UAC DEVRE DIŞI BIRAKIN.\rKULLANICI HESABI DENETIMI DEVRE DIŞI BIRAKMA (UAC)\rUAC DEVRE DIŞI BIRAKMAK IÇIN, PROGRAMI \\\\ \"MSCONFIG \" KULLANIN. \\\\ \"MSCONFIG \" \\\\ GIDIN \"ARAÇLAR \", \\\\ \"DEVRE DIŞI KULLANICI HESABI DENETIMI \" SEÇIN VE SEÇIMINIZI DOĞRULAYIN. ŞIMDI WINDOWS\'U YENIDEN BAŞLATMANIZ GEREKIR. AYNI ZAMANDA, YINE UAC ETKINLEŞTIREBILIR.\rNASIL MD5 CHECKSUM KONTROL EDEBILIRIM?\rDOSYALARI KARŞILAŞTIRMAK IÇIN, SIK SIK SAĞLAMA KULLANILIR. STANDART BU SAĞLAMA MD5 (MESSAGE DIGEST ALGORITHM 5) OLUŞTURMAK IÇIN.\rXAMPP PAKETININ INDIRME DOĞRU OLUP OLMADIĞINI, BU MD5 SAĞLAMA ILE, TEST EDEBILIRSINIZ. TABII KI BU SAĞLAMA OLUŞTURABILIRSINIZ BIR PROGRAM GEREKIYOR. WINDOWS IÇIN MICROSOFT\'TAN BIR ARACI KULLANABILIRSINIZ:\rKULLANILABILIRLIK VE FILE CHECKSUM INTEGRITY VERIFIER YARDIMCI PROGRAMI AÇIKLAMASI\rGNU MD5SUM GIBI, MD5 TOPLAMLARINI OLUŞTURABILIR BAŞKA BIR PROGRAM KULLANMAK DA MÜMKÜNDÜR.\r(ÖRN FCIV.EXE) BU TÜR BIR PROGRAMI KURDUKTAN GIBI, ADIMLARI IZLEYEREK YAPABILIRSINIZ:\rİNDIR XAMPP (FE XAMPP-WIN32-1.8.2-0.EXE)\rILE CHECKSUM OLUŞTURUN:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rVE ŞIMDI SIZE XAMPP WINDOWS IÇIN ANA SAYFASINDA BULABILIRSINIZ BIRI ILE BU SAĞLAMA KARŞILAŞTIRABILIRSINIZ.\rHER IKI SAĞLAMA EŞIT, TÜM OK. DEĞILSE, INDIR BOZUK VEYA DOSYA DEĞIŞTIRILDI.\rNEDEN BENIM PHP.INI DEĞIŞIKLIKLERIN GEÇERLI DEĞIL MI?\r\\\\ \"PHP.INI \" BIR DEĞIŞIKLIK HIÇBIR ETKISI VARSA, MÜMKÜN PHP FARKLI BIR BIRINI KULLANARAK MI. SEN PHPINFO ILE KONTROL EDEBILIRSINIZ (). URI HTTP: //LOCALHOST/XAMPP/PHPINFO.PHP VE \\\\ \"LOADED CONFIGURATION FILE \" IÇIN ARAMA. BU DEĞER SIZE \"PHP.INI \" PHP GERÇEKTEN KULLANIYOR \\\\ GÖSTERIR.\rNOT:\r\\\\ DEĞIŞTIRDIKTEN SONRA \"PHP.INI \" APACHE / PHP YENI AYARLARI OKUYABILIR BÖYLECE APACHE YENIDEN BAŞLATMANIZ GEREKIR.\rYARDIM EDIN! XAMPP BIR VIRÜS VAR!\rBIR VIRÜS IÇIN BAZI ANTIVIRÜS PROGRAMLARI HATA XAMPP, GENELLIKLE DOSYA XAMPP-MANAGER.EXE IŞARETLEME BU OLMADIĞI ZAMAN ANTIVIRÜS YANLIŞLIKLA BIR VIRÜS OLARAK TANIMLANAN BIR YALANCI POZITIF ANLAMIDIR. BIZ XAMPP HER YENI SÜRÜM ÖNCE VIRÜS TARAMA YAZILIMI ARACILIĞIYLA ÇALIŞTIRIN. ŞU ANDA KULLANMAKTA OLDUĞUNUZ \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rNASIL BENIM ANTIVIRÜS UYGULAMASINI YAPILANDIRMAK MI?\rBIZ BIRLIKTE WEB UYGULAMASI ÇALIŞTIRMAK IÇIN GEREKLI TÜM BAĞIMLILIKLARI VE SUNUCULAR DAHIL ETTIK, BU YÜZDEN XAMPP ÇOK SAYIDA DOSYA YÜKLER BULACAKSINIZ. ETKIN BIR ANTIVIRÜS UYGULAMASI ILE BIR WINDOWS MAKINEDE BIR XAMPP UYGULAMA YÜKLÜYORSANIZ, BU ANLAMLI YÜKLEMEYI YAVAŞLATABILIR VE SUNUCULARDAN BIRI (WEB SUNUCUSU, VERITABANI SUNUCUSU) ANTIVIRÜS YAZILIMI TARAFINDAN BLOKE EDILEBILIR BIR ŞANS DA VAR . EĞER BIR ANTIVIRÜS ARACI ETKIN VARSA, PERFORMANS SORUNLARI OLMADAN XAMPP ÇALIŞTIRMAK IÇIN AŞAĞIDAKI AYARLARI KONTROL EDIN:\rGÜVENLIK DUVARI ÖZEL DURUMLARI EKLEYIN: APACHE, MYSQL VEYA BAŞKA BIR SUNUCU IÇIN.\rTARAMA DOSYALAR ÇALIŞTIRILDIĞINDA: EĞER TÜM DOSYALAR IÇIN ANTIVIRÜS TARAMASI ETKIN VARSA, SUNUCULAR IÇIN ÇALIŞTIRILABILIR DOSYALARI YAVAŞLATABILIR.\rFARKLI URL\'LER IÇIN TRAFIĞI TARAYIN: KENDI MAKINENIZDE XAMPP GELIŞMEKTE ISENIZ, ANTIVIRÜS AYARLARINDA \\\\ \"LOCALHOST \" TRAFIĞI HARIÇ TUTABILIRSINIZ.\rNEDEN APACHE SUNUCUSUNU BENIM SISTEMDE BAŞLAMIYOR?\rBU SORUN ÇEŞITLI NEDENLERLE BIRI OLABILIR:\rSEN (YANI IIS, SAMBAR, ZEUS VE BENZERI) DAHA SONRA BIR HTTP SUNUCUSU BAŞLADI. SADECE BIR SUNUCU BU HATA ILETISI SORUNU GÖSTERIYOR PORT 80 KULLANABILIRSINIZ:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\r-> SEÇENEKLER - SEN BÖYLE BIR SORUN \\\\ \"SKYPE \" ISE LIMAN 80. EĞER EYLEMLER SKYPE GIDEBILIRSINIZ AYRICA BLOKLAR INTERNET TELEFON \\\\ \"SKYPE \" GIBI BAŞKA YAZILIMLARI VAR> BAĞLANTI -> \"ALTERNATIF BIR LIMAN \\\\ IÇIN KULLANILMASI PORT 80 \" DE ONAY IŞARETINI KALDIRIN VE SKYPE\'I YENIDEN BAŞLATIN. ŞIMDI ÇALIŞMALIDIR.\rHANGI BLOKLAR APACHE PORTU BIR GÜVENLIK DUVARI VAR. TÜM GÜVENLIK DUVARLARI, APACHE ILE UYUMLU VE BAZEN GÜVENLIK DUVARINI DEVRE DIŞI BIRAKILMASI YETERLI DEĞILDIR VE BUNU KALDIRMANIZ GEREKIR. BU HATA ILETISI, BIR GÜVENLIK DUVARI BELIRTIR:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rAPACHE BAŞLAYABILIR, ANCAK TARAYICINIZ BUNA BAĞLANAMIYOR AYRICA EĞER AŞAĞIDAKILERDEN BIRINE BAĞLI OLABILIR:\rBAZI VIRÜS TARAYICILARI GÜVENLIK DUVARLARI ENGELLEYEBILIR AYNI ŞEKILDE BU NEDEN OLABILIR.\rSEN XAMPP IÇIN EN AZ SP1 OLMASI GEREKIR HIZMET PAKETI 1. OLMADAN XP PROFESSIONAL VAR.\rİPUCU:\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\rNEDEN APACHE NEREDEYSE% 99 BENIM CPU YÜKÜ NEDIR?\rBURADA OYNAYAN IKI SENARYO BIRI VARDIR. YA CPU MAXING EDILIR VEYA TARAYICI SUNUCUYA BAĞLANMAK, ANCAK (SISTEM SAYFASINI YÜKLEMEK IÇIN UNSUCESSFULLY ÇALIŞIYOR) BIR ŞEY GÖREMIYORUM. HER IKI DURUMDA DA APACHE GÜNLÜK DOSYASINDA AŞAĞIDAKI ILETIYI BULABILIRSINIZ:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rMPM GERI GÜVENLI UYGULANMASINA DÜŞÜYOR, AMA BAZI ISTEMCI ISTEKLERI DÜZGÜN IŞLENMEZ BULUNDU. BU HATAYI ÖNLEMEK IÇIN, \\\\ \"ACCEPTFILTER \" KULLANIN FILTRE \\\\ \\\\ IÇINDE \"YOK \" \\\\ \"XAMPP \\\\ APACHE \\\\ CONF \\\\ EXTRA \\\\ HTTPD-MPM.CONF \" DOSYASI KABUL EDIN.\rNEDEN RESIM VE STIL SAYFALARI DEĞIL GÖSTERILDI MI?\rBAZEN GÖRÜNTÜLENIYOR RESIM VE STIL SAYFASI ILE ILGILI SORUNLAR VAR. BU DOSYALAR BIR AĞ SÜRÜCÜSÜNDE BULUNAN ÖZELLIKLE. BU DURUMDA DOSYA \\\\ AŞAĞIDAKI SATIRLARI EĞER BIRINI ETKINLEŞTIRIN (VEYA EKLEMEK) OLABILIR \"\\\\ XAMPP \\\\ APACHE \\\\ CONF \\\\ HTTPD.CONF \":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rBU SORUN, NETLIMITER GIBI BANT GENIŞLIĞI DÜZENLEMEK IÇIN PROGRAMLAR TARAFINDAN NEDEN OLABILIR.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rNASIL MYSQL BIR KÖK ŞIFRE AYARLAYABILIRSINIZ?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rBENIM KENDI MYSQL SUNUCUSU KULLANABILIR MIYIM?\rEVET. BASITÇE XAMPP PAKETINDEN MYSQL BAŞLATMAYIN. İKI SUNUCUNUN AYNI BAĞLANTI NOKTASINDA BAŞLAMIŞ OLAMAZ UNUTMAYIN. EĞER \\\\ \"ROOT \" IÇIN BIR PAROLA AYARLADIYSANIZ, DOSYA \\\\ \"\\\\ XAMPP \\\\ PHPMYADMIN \\\\ CONFIG.INC.PHP \" DÜZENLEMEK UNUTMAYINIZ.\rNASIL DIŞARIDAN PHPMYADMIN ERIŞIMI KISITLAMAK MI?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rMYSQL SUNUCUSUNA ERIŞMEDEN ÖNCE, PHPMYADMIN KULLANICI ADI VE ŞIFRE ISTEYECEKTIR. İLK KULLANICI \\\\ \"ROOT \" IÇIN BIR ŞIFRE KOYMAK UNUTMAYIN.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rNEREDE PHP IMAP DESTEĞI NEDIR?\rEĞER, DOSYA \\\\ AÇABILIRSINIZ NT SISTEMLERINDE ÇALIŞIYORSANIZ, VARSAYILAN OLARAK, PHP IMAP DESTEĞI NEDENIYLE WINDOWS 98 GIBI BAZI EV SÜRÜMLERI ILE BAZI GIZEMLI BAŞLATMA HATALARI XAMPP DEVRE DIŞI BIRAKILIR \"\\\\ XAMPP PHP \\\\ PHP.INI \\\\ \" \"; EXTENSION = PHP_IMAP.DLL \" HAT \\\\ BAŞLAYAN NOKTALI VIRGÜL KALDIRARAK PHP EXSTENSION ETKINLEŞTIRMEK IÇIN. OLMALI:\rEXTENSION=PHP_IMAP.DLL\rŞIMDI APACHE YENIDEN BAŞLATIN VE IMAP ÇALIŞMASI GEREKIR. VARSAYILAN YAPILANDIRMADA ETKIN DEĞIL HER UZATMA IÇIN AYNI ADIMLARI KULLANABILIRSINIZ.\rNEDEN BAZI PHP AÇIK KAYNAK UYGULAMALARI WINDOWS ÜZERINDE XAMPP ILE ÇALIŞMAK DEĞIL MI?\rLINUX IÇIN YAZILMIŞ PHP UYGULAMALARI VEYA UZANTILARI BIR SÜRÜ WINDOWS TAŞIDIK EDILMEMIŞTIR. \rCAN I DELETE THE \"INSTALL\" DIRECTORY AFTER INSTALLATION?\rO DEĞIL DAHA IYI. BURADA KOMUT DOSYALARI HALA XAMPP TÜM EK PAKETLER (ADD-ONS) VE YÜKSELTMELERI IÇIN GEREKLIDIR.\rEACCELERATOR\'U NASIL ETKINLEŞTIREBILIRIM?\rDIĞER (ZEND) UZANTILARI GIBI, \\\\ \"PHP.INI \" BUNU ETKINLEŞTIREBILIRSINIZ. \"; ZEND_EXTENSION = \" \\\\ PHP_EACCELERATOR.DLL \\\\ \"\" \\\\ XAMPP \\\\ PHP \\\\ EXT BU DOSYADA, SATIR \\\\ ETKINLEŞTIRIN. OLMALI:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rNASIL BENIM SQL SUNUCUSUNA MS BIR BAĞLANTI HATASI DÜZELTEBILIRIM?\rMSSQL UZANTISI PHP.INI YÜKLENDIYSE YALNIZCA TCP / IP KULLANILDIĞINDA BAZEN SORUNLAR GÖRÜNÜR. MICROSOFT\'TAN YENI BIR \\\\ \"NTWDBLIB.DLL \" ILE BU SORUNU ÇÖZEBILIRSINIZ. \\\\ ESKI DOSYAYI DEĞIŞTIRMEK LÜTFEN \"\\\\ XAMPP APACHE \\\\ BIN \\\\ \" VE \\\\ YENISI ILE \"\\\\ XAMPP \\\\ PHP \". ÇÜNKÜ LISANS, BIZ XAMPP ILE BU DOSYANIN DAHA YENI BIR SÜRÜMÜNÜ PAKET OLAMAZ.\rNASIL PHP MCRYPT UZANTISI ILE ÇALIŞIR?\r% {} MCRYPT: BUNUN IÇIN ÖRNEKLER VE OLASI ÇÖZÜMLERI ILE FORUMDA BIR KONU AÇTI\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rPERL EKLE-ON ILE NO. VE APACHE :: ASP AYNI DEĞILDIR. APACHE :: ASP SADECE PERL-SCRIPT BILIR, AMA INTERNET INFORMATION SERVER (IIS) ASP NORMAL VBSCRIPT BILIR. AMA ASP .NET IÇIN, MEVCUT BIR 3. PARTI APACHE MODÜLÜ VAR.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rGIZLILIK POLITIKASI\rCDN SAĞLADIĞI\r\n'),(87,'3d2ce4b065681049c5bf8e0f6838912c','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rSSS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rGIZLILIK POLITIKASI\rCDN SAĞLADIĞI\r\n'),(88,'8293ef842d000103add575e6a14582cc','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rSSS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rGIZLILIK POLITIKASI\rCDN SAĞLADIĞI\r\n'),(89,'a317d984cb58ab07e9231d9a4f27c1bb','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rSSS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rGIZLILIK POLITIKASI\rCDN SAĞLADIĞI\r\n'),(90,'8675b6d01023ed560044128956c3d4d9','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rSSS\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rSSS\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nTOPLULUK\rXAMPP, 10 YILI AŞKIN SÜREDIR PIYASADA  ARKASINDA BÜYÜK BIR TOPLULUK VARDIR. KATILMAK IÇIN \rFORUMLAR\rKAYIT OLABILIR, BIZI \rFACEBOOK\rBEĞENEBILIR YADA \rTWITTER\rISTISMARLARIMIZI TAKIP EDEBILIRSINIZ.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rCOPYRIGHT (C) 2022, APACHE FRIENDS\rBLOG\rGIZLILIK POLITIKASI\rCDN SAĞLADIĞI\r\n'),(91,'2e353e0bae8aa1508bfc7f96ad741f54','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\rاکثر پوچھے گئے سوالات\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rعمومی سوالات\rمیں کس طرح XAMPP کو انسٹال کروں ؟\rونڈوز کے لیے XAMPP کی تین مختلف ذائقوں میں موجود ہے:\rانسٹالر\rشاید XAMPP کی نصب کرنے کے لئے سب سے آسان طریقہ.\rZIP:\rPURISTS کے لئے: XAMPP کی عام زپ محفوظ شدہ دستاویزات.\r7ZIP:\rXAMPP کی 7ZIP محفوظ شدہ دستاویزات کے طور پر: کم بینڈوڈتھ کے ساتھ PURISTS کے لئے.\rنوٹ: اگر آپ فائلوں کو ہٹا دیں، تو، جھوٹے مثبت وائرس انتباہ ہو سکتا ہے.\rانسٹالر استعمال کرتے ہوئے:\rXAMPP کنٹرول پینل APACHE, MYSQL, FILEZILLA & MERCURY کو شروع کرنے یا روکنے کے لئے یا ان سرورز کو سروس کے طور پر انسٹال کرنے کے لئے استعمال کرتے ہیں\rزپ کی طرف سے نصب\rآپ کی پسند کا فولڈر میں ZIP ابلیھاگار ان زپ. منتخب شدہ ہدف کی ڈائرکٹری ذیل: \"XAMPP\\C:\" XAMPP کی ذیری ڈائریکٹری پر نکالنے ہے. اب آپ کا سسٹم پر XAMPP کی ترتیب کو ایڈجسٹ کرنے کے لئے، فائل \"SETUP_XAMPP.BAT\" شروع.\rآپ کو ایک روٹ ڈائریکٹری \"C:\\\" کا انتخاب کرتے ہیں ہدف کے طور پر، آپ کو \"SETUP_XAMPP.BAT\" شروع نہیں ہونا چاہیے.\rانسٹالر کے ورژن کے ساتھ کی طرح، آپ کو اب اضافی کاموں کے لئے \"XAMPP کی کنٹرول پینل\" استعمال کر سکتے ہیں.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rمیں کس طرح سیٹ اپ کے بغیر XAMPP کی شروع کر سکتے ہیں؟\rاگر آپ XAMPP کو اعلی سطحی فولڈر جیسا کہ ,\"C:\\\\\" OR \"D:\\\\\" میں ڈالیں تو آپ بہت سی سروسز جیسا کہ APECHE اور MYSQL براہراست شروع کر سکتے ہیں \"SETUP_XAMPP.BAT\" اس فائل کو چلاے بغیر .\rآپ کو ایک یوایسبی ڈرائیو پر XAMPP کی نصب کر رہے ہیں تو سیٹ اپ سکرپٹ کا استعمال کرتے ہوئے، یا سیٹ اپ سکرپٹ میں رشتہ دار کے راستے کا انتخاب نہیں، ترجیح دی جاتی ہے. ہر کمپیوٹر پر اس طرح کی ایک ڈرائیو ایک دوسرے ڈرائیو خط ہے کر سکتے ہیں. آپ سیٹ اپ سکرپٹ کے ساتھ کسی بھی وقت رشتہ دار راستے پر مطلق کی طرف سے تبدیل کر سکتے ہیں.\rہمارے ڈاؤن لوڈ کے صفحے سے انسٹالر استعمال کرتے ہوئے XAMPP کی نصب کرنے کے لئے کا سب سے آسان طریقہ ہے. XAMPP کی | پروگرام | تنصیب مکمل ہونے کے بعد، آپ کو شروع کرنے کے تحت XAMPP کی مل جائے گا. آپ / شروع تمام سرور کو روکنے کے اور بھی / انسٹال کی خدمات کو انسٹال کرنے کے XAMPP کی کنٹرول پینل استعمال کر سکتے ہیں.\rXAMPP کنٹرول پینل APACHE, MYSQL, FILEZILLA & MERCURY کو شروع کرنے یا روکنے کے لئے یا ان سرورز کو سروس کے طور پر انسٹال کرنے کے لئے استعمال کرتے ہیں\rمیں کس طرح شروع کرنے اور XAMPP کی روک سکتا ہوں؟\rعالمی کنٹرول سینٹر \"XAMPP کی کنٹرول پینل\" (شکریہ WWW.NAT32.COM) ہے. اس کے ساتھ شروع کر دیا ہے:\r\\XAMPP\\XAMPP-CONTROL.EXE\rتم نے بھی سرور کو روکنے / شروع کرنے کے لئے کچھ BATCHFILES استعمال کر سکتے ہیں:\rاپاچی اور مائی ایس کیو ایل شروع:\n\\XAMPP\\XAMPP_START.EXE\rاپاچی اور مائی ایس کیو ایل سٹاپ:\n\\XAMPP\\XAMPP_STOP.EXE\rاپاچی شروع:\n\\XAMPP\\APACHE_START.BAT\rاپاچی سٹاپ:\n\\XAMPP\\APACHE_STOP.BAT\rایس کیو ایل شروع:\n\\XAMPP\\MYSQL_START.BAT\rایس کیو ایل سٹاپ:\n\\XAMPP\\MYSQL_STOP.BAT\rمرکری MAILSERVER شروع:\n\\XAMPP\\MERCURY_START.BAT\rمرکری MAILSERVER سٹاپ:\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA کے سرور شروع:\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA کے سرور سٹاپ:\n\\XAMPP\\FILEZILLA_STOP.BAT\rمیں کس طرح جانچ سکتا ہوں کہ سب چیزوں نے کام کیا ؟\rآپ اپنے پسندیدہ ویب براؤزر میں مندرجہ ذیل یو آر ایل لکھیں :\rHTTP://LOCALHOST/\rیا \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rمیں کس طرح ایک خدمت کے طور پر ایک سرور انسٹال کر سکتے ہیں؟\rXAMPP کی میں ہر سرور آپ ونڈوز خدمت کے طور پر بھی انسٹال کر سکتے ہیں. تم نے بھی XAMPP کی کنٹرول پینل سے انسٹال کر سکتے ہیں. اس صورت میں یہ ایڈمنسٹریٹر کی سہولیات کے ساتھ سکرپٹ یا کنٹرول پینل کو چلانے کے لئے ضروری ہے.\rاپاچی سروس انسٹال کریں: XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\\\\\rAPACHE سروس انسٹال کریں : XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT\\\\ \rایس کیو ایل سروس انسٹال کریں: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \rایس کیو ایل سروس انسٹال: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA کے خارج انسٹال کریں: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rمرکری: کوئی سروس کی تنصیب دستیاب\rکیا XAMPP کی پیداوار تیار ہے؟\rXAMPP صرف ترقی کے ماحول کے لئے ہی نہیں ترتیب دیا گیا ہے، لیکن . XAMPP کو جس طرح وہ چاہتا / چاہتی ہے ڈویلپر کچھ بھی اجازت دینے کے لئے ہر ممکن حد تک کھلا ہے. ترقی کے ماحول کے لئے یہ بہت اچھا ہے لیکن پیداوار کے ماحول میں یہ مہلک ہو سکتا ہے.\rیہاں XAMPP کی لاپتہ سلامتی کی فہرست:\rمائی ایس کیو ایل کے منتظم (جڑ)/ (ROOT) کا کوئی پاسوڑد نہیں ہے.\rمائی ایس کیو ایل ڈیمان نیٹ ورک کے ذریعے قابل رسائی ہے.\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rمرکری اور FILEZILLA کے پہلے سے طے شدہ صارفین کے نام سے جانا جاتا.\rتمام پوائنٹس کی ایک بہت بڑی سیکورٹی رسک ہو سکتا ہے. XAMPP کی آپ کے LAN کے باہر نیٹ ورک اور لوگوں کے ذریعے قابل رسائی ہے خاص طور پر اگر. یہ بھی ایک فائر وال یا ایک (NAT) روٹر استعمال کرنے کے لئے مدد کر سکتے ہیں. ایک روٹر یا فائروال کے معاملے میں، آپ کے کمپیوٹر کو عام طور پر نیٹ ورک کے ذریعے قابل رسائی نہیں ہے. یہ ان مسائل کو ٹھیک کرنے کے لئے آپ پر منحصر ہے. ایک چھوٹی سی مدد کے طور پر \"XAMPP کی سیکورٹی کنسول\" ہے.\rآن لائن کچھ بھی شائع کرنے سے پہلے XAMPP کی محفوظ کریں. فائروال یا ایک بیرونی روٹر سیکورٹی کی کم سطح کے لئے صرف کافی ہیں. تھوڑا سا زیادہ حفاظت کے لئے، آپ کو \"XAMPP کی سیکورٹی کنسول\" چلانے اور پاس ورڈ تفویض کر سکتے ہیں.\rآپ انٹرنیٹ سے آپ XAMPP کی قابل رسائی ہے کرنا چاہتے ہیں تو، آپ کو کچھ مسائل کو ٹھیک کر سکتے ہیں جو مندرجہ ذیل URI کو جانا چاہئے:\rHTTP://LOCALHOST/SECURITY/\rسیکورٹی کنسول کے ساتھ آپ ایس کیو ایل صارف \"جڑ\" اور PHPMYADMIN کے لئے ایک پاس ورڈ مقرر کر سکتے ہیں. تم نے بھی XAMPP کی DEMOPAGES کے لئے ایک کی توثیق چالو کر سکتے ہیں.\rیہ ویب کی بنیاد پر آلے کے کسی بھی اضافی سیکورٹی کے مسائل حل نہیں ہے! خاص طور پر FILEZILLA کے FTP سرور اور مرکری میل سرور آپ کو اپنے آپ کو محفوظ کرنا ضروری ہے.\rمیں کس طرح اپنے کمپیوٹر سے XAMPP کی خارج کروں؟\rآپ انسٹالر ورژن استعمال XAMPP کی نصب، کی UNINSTALLER استعمال کریں. کی UNINSTALLER آپ کی رجسٹری کی طرف سے تمام XAMPP کی اندراجات کو خارج کر دیں اور اس کے ساتھ XAMPP شامل کچھ نصب خدمات انسٹال کیا جائے گا. ہم انتہائی اگر انسٹالر VERSION.PLEASE بیک اپ سے آپ XAMPP کی ناتنصیب سے پہلے رکھنا چاہتے ہیں تمام اعداد و شمار XAMPP کی تنصیبات کے دور کرنے کے لئے انسٹال پروگرام استعمال کرتے ہیں مشورہ ہے کہ.\rآپ کو زپ اور 7ZIP ورژن کا استعمال کرتے ہوئے XAMPP کی نصب، تمام XAMPP کی سرورز کو بند اور تمام پینل سے باہر نکلیں. آپ کو کسی بھی خدمات نصب، انسٹال کریں اور انہیں بھی بند. اب صرف XAMPP کی نصب کیا جاتا ہے، جہاں پورے فولڈر کو خارج. صاف کرنے کے لئے کوئی رجسٹری اندراجات اور کوئی ماحول متغیر ہیں.\rXAMPP کی کی \"واپس موضوع پر\" ورژن کیا ہے؟\rXAMPP کی واپس موضوع پر (\"ہلکے وزن\" میں کے طور پر \"روشنی\" کا مطلب ہے) صرف پی ایچ پی اور MYSQL کا استعمال کرتے ہوئے فوری کام کے لئے سفارش کی جاتی ہے جس میں XAMPP کی اجزاء، کی ایک چھوٹی بنڈل ہے. اس طرح پارا میل اور FTP FILEZILLA کے طور پر کچھ سرورز یا فورم کے اوزار واپس موضوع پر ورژن میں یاد کر رہے ہیں.\rمیں اپنے ویب کے مواد کی جگہ چاہئے؟\rتمام ورلڈ وائڈ ویب دستاویزات کے لئے اہم ڈائریکٹری XAMPP\\\\HTDOCS\\\\ ہے. اگر آپ ایک فائل \"TEST.HTML\" اس ڈائریکٹوری میں ڈالیں, تو آپ اس تک رسائی حاصل کر سکتے ہیں\"URI \"HTTP://LOCALHOST/TEST.HTML اس کے ساتھ .\rاور \"TEST.PHP\"؟ صرف \"HTTP://LOCALHOST/TEST.PHP\" کا استعمال. ایک سادہ TESTSCRIPT ہو سکتا ہے:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rآپ کی ویب کے لئے ایک نئی ذیلی ڈائریکٹری؟ صرف ایک نئی ڈائریکٹری بنایں (\"E.G. \"NEW) ڈائریکٹری کے اندر \"XAMPP\\\\HTDOCS\\\\\" ایک ٹیسٹ فائل بنایں اور اس سے رسائی حاصل کریں \"HTTP://LOCALHOST/NEW/TEST.PHP\".\rمزید تفصیلات\rHTML:\rکارکردگی: \\XAMPP\\HTDOCS\rختم اجازت: .HTML .HTM\r=> بنیادی پیکیج\rSSI:\rکارکردگی: \\XAMPP\\HTDOCS\rختم اجازت: .SHTML\r=> بنیادی پیکیج\rCGI:\rکارکردگی: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rختم اجازت: .CGI\r=> بنیادی پیکیج\rPHP:\rکارکردگی: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rختم اجازت: .PHP\r=> بنیادی پیکیج\rPERL:\rکارکردگی: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rختم اجازت: .PL\r=> بنیادی پیکیج\rAPACHE::ASP PERL:\rکارکردگی: \\XAMPP\\HTDOCS\rختم اجازت: .ASP\r=> بنیادی پیکیج\rJSP JAVA:\rکارکردگی: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rختم اجازت: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rکارکردگی: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rختم اجازت: .HTML (U.A)\r=> TOMCAT ADD-ON\rمیں XAMPP کی تنصیب منتقل کر سکتے ہیں؟\rجی ہاں. XAMPP کی ڈائریکٹری کے منتقل کرنے کے بعد، آپ \"SETUP_XAMPP.BAT\" عملدرآمد ضروری ہے. ترتیب فائل میں راستے اس قدم کے ساتھ ایڈجسٹ کیا جائے گا.\rآپ کو ونڈوز سروس کے طور پر کسی بھی سرور انسٹال کیا ہے تو آپ کو پہلے ونڈوز سروس ہٹانے کے، اور ضروری ہے کے بعد آپ کو دوبارہ سروس انسٹال کر سکتے ہیں منتقل.\rانتباہ: آپ کے اپنے سکرپٹ کی طرف سے ترتیب فائل، پی ایچ پی کی ایپلی کیشنز کی طرح، ایڈجسٹ نہیں کر رہے ہیں. لیکن یہ انسٹالر کے لئے ایک \"پلگ ان\" لکھنے کے لئے ممکن ہے. اس طرح کے ایک پلگ ان کے ساتھ، انسٹالر بھی اس طرح کی فائلوں کو ایڈجسٹ کر سکتے ہیں.\rدیکھیے ورلڈ وائڈ ویب ڈائریکٹریز کے لئے \"خود کار طریقے سے شروع کے صفحات\" کیا ہیں؟\rاپاچی تقریب \"DIRECTORYINDEX\" کے لئے معیاری فائل کا نام \"INDEX.HTML\" یا \"INDEX.PHP کو\" ہے. آپ کو صرف ایک فولڈر (مثال کے طور پر \"HTTP://LOCALHOST/XAMPP/\") پر براؤزنگ کر رہے ہیں، اور اپاچی اس طرح ایک فائل تلاش کر سکتے ہیں ہر وقت، اپاچی اس فائل کی بجائے ایک ڈائرکٹری کی لسٹنگ کی نمائش ہے.\rمیں کہاں ترتیب تبدیل کر سکتے ہیں؟\rتقریبا XAMPP کی میں تمام ترتیبات آپ کو ترتیب فائل کے ساتھ تبدیل کر سکتے ہیں. بس ایک TEXTEDIT میں فائل کو کھولنے اور آپ چاہتے ہیں کی ترتیب کو تبدیل. صرف FILEZILLA کے اور مرکری کی درخواست کی تشکیل کے آلے کے ساتھ ترتیب دیا جانا چاہئے.\rکیوں XAMPP کی WINDOWS XP SP2 پر کام نہیں کر سکتے ہیں؟\rمائیکروسافٹ خود کار طریقے سے شروع ہوتا ہے جس سروس پیک 2 (SP2)، کے ساتھ ایک بہتر فائروال فراہم کرتا ہے. یہ فائروال اب بلاکس کے لئے ضروری بندرگاہوں 80 (HTTP) اور 443 (HTTPS) اور اپاچی شروع نہیں کر سکتے.\rسب سے تیز حل:\rٹول بار کے ساتھ مائیکروسافٹ فائر وال کو غیر فعال اور XAMPP کی زیادہ ONCES شروع کرنے کی کوشش کریں. بہتر حل سلامتی کے مرکز کے اندر اندر ایک رعایت کی وضاحت کرنے کے لئے ہے.\rمندرجہ ذیل بندرگاہوں کے بنیادی فعالیت کے لئے استعمال کیا جاتا ہے:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rکیوں XAMPP کی VISTA پر کام نہیں کرتا؟\rیوزر اکاؤنٹ کنٹرول (UAC)\rڈائریکٹری \"C: \\\\ \\\\ پروگرام فائلیں\" میں آپ بھی ایڈمن کے طور پر، مکمل لکھنا استحقاق نہیں ہے. یا آپ کو صرف محدود استحقاق ہے (کے لئے مثال کے طور پر \". \\\\ \\\\ XAMPP کی \\\\ \\\\ HTDOCS\"). اس صورت میں آپ کو ایک فائل میں ترمیم نہیں کر سکتے ہیں.\rحل:\rایکسپلورر کے اندر اندر آپ کی مراعات میں اضافہ (دائیں / سیکورٹی کلک کریں) یا صارف کے اکاؤنٹ کنٹرول (UAC) کو غیر فعال.\rآپ میں اپاچی / ایس کیو ایل انسٹال کیا ہے \"C: \\\\ \\\\ XAMPP کی\" ونڈوز سروس کے طور پر. لیکن آپ کو \"XAMPP کی کنٹرول پینل\" کے ساتھ خدمات روکنے / شروع نہیں کر سکتے یا ان انسٹال نہیں کر سکتے ہیں.\rحل:\rونڈوز یا غیر فعال UAC سے سروس منیجمنٹ کنسول استعمال کرتے ہیں.\rیوزر اکاؤنٹ کنٹرول (UAC) غیر فعال\rUAC کو غیر فعال کرنے کے لئے \"MSCONFIG\" پروگرام استعال کریں. \"MSCONFIG\" میں \"TOOLS\" میں جایں اور سلیکٹ \"DISABLE USER ACCOUNT CONTROL\" اور انتخاب کی توثیق کریں.اب آپکو لازمی WINDOWS دوبارہ شروع کرنا پڑے گی پھر آپ دوبارہ UAC فعال کر سکتے ہیں.\rمیں کس طرح MD5 حیض چیک کروں؟\rفائلوں کا آپس میں موازنہ کرنے کے لئے، اکثر CHECKSUMS کے استعمال کیا جاتا ہے. اس حیض MD5 (پیغام ڈائجسٹ الگورتھم 5) بنانے کے لئے ایک معیار.\rXAMPP کی پیکیج کے آپ کے ڈاؤن لوڈ، اتارنا درست ہے یا نہیں ہے اگر یہ MD5 حیض کے ساتھ آپ کو، ٹیسٹ کر سکتے ہیں. کورس کے آپ ان CHECKSUMS کے تشکیل دے سکتے ہیں جس میں ایک پروگرام کی ضرورت ہے. WINDOWS کے لیے آپ کو مائیکروسافٹ کی طرف سے ایک آلے کا استعمال کر سکتے ہیں:\rدستیابی اور فائل حیض سالمیت ستیاپک افادیت کی تفصیل\rیہ GNU MD5SUM طرح، MD5 CHECKSUMS کے تشکیل دے سکتے ہیں جو کسی بھی دوسرے پروگرام کا استعمال بھی ممکن ہے.\rآپ اس طرح کے ایک پروگرام (مثال کے طور FCIV.EXE) نصب ہے، آپ کو مندرجہ ذیل اقدامات کر سکتے ہیں:\rDOWNLOAD XAMPP (F.E. XAMPP-WIN32-1.8.2-0.EXE)\rکے ساتھ حیض تشکیل دیں:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rاور اب آپ کو آپ کے WINDOWS ایم کے لئے XAMPP کی پر تلاش کر سکتے ہیں ہے کہ ایک کے ساتھ اس حیض موازنہ کر سکتے ہیں.\rدونوں CHECKSUMS کے برابر ہیں، تو سب ٹھیک ہے. اگر نہیں تو، ڈاؤن لوڈ، اتارنا ٹوٹ جاتا ہے یا فائل کو تبدیل کر دیا گیا ہے.\rکیوں میرے PHP.INI میں تبدیلی کا اثر نہیں لیا ہے؟\rاگر \"PHP.INI\" میں تبدیلی کوئی اثر نہیں ہے، تو یہ ہو سکتا ہے کہ PHP کی ایک مختلف استعمال کر رہا ہو . آپ ()PHPINFO کے ساتھ اس بات کی تصدیق کر سکتے ہیں. URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP پر جائیں اور \"LOADED CONFIGURATION FILE\" کے لئے تلاش کریں. یہ قدر آپ \"PHP.INI\" PHP کی واقعی استعمال کر رہا ہے سے پتہ چلتا ہے.\rنوٹ:\rفائل \"PHP.INI\" آپکو APACHE دوبارہ سٹارٹ کرنا ہو گا تاکہ APACHE/PHP نئی تبدیلیوں کو پڑھ سکے.\rمدد کرو! XAMPP کی میں ایک وائرس ہے!\rSOME ANTIVIRUS PROGRAMS MISTAKE XAMPP FOR A VIRUS, TYPICALLY FLAGGING THE FILE XAMPP-MANAGER.EXE THIS IS A FALSE POSITIVE MEANING THAT THE ANTIVIRUS ERRONEOUSLY IDENTIFIED IT AS A VIRUS, WHEN IT IS NOT. BEFORE WE RELEASE EACH NEW VERSION OF XAMPP WE RUN IT THROUGH VIRUS SCANNING SOFTWARE. AT THE MOMENT WE ARE USING \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rمیں کس طرح اپنے ینٹیوائرس درخواست کی تشکیل کرتے ہیں؟\rہم بنڈل ویب ایپلیکیشن کو چلانے کے لئے ضروری تمام DEPENDENCES اور سرور شامل ہے، تو آپ XAMPP کی فائلوں کی بڑی تعداد میں انسٹال ہے مل جائے گا. آپ کو فعال ایک ینٹیوائرس اپلی کیشن کے ساتھ ایک WINDOWS مشین پر ایک XAMPP کی درخواست کو انسٹال کر رہے ہیں تو، یہ نمایاں طور پر کی تنصیب کو سست کر سکتے ہیں، اور (ویب سرور، ڈیٹا بیس سرور) کے سرورز کی ایک ینٹیوائرس سافٹ ویئر کی طرف سے بلاک کیا جا سکتا ہے کا ایک موقع بھی ہے . آپ کو فعال ایک ینٹیوائرس آلے کے ہے، کارکردگی کے مسائل کے بغیر XAMPP کی کو چلانے کے لئے مندرجہ ذیل ترتیبات چیک کریں:\rAPACHE، MYSQL یا کسی دوسرے سرور کے لئے: فصیل میں مستثنیات شامل کریں.\rعمل جب فائلوں کو اسکین: آپ تمام فائلوں کے لئے ینٹیوائرس سکین فعال ہے تو، سرورز کے لئے فائلوں کو سست کر سکتے ہیں.\rمختلف یو آر ایل کے لئے ٹریفک سکین کریں: آپ کو آپ کے اپنے مشین پر ساتھ XAMPP ترقی کر رہے ہیں، تو آپ ینٹیوائرس کی ترتیبات میں \"لوکل ہوسٹ\" ٹریفک خارج کر سکتے ہیں.\rکیوں APACHE سرور اپنے سسٹم پر شروع نہیں ہے؟\rیہ مسئلہ کئی وجوہات میں سے ایک ہو سکتا ہے:\rآپ کو زیادہ تو ایک HTTP سرور (تو IIS، سانبھر، ZEUS اور) شروع کر دیا ہے. صرف ایک سرور پورٹ 80 استعمال کر سکتے ہیں. خامی کا یہ پیغام مسئلہ کی طرف اشارہ ہے:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rتم نے اس طرح انٹرنیٹ ٹیلی فون \"اسکائپ\" بھی ہے جس کے بلاکس پورٹ 80 کے طور پر دوسرے سافٹ ویئر، ہے. > \"ایک متبادل پورٹ کے لئے استعمال پورٹ 80\" میں نشان ہٹا دیں اور اسکائپ دوبارہ شروع - کنکشن> -> اختیارات - مسئلہ \"اسکائپ\" ہے تو، آپ کے عوامل کو SKYPE میں جا سکتے ہیں. اب یہ کام کرنا چاہئے.\rآپ کو ایک فائر وال جس بلاکس APACHE بندرگاہ ہے. تمام فائر والز APACHE ساتھ ہم آہنگ ہیں، اور کبھی کبھی فائر وال غیر تابکار کافی نہیں ہے اور آپ اس تنصیب ربائی کریں ضروری ہے. خامی کا یہ پیغام ایک فائروال کی طرف اشارہ:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rAPACHE شروع کر سکتے ہیں، لیکن آپ کے براؤزر میں اس سے رابطہ قائم نہیں کر سکتے ہیں اس کے علاوہ مندرجہ ذیل میں سے ایک کی وجہ سے ہو سکتا ہے:\rکچھ وائرس سکینر فائر والز مداخلت کر سکتے ہیں اسی طرح ہے کہ میں اس وجہ سے کر سکتے.\rآپ سروس پیک 1 کے بغیر ایکس پی پروفیشنل ہے. آپ XAMPP کی کم از کم SP1 ہونا ضروری ہے.\rٹپ:\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\rکیوں اپاچی کے لئے اپنے CPU لوڈ تقریبا 99٪ ہے؟\rیہاں کھیل میں دو حالتوں میں سے ایک ہے. اپنے CPU باہر MAXING ہے، یا آپ براؤزر سرور سے رابطہ قائم کر سکتے ہیں، لیکن (نظام پیج لوڈ کرنے UNSUCESSFULLY کوشش کر رہا ہے) کچھ بھی نظر نہیں یا تو. دونوں صورتوں میں آپ اپاچی لاگ فائل میں مندرجہ ذیل پیغام حاصل کر سکتے ہیں:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rMPM ایک محفوظ عمل درآمد کرنے کے لئے واپس آتا ہے، لیکن کچھ کلائنٹ کی درخواستوں کو صحیح طریقے سے عملدرآمد نہیں کیا گیا. اس خرابی سے بچنے کے لئے، میں فلٹر قبول \"کوئی نہیں\" کے ساتھ \"ACCEPTFILTER\" استعمال \"\\\\ \\\\ XAMPP کی \\\\ \\\\ اپاچی \\\\ \\\\ CONF \\\\ \\\\ اضافی \\\\ HTTPD پر-MPM.CONF \\\\\" فائل.\rکیوں تصاویر اور سٹائل شیٹ ظاہر نہیں کر رہے ہیں؟\rکبھی کبھی کی نمائش تصاویر اور سٹائل شیٹ کے ساتھ مسائل ہیں. ان فائلوں کو ایک نیٹ ورک ڈرائیو پر واقع ہیں خاص طور پر اگر. اس صورت میں آپ کو چالو (یا شامل کریں) ایک فائل میں مندرجہ ذیل لائنوں \"\\XAMPP\\APACHE\\CONF \\ HTTPD.CONF\" اگر کر سکتے ہیں:\rENABLESENDFILE OFF\rENABLEMMAP OFF\rیہ مسئلہ بھی NETLIMITER طرح، بینڈ وڈتھ کو ریگولیٹری کے لئے پروگرام کی وجہ سے کیا جا سکتا ہے.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rمیں کس طرح MYSQL میں ایک روٹ کے پاس ورڈ مقرر کر سکتے ہیں؟\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rمیں اپنے MYSQL سرور کا استعمال کر سکتے ہیں؟\rجی ہاں. بس XAMPP کی پیکج کی طرف سے MYSQL شروع نہیں کرتے. دو سرورز اسی بندرگاہ پر شروع نہیں کیا جا سکتا ہے براہ مہربانی نوٹ. آپ کو \"جڑ\" کے لئے ایک پاس ورڈ مقرر ہے تو، فائل \"\\XAMPP\\PHPMYADMIN کے \\CONFIG.INC.PHP \\\" ترمیم کرنے کے لئے نہیں بھولنا.\rمیں کس طرح باہر سے PHPMYADMIN کے تک رسائی کو محدود کرتے ہیں؟\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rآپ MYSQL سرور تک رسائی حاصل کر سکتے ہیں اس سے پہلے کہ، PHPMYADMIN کے ایک صارف نام اور پاس ورڈ کے لئے آپ کو فوری طور پر کیا جائے گا. سب سے پہلے صارف \"جڑ\" کے لئے ایک پاس ورڈ کو قائم کرنے کے لئے نہیں بھولنا.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rکہاں PHP کے لئے IMAP کی حمایت کی ہے؟\rڈیفالٹ کے طور پر، PHP کے لئے IMAP کی حمایت کی وجہ سے WINDOWS 98 کی طرح کچھ تلاش ہوم ورژن کے ساتھ کچھ پراسرار ابتدا غلطیوں XAMPP کی میں غیر فعال ہے. آپ NT نظام کے ساتھ کام کرتے ہیں تو، آپ فائل کو کھولنے کر سکتے ہیں \"\\ XAMPP\\PHP \\PHP.INI\" لائن میں شروع نیم وقفہ اتارنے کی طرف سے PHP کی EXSTENSION چالو کرنے کے لئے \"؛ توسیع = PHP_IMAP.DLL\". یہ ہونا چاہئے:\rEXTENSION=PHP_IMAP.DLL\rاب APACHE دوبارہ شروع اور IMAP کام کرنا چاہئے. آپ ڈیفالٹ ترتیب میں فعال نہیں ہے جس میں ہر توسیع، کے لئے ایک ہی اقدامات استعمال کر سکتے ہیں.\rکیوں نہیں کچھ PHP اوپن سورس ایپلی کیشنز WINDOWS کے ساتھ XAMPP کام کرتے ہیں؟\rلینکس کے لئے لکھا گیا ہے کہ PHP کی ایپلی کیشنز یا ملانے کے بہت سے WINDOWS PORTED کیا نہیں کیا گیا ہے. \rCAN I DELETE THE \"INSTALL\" DIRECTORY AFTER INSTALLATION?\rیہ بہتر ہے. یہاں سکرپٹ بھی تمام اضافی پیکجوں کے (ONS شامل) اور XAMPP کی کی اپ گریڈ کے لئے کی ضرورت ہے.\rمیں کس طرح EACCELERATOR چالو کرتے ہیں؟\rدیگر (ZEND) ملانے کی طرح، آپ کو \"PHP.INI\" میں اسے چالو کر سکتے ہیں. اس فائل میں، لائن کو چالو کرنے کے \"؛ ZEND_EXTENSION =\" \\XAMPP\\PHP \\ ایکسٹینشن \\PHP_EACCELERATOR.DLL \"\". یہ ہونا چاہئے:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rمیں کس طرح اپنے MS SQL سرور کے لئے ایک کنکشن کی خرابی ٹھیک کروں؟\rMSSQL توسیع PHP.INI میں لوڈ کیا گیا تو صرف TCP / IP استعمال کیا جاتا ہے، بعض اوقات مسائل نظر آتے ہیں. آپ مائیکروسافٹ کی طرف سے ایک نئے \"NTWDBLIB.DLL\" کے ساتھ اس مسئلہ کو حل کر سکتے ہیں. نئے ایک کے ساتھ \"PHP \\XAMPP\\ \\\" \"APACHE \\بن \\XAMPP\\\" میں بڑی عمر کے فائل کی جگہ اور براہ مہربانی. کیونکہ لائسنس کی، ہم ساتھ XAMPP اس فائل کا نیا ورژن پیکج نہیں کر سکتے ہیں.\rمیں کس طرح PHP MCRYPT توسیع کے ساتھ کام کرتے ہیں؟\rاس کے لئے، ہم نے مثالیں اور ممکنہ حل کے ساتھ فورم میں موضوع کھول دیا ہے:٪ {MCRYPT}\rمائیکروسافٹ ACTIVE سرور (صفحات یسپ) کے ساتھ XAMPP کام کرتے ہیں؟\rPERL شامل کریں پر کے ساتھ نمبر اور APACHE :: یسپ ہی نہیں ہے. APACHE :: یسپ صرف PERL سکرپٹ جانتا ہے، لیکن انٹرنیٹ انفارمیشن سرور (IIS) سے یسپ بھی عام ہے VBSCRIPT جانتا ہے. لیکن یسپ NET. لئے، دستیاب 3RD پارٹی APACHE ماڈیول ہے.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rکاپی رائٹ 2022, APACHE FRIENDS\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم\r\n'),(92,'354097f5baaf72f7d1d02d73a60a0fca','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\rاکثر پوچھے گئے سوالات\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rکاپی رائٹ 2022, APACHE FRIENDS\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم\r\n'),(93,'9660cdf2bfe523c72b7cfefd43fc0b82','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rاکثر پوچھے گئے سوالات\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rکاپی رائٹ 2022, APACHE FRIENDS\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم\r\n'),(94,'67ea22a364f291d986b60312b5494902','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\rاکثر پوچھے گئے سوالات\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rکاپی رائٹ 2022, APACHE FRIENDS\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم\r\n'),(95,'bc41fe10a9788b17cc46f14148ab3693','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\rاکثر پوچھے گئے سوالات\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \rاکثر پوچھے گئے سوالات\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\nکمیونٹی\rXAMPP HAS BEEN AROUND FOR MORE THAN 10 YEARS  THERE IS A HUGE COMMUNITY BEHIND IT. YOU CAN GET INVOLVED BY JOINING OUR \rفورم\r, LIKING US ON \rFACEBOOK\r, OR FOLLOWING OUR EXPLOITS ON \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\rکاپی رائٹ 2022, APACHE FRIENDS\rبلاگ\rرازداری کی پالیسی\rCDN کی طرف سے فراہم\r\n'),(96,'b5b6d31ae480b65dbea4eee2e18fcc41','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\r常见问题\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \r经常提到的问题\r如何安装XAMPP？\rXAMPP在WINDOWS平台有三个不同版本：\r安装程序：\r大概是安装XAMPP最容易的方法了。\rZIP:\r为纯净软件爱好者提供的：XAMPP的标准ZIP压缩包。\r7ZIP:\r为网速慢的纯净软件爱好者提供的：XAMPP的7ZIP压缩包。\r注意：如果你解压文件的话，可能会被杀软误报毒。\r使用安装程序：\rXAMPP控制面板可以用于启动/停止APACHE, MYSQL, FILEZILLA和MERCURY以及将它们安装为服务。\r通过ZIP安装\r解压ZIP压缩文件到您选择的文件夹中。 XAMPP被提取到子目录\"C:\\\\XAMPP\"选定的目标目录下。然后启动文件“SETUP_XAMPP.BAT”进行配置以便XAMPP的配置调整到系统中。\r如果你选择根目录\"C:\\\\\"作为安装目标，你绝对不要启动\"SETUP_XAMPP.BAT\"。\r就像安装版一样，你现在可以使用XAMPP控制面板来完成更多工作。\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\r我如何免安装启动XAMPP？\r如果你将XAMPP解压到一个根目录，比如\"C:\\\\\"或者是\"D:\\\\\"，你就可以直接启动大多数服务器例如APACHE或者MYSQL而无需执行文件\"SETUP_XAMPP.BAT\"。\r如果你想在一个U盘上面安装XAMPP的话，不使用安装脚本，或者在安装脚本里面选择相对路径应该会是更好的做法。因为在不同的PC上面U盘的盘符应该都是不一样的。你可以通过安装脚本在任何时候从绝对路径切换到相对路径。\r下载页面上的安装包版本应该是安装XAMPP的最简单的方式了。安装过程结束之后，你会在开始菜单-程序-XAMPP下找到XAMPP。你可以使用XAMPP的控制面板来启动/停止任意一个服务器或者是安装/卸载服务。\rXAMPP控制面板可以用于启动/停止APACHE, MYSQL, FILEZILLA和MERCURY以及将它们安装为服务。\r我如何启动和停止XAMPP？\r通用的控制中心位于XAMPP控制面板(感谢WWW.NAT32.COM)。它开始于：\r\\XAMPP\\XAMPP-CONTROL.EXE\r您也可以使用一些批处理文件来启动/停止服务器：\rAPACHE & MYSQL 启动:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL 停止:\n\\XAMPP\\XAMPP_STOP.EXE\r启动APACHE\n\\XAMPP\\APACHE_START.BAT\r停止APACHE\n\\XAMPP\\APACHE_STOP.BAT\r启动MYSQL：\n\\XAMPP\\MYSQL_START.BAT\r停止MYSQL：\n\\XAMPP\\MYSQL_STOP.BAT\r启动MERCURY邮件服务器：\n\\XAMPP\\MERCURY_START.BAT\r停止MERCURY邮件服务器：\n\\XAMPP\\MERCURY_STOP.BAT\r启动FILEZILLA服务器：\n\\XAMPP\\FILEZILLA_START.BAT\r停止FILEZILLA服务器：\n\\XAMPP\\FILEZILLA_STOP.BAT\r我如何检查是否一切正常？\r在你喜欢的浏览器中输入下面的链接：\rHTTP://LOCALHOST/\r或 \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\r我如何将一个服务器安装成为服务？\r你可以将XAMPP中的每一个服务器安装成为WINDOWS服务。你也可以从XAMPP控制面板里面安装它。在这种情况下必须通过管理员权限运行控制面板或脚本。\r安装APACHE服务：\\\\XAMPP\\\\APACHE\\\\APACHE_INSTALLSERVICE.BAT\r卸载APACHE服务：\\\\XAMPP\\\\APACHE\\\\APACHE_UNINSTALLSERVICE.BAT \r安装MYSQL服务: \\\\XAMPP\\\\MYSQL\\\\MYSQL_INSTALLSERVICE.BAT \r卸载MYSQL服务: \\\\XAMPP\\\\MYSQL\\\\MYSQL_UNINSTALLSERVICE.BAT \r安装/卸载FILEZILLA服务: \\\\XAMPP\\\\FILEZILLA_SETUP.BAT \rMERCURY: 没有服务可供安装\rXAMPP准备好了吗？\rXAMPP是一个非常优秀而又实用的开发测试环境，XAMPP的配置是开放的，允许开发者任意去修改或配置适合您的开发环境。XAMPP并非商业运行环境，用于商业运作将是一个致命的环境！\r如下是XAMPP不安全的配置：\rMYSQL数据库管理帐号 (ROOT)没设置密码。\rMYSQL数据库可以通过网络打开。\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rMERCURY和FILEZILLA的默认用户是已知的。\r所有的点都可能成为一个巨大的安全隐患。尤其是如果XAMPP是可以通过网络或你的局域网外的人访问的话。使用防火墙或一个（带NAT的）路由器也是有帮助的。在有路由器或者防火墙的情况下，你的电脑正常情况下是无法从外部互联网访问的。是否修复这些问题要取决于你。XAMPP安全控制台可以提供一点小的帮助。\r请在发布任何东西到网上之前做好XAMPP的安全。一个防火墙或者一个外部路由器只能让你达到一个比较低的安全水平。需要高一点的安全的话，你可以运行下XAMPP安全控制台并设置密码。\r如果你想要让你的XAMPP通过互联网访问的话，你需要访问下述网站来修复一些问题：\rHTTP://LOCALHOST/SECURITY/\r借助安全控制台，您可以设置MYSQL的“ROOT”用户和PHPMYADMIN的密码。您还可以给XAMPP的演示页启用一个认证。\r这个基于网络的工具不能修复任何附加的安全问题！尤其是FILEZILLA FTP服务器和MERCURY邮件服务器，你必须自行保护它们。\r如何卸载XAMPP？\r如果你使用安装包版本安装了XAMPP，请使用卸载工具卸载。卸载工具会删除掉所有的XAMPP的文件并会卸载掉已经安装的服务，包括XAMPP自身。我们强烈推荐你使用卸载程序移除XAMPP的安装。请在卸载之前备份你所有想保留的文件。\r如果你使用ZIP或者7ZIP版本安装了XAMPP，请关掉所有的XAMPP服务器并退出控制面板。如果你安装了服务，也需要卸载并关闭他们。现在只需要简单的把XAMPP所在文件夹一删就完事了，不会再有需要清理的任何注册表项或者环境变量啦。\rXAMPP的“LITE”版本是什么玩意？\rXAMPP LITE（意思是“轻的”或者“轻量级的”）是一个更小的XAMPP的组件合集，推荐用来做一些只需要PHP和MYSQL的快速的工作。像MERCURY邮件或者是FILEZILLA的FTP服务器在这个版本里都是没有的。\r我应该把我的WEB内容放在哪里呢？\r所有WWW文档的根目录都是\\\\XAMPP\\\\HTDOCS。如果你在目录里放一个文件“TEST.HTML”，你可以通过这个URL访问它：HTTP://LOCALHOST/TEST.HTML。\r至于\"TEST.PHP\"呢？用\"HTTP://LOCALHOST/TEST.PHP\"就可以啦。一个简单的测试脚本可以这么写：\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\r想给你的WEB服务器设一个新的子目录？只需要在目录\\\\XAMPP\\\\HTDOCS新建个文件夹就行了（最好不要空格并且只使用英文字母和数字），并且建一个测试文件然后访问它，例如HTTP://LOCALHOST/NEW/TEST.PHP。\r更多细节\rHTML:\r可执行的： \\XAMPP\\HTDOCS\r允许的结尾： .HTML .HTM\r=> 基本的包\rSSI:\r可执行的： \\XAMPP\\HTDOCS\r允许的结尾： .SHTML\r=> 基本的包\rCGI:\r可执行的： \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\r允许的结尾： .CGI\r=> 基本的包\rPHP:\r可执行的： \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\r允许的结尾： .PHP\r=> 基本的包\rPERL:\r可执行的： \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\r允许的结尾： .PL\r=> 基本的包\rAPACHE::ASP PERL:\r可执行的： \\XAMPP\\HTDOCS\r允许的结尾： .ASP\r=> 基本的包\rJSP JAVA:\r可执行的： \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\r允许的结尾： .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\r可执行的： \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\r允许的结尾： .HTML (U.A)\r=> TOMCAT ADD-ON\r我可以移动XAMPP安装文件么？\r是的，当移动XAMPP文件目录之后，你必须执行一下\"SETUP_XAMPP.BAT\"。在配置文件里的路径会在这一步之后被改变。\r如果你已经将任意一个服务器安装成了WINDOWS服务，你必须先移除服务，移动之后你可以重新安装服务。\r警告：你自己的脚本的配置文件，例如你的PHP应用，是不会被调整的。但是你可以为安装工具写一个插件，借助这样一个插件，安装工具就也可以同时调整这些文件了。\r访问WWW目录的时候指向的“默认起始页”的名称是什么呢？\rAPACHE的\"DIRECTORYINDEX\"（目录起始页）功能的预设文件名是“INDEX.HTML”或者“INDEX.PHP”。每次当你访问一个文件夹的时候（例如HTTP://LOCALHOST/XAMPP/），APACHE会先找一下指定名称的文件，并且找的话会默认显示那个文件而不会再显示目录的文件列表啦。\r我可以在哪儿修改配置呢？\rXAMPP几乎所有的设置都可以在配置文件里修改。只需要在文本编辑器里打开文件然后就可以按你的需要修改设置了。只有FILEZILLA和MERCURY需要使用应用配置工具里自定义设置。\r为啥XAMPP不能在WINDOWS XP SP2下工作呢？\r微软在SERVICE PACK 2 (SP2)里面提供了一个更加高大上的会自动启动的防火墙，这个防火墙会拦截掉APACHE必需的80和443端口，然后APACHE就启动不了了。\r最快的解决方案：\r把微软那个防火墙给它关了，然后再启动一下XAMPP试试。更好的解决办法是在安全中心里面给XAMPP定义一个例外。\r下述端口是提供给基本功能用的：\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\r为什么XAMPP不能在VISTA上工作？\r用户帐户控制（UAC）\r在目录\"C:\\\\PROGRAM FILES\"当中你是没有完整的写权限的，即便管理员也不行。或者你就只有有限的权限（例如\".\\\\XAMPP\\\\HTDOCS\"）了。在这种情况下你就不能编辑文件了。\r解决方案：\r通过浏览器（右键-安全）来提高你的权限或者禁用用户帐户控制（UAC）\r你已经在\"C:\\\\XAMPP\"将APACHE/MYSQL安装成WINDOWS服务但你不能通过\"XAMPP控制面板\"启动/停止这些服务或者不能卸载它们。\r解决方案：\r从WINDOWS使用服务管理控制台或禁用UAC。\r禁用用户帐户控制（UAC）\r为了禁用UAC，你需要使用程序“MSCONFIG”。在MSCONFIG当中找到“工具”，选择“禁用用户账户控制”然后保存你的更改。现在你必须重启一下电脑。同时你也可以再次启动UAC。\r我如何检查MD5校验值呢？\r想要比较文件，通常使用的办法是计算校验值。MD5（消息摘要算法5）就是其中的一个生成校验值的标准。\r使用这个MD5校验值你可以检查出来你下载的XAMPP包是不是完好的。当然你需要有一个工具来生成这个校验值。WINDOWS用户可以使用微软的一个工具：\r可用性和文件校验和完整性验证程序的描述\r也可以使用其他能够生成MD5的程序，例如GNU MD5SUM。\r安装好这样的一个程序（例如FCIV.EXE）之后，你可以完成如下的步骤：\r下载XAMPP（例如XAMPP-WIN32-1.8.2-0.EXE）\r用于生成校验值的：\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\r然后你就可以用你的校验值和在XAMPP主页找到的校验值进行比较了。\r如果两个校验值是一样的，就是好的。否则，要么下载文件损坏了要么是文件被修改过。\r为啥我在PHP.INI里做的修改没有生效?\r如果在\"PHP.INI\"里做的修改没有生效，很可能是因为PHP用的是另外一个。你可以通过PHPINFO()来检查这一点。访问这个网址 HTTP://LOCALHOST/XAMPP/PHPINFO.PHP 并找到LOADED CONFIGURATION FILE。这个值会告诉你PHP实际使用的PHP.INI。\r注意：\r在修改PHP.INI之后你必须重启APACHE这样APACHE/PHP才能够读取设置。\r卧槽！XAMPP里头有病毒！\r有些杀软会误报你懂的。通常他们会把XAMPP-MANAGER.EXE这个文件当成病毒。误报的意思就是本来不是病毒的东西被杀软错误的看做了病毒。我们每次发布新版XAMPP的时候都会用杀软扫一遍的。我们目前使用的是 \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\r我如何配置我的杀软？\r我们已经添加好了所有运行这个打包好的WEB应用所需的必要组件和服务器软件，所以你会发现XAMPP会安装一大堆文件。如果你在一个开着杀软的WINDOWS的机器上安装XAMPP应用，可能会明显的拖缓安装进程的速度，而且还可能会有服务器（如WEB服务器，数据库服务器）被杀软阻塞了。如果你有开着的杀软，请检查下列可以保证运行XAMPP而不造成性能问题的设置：\r给防火墙添加例外：针对APACHE，MYSQL或者其他任何的服务器。\r执行的时候扫描文件：如果你对所有文件都启动了杀软的扫描功能，服务器的可执行文件可能会被拖慢。\r扫描不同网址的流量：如果你在自己的机器上用XAMPP做开发，你可以在杀软的设置里排除掉LOCALHOST的流量监测。\r为什么APACHE服务器在我的系统上启动不了呢？\r这个问题可能是由这几种原因之一造成的：\r你开启了不止一个HTTP的服务器(IIS, SAMBAR, ZEUS以及别的什么)。只有一个服务器可以占用80端口。这个错误消息指出了这个问题：\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\r你有其他的软件，例如也会阻断80端口的互联网电话软件“SKYPE”。如果问题来源于SKYPE，你可以进入SKYPE找到操作 - >选项 - >连接 - >取消勾选“使用端口80作为备用端口”，然后重新启动SKYPE。现在应该可以正常工作了。\r你有一个阻断了APACHE端口的防火墙。不是所有的防火墙都兼容APACHE，而有的时候禁用防火墙是不够的，还得卸载掉它才行。这个错误信息是指向防火墙的：\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\r此外，如果APACHE可以启动，但您的浏览器无法连接到它可能是由于以下原因之一：\r有些病毒扫描程序可能会像防火墙一样产生干扰并导致这个问题。\r你的XP PROFESSIONAL没有安装SP1。你必须至少安装一个SP1才能用XAMPP。\r提示：\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\r为什么我的APACHE占用的CPU负载接近99%呢？\r有两种情况，要么是你的CPU确实达到上限了，要么你的浏览器能够连接到服务器但是啥也看不到（系统尝试加载页面但是失败了），不管是哪种情况你都可以在APACHE的LOG文件里面找到下述信息：\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\r多道处理模块（MPM）回归到一个更加安全的执行模式，从而导致一些客户端的请求没有没有正确的执行。为了避免这样的错误，可以在\"\\\\XAMPP\\\\APACHE\\\\CONF\\\\EXTRA\\\\HTTPD-MPM.CONF\"文件当中将可接受的过滤器\"ACCEPTFILTER\"置为\"NONE\"。\r为什么图片和样式表显示不出来？\r有时候显示图片和样式表会有问题，特别是如果这些文件位于网络驱动器上的时候。在这种情况下，您可以启用（或增加）一行，如果文件\"\\\\XAMPP\\\\APACHE\\\\CONF\\\\HTTPD.CONF\"中的以下行:\rENABLESENDFILE OFF\rENABLEMMAP OFF\r这个问题也可能是由带宽调整软件，例如NETLIMITER导致的。\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\r我如何在MYSQL里面设置一个ROOT的密码？\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\r我可以使用自己的MYSQL服务器么？\r可以的，只是不要启动XAMPP包里的MYSQL就够了。请注意两个服务器不能在同一个端口上同时启动如果你已经设置了一个ROOT的密码，请不要忘记修改这个文件：\\\\XAMPP\\\\PHPMYADMIN\\\\CONFIG.INC.PHP。\r我如何限制PHPMYADMIN的外部访问呢？\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\r当你能访问MYSQL服务器之前，PHPMYADMIN会提示你输入用户名和密码。不要忘记先给用户\"ROOT\"设个密码哦。\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rPHP的IMAP支持在哪儿呢？\r默认的话，在XAMPP里面PHP对IMAP的支持是被停用的，因为对于某些家用的系统版本比如WINDOWS 98会出现一些诡异的初始化错误。如果你用的是WINDOWS NT系统的话，你可以打开文件\"\\\\XAMPP\\\\PHP\\\\PHP.INI\"并去掉\";EXTENSION=PHP_IMAP.DLL\"这一行前面的分号来激活这个PHP扩展。它应该是这样的：\rEXTENSION=PHP_IMAP.DLL\r现在重启一下APACHE然后IMAP就好使啦。你可以使用同样的步骤来操作任何一个在默认配置里没有激活的扩展。\r为什么一些PHP开源应用不能在WINDOWS版的XAMPP工作呢？\r许多PHP应用或者扩展都是为LINUX写的，还没有被移植到WINDOWS。 \rCAN I DELETE THE \"INSTALL\" DIRECTORY AFTER INSTALLATION?\r最好不要这样。所有的附加组件和XAMPP的升级仍然是需要使用这个脚本的。\r我如何激活EACCELERATOR？\r就像很多(ZEND)扩展一样，你可以在\"PHP.INI\"里激活它。在这个文件里，启用这一行\";ZEND_EXTENSION = \"\\\\XAMPP\\\\PHP\\\\EXT\\\\PHP_EACCELERATOR.DLL\"\"。它应该是这样子的：\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\r我如何修复我的MS SQL服务器的连接错误？\r如果MSSQL扩展加载到了PHP.INI，有时候当只有TCP/IP使用的时候会出问题。你可以从微软获取一个新的“NTWDBLIB.DLL”来修复这个问题。请用新的替换掉位于\"\\\\XAMPP\\\\APACHE\\\\BIN\"和\"\\\\XAMPP\\\\PHP\"的旧的文件。因为许可证问题，我们不能把这个文件的更新版本打包进XAMPP。\r我如何使用PHP MCRYPT扩展？\r为了这个，我们已经在社区里开了一个话题，关于例子和有效的解决方案：\rMCRYPT主题\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\r不行。那个和带有PERL的APACHE::ASP附加组件是不一样的。APACHE::ASP只能运行PERL脚本，但是IIS上的ASP文件还会有正常的VBSCRIPT。不过对于ASP .NET，有一个第三方的APACHE扩展模块可以使用。\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版权所有(C) 2022, APACHE FRIENDS\r博客\r隐私政策\rCDN提供\r\n'),(97,'6b051ba0620247463e14b4de4cd12697','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\r常见问题\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版权所有(C) 2022, APACHE FRIENDS\r博客\r隐私政策\rCDN提供\r\n'),(98,'a65a3ffe49db87a1dd985cf9ada7ac44','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\r常见问题\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版权所有(C) 2022, APACHE FRIENDS\r博客\r隐私政策\rCDN提供\r\n'),(99,'5707355e7e9dd5c4a54d95014ff5125b','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\r常见问题\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版权所有(C) 2022, APACHE FRIENDS\r博客\r隐私政策\rCDN提供\r\n'),(100,'08b88bfc9f7e8cca95db51b345f48b29','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\r常见问题\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \r常见问题\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\n社区\rXAMPP已经存在了大约十多年——在它背后有一个巨大的社区。你可以通过加入我们的\r论坛\r，在\rFACEBOOK\r上喜欢我们，在\rTWITTER\r上关注我们的成就。\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版权所有(C) 2022, APACHE FRIENDS\r博客\r隐私政策\rCDN提供\r\n'),(101,'595a97f31bbc428b7771826304bb7e4f','XAMPP FAQS FOR WINDOWS\r\nAPACHE FRIENDS\rMENU\r常見問題\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rFREQUENTLY ASKED QUESTIONS\rHOW DO I INSTALL XAMPP?\rXAMPP FOR WINDOWS EXISTS IN THREE DIFFERENT FLAVORS:\rINSTALLER:\rPROBABLY THE EASIEST WAY TO INSTALL XAMPP.\rZIP:\rFOR PURISTS: XAMPP AS ORDINARY ZIP ARCHIVE.\r7ZIP:\rFOR PURISTS WITH LOW BANDWIDTH: XAMPP AS 7ZIP ARCHIVE.\rNOTE: IF YOU EXTRACT THE FILES, THERE CAN BE FALSE-POSITIVES VIRUS WARNINGS.\rUSING THE INSTALLER:\rTHE XAMPP CONTROL PANEL FOR START/STOP APACHE, MYSQL, FILEZILLA & MERCURY OR INSTALL THESE SERVER AS SERVICES.\rINSTALLING FROM ZIP\rUNZIP THE ZIP ARCHIVES INTO THE FOLDER OF YOUR CHOICE. XAMPP IS EXTRACTING TO THE SUBDIRECTORY \"C:\\XAMPP\" BELOW THE SELECTED TARGET DIRECTORY. NOW START THE FILE \"SETUP_XAMPP.BAT\", TO ADJUST THE XAMPP CONFIGURATION TO YOUR SYSTEM.\rIF YOU CHOOSE A ROOT DIRECTORY \"C:\\\" AS TARGET, YOU MUST NOT START \"SETUP_XAMPP.BAT\".\rLIKE WITH THE INSTALLER VERSION, YOU CAN NOW USE THE \"XAMPP CONTROL PANEL\" FOR ADDITIONAL TASKS.\rDOES XAMPP INCLUDE MYSQL OR MARIADB?\rSINCE XAMPP 5.5.30 AND 5.6.14, XAMPP SHIPS MARIADB INSTEAD OF MYSQL. THE COMMANDS AND TOOLS ARE THE SAME FOR BOTH.\rHOW CAN I START XAMPP WITHOUT SETUP?\rIF YOU EXTRACT XAMPP IN A TOP LEVEL FOLDER LIKE \"C:\\\" OR \"D:\\\", YOU CAN START MOST SERVERS LIKE APACHE OR MYSQL DIRECTLY WITHOUT EXECUTION OF THE FILE \"SETUP_XAMPP.BAT\".\rNOT USING THE SETUP SCRIPT, OR SELECTING RELATIVE PATHS IN THE SETUP SCRIPT, IS PREFERRED IF YOU ARE INSTALLING XAMPP ON A USB DRIVE. BECAUSE ON EACH PC SUCH A DRIVE CAN HAVE AN OTHER DRIVE LETTER. YOU CAN SWITCH FROM ABSOLUTE TO RELATIVE PATHS AT ANY TIME WITH THE SETUP SCRIPT.\rUSING THE INSTALLER FROM OUR DOWNLOADS PAGE IS THE EASIEST WAY TO INSTALL XAMPP. AFTER THE INSTALLATION IS COMPLETE, YOU WILL FIND XAMPP UNDER START | PROGRAMS | XAMPP. YOU CAN USE THE XAMPP CONTROL PANEL TO START/STOP ALL SERVER AND ALSO INSTALL/UNINSTALL SERVICES.\rTHE XAMPP CONTROL PANEL FOR START/STOP APACHE, MYSQL, FILEZILLA & MERCURY OR INSTALL THESE SERVER AS SERVICES.\rHOW DO I START AND STOP XAMPP?\rTHE UNIVERSAL CONTROL CENTER IS THE \"XAMPP CONTROL PANEL\" (THANKS WWW.NAT32.COM). IT IS STARTED WITH:\r\\XAMPP\\XAMPP-CONTROL.EXE\rYOU CAN ALSO USE SOME BATCHFILES TO START/STOP THE SERVERS:\rAPACHE & MYSQL START:\n\\XAMPP\\XAMPP_START.EXE\rAPACHE & MYSQL STOP:\n\\XAMPP\\XAMPP_STOP.EXE\rAPACHE START:\n\\XAMPP\\APACHE_START.BAT\rAPACHE STOP:\n\\XAMPP\\APACHE_STOP.BAT\rMYSQL START:\n\\XAMPP\\MYSQL_START.BAT\rMYSQL STOP:\n\\XAMPP\\MYSQL_STOP.BAT\rMERCURY MAILSERVER START:\n\\XAMPP\\MERCURY_START.BAT\rMERCURY MAILSERVER STOP:\n\\XAMPP\\MERCURY_STOP.BAT\rFILEZILLA SERVER START:\n\\XAMPP\\FILEZILLA_START.BAT\rFILEZILLA SERVER STOP:\n\\XAMPP\\FILEZILLA_STOP.BAT\rHOW CAN I TEST THAT EVERYTHING WORKED?\rTYPE IN THE FOLLOWING URL AT YOUR FAVOURITE WEB BROWSER:\rHTTP://LOCALHOST/\rOR \rHTTP://127.0.0.1/\rYOU SHOULD SEE THE XAMPP START PAGE, AS SHOWN BELOW.\rHOW CAN I INSTALL A SERVER AS A SERVICE?\rEACH SERVER IN XAMPP YOU CAN INSTALL ALSO AS WINDOWS SERVICE. YOU CAN ALSO INSTALL IT FROM THE XAMPP CONTROL PANEL. IN THIS CASE IT IS NECESSARY TO RUN THE SCRIPTS OR THE CONTROL PANEL WITH ADMINISTRATOR PRIVILEGES.\rAPACHE SERVICE INSTALL: \\XAMPP\\APACHE\\APACHE_INSTALLSERVICE.BAT\rAPACHE SERVICE UNINSTALL: \\XAMPP\\APACHE\\APACHE_UNINSTALLSERVICE.BAT \rMYSQL SERVICE INSTALL: \\XAMPP\\MYSQL\\MYSQL_INSTALLSERVICE.BAT \rMYSQL SERVICE UNINSTALL: \\XAMPP\\MYSQL\\MYSQL_UNINSTALLSERVICE.BAT \rFILEZILLA SERVICE (UN)INSTALL: \\XAMPP\\FILEZILLA_SETUP.BAT \rMERCURY: NO SERVICE INSTALLATION AVAILABLE\rIS XAMPP PRODUCTION READY?\rXAMPP IS NOT MEANT FOR PRODUCTION USE BUT ONLY FOR DEVELOPMENT ENVIRONMENTS. XAMPP IS CONFIGURED TO BE OPEN AS POSSIBLE TO ALLOW THE DEVELOPER ANYTHING HE/SHE WANTS. FOR DEVELOPMENT ENVIRONMENTS, THIS IS GREAT BUT IN A PRODUCTION ENVIRONMENT, IT COULD BE FATAL.\rHERE A LIST OF MISSING SECURITY IN XAMPP:\rTHE MYSQL ADMINISTRATOR (ROOT) HAS NO PASSWORD.\rTHE MYSQL DAEMON IS ACCESSIBLE VIA NETWORK.\rPROFTPD USES THE PASSWORD \"LAMPP\" FOR USER \"DAEMON\".\rTHE DEFAULT USERS OF MERCURY AND FILEZILLA ARE KNOWN.\rALL POINTS CAN BE A HUGE SECURITY RISK. ESPECIALLY IF XAMPP IS ACCESSIBLE VIA NETWORK AND PEOPLE OUTSIDE YOUR LAN. IT CAN ALSO HELP TO USE A FIREWALL OR A (NAT) ROUTER. IN CASE OF A ROUTER OR FIREWALL, YOUR PC IS NORMALLY NOT ACCESSIBLE VIA NETWORK. IT IS UP TO YOU TO FIX THESE PROBLEMS. AS A SMALL HELP THERE IS THE \"XAMPP SECURITY CONSOLE\".\rPLEASE SECURE XAMPP BEFORE PUBLISHING ANYTHING ONLINE. A FIREWALL OR AN EXTERNAL ROUTER ARE ONLY SUFFICIENT FOR LOW LEVELS OF SECURITY. FOR SLIGHTLY MORE SECURITY, YOU CAN RUN THE \"XAMPP SECURITY CONSOLE\" AND ASSIGN PASSWORDS.\rIF YOU WANT HAVE YOUR XAMPP ACCESSIBLE FROM THE INTERNET, YOU SHOULD GO TO THE FOLLOWING URI WHICH CAN FIX SOME PROBLEMS:\rHTTP://LOCALHOST/SECURITY/\rWITH THE SECURITY CONSOLE YOU CAN SET A PASSWORD FOR THE MYSQL USER \"ROOT\" AND PHPMYADMIN. YOU CAN ALSO ENABLE A AUTHENTICATION FOR THE XAMPP DEMOPAGES.\rTHIS WEB BASED TOOL DOES NOT FIX ANY ADDITIONAL SECURITY ISSUES! ESPECIALLY THE FILEZILLA FTP SERVER AND THE MERCURY MAIL SERVER YOU MUST SECURE YOURSELF.\rHOW DO I UNINSTALL XAMPP?\rIF YOU INSTALLED XAMPP USING THE INSTALLER VERSION, PLEASE USE THE UNINSTALLER. THE UNINSTALLER WILL DELETE ALL XAMPP ENTRIES FROM YOUR REGISTRY AND IT WILL UNINSTALL SOME INSTALLED SERVICES INCLUDED WITH XAMPP. WE HIGHLY RECOMMEND THAT YOU USE THE UNINSTALL PROGRAM FOR REMOVING XAMPP INSTALLATIONS FROM THE INSTALLER VERSION.PLEASE BACKUP ALL THE DATA YOU WANT TO KEEP BEFORE UNINSTALLING XAMPP.\rIF YOU INSTALLED XAMPP USING THE ZIP AND 7ZIP VERSIONS, SHUT DOWN ALL XAMPP SERVERS AND EXIT ALL PANELS. IF YOU INSTALLED ANY SERVICES, UNINSTALL AND SHUT THEM DOWN TOO. NOW SIMPLY DELETE THE ENTIRE FOLDER WHERE XAMPP IS INSTALLED. THERE ARE NO REGISTRY ENTRIES AND NO ENVIRONMENT VARIABLES TO CLEAN UP.\rWHAT IS THE \"LITE\" VERSION OF XAMPP?\rXAMPP LITE (MEANS \"LIGHT\" AS IN \"LIGHT-WEIGHT\") IS A SMALLER BUNDLE OF XAMPP COMPONENTS, WHICH IS RECOMMENDED FOR QUICK WORK USING ONLY PHP AND MYSQL. SOME SERVERS OR TOOLS SUCH AS MERCURY MAIL AND FILEZILLA FTP ARE MISSING IN THE LITE VERSION.\rWHERE SHOULD I PLACE MY WEB CONTENT?\rTHE MAIN DIRECTORY FOR ALL WWW DOCUMENTS IS \\XAMPP\\HTDOCS. IF YOU PUT A FILE \"TEST.HTML\" IN THIS DIRECTORY, YOU CAN ACCESS IT WITH THE URI \"HTTP://LOCALHOST/TEST.HTML\".\rAND \"TEST.PHP\"? JUST USE \"HTTP://LOCALHOST/TEST.PHP\". A SIMPLE TESTSCRIPT CAN BE:\r<?PHP\rECHO \'HELLO WORLD\'; \r?>\rA NEW SUBDIRECTORY FOR YOUR WEB? JUST MAKE A NEW DIRECTORY (E.G. \"NEW\") INSIDE THE DIRECTORY \"\\XAMPP\\HTDOCS\" (BEST WITHOUT WHITESPACES AND ONLY ASCII), CREATE A TEST FILE IN THIS DIRECTORY AND ACCESS IT WITH \"HTTP://LOCALHOST/NEW/TEST.PHP\".\rFURTHER SPECIFICS\rHTML:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .HTML .HTM\r=> BASIC PACKAGE\rSSI:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .SHTML\r=> BASIC PACKAGE\rCGI:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .CGI\r=> BASIC PACKAGE\rPHP:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .PHP\r=> BASIC PACKAGE\rPERL:\rEXECUTABLE: \\XAMPP\\HTDOCS AND \\XAMPP\\CGI-BIN\rALLOWED ENDINGS: .PL\r=> BASIC PACKAGE\rAPACHE::ASP PERL:\rEXECUTABLE: \\XAMPP\\HTDOCS\rALLOWED ENDINGS: .ASP\r=> BASIC PACKAGE\rJSP JAVA:\rEXECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rALLOWED ENDINGS: .JSP\r=> TOMCAT ADD-ON\rSERVLETS JAVA:\rEXECUTABLE: \\XAMPP\\TOMCAT\\WEBAPPS\\JAVA (E.G.)\rALLOWED ENDINGS: .HTML (U.A)\r=> TOMCAT ADD-ON\rCAN I MOVE THE XAMPP INSTALLATION?\rYES. AFTER MOVING OF THE XAMPP DIRECTORY, YOU MUST EXECUTE \"SETUP_XAMPP.BAT\". THE PATHS IN THE CONFIGURATION FILES WILL BE ADJUSTED WITH THIS STEP.\rIF YOU HAVE INSTALLED ANY SERVER AS WINDOWS SERVICE, YOU MUST FIRST REMOVE THE WINDOWS SERVICE, AND AFTER THE MOVING YOU CAN INSTALL THE SERVICE AGAIN.\rWARNING: THE CONFIGURATION FILES FROM YOUR OWN SCRIPTS, LIKE PHP APPLICATIONS, ARE NOT ADJUSTED. BUT IT\'S POSSIBLE TO WRITE A \"PLUG-IN\" FOR THE INSTALLER. WITH SUCH A PLUG-IN, THE INSTALLER CAN ADJUST SUCH FILES TOO.\rWHAT ARE \"AUTOMATIC START PAGES\" FOR THE WWW DIRECTORIES?\rTHE STANDARD FILENAME FOR THE APACHE FUNCTION \"DIRECTORYINDEX\" IS \"INDEX.HTML\" OR \"INDEX.PHP\". EVERY TIME YOU ARE JUST BROWSING TO A FOLDER (E.G. \"HTTP://LOCALHOST/XAMPP/\"), AND APACHE CAN FIND SUCH A FILE, APACHE IS DISPLAYING THIS FILE INSTEAD OF A DIRECTORY LISTING.\rWHERE CAN I CHANGE THE CONFIGURATION?\rALMOST ALL SETTINGS IN XAMPP YOU CAN CHANGE WITH CONFIGURATION FILES. JUST OPEN THE FILE IN A TEXTEDIT AND CHANGE THE SETTING YOU WANT. ONLY FILEZILLA AND MERCURY SHOULD BE CONFIGURED WITH THE APPLICATION CONFIG TOOL.\rWHY CAN\'T XAMPP WORK ON WINDOWS XP SP2?\rMICROSOFT DELIVERS A BETTER FIREWALL WITH SERVICE PACK 2 (SP2), WHICH STARTS AUTOMATICALLY. THIS FIREWALL NOW BLOCKS THE NECESSARY PORTS 80 (HTTP) AND 443 (HTTPS) AND APACHE CAN\'T START.\rTHE FAST SOLUTION:\rDISABLE THE MICROSOFT FIREWALL WITH THE TOOLBAR AND TRY TO START XAMPP ONCES MORE. THE BETTER SOLUTION IS TO DEFINE AN EXCEPTION WITHIN THE SECURITY CENTER.\rTHE FOLLOWING PORTS ARE USED FOR BASIC FUNCTIONALITY:\rAPACHE (HTTP): PORT 80\rAPACHE (WEBDAV): PORT 81\rAPACHE (HTTPS): PORT 443\rMYSQL: PORT 3306\rFILEZILLA (FTP): PORT 21\rFILEZILLA (ADMIN): PORT 14147\rMERCURY (SMTP): PORT 25\rMERCURY (POP3): PORT 110\rMERCURY (IMAP): PORT 143\rMERCURY (HTTP): PORT 2224\rMERCURY (FINGER): PORT 79\rMERCURY (PH): PORT 105\rMERCURY (POPPASS): PORT 106\rTOMCAT (AJP/1.3): PORT 8009\rTOMCAT (HTTP): PORT 8080\rWHY DOESN\'T XAMPP WORK ON VISTA?\rUSER ACCOUNT CONTROL (UAC)\rIN THE DIRECTORY \"C:\\PROGRAM FILES\" YOU DON\'T HAVE FULL WRITE PRIVILEGES, EVEN AS ADMIN. OR YOU HAVE ONLY LIMITED PRIVILEGES (E.G. FOR \".\\XAMPP\\HTDOCS\"). IN THIS CASE YOU CAN\'T EDIT A FILE.\rSOLUTION:\rRAISE YOUR PRIVILEGES WITHIN EXPLORER (RIGHT CLICK / SECURITY) OR DEACTIVATE THE USER ACCOUNT CONTROL (UAC).\rYOU HAVE INSTALLED APACHE/MYSQL IN \"C:\\XAMPP\" AS WINDOWS SERVICE. BUT YOU CAN\'T START/STOP THE SERVICES WITH THE \"XAMPP CONTROL PANEL\" OR CAN\'T UNINSTALL THEM.\rSOLUTION:\rUSE THE SERVICE MANAGEMENT CONSOLE FROM WINDOWS OR DEACTIVATE UAC.\rDISABLING THE USER ACCOUNT CONTROL (UAC)\rTO DEACTIVATE THE UAC, USE THE PROGRAM \"MSCONFIG\". IN \"MSCONFIG\" GO TO \"TOOLS\", SELECT \"DISABLE USER ACCOUNT CONTROL\" AND VERIFY YOUR SELECTION. NOW YOU MUST RESTART WINDOWS. AT THE SAME TIME, YOU CAN ENABLE THE UAC AGAIN.\rHOW DO I CHECK THE MD5 CHECKSUM?\rTO COMPARE FILES, OFTEN CHECKSUMS ARE USED. A STANDARD TO CREATE THIS CHECKSUM MD5 (MESSAGE DIGEST ALGORITHM 5).\rWITH THIS MD5 CHECKSUM YOU CAN TEST, IF YOUR DOWNLOAD OF THE XAMPP PACKAGE IS CORRECT OR NOT. OF COURSE YOU NEED A PROGRAM WHICH CAN CREATE THESE CHECKSUMS. FOR WINDOWS YOU CAN USE A TOOL FROM MICROSOFT:\rAVAILABILITY AND DESCRIPTION OF THE FILE CHECKSUM INTEGRITY VERIFIER UTILITY\rIT\'S ALSO POSSIBLE TO USE ANY OTHER PROGRAM WHICH CAN CREATE MD5 CHECKSUMS, LIKE THE GNU MD5SUM.\rAS YOU HAVE INSTALLED SUCH A PROGRAM (E.G. FCIV.EXE), YOU CAN DO FOLLOWING STEPS:\rDOWNLOAD XAMPP (F.E. XAMPP-WIN32-1.8.2-0.EXE)\rCREATE THE CHECKSUM WITH:\rFCIV.EXE XAMPP-WIN32-1.8.2-0.EXE\rAND NOW YOU CAN COMPARE THIS CHECKSUM WITH THAT ONE YOU CAN FIND ON THE XAMPP FOR WINDOWS HOMEPAGE.\rIF BOTH CHECKSUMS EQUAL, ALL IS OK. IF NOT, THE DOWNLOAD IS BROKEN OR THE FILE HAS BEEN CHANGED.\rWHY HAVE CHANGES IN MY PHP.INI NOT TAKEN EFFECT?\rIF A CHANGE IN THE \"PHP.INI\" HAS NO EFFECT, IT\'S POSSIBLE PHP IS USING A DIFFERENT ONE. YOU CAN VERIFY THIS WITH PHPINFO(). GO TO THE URI HTTP://LOCALHOST/XAMPP/PHPINFO.PHP AND SEARCH FOR \"LOADED CONFIGURATION FILE\". THIS VALUE SHOWS YOU THE \"PHP.INI\" PHP IS REALLY USING.\rNOTE:\rAFTER CHANGING THE \"PHP.INI\" YOU HAVE TO RESTART APACHE SO THAT APACHE/PHP CAN READ THE NEW SETTINGS.\rHELP! THERE IS A VIRUS IN XAMPP!\rSOME ANTIVIRUS PROGRAMS MISTAKE XAMPP FOR A VIRUS, TYPICALLY FLAGGING THE FILE XAMPP-MANAGER.EXE THIS IS A FALSE POSITIVE MEANING THAT THE ANTIVIRUS ERRONEOUSLY IDENTIFIED IT AS A VIRUS, WHEN IT IS NOT. BEFORE WE RELEASE EACH NEW VERSION OF XAMPP WE RUN IT THROUGH VIRUS SCANNING SOFTWARE. AT THE MOMENT WE ARE USING \rKAPERSKY ONLINE VIRUS SCANNER\r. YOU CAN ALSO USE THE ONLINE TOOL \rVIRUS TOTAL\rFOR SCANNING XAMPP OR SEND US AN EMAIL TO SECURITY (AT) APACHEFRIENDS (DOT) ORG IF YOU FIND ANY ISSUE.\rHOW DO I CONFIGURE MY ANTIVIRUS APPLICATION?\rWE HAVE INCLUDED ALL DEPENDENCES AND SERVERS REQUIRED FOR RUNNING THE BUNDLED WEB APPLICATION, SO YOU WILL FIND THAT XAMPP INSTALLS LARGE NUMBERS OF FILES. IF YOU ARE INSTALLING A XAMPP APPLICATION ON A WINDOWS MACHINE WITH AN ANTIVIRUS APP ENABLED, THIS MAY SLOW DOWN THE INSTALLATION SIGNIFICANTLY, AND THERE IS ALSO A CHANCE THAT ONE OF THE SERVERS (WEB SERVER, DATABASE SERVER) MAY BE BLOCKED BY THE ANTIVIRUS SOFTWARE. IF YOU HAVE AN ANTIVIRUS TOOL ENABLED, CHECK THE FOLLOWING SETTINGS FOR RUNNING XAMPP WITHOUT PERFORMANCE ISSUES:\rADD EXCEPTIONS IN THE FIREWALL: FOR APACHE, MYSQL OR ANY OTHER SERVER.\rSCAN FILES WHEN EXECUTING: IF YOU HAVE ENABLED THE ANTIVIRUS SCAN FOR ALL FILES, THE EXECUTABLE FILES FOR THE SERVERS MAY SLOW DOWN.\rSCAN THE TRAFFIC FOR DIFFERENT URLS: IF YOU ARE DEVELOPING WITH XAMPP ON YOUR OWN MACHINE, YOU CAN EXCLUDE \"LOCALHOST\" TRAFFIC IN THE ANTIVIRUS SETTINGS.\rWHY DOESN\'T THE APACHE SERVER START ON MY SYSTEM?\rTHIS PROBLEM CAN BE ONE OF SEVERAL REASONS:\rYOU HAVE STARTED MORE THEN ONE HTTP SERVER (IIS, SAMBAR, ZEUS AND SO ON). ONLY ONE SERVER CAN USE PORT 80. THIS ERROR MESSAGE INDICATE THE PROBLEM:\r(OS 10048)... MAKE_SOCK: COULD NOT BIND TO ADRESS 0.0.0.0:80\nNO LISTENING SOCKETS AVAILABLE, SHUTTING DOWN\rYOU HAVE OTHER SOFTWARE, SUCH AS THE INTERNET TELEPHONE \"SKYPE\" WHICH ALSO BLOCKS THE PORT 80. IF THE PROBLEM IS \"SKYPE\", YOU CAN GO IN SKYPE TO ACTIONS --> OPTIONS --> CONNECTION --> REMOVE THE CHECK MARK AT \"USE PORT 80 FOR AN ALTERNATE PORT\" AND RESTART SKYPE. NOW IT SHOULD WORK.\rYOU HAVE A FIREWALL WHICH BLOCKS THE APACHE PORT. NOT ALL FIREWALLS ARE COMPATIBLE WITH APACHE, AND SOMETIMES DEACTIVATING THE FIREWALL IS NOT ENOUGH AND YOU MUST DEINSTALL IT. THIS ERROR MESSAGE INDICATES A FIREWALL:\r(OS 10038)SOCKET OPERATION ON NON-SOCKET: MAKE_SOCK: FOR ADDRESS 0.0.0.0:80,\nAPR_SOCKET_OPT_SET: (SO_KEEPALIVE)\rALSO IF APACHE CAN START, BUT YOUR BROWSER CAN\'T CONNECT TO IT IT COULD BE DUE TO ONE OF THE FOLLOWING:\rSOME VIRUS SCANNERS CAN CAUSE THIS IN THE SAME WAY THAT FIREWALLS CAN INTERFERE.\rYOU HAVE XP PROFESSIONAL WITHOUT SERVICE PACK 1. YOU MUST HAVE AT LEAST SP1 FOR XAMPP.\rTIP:\rIF YOU HAVE PROBLEMS WITH USED PORTS, YOU CAN TRY THE TOOL \"XAMPP-PORTCHECK.EXE\". MAYBE IT CAN HELP.\rWHY IS MY CPU LOAD FOR APACHE ALMOST 99%?\rTHERE IS ONE OF TWO SCENARIOS AT PLAY HERE. EITHER YOUR CPU IS MAXING OUT, OR YOU CAN BROWSER CONNECT TO THE SERVER, BUT NOT SEE ANYTHING (THE SYSTEM IS TRYING UNSUCESSFULLY TO LOAD THE PAGE). IN EITHER CASE YOU CAN FIND THE FOLLOWING MESSAGE IN THE APACHE LOG FILE:\rCHILD: ENCOUNTERED TOO MANY ACCEPTEX FAULTS ACCEPTING CLIENT CONNECTIONS.\nWINNT_MPM: FALLING BACK TO \'ACCEPTFILTER NONE\'.\rTHE MPM FALLS BACK TO A SAFER IMPLEMENTATION, BUT SOME CLIENT REQUESTS WERE NOT PROCESSED CORRECTLY. IN ORDER TO AVOID THIS ERROR, USE \"ACCEPTFILTER\" WITH ACCEPT FILTER \"NONE\" IN THE \"\\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-MPM.CONF\" FILE.\rWHY ARE PICTURES AND STYLE-SHEETS NOT DISPLAYED?\rSOMETIMES THERE ARE PROBLEMS WITH DISPLAYING PICTURES AND STYLE-SHEETS. ESPECIALLY IF THESE FILES ARE LOCATED ON A NETWORK DRIVE. IN THIS CASE YOU CAN ENABLE (OR ADD) ONE IF THE FOLLOWING LINES IN THE FILE \"\\XAMPP\\APACHE\\CONF\\HTTPD.CONF\":\rENABLESENDFILE OFF\rENABLEMMAP OFF\rTHIS PROBLEM CAN ALSO BE CAUSED BY PROGRAMS FOR REGULATING BANDWIDTH, LIKE NETLIMITER.\rHOW DO I SEND EMAIL WITH XAMPP?\rTO CONFIGURE XAMPP TO USE THE INCLUDED SENDMAIL.EXE BINARY FOR EMAIL DELIVERY, FOLLOW THESE STEPS:\rEDIT THE XAMPP \"PHP.INI\" FILE. WITHIN THIS FILE, FIND THE [MAIL FUNCTION] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES. CHANGE THE XAMPP INSTALLATION PATH IF NEEDED.\nSENDMAIL_PATH = \"\\\"C:\\XAMPP\\SENDMAIL\\SENDMAIL.EXE\\\" -T\"\nEDIT THE XAMPP \"SENDMAIL.INI\" FILE. WITHIN THIS FILE, FIND THE [SENDMAIL] SECTION AND REPLACE IT WITH THE FOLLOWING DIRECTIVES:\nSMTP_SERVER=SMTP.GMAIL.COM\nSMTP_PORT=465\nSMTP_SSL=AUTO\nERROR_LOGFILE=ERROR.LOG\nAUTH_USERNAME=YOUR-GMAIL-USERNAME@GMAIL.COM\nAUTH_PASSWORD=YOUR-GMAIL-PASSWORD\nREMEMBER TO REPLACE THE DUMMY VALUES SHOWN WITH YOUR ACTUAL GMAIL ADDRESS AND ACCOUNT PASSWORD. IF YOU DON\'T PLAN TO USE GMAIL\'S SMTP SERVER, REPLACE THE SMTP HOST DETAILS WITH APPROPRIATE VALUES FOR YOUR ORGANIZATION OR ISP\'S SMTP SERVER.\rRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\nYOU CAN NOW USE PHP\'S MAIL() FUNCTION TO SEND EMAIL FROM YOUR APPLICATION.\rHOW CAN I SET A ROOT PASSWORD IN MYSQL?\rCONFIGURE IT WITH THE \"XAMPP SHELL\" (COMMAND PROMPT). OPEN THE SHELL FROM THE XAMPP CONTROL PANE AND EXECUTE THIS COMMAND:\rMYSQLADMIN.EXE -U ROOT PASSWORD SECRET\rTHIS SETS THE ROOT PASSWORD TO \'SECRET\'.\rCAN I USE MY OWN MYSQL SERVER?\rYES. SIMPLY DON\'T START THE MYSQL FROM THE XAMPP PACKAGE. PLEASE NOTE THAT TWO SERVERS CANNOT BE STARTED ON THE SAME PORT. IF YOU HAVE SET A PASSWORD FOR \"ROOT\", PLEASE DO NOT FORGET TO EDIT THE FILE \"\\XAMPP\\PHPMYADMIN\\CONFIG.INC.PHP\".\rHOW DO I RESTRICT ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rBEFORE YOU CAN ACCESS THE MYSQL SERVER, PHPMYADMIN WILL PROMPT YOU FOR A USER NAME AND PASSWORD. DON\'T FORGET TO SET A PASSWORD FOR THE USER \"ROOT\" FIRST.\rHOW DO I ENABLE ACCESS TO PHPMYADMIN FROM THE OUTSIDE?\rIN THE BASIC CONFIGURATION OF XAMPP, PHPMYADMIN IS ACCESSIBLE ONLY FROM THE SAME HOST THAT XAMPP IS RUNNING ON, AT HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rIMPORTANT: ENABLING EXTERNAL ACCESS FOR PHPMYADMIN IN PRODUCTION ENVIRONMENTS IS A SIGNIFICANT SECURITY RISK. YOU ARE STRONGLY ADVISED TO ONLY ALLOW ACCESS FROM LOCALHOST. A REMOTE ATTACKER COULD TAKE ADVANTAGE OF ANY EXISTING VULNERABILITY FOR EXECUTING CODE OR FOR MODIFYING YOUR DATA.\rTO ENABLE REMOTE ACCESS TO PHPMYADMIN, FOLLOW THESE STEPS:\rEDIT THE APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF FILE IN YOUR XAMPP INSTALLATION DIRECTORY.\rWITHIN THIS FILE, FIND THE LINES BELOW. \nALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE LOCAL\nTHEN REPLACE \'REQUIRE LOCAL\' WITH \'REQUIRE ALL GRANTED\'.\rALIAS /PHPMYADMIN \"C:/XAMPP/PHPMYADMIN/\"\n<DIRECTORY \"C:/XAMPP/PHPMYADMIN\">\nALLOWOVERRIDE AUTHCONFIG\nREQUIRE ALL GRANTED\nRESTART THE APACHE SERVER USING THE XAMPP CONTROL PANEL.\rWHERE IS THE IMAP SUPPORT FOR PHP?\rAS DEFAULT, THE IMAP SUPPORT FOR PHP IS DEACTIVATED IN XAMPP DUE TO SOME MYSTERIOUS INITIALIZATION ERRORS WITH SOME HOME VERSIONS LIKE WINDOWS 98. IF YOU WORK WITH NT SYSTEMS, YOU CAN OPEN THE FILE \"\\XAMPP\\PHP\\PHP.INI\" TO ACTIVATE THE PHP EXSTENSION BY REMOVING THE BEGINNING SEMICOLON AT THE LINE \";EXTENSION=PHP_IMAP.DLL\". IT SHOULD BE:\rEXTENSION=PHP_IMAP.DLL\rNOW RESTART APACHE AND IMAP SHOULD WORK. YOU CAN USE THE SAME STEPS FOR EVERY EXTENSION, WHICH IS NOT ENABLED IN THE DEFAULT CONFIGURATION.\rWHY DON\'T SOME PHP OPEN SOURCE APPS WORK WITH XAMPP ON WINDOWS?\rA LOT OF PHP APPLICATIONS OR EXTENSIONS THAT HAVE BEEN WRITTEN FOR LINUX HAVEN’T BEEN PORTED TO WINDOWS. \rCAN I DELETE THE \"INSTALL\" DIRECTORY AFTER INSTALLATION?\rIT\'S BETTER NOT TO. THE SCRIPTS HERE ARE STILL NEEDED FOR ALL ADDITIONAL PACKAGES (ADD-ONS) AND UPGRADES OF XAMPP.\rHOW DO I ACTIVATE THE EACCELERATOR?\rLIKE OTHER (ZEND) EXTENSIONS, YOU CAN ACTIVATE IT IN \"PHP.INI\". IN THIS FILE, ENABLE THE LINE \";ZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\". IT SHOULD BE:\rZEND_EXTENSION = \"\\XAMPP\\PHP\\EXT\\PHP_EACCELERATOR.DLL\"\rHOW DO I FIX A CONNECTION ERROR TO MY MS SQL SERVER?\rIF THE MSSQL EXTENSION WAS LOADED IN THE PHP.INI, SOMETIMES PROBLEMS APPEAR WHEN ONLY TCP/IP IS USED. YOU CAN FIX THAT PROBLEM WITH A NEWER \"NTWDBLIB.DLL\" FROM MICROSOFT. PLEASE REPLACE THE OLDER FILE IN \"\\XAMPP\\APACHE\\BIN\" AND \"\\XAMPP\\PHP\" WITH THE NEW ONE. BECAUSE OF THE LICENSE, WE CAN\'T PACKAGE A NEWER VERSION OF THIS FILE WITH XAMPP.\rHOW DO I WORK WITH THE PHP MCRYPT EXTENSION?\rFOR THIS, WE HAVE OPENED A TOPIC IN THE FORUM WITH EXAMPLES AND POSSIBLE SOLUTIONS: \rMCRYPT TOPIC\rDO MICROSOFT ACTIVE SERVER PAGES (ASP) WORK WITH XAMPP?\rNO. AND APACHE::ASP WITH THE PERL ADD-ON IS NOT THE SAME. APACHE::ASP ONLY KNOWS PERL-SCRIPT, BUT ASP FROM THE INTERNET INFORMATION SERVER (IIS) ALSO KNOWS THE NORMAL VBSCRIPT. BUT FOR ASP .NET, THERE IS A 3RD PARTY APACHE MODULE AVAILABLE.\rHOW CAN I GET XAMPP WORKING ON PORT 80 UNDER WINDOWS 10?\rBY DEFAULT, WINDOWS 10 STARTS MICROSOFT IIS ON PORT 80, WHICH IS THE SAME DEFAULT PORT USED BY APACHE IN XAMPP. AS A RESULT, APACHE CANNOT BIND TO PORT 80.\rTO DEACTIVATE IIS FROM RUNNING ON PORT 80, FOLLOW THESE STEPS:\rOPEN THE SERVICES PANEL IN COMPUTER MANAGEMENT.\rSEARCH FOR THE \'WORLD WIDE WEB PUBLISHING SERVICE\' AND SELECT IT.\rCLICK THE LINK TO \'STOP THE SERVICE\'.\rDOUBLE-CLICK THE SERVICE NAME.\rIN THE \'STARTUP TYPE\' FIELD, CHANGE THE STARTUP TYPE TO \'DISABLED\'.\rCLICK \'OK\' TO SAVE YOUR CHANGES.\rYOU SHOULD NOW BE ABLE TO START APACHE IN XAMPP ON PORT 80.\rFOR MORE INFORMATION, REFER TO THE \'TROUBLESHOOT APACHE STARTUP PROBLEMS\' GUIDE INCLUDED WITH XAMPP OR \rTHIS FORUM POST\r.\rHOW CAN I USE MICROSOFT EDGE TO ACCESS LOCAL ADDRESSES UNDER WINDOWS 10?\rIF YOUR LOCAL MACHINE HAS THE HOST NAME \'MYHOST\', YOU WILL NOT BE ABLE TO ACCESS URLS SUCH AS HTTP://MYHOST IN MICROSOFT EDGE. TO RESOLVE THIS, YOU SHOULD INSTEAD USE THE ADDRESSES HTTP://127.0.0.1 OR HTTP://LOCALHOST.\rWHERE ARE THE MAIN XAMPP CONFIGURATION FILES?\rTHE MAIN XAMPP CONFIGURATION FILES ARE LOCATED AS FOLLOWS:\rAPACHE CONFIGURATION FILE: \\XAMPP\\APACHE\\CONF\\HTTPD.CONF, \\XAMPP\\APACHE\\CONF\\EXTRA\\HTTPD-XAMPP.CONF\rPHP CONFIGURATION FILE: \\XAMPP\\PHP\\PHP.INI\rMYSQL CONFIGURATION FILE: \\XAMPP\\MYSQL\\BIN\\MY.INI\rFILEZILLA SERVER CONFIGURATION FILE: \\XAMPP\\FILEZILLAFTP\\FILEZILLA SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\TOMCAT\\CONF\\SERVER.XML\rAPACHE TOMCAT CONFIGURATION FILE: \\XAMPP\\SENDMAIL\\SENDMAIL.INI\rMERCURY MAIL CONFIGURATION FILE: \\XAMPP\\MERCURYMAIL\\MERCURY.INI\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版權所有(C) 2022, APACHE FRIENDS\r部落格\r隱私政策\rCDN提供\r\n'),(102,'b7f8ea8f7de4245816439a4b790ec254','XAMPP HOWTO GUIDES\r\nAPACHE FRIENDS\rMENU\r常見問題\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rWINDOWS \rHOW-TO GUIDES\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版權所有(C) 2022, APACHE FRIENDS\r部落格\r隱私政策\rCDN提供\r\n'),(103,'ae1b41579219794f60b8c5ad23f1677d','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\r常見問題\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rUSE A DIFFERENT PHP VERSION\rRUN PHP UNDER FASTCGI\rCONFIGURE AND USE APACHE TOMCAT\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版權所有(C) 2022, APACHE FRIENDS\r部落格\r隱私政策\rCDN提供\r\n'),(104,'42e42f54311a54647e51ad191c5dbd48','APACHE FRIENDS\r\nAPACHE FRIENDS\rMENU\r常見問題\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rBACKUP AND RESTORE MYSQL/MARIADB DATABASES\rCONFIGURE FTP ACCESS\rCONFIGURE VIRTUAL HOSTS\rCONFIGURE WILDCARD-BASED SUBDOMAINS\rDEPLOY AN APPLICATION USING GIT\rRESET THE MYSQL/MARIADB ROOT PASSWORD\rSEND MAIL WITH PHP\rUSE SQLITE WITH PHP\rACTIVATE AND USE XDEBUG\rSTART A NEW ZEND FRAMEWORK 1.X PROJECT\rSTART A NEW ZEND FRAMEWORK 2.X PROJECT\rTROUBLESHOOT APACHE STARTUP PROBLEMS\rCHANGE THE MYSQL TEMPORARY FILES DIRECTORY\rINCREASE THE PHP FILE UPLOAD LIMIT\rENABLE REMOTE ACCESS TO PHPMYADMIN\rAUTO-START XAMPP\rFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版權所有(C) 2022, APACHE FRIENDS\r部落格\r隱私政策\rCDN提供\r\n'),(105,'f4f6ccaaf4c714bd8e4d7f25d11fa2dc','WELCOME TO XAMPP\r\nAPACHE FRIENDS\rMENU\r常見問題\rHOW-TO GUIDES\rPHPINFO\rPHPMYADMIN\rXAMPP \rAPACHE + MARIADB + PHP + PERL\rWELCOME TO XAMPP FOR WINDOWS 8.2.12\rYOU HAVE SUCCESSFULLY INSTALLED XAMPP ON THIS SYSTEM! NOW YOU CAN START USING APACHE, MARIADB, PHP AND OTHER COMPONENTS.\nYOU CAN FIND MORE INFO IN THE \r常見問題\rSECTION OR CHECK THE \rHOW-TO GUIDES\rFOR GETTING STARTED WITH PHP APPLICATIONS.\nXAMPP IS MEANT ONLY FOR DEVELOPMENT PURPOSES. IT HAS CERTAIN CONFIGURATION SETTINGS THAT MAKE IT EASY TO DEVELOP LOCALLY BUT THAT ARE INSECURE IF YOU WANT TO HAVE YOUR INSTALLATION ACCESSIBLE TO OTHERS.\nSTART THE XAMPP CONTROL PANEL TO CHECK THE SERVER STATUS.\n社區\rXAMPP HAS BEEN AROUND FOR MORE THAN 10 YEARS  THERE IS A HUGE COMMUNITY BEHIND IT. YOU CAN GET INVOLVED BY JOINING OUR \r論壇\r, LIKING US ON \rFACEBOOK\r, OR FOLLOWING OUR EXPLOITS ON \rTWITTER\r.\nFOLLOW US ON TWITTER\rLIKE US ON FACEBOOK\r版權所有(C) 2022, APACHE FRIENDS\r部落格\r隱私政策\rCDN提供\r\n'),(106,'21114cbd09d60ca232b3e53d004564dc','НОВОСТИ КОМПАНИИ\r\n\r\n'),(107,'f58e028735b5d07233c4a161c9231405','ПОИСК\r\n\r\n'),(108,'be3fe2336ca014ea48484837a6379cf7','КАРТА САЙТА\r\n\r\n'),(109,'ddea3137a2dc2052dfdc6ef265d0e1de','ИНТЕРНЕТ-БАНКИНГ\r\n\"ИНТЕРНЕТ-БАНК\" — ЭТО ПОЛНОФУНКЦИОНАЛЬНАЯ, УДОБНАЯ И БЕЗОПАСНАЯ СИСТЕМА ДИСТАНЦИОННОГО БАНКОВСКОГО ОБСЛУЖИВАНИЯ, С ЕЕ ПОМОЩЬЮ ВЫ МОЖЕТЕ В ПОЛНОМ ОБЪЕМЕ УПРАВЛЯТЬ БАНКОВСКИМИ СЧЕТАМИ В РЕЖИМЕ РЕАЛЬНОГО ВРЕМЕНИ. ПОНЯТНЫЙ ДЛЯ КЛИЕНТА ИНТЕРФЕЙС ПОЗВОЛЯЕТ НЕ ТРАТИТЬ ВРЕМЯ НА ОБУЧЕНИЕ РАБОТЕ С СИСТЕМОЙ. СИСТЕМА СНАБЖЕНА ВНУТРЕННИМИ ПОДСКАЗКАМИ.\r\"ИНТЕРНЕТ-БАНК\" ПОЗВОЛЯЕТ:\rЧЕРЕЗ САЙТ БАНКА В ИНТЕРНЕТЕ ПОЛУЧИТЬ ДОСТУП К ВАШИМ БАНКОВСКИМ СЧЕТАМ ПРАКТИЧЕСКИ С ЛЮБОГО КОМПЬЮТЕРА В ЛЮБОЙ ТОЧКЕ ЗЕМНОГО ШАРА, ГДЕ ЕСТЬ ДОСТУП В ИНТЕРНЕТ \rВВОДИТЬ, РЕДАКТИРОВАТЬ И ПЕЧАТАТЬ ПЛАТЕЖНЫЕ ДОКУМЕНТЫ \rПОДПИСЫВАТЬ КАЖДЫЙ ПЛАТЕЖНЫЙ ДОКУМЕНТ ПЕРСОНИФИЦИРОВАННОЙ ЭЛЕКТРОННОЙ-ЦИФРОВОЙ ПОДПИСЬЮ \rНАПРАВЛЯТЬ ДОКУМЕНТЫ В БАНК НА ИСПОЛНЕНИЕ \r«ВИЗИРОВАТЬ» НАПРАВЛЯЕМЫЕ В БАНК ПЛАТЕЖНЫЕ ДОКУМЕНТЫ УПОЛНОМОЧЕННЫМ ЛИЦОМ \rПОЛУЧАТЬ ВЫПИСКИ СО ВСЕМИ ПРИЛОЖЕНИЯМИ ПО СЧЕТАМ ЗА ОПРЕДЕЛЕННЫЙ ПЕРИОД ВРЕМЕНИ \rОСУЩЕСТВЛЯТЬ ПОКУПКУ/ПРОДАЖУ ИНОСТРАННОЙ ВАЛЮТЫ, КОНВЕРТАЦИЮ ВАЛЮТ В РЕЖИМЕ ON-LINE ПО ТЕКУЩЕМУ РЫНОЧНОМУ КУРСУ \rРЕЗЕРВИРОВАТЬ НА СЧЕТЕ ВРЕМЕННО СВОБОДНЫЕ ДЕНЕЖНЫЕ СРЕДСТВА И ПОЛУЧАТЬ ДОПОЛНИТЕЛЬНЫЙ ДОХОД В ВИДЕ НАЧИСЛЕННЫХ ПРОЦЕНТОВ \rОТСЛЕЖИВАТЬ ТЕКУЩЕЕ СОСТОЯНИЕ СЧЕТОВ\rПОЛУЧАТЬ АКТУАЛЬНУЮ ИНФОРМАЦИЮ О ПЛАТЕЖАХ КОНТРАГЕНТОВ ИЗ ДРУГИХ БАНКОВ, КОТОРЫЕ ЗАЧИСЛЯЮТСЯ НА СЧЕТ КЛИЕНТА В МОМЕНТ ПОСТУПЛЕНИЯ В БАНК \rНАПРАВЛЯТЬ В БАНК БУХГАЛТЕРСКУЮ ОТЧЕТНОСТЬ В ЭЛЕКТРОННОМ ВИДЕ \rКОНТРОЛИРОВАТЬ СОСТОЯНИЕ ССУДНЫХ СЧЕТОВ, ПОГАШЕНИЕ И УПЛАТУ ПРОЦЕНТОВ \rПОДКЛЮЧЕНИЕ К СИСТЕМЕ, В ТОМ ЧИСЛЕ ГЕНЕРАЦИЯ КЛЮЧЕЙ ДЛЯ ФОРМИРОВАНИЯ ЭЛЕКТРОННО-ЦИФРОВОЙ ПОДПИСИ, БЕСПЛАТНО. АБОНЕНТСКАЯ ПЛАТА ЗА ОБСЛУЖИВАНИЕ НЕ ВЗИМАЕТСЯ.\rТЕХНИЧЕСКИЕ ТРЕБОВАНИЯ\rДЛЯ ПОЛНОЦЕННОЙ РАБОТЫ С СИСТЕМОЙ НЕОБХОДИМ КОМПЬЮТЕР С ОС WINDOWS ,НЕ НИЖЕ WINDOWS 2000; ПРОГРАММА ПРОСМОТРА ИНТЕРНЕТ-СТРАНИЦ INTERNET EXPLORER ВЕРСИИ НЕ НИЖЕ 6.0; ПРИЛОЖЕНИЕ JAVA RUNTIME ENVIRONMENT (JRE) VERSION 1.5.0\r\n'),(110,'54c7cb63bd2ee9f4878bc248cccbab6b','ИНКАССАЦИЯ\r\nИНКАССАЦИЯ\r– ДОСТАВКА ЦЕННОСТЕЙ И ДЕНЕЖНЫХ СРЕДСТВ.\rБАНК ПРЕДЛАГАЕТ ВОСПОЛЬЗОВАТЬСЯ УСЛУГАМИ СЛУЖБЫ ИНКАССАЦИИ. СЛУЖБА ИНКАССАЦИИ БАНКА ОБЕСПЕЧИТ:\rИНКАССАЦИЮ НАЛИЧНЫХ ДЕНЕЖНЫХ СРЕДСТВ, ДОСТАВКУ ИХ НА СПЕЦИАЛЬНО ОБОРУДОВАННОМ ТРАНСПОРТЕ В БАНК, ПО СОГЛАСОВАННОМУ С КЛИЕНТОМ, ГРАФИКУ РАБОТЫ;\rСОПРОВОЖДЕНИЕ ЦЕННОСТЕЙ И ДЕНЕЖНЫХ СРЕДСТВ КЛИЕНТА ПО МАРШРУТУ, УКАЗАННОМУ КЛИЕНТОМ; \rДОСТАВКУ НАЛИЧНЫХ ДЕНЕЖНЫХ СРЕДСТВ КЛИЕНТУ; \rДОСТАВКУ КЛИЕНТУ РАЗМЕННОЙ МОНЕТЫ.\rУСЛУГИ ПРЕДОСТАВЛЯЮТСЯ КАК СОБСТВЕННОЙ СЛУЖБОЙ ИНКАССАЦИИ, ТАК И ЧЕРЕЗ ДРУГИЕ СПЕЦИАЛИЗИРОВАННЫЕ ОРГАНИЗАЦИИ.\rНЕОБХОДИМАЯ ДОКУМЕНТАЦИЯ:\rДОГОВОР НА СБОР (ИНКАССАЦИЮ) ДЕНЕЖНОЙ ВЫРУЧКИ И ДОСТАВКУ РАЗМЕННОЙ МОНЕТЫ;\rЗАЯВКА НА ИНКАССАЦИЮ;\rПРЕДВАРИТЕЛЬНАЯ ЗАЯВКА НА ОКАЗАНИЕ УСЛУГ ПО ДОСТАВКЕ ДЕНЕЖНОЙ НАЛИЧНОСТИ;\rДОГОВОР НА ОКАЗАНИЕ УСЛУГ ПО ДОСТАВКЕ НАЛИЧНЫХ ДЕНЕЖНЫХ СРЕДСТВ.\rОБЪЕМ ИНКАССИРУЕМЫХ ДЕНЕЖНЫХ СРЕДСТВ\rТАРИФЫ ПО СТАВКЕ ПРОЦЕНТА ОТ ОБЪЕМА ИНКАССАЦИИ\rТАРИФЫ ОТ КОЛИЧЕСТВА ВЫЕЗДОВ\rТАРИФЫ С ФИКСИРОВАННОЙ СТОИМОСТЬЮ\rДО 0,5 МЛН. РУБ.\r0,45%\rОТ 120 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 2500 РУБ. В МЕСЯЦ\rОТ 0,5 ДО 1,0 МЛН. РУБ.\r0,4 - 0,35%\rОТ 140 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 3500 РУБ. В МЕСЯЦ\rОТ 1,0 ДО 1,5 МЛН. РУБ.\r0,35 -0,3%\rОТ 160 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 4500 РУБ. В МЕСЯЦ\rОТ 1,5 ДО 2,0 МЛН. РУБ.\r0,3 -0,25%\rОТ 180 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 5000 РУБ. В МЕСЯЦ\rОТ 2,0 МЛН ДО 3,0 МЛН. РУБ.\r0,25 - 0,2 %\rОТ 200 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 6000 РУБ. В МЕСЯЦ\rОТ 4,0 МЛН. ДО 6 МЛН. РУБ.\r0,2 -0,15%\rОТ 220 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 7000 РУБ. В МЕСЯЦ\rОТ 6,0 МЛН. ДО 10 МЛН. РУБ.\r0,15 -0,1 %\rОТ 240 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 8000 РУБ. В МЕСЯЦ\rСВЫШЕ 10 МЛН. РУБ.\r0,1 - 0,05%\rОТ 260 РУБ/ЗАЕЗД\rНЕ МЕНЕЕ 9000 РУБ. В МЕСЯЦ\rДРУГИЕ УСЛОВИЯ\rИНКАССАЦИЯ 5-10 ТОРГОВЫХ ТОЧЕК КЛИЕНТА\rПЛЮС 5 % ОТ ТАРИФНОЙ СТАВКИ ЗА КАЖДУЮ ПОСЛЕДУЮЩУЮ ТОЧКУ\rИНКАССАЦИЯ СВЫШЕ 10 ТОРГОВЫХ ТОЧЕК КЛИЕНТА\rПЛЮС 10 % ОТ ТАРИФНОЙ СТАВКИ ЗА КАЖДУЮ ПОСЛЕДУЮЩУЮ ТОЧКУ\rВРЕМЯ ИНКАССАЦИИ УСТАНАВЛИВАЕТ КЛИЕНТ\rПЛЮС 10 % ОТ ТАРИФНОЙ СТАВКИ\rНОЧНАЯ ИНКАССАЦИЯ (С 22:00)\rПЛЮС 20% ОТ ТАРИФНОЙ СТАВКИ\rУТРЕННЯЯ ИНКАССАЦИЯ ДЛЯ ЗАЧИСЛЕНИЯ В 1ОЙ ПОЛОВИНЕ ДНЯ\rБЕСПЛАТНО\rЕСЛИ СДАЮТ НА ОДНОМ ОБЪЕКТЕ НЕСКОЛЬКО ЮРИДИЧЕСКИХ ЛИЦ\rБЕСПЛАТНО\rДОСТАВКА РАЗМЕННОЙ МОНЕТЫ\r0,4 % ОТ СУММЫ ДОСТАВКИ\rРАСХОДНЫЙ МАТЕРИАЛ\rБЕСПЛАТНО\rХРАНЕНИЕ ДЕНЕЖНЫХ СРЕДСТВ В НОЧНОЕ ВРЕМЯ, ПРАЗДНИЧНЫЕ И ВЫХОДНЫЕ\rБЕСПЛАТНО\rЗАГРУЗКА БАНКОМАТОВ, ПОДКРЕПЛЕНИЕ ДОПОЛНИТЕЛЬНЫХ ОФИСОВ\rОТ 350 РУБ/ЧАС\rДОСТАВКА ДЕНЕЖНЫХ СРЕДСТВ ИЗ БАНКА КЛИЕНТУ\r0,5 % ОТ СУММЫ, ЛИБО ПО СОГЛАШЕНИЮ СТОРОН\r\n'),(111,'cbfa46d27f8efb5a7a8153fe51f3bf3b','КОРПОРАТИВНЫМ КЛИЕНТАМ\r\nБАНК ЯВЛЯЕТСЯ ОДНИМ ИЗ ЛИДЕРОВ БАНКОВСКОГО РЫНКА ПО ОБСЛУЖИВАНИЮ КОРПОРАТИВНЫХ КЛИЕНТОВ. \rКОМПЛЕКСНОЕ БАНКОВСКОЕ ОБСЛУЖИВАНИЕ НА ОСНОВЕ МАКСИМАЛЬНОГО ИСПОЛЬЗОВАНИЯ КОНКУРЕНТНЫХ ПРЕИМУЩЕСТВ И ВОЗМОЖНОСТЕЙ БАНКА ПОЗВОЛЯЕТ СОЗДАТЬ УСТОЙЧИВУЮ \rФИНАНСОВУЮ ПЛАТФОРМУ ДЛЯ РАЗВИТИЯ БИЗНЕСА ПРЕДПРИЯТИЙ И ХОЛДИНГОВ РАЗЛИЧНЫХ ОТРАСЛЕЙ ЭКОНОМИКИ. УЖЕ БОЛЕЕ 15 ЛЕТ БАНК РАБОТАЕТ ДЛЯ СВОИХ КЛИЕНТОВ, \rЯВЛЯЯСЬ ОБРАЗЦОМ НАДЕЖНОСТИ И ВЫСОКОГО ПРОФЕССИОНАЛИЗМА.\rНАШ БАНК ПРЕДЛАГАЕТ КОРПОРАТИВНЫМ КЛИЕНТАМ СЛЕДУЮЩИЕ ВИДЫ УСЛУГ:\rРАСЧЕТНО-КАССОВОЕ ОБСЛУЖИВАНИЕ\rИНКАССАЦИЯ\rИНТЕРНЕТ-БАНКИНГ\r\n'),(112,'0081c8541e53a7f35c06cc7a74ff5a29','РАСЧЕТНО-КАССОВОЕ ОБСЛУЖИВАНИЕ\r\nВО ВСЕХ СТРАНАХ МИРА САМОЙ РАСПРОСТРАНЕННОЙ ФУНКЦИЕЙ БАНКОВ ЯВЛЯЮТСЯ РАСЧЕТЫ. БОЛЬШИНСТВО ОКАЗЫВАЕМЫХ БАНКОМ УСЛУГ СВЯЗАНЫ С БЫСТРЫМ И КАЧЕСТВЕННЫМ ПРОВЕДЕНИЕМ РАСЧЕТНЫХ ОПЕРАЦИЙ. КАЖДЫЙ КЛИЕНТ, НЕЗАВИСИМО ОТ ВИДА ОСУЩЕСТВЛЯЕМЫХ В БАНКЕ ОПЕРАЦИЙ, ПОЛЬЗУЕТСЯ ПЕРЕВОДОМ СРЕДСТВ.\rКОРПОРАТИВНЫМ КЛИЕНТАМ БАНК ОКАЗЫВАЕТ СЛЕДУЮЩИЕ УСЛУГИ:\rОТКРЫТИЕ И ВЕДЕНИЕ СЧЕТОВ ЮРИДИЧЕСКИХ ЛИЦ - РЕЗИДЕНТОВ И НЕРЕЗИДЕНТОВ РОССИЙСКОЙ ФЕДЕРАЦИИ — В ВАЛЮТЕ РФ И ИНОСТРАННОЙ ВАЛЮТЕ; \rВСЕ ВИДЫ РАСЧЕТОВ В РУБЛЯХ И ИНОСТРАННОЙ ВАЛЮТЕ; \rКАССОВОЕ ОБСЛУЖИВАНИЕ В РУБЛЯХ И ИНОСТРАННОЙ ВАЛЮТЕ; \rУСКОРЕННЫЕ ПЛАТЕЖИ ПО РОССИИ ПО СИСТЕМЕ МЕЖРЕГИОНАЛЬНЫХ ЭЛЕКТРОННЫХ ПЛАТЕЖЕЙ; \rПЛАТЕЖИ В ЛЮБУЮ СТРАНУ МИРА В КРАТЧАЙШИЕ СРОКИ \rПРОВЕДЕНИЕ КОНВЕРСИОННЫХ ОПЕРАЦИЙ ПО СЧЕТАМ КЛИЕНТОВ \rИНКАССАЦИЯ И ДОСТАВКА НАЛИЧНЫХ ДЕНЕГ И ЦЕННОСТЕЙ \rРАСПОРЯЖЕНИЕ СЧЕТОМ ПОСРЕДСТВОМ СИСТЕМЫ «ИНТЕРНЕТ-БАНК» \rОПЕРАЦИОННЫЙ ДЕНЬ В БАНКЕ УСТАНОВЛЕН: ЕЖЕДНЕВНО С 09.00 ДО 16.00, В ПЯТНИЦУ И ПРЕДПРАЗДНИЧНЫЕ ДНИ С 09.00 ДО 15.00.\rКАССОВОЕ ОБСЛУЖИВАНИЕ ОСУЩЕСТВЛЯЕТСЯ НА ДОГОВОРНОЙ ОСНОВЕ, ПЛАТА ВЗИМАЕТСЯ ПО ФАКТУ СОВЕРШЕНИЯ КАЖДОЙ ОПЕРАЦИИ В СООТВЕТСТВИИ С УТВЕРЖДЕННЫМИ БАНКОМ ТАРИФАМИ ЗА УСЛУГИ КОРПОРАТИВНЫМ КЛИЕНТАМ.\r\n'),(113,'c53e6ba1e8943d2df7ff449091252209','ДЕПОЗИТАРНЫЕ УСЛУГИ\r\nДЕПОЗИТАРИЙ БАНКА ИМЕЕТ КОРРЕСПОНДЕНТСКИЕ ОТНОШЕНИЯ СО ВСЕМИ КРУПНЫМИ РАСЧЕТНЫМИ И УПОЛНОМОЧЕННЫМИ ДЕПОЗИТАРИЯМИ. РАЗВЕТВЛЕННАЯ СЕТЬ КОРРЕСПОНДЕНТСКИХ СЧЕТОВ ПОЗВОЛЯЕТ КЛИЕНТАМ ДЕПОЗИТАРИЯ ОСУЩЕСТВЛЯТЬ ОПЕРАЦИИ ПРАКТИЧЕСКИ С ЛЮБЫМИ ИНСТРУМЕНТАМИ ФОНДОВОГО РЫНКА.\rУСЛУГИ ДЕПОЗИТАРИЯ БАНКА:\rОТКРЫТИЕ И ВЕДЕНИЕ СЧЕТОВ ДЕПО КЛИЕНТОВ;\rХРАНЕНИЕ И УЧЕТ ВСЕХ ВИДОВ ЦЕННЫХ БУМАГ, ВКЛЮЧАЯ АКЦИИ, ОБЛИГАЦИИ, ПАИ, ВЕКСЕЛЯ, МЕЖДУНАРОДНЫХ ФИНАНСОВЫХ ИНСТРУМЕНТОВ (ЕВРООБЛИГАЦИИ, АДР, ГДР);\rКОНСУЛЬТИРОВАНИЕ И ПРОВЕДЕНИЕ КОМПЛЕКСНЫХ СТРУКТУРИРОВАННЫХ ОПЕРАЦИЙ С ЦЕННЫМИ БУМАГАМИ;\rПЕРЕРЕГИСТРАЦИЯ ПРАВ СОБСТВЕННОСТИ НА ЦЕННЫЕ БУМАГИ, В ТОМ ЧИСЛЕ ПРИ ВЫПОЛНЕНИИ ОПРЕДЕЛЕННОГО УСЛОВИЯ;\rОФОРМЛЕНИЕ И УЧЕТ ЗАЛОГОВЫХ ОПЕРАЦИЙ С ЦЕННЫМИ БУМАГАМИ ДЕПОНЕНТОВ;\rПРЕДОСТАВЛЕНИЕ ИНФОРМАЦИИ ОБ ЭМИТЕНТЕ;\rПОМОЩЬ ДЕПОНЕНТАМ В РЕАЛИЗАЦИИ ПРАВ, ЗАКРЕПЛЕННЫХ ЗА НИМИ КАК ЗА ВЛАДЕЛЬЦАМИ ЦЕННЫХ БУМАГ;\rКОНСУЛЬТАЦИОННАЯ ПОДДЕРЖКА ПРИ ПРОВЕДЕНИИ ОПЕРАЦИЙ ПО СЧЕТАМ ДЕПО;\rВЫПОЛНЕНИЕ ФУНКЦИЙ ПЛАТЕЖНОГО АГЕНТА:\rХРАНЕНИЕ ЦЕННЫХ БУМАГ НА ОСНОВАНИИ ДОГОВОРОВ ОТВЕТСТВЕННОГО ХРАНЕНИЯ;\rПРОВЕДЕНИЕ ЭКСПЕРТИЗЫ ЦЕННЫХ БУМАГ;\rДРУГИЕ УСЛУГИ.\rСПОСОБЫ ОБМЕНА ДОКУМЕНТОВ С ДЕПОЗИТАРИЕМ:\rВ БУМАЖНОМ ВИДЕ С ОРИГИНАЛЬНЫМИ ПОДПИСЯМИ И ПЕЧАТЯМИ;\rПО ФАКСУ (ПОРУЧЕНИЯ НА ЗАЧИСЛЕНИЕ ЦЕННЫХ БУМАГ И ПРЕДОСТАВЛЕНИЕ ВЫПИСОК) С ПОСЛЕДУЮЩИМ ПРЕДОСТАВЛЕНИЕМ ОРИГИНАЛА;\rПО СИСТЕМАМ S.W.I.F.T. И TELEX.\rТАРИФЫ НА ДЕПОЗИТАРНОЕ ОБСЛУЖИВАНИЕ\rНАИМЕНОВАНИЕ УСЛУГИ\rТАРИФ\rОТКРЫТИЕ СЧЕТА ДЕПО ДЛЯ ФИЗИЧЕСКИХ ЛИЦ (РЕЗИДЕНТОВ И НЕРЕЗИДЕНТОВ)\n150 РУБ.\nОТКРЫТИЕ СЧЕТА ДЕПО ДЛЯ ЮРИДИЧЕСКИХ ЛИЦ – РЕЗИДЕНТОВ\n400 РУБ.\nОТКРЫТИЕ СЧЕТА ДЕПО ДЛЯ ЮРИДИЧЕСКИХ ЛИЦ – НЕРЕЗИДЕНТОВ\n1600 РУБ.\nЗАКРЫТИЕ СЧЕТА ДЕПО\nНЕ ВЗИМАЕТСЯ\nВНЕСЕНИЕ ИЗМЕНЕНИЯ В АНКЕТУ ДЕПОНЕНТА\nНЕ ВЗИМАЕТСЯ\nАБОНЕНТСКАЯ ПЛАТА В МЕСЯЦ ЗА ВЕДЕНИЕ СЧЕТА ДЕПО ДЛЯ ЮРИДИЧЕСКИХ ЛИЦ - РЕЗИДЕНТОВ,\nПРИ НАЛИЧИИ ОСТАТКА НА СЧЕТЕ ДЕПО\n500 РУБ.\nАБОНЕНТСКАЯ ПЛАТА В МЕСЯЦ ЗА ВЕДЕНИЕ СЧЕТА ДЕПО ДЛЯ ЮРИДИЧЕСКИХ ЛИЦ - НЕРЕЗИДЕНТОВ,\nПРИ НАЛИЧИИ ОСТАТКА НА СЧЕТЕ ДЕПО\n2 500 РУБ.\nАБОНЕНТСКАЯ ПЛАТА В МЕСЯЦ ЗА ВЕДЕНИЕ СЧЕТА ДЕПО ДЛЯ ДЕПОНЕНТОВ, НАХОДЯЩИХСЯ НА БРОКЕРСКОМ\nОБСЛУЖИВАНИИ, ПРИ НАЛИЧИИ ДВИЖЕНИЯ ПО СЧЕТУ ДЕПО\n150 РУБ.\nФОРМИРОВАНИЕ ОТЧЕТА О СОВЕРШЕННЫХ ПО СЧЕТУ ДЕПО ОПЕРАЦИЯХ ЗА ПЕРИОД ПОСЛЕ ПРОВЕДЕНИЯ\nОПЕРАЦИИ\nНЕ ВЗИМАЕТСЯ\nФОРМИРОВАНИЕ ОТЧЕТА О СОВЕРШЕННЫХ ПО СЧЕТУ ДЕПО ОПЕРАЦИЯХ ЗА ПЕРИОД, ВЫПИСКИ О СОСТОЯНИИ\nСЧЕТА (РАЗДЕЛА СЧЕТА) ДЕПО ПО ИНФОРМАЦИОННОМУ ЗАПРОСУ ДЕПОНЕНТА\n150 РУБ.\nЗАЧИСЛЕНИЕ (СПИСАНИЕ) БЕЗДОКУМЕНТАРНЫХ ЦЕННЫХ БУМАГ, ЗА ОДНО ПОРУЧЕНИЕ\n300 РУБ.\nЗАЧИСЛЕНИЕ (СПИСАНИЕ) ДОКУМЕНТАРНЫХ ЦЕННЫХ БУМАГ, ЗА ОДНУ ЦЕННУЮ БУМАГУ\n580 РУБ.\nПЕРЕВОД (ВНУТРИ ДЕПОЗИТАРИЯ) БЕЗДОКУМЕНТАРНЫХ И ДОКУМЕНТАРНЫХ ЦЕННЫХ БУМАГ, ЗА ОДНО\nПОРУЧЕНИЕ (ВЗИМАЕТСЯ С ДЕПОНЕНТА - ИНИЦИАТОРА ОПЕРАЦИИ)\n300 РУБ.\nИЗМЕНЕНИЕ МЕСТ ХРАНЕНИЯ БЕЗДОКУМЕНТАРНЫХ ЦЕННЫХ БУМАГ (ЗА ОДНО ПОРУЧЕНИЕ) И ДОКУМЕНТАРНЫХ\nЦЕННЫХ БУМАГ (ЗА ОДНУ ЦЕННУЮ БУМАГУ)\n580 РУБ.\nБЛОКИРОВКА (РАЗБЛОКИРОВКА), РЕГИСТРАЦИЯ ЗАЛОГА (ВОЗВРАТА ЗАЛОГА) БЕЗДОКУМЕНТАРНЫХ\nЦЕННЫХ БУМАГ\n870 РУБ.\nБЛОКИРОВКА (РАЗБЛОКИРОВКА), РЕГИСТРАЦИЯ ЗАКЛАДА (ВОЗВРАТА ЗАКЛАДА) ДОКУМЕНТАРНЫХ\nЦЕННЫХ БУМАГ\n870 РУБ.\n*ПРИ ВЗИМАНИИ ТАРИФОВ ДОПОЛНИТЕЛЬНО ВЗИМАЕТСЯ НАЛОГ НА ДОБАВЛЕННУЮ СТОИМОСТЬ ПО СТАВКЕ 18%.\rПЛАТА ЗА ИНЫЕ УСЛУГИ, НЕ ОГОВОРЕННЫЕ В ДАННЫХ ТАРИФАХ ДЕПОЗИТАРИЯ, ЗА ИСКЛЮЧЕНИЕМ УСЛУГ, ОКАЗЫВАЕМЫХ ПРИ ПРОВЕДЕНИИ ОПЕРАЦИЙ ДЕПОНЕНТА ДРУГИМИ ДЕПОЗИТАРИЯМИ И РЕЕСТРОДЕРЖАТЕЛЯМИ, НЕ ВЗИМАЕТСЯ.\r\n'),(114,'65624a89c9bf009bafe9104c4ca2c703','ДОКУМЕНТАРНЫЕ ОПЕРАЦИИ\r\nНАШ БАНК ПРЕДЛАГАЕТ ШИРОКИЙ СПЕКТР БАНКОВСКИХ УСЛУГ ПО ПРОВЕДЕНИЮ ДОКУМЕНТАРНЫХ РАСЧЕТОВ В ОБЛАСТИ МЕЖДУНАРОДНЫХ ТОРГОВО-ЭКОНОМИЧЕСКИХ ОТНОШЕНИЙ ,В ТОМ ЧИСЛЕ ПО НЕСТАНДАРТНЫМ И СЛОЖНО СТРУКТУРИРОВАННЫМ СХЕМАМ.\rБЕЗУСЛОВНЫМ ПРЕИМУЩЕСТВОМ РАБОТЫ С НАШИМ БАНКОМ ЯВЛЯЕТСЯ ВОЗМОЖНОСТЬ ПРОВОДИТЬ ОПЕРАЦИИ В ПРЕДЕЛЬНО СЖАТЫЕ СРОКИ ПО КОНКУРЕНТОСПОСОБНЫМ ТАРИФАМ, А ТАКЖЕ ИХ ОБШИРНАЯ ГЕОГРАФИЯ: СТРАНЫ СНГ И БАЛТИИ, БЛИЖНЕГО И ДАЛЬНЕГО ЗАРУБЕЖЬЯ.\rСПЕКТР УСЛУГ ПО БАНКОВСКИМ ГАРАНТИЯМ: \rВЫДАЧА ЛЮБЫХ ВИДОВ ГАРАНТИЙ ПОД КОНТРГАРАНТИИ БАНКОВ-КОРРЕСПОНДЕНТОВ В СЧЕТ УСТАНОВЛЕННЫХ НА НИХ ДОКУМЕНТАРНЫХ ЛИМИТОВ: 									 \nГАРАНТИИ НАДЛЕЖАЩЕГО ИСПОЛНЕНИЯ КОНТРАКТОВ;\rГАРАНТИИ ПЛАТЕЖА (Т.Е. ВЫПОЛНЕНИЯ ПЛАТЕЖНЫХ ОБЯЗАТЕЛЬСТВ ПО КОНТРАКТАМ);\rГАРАНТИИ ВОЗВРАТА АВАНСОВОГО ПЛАТЕЖА;\rГАРАНТИИ В ПОЛЬЗУ ТАМОЖЕННЫХ ОРГАНОВ;\rГАРАНТИИ В ПОЛЬЗУ НАЛОГОВЫХ ОРГАНОВ;\rТЕНДЕРНЫЕ ГАРАНТИИ (Т.Е. ГАРАНТИИ УЧАСТИЯ В ТОРГАХ/КОНКУРСАХ);\rГАРАНТИИ ВОЗВРАТА КРЕДИТА;\rГАРАНТИИ ОПЛАТЫ АКЦИЙ;\rГАРАНТИИ, ПРЕДОСТАВЛЯЕМЫЕ В КАЧЕСТВЕ ВСТРЕЧНОГО ОБЕСПЕЧЕНИЯ СУДЕБНЫХ ИСКОВ;\rАВИЗОВАНИЕ ГАРАНТИЙ ИНОСТРАННЫХ И РОССИЙСКИХ БАНКОВ-КОРРЕСПОНДЕНТОВ В ПОЛЬЗУ ОТЕЧЕСТВЕННЫХ И ЗАРУБЕЖНЫХ БЕНЕФИЦИАРОВ;\rПРЕДЪЯВЛЕНИЕ ТРЕБОВАНИЯ ПЛАТЕЖА ПО ПОРУЧЕНИЮ БЕНЕФИЦИАРОВ В СЧЕТ БАНКОВСКИХ ГАРАНТИЙ;\rЗАВЕРКА ПОДЛИННОСТИ ПОДПИСЕЙ НА ГАРАНТИЯХ ИНОСТРАННЫХ И РОССИЙСКИХ БАНКОВ ПО ПРОСЬБЕ БЕНЕФИЦИАРА;\rВ СЛУЧАЕ НЕОБХОДИМОСТИ ИНЫЕ ВИДЫ ОПЕРАЦИЙ, ВКЛЮЧАЯ ПРЕДВАРИТЕЛЬНУЮ ПРОРАБОТКУ УСЛОВИЙ ГАРАНТИЙНОЙ СДЕЛКИ.\rПРЕДОСТАВЛЯЕМЫЕ УСЛУГИ ПО ДОКУМЕНТАРНЫМ (В ТОМ ЧИСЛЕ РЕЗЕРВНЫМ) АККРЕДИТИВАМ:\rАВИЗОВАНИЕ АККРЕДИТИВОВ ИНОСТРАННЫХ И РОССИЙСКИХ БАНКОВ-КОРРЕСПОНДЕНТОВ В ПОЛЬЗУ ОТЕЧЕСТВЕННЫХ И ЗАРУБЕЖНЫХ БЕНЕФИЦИАРОВ;\rПОДТВЕРЖДЕНИЕ АККРЕДИТИВОВ БАНКОВ-КОРРЕСПОНДЕНТОВ ПОД ПРЕДОСТАВЛЕННОЕ ДЕНЕЖНОЕ ПОКРЫТИЕ ИЛИ В СЧЕТ ДОКУМЕНТАРНЫХ ЛИМИТОВ, УСТАНОВЛЕННЫХ НА БАНК-ЭМИТЕНТ;\rПОДТВЕРЖДЕНИЕ ЭКСПОРТНЫХ АККРЕДИТИВОВ КОТНРАГЕНТА;\rИСПОЛНЕНИЕ АККРЕДИТИВОВ;\rВЫПОЛНЕНИЕ ФУНКЦИИ РАМБУРСИРУЮЩЕГО БАНКА НА ОСНОВАНИИ ПРЕДОСТАВЛЕННЫХ ПОЛНОМОЧИЙ ПО АККРЕДИТИВАМ ИНОСТРАННЫХ И РОССИЙСКИХ БАНКОВ-КОРРЕСПОНДЕНТОВ (ПРИ НАЛИЧИИ У БАНКА-ЭМИТЕНТА КОРРЕСПОНДЕНТСКОГО СЧЕТА ЛОРО В ГАЗПРОМБАНКЕ);\rВЫДАЧА БЕЗОТЗЫВНЫХ РАМБУРСНЫХ ОБЯЗАТЕЛЬСТВ ПО АККРЕДИТИВАМ, ОТКРЫТЫМ БАНКАМИ-КОРРЕСПОНДЕНТАМИ, В СЧЕТ ДОКУМЕНТАРНЫХ ЛИМИТОВ, УСТАНОВЛЕННЫХ НА БАНК-ЭМИТЕНТ (ПРИ НАЛИЧИИ У БАНКА-ЭМИТЕНТА КОРРЕСПОНДЕНТСКОГО СЧЕТА ЛОРО В ГАЗПРОМБАНКЕ);\rОФОРМЛЕНИЕ ТРАНСФЕРАЦИИ И ПЕРЕУСТУПКИ ВЫРУЧКИ ПО АККРЕДИТИВАМ;\rОТКРЫТИЕ АККРЕДИТИВОВ/ПРЕДОСТАВЛЕНИЕ ПЛАТЕЖНЫХ ГАРАНТИЙ В РАМКАХ ОПЕРАЦИЙ ТОРГОВОГО ФИНАНСИРОВАНИЯ;\rИНЫЕ ВИДЫ ОПЕРАЦИЙ, ВКЛЮЧАЯ ПРЕДВАРИТЕЛЬНУЮ ПРОРАБОТКУ СХЕМЫ РАСЧЕТОВ И УСЛОВИЙ АККРЕДИТИВНОЙ СДЕЛКИ.\r\n'),(115,'c24ffbaa8b72cfcb3d011c1f2708c749','ФИНАНСОВЫМ ОРГАНИЗАЦИЯМ\r\nАКТИВНОЕ СОТРУДНИЧЕСТВО НА ФИНАНСОВЫХ РЫНКАХ ПРЕДСТАВЛЯЕТ СОБОЙ ОДНУ ИЗ НАИБОЛЕЕ ВАЖНЫХ СТОРОН БИЗНЕСА И ЯВЛЯЕТСЯ ПЕРСПЕКТИВНЫМ НАПРАВЛЕНИЕМ ДЕЯТЕЛЬНОСТИ НАШЕГО БАНКА. ПОЛИТИКА БАНКА НАПРАВЛЕНА НА РАСШИРЕНИЕ СОТРУДНИЧЕСТВА, УВЕЛИЧЕНИЕ ОБЪЕМОВ ВЗАИМНЫХ КРЕДИТНЫХ ЛИНИЙ. СОЛИДНАЯ ДЕЛОВАЯ РЕПУТАЦИЯ БАНКА НА РЫНКЕ МЕЖБАНКОВСКИХ ОПЕРАЦИЙ СПОСОБСТВУЕТ НАЛАЖИВАНИЮ СТАБИЛЬНЫХ И ВЗАИМОВЫГОДНЫХ ПАРТНЕРСКИХ ОТНОШЕНИЙ С САМЫМИ КРУПНЫМИ И НАДЕЖНЫМИ БАНКАМИ СТРАНЫ.\rОСОБОЕ ВНИМАНИЕ БАНК УДЕЛЯЕТ РАЗВИТИЮ ВЗАИМООТНОШЕНИЙ С МЕЖДУНАРОДНЫМИ ФИНАНСОВЫМИ ИНСТИТУТАМИ. ФИНАНСИРОВАНИЕ ДОЛГОСРОЧНЫХ И СРЕДНЕСРОЧНЫХ ПРОЕКТОВ КЛИЕНТОВ ЗА СЧЕТ ПРИВЛЕЧЕНИЯ СРЕДСТВ НА МЕЖДУНАРОДНЫХ РЫНКАХ КАПИТАЛА - ОДНО ИЗ ПРИОРИТЕТНЫХ НАПРАВЛЕНИЙ ДЕЯТЕЛЬНОСТИ БАНКА. НАШ БАНК ИМЕЕТ РАЗВИТУЮ СЕТЬ КОРРЕСПОНДЕНТСКИХ СЧЕТОВ, ЧТО ПОЗВОЛЯЕТ БЫСТРО И КАЧЕСТВЕННО ОСУЩЕСТВЛЯТЬ РАСЧЕТЫ В РАЗЛИЧНЫХ ВАЛЮТАХ. ПОРУЧЕНИЯ КЛИЕНТОВ МОГУТ БЫТЬ ИСПОЛНЕНЫ БАНКОМ В СЖАТЫЕ СРОКИ.\rВ ЦЕЛЯХ МИНИМИЗАЦИИ РИСКОВ ПРИ ПОВЕДЕНИИ ОПЕРАЦИЙ НА ФИНАНСОВЫХ РЫНКАХ НАШ БАНК МАКСИМАЛЬНО ТРЕБОВАТЕЛЬНО ПОДХОДИТ К ВЫБОРУ СВОИХ БАНКОВ-КОНТРАГЕНТОВ. \rВ ДАННОМ НАПРАВЛЕНИИ БАНК ПРЕДЛАГАЕТ ФИНАНСОВЫМ ОРГАНИЗАЦИЯМ СЛЕДУЮЩИЕ УСЛУГИ:\rУСЛУГИ НА МЕЖБАНКОВСКОМ РЫНКЕ\rДЕПОЗИТАРНЫЕ УСЛУГИ\rДОКУМЕНТАРНЫЕ ОПЕРАЦИИ\r\n'),(116,'53412cd449563f783dca67a6dbdc6d62','УСЛУГИ НА МЕЖБАНКОВСКОМ РЫНКЕ\r\nМЕЖБАНКОВСКОЕ КРЕДИТОВАНИЕ\rВИД УСЛУГИ\nОПИСАНИЕ\nКРЕДИТОВАНИЕ ПОД ВАЛЮТНЫЙ ДЕПОЗИТ\nКРЕДИТЫ ВЫДАЮТСЯ В РУБЛЯХ НА СРОК ОТ 1 ДНЯ ДО 1 МЕСЯЦА С ВОЗМОЖНОСТЬЮ ДАЛЬНЕЙШЕЙ\nПРОЛОНГАЦИИ. ТАРИФНЫЕ СТАВКИ ЗАВИСЯТ ОТ КОНКРЕТНЫХ УСЛОВИЙ СДЕЛКИ.\nКРЕДИТОВАНИЕ ПОД ЗАЛОГ ОВГВЗ\nКРЕДИТЫ ВЫДАЮТСЯ В РУБЛЯХ И ВАЛЮТЕ НА СРОК ДО 1 МЕСЯЦА С ВОЗМОЖНОЙ ПРОЛОНГАЦИЕЙ.\nСТАВКА ДИСКОНТА СОСТАВЛЯЕТ 25—30%.\nКРЕДИТОВАНИЕ ПОД ЗАЛОГ ГОСУДАРСТВЕННЫХ ЦЕННЫХ БУМАГ\nВ ЗАЛОГ ПРИНИМАЮТСЯ ОБЛИГАЦИИ ФЕДЕРАЛЬНОГО ЗАЙМА (ОФЗ) ЛЮБОГО ВЫПУСКА. СТАВКА ДИСКОНТА:\nОФЗ С ДАТОЙ ПОГАШЕНИЯ ДО 91 ДНЯ — 5%;\rОФЗ С ДАТОЙ ПОГАШЕНИЯ ДО 365 ДНЕЙ — 8%;\rОФЗ С ДАТОЙ ПОГАШЕНИЯ СВЫШЕ 365 ДНЕЙ — 13%.\rКРЕДИТЫ ВЫДАЮТСЯ НА СРОК ДО2 НЕДЕЛЬ.\nКРЕДИТОВАНИЕ ПОД ЗАЛОГ ВЕКСЕЛЕЙ\nДЛЯ КОНСУЛЬТАЦИЙ ПО ЭТОМУ ВИДУ КРЕДИТОВАНИЯ ОБРАТИТЕСЬ В УПРАВЛЕНИЕ ВЕКСЕЛЬНОГО\nОБРАЩЕНИЯ И РАБОТЫ С ДОЛГОВЫМИ ОБЯЗАТЕЛЬСТВАМИ ПО ТЕЛЕФОНУ (495) 978-78-78.\nКОНВЕРСИОННЫЕ ОПЕРАЦИИ\rНА ВНУТРЕННЕМ ДЕНЕЖНОМ РЫНКЕ БАНК ОСУЩЕСТВЛЯЕТ:\rБРОКЕРСКОЕ ОБСЛУЖИВАНИЕ БАНКОВ ПО ИХ УЧАСТИЮ В ТОРГАХ ЕТС НА ММВБ. СТАВКИ КОМИССИОННОГО ВОЗНАГРАЖДЕНИЯ ВАРЬИРУЮТСЯ В ЗАВИСИМОСТИ ОТ ОБЪЕМА ОПЕРАЦИЙ (В ПРЕДЕЛАХ 0,147—0,18%).\rКОНВЕРСИОННЫЕ ОПЕРАЦИИ. БАНК ПРЕДЛАГАЕТ БАНКАМ-КОНТРАГЕНТАМ РАБОТУ НА ВАЛЮТНОМ РЫНКЕ ПО ПОКУПКЕ И ПРОДАЖЕ ИНОСТРАННОЙ ВАЛЮТЫ ЗА РОССИЙСКИЕ РУБЛИ ПО ТЕКУЩИМ РЫНОЧНЫМ ЦЕНАМ. ПРИ ОТСУТСТВИИ ОТКРЫТЫХ ЛИНИЙ ПРИ ПРОДАЖЕ ИНОСТРАННОЙ ВАЛЮТЫ БАНК-КОНТРАГЕНТ ПРОИЗВОДИТ ПРЕДОПЛАТУ ПО ЗАКЛЮЧЕННОЙ СДЕЛКЕ, ВОЗМОЖНА РАБОТА ПОД КРЕДИТОВОЕ АВИЗО.\rБАНКНОТНЫЕ ОПЕРАЦИИ\rПОКУПКА И ПРОДАЖА НАЛИЧНОЙ ВАЛЮТЫ ЗА БЕЗНАЛИЧНУЮ ВАЛЮТУ;\rПРОДАЖА НОВЫХ БАНКНОТ В УПАКОВКЕ АМЕРИКАНСКОГО БАНКА-ЭМИТЕНТА;\rПОКУПКА И ПРОДАЖА БАНКНОТ, БЫВШИХ В УПОТРЕБЛЕНИИ.\rУРОВЕНЬ КОМИССИОННЫХ ЗАВИСИТ ОТ ОБЪЕМОВ И КОНКРЕТНЫХ УСЛОВИЙ СДЕЛКИ.\rДОКУМЕНТАРНЫЕ ОПЕРАЦИИ\rМЕЖДУНАРОДНЫЕ РАСЧЕТЫ:\nАККРЕДИТИВ\r- ЭТО УСЛОВНОЕ ДЕНЕЖНОЕ ОБЯЗАТЕЛЬСТВО, ПРИНИМАЕМОЕ БАНКОМ (БАНКОМ-ЭМИТЕНТОМ) ПО ПОРУЧЕНИЮ ПЛАТЕЛЬЩИКА, ПРОИЗВЕСТИ ПЛАТЕЖИ В ПОЛЬЗУ ПОЛУЧАТЕЛЯ СРЕДСТВ ПО ПРЕДЪЯВЛЕНИИ ПОСЛЕДНИМ ДОКУМЕНТОВ, СООТВЕТСТВУЮЩИХ УСЛОВИЯМ АККРЕДИТИВА, ИЛИ ПРЕДОСТАВИТЬ ПОЛНОМОЧИЯ ДРУГОМУ БАНКУ (ИСПОЛНЯЮЩЕМУ БАНКУ) ПРОИЗВЕСТИ ТАКИЕ ПЛАТЕЖИ.\rИНКАССО\r- ЭТО РАСЧЕТНАЯ ОПЕРАЦИЯ, ПОСРЕДСТВОМ КОТОРОЙ БАНК НА ОСНОВАНИИ РАСЧЕТНЫХ ДОКУМЕНТОВ ПО ПОРУЧЕНИЮ КЛИЕНТА ПОЛУЧАЕТ ПРИЧИТАЮЩИЕСЯ КЛИЕНТУ ДЕНЕЖНЫЕ СРЕДСТВА ОТ ПЛАТЕЛЬЩИКА ЗА ПОСТУПИВШИЕ В АДРЕС ПЛАТЕЛЬЩИКА ТОВАРЫ ИЛИ ОКАЗАННЫЕ ЕМУ УСЛУГИ, ПОСЛЕ ЧЕГО ЭТИ СРЕДСТВА ЗАЧИСЛЯЮТСЯ НА СЧЕТ КЛИЕНТА В БАНКЕ.\rОПЕРАЦИИ С ВЕКСЕЛЯМИ БАНКА\rВЕКСЕЛИ НАШЕГО БАНКА ЯВЛЯЮТСЯ ПРОСТЫМИ ВЕКСЕЛЯМИ.\rПРОСТОЙ ВЕКСЕЛЬ — ДОКУМЕНТ УСТАНОВЛЕННОЙ ЗАКОНОМ ФОРМЫ, ДАЮЩИЙ ЕГО ДЕРЖАТЕЛЮ (ВЕКСЕЛЕДЕРЖАТЕЛЮ) БЕЗУСЛОВНОЕ ПРАВО ТРЕБОВАТЬ С ЛИЦА, УКАЗАННОГО В ДАННОМ ДОКУМЕНТЕ (ПЛАТЕЛЬЩИКА), УПЛАТЫ ОГОВОРЕННОЙ СУММЫ ПО НАСТУПЛЕНИЮ НЕКОТОРОГО СРОКА. ОБЯЗАТЕЛЬСТВО ПО ПРОСТОМУ ВЕКСЕЛЮ ВОЗНИКАЕТ С МОМЕНТА ЕГО СОСТАВЛЕНИЯ И ПЕРЕДАЧИ ПЕРВОМУ ВЕКСЕЛЕДЕРЖАТЕЛЮ.\rПЕРЕЧЕНЬ ПРОВОДИМЫХ БАНКОМ ОПЕРАЦИЙ С СОБСТВЕННЫМИ ВЕКСЕЛЯМИ:\nВЫПУСК ВЕКСЕЛЕЙ;\rПОГАШЕНИЕ ВЕКСЕЛЕЙ;\rДОСРОЧНЫЙ УЧЕТ ВЕКСЕЛЕЙ;\rОТВЕТСТВЕННОЕ ХРАНЕНИЕ ВЕКСЕЛЕЙ;\rКРЕДИТОВАНИЕ ПОД ЗАЛОГ ВЕКСЕЛЕЙ;\rВЫДАЧА КРЕДИТОВ НА ПРИОБРЕТЕНИЕ ВЕКСЕЛЕЙ;\rНОВАЦИЯ И РАЗМЕН ВЕКСЕЛЕЙ;\rПРОВЕРКА ПОДЛИННОСТИ ВЕКСЕЛЕЙ.\r\n'),(117,'89a00e9561c33cb54aca96d9d99c715e','БАНКОВСКИЕ КАРТЫ\r\nКРЕДИТНЫЕ КАРТЫ\rСРОК ДЕЙСТВИЯ КАРТЫ\r3 ГОДА\rКОМИССИЯ ЗА ЕЖЕГОДНОЕ ОСУЩЕСТВЛЕНИЕ РАСЧЕТОВ ПО ОПЕРАЦИЯМ С ОСНОВНОЙ КАРТОЙ.\r600 РУБ. / 25 ДОЛЛ. США / 25 ЕВРО\rЛЬГОТНЫЙ ПЕРИОД ОПЛАТЫ\rДО 50 КАЛЕНДАРНЫХ ДНЕЙ\rЕЖЕМЕСЯЧНЫЙ МИНИМАЛЬНЫЙ ПЛАТЕЖ \r(В ПРОЦЕНТАХ ОТ СУММЫ ЗАДОЛЖЕННОСТИ ПО ОВЕРДРАФТАМ):\r10% \rДОПОЛНИТЕЛЬНЫЕ ПРОЦЕНТЫ/ШТРАФЫ/КОМИССИИ/ НА СУММУ НЕРАЗРЕШЕННОГО ОВЕРДРАФТА\rНЕ ВЗИМАЕТСЯ (ОТМЕНЕНА С 1 МАРТА) \rКОМИССИЯ ЗА УЧЕТ ОТЧЕТНОЙ СУММЫ ЗАДОЛЖЕННОСТИ, НЕПОГАШЕННОЙ НА ПОСЛЕДНИЙ КАЛЕНДАРНЫЙ ДЕНЬ ЛЬГОТНОГО ПЕРИОДА ОПЛАТЫ.\rДЛЯ 1-6-ГО МЕСЯЦЕВ\rДЛЯ 6-ГО И ПОСЛЕДУЮЩИХ МЕСЯЦЕВ\r12% / 15% \r21% / 24% \rВ ПУНКТАХ ВЫДАЧИ НАЛИЧНЫХ ИЛИ БАНКОМАТАХ \"БАНКА\" \rВ БАНКОМАТАХ БАНКОВ-ПАРТНЕРОВ \"ОБЪЕДИНЕННОЙ РАСЧЕТНОЙ СИСТЕМЫ (ОРС)\" \rВ ПУНКТАХ ВЫДАЧИ НАЛИЧНЫХ ИЛИ БАНКОМАТАХ ИНОГО БАНКА \r0%\r0,5%\r2,5%\rМИНИМАЛЬНАЯ СУММА КОМИССИИ ПО ОПЕРАЦИЯМ ПОЛУЧЕНИЯ НАЛИЧНЫХ ДЕНЕЖНЫХ СРЕДСТВ В ПУНКТАХ ВЫДАЧИ НАЛИЧНЫХ ИЛИ БАНКОМАТАХ ИНОГО БАНКА. \r150 РУБЛЕЙ\rКОМИССИЯ ЗА ОСУЩЕСТВЛЕНИЕ КОНВЕРТАЦИИ ПО ТРАНСГРАНИЧНЫМ ОПЕРАЦИЯМ (СОВЕРШЕННЫМ ЗА ПРЕДЕЛАМИ ТЕРРИТОРИИ РФ). \r0,75% \rРАСЧЕТНЫЕ КАРТЫ БАНКА\rВАЛЮТА КАРТСЧЕТА\rРОССИЙСКИЕ РУБЛИ / ДОЛЛАРЫ США / ЕВРО\rСРОК ДЕЙСТВИЯ КАРТЫ\r3 ГОДА\rКОМИССИЯ ЗА ОСУЩЕСТВЛЕНИЕ РАСЧЕТОВ В ТЕЧЕНИЕ ОДНОГО ГОДА ПО ОПЕРАЦИЯМ С ОСНОВНОЙ КАРТОЙ ПРИ ЕЕ ПЕРВИЧНОМ ВЫПУСКЕ.\rВЗИМАЕТСЯ ПЕРЕД НАЧАЛОМ КАЖДОГО ГОДА РАСЧЕТОВ ПО ДЕЙСТВУЮЩЕЙ КАРТЕ ИЗ СРЕДСТВ НА КАРТСЧЕТЕ.\r500 РУБЛЕЙ/20 ДОЛЛ. США/20 ЕВРО\rКОМИССИЯ ЗА ОПЕРАЦИЮ ПОЛУЧЕНИЯ НАЛИЧНЫХ ДЕНЕЖНЫХ СРЕДСТВ:\rДО 300 000 РУБЛЕЙ (ВКЛЮЧИТЕЛЬНО)\rВ ПУНКТАХ ВЫДАЧИ НАЛИЧНЫХ ИЛИ БАНКОМАТАХ «БАНКА»\rВ БАНКОМАТАХ БАНКОВ-ПАРТНЕРОВ\rВ ПУНКТАХ ВЫДАЧИ НАЛИЧНЫХ ИЛИ БАНКОМАТАХ ИНОГО БАНКА\r0%\r0,5%\r1,5% МИН. 90 РУБ.\rОТ 300 001 ДО 10 000 000 РУБЛЕЙ (ВКЛЮЧИТЕЛЬНО)\r2,5% \rОТ 10 000 001 РУБЛЯ И ВЫШЕ\r5%\rМИНИМАЛЬНАЯ СУММА КОМИССИИ ПО ОПЕРАЦИЯМ ПОЛУЧЕНИЯ НАЛИЧНЫХ ДЕНЕЖНЫХ СРЕДСТВ В ПУНКТАХ ВЫДАЧИ НАЛИЧНЫХ ИЛИ БАНКОМАТАХ ИНОГО БАНКА. \r90 РУБЛЕЙ\rКОМИССИЯ ЗА ПЕРЕЧИСЛЕНИЕ И КОНВЕРСИЮ ДЕНЕЖНЫХ СРЕДСТВ В ИНТЕРНЕТ-БАНКЕ. \r0%\rКОМИССИЯ ЗА ОСТАНОВКУ ОПЕРАЦИЙ ПО КАРТСЧЕТУ, СОВЕРШАЕМЫХ С ИСПОЛЬЗОВАНИЕМ КАРТЫ, ПРИ ЕЕ УТРАТЕ. \r600 РУБЛЕЙ/25 ДОЛЛ. США/25 ЕВРО\rКОМИССИЯ ЗА ОСУЩЕСТВЛЕНИЕ КОНВЕРСИИ ПО ТРАНСГРАНИЧНЫМ ОПЕРАЦИЯМ (СОВЕРШЕННЫМ ЗА ПРЕДЕЛАМИ ТЕРРИТОРИИ РФ).\r0,75%\rВЫДАЧА КАРТОЧКИ ДОСТУПА.\rБЕСПЛАТНО\rКОМИССИЯ ЗА ОПЛАТУ УСЛУГ В ИНТЕРНЕТ - БАНКЕ И В БАНКОМАТАХ БАНКА. \rБЕСПЛАТНО\rКОМИССИЯ ЗА УЧЕТ ПЕРЕРАСХОДА СРЕДСТВ (В ПРОЦЕНТАХ ГОДОВЫХ ОТ СУММЫ ПЕРЕРАСХОДА). \r36%\rКОМИССИЯ ЗА ОТПРАВКУ SMS СООБЩЕНИЙ О СУММАХ ПРОВЕДЕННЫХ ПО КАРТЕ ОПЕРАЦИЙ И ДОСТУПНОМ БАЛАНСЕ В ТЕЧЕНИЕ ЕЕ СРОКА ДЕЙСТВИЯ.\rБЕСПЛАТНО\r\n'),(118,'97cc4b8d5eae6669c6e5920eca22f9cd','ПОТРЕБИТЕЛЬСКИЙ КРЕДИТ\r\nНЕ ВАЖНО, ДЛЯ ЧЕГО ВАМ НУЖНЫ ДЕНЬГИ — МЫ ДОВЕРЯЕМ ВАМ И НЕ ТРАТИМ ВРЕМЯ НА ЛИШНИЕ ПРОЦЕДУРЫ.\rТАРИФЫ КРЕДИТОВАНИЯ ФИЗИЧЕСКИХ ЛИЦ\rВ РУБЛЯХ\rСУММА КРЕДИТА: ОТ 150 000 ДО 1 500 000 РУБЛЕЙ\rСРОК КРЕДИТА: ОТ 6 ДО 36 МЕСЯЦЕВ\r% СТАВКА: ОТ 18 ДО 21,5% ГОДОВЫХ\rЕДИНОВРЕМЕННАЯ КОМИССИЯ ЗА ВЫДАЧУ КРЕДИТА: 2% ОТ СУММЫ КРЕДИТА\rВ ДОЛЛАРАХ США\rСУММА КРЕДИТА: ОТ 5 000 ДО 50 000 ДОЛЛАРОВ США\rСРОК КРЕДИТА: ОТ 6 ДО 24 МЕСЯЦЕВ\r% СТАВКА: ОТ 14,5 ДО 16,5% ГОДОВЫХ\rЕДИНОВРЕМЕННАЯ КОМИССИЯ ЗА ВЫДАЧУ КРЕДИТА: 2% ОТ СУММЫ КРЕДИТА\rУСЛОВИЯ КРЕДИТНОГО ДОГОВОРА И ПРИМЕНЯЕМЫЙ ТАРИФНЫЙ ПЛАН И/ИЛИ ТАРИФЫ ОПРЕДЕЛЯЮТСЯ В ИНДИВИДУАЛЬНОМ ПОРЯДКЕ, В ТОМ ЧИСЛЕ В ЗАВИСИМОСТИ ОТ ПОДТВЕРЖДЕННОГО ДОХОДА КЛИЕНТА. ИЗЛОЖЕННАЯ ИНФОРМАЦИЯ НЕ ЯВЛЯЕТСЯ ПУБЛИЧНОЙ ОФЕРТОЙ И НЕ ВЛЕЧЕТ ВОЗНИКНОВЕНИЯ У ЗАО «БАНК ИНТЕЗА» ОБЯЗАННОСТИ ПРЕДОСТАВИТЬ КРЕДИТ, КАК НА УКАЗАННЫХ, ТАК И НА ЛЮБЫХ ИНЫХ УСЛОВИЯХ.\rМИНИМАЛЬНЫЕ ТРЕБОВАНИЯ К ЗАЕМЩИКУ\rВЫ ГРАЖДАНИН РОССИИ.\rВАМ СЕЙЧАС БОЛЬШЕ 23 ЛЕТ И ВАМ БУДЕТ МЕНЬШЕ 60 (ДЛЯ МУЖЧИН) ИЛИ МЕНЬШЕ 55 (ДЛЯ ЖЕНЩИН) НА МОМЕНТ ПОГАШЕНИЯ (ТО ЕСТЬ ПОЛНОЙ ОПЛАТЫ) КРЕДИТА.\rУ ВАС ЕСТЬ ОФИЦИАЛЬНОЕ МЕСТО РАБОТЫ, И ВЫ РАБОТАЕТЕ НА НЕМ ПО НАЙМУ НЕ МЕНЕЕ ШЕСТИ МЕСЯЦЕВ И ПРОШЛИ ИСПЫТАТЕЛЬНЫЙ СРОК.\rВАШ ОБЩИЙ ТРУДОВОЙ СТАЖ СОСТАВЛЯЕТ НЕ МЕНЕЕ ДВУХ ЛЕТ\rВЫ МОЖЕТЕ ПОДТВЕРДИТЬ СВОЙ ДОХОД ОФИЦИАЛЬНО ПРИ ПОМОЩИ СТАНДАРТНОЙ ФОРМЫ 2НДФЛ ИЛИ СПРАВКОЙ ПО ФОРМЕ БАНКА.\rВЫ ОБРАТИЛИСЬ В ОТДЕЛЕНИЕ БАНКА В ТОМ ЖЕ ГОРОДЕ, В КОТОРОМ ВЫ РАБОТАЕТЕ.\rС ВАМИ МОЖНО СВЯЗАТЬСЯ ПО ГОРОДСКОМУ ТЕЛЕФОНУ ПО МЕСТУ РАБОТЫ.\rТЕЛЕФОН ГОРЯЧЕЙ ЛИНИИ: \r8 800 2002 808\r( ЗВОНОК ПО РОССИИ БЕСПЛАТНЫЙ)\r\n'),(119,'1560168bdcc5a4573c23c7cacbbf48d8','ЧАСТНЫМ ЛИЦАМ\r\nНАШ БАНК ПРЕДОСТАВЛЯЕТ ФИЗИЧЕСКИМ ЛИЦАМ БОЛЬШОЕ ЧИСЛО РАЗЛИЧНЫХ ВОЗМОЖНОСТЕЙ, СВЯЗАННЫХ С СОХРАНЕНИЕМ СРЕДСТВ И СОВЕРШЕНИЕМ РАЗЛИЧНЫХ СДЕЛОК. В ЧАСТНОСТИ, БАНК ПРЕДЛАГАЕТ СВОИМ КЛИЕНТАМ ШИРОКУЮ ЛИНЕЙКУ РАЗНООБРАЗНЫХ ВКЛАДОВ, СПОСОБНЫХ УДОВЛЕТВОРИТЬ КАК ДОЛГОСРОЧНЫЕ, ТАК И КРАТКОСРОЧНЫЕ ИНТЕРЕСЫ, КАСАЮЩИЕСЯ РАЗМЕЩЕНИЯ СВОБОДНЫХ СРЕДСТВ ПО ВЫГОДНЫМ СТАВКАМ. В СВОЕЙ РАБОТЕ БАНК АКТИВНО ПРИМЕНЯЕТ ИННОВАЦИОННЫЕ ТЕХНОЛОГИИ ДИНАМИЧНО РАЗВИВАЮЩЕЙСЯ БАНКОВСКОЙ СФЕРЫ.\rБАНК ПРЕДЛАГАЕТ СВОИМ КЛИЕНТАМ КАЧЕСТВЕННЫЙ УНИВЕРСАЛЬНЫЙ СЕРВИС ПО СЛЕДУЮЩИМ НАПРАВЛЕНИЯМ:\rБАНКОВСКИЕ КАРТЫ\rПОТРЕБИТЕЛЬСКИЙ КРЕДИТ\r\n'),(120,'5294819207cd629318e1de373aa1e6f3','УСЛУГИ\r\nНАШ БАНК ПРЕДОСТАВЛЯЕТ ФИЗИЧЕСКИМ ЛИЦАМ БОЛЬШОЕ ЧИСЛО РАЗЛИЧНЫХ ВОЗМОЖНОСТЕЙ, СВЯЗАННЫХ С СОХРАНЕНИЕМ СРЕДСТВ И СОВЕРШЕНИЕМ РАЗЛИЧНЫХ СДЕЛОК. В ЧАСТНОСТИ, БАНК ПРЕДЛАГАЕТ СВОИМ КЛИЕНТАМ ШИРОКУЮ ЛИНЕЙКУ РАЗНООБРАЗНЫХ ВКЛАДОВ, СПОСОБНЫХ УДОВЛЕТВОРИТЬ КАК ДОЛГОСРОЧНЫЕ, ТАК И КРАТКОСРОЧНЫЕ ИНТЕРЕСЫ, КАСАЮЩИЕСЯ РАЗМЕЩЕНИЯ СВОБОДНЫХ СРЕДСТВ ПО ВЫГОДНЫМ СТАВКАМ. В СВОЕЙ РАБОТЕ БАНК АКТИВНО ПРИМЕНЯЕТ ИННОВАЦИОННЫЕ ТЕХНОЛОГИИ ДИНАМИЧНО РАЗВИВАЮЩЕЙСЯ БАНКОВСКОЙ СФЕРЫ.\rБАНК ПРЕДЛАГАЕТ СВОИМ КЛИЕНТАМ КАЧЕСТВЕННЫЙ УНИВЕРСАЛЬНЫЙ СЕРВИС ПО СЛЕДУЮЩИМ НАПРАВЛЕНИЯМ:\rБАНКОВСКИЕ КАРТЫ\rПОТРЕБИТЕЛЬСКИЙ КРЕДИТ\rМАЛОМУ И СРЕДНЕМУ БИЗНЕСУ\rРАБОТА С ПРЕДПРИЯТИЯМИ МАЛОГО И СРЕДНЕГО БИЗНЕСА - ОДНО ИЗ СТРАТЕГИЧЕСКИ ВАЖНЫХ НАПРАВЛЕНИЙ ДЕЯТЕЛЬНОСТИ БАНКА. НАШ БАНК ПРЕДСТАВЛЯЕТ СОВРЕМЕННЫЕ ПРОГРАММЫ ОБСЛУЖИВАНИЯ МАЛОГО И СРЕДНЕГО БИЗНЕСА, ОБЕСПЕЧИВАЕТ ОПТИМАЛЬНЫЕ И ВЗАИМОВЫГОДНЫЕ ВАРИАНТЫ СОТРУДНИЧЕСТВА, В ОСНОВЕ КОТОРЫХ ЛЕЖИТ ПРОФЕССИОНАЛИЗМ СОТРУДНИКОВ И ВЫСОКОЕ КАЧЕСТВО БАНКОВСКИХ УСЛУГ. УСЛУГИ НАШЕГО БАНКА ОТЛИЧАЮТСЯ ОПЕРАТИВНОСТЬЮ И НАДЕЖНОСТЬЮ, ТАК КАК ОРИЕНТИРОВАНЫ НА ДЕЛОВЫХ ЛЮДЕЙ - НА ТЕХ, КТО ЦЕНИТ СВОЕ ВРЕМЯ И ДЕНЬГИ.\rБАНК ПРЕДЛАГАЕТ СЛЕДУЮЩИЕ ВИДЫ УСЛУГ ДЛЯ ПРЕДПРИЯТИЙ МАЛОГО И СРЕДНЕГО БИЗНЕСА:\rКРЕДИТОВАНИЕ\rЛИЗИНГ\rДЕПОЗИТЫ\rПЛАСТИКОВЫЕ КАРТЫ\rКОРПОРАТИВНЫМ КЛИЕНТАМ\rБАНК ЯВЛЯЕТСЯ ОДНИМ ИЗ ЛИДЕРОВ БАНКОВСКОГО РЫНКА ПО ОБСЛУЖИВАНИЮ КОРПОРАТИВНЫХ КЛИЕНТОВ. \rКОМПЛЕКСНОЕ БАНКОВСКОЕ ОБСЛУЖИВАНИЕ НА ОСНОВЕ МАКСИМАЛЬНОГО ИСПОЛЬЗОВАНИЯ КОНКУРЕНТНЫХ ПРЕИМУЩЕСТВ И ВОЗМОЖНОСТЕЙ БАНКА ПОЗВОЛЯЕТ СОЗДАТЬ УСТОЙЧИВУЮ \rФИНАНСОВУЮ ПЛАТФОРМУ ДЛЯ РАЗВИТИЯ БИЗНЕСА ПРЕДПРИЯТИЙ И ХОЛДИНГОВ РАЗЛИЧНЫХ ОТРАСЛЕЙ ЭКОНОМИКИ. УЖЕ БОЛЕЕ 15 ЛЕТ БАНК РАБОТАЕТ ДЛЯ СВОИХ КЛИЕНТОВ, \rЯВЛЯЯСЬ ОБРАЗЦОМ НАДЕЖНОСТИ И ВЫСОКОГО ПРОФЕССИОНАЛИЗМА.\rНАШ БАНК ПРЕДЛАГАЕТ КОРПОРАТИВНЫМ КЛИЕНТАМ СЛЕДУЮЩИЕ ВИДЫ УСЛУГ:\rРАСЧЕТНО-КАССОВОЕ ОБСЛУЖИВАНИЕ\rИНКАССАЦИЯ\rИНТЕРНЕТ-БАНКИНГ\rФИНАНСОВЫМ ОРГАНИЗАЦИЯМ\rАКТИВНОЕ СОТРУДНИЧЕСТВО НА ФИНАНСОВЫХ РЫНКАХ ПРЕДСТАВЛЯЕТ СОБОЙ ОДНУ ИЗ НАИБОЛЕЕ ВАЖНЫХ СТОРОН БИЗНЕСА И ЯВЛЯЕТСЯ ПЕРСПЕКТИВНЫМ НАПРАВЛЕНИЕМ ДЕЯТЕЛЬНОСТИ НАШЕГО БАНКА. ПОЛИТИКА БАНКА НАПРАВЛЕНА НА РАСШИРЕНИЕ СОТРУДНИЧЕСТВА, УВЕЛИЧЕНИЕ ОБЪЕМОВ ВЗАИМНЫХ КРЕДИТНЫХ ЛИНИЙ. СОЛИДНАЯ ДЕЛОВАЯ РЕПУТАЦИЯ БАНКА НА РЫНКЕ МЕЖБАНКОВСКИХ ОПЕРАЦИЙ СПОСОБСТВУЕТ НАЛАЖИВАНИЮ СТАБИЛЬНЫХ И ВЗАИМОВЫГОДНЫХ ПАРТНЕРСКИХ ОТНОШЕНИЙ С САМЫМИ КРУПНЫМИ И НАДЕЖНЫМИ БАНКАМИ СТРАНЫ.\rОСОБОЕ ВНИМАНИЕ БАНК УДЕЛЯЕТ РАЗВИТИЮ ВЗАИМООТНОШЕНИЙ С МЕЖДУНАРОДНЫМИ ФИНАНСОВЫМИ ИНСТИТУТАМИ. ФИНАНСИРОВАНИЕ ДОЛГОСРОЧНЫХ И СРЕДНЕСРОЧНЫХ ПРОЕКТОВ КЛИЕНТОВ ЗА СЧЕТ ПРИВЛЕЧЕНИЯ СРЕДСТВ НА МЕЖДУНАРОДНЫХ РЫНКАХ КАПИТАЛА - ОДНО ИЗ ПРИОРИТЕТНЫХ НАПРАВЛЕНИЙ ДЕЯТЕЛЬНОСТИ БАНКА. НАШ БАНК ИМЕЕТ РАЗВИТУЮ СЕТЬ КОРРЕСПОНДЕНТСКИХ СЧЕТОВ, ЧТО ПОЗВОЛЯЕТ БЫСТРО И КАЧЕСТВЕННО ОСУЩЕСТВЛЯТЬ РАСЧЕТЫ В РАЗЛИЧНЫХ ВАЛЮТАХ. ПОРУЧЕНИЯ КЛИЕНТОВ МОГУТ БЫТЬ ИСПОЛНЕНЫ БАНКОМ В СЖАТЫЕ СРОКИ.\rВ ЦЕЛЯХ МИНИМИЗАЦИИ РИСКОВ ПРИ ПОВЕДЕНИИ ОПЕРАЦИЙ НА ФИНАНСОВЫХ РЫНКАХ НАШ БАНК МАКСИМАЛЬНО ТРЕБОВАТЕЛЬНО ПОДХОДИТ К ВЫБОРУ СВОИХ БАНКОВ-КОНТРАГЕНТОВ. \rВ ДАННОМ НАПРАВЛЕНИИ БАНК ПРЕДЛАГАЕТ ФИНАНСОВЫМ ОРГАНИЗАЦИЯМ СЛЕДУЮЩИЕ УСЛУГИ:\rУСЛУГИ НА МЕЖБАНКОВСКОМ РЫНКЕ\rДЕПОЗИТАРНЫЕ УСЛУГИ\rДОКУМЕНТАРНЫЕ ОПЕРАЦИИ\r\n'),(121,'4c6e4f50a46679283be9c0d9734ef751','ПЛАСТИКОВЫЕ КАРТЫ\r\nНАШ БАНК ПРОВОДИТ ОПЕРАЦИИ С ПЛАСТИКОВЫМИ КАРТАМИ С 1997 Г. СЕГОДНЯ МЫ ПРЕДЛАГАЕМ ПЛАСТИКОВЫЕ КАРТЫ ОСНОВНЫХ МЕЖДУНАРОДНЫХ ПЛАТЁЖНЫХ СИСТЕМ – VISA И MASTERCARD; ОТ САМЫХ ДЕМОКРАТИЧНЫХ ЕLЕCTRON ДО ЭЛИТНЫХ GOLD И PLATINUM. В РАМКАХ ПЕРСОНАЛЬНОГО ОБСЛУЖИВАНИЯ В РАМКАХ ПЕРСОНАЛЬНОГО БАНКОВСКОГО ОБСЛУЖИВАНИЯ БАНК ДОПОЛНИТЕЛЬНО ПРЕДЛАГАЕТ ЭКСКЛЮЗИВНЫЕ КАРТЫ VISA INFINITE С БРИЛЛИАНТАМИ И ПЛАТИНОВЫМ ОРНАМЕНТОМ.\rЗАКАЗАТЬ МЕЖДУНАРОДНУЮ ПЛАСТИКОВУЮ КАРТУ МОЖНО В ЛЮБОМ ОТДЕЛЕНИИ НАШЕГО БАНКА. ВАША КАРТА БУДЕТ ГОТОВА УЖЕ ЧЕРЕЗ 3-5 ДНЕЙ. НАШ БАНК ОДИН ИЗ НЕМНОГИХ В РОССИИ, КТО ВЫДАЕТ КАРТУ СРОКОМ НА ДВА ГОДА, КАК И КРУПНЕЙШИЕ ЗАРУБЕЖНЫЕ БАНКИ.КАЖДЫЙ ПАКЕТ УСЛУГ БАНКА ВКЛЮЧАЕТ ОДНУ ОСНОВНУЮ И ДО ТРЕХ ДОПОЛНИТЕЛЬНЫХ ПЛАСТИКОВЫХ КАРТ ДЛЯ ВАС И ДЛЯ ЧЛЕНОВ ВАШЕЙ СЕМЬИ (ВКЛЮЧАЯ ДЕТЕЙ СТАРШЕ 14 ЛЕТ). ВЫ САМИ УСТАНАВЛИВАЕТЕ ОГРАНИЧЕНИЯ: КТО И СКОЛЬКО МОЖЕТ ПОТРАТИТЬ ПО КАРТЕ.\rТЕРЯЯ ПЛАСТИКОВУЮ КАРТУ, ВЫ НЕ ТЕРЯЕТЕ ДЕНЬГИ. ПОТОМУ ЧТО КАРТЫ НАШЕГО БАНКА НАДЕЖНО ЗАЩИЩЕНЫ ОТ НЕЗАКОННОГО ИСПОЛЬЗОВАНИЯ. ПРОСТО СОБЛЮДАЙТЕ ПРАВИЛА БЕЗОПАСНОСТИ ПРИ ОБРАЩЕНИИ СО СВОЕЙ КАРТОЙ, А В СЛУЧАЕ ЕЕ ПРОПАЖИ ИЛИ ХИЩЕНИЯ БЕЗ ПРОМЕДЛЕНИЯ ОБРАТИТЕСЬ В БАНК.\rПРЕИМУЩЕСТВА ПЛАСТИКОВЫХ КАРТ БАНКА\rПОЛУЧЕНИЕ НАЛИЧНЫХ БЕЗ КОМИССИИ В ШИРОКОЙ СЕТИ БАНКОМАТОВ;\rСВЕДЕНИЯ ОБ ОСТАТКЕ И СОВЕРШЁННЫХ ОПЕРАЦИЯХ ПО КАРТЕ ПРИХОДЯТ ПО SMS;\rСИСТЕМА ИНТЕРНЕТ-БАНКИНГА ПОЗВОЛЯЕТ ВЛАДЕЛЬЦУ КАРТЫ КОНТРОЛИРОВАТЬ РАСХОДЫ И УПРАВЛЯТЬ СРЕДСТВАМИ НА КАРТОЧНЫХ СЧЕТАХ.\rВСЕМ ВЛАДЕЛЬЦАМ КАРТ БАНКА ДОСТУПНЫ CКИДКИ И БОНУСНЫЕ ПРОГРАММЫ.\rВИДЫ ПЛАСТИКОВЫХ КАРТ\rДЕБЕТОВЫЕ КАРТЫ:\rУДОБСТВО БЕЗНАЛИЧНОЙ ОПЛАТЫ ТОВАРОВ И УСЛУГ\rБЕЗОПАСНОЕ ХРАНЕНИЕ СОБСТВЕННЫХ СРЕДСТВ\rНАЧИСЛЕНИЕ ПРОЦЕНТОВ НА ОСТАТОК ПО КАРТЕ\rКОНТРОЛЬ НАД РАСХОДАМИ И УПРАВЛЕНИЕ СВОИМИ ДЕНЬГАМИ\rКРЕДИТНЫЕ КАРТЫ:\rКРЕДИТОВАНИЕ БЕЗ ПРОЦЕНТОВ ДО 55 ДНЕЙ\rПОЛЬЗОВАТЬСЯ КРЕДИТОМ МОЖНО МНОГОКРАТНО, НЕ ОБРАЩАЯСЬ В БАНК\rБЕЗНАЛИЧНАЯ ОПЛАТА ТОВАРОВ И УСЛУГ БЕЗ КОМИССИЙ В ЛЮБОЙ ТОЧКЕ МИРА\rПРОВОЗ ДЕНЕГ ЧЕРЕЗ ГРАНИЦУ БЕЗ ТАМОЖЕННОГО ОФОРМЛЕНИЯ\rНЕ НУЖНО ПОКУПАТЬ ВАЛЮТУ ДЛЯ ВЫЕЗДА В ДРУГИЕ СТРАНЫ\rВСЕ ПОЛЕЗНЫЕ ФУНКЦИИ ДЕБЕТОВЫХ КАРТ\r\n'),(122,'344cad3205bd5c2e8cffcf29a17ae499','КРЕДИТОВАНИЕ\r\nКРЕДИТОВАНИЕ МАЛОГО И СРЕДНЕГО БИЗНЕСА ЯВЛЯЕТСЯ ОДНИМ ИЗ СТРАТЕГИЧЕСКИХ НАПРАВЛЕНИЙ БАНКА.\rДАННОЕ НАПРАВЛЕНИЕ ВКЛЮЧАЕТ В СЕБЯ:\nКРЕДИТОВАНИЕ ЮРИДИЧЕСКИХ ЛИЦ\rКРЕДИТОВАНИЕ ИНДИВИДУАЛЬНЫХ ПРЕДПРИНИМАТЕЛЕЙ\rВ ЗАВИСИМОСТИ ОТ ПОЖЕЛАНИЙ КЛИЕНТА КРЕДИТЫ ДЛЯ БИЗНЕСА ПРЕДОСТАВЛЯЮТСЯ В РАЗНЫХ ВАЛЮТАХ: В РУБЛЯХ РФ, ДОЛЛАРАХ США И ЕВРО. \nПРЕИМУЩЕСТВА ПОЛУЧЕНИЯ КРЕДИТА В НАШЕМ БАНКЕ:\rСРОК РАССМОТРЕНИЯ КРЕДИТНОЙ ЗАЯВКИ ОТ 2-Х РАБОЧИХ ДНЕЙ; \rОТСУТСТВИЕ ЕЖЕМЕСЯЧНОЙ ПЛАТЫ ЗА ВЕДЕНИЕ ССУДНОГО СЧЕТА;\rОТСУТСТВИЕ ТРЕБОВАНИЙ ПО ПРЕДОСТАВЛЕНИЮ БИЗНЕС-ПЛАНА;\rПРИНИМАЕТСЯ К РАССМОТРЕНИЮ УПРАВЛЕНЧЕСКАЯ ОТЧЕТНОСТЬ;\rВ КАЧЕСТВЕ ЗАЛОГА РАССМАТРИВАЮТСЯ ТОВАРЫ В ОБОРОТЕ, АВТОТРАНСПОРТ, ОБОРУДОВАНИЕ, НЕДВИЖИМОСТЬ И ДРУГОЕ ЛИКВИДНОЕ ИМУЩЕСТВО; \rГИБКИЕ УСЛОВИЯ ПОГАШЕНИЯ КРЕДИТА. \rДЛЯ ПОЛУЧЕНИЯ КРЕДИТА:\rПОЗВОНИТЕ НАМ ПО ТЕЛЕФОНУ +7 (495) 757-57-57, ОБРАТИТЕСЬ В БЛИЖАЙШЕЕ К ВАМ ОТДЕЛЕНИЕ БАНКА ИЛИ ЗАПОЛНИТЕ ON-LINE ЗАЯВКУ. \rНАШИ СПЕЦИАЛИСТЫ ПОМОГУТ ВАМ ВЫБРАТЬ УДОБНЫЕ УСЛОВИЯ КРЕДИТОВАНИЯ И ОТВЕТЯТ НА ИНТЕРЕСУЮЩИЕ ВАС ВОПРОСЫ.\rПОДГОТОВЬТЕ НЕОБХОДИМЫЕ ДЛЯ РАССМОТРЕНИЯ КРЕДИТНОЙ ЗАЯВКИ ДОКУМЕНТЫ И ДОГОВОРИТЕСЬ О ВСТРЕЧЕ С КРЕДИТНЫМ ЭКСПЕРТОМ БАНКА.\rПОКАЖИТЕ КРЕДИТНОМУ ЭКСПЕРТУ ВАШЕ ПРЕДПРИЯТИЕ И ИМУЩЕСТВО, ПРЕДЛАГАЕМОЕ В ЗАЛОГ.\rПОЛУЧИТЕ КРЕДИТ НА РАЗВИТИЕ ВАШЕГО БИЗНЕСА! \nПРОГРАММЫ КРЕДИТОВАНИЯ МАЛОГО И СРЕДНЕГО БИЗНЕСА:\rПРОГРАММА\nСУММА КРЕДИТА\nПРОЦЕНТНАЯ СТАВКА\nСРОК КРЕДИТА\n«ОВЕРДРАФТ»\rОТ 300 000\nДО 5 000 000 РУБЛЕЙ\nОТ 18% ГОДОВЫХ\nДО 12 МЕСЯЦЕВ\n«МИНИКРЕДИТ»\rОТ 150 000\nДО 1 000 000 РУБЛЕЙ\nОТ 24% ГОДОВЫХ\nДО 36 МЕСЯЦЕВ\n«РАЗВИТИЕ»\nОТ 1 000 000\nДО 15 000 000 РУБЛЕЙ\nОТ 17% ГОДОВЫХ\nДО 36 МЕСЯЦЕВ\n«ИНВЕСТ»\nОТ 1 000 000\nДО 30 000 000 РУБЛЕЙ\nОТ 15% ГОДОВЫХ\nДО 72 МЕСЯЦЕВ\r\n'),(123,'3e30b6e27a290bc4818f2de6a938fdf3','ДЕПОЗИТЫ\r\nНАШ БАНК ПРЕДЛАГАЕТ ВАМ ЭФФЕКТИВНО РАЗМЕСТИТЬ СВОБОДНЫЕ ДЕНЬГИ НА БАНКОВСКОМ ДЕПОЗИТЕ И ПОЛУЧИТЬ ДОПОЛНИТЕЛЬНУЮ ПРИБЫЛЬ.\rДЕПОЗИТНЫЕ ПРОДУКТЫ\r \rДОСРОЧНОЕ РАСТОРЖЕНИЕ\rПОПОЛНЕНИЕ\rЧАСТИЧНОЕ ИЗЪЯТИЕ\rВЫПЛАТА ПРОЦЕНТОВ\rДЕПОЗИТ С ВЫПЛАТОЙ ПРОЦЕНТОВ В КОНЦЕ СРОКА\rНЕ ПРЕДУСМОТРЕНО.\rНЕ ПРЕДУСМОТРЕНО.\rНЕ ПРЕДУСМОТРЕНО.\rВ КОНЦЕ СРОКА.\rДЕПОЗИТ С ВЫПЛАТОЙ ПРОЦЕНТОВ ЕЖЕМЕСЯЧНО\rНЕ ПРЕДУСМОТРЕНО.\rНЕ ПРЕДУСМОТРЕНО.\rНЕ ПРЕДУСМОТРЕНО.\rЕЖЕМЕСЯЧНО.\rДЕПОЗИТ С ВОЗМОЖНОСТЬЮ ПОПОЛНЕНИЯ\rНЕ ПРЕДУСМОТРЕНО.\rПРЕКРАЩАЕТСЯ ЗА 2 МЕСЯЦА ДО ОКОНЧАНИЯ СРОКА ДЕЙСТВИЯ ДЕПОЗИТА. \rНЕ ПРЕДУСМОТРЕНО \rВ КОНЦЕ СРОКА. \rДЕПОЗИТ С ВОЗМОЖНОСТЬЮ ПОПОЛНЕНИЯ И ИЗЪЯТИЯ\rНЕ ПРЕДУСМОТРЕНО.\rПРЕКРАЩАЕТСЯ ЗА 2 МЕСЯЦА ДО ОКОНЧАНИЯ СРОКА ДЕЙСТВИЯ ДЕПОЗИТА.\rНЕ БОЛЕЕ 40% ОТ ПЕРВОНАЧАЛЬНОЙ СУММЫ ВКЛАДА ЗА ВЕСЬ СРОК ДЕПОЗИТА \rВ КОНЦЕ СРОКА. \rДЕПОЗИТ С ВОЗМОЖНОСТЬЮ ДОСРОЧНОГО РАСТОРЖЕНИЯ \rВОЗМОЖНО ПРИ РАЗМЕЩЕНИИ НА 12 МЕСЯЦЕВ, НО НЕ РАНЕЕ ЧЕМ ЧЕРЕЗ 6 МЕСЯЦЕВ.\rНЕ ПРЕДУСМОТРЕНО.\rНЕ ПРЕДУСМОТРЕНО. \rВ КОНЦЕ СРОКА.\r\n'),(124,'dc76e079e3571df6ebba5ee1fd4ce0cd','МАЛОМУ И СРЕДНЕМУ БИЗНЕСУ\r\nРАБОТА С ПРЕДПРИЯТИЯМИ МАЛОГО И СРЕДНЕГО БИЗНЕСА - ОДНО ИЗ СТРАТЕГИЧЕСКИ ВАЖНЫХ НАПРАВЛЕНИЙ ДЕЯТЕЛЬНОСТИ БАНКА. НАШ БАНК ПРЕДСТАВЛЯЕТ СОВРЕМЕННЫЕ ПРОГРАММЫ ОБСЛУЖИВАНИЯ МАЛОГО И СРЕДНЕГО БИЗНЕСА, ОБЕСПЕЧИВАЕТ ОПТИМАЛЬНЫЕ И ВЗАИМОВЫГОДНЫЕ ВАРИАНТЫ СОТРУДНИЧЕСТВА, В ОСНОВЕ КОТОРЫХ ЛЕЖИТ ПРОФЕССИОНАЛИЗМ СОТРУДНИКОВ И ВЫСОКОЕ КАЧЕСТВО БАНКОВСКИХ УСЛУГ. УСЛУГИ НАШЕГО БАНКА ОТЛИЧАЮТСЯ ОПЕРАТИВНОСТЬЮ И НАДЕЖНОСТЬЮ, ТАК КАК ОРИЕНТИРОВАНЫ НА ДЕЛОВЫХ ЛЮДЕЙ - НА ТЕХ, КТО ЦЕНИТ СВОЕ ВРЕМЯ И ДЕНЬГИ.\rБАНК ПРЕДЛАГАЕТ СЛЕДУЮЩИЕ ВИДЫ УСЛУГ ДЛЯ ПРЕДПРИЯТИЙ МАЛОГО И СРЕДНЕГО БИЗНЕСА:\rКРЕДИТОВАНИЕ\rЛИЗИНГ\rДЕПОЗИТЫ\rПЛАСТИКОВЫЕ КАРТЫ\r\n'),(125,'da1f66499efacd659dcf24c5c7f6fcb2','ЛИЗИНГ\r\nНАШ БАНК ОКАЗЫВАЕТ ВЕСЬ СПЕКТР УСЛУГ ПО ФИНАНСОВОЙ АРЕНДЕ (ЛИЗИНГУ) ОТЕЧЕСТВЕННОГО И ИМПОРТНОГО ОБОРУДОВАНИЯ, ТРАНСПОРТА И НЕДВИЖИМОСТИ.\rЛИЗИНГ ОБОРУДОВАНИЯ И ТРАНСПОРТА\rОСНОВНЫЕ УСЛОВИЯ:\rСРОК ФИНАНСИРОВАНИЯ:\nОБОРУДОВАНИЕ И ТРАНСПОРТ - ДО 5 ЛЕТ\rЖ/Д ПОДВИЖНОЙ СОСТАВ - ДО 10 ЛЕТ\rВАЛЮТА ФИНАНСИРОВАНИЯ: РУБЛИ, ДОЛЛАРЫ США, ЕВРО\rМИНИМАЛЬНАЯ СУММА ФИНАНСИРОВАНИЯ: ОТ 4,5 МЛН.РУБ.\rАВАНС: ОТ 0%\rУДОРОЖАНИЕ: ОТ 9%\rСРОК ПРИНЯТИЯ РЕШЕНИЯ: ОТ 14 ДНЕЙ\rФИНАНСИРОВАНИЕ ИМПОРТНЫХ ПОСТАВОК\rМЫ ПРЕДОСТАВЛЯЕМ ПРЕДПРИЯТИЯМ ДОСТУП К ЛЬГОТНОМУ ФИНАНСИРОВАНИЮ ИМПОРТНЫХ ПОСТАВОК ОБОРУДОВАНИЯ И ТРАНСПОРТА С ИСПОЛЬЗОВАНИЕМ МЕХАНИЗМА ЛИЗИНГА ПРИ УЧАСТИИ ЭКСПОРТНЫХ КРЕДИТНЫХ АГЕНТСТВ.\rОСНОВНЫЕ УСЛОВИЯ:\rСРОК ФИНАНСИРОВАНИЯ: ДО 7 ЛЕТ\rВАЛЮТА ФИНАНСИРОВАНИЯ: РУБЛИ, ДОЛЛАРЫ США, ЕВРО\rМИНИМАЛЬНАЯ СУММА ФИНАНСИРОВАНИЯ: ОТ 15 МЛН.РУБ. \rАВАНС: ОТ 15% (БЕЗ УЧЕТА ТАМОЖЕННЫХ ПОШЛИН) \rУДОРОЖАНИЕ: ОТ 5%\rСРОК ПРИНЯТИЯ РЕШЕНИЯ: ОТ 14 ДНЕЙ\rЛИЗИНГ КОММЕРЧЕСКОЙ НЕДВИЖИМОСТИ\rПОЗВОЛЯЕТ ПРЕДПРИЯТИЯМ ПРИОБРЕСТИ ОБЪЕКТЫ КОММЕРЧЕСКОЙ НЕДВИЖИМОСТИ БЕЗ ЕДИНОВРЕМЕННОГО ОТВЛЕЧЕНИЯ ЗНАЧИТЕЛЬНЫХ СРЕДСТВ.\rВ КАЧЕСТВЕ ПРЕДМЕТА ЛИЗИНГА МОГУТ ВЫСТУПАТЬ:\rОФИСНЫЕ ЗДАНИЯ;\rТОРГОВЫЕ, СКЛАДСКИЕ И ПРОИЗВОДСТВЕННЫЕ ПОМЕЩЕНИЯ;\rДРУГИЕ ОБЪЕКТЫ КОММЕРЧЕСКОЙ НЕДВИЖИМОСТИ.\rОСНОВНЫЕ УСЛОВИЯ:\rСРОК ФИНАНСИРОВАНИЯ: ОТ 5 ЛЕТ\rВАЛЮТА ФИНАНСИРОВАНИЯ: РУБЛИ, ДОЛЛАРЫ США, ЕВРО\rМИНИМАЛЬНАЯ СУММА ФИНАНСИРОВАНИЯ: ОТ 50 МЛН.РУБ.* \rАВАНС: ОТ 0%\rУДОРОЖАНИЕ: ОТ 7%\rСРОК ПРИНЯТИЯ РЕШЕНИЯ: ОТ 14 ДНЕЙ\r* РАЗМЕР СУММЫ ФИНАНСИРОВАНИЯ ЗАВИСИТ ОТ РЕГИОНА, В КОТОРОМ НАХОДИТСЯ ОБЪЕКТ НЕДВИЖИМОСТИ.\rОСНОВНЫМ ТРЕБОВАНИЕМ, ПРЕДЪЯВЛЯЕМЫМ НАШИМ БАНКОМ ДЛЯ РАССМОТРЕНИЯ ЗАЯВКИ НА ЛИЗИНГ КОММЕРЧЕСКОЙ НЕДВИЖИМОСТИ, ЯВЛЯЕТСЯ НАЛИЧИЕ ПОЛНОГО КОМПЛЕКТА ПРАВОУСТАНАВЛИВАЮЩИХ ДОКУМЕНТОВ НА НЕДВИЖИМОСТЬ И НАЛИЧИЕ ОТЧЕТА НЕЗАВИСИМОГО ОЦЕНЩИКА.\r\n'),(126,'f38b1d21b4e881774aab9ca0e121ef4d','НОВОСТИ БАНКА\r\n\r\n'),(127,'9dfab91b86ab4a11b04df5f40578198c','БАНК ПЕРЕНОСИТ ДАТУ ВСТУПЛЕНИЯ В ДЕЙСТВИЕ ТАРИФОВ НА УСЛУГИ В ИНОСТРАННОЙ ВАЛЮТЕ\r\nУВАЖАЕМЫЕ КЛИЕНТЫ,\rСООБЩАЕМ ВАМ, ЧТО БАНК ПЕРЕНОСИТ ДАТУ ВСТУПЛЕНИЯ В ДЕЙСТВИЕ ТАРИФОВ НА УСЛУГИ ДЛЯ ЮРИДИЧЕСКИХ ЛИЦ И ИНДИВИДУАЛЬНЫХ ПРЕДПРИНИМАТЕЛЕЙ В ИНОСТРАННОЙ ВАЛЮТЕ. В СВЯЗИ С ЭТИМ ДО ДАТЫ ВВЕДЕНИЯ В ДЕЙСТВИЕ НОВОЙ РЕДАКЦИИ ТАРИФОВ, УСЛУГИ ЮРИДИЧЕСКИМ ЛИЦАМ И ИНДИВИДУАЛЬНЫМ ПРЕДПРИНИМАТЕЛЯМ БУДУТ ОКАЗЫВАТЬСЯ В РАМКАХ ДЕЙСТВУЮЩИХ ТАРИФОВ. \rИНФОРМАЦИЯ О ДАТЕ ВВЕДЕНИЯ НОВОЙ РЕДАКЦИИ ТАРИФОВ БУДЕТ СООБЩЕНА ДОПОЛНИТЕЛЬНО.\r\nУВАЖАЕМЫЕ КЛИЕНТЫ,\rСООБЩАЕМ ВАМ, ЧТО БАНК ПЕРЕНОСИТ ДАТУ ВСТУПЛЕНИЯ В ДЕЙСТВИЕ ТАРИФОВ НА УСЛУГИ ДЛЯ ЮРИДИЧЕСКИХ ЛИЦ И ИНДИВИДУАЛЬНЫХ ПРЕДПРИНИМАТЕЛЕЙ В ИНОСТРАННОЙ ВАЛЮТЕ. В СВЯЗИ С ЭТИМ ДО ДАТЫ ВВЕДЕНИЯ В ДЕЙСТВИЕ НОВОЙ РЕДАКЦИИ ТАРИФОВ, УСЛУГИ ЮРИДИЧЕСКИМ ЛИЦАМ И ИНДИВИДУАЛЬНЫМ ПРЕДПРИНИМАТЕЛЯМ БУДУТ ОКАЗЫВАТЬСЯ В РАМКАХ ДЕЙСТВУЮЩИХ ТАРИФОВ. \rИНФОРМАЦИЯ О ДАТЕ ВВЕДЕНИЯ НОВОЙ РЕДАКЦИИ ТАРИФОВ БУДЕТ СООБЩЕНА ДОПОЛНИТЕЛЬНО.\r\n'),(128,'437ea50fe03f56e33342d948ce95e9f8','НАЧАТЬ РАБОТАТЬ С СИСТЕМОЙ «ИНТЕРНЕТ-КЛИЕНТ» СТАЛО ЕЩЕ ПРОЩЕ\r\nНАШ БАНК ПРЕДЛАГАЕТ СВОИМ КЛИЕНТАМ МАСТЕР УСТАНОВКИ «ИНТЕРНЕТ-КЛИЕНТ», КОТОРЫЙ СУЩЕСТВЕННО УПРОСТИТ НАЧАЛО РАБОТЫ С СИСТЕМОЙ. ТЕПЕРЬ ДОСТАТОЧНО СКАЧАТЬ И ЗАПУСТИТЬ МАСТЕР УСТАНОВКИ, И ВСЕ НАСТРОЙКИ БУДУТ ПРОИЗВЕДЕНЫ АВТОМАТИЧЕСКИ. ВАМ БОЛЬШЕ НЕ НУЖНО ТРАТИТЬ ВРЕМЯ НА ИЗУЧЕНИЕ ОБЪЕМНЫХ ИНСТРУКЦИЙ, ИЛИ ЗВОНИТЬ В СЛУЖБУ ТЕХПОДДЕРЖКИ, ЧТОБЫ НАЧАТЬ РАБОТАТЬ С СИСТЕМОЙ.\r\nНАШ БАНК ПРЕДЛАГАЕТ СВОИМ КЛИЕНТАМ МАСТЕР УСТАНОВКИ «ИНТЕРНЕТ-КЛИЕНТ», КОТОРЫЙ СУЩЕСТВЕННО УПРОСТИТ НАЧАЛО РАБОТЫ С СИСТЕМОЙ. ТЕПЕРЬ ДОСТАТОЧНО СКАЧАТЬ И ЗАПУСТИТЬ МАСТЕР УСТАНОВКИ, И ВСЕ НАСТРОЙКИ БУДУТ ПРОИЗВЕДЕНЫ АВТОМАТИЧЕСКИ. ВАМ БОЛЬШЕ НЕ НУЖНО ТРАТИТЬ ВРЕМЯ НА ИЗУЧЕНИЕ ОБЪЕМНЫХ ИНСТРУКЦИЙ, ИЛИ ЗВОНИТЬ В СЛУЖБУ ТЕХПОДДЕРЖКИ, ЧТОБЫ НАЧАТЬ РАБОТАТЬ С СИСТЕМОЙ.\r\n'),(129,'e9a9009de370e84b759e3b542f854458','РЕОРГАНИЗАЦИЯ СЕТИ ОТДЕЛЕНИЙ БАНКА\r\nВ БЛИЖАЙШЕЕ ВРЕМЯ БУДЕТ ЗНАЧИТЕЛЬНО РАСШИРЕН ПРОДУКТОВЫЙ РЯД И ПЕРЕЧЕНЬ ПРЕДОСТАВЛЯЕМЫХ БАНКОВСКИХ УСЛУГ, КОТОРЫЕ БАНК СМОЖЕТ ПРЕДЛАГАТЬ ВО ВСЕХ СВОИХ ДОПОЛНИТЕЛЬНЫХ ОФИСАХ. ТЕПЕРЬ НАШИ КЛИЕНТЫ СМОГУТ ПОЛУЧИТЬ ПОЛНЫЙ ПЕРЕЧЕНЬ УСЛУГ В ЛЮБОМ ИЗ ОТДЕЛЕНИЙ БАНКА. \rБЫЛО ПРОВЕДЕНО КОМПЛЕКСНОЕ ВСЕСТОРОННЕЕ ИССЛЕДОВАНИЕ ФУНКЦИОНИРОВАНИЯ РЕГИОНАЛЬНЫХ ОФИСОВ НА ПРЕДМЕТ СООТВЕТСТВИЯ ВОЗРОСШИМ ТРЕБОВАНИЯМ. В РЕЗУЛЬТАТЕ, ПРИНЯТО РЕШЕНИЕ О ВРЕМЕННОМ ЗАКРЫТИИ ОФИСОВ, НЕ СООТВЕТСТВУЮЩИХ ВЫСОКИМ СТАНДАРТАМ И НЕ ПРИСПОСОБЛЕННЫХ К ТРЕБОВАНИЯМ РАСТУЩЕГО БИЗНЕСА. ОФИСЫ ПОСТЕПЕННО БУДУТ ОТРЕМОНТИРОВАНЫ И ПЕРЕОБОРУДОВАНЫ, СТАНУТ СОВРЕМЕННЫМИ И УДОБНЫМИ. \rПРИНОСИМ СВОИ ИЗВИНЕНИЯ ЗА ВРЕМЕННО ДОСТАВЛЕННЫЕ НЕУДОБСТВА. \r\nВ БЛИЖАЙШЕЕ ВРЕМЯ БУДЕТ ЗНАЧИТЕЛЬНО РАСШИРЕН ПРОДУКТОВЫЙ РЯД И ПЕРЕЧЕНЬ ПРЕДОСТАВЛЯЕМЫХ БАНКОВСКИХ УСЛУГ, КОТОРЫЕ БАНК СМОЖЕТ ПРЕДЛАГАТЬ ВО ВСЕХ СВОИХ ДОПОЛНИТЕЛЬНЫХ ОФИСАХ. ТЕПЕРЬ НАШИ КЛИЕНТЫ СМОГУТ ПОЛУЧИТЬ ПОЛНЫЙ ПЕРЕЧЕНЬ УСЛУГ В ЛЮБОМ ИЗ ОТДЕЛЕНИЙ БАНКА. \rБЫЛО ПРОВЕДЕНО КОМПЛЕКСНОЕ ВСЕСТОРОННЕЕ ИССЛЕДОВАНИЕ ФУНКЦИОНИРОВАНИЯ РЕГИОНАЛЬНЫХ ОФИСОВ НА ПРЕДМЕТ СООТВЕТСТВИЯ ВОЗРОСШИМ ТРЕБОВАНИЯМ. В РЕЗУЛЬТАТЕ, ПРИНЯТО РЕШЕНИЕ О ВРЕМЕННОМ ЗАКРЫТИИ ОФИСОВ, НЕ СООТВЕТСТВУЮЩИХ ВЫСОКИМ СТАНДАРТАМ И НЕ ПРИСПОСОБЛЕННЫХ К ТРЕБОВАНИЯМ РАСТУЩЕГО БИЗНЕСА. ОФИСЫ ПОСТЕПЕННО БУДУТ ОТРЕМОНТИРОВАНЫ И ПЕРЕОБОРУДОВАНЫ, СТАНУТ СОВРЕМЕННЫМИ И УДОБНЫМИ. \rПРИНОСИМ СВОИ ИЗВИНЕНИЯ ЗА ВРЕМЕННО ДОСТАВЛЕННЫЕ НЕУДОБСТВА.\r\n'),(130,'a0b07dac40b2192e3759747f41ea1edc','ГЛАВНЫЙ СПЕЦИАЛИСТ ОТДЕЛА АНАЛИЗА КРЕДИТНЫХ ПРОЕКТОВ РЕГИОНАЛЬНОЙ СЕТИ\r\nТРЕБОВАНИЯ\rВЫСШЕЕ ЭКОНОМИЧЕСКОЕ/ФИНАНСОВОЕ ОБРАЗОВАНИЕ, ОПЫТ В БАНКАХ ТОП-100 НЕ МЕНЕЕ 3-Х ЛЕТ В КРЕДИТНОМ ОТДЕЛЕ (АНАЛИЗ ЗАЕМЩИКОВ), ЖЕЛАТЕЛЕН ОПЫТ РАБОТЫ С КРЕДИТНЫМИ ЗАЯВКАМИ ФИЛИАЛОВ, ЗНАНИЕ ТЕХНОЛОГИЙ АФХД ПРЕДПРИЯТИЙ, НАВЫКИ НАПИСАНИЯ ЭКСПЕРТНОГО ЗАКЛЮЧЕНИЯ, ЗНАНИЕ ЗАКОНОДАТЕЛЬСТВА (В Т.Ч. ПОЛОЖЕНИЕ ЦБ № 254-П).\rОБЯЗАННОСТИ\rАНАЛИЗ КРЕДИТНЫХ ПРОЕКТОВ ФИЛИАЛОВ БАНКА, ПОДГОТОВКА ПРЕДЛОЖЕНИЙ ПО СТРУКТУРИРОВАНИЮ КРЕДИТНЫХ ПРОЕКТОВ, ОЦЕНКА ПОЛНОТЫ И КАЧЕСТВА ФОРМИРУЕМЫХ ФИЛИАЛАМИ ЗАКЛЮЧЕНИЙ, ВЫЯВЛЕНИЕ СТОП-ФАКТОРОВ, ДОРАБОТКА ЗАЯВОК ФИЛИАЛОВ В СООТВЕТСТВИИ СО СТАНДАРТАМИ БАНКА, ПОДГОТОВКА ЗАКЛЮЧЕНИЯ (РЕКОМЕНДАЦИЙ) НА КК ПО ЗАЯВКАМ ФИЛИАЛОВ В ЧАСТИ ОЦЕНКИ ФИНАНСОВО-ЭКОНОМИЧЕСКОГО СОСТОЯНИЯ ЗАЕМЩИКА, ЗАЩИТА ПРОЕКТОВ НА КК БАНКА, КОНСУЛЬТИРОВАНИЕ И МЕТОДОЛОГИЧЕСКАЯ ПОМОЩЬ ФИЛИАЛАМ БАНКА В ЧАСТИ КОРПОРАТИВНОГО КРЕДИТОВАНИЯ.\rУСЛОВИЯ\rМЕСТО РАБОТЫ: М.ПАРК КУЛЬТУРЫ. ГРАФИКИ РАБОТЫ: ПЯТИДНЕВНАЯ РАБОЧАЯ НЕДЕЛЯ, С 9:00 ДО 18:00, ПТ. ДО 16:45. ЗАРПЛАТА: 50000 РУБ. ОКЛАД + ПРЕМИИ, ПОЛНЫЙ СОЦ. ПАКЕТ,ОФОРМЛЕНИЕ СОГЛАСНО ТК РФ\r\n'),(131,'c2f74d9d9478f621cc944462301f0298','СПЕЦИАЛИСТ ПО ПРОДАЖАМ РОЗНИЧНЫХ БАНКОВСКИХ ПРОДУКТОВ\r\nТРЕБОВАНИЯ\rВЫСШЕЕ ЭКОНОМИЧЕСКОГО ОБРАЗОВАНИЯ ‚ ОПЫТ РАБОТЫ В СФЕРЕ ПРОДАЖ БАНКОВСКИХ ПРОДУКТОВ‚ ОПЫТНЫЙ ПОЛЬЗОВАТЕЛЬ ПК‚ ЭТИКА ДЕЛОВОГО ОБЩЕНИЯ‚ ОТВЕТСТВЕННОСТЬ‚ ИНИЦИАТИВНОСТЬ‚ АКТИВНОСТЬ.\rОБЯЗАННОСТИ\rПРОДАЖА РОЗНИЧНЫХ БАНКОВСКИХ ПРОДУКТОВ, ОФОРМЛЕНИЕ ДОКУМЕНТОВ.\rУСЛОВИЯ\rТРУДОУСТРОЙСТВО ПО ТК РФ‚ ПОЛНЫЙ СОЦ. ПАКЕТ. ГРАФИК РАБОТЫ: ПЯТИДНЕВНАЯ РАБОЧАЯ НЕДЕЛЯ. ЗАРПЛАТА: 20000 РУБ. ОКЛАД + ПРЕМИИ\r\n'),(132,'f80f82e8603db0db02c1d3a241b0db0c','СПЕЦИАЛИСТ ОТДЕЛА АНДЕРРАЙТИНГА\r\nТРЕБОВАНИЯ\rВЫСШЕЕ ПРОФЕССИОНАЛЬНОЕ ОБРАЗОВАНИЕ, ОПЫТ РАБОТЫ ОТ 2 ЛЕТ В ОТДЕЛЕ ПО РАБОТЕ С ФИЗИЧЕСКИМИ И ЮРИДИЧЕСКИМИ ЛИЦАМИ БАНКОВ, СВЯЗАННЫХ С АНАЛИЗОМ ПЛАТЁЖЕСПОСОБНОСТИ И КРЕДИТОСПОСОБНОСТИ ФИЗИЧЕСКИХ И ЮРИДИЧЕСКИХ ЛИЦ.\rОБЯЗАННОСТИ\rПРОВЕРКА СООТВЕТСТВИЯ ДОКУМЕНТОВ, ПРЕДОСТАВЛЕННЫХ КЛИЕНТАМИ БАНКА, АНАЛИЗ ИНФОРМАЦИИ О РИСКЕ\rУСЛОВИЯ\rТРУДОУСТРОЙСТВО ПО ТК РФ‚ ПОЛНЫЙ СОЦ. ПАКЕТ. ГРАФИК РАБОТЫ: ПЯТИДНЕВНАЯ РАБОЧАЯ НЕДЕЛЯ. ЗАРПЛАТА: ОКЛАД 25000 РУБ.\r\n'),(133,'40526f6ed8d47dfbfba0a1e59718453a','МОЯ НОВОСТЬ\r\nЯ СДЕЛАЛ САЙТ И СОЗДАЛ НОВОСТЬ.\r\n'),(135,'ee405e1b34d38d62577649f234e3eecd','JUNIOR PHP\r\n\r\n'),(136,'8e0bd0f63a3a2bcbff1b2533ad5d67bb','НОВОСТИ БАНКА\r\nНОВОСТИ БАНКА\rВАКАНСИИ\r\n'),(137,'7fc0a9a3440e87d2be3fe47c295cef3f','ВОВА\r\n\r\n'),(138,'7fc0a9a3440e87d2be3fe47c295cef3f','ВОВА\r\n\r\n'),(139,'7fc0a9a3440e87d2be3fe47c295cef3f','ВОВА\r\n\r\n'),(140,'bc75e9840fd9e405e2cc3c4b47940b53','WWWWWWW\r\n\r\n'),(141,'74c220294148c7f4538aa5924884a257','JJJJ\r\n\r\n'),(142,'a54278c7c399742075c9a821446e3dd4','ЛЛЛЛ\r\n\r\n'),(143,'cafc08e2719d73025cd1679726fee65c','NNN\r\n\r\n'),(144,'7ee9ae811795040e9e3c6ac427413836','LLL\r\n\r\n'),(145,'0a359f0b5e7a17c95de488e0af997790','UUUU\r\n\r\n'),(146,'cfa58291d41c1cb58cbf730917c40543','HHH\r\n\r\n'),(147,'cfa58291d41c1cb58cbf730917c40543','HHH\r\n\r\n'),(148,'b078040cc7f955cb0b23b8c26b08a11d','ОО\r\n\r\n'),(149,'b569f7c0968f1cadb8ce2060bcd974e6','OO\r\n\r\n'),(150,'bd2af1f33782f4cab87940b1468b91e8','HH\r\n\r\n');
